INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (39104,'dus3','양현주','','[6월/34회기]충무스포츠센터 물개수영반 프로그램','<p class="isSelectedEnd">아이들이 기다리던 수영 수업에 즐겁게 참여하였습니다.</p><p class="isSelectedEnd">자유형 수업에서는 바른 자세로 팔과 다리를 움직이는 방법을 익히고, 호흡하는 연습도 함께 진행하였습니다.&nbsp;</p><p class="isSelectedEnd">그동안의 배웠던 수영 수업을 통해 아이들은 기초 체력이 많이 향상되었습니다.</p>          </td>
        </tr>',17,1781708400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (39029,'dus3','양현주','','[6월/33회기]충무스포츠센터 물개수영반 프로그램','<p data-start="135" data-end="165">물개수영반 아동들 수영 수업에 참여했습니다.</p><p data-start="167" data-end="280">이번 수업에서는 바른 호흡법 익히기, 발차기 연습, 자유형 팔 돌리기, 배형 등의 활동을 진행하였습니다.&nbsp;</p><p data-start="167" data-end="280">아이들은 강사의 지도에 따라 안전 수칙을 지키며 즐겁고 적극적으로 수업에 참여했습니다.</p><p data-start="282" data-end="388">수업을 통해 물에 대한 두려움을 줄이고 자신감을 키우는 것은 물론, 신체 발달과 기초 체력 향상에도 도움이 되는&nbsp;</p><p data-start="282" data-end="388">시간을 가졌습니다. 앞으로도 아이들이 안전하고 즐겁게 수영을 배울 수 있도록 최선을 다하겠습니다.</p>          </td>
        </tr>',37,1780930800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35084,'dus3','관리자','test@test.com','개인정보로 인하여 아동의 사진, 영상은 모자이크 또는 게시되지 않습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'2407221115455_1.png\');><img src=\'/admin/data/bbs/dus3/M2407221115455_1.png\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
							<col width=100%></col>
							<tr>
								<td><img src=\'\' border=\'0\' name=\'wiz_target_resize\' width=\'0\' height=\'0\'></td>
							</tr>',16313,1721574000,'image01.png', '', '', 'image01.png', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (39003,'dus3','이선주','dltjswn222@naver.com','[6월/31회기]충무스포츠센터 물개수영반 프로그램','<p>어느덧 1년의 절반인 6월이 되어 어느때와 다름없이 충무수영에 다녀왔습니다.</p><p>월초에는 준비운동을 마친 뒤 새로 들어오거나 까먹었을 분들을 위해 수영 시 유의사항에 대해</p><p>다시 한번 얘기한다고 합니다. 남산원 아동들도 이에 열심히 소리를 내어 따라 읽고</p><p>새로운 마음가짐을 가져봅니다. 지난 수영수업에 이어서 자유형, 평형, 발차기 등&nbsp;</p><p>강사님의 지시를 따라 열심히 수업에 참여하는 모습이 대견합니다.</p>          </td>
        </tr>',41,1780326000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (39009,'dus3','양현주','','[6월/32회기]충무스포츠센터 물개수영반 프로그램','<p>오늘은 배영, 자유형, 음파 발차기, 평형을 배웠습니다.&nbsp;</p><p>자유시간 10분도 주셔서 물속 얼음 땡도 하고 놀았습니다.&nbsp;</p><p>나날이 실력이 발전하는 아동들입니다 ^^</p>          </td>
        </tr>',37,1780498800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38968,'dus3','서미영','occupancy@naver.com','[5월/30회기]충무스포츠센터 물개수영반 프로그램','<p data-start="0" data-end="146">오늘 충무수영 프로그램에서는 음파발차기, 자유형 팔돌리기, 배영 발차기, 사이드 발차기 연습을 진행했습니다.<br data-start="60" data-end="63">
아이들은 강사님의 설명에 집중하며 동작을 하나씩 따라 해 보았고, 물속에서 균형을 잡으며 자신감 있게 수영 동작을 익혀 나가는 모습을 보였습니다.</p><p data-start="148" data-end="300">특히 초등학교 2학년 아동들은 킥판 없이 발차기를 연습하게 되자 “더 재미있다”며 적극적으로 참여하였고, 스스로 물에 뜨고 움직여 보는 활동에 큰 흥미를 보였습니다.<br data-start="240" data-end="243">
처음에는 어려워하던 동작도 반복 연습을 통해 점차 자연스럽게 연결하며 즐겁게 수업에 참여하였습니다.</p><p data-start="380" data-end="422" data-is-last-node="" data-is-only-node="">서로 응원하며 안전하게 수영 활동을 마친 아이들에게 칭찬의 박수를 보냅니다.</p>          </td>
        </tr>',44,1779721200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38940,'dus3','김지연','lutein8@naver.com','[5월/29회기]충무스포츠센터 물개수영반 프로그램','<p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">오늘 충무 수영수업에는 </span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">7</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">명의 아동이 참석하여 준비운동과 스트레칭으로 몸을 충분히 풀어준 뒤 팔 평영</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">다리평영</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">자유형 팔돌리기</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">배형 등 다양한 수영 동작을 연습하였습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.&nbsp;</span><span style="font-family: 굴림;">눈 치료로 수업을 하지 못하다가 금일 참여한 아동은 </span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt;">‘</span><span style="font-family: 굴림;">음파가 어려웠고 며칠 안하다 하니까 코에 물이 들어가서 많이 아팠다</span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt;">‘</span><span style="font-family: 굴림;">고 해서 다시 익숙해지면 괜찮아진다고 말해주었습니다</span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt;">. </span><span style="font-family: 굴림;">자유형과 음파</span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt;">, </span><span style="font-family: 굴림;">발차기를 했다며 수영으로 신체활동하며 즐거워하는 표정이었습니다</span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt;">. 수영을 하고 나오는 아동들의 기분이&nbsp;</span><span style="font-family: 굴림;">시작할 때보다 좋아진 표정으이었으며 수영으로 신체활동한 것에 대한 만족도가 높아 보였습니다</span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt;">.</span></p>          </td>
        </tr>',55,1779289200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38933,'dus3','서미영','occupancy@naver.com','[5월/28회기]충무스포츠센터 물개수영반 프로그램','<p><span style="font-family: 굴림;">오늘 충무 수영수업에는 </span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt;">6</span><span style="font-family: 굴림;">명의 아동이 참석하여 준비운동과 스트레칭으로 몸을 충분히 풀어준 뒤 팔평영</span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt;">, </span><span style="font-family: 굴림;">다리평영</span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt;">, </span><span style="font-family: 굴림;">자유형 팔돌리기 등 다양한 수영 동작을 연습하였습니다.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">아동들은 </span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">“</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">평영이 조금 어려웠다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">”, “</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">날씨는 더웠지만 물이 시원해서 좋았다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">” </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">등의 소감을 이야기하며 즐겁게 참여하였고</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">한 아동은 머리가 아파 준비운동 후 잠시 휴식을 취하며 컨디션을 조절하였으며</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">남자아동들은 배영과 자유형 연습이 재미있었다고 이야기하였습니다.</span></p><p class="0"><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">3</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">학년 여자 아동은 평영 동작 중 힘들어하는 모습이 있어 잠시 휴식을 가진 뒤 다시 수업에 참여하며 끝까지 노력하는 모습을 보였습니다.</span></p><p class="0"><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">2</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">학년 여자 아동은 드디어 휘판과 거북이 등딱지를 빼고 자유형</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">배영</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">음파 발차기에 도전하며 한층 성장한 모습을 보여주었습니다.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">앞으로도 물에 대한 자신감을 키우며 즐겁고 안전하게 수영을 배워가길 기대합니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p><table width="100%" border="0" cellpadding="0" cellspacing="0" style="color: rgb(132, 127, 116); line-height: 19.2px; font-family: verdana;"><tbody><tr><td colspan="3" style="line-height: 19.2px; padding-left: 10px;"><table width="100%" border="0" style="line-height: 19.2px;"><tbody><tr><td width="80%" align="left" style="line-height: 19.2px;"><br></td></tr></tbody>',60,1779116400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38914,'dus3','양현주','','[5월/27회기]충무스포츠센터 물개수영반 프로그램','<p data-start="20" data-end="110">물개수영반 아동들 오늘도 씩씩하게 수영 수업에 참여했습니다.<br data-start="57" data-end="60">처음에는 물속에서 움직이는 것을 어려워하던 친구들도 있었지만, 반복 연습을 통해 점점 자신감을 얻고 있습니다.</p><p data-start="112" data-end="219">
팔과 다리의 움직임을 하나씩 익히며 스스로 해내려는 모습이 대견했습니다.</p><p data-start="221" data-end="334">특히 자유형에서는 힘차게 물살을 가르며 앞으로 나아가는 연습을 했고,<br data-start="259" data-end="262">
평형에서는 호흡과 동작을 맞추는 방법을 배웠습니다.<br data-start="290" data-end="293">
배형 시간에는 몸의 균형을 잡으며 편안하게 물에 뜨는 연습도 진행했습니다.</p><p data-start="336" data-end="438">친구들은 서로 응원하며 즐겁게 수업에 참여했고, 안전수칙도 잘 지키며 멋진 태도를 보여주었습니다.<br data-start="390" data-end="393">
앞으로도 물개수영반 아이들이 건강하고 즐겁게 성장할 수 있도록 응원 부탁드립니다.</p>          </td>
        </tr>',71,1778684400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38913,'dus3','양현주','','[5월/26회기]충무스포츠센터 물개수영반 프로그램','<p>지난 주에는 긴 연휴가 있었고 오랜만에 수영에 참여하게 되어 반가운 아동들입니다.</p><p>초급에서 중급으로 넘어가는 아동들이 있고 즐겁게 배우고 있습니다.</p><p>더워지는 날씨에 배웠던 수영을 시원하게 할 생각에 즐거운 아동들입니다.&nbsp;</p>          </td>
        </tr>',70,1778598000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38810,'dus3','오정복','jungbokoh@hanmail.net','4월30일  중경고 중간고사 끝났습니다.','<p>중경고 중간고사 끝났습니다.</p><p>하고 싶은 일을 생각하며 중간고사 기간을 보냈습니다.</p><p>학교 생활을 즐겁게 성실하게 하겠습니다.</p>          </td>
        </tr>',80,1777474800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38809,'dus3','오정복','jungbokoh@hanmail.net','4월29일 환일중 중간고사 끝났습니다.','<p>시험기간 동안 스스로 공부하고 조금은 설레는 마음으로 시험을 봤습니다.</p><p>결과에 만족하는 과목도 있고 아쉬움도 있습니다.</p><p>성실한 학교 생활을 하고 매일 학습하는 습관을 기르겠습니다.</p>          </td>
        </tr>',78,1777474800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38784,'dus3','이세랑','','덕수중 1학기 중간고사 시험 끝났습니다.','<p>23일(목)부터 시작된 1학기 중간고사가 24(금) 오늘 종료되었습니다. 시험기간에 열심히 노력한 만큼 좋은 결과가 있길 바랍니다. 가채점을 하며 틀린문제에 대해 오답풀이를 해봅니다~중간고사 기간동안 수고많았습니다!!&nbsp;</p>          </td>
        </tr>',85,1776956400,'', '', '', '', '', '');
