INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38782,'dus3','오정복','jungbokoh@hanmail.net','중경고등학교 1학기 중간고사 기간입니다.','<p>4월24일(금) ~ 4월30일(목) 중경고등학교 중간고사 기간입니다.</p><p>고등학교 입학 후 첫 중간고사 입니다.&nbsp; 열심히 준비하겠습니다.</p>          </td>
