INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38775,'dus3','이세랑','','덕수중학교 1학기 중간고사 기간입니다.','<p>4월23일(목)~4월24일(금)까지 덕수중 2~3학년 중간고사 기간입니다~ 중간고사를 대비하여 학습을 했었습니다~ 평소보다 더 좋은 점수가 나오길 바랍니다~ 1학년은 진로탐색 기간이여 비전옥망설계,신산업분야에 대해 배울예정입니다~!!&nbsp;</p>          </td>
        </tr>',82,1776870000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38774,'dus3','양현주','','[4월/25회기]충무스포츠센터 물개수영반 프로그램','<p>오늘은 건강 상의 이유로 5명의 아동들이 수영에 참여했습니다.&nbsp;</p><p>초급반을 열심히 배우고 있는 두 아동은 음파, 배영 발차기를 배웠습니다.</p>          </td>
        </tr>',81,1776870000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38768,'dus3','이선주','dltjswn222@naver.com','[4월/24회기]충무스포츠센터 물개수영반 프로그램','<p>본격적인 수영을 시작하기 전에 앞서 스트레칭을 했습니다.</p><p>몸을 충분히 풀고 나선 선생님의 지도하에 배영, 자유형 등&nbsp;</p><p>수영 수업에 열심히 참여하는 아동들 볼 수 있었습니다.</p><p>지속적인 수영 연습을 통해 아동들의 수영실력이 쑥쑥 성장하기를 바랍니다.^^</p>          </td>
        </tr>',87,1776697200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38743,'dus3','홍영지','youngzzji@gmail.com','[4월/23회기]충무스포츠센터 물개수영반 프로그램','<p>아동들은 센터에 도착해 스스로 카운터를 방문해 수건을 챙기며 준비를 했습니다.</p><p>수영복으로 갈아입고 수업 전 호루라기 소리에 맞춰 준비 운동을 마쳤습니다.</p><p>물속으로 들어가 자연스럽게 킥판을 잡고 각자의 레벨에 맞춰 수업을 들었습니다.</p><p>레인을 따라 돌며 열심히 발장구를 치고</p><p>수업에 집중해 열심히 하는 모습이 대견한 아동들입니다:)</p><p><br></p>          </td>
        </tr>',100,1776265200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38739,'dus3','서미영','occupancy@naver.com','[4월/22회기]충무스포츠센터 물개수영반 프로그램','<p>4월 22회기 충무 스포츠센터 수영수업에 참여했습니다.</p><p>오늘의 수영수업도 지난 수업에 이어 준비운동 한 후에&nbsp; 평영.자유형,접영과 팔동작을 배우며 활기차게 수영수업을 진행했습니다.</p><p>열심히 신체활동과 에너지를 발산함으로 인해 귀원하는 차 안에서 식당과 편의점을 지나칠 때마다 "맛있겠다"라고 소리치며 "오늘 저녁 메뉴는 뭘까?"기대하는 모습으로 즐거워 하였습니다. 오늘도 열심히 운동하며&nbsp; 신체를 단련하는 아동들 건강하게 잘 성장하기를 응원합니다.&nbsp;</p><p><br></p><p><br></p><p><br></p>          </td>
        </tr>',100,1776178800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38703,'dus3','이선주','dltjswn222@naver.com','[4월/21회기]충무스포츠센터 물개수영반 프로그램','<p>4월 21회기 충무 스포츠센터 수영수업 참석했습니다.</p><p>어느때와 다름없이 준비운동으로 몸을 푼 다음 본격적인 수영 수업에 임했습니다.</p><p>자유형, 평영, 팔돌리기 등 지난번에 배웠던 수영을 똑같이 따라서 복습하는 아동들입니다.</p><p>점점 수영 동작이 익숙해지는 모습 보이니 뿌듯해집니다.</p><p>앞으로도 오늘의 동작들을 잊지 않고, 수영 수업에 참여하기를 바랍니다.</p><p><br></p>          </td>
        </tr>',107,1775660400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38696,'dus3','서미영','occupancy@naver.com','[4월/20회기]충무스포츠센터 물개수영반 프로그램','<p>물개 수영 20회기 참여 하였습니다. 수영 수업을 마치고 귀원 하는 차량 안에서 수영 소감을 묻자, 여자 아동 중에 한 명이 그동안 평형 발 동작만 배웠었는데 드디어 오늘 팔 동작을 배워 너무 재미있었다고 합니다. 마치 물속 탐험을 하듯, 스노쿨링 하는 기분이었다고 하면서 들떠 있었습니다. 그러자 제일 막내 아동도 물이 무섭긴 하지만, 수영 동작을 배우는 것은 즐겁다고 하였습니다.</p><p>오늘도 문화 여가 시간으로, 신체 활동 시간으로 즐겁게 수영을 배우며 안전하게 잘 다녀 왔습니다.&nbsp; &nbsp;</p>          </td>
        </tr>',109,1775487600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38669,'dus3','서미영','occupancy@naver.com','[4월/19회기]충무스포츠센터 물개수영반 프로그램','<p>물개 수영 19회기 참여 했습니다. 남자 아동은 평형, 자유형, 팔돌리기, 사이드 발차기 등을 배우며 즐겁게 수업에 참여하였습니다.</p><p>여자 아동 두 명은 헬퍼(거북이 등딱지 모양의 보호장비)를 착용하였으며, 헬퍼가 목에 닿아 다소 불편함을 느꼈다고 했습니다. 그러나&nbsp; 안전을 위해 잘 참고 참여하는 모습을 보였습니다. 귀원하는 차량 안에서 아동들이 저녁 메뉴에 대해 이야기하며 수영 활동으로 인해 배가 많이 고팠는지, 먹는 이야기로 즐거운 분위기를 이어갔습니다.&nbsp;</p><p>오늘도 행복하고 즐거운 물개수영반 아동들! 수영실력도 쑥쑥!!! 키도 쑥쑥!!! 정신과 육체가 건강하게 잘 자라기를 원합니다.</p>          </td>
        </tr>',116,1775055600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38660,'dus3','양현주','','[3월/18회기]충무스포츠센터 물개수영반 프로그램','<p>물개 수영 18회기 참여했습니다.</p><p>3명의 아동은 감기약 복용 중으로 원내 생활 했습니다.</p><p>초급반 아동들은 킥판, 부력스틱 활용하여 수업 참여했습니다.</p><p>수영 수업 마치고 나른해 하던 아이들의 체력이 많이 성장했습니다.</p><p>잠든 아동 없이 맑은 눈으로 오손도손 밝게 이야기 나누며 귀원했습니다.</p>          </td>
        </tr>',108,1774882800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38627,'dus3','양현주','','[3월/17회기]충무스포츠센터 물개수영반 프로그램','<p>그동안 열심히 충무 스포츠센터 수영 수업을 다닌 결과, 3명의 아이들이 평영에 접어들었습니다!</p><p>다른 아동들도 수영을 좋아하며 물과 친해지며 성실하게 수영을 배우고 있습니다.</p><p>제일 큰 언니인 지* 아동은 오리발 착용을 하고 접영을 하고 있어 쑥쑥 성장 중입니다.</p>          </td>
        </tr>',121,1774278000,'', '', '', '', '', '');
