INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38600,'dus3','서미영','occupancy@naver.com','[3월/16회기]충무스포츠센터 물개수영반 프로그램','<table width="100%" border="0" style="color: rgb(132, 127, 116); line-height: 19.2px; font-family: verdana;"><tbody><tr><td width="80%" align="left" style="line-height: 19.2px;"><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">오늘 세 명의 아동은 감기로 인해 출석 하지 못하였고</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, 5</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">명의 아동만 출석하여 수영수업에 참석하였습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">유아풀 에서는 자유형을 연습하며 기본 동작을 익혔고</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">성인풀 에서는  피판 없이 배영</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">평영</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">접영</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">웨이브</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">,&nbsp;</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">입수킥까지 다양한 수영법을 배우며 한 층 더 실력을 키워 보았습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">열심히 연습한 만큼 성취감도 느끼고 수영의 재미도 경험할 수 있는 시간이었습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">활동을 마친 후에는 많이 움직인 탓에 배고픔을 느끼며</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">더욱 건강한 하루를 보냈습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p></td></tr></tbody>',121,1773846000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38571,'dus3','이새나','','[3월/15회기]충무스포츠센터 물개수영반 프로그램','<p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">충무스포츠센터 물개수영반 프로그램 총 </span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">8</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">명에서 진행된 충무수영</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">준비 운동을 끝내고 음파</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">발차기까지 끝낸 뒤에 팔 돌리기와 평형을 배우고 계속해서 반복 연습을 하는 시간을 가졌다고 합니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">아동들 모두 수영을 할 때면 힘들지만 점점 늘어나는 실력에 괜시리 기분이 좋은지 오는 내내 오늘 뭐 배웠는지</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">실력이 얼만큼 늘었는지에 대해 대화를 나누며 왔습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">수업 시간이 끝나기 전에는 자유 놀이로 수영하며 술래잡기를 하는 걸로 마무리해서 너무 재미있었다고 합니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p>          </td>
        </tr>',126,1773241200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38564,'dus3','이새나','','[3월/14회기]충무스포츠센터 물개수영반 프로그램','<p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">충무스포츠센터 물개수영반 프로그램 총 </span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">8</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">명으로 충무수영 진행했습니다.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">오늘도 시작 전 열심히 준비 운동을 하고 음파 연습 했습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">자유형</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">(</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">발차기</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">)</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">와 배영도 하며 수영의 기본기를 잘 다듬으며 수업 마무리 했습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">아동들 모두 금일 수영 수업도 너무 재미있었다고 하며 전보다 더 나아진 실력을 많이 보여주었습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p>          </td>
        </tr>',126,1773068400,'', '', '', '', '', '');
