INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38533,'dus3','오정복','jungbokoh@hanmail.net','중경고등학교 입학식했습니다','<p>중경고등학교 입학식 했습니다. 중학교 생활을 잘 마무리하고 고등학교에 진학했습니다.</p><p>새로운 환경이지만 학교도 친구들도 친근한 느낌입니다.</p><p>즐거운 학교 생활, 성실한 학교 생활을 하겠습니다.</p>          </td>
        </tr>',167,1772463600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38537,'dus3','이선주','dltjswn222@naver.com','[3월/13회기]충무스포츠센터 물개수영반 프로그램','<p>[3월/13회기]충무스포츠센터 물개수영반 프로그램 총 8명에서 진행된 충무수영&nbsp;</p><p>지난주에 이어서 오늘도 준비운동, 음파, 배영, 팔돌리기 자유형 등 다들 잘 참여했습니다.</p><p>제일 큰언니인 지*이는 고급반, 3학년에 진학하는 하*이도 이번에 중급반 올라갔습니다^^&nbsp;</p><p>다른 아동들도 열심히 하여 월반하기를 바랍니다</p>          </td>
        </tr>',138,1772636400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38532,'dus3','오정복','jungbokoh@hanmail.net','환일중학교 입학, 개학했습니다.','<p>환일중학교 입학식 했습니다. 교복을 입고 학교에 가는 모습이 의젓합니다.&nbsp;</p><p>공부도 열심히~~ 학교 활동도 적극적으로 참여하겠습니다.</p><p>2학년 3학년이 된 형들도 성실한 2026년을 보내도록 보육하겠습니다.</p><p><br></p>          </td>
        </tr>',149,1772463600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38530,'dus3','이세랑','','덕수중학교 입학식 및 개학식했습니다.','오늘은 덕수중 입학식날 입니다.새로운 교복을 입고 새친구들을 만나는 길이 무척이나 신이난 아동들입니다^^ 새로운 환경에서 적응을 잘하실 바랍니다~^^ 2,3학년은 개학식을 했습니다. 한학년이 올라가고 한가지씩 목표를 세우는 아동들입니다~ 아동들 모두 새로운 환경에서의 시작을 응원합니다~&nbsp;          </td>
        </tr>',140,1772463600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38531,'dus3','오정복','jungbokoh@hanmail.net','장충초등학교 개학했습니다.','<p>장충초등학교&nbsp; 개학했습니다. 단정한 차림으로 등교했습니다.</p><p>신학기 준비물과 교과서를 챙겼습니다.</p><p>새로운 친구들과 새로운 교실에서 지낼 1년이 기대됩니다.</p>          </td>
        </tr>',130,1772463600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38529,'dus3','이주현','dlwngus0608@gmail.com','3월 3일 남산초등학교 개학했습니다.','<p>오늘 남산초등학교 개학식날입니다 ^^</p><p>아동들 모두 한 학년씩 올라가서 새로운 담임선생님과 반 친구들을 만났습니다~!!</p><p>새로운 학년을 잘 적응할 수 있도록 지원하겠습니다 *^^*</p>          </td>
        </tr>',149,1772463600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38438,'dus3','서미영','occupancy@naver.com','[2월/11회기]충무스포츠센터 물개수영반 프로그램','<p>오늘 수영에 참여한 아동들은 6명이었고, 한명의 아동은 감기로 인해 수영 할 수 없음에 많이 아쉬워하며 컨디션을 회복시켜서 다음 시간에는 꼭 수영에 참여하겠다는 의지를 보이기도 하였습니다. 오늘도 수영에 참여한 아동들은 음파 발차기, 팔돌리기, 자유형, 배영등 열심히 수영수업에 참여하며 안전하게 열심히 수영을 배우는 시간이 되었습니다.</p>          </td>
        </tr>',151,1771426800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38503,'dus3','이선주','dltjswn222@naver.com','[2월/12회기]충무스포츠센터 물개수영반 프로그램','<p>총 8명에서 진행된 충무수영 오늘은 학부모 참관을 했습니다^^</p><p>준비운동, 음파, 배영, 팔돌리기 자유형 등 다들 수업에 잘 참여했는데요~</p><p>수영선생님께서도 오늘 아이들이 더 잘하는 거 같다고 말하시는게 인상 깊었습니다.</p><p>다들 오늘의 기억을 갖고 앞으로 수영 달인이 되길 바랍니다.</p>          </td>
        </tr>',141,1772031600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38402,'dus3','김지은','','한나방 남산초 졸업생들 상장받았습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'2602141237242_1.jpg\');><img src=\'/admin/data/bbs/dus3/M2602141237242_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
							<col width=100%></col>
							<tr>
