INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38396,'dus3','양현주','','[1월/10회기]충무스포츠센터 물개수영반 프로그램','<p>오늘은 기초 발차기, 호흡, 자유형, 평영을 배웠습니다.</p><p>호흡기 질환으로 일부 아동들은 원내 생활을 했습니다.&nbsp;</p><p>주 2회 수영 수업을 다니게 되어 아동들의 체력과 실력이 많이 늘었습니다.&nbsp;</p>          </td>
