INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38394,'dus3','오정복','jungbokoh@hanmail.net','환일중학교 오리엔테이션 했습니다.','<p>2월11일~2월12일 환일중학교 오리엔테이션이 있었습니다.<br>다윗방 박**, 박**, 박** 세 아동들이 참여했습니다.</p><p>교복을 입은 의젓한 발걸음과 체육복을 입고 활기찬 발걸음으로 학교에 갔고</p><p>새로운 친구들을 만나고 집에 와서 이야기를 한가득 풀어 놓았습니다.</p><p>성실하고 바른 학교 생활 하겠습니다.</p>          </td>
        </tr>',183,1770822000,'', '', '', '', '', '');
