INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38387,'dus3','양현주','','[1월/9회기]충무스포츠센터 물개수영반 프로그램','<p>수영을 시작 한지 얼마 되지 않은 2학년 아동들은 기초 발차기, 음파를 배웠습니다.&nbsp;</p><p>기존에 다니고 있던 언니들은 자유형을 했습니다. 날씨가 흐려 피곤하기도 하고 다녀와서 배가 많이 고팠지만</p><p>돌아오는 차 안에서 여유롭게 대화도 나누고 즐거운 시간을 보냈습니다.&nbsp;</p><p><br></p>          </td>
        </tr>',187,1770649200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38375,'dus3','오정복','jungbokoh@hanmail.net','1월29일 다윗방 입학등록 했습니다.','<p>1월29일 맏형인 이**아동은 중경고등학교, 박**,박**,박** 아동들은 환일중학교에 입학 등록 했습니다.</p><p>선생님과 함께 학교 가는 길을 익히고 교복도 맞췄습니다.</p><p>의젓한 중학생, 고등학생이 되겠습니다.</p>          </td>
        </tr>',192,1770476400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38374,'dus3','오정복','jungbokoh@hanmail.net','2월5일 환일중학교  종업식 했습니다.','<p>환일중학교 배**, 장**, 박**&nbsp; 아동 종업식 했습니다.</p><p>성실하고 적극적으로 학교 생활을 하고 한 학년 마무리를 했습니다.</p><p>신학기 준비도 잘 하겠습니다.</p>          </td>
        </tr>',193,1770476400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38355,'dus3','홍영지','youngzzji@gmail.com','[2월/5회기]유니콘스포츠클럽 생활체육 프로그램','<p>아동들이 일주일 간 기다리던 유니콘스포츠클럽 다녀왔습니다.</p><p>스트레칭, 줄넘기, 원반 던지기 활동 진행했습니다.</p><p><br></p><p>도착하자마자 바로 수업 교실로 스스로 찾아가는 아동들</p><p>수업이 시작되고 스트레칭으로 열심히 몸을 풀고 줄넘기 활동 진행했습니다.&nbsp;</p><p>앞으로 넘기, 뒤로 넘기, 발 바꿔 넘기, 엑스자 넘기 등 다양한 방식으로 줄넘기하면서</p><p>숨을 헉헉 거리면서도 끝까지 뛰는 모습입니다 :)</p><p>원반 던지기 활동에서는 원 안에 넣어 점수 내기를 목표로 협동심 기르는 시간을 가졌습니다.</p><p>각자의 목표를 가지고 던져 점수를 내는데 조언을 하고 서로 도와주며&nbsp;</p><p>점수가 생길 때마다 뿌듯해하는 모습이 보기 좋았습니다.</p>          </td>
        </tr>',173,1770130800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38356,'dus3','양현주','','[1월/8회기]충무스포츠센터 물개수영반 프로그램','<p>지* 아동은 접영을 배우기 시작했습니다.</p><p>새로 시작한 유**, 임** 아동은 발차기와 음파를 배우고 있습니다.</p><p>즐겁게 수영을 배우고 나니 배도 고프고 체력도 쑥쑥 성장하는 아동들입니다.&nbsp;</p>          </td>
        </tr>',171,1770217200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38343,'dus3','문소연','dawooriy3175@gmail.com','2월 2일 남산초등학교 개학식 했습니다.','<p>2월 2일 오늘! 남산초등학교 개학을 했습니다.</p><p>2월 2일(월)~ 2월 12일(목)까지 2주간의 개학을 한 뒤 짧은 봄방학을 또 맞이하게 되는데요.</p><p>우리 아이들이 짧은 2주간의 개학, 학교 가는 날이지만</p><p>좋은 추억 쌓고 한 학년을 잘 마무리 하도록 옆에서 지원하겠습니다 :)</p>          </td>
        </tr>',201,1769958000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38351,'dus3','이선주','dltjswn222@naver.com','[1월/7회기]충무스포츠센터 물개수영반 프로그램','1월 7회기 물개수영반 프로그램에 임*, 유*,유*,유*,최*,지*,최*,윤* 8명의 아동들이 참여 했습니다.<div>수업 전에 간단히 오늘 할 활동을 이야기한 뒤 준비 운동을 하고, 바로 물에 들어가 수업을 시작했습니다.</div><div>
아이들은 각자 정해진 순서에 맞춰 연습을 했고, 서로 부딪히지 않도록 주의하며 움직였습니다.^^<br data-start="157" data-end="160">
중간중간 쉬는 시간에는 친구들과 이야기를 나누며 웃는 모습도 보였습니다~<br data-start="200" data-end="203">
전체적으로 차분한 분위기 속에서 수업에 열심히 참여하는 아동들 대견합니다.</div>          </td>
        </tr>',164,1770044400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38344,'dus3','이선주','dltjswn222@naver.com','모세방 유*아동 상장 받았습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'2602020439533_1.jpg\');><img src=\'/admin/data/bbs/dus3/M2602020439533_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
							<col width=100%></col>
							<tr>
								<td><img src=\'\' border=\'0\' name=\'wiz_target_resize\' width=\'0\' height=\'0\'></td>
							</tr>',201,1769958000,'1.jpg', '', '', '1.jpg', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38316,'dus3','이새나','','[1월/4회기]유니콘스포츠클럽 생활체육 프로그램','<p>오늘은 간단히 스트레칭 후에 셔틀런 - 왕복 오래 달리기 활동을 했습니다.</p><p>참여 아동들 모두 약 100개 정도하며 이때까지 셔틀런 했던 것 중에 제일 많이 뛰었다고 좋아했습니다!</p><p>막내 정* 아동 또한 쉬고 뛰고를 반복하며 아동 또한 매우 열심히 하는 모습이였습니다.</p><p>이후에는 뛰기 연습을 하고 축구, 피구를 팀을 계속 바꾸며 운동했습니다.</p><p>평소보다 더 열정적으로 참여했으며 운동이 끝난 후에는 아동들 모두 땀을 뻘뻘 흘렸답니다.</p><p>&nbsp;오늘 수업의 끝은 시원한 물 한잔 마시며 마무리 했습니다~^^</p>          </td>
        </tr>',182,1769526000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38311,'dus3','오정복','jungbokoh@hanmail.net','1월26일 환일중학교 개학 했습니다.','<p>환일중학교 배**, 장**, 박** 아동들 개학했습니다.</p><p>개학식을 하고 2박3일 동안 스키캠프에 참여합니다.</p><p>건강하고 성실한 학교 생활을 하도록 보육하겠습니다.</p>          </td>
        </tr>',185,1769439600,'', '', '', '', '', '');
