INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38309,'dus3','이선주','dltjswn222@naver.com','[1월/6회기]충무스포츠센터 물개수영반 프로그램','<p class="0" style="color: rgb(132, 127, 116); font-family: verdana;"><span style="margin: 0px; padding: 0px; color: rgb(0, 0, 0);">1월 6회기 물개수영반 프로그램에 임*, 유*,유*,유*,최*,지*,최*,윤* 8명의 아동들이 참여 했습니다.</span><span style="margin: 0px; padding: 0px; font-family: 굴림;"></span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">다 함께 준비운동을 끝낸 뒤 자유형</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">배영</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">평영</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">자유 시간 등을 보내고 수영을 마무리 했습니다.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">지난번에 배웠던 활동이여서 그런지 다들 집중하여 잘 참여 했습니다.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">수업 끝나고 자유 시간을 보낼 때 가장 신나게 활동 했으며</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">&nbsp;</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">점심을 먹은지 얼마 되지 않았는데도&nbsp;</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">불구하고 금방 배가 고프다고 말한 만큼 열심히 활동한 것으로 보입니다.</span></p>          </td>
        </tr>',180,1769439600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38262,'dus3','이선주','dltjswn222@naver.com','[1월/5회기]충무스포츠센터 물개수영반 프로그램','<p class="0"><span style="color: rgb(0, 0, 0); font-family: verdana;">1월 5회기 물개수영반 프로그램에 임*, 유*,유*,유*,최*,지* 6명의 아동들이 참여 했습니다.</span><span style="font-family:굴림;mso-fareast-font-family:굴림;"></span></p><p class="0"><span style="font-family: 굴림; color: rgb(0, 0, 0);">본격적으로 수영 수업에 참여하기 앞서 다 함께 준비 운동을 하고&nbsp;</span></p><p class="0"><span style="font-family: 굴림; color: rgb(0, 0, 0);">키판을 잡고 자유형을 지속적으로 연습했습니다.&nbsp;</span><span style="font-family: 굴림; color: rgb(0, 0, 0);">또</span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt; color: rgb(0, 0, 0);">, </span><span style="font-family: 굴림; color: rgb(0, 0, 0);">음파와 발차기도 연습하였습니다.</span></p><p class="0"><span style="font-family: 굴림; color: rgb(0, 0, 0);">다들 열심히 참여하였고</span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt; color: rgb(0, 0, 0);">, </span><span style="font-family: 굴림; color: rgb(0, 0, 0);">열심히 참여한만큼 돌아오는 길에 다 함께 조용히 쉬면서 왔습니다.^^</span></p>          </td>
        </tr>',201,1769007600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38256,'dus3','이새나','','[1월/3회기]유니콘스포츠클럽 생활체육 프로그램','<p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">아동들 모두 오늘은 어떤 스포츠를 배우며 할지에 대해 기대감을 많이 안고 수업을 시작하였습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">스트레칭과 줄넘기</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">(</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">앞으로 넘기</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">뒤로 넘기</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">엑스자 줄넘기</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">, 2</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">번 뛰기</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">)</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">로 몸을 풀고 본격적으로 농구에 대해 배우는 시간 가졌습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">방과후로 농구하는 아동들이 있어서인지 다들 농구의 기본인 드리블은 가볍게 해내며 고깔을 두고 드리블 할 때에도 잘해내는 모습이라 놀랐습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">농구의 기본적인 자세에 대해 배우고 팀을 이루어 시합하는 시간도 가졌습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">마무리로 피구 활동까지 했습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p>          </td>
        </tr>',218,1768921200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38249,'dus3','서미영','occupancy@naver.com','[1월/4회기]충무스포츠센터 물개수영반 프로그램','<p><span style="color: rgb(132, 127, 116); font-family: verdana;">1월 4회기 물개수영반 프로그램에 임*, 유*,유*,유*,정*,지* 6명의 아동들이 참여 했습니다.</span></p><p><span style="font-family: verdana; color: rgb(132, 127, 116);">가벼운 스트레칭으로 몸을 풀고 준비운동을 마치고 본격적인 수영 동작을 배웠습니다.</span></p><p><span style="font-family: verdana; color: rgb(132, 127, 116);">어린 아동들은 유아풀에서 안전하게 수영을 배웠고,&nbsp;</span></p><p><span style="font-family: verdana; color: rgb(132, 127, 116);">접영을 처음 배우는 아동은 벽을 잡고 연습하였다고 합니다.</span></p><p><span style="font-family: verdana; color: rgb(132, 127, 116);">자유형을 처음 배운 아동은 처음에는 어려웠지만, 계속 연습하면서 점점 재미있어졌다고 합니다.</span></p><p><span style="font-family: verdana; color: rgb(132, 127, 116);">그리고 수영실력이 있는 아동들은 수영 선생님과 시합도 했습니다.&nbsp;</span></p><p><span style="font-family: verdana; color: rgb(132, 127, 116);">비록 바깥 날씨는 춥지만 아동들의 수영 열기는 날씨조차도 비껴 가는 듯 합니다.&nbsp;</span></p><p><font color="#847f74" face="verdana">오늘도 즐겁고 재미있게 안전하게 잘 다녀왔습니다.</font></p>          </td>
        </tr>',195,1768834800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38213,'dus3','문소연','dawooriy3175@gmail.com','[1월/3회기]충무스포츠센터 물개수영반 프로그램','<p><span style="color: rgb(132, 127, 116); font-family: verdana;">1월 3회기 물개수영반 프로그램에 임*, 유*,유*,윤*,최* 5명의 아동들이 참여 했습니다.</span></p><p><font color="#847f74" face="verdana">우리 아이들 깊은 물 속에서도 두려움에 떨지 않고</font></p><p><font color="#847f74" face="verdana">돌고래처럼 자유형을 하는 아이들이 멋이 있습니다.</font></p><p><font color="#847f74" face="verdana">음파 발차기, 자유형 등 다양한 수영법을 하는 아이들이</font></p><p><font color="#847f74" face="verdana">다음 수업 내용을 궁금해하고 연습해 보는 아이들이 대견하기만 합니다 :)</font></p>          </td>
        </tr>',198,1768402800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38205,'dus3','정동수','ehdtn7573@naver.com','다윗방 배**, 장** 2학기 성적향상금 받았습니다.','<p>다윗방 중등 아동들 2학기 기말고사 성적표 나왔습니다.</p><p>이번에 성적이 오른 배** 아동은 54,000원&nbsp; 장** 아동은 33,000원의 성적향상금을 전달받았습니다.</p><p>아동들은 매우 뿌듯해 하였으며 기뻐하였습니다.</p><p>꾸준히 성적이 오를 수 있도록 열심히 지도하겠습니다!</p>          </td>
        </tr>',209,1768316400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38201,'dus3','홍미진','ghdalwls0410@naver.com','[1월/2회기]유니콘스포츠클럽 생활체육 프로그램','<p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">유니콘스포츠클럽</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">2</span><span style="font-family:굴림;mso-fareast-font-family:굴림;">회기 수업으로 처음보다  많이 안정된모습보였습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">줄넘기활동으로 몸 풀기를 시작하여 난위도 있는 동작까지 잘해내는 모습 이었습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">다음으로는 플로오볼 활동을 했는데 모든 아동이 집중하여 선생님 말씀 들으며 열심히 하였습니다</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">세번째 수업으로는 아이들이 좋아하는 패드민턴 수업이었는데 기존에 했던 배드민턴 활동과 비슷하여 아이들이 능숙하게 잘 해내는 모습이었음</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span><span style="font-family:굴림;mso-fareast-font-family:굴림;">마지막활동으로 평소 즐겨하는 피구활동으로 모두가 즐겁게 활동하며 수업종료 함</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.&nbsp;</span></p>          </td>
        </tr>',222,1768316400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38160,'dus3','서미영','occupancy@naver.com','[1월/1회기]충무스포츠센터 물개수영반 프로그램','<p>1월 1회기 물개수영반 프로그램에 임*, 유*,유*,유*윤*,지* 6명의 아동들이 참여 했습니다.</p><p>오늘 처음 참석한 두 명의 아동도 기대감 상승으로 수영가방을 열었다, 닫았다 하며 시간을 기다렸습니다.</p><p>아동들은 도착 하여 입수 전에 수영 선생님의 호루라기 소리에 맞춰 몸 풀기와 준비운동과 스트레칭을 한 후</p><p>선생님의 지도에 따라 다양한 수영 동작을 연습하였습니다.</p><p>처음 참석한 아동들을 포함한 모든 아동들이 즐겁고 재미있게 수업에 참여했습니다.</p>          </td>
        </tr>',242,1767798000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38199,'dus3','서미영','occupancy@naver.com','[1월/2회기]충무스포츠센터 물개수영반 프로그램','<p>1월 2회기 물개수영반 프로그램에 임*, 유*,유*,유*,윤*,지*,최*,정* 8명의 아동들이 참여 했습니다.</p><p>수영장에 도착한 아동들은 가볍게 샤워한 후 준비운동을 하였습니다.</p><p>손목과 발목 돌리기, 팔 벌려 뛰기, 무릎당겨주기, 음파 발차기,자유형 등...</p><p>수영을 마치고 돌아오는 길에 아동들이 오늘은 새로운 것을 배웠는데&nbsp;</p><p>평형을 배워서 뿌듯했다고 합니다.</p><p>돌아오는 차 안에서 오늘 수영배운 소감을 이야기하며 즐겁고 재미있는 수영시간이 되었습니다.</p>          </td>
        </tr>',202,1768230000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38157,'dus3','이세랑','','1월 8일 덕수중학교 방학식 했습니다.','<p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">오늘 덕수중 방학식을 했습니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. 1</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">월</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">9</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">일</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">(</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">금</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">)~2</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">월</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">28</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">일</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">(</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">토</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">) </span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">까지 겨울방학입니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">방학기간동안 예습</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">,</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">복습을 해보려고 합니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">^^ </span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">또한 아동들이 즐거운 추억을 많이 만들 수 있도록 지원하겠습니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.&nbsp;</span></p>          </td>
        </tr>',233,1767798000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38152,'dus3','문소연','dawooriy3175@gmail.com','1월 8일 덕수중학교 종업식 / 졸업식 했습니다.','<p>오늘 덕수중학교 종업식 / 졸업식을 했습니다.</p><p>한 학년이 끝나고 새 학년을 맞이하는 친구도 있고,</p><p>3개의 학년을 끝내고 고등학교를 바라보고 있는 친구도 있습니다.</p><p>우리 아이들이 졸업, 종업을 하면서 학교에서의 좋았던, 즐거웠던 기억을 가지고,</p><p>새로운 시작을 두려워하지 않았으면 합니다 :)</p><p>졸업, 종업 모두 축하해요 *^0^*</p>          </td>
        </tr>',225,1767798000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (38150,'dus3','김보영','qwert7337@naver.com','1월 8일 서울의료보건고등학교 방학식 했습니다.','<p><span style="color: rgb(132, 127, 116); font-family: verdana;">1월 8일(목)~3월 1일(일)까지 서울의료보건고등학교 겨울방학 기간입니다.</span></p><p><span style="color: rgb(132, 127, 116); font-family: verdana;">3월 2일(월)에 개학식 진행됩니다.</span></p><p><span style="color: rgb(132, 127, 116); font-family: verdana;">겨울방학 기간 동안 동계 실습도 같이 진행되는데요!</span></p><p><span style="color: rgb(132, 127, 116); font-family: verdana;">실습과 함께 건강하고 알찬 방학 보낼 수 있도록 지원하겠습니다.</span></p>          </td>
