INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37960,'dus3','김보영','qwert7337@naver.com','룻방 한* 아동 동계 간호 실습 진행합니다.','<p style="color: rgb(132, 127, 116); font-family: verdana;">서울의료보건고등학교 재학 중인</p><p style="color: rgb(132, 127, 116); font-family: verdana;">한* 아동 동계 간호 실습 시작했습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">(25.12.15~26.02.27 / 총 50일 400시간)</p><p style="color: rgb(132, 127, 116); font-family: verdana;">하계 실습 보다 더 긴 시간 동안 진행이 됩니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">실습 기간 동안 수술실을 배정 받아 더 책임감을</p><p style="color: rgb(132, 127, 116); font-family: verdana;">갖고 임할 한* 아동을 응원합니다!</p>          </td>
