INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37959,'dus3','김보영','qwert7337@naver.com','서울의료보건고등학교 기말고사 끝났습니다. (12/9~12/12)','<p style="color: rgb(132, 127, 116); font-family: verdana;">서울의료보건고등학교 12월 9일~12월 12일 기말고사 시험 봤습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">시험 기간 동안 성실하게 참여해준 아동을 칭찬합니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">이제 한 해가 마무리 되어가는데</p><p style="color: rgb(132, 127, 116); font-family: verdana;">남은 기간도 즐거운 학교 생활 할 수 있도록 지원하겠습니다~^^</p>          </td>
