INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37949,'dus3','이세랑','','덕수중학교 1,2학년 학기말고사 기간입니다.','12월15일(월)~12월17일(수)까지 덕수중 학기말고사 기간입니다~ 시험대비 공부를 열심히 했습니다~ 시험기간동안 긴장하지 않고 잘 볼수있길 응원합니다^^          </td>
        </tr>',232,1765724400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37922,'dus3','이선주','dltjswn222@naver.com','[12월/10회기]충무스포츠센터 물개수영반 프로그램','<p>남산원 아동들 오늘도 수영 수업에 씩씩하게 참여했습니다!&nbsp;</p><p>먼저 준비 운동으로 몸을 풀고, 수영판을 들고 물에 들어가 한 명씩 돌아가며&nbsp;</p><p>자유형, 배영으로 번갈아가며 헤엄쳐 봤답니다.</p><p>수업 마지막에는 혹시 생길 근육통을 예방하기 위해 강사님과 함께 스트레칭도 않았습니다.&nbsp;</p><p>물개처럼 유연하게 수영하는 아이들의 모습이 정말 멋있습니다.^^</p>          </td>
        </tr>',235,1765378800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37890,'dus3','홍미진','ghdalwls0410@naver.com','[12월/9회기]충무스포츠센터 물개수영반 프로그램','<div>오늘은 12얼 9회기 수영활동 수업을 했습니다~~^^&nbsp;</div><div>준비운동 후 키판을 잡고 호흡과 함께 힘차게 발차기 하며 수영활동 시작 했는데요~~^^*</div><div>이제 제법 키판을 잡고 활동하는 것이 능숙해 보이고 아동들도 잘 하는 모습이었습니다.</div><div>처음보다 호흡을 길게 하며 발차는 모습도 힘 있어 보이고 실력도 많이 좋아졌습니다~~^^&nbsp;</div><div>오늘 수영수업도 다친 아동 없이 모두 잘 하였습니다^^!!</div>          </td>
        </tr>',245,1765206000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37871,'dus3','이선주','dltjswn222@naver.com','[12월/8회기]충무스포츠센터 물개수영반 프로그램','<p>남산원 아동들 오늘도 열심히 수영 수업에 참여했습니다^^</p><p>먼저 안전을 위해 준비하는 시간을 가진 뒤 수영판을 가지고 돌아가며 헤엄치기도 하고,</p><p>모든 수영 수업을 끝낸 뒤엔 몸이 놀라서 근육통이 생기지 않도록 스트레칭도 했답니다~</p><p>강사님의 지도하에 물개처럼 유연하게 수영하는 모습이 인상적입니다~</p><p><br></p>          </td>
        </tr>',241,1764774000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37855,'dus3','이주현','dlwngus0608@gmail.com','[12월/7회기]충무스포츠센터 물개수영반 프로그램','<p>12월 7회기 충무스포츠센터 물개수영반 프로그램에 김*, 소*, 박* 아동들이 참여하였습니다.</p><p>수영시작 전에 준비운동을 하고 호흡법과 발차기를 연습한 후에 아동 별로 자유형, 배영, 평형 등을 연습하였습니다 ^^&nbsp;</p><p>아동들이 열심히 수영을 연습하고 배우면서 즐겁게 웃는 모습이 참 기특합니다! 마무리도 잘 하고 정리도 잘 하는 아동들을 칭찬합니다 *^^*&nbsp;</p>          </td>
        </tr>',251,1764601200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37838,'dus3','오정복','jungbokoh@hanmail.net','[11월/6회기] 충무스포츠센터 물개수영반 프로그램','<p>11월 6회기 충무스포츠센터 물개수영반 프로그램에 박*,지*,윤*, 유*,유* 아동들이 참여하였습니다.</p><p>준비운동을 하고 발차기와, 호흡법을 익히고 자유형과 배영을 하였습니다.</p><p>서두르지 않고 정확한 동작을 하고 물 속에서도 대기하면서도 질서를 잘 지켰습니다.</p><p>유익하고 즐거운 수영프로그램에 참여하게 해주셔서 감사합니다.</p>          </td>
        </tr>',257,1764169200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37798,'dus3','오정복','jungbokoh@hanmail.net','[11월/4회기] 충무스포츠센터 물개수영반 프로그램','<p>11월 4회기 충무스포츠센터 물개수영반 프로그램에 박*, 김*, 소*, 정*, 최*, 윤* 아동들이 참여 하였습니다.</p><p>준비 운동과 자유형, 배영, 평형 발차기 까지 익숙한 것부터 새로 배우는 것까지 ~</p><p>수업에 참여하는 아이들이 진지하고 의젓합니다.</p><p>매일 성장하고 발전하는 아동들을 칭찬합니다.</p><p><br></p>          </td>
        </tr>',271,1763391600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37822,'dus3','이택인','tegin@naver.com','[11월/5회기] 충무스포츠센터 물개수영반 프로그램','<p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">11월 5회기 충무스포츠센터 물개수영반&nbsp;</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">프로그램에 정*, 최*, 소*, 김*, 박*, 박* 아동들이 참여 하였습니다.</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">수영장 물에 들어가기전에 준비운동과 스트레칭을 하고, 강사선생님 지도에</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">따라 아동들이 열심히 수영동작을 합니다. 완벽한 동작을 하기엔 아직 부족하지만</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">매일 성장하고 발전하는 아동들을 칭찬합니다.</p>          </td>
        </tr>',285,1763996400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37726,'dus3','홍미진','ghdalwls0410@naver.com','[11월/3회기] 충무스포츠센터 물개수영반 프로그램','<p>11월 3회기 수영수업입니다~~^^</p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">준비운동으로 시작하여 호흡하며 숨을 고르는 모습이 침착해 보였는데요~~^^*</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">발차기 연습하며 배형 자유형하며 순서지켜 활동하였습니다^^*</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">마지막으로 아이들이 좋아하는 자유활동으로 시간 보내며 활동 마무리하며&nbsp;</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">오늘 수영 수업도 즐겁고 행복한 시간이었습니다^^*</span></p>          </td>
