INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37700,'dus3','문소연','dawooriy3175@gmail.com','[11월/2회기] 충무스포츠센터 물개수영반 프로그램','<p>오늘은 충무스포츠센터 물개수영반 두번째 수업입니다~!</p><p>준비운동도 열심히 하고, 발차기, 음파 호흡법, 자유형까지 진지한 표정으로</p><p>수업에 임하는 우리 아이들의 모습이 멋있습니다 :)</p><p>새로운 수영을 배워 빨리 물고기처럼 수영하고 싶다고</p><p>말하는 우리 아이들이 귀엽기만 합니다 ^0^</p>          </td>
        </tr>',268,1762441200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37697,'dus3','홍미진','ghdalwls0410@naver.com','[11월/1회기] 충무스포츠센터 물개수영반 프로그램','<p class="0"><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">11</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">월 물개수영반 첫 수업인 만큼 </span></p><p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">오늘도 준비운동과 함께 힘차게 수영수업에 임하는 모습이 보였어요</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">~~~</span></p><p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">이제 제법 수영 실력이 많이 늘어 동작 하나 하나 잘하는 우리아동들입니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p><p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">호흡도 고르게 잘 하며 수영동작도 안정적으로 잘하는 모습이 대견스러웠습니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">^^</span></p><p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">마지막시간에는 아이들이 자유롭게 물놀이활동하며</span></p><p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">오늘하루도 즐겁고 알찬 수영수업이었습니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">^^*</span></p>          </td>
        </tr>',270,1762182000,'', '', '', '', '', '');
