INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37423,'dus3','이선주','dltjswn222@naver.com','[9월/5회기] 충무포츠센터 물개수영반 프로그램','<p>지난 수업에 이어서 오늘도 남산원 아동들 수영 수업에 참석했습니다.^^</p><p>충무 수영을 가기 전 부터 많은 기대감을 보이는 모습이 귀엽습니다.</p><p>아동들의 기대감만큼 수영 준비를 위한 샤워, 준비운동,</p><p>본격적인 수영 수업 모두 열심히 임하는 모습이 대견합니다.</p><p>남산원 아동들의 수영 실력이 쑥쑥 성장하기를 기원합니다.</p>          </td>
        </tr>',359,1758121200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37467,'dus3','김보영','qwert7337@naver.com','남산초등학교 요리프로그램 참여했습니다.(09.29.)','<div align=\'LEFT\'><a href=javascript:viewImg(\'2509290606258_1.jpg\');><img src=\'/admin/data/bbs/dus3/M2509290606258_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div><div align=\'LEFT\'><a href=javascript:viewImg(\'2509290606258_2.jpg\');><img src=\'/admin/data/bbs/dus3/M2509290606258_2.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
