INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37413,'dus3','오정복','jungbokoh@hanmail.net','[9월/4회기] 충무포츠센터 물개수영반 프로그램','<p style="color: rgb(132, 127, 116); font-family: verdana;">충무스포츠센터 물개수영반 프로그램에 참여 했습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">수영복을 챙기고 샤워 준비를 하는 아동들의 모습이 의젓합니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">준비 운동을 하고 각자 진도에 맞는 수영 실력을 뽐냈습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">새로운 영법을 익히기도 하고 속도를 빠르게 내기도 합니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">꾸준히 수업에 참여하고 성장하는 아동들을 칭찬합니다.</p>          </td>
        </tr>',316,1757948400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37394,'dus3','이새나','','[9월/3회기] 충무포츠센터 물개수영반 프로그램','<p>오늘도 즐거운 마음으로 수영 수업에 참여했습니다.</p><p>도착하여 수영장으로 들어가기까지 아동들은 스스로 수영복을 입고 챙기는 멋있는 모습을 보여줬습니다.</p><p>준비 운동을 마치고 호흡법, 발차기, 자유형, 배영 등을 배우며 처음보다 훨씬 나아진 수영 실력을 보여줬습니다.</p><p>아동들 스스로도 나아진 수영 실력에 대해 자신감 높은 모습을 보여 칭찬 해주었습니다.</p><p>다음 수업도 집중하여 잘 참여할 수 있도록 지도 하겠습니다. 열심히 잘하고 온 아동들을 매우 칭찬합니다.</p>          </td>
        </tr>',348,1757602800,'', '', '', '', '', '');
