INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37367,'dus3','김지현','wlgus1366@naver.com','[9월/2회기] 충무포츠센터 물개수영반 프로그램','<p>아동은 개학 후 오랜만에 수영을 간다는 소식에 들뜬 마음으로 하교하여 즐겁게 수영 준비물을 챙겼습니다~~<br>수영을 하기전 준비운동에도 열심히 참여하는 모습이 보기 좋았습니다!!<br>평소 물을 좋아하는 아동은 수업 내내 집중하며 적극적으로 활동에 임하였고 점차 늘어나는 수영 실력이 눈에 띄었습니다^ㅡ^</p><p>수업을 마친 뒤에도 환하게 웃으며 즐거워하는 모습에서 아동의 행복한 마음이 전해져 따듯함을 느낄 수 있었습니다^*^</p><p>무엇보다 아동이 다음 수영 수업도 손꼽아 기다리며 더 즐겁게 참여할 모습을 기대하게 됩니다~~</p>          </td>
        </tr>',350,1756911600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37364,'dus3','이택인','tegin@naver.com','[9월/1회기] 충무포츠센터 물개수영반 프로그램','<p>초등학교 개학하고 다시 시작하는 9월 첫주 충무스포츠센터 물개수영반 입니다.</p><p>오랜만에 수영장에와서 아동들 기분이 좋아 보입니다.&nbsp;</p><p>수영장 물 안으로 들어가기전에 준비운동을 충분히 하고 강사선생님 설명을 듣습니다.&nbsp;</p><p>노력하고 열심히 배우는 아동들 재미있는 즐거운 시간이었습니다.</p>          </td>
        </tr>',360,1756738800,'', '', '', '', '', '');
