INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37314,'dus3','이주향','hyangbird@hanmail.net','남산초등학교 개학했습니다(8월 22일/금).','<p style="color: rgb(132, 127, 116); font-family: verdana;">오늘은 남산초등학교가 개학하여 박*성, 박*진 아동이 등교했습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">여름방학 동안 신나게 놀아 피부도 새까맣게 타고 키도 훌쩍 크고,</p><p style="color: rgb(132, 127, 116); font-family: verdana;">무엇보다 캠프와 행사 참여로 다양한 경험을 할 수 있었습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;"><br></p><p style="color: rgb(132, 127, 116); font-family: verdana;">이제는 학교생활에 잘 적응하며 선생님 말씀에 귀 기울이고</p><p style="color: rgb(132, 127, 116); font-family: verdana;">학급 친구들과 잘 어울리고 공부도 열심히 할 수 있도록</p><p style="color: rgb(132, 127, 116); font-family: verdana;">적극적인 지원과 지지를 하여 더욱 성장할 수 있도록 하겠습니다.</p>          </td>
        </tr>',367,1755788400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37294,'dus3','김지은','','덕수중학교, 서울의료보건고 개학했습니다(8월 14일)','<p>즐거운 여름방학 알차게 보내고 덕수중학교, 서울의료보건고 아이들 개학했습니다.</p><p>한나방, 룻방, 다윗방 아동들 입니다.</p><p>2학기 학교생활이 시작됐는데 아이들 한 학기 생활도 성실하게 할 수 있도록 지도하겠습니다.^^</p><p><br></p>          </td>
        </tr>',395,1755615600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37224,'dus3','김지은','','룻방 한*아동성적향상금 지급받았습니다.','<p>룻방 한* 아동 성적향상금 지급받았습니다.</p><p>이번 1학기 기말고사에서 성적이 많이 올라 평균 75점으로 55,000원을 받았습니다.</p><p>2학기에도 우수한 성적으로 좋은 결과 얻을 수 있도록 지도하겠습니다.</p><p>축하합니다^^</p>          </td>
        </tr>',401,1754838000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37199,'dus3','양현주','','다윗방 박* 아동성적향상금 지급받았습니다.','<p>중학교에 다니고 있는 박* 아동은 이번 1학기 기말고사 시험 성적에서&nbsp;</p><p>평균 74점을 받아 성적향상금 54,000원을 지급받았습니다.&nbsp;</p><p>시험을 준비하느라 노력한 아동에게 칭찬과 상금을 수여하였고 앞으로도</p><p>성실하게 학교생활을 하며 좋은 성적을 거둘 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',404,1754578800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37118,'dus3','문소연','dawooriy3175@gmail.com','[7월/7회기] 충무스포츠센터 물개수영반 프로그램','<p>무더운 여름 시원한 수영 수업하러 가는 길을&nbsp;</p><p>여전히 들뜨기만 하는 우리 아이들입니다.</p><p>얕은 곳에서 수영하다가 깊은 곳에서 수영하니 더더욱 재미있다고&nbsp;</p><p>함박 웃음 짓는 아이들이 예쁘기만 합니다.</p><p><br></p>          </td>
        </tr>',449,1753455600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37117,'dus3','김규리','dawooriy3175@gmail.com','[7월/6회기] 충무스포츠센터 물개수영반 프로그램','<p>오늘은 우리 아이들 충무 스포츠센터 물개수영반 가는 날입니다.</p><p>준비운동을 한 뒤에 물속에 퐁당 들어가는 아이들입니다~</p><p>배영 수업도 하고, 자유형도 배워보는 시간을 가졌습니다.</p>          </td>
        </tr>',425,1753455600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37098,'dus3','양현주','','7월 23일 장충초등학교 방학했습니다.','<p>장충 초등학교에 다니고 있는 박** 아동 방학했습니다.</p><p>1학기 동안 함께 했던 친구들과 즐거운 방학을 보내자고 인사를 나누고</p><p>선생님께도 덕담을 들었습니다. 안전하고 즐거운 방학이 되도록 돕겠습니다.&nbsp;</p>          </td>
        </tr>',418,1753282800,'', '', '', '', '', '');
