INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37091,'dus3','김지은','','7월 24일 남산초 방학식했습니다','<p>남산초 방학식을 했습니다.</p><p>개학은 8월22일 금요일입니다~</p><p>오늘은 방학식날로 4교시를 하고 점심을 먹고 귀원했습니다.</p><p>여름방학기간 친구들과의 헤어짐은 아쉽지만 방학을 통해 부족한 운동도 하고, 학습도 하며&nbsp;</p><p>2학기를 잘 준비할 수 있도록 지도하겠습니다.</p><p>알찬 방학, 즐거운 방학이 될 수 있도록 지도하겠습니다^^</p>          </td>
        </tr>',391,1753282800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37089,'dus3','김형식','','7월21일 덕수중 방학했습니다.','<p class="0" style="color: rgb(132, 127, 116); font-family: verdana;"><span style="margin: 0px; padding: 0px; font-family: 돋움체, DotumChe, AppleGothic;">덕수중에 다니고 있는 다윗 이*민</span><span style="margin: 0px; padding: 0px; font-family: 돋움체, DotumChe, AppleGothic;">&nbsp;아동 여름방학식 했습니다.&nbsp;</span></p><p class="0" style="color: rgb(132, 127, 116); font-family: verdana;"><span style="margin: 0px; padding: 0px; font-family: 돋움체, DotumChe, AppleGothic;">여름방학 기간(</span><span lang="EN-US" style="margin: 0px; padding: 0px; letter-spacing: 0pt; font-family: 돋움체, DotumChe, AppleGothic;">7/22(</span><span style="margin: 0px; padding: 0px; font-family: 돋움체, DotumChe, AppleGothic;">화</span><span lang="EN-US" style="margin: 0px; padding: 0px; letter-spacing: 0pt; font-family: 돋움체, DotumChe, AppleGothic;">)~8/13(수))동안 알차게 보내도록 지원하겠습니다!!</span></p>          </td>
