INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37087,'dus3','이세랑','rheese1228@naver.com','7월 21일 덕수중 여름방학식 했습니다.','<p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">덕수중에 재학중인 한나방 연</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">*,</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">고</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">* </span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">두 아동은 오늘 여름방학식 했습니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span></p><p class="0"><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">7/22(</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">화</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">)~8/13(</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">수</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">)</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">까지 여름방학 기간입니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span></p><p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">한학기를 잘 마무리 해봅니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">.</span><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">방학기간 동안 아동들이 유익하고 즐거운 시간을 보낼 수 있도록 지원하겠습니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">!!</span></p>          </td>
        </tr>',387,1753023600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37067,'dus3','홍영지','youngzzji@gmail.com','7월 18일 서의보고 여름방학식 했습니다.','<p>룻방 한* 아동이 하계 보건실습을 열심히 진행중인 가운데</p><p>서울의료보건고 여름방학이 시작되었습니다.</p><p>방학동안 더 알차고 바쁜 하루하루를 보낼 아동이</p><p>실습 마무리 잘 지을 수 있도록 지원하겠습니다!</p>          </td>
        </tr>',418,1752764400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37059,'dus3','문소연','dawooriy3175@gmail.com','다윗방 환일중 아동들 여름방학식을 했습니다.','<p>오늘 환일중에 다니는 다윗방 아동들이 여름방학식을 했습니다.</p><p>오늘부터 8월 18일까지 약 한 달동안 여름방학을 가지는데요,</p><p>여름방학동안 2학기 문제집도 미리 풀어보며 예, 복습 열심히 하고</p><p>열심히 물놀이도 하며 재미있게 여름방학을 보낼 수 있도록&nbsp;</p><p>옆에서 지원하겠습니다.</p>          </td>
        </tr>',409,1752591600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37058,'dus3','오정복','jungbokoh@hanmail.net','[7월/5회기] 충무스포츠센터 물개수영반 프로그램','<p>준비운동 하고~~</p><p>발차기, 숨쉬기, 줄 맞춰서 앞으로 나아가기를 익숙하게 합니다.</p><p>물 속에서 자유롭게 움직이는 아이들의 표정도 밝습니다.</p><p>스스로 수영 도구를 준비하고 챙기는 의젓한 물개수영반입니다.</p>          </td>
        </tr>',426,1752591600,'', '', '', '', '', '');
