INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37037,'dus3','홍영지','youngzzji@gmail.com','룻방 한* 아동 하계 간호 실습 진행합니다.','<p>07월 14일, 서의보고 재학 중인 한* 아동 하계 간호 실습 시작했습니다.</p><p>(25.07.14~08.14 총 24일, 192시간)</p><p>앞으로 한 달동안 병원으로 출, 퇴근을 하며&nbsp;</p><p>이론으로 배운 것을 현장에서 실습하게 되는데요!</p><p>아동은 실습 조에서 반장을 맡았다며 걱정과 설렘 모두 안고 첫 실습에 나섰습니다.</p><p>평소 밝고 상냥한 아동의 성향이 뒷받침되어&nbsp;</p><p>새로운 환경에서도 잘 해냈으면 좋겠습니다.</p><p>한* 아동이 실습 끝까지 잘 마무리하길 응원합니다 :)</p>          </td>
        </tr>',431,1752418800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37023,'dus3','김보영','qwert7337@naver.com','[7월/4회기] 충무스포츠센터 물개수영반 프로그램','<p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">무더운 날씨지만 아동들 모두 즐거운 마음으로</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">수영 프로그램 다녀왔습니다.</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">집중하여 스트레칭 동착을 마친 후 키판 잡기를 통해</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">시원한 물속에서의 시간 가졌습니다~^^</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">자유형 연습도 하고 반복 동작을 통해 열심히 하는</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">아동들의 모습이 너무 기특합니다.</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">물 위에 뜨려고 열심히 발차기하면서 자유형을 연습했습니다.</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">서로 어려워하는 동작들은 알려주기도 하며 규칙을 지켜 열심히 하였습니다.</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">더운 날씨에도 나날이 열심히 해주는 아동들 다음에도 멋진 수업 기대해봅니다~!</p>          </td>
        </tr>',422,1752073200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37021,'dus3','홍영지','youngzzji@gmail.com','7월 10일 서의보고 기말고사 끝났습니다.','<p>7월 10일, 서울의료보건고등학교 1학기 기말고사 끝났습니다.</p><p>열대야가 이어지는 무더운 날씨에도</p><p>늦은 시간까지 열심히 시험 준비한 한* 아동 고생 많았어요!</p><p>다음 주부터 시작될 하계 실습도 응원합니다 :)</p>          </td>
        </tr>',458,1752073200,'', '', '', '', '', '');
