INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37010,'dus3','홍영지','youngzzji@gmail.com','[7월/3회기] 충무스포츠센터 물개수영반 프로그램','<p>무더운 날씨가 이어지는 가운데 오늘도 물개수영 프로그램 참여하러</p><p>수영장을 다녀왔습니다!</p><p>오늘도 어김없이 몸풀기를 열심히 하고 킥판을 잡고 물속으로 들어갑니다.</p><p>물 위에 뜨려고 열심히 발차기하면서 자유형을 연습했습니다.</p><p>자신의 레인에서 줄을 지어 자유형하며 질서있게 수영하는 모습이 기특합니다.</p><p>팔을 젓는 모습이 아직 어색하기도 하지만</p><p>물속에서 꽤 오랜 시간 숨을 참기도 하는 걸 보니 대견했습니다.</p><p>다음 시간에 조금 더 발전해있을 아동들의 모습이 기대됩니다!</p>          </td>
        </tr>',411,1751900400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (37009,'dus3','홍영지','youngzzji@gmail.com','바울방 정* 아동 남산초 어울림 골프 수업 모범상 받았습니다.','<p>바울방 정* 아동 학교에서 진행되는 골프 수업에 열심히 참여하더니</p><p>성실한 태도를 보여 모범상 받았습니다!</p><p>상장을 받고 정말 기뻐하며 자랑했던 아동인데요!</p><p>앞으로도 다양한 활동에서 모범이 되도록 노력하는 아동이 되길 바랍니다 :)</p>          </td>
        </tr>',425,1751900400,'', '', '', '', '', '');
