INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36987,'dus3','이세랑','','7월 4일 덕수중기말고사 끝났습니다.','<p>7/2(화)~7/4(금) 3일간 진행했던 덕수중 기말고사가 끝났습니다.&nbsp;</p><p>1학년들은 다양한 진로 체험을 하였고&nbsp;</p><p>2학년은 준비한 만큼 열심히 시험을 잘 보았습니다^^&nbsp;</p><p>평소 틈틈히 공부하고 노력하는 모습이 대견한 아동입니다~&nbsp;</p><p>수고했어요~~&nbsp;</p>          </td>
        </tr>',442,1751554800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36984,'dus3','오정복','jungbokoh@hanmail.net','[7월2회기] 충무스포츠센터 물개수영반 프로그램','<p>꾸준히 수영 강습을 받은 아동들이 수심이 깊은 곳에서 수영을 했습니다.</p><p>강습 받은 대로 팔을 젓고 호흡을 하며 저마다 진지하게 연습 합니다.</p><p>조금씩 늘어가는 수영 실력을 보며 거침없이 물살을 가로지르는 모습을 기대합니다.</p>          </td>
        </tr>',424,1751468400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36976,'dus3','김지은','','7월 2일 덕수중기말고사 시작됐습니다.','<p>덕수중학교 기말고사가 시작되었습니다.</p><p>7월 2일부터 4일까지 3일간 진행됩니다.</p><p>중학교 1학년 아동들은 시험을 보지 않아 진로탐색활동을 시작합니다.</p><p>아동들 1학기의 마지막 기말고사 잘 준비할 수 있도록 지도하겠습니다.</p><p><br></p>          </td>
        </tr>',429,1751468400,'', '', '', '', '', '');
