INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36970,'dus3','김형식','','[7월1회기] 충무스포츠센터 물개수영반 프로그램','<p style="color: rgb(132, 127, 116); font-family: verdana;">매주 화, 목에 진행하는 물개수영반!&nbsp;</p><p style="color: rgb(132, 127, 116); font-family: verdana;">아이들의 만족도가 무척이나 높습니다~~</p><p style="color: rgb(132, 127, 116); font-family: verdana;">수영 수업에 들어가기 전 몸풀기를 열심히 따라하고</p><p style="color: rgb(132, 127, 116); font-family: verdana;">물 속으로 들어가 레인 안에 줄을 지어 호흡법을 하면서 수영을 배웁니다</p><p style="color: rgb(132, 127, 116); font-family: verdana;">수업 마치기 전 자유 시간도 맘껏 즐깁니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">만족도가 높은 만큼 배움의 깊이가 더해가기를 기대해 봅니다 ^^</p>          </td>
        </tr>',403,1751295600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36948,'dus3','홍영지','youngzzji@gmail.com','[6월/5회기] 충무스포츠센터 물개수영반 프로그램','<p>수영장에 도착해 수영 수업 들어갈 준비를 스스로 하는 아동들!</p><p>수영 수업에 들어가기 전 몸풀기를 열심히 따라하고</p><p>물 속으로 들어가 레인 안에 줄을 지어 호흡법을 하면서 수영을 해봅니다.&nbsp;</p><p>오늘은 6월 마지막 수업으로 자유시간도 가졌습니다.</p><p>킥판을 잡고 배운 수영을 뽐내기도 하고&nbsp;</p><p>배영처럼 물 위에 누워 떠다니며 뿌듯해하기도 합니다.</p><p>아동들에게 앞으로도 의미있는 배움의 시간이 되길 바랍니다 :)</p>          </td>
        </tr>',397,1750863600,'', '', '', '', '', '');
