INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36937,'dus3','문소연','dawooriy3175@gmail.com','[6월/4회기] 충무스포츠센터 물개수영반 프로그램','<p>오늘 우리 아이들</p><p>언제나 그랬듯 수영장 가는 것에 매우 들떠있는 아이들입니다.</p><p>오늘은 수영 수업 시간에 얕은 수영장이 아닌</p><p>약간 깊이가 있는 수영장에서 배영을 배웠는데요,</p><p>처음엔 덜컥 겁이 났지만 점차 적응했는지</p><p>점점 미소를 띠는 아이들입니다 :)</p>          </td>
        </tr>',420,1750777200,'', '', '', '', '', '');
