INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36900,'dus3','김지은','','[6월/3회기] 충무스포츠센터 물개수영반 프로그램','<p>오늘은 즐거운 수영하는 날!</p><p>충무스포츠센터에 가서 수영 프로그램에 참여했습니다.</p><p>준비운동을 한 후 신나게 수영을 했습니다.</p><p>반복되는 연습을 하며 아이들 실력이 조금씩 늘고 있습니다.</p><p>오늘도 어김없이 음파 호흡법과 발차기를 했습니다.^^</p><p>팔돌리기, 배영, 자유형도 배웠습니다.</p><p>꾸준하게 참여하며 배울 수 있도록 지도하겠습니다.</p><p><br></p>          </td>
        </tr>',441,1750086000,'', '', '', '', '', '');
