INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36870,'dus3','문소연','dawooriy3175@gmail.com','[6월/2회기] 충무스포츠센터 물개수영반 프로그램','<p>어느덧 6월 중순으로 가고있는 날입니다.</p><p>뜨거운 햇빛을 피해 시원한 물로 풍덩하는 아이들 얼굴에는</p><p>미소가 떠나질 않습니다.</p><p>오늘 음파 호흡법, 발차기를 배웠습니다.</p><p>처음에는 물이 무섭고 호흡 하는 방법을 잘 몰랐던 아이들이지만</p><p>지금 우리 아이들은 누구보다 물을 즐기고 두려워하지 않는</p><p>아이들이 되었습니다 :)</p>          </td>
        </tr>',425,1749740400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36831,'dus3','이새나','','[6월/1회기] 충무스포츠센터 물개수영반 프로그램','<p>이제 진짜 여름이 되었습니다.&nbsp;</p><p>수영 수업에 참여하는 아동들은 더운 날씨 탓에 수영을 하러 가는 것을 설레여 했습니다.</p><p>수영 수업 전 준비 운동을 한 뒤, 호흡법을 배웠습니다.</p><p>이후 배영 연습과 팔 돌리기 등 기본 동작들을 배우며 기본기를 더욱 더 탄탄하게 연습했습니다.</p><p>아동들 모두 이번 여름에 수영장에 가서 수영 수업에서 배웠던 기본 동작들을 쓰며&nbsp;</p><p>재미있게 놀 수 있었으면 좋겠습니다. 다치지 않고 즐겁게 수영 수업을 배울 수 있도록 지도하겠습니다.</p><p><br></p>          </td>
        </tr>',463,1749135600,'', '', '', '', '', '');
