INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36803,'dus3','오정복','jungbokoh@hanmail.net','[5월/7회기] 충무스포츠센터 물개수영반 프로그램','<p>물개수영반 프로그램에 참여한 아이들이 각자의 레인에서 힘차게 발차기를 하며 앞으로 나아갑니다.<br>
아직 호흡이 완전히 익숙하진 않지만, 팔 돌리기와 함께 한 동작씩 차근차근 열심히 연습해 나갑니다.<br>
배영을 배우기 위해 물 위에 몸을 눕히고 용기를 내어 힘을 빼는 모습에서도 아이들의 성장과 노력이 느껴집니다.<br>
조금 더 배우고, 조금 더 자라나는 아이들의 모습이 참 멋집니다.</p>&nbsp;          </td>
        </tr>',463,1748444400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36800,'dus3','박현정','','[5월/6회기] 충무스포츠센터 물개수영반 프로그램','<p>* 수영장이 익숙해지고, 아동들도 더 성장해가고 있습니다.</p><p><br></p><p>&nbsp; 오늘은 안전가드를 하고, 앞으로 나아가기, 올바른 자세 익히기 등</p><p>&nbsp;</p><p>&nbsp; 수영을 배웠습니다.&nbsp;</p><p><br></p><p>&nbsp; 수영 실력도 점점 쌓여가고 있습니다. 감사합니다.&nbsp;</p>          </td>
