INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36764,'dus3','장영호','yeongho11@naver.com','[5월/5회기] 충무스포츠센터 물개수영반 프로그램','<p>날씨가 많이 더워졌습니다.&nbsp;</p><p>그래서 그런지 오늘 수영수업에 참여하는 아동들의 모습이 즐거운 물놀이를 가는&nbsp;</p><p>모습이었습니다.</p><p>준비운동을 마치고 물속으로 첨벙첨벙 들어가서 수업준비를 합니다.</p><p>발차기, 팔돌리기 등 기본동작들을 하며 열심히 수업에 임합니다.</p><p>이제 자주 물과 접할 수 있는 계절이므로 좀 더 열심히 연습해서&nbsp;</p><p>이번 여름에 수영실력을 뽐내기를 바랍니다.</p><p>더욱 더 잘하고 즐겁게 수영을 하도록 옆에서 지도하도록 하겠습니다.</p>          </td>
        </tr>',475,1747839600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36747,'dus3','김나예','nayea22@gmail.com','[5월/4회기] 충무스포츠센터 물개수영반 프로그램','<p>오늘도 아동들은 수영을 배우러 다녀왔습니다.&nbsp;</p><p>특별히 오늘은 5학년 아동들만 참석했는데요~ 의젓하게 배우는 모습이 기특합니다.</p><p>준비운동과 음파음파를 시작으로 배영을 배웠습니다.&nbsp;</p><p>수업 후 짧은 자유시간도 주셔서 재밌게 물장구를 친 아동들입니다.&nbsp;</p><p>돌아오는 길에 배영이 늘었냐고 물어보니 어깨를 으쓱이는 아동들입니다:)</p><p>날로 성장할 아동들의 실력을 기대해봅니다~!</p>          </td>
        </tr>',474,1747666800,'', '', '', '', '', '');
