INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36712,'dus3','양현주','','[5월/2회기] 충무스포츠센터 물개수영반 프로그램','<p>오늘은 음파, 자유형, 배영 수업을 했습니다.</p><p>아동들이 수영을 하러 가는 시간은 언제나 즐겁습니다.</p><p>아직 음파가 어렵다고 이야기하는 유*나 아동에게</p><p>열심히 하다 보면 할 수 있다고 격려해 주었습니다.</p><p>벌써 배영을 배우고 있다는 지* 아동은 자신감이 붙어</p><p>이번 여름에 수영장에 가서도 실력을 맘껏 뽐낼 것 같습니다.</p><p><br></p>          </td>
        </tr>',433,1747148400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36721,'dus3','이경숙','lksabs@naver.com','[5월/3회기] 충무스포츠센터 물개수영반 프로그램','<p>오늘은 충무스포츠센터 물개 수영반 5월/3회기 수업입니다.</p><p>4, 5학년 현장 학습으로 많은 인원이 참여하지는 못했지만 즐겁게 수영을 하러 갔습니다.</p><p>준비운동으로 팔, 다리, 전신의 몸을 푼 후 물에 들어가 움직이기 시작합니다.&nbsp;</p><p>키판으로 물을 튀기고 장난을 치는 아동도 있지만 열심히 발차기를 하며 팔을 돌리는 아동도 있습니다.&nbsp;</p><p>돌아오는 차 안에서 수영실력이 좋아졌다며 다음 단계로 간다는 아동에게 열심히 연습한 결과라고 칭찬하고 독려하였습니다.</p><p><br></p><p>얘들아, 선생님께 배운 대로 열심히 연습해서 더운 여름에 수영장에서 재미나게 놀자!</p>          </td>
        </tr>',463,1747234800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36689,'dus3','문소연','dawooriy3175@gmail.com','[5월/1회기] 충무스포츠센터 물개수영반 프로그램','<p style="color: rgb(132, 127, 116); font-family: verdana;">오늘 물개 수영반 5월 1회기 수업 하는 날입니다~</p><p style="color: rgb(132, 127, 116); font-family: verdana;">여전히 수영장으로 가는 차 안에서 한껏 들떠 왁자지껄 떠드는 아이들이 귀엽기만합니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">오늘 수업 시간에는 음파 호흡법, 팔 돌리기, 물 속에서 발차기 하는 법을 배웠습니다 :)</p>          </td>
        </tr>',451,1746716400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36657,'dus3','김지은','','환일중, 덕수중, 서울의료보건고 시험끝났습니다.','<p style="color: rgb(132, 127, 116); font-family: verdana;">4월 29일 화요일부터 시작한 아동들의 중간고사가 끝났습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">환일중, 덕수증, 서울의료보건고 아동들 시험을 준비하느라 고생많았습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">결과는 아직 나오지 않았지만 원하는 결과 얻기를 바랍니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">오늘부터 시작된 연휴도 즐겁게 보낼수 있기를 바랍니다~</p>          </td>
        </tr>',516,1746198000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36627,'dus3','김보영','qwert7337@naver.com','[4월/6회기] 충무스포츠센터 물개수영반 프로그램','<p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">오늘은 4월 마지막 수업으로</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">아동들 모두 수업 시간에 더 집중하는 모습을 보였습니다.</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">오늘은 많은 아동들이 참여해주었는데요!</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">그럼에도 불구하고 배영, 팔돌리기 등</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">다양한 동작들을 유연하게 잘 소화하는 모습 보였습니다~^^</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">물장구도 쳐보며 나날이 물과 가까워지는 아동들의 모습이 보기 좋습니다.</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">동작이 어려운 아동들은 서로 도와가며</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">챙기는 모습도 참 기특했습니다.</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">5월에 진행될 수영 수업도 아동들의 더 멋진 모습 기대해봅니다~!</p>          </td>
        </tr>',480,1745852400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36636,'dus3','김지은','','환일중, 덕수중, 서울의료보건고 시험기간입니다','<p>4월 29일 화요일부터 아동들의 1학기 중간고사가 시작되었습니다.</p><p>서울의료보건고등학교는 4.29(화)~5.2(금)</p><p>환일중학교는 4.30(수)~5.2(금)</p><p>덕수중학교는 4.30(수)~5.1(목)까지 시험을 봅니다.</p><p>새학년 새학기 첫 중간고사!!</p><p>아동들이 준비하며 노력한 만큼의 성적을 거둘 수 있길 바랍니다!</p><p>화이팅!^^</p><p><br></p>          </td>
        </tr>',498,1746025200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36590,'dus3','장영호','yeongho11@naver.com','[4월/5회기]충무스포츠센터 물개수영반 수업','<p>오늘 수업은 발차기, 팔돌리기를 중점적으로 수업하였습니다.</p><p>몸풀기를 시작으로 발차기를 하였고 바로 팔돌리기 동작을 진행하였습니다.</p><p>이전보다 동작들이 훨씬 부드럽고 유연합니다.</p><p>이렇게 40분 가량 수업을 진행하였고 남은 10분은 자유수영을 하였습니다.</p><p>그 시간은 서로 장난도 하고 다른 동작들도 연습해보는&nbsp; 즐거운 시간입니다.</p><p>오늘도 열심히 수업에 참여한 우리 아동들이 대견하고 조금씩 실력이 느는것을 볼 수 있었습니다.</p><p>앞으로도 더 열심히 하여 원하는 결과를 거두기를 기대합니다.</p><p><br></p>          </td>
        </tr>',471,1745247600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36568,'dus3','이택인','tegin@naver.com','[4월/4회기]충무스포츠센터 물개수영반 참여','<p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">매주 화/목 충무스포츠센터에서 진행하는 물개수영반 4월/4회기 수업 참여했습니다.</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">아동들은 수영장에 들어와 수영 지도교사의 지도에 따라 준비운동으로 충분히 몸의&nbsp;</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">긴장을 풀어주고, 수영장 물 안으로 들어가 수영을 시작합니다.</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">킥판을 이용해 자유형 연습을 하는 아동들 제법 자세가 잡혀 보입니다. 열심히 수영 수업을 &nbsp;</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">하고, 교사에게 다가와 제가 수영하는 모습 보셨냐고 잘하지 않냐며 자랑하는 모습에&nbsp;</p><p style="caret-color: rgb(132, 127, 116); color: rgb(132, 127, 116); font-family: verdana; -webkit-text-size-adjust: auto;">칭찬을 아끼지 않았습니다. 아동들이 꾸준히 참여 할 수 있도록 격려하고 지원하겠습니다.</p>          </td>
        </tr>',513,1744815600,'', '', '', '', '', '');
