INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36566,'dus3','최수미','bluemi6677@naver.com','[4월/3회기] 충무스포츠센터 물개수영반 프로그램','<p>물개반 아동들 금일도 씩씩하게 수업 참여하고 왔습니다!</p><p><br></p><p>준비운동 후 킥판을 이용해서 발로 물장구를 쳤습니다.&nbsp;</p><p><br></p><p>자유형의 기초 자세 고개 숙이기와 팔 돌리기도 하며&nbsp;</p><p><br></p><p>열심히 수영을 배우는 모습을 보였습니다.&nbsp;</p><p><br></p><p>수영을 통하여 체력증진과 또래와의 단체 활동을 통한&nbsp;</p><p><br></p><p>사회성을 향상할 수 있는 좋은 시간이었습니다.</p>          </td>
        </tr>',486,1744729200,'', '', '', '', '', '');
