INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36517,'dus3','김형식','','[4월/2회기]충무스포츠센터 물개수영반 참여','<p style="color: rgb(132, 127, 116); font-family: verdana;"><br></p><p style="color: rgb(132, 127, 116); font-family: verdana;">매주 화/목 충무스포츠센터에서 진행하는 물개수영반 참여했습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">매번 진행되는 시간이지만 수영 가기 전부터 한껏 들떠 있는 아이들이 귀엽기만 합니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">음파 수영법과 한 발로 서서 발차기도 했습니다~!</p><p style="color: rgb(132, 127, 116); font-family: verdana;">아이들의 수영 실력이 점점 늘고 있고, 아이들도 스스로 느끼고&nbsp;</p><p style="color: rgb(132, 127, 116); font-family: verdana;">신기해하는 표정을 지으며 열심히 참여하고 있습니다. *^^*</p>          </td>
        </tr>',501,1744124400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36515,'dus3','문소연','dawooriy3175@gmail.com','[4월/1회기] 충무스포츠센터 물개수영반 프로그램','<p>오늘 물개 수영반 4월 1회기 수업 하는 날이었습니다~!</p><p>우리 아이들 수영 가기 전부터 한껏 들떠 있는 아이들이 귀엽기만 합니다.</p><p>음파 수영법과 한 발로 서서 발차기도 했습니다~!</p><p>아이들의 수영 실력이 점점 늘고 있고, 아이들도 스스로 느끼고&nbsp;</p><p>신기해하는 표정을 짓는 우리 아이들입니다 *^^*</p>          </td>
        </tr>',501,1744038000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36491,'dus3','오정복','jungbokoh@hanmail.net','솔로몬방 박*주 전교부회장 임명장 받았습니다.','<p>밝고 유쾌한 박*주 아동이 전교 부회장이 되었습니다.</p><p>학교 생활을 열심히 하는 박*주 아동을 칭찬합니다.</p><p>전교 부회장 일을 잘 할 수 있도록 격려하고 지원하겠습니다.</p>          </td>
        </tr>',561,1743433200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36461,'dus3','장영호','yeongho11@naver.com','[3월/8회기]  충무스포츠센터 물개수영반','<p>오늘은 3월 마지막 수업입니다.</p><p>수업내용으로 발차기, 음파발차기, 팔돌리기를 하였습니다.</p><p>복습차원에서 여유롭게 배웠던 대로 수업을 마쳤습니다.</p><p>그리고 수업을 마친 후 자유놀이 시간을 가졌습니다.&nbsp;</p><p>서로 물을 뿌리며 장난도 치고 잠수도 하며 각자 방식대로 즐겁게</p><p>물놀이를 하였습니다.</p><p>이렇게 3월의 마지막 수영수업을 마쳤고 다음달 4월부터 새로운 마음가짐으로</p><p>열심히 수영을 할 계획입니다.</p><p>앞으로도 열심히 해서 우리가 바라던 대로 월등한 수영 실력을 쌓도록 하겠습니다.</p><p><br></p>          </td>
        </tr>',551,1743001200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36454,'dus3','오정복','jungbokoh@hanmail.net','[3월/7회기] 충무스포츠센터 물개수영반 프로그램','<p>수영 7회기를 진행하였습니다.</p><p>준비 운동을 하고 키판 잡고 돌기를 하니 물이 익숙집니다.</p><p>키판 잡고 하는 호흡법을 배우고 배영도 하였습니다.</p><p>키판을 놓고 속도 내서 수영 할 수 있으면 좋겠다고 이야기하며 돌아왔습니다.</p><p><br></p>          </td>
        </tr>',551,1742828400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36432,'dus3','홍미진','ghdalwls0410@naver.com','[3월/6회기] 충무스포츠센터 물개수영반 프로그램','<p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">오늘은 벌써 수영수업을 시작한지 6회기입니다~^^*</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">오늘도 준비운동과 함께 힘차게 수영수업에 임하는 모습이 보였어요~~~</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">호흡법을 하는 중간 중간 고르게 숨을 쉬고 내쉬며&nbsp;</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">자유롭게 수영하는 모습들이 전보다 실력이 많이 늘어 아낌없이 칭찬해주었어요^^</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">자유형을 연습하는 부분에도 배형도 스스로 연습하며 곧잘 하며&nbsp;</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">아동들 전반적으로 수영하는 실력이 많이 늘고 아동들도 수영수업에 즐겁게 참여하며</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">오늘하루도 즐겁고 알찬 수영수업이었습니다^^*</span></p>          </td>
        </tr>',510,1742396400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36431,'dus3','김지은','','3월 4일 덕수중, 환일중 시업식 및 입학식했습니다.','<p>3월 4일날 덕수중과 환일중 시업식과 입학식을 했습니다.</p><p>환일중, 덕수중 1학년으로 입학한 아동들도 있어 입학식을 강당에서 진행한 후 교실활동을 했습니다.</p><p>새로운 첫 출발을 시작한 아동들을 응원합니다.</p><p>승급한 아동들은 고학년 생활에 잘 적응하며 이겨내길 바랍니다.</p><p>아동들 모두 학교생활 잘 해나갈 수 있도록 지도하겠습니다.^^</p>          </td>
        </tr>',504,1742396400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36426,'dus3','양현주','','[3월/5회기] 충무스포츠센터 물개수영반 프로그램','<p>물개반 아동들 금일도 씩씩하게 수업 참여하고 왔습니다!</p><p>호흡(음파), 발차기를 하다 최근에 팔 돌리기를 배우기 시작하여</p><p>열정이 가득한 아동들입니다 ^^</p><p>수영을 다녀와서는 배가 많이 고픈지 귀원하는 차량에서 먹고 싶은 음식을</p><p>여러 개 이야기하는 아동들이 귀엽습니다 ㅎㅎ</p><p>여름이 다가오고 있으니 열심히 배워서 즐겁게 수영하자!</p>          </td>
        </tr>',786,1742223600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36392,'dus3','홍미진','ghdalwls0410@naver.com','[3월/4회기] 충무스포츠센터 물개수영반 프로그램','<p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">오늘은 4번째 수영수업인데요~ 시작 전 준비운동부터 시작하여&nbsp;</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">아이들 모두 적극적으로 참여하는 모습이보였어요~~^^</span><span lang="EN-US" style="mso-fareast-font-family:굴림;font-family:굴림;mso-ascii-font-family:굴림;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">&nbsp;</span></p><p class="0"><span style="font-family:굴림;mso-fareast-font-family:굴림;">일전에 아이들이 수영수업에서 배웠던&nbsp;</span></p><p class="0"><span style="font-family: 굴림;">수업과 겹쳐 아이들이 이번 수영수업에는 좀 더 쉽고 재미있게 참여하는 모습이 보였어요~~^^*</span><span lang="EN-US" style="font-family: 굴림; letter-spacing: 0pt;">&nbsp;</span></p><p class="0"><span style="font-family: 굴림;">수영 중 호흡도 많이 길어지고 물속에 깊게 있는 모습이 보였고</span></p><p class="0"><span style="font-family: 굴림;">자유형도 곧잘 하며 재미있게 수업에참여하며 오늘하루도 알차고 보람있는 수업이였어요~~^^*</span></p>          </td>
        </tr>',524,1741791600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36389,'dus3','장영호','yeongho11@naver.com','[3월/3회기] 충무스포츠센터 물개수영반 프로그램','<p>오늘은 3번째 수업입니다.</p><p>아동들 모두 선생님의 지도하에 열심히 수업에 임합니다.</p><p>선생님께서 기본적인 것이 가장 중요하다는것을 아동들에게 얘기하며 발차기의 중요성을 또다시</p><p>강조하십니다.</p><p>모든 아동들이 지난시간에 이어 발차기연습을 합니다. 확실히 지난 시간보다 많이 좋아졌고</p><p>속도도 빨라졌습니다. 이제 힘내서 조금만 더 발차기를 연습한다면 다음 단계로 금방 나갈 수 있을것 같습니다.</p><p>오늘은 반복하여 발차기를 연습하였지만 다음시간부터는 본격적으로 수영을 배우게 됩니다.</p><p>너무나 즐겁게 하하호호하며 수업을 마쳤습니다.</p><p>몸은 지쳤지만 신나고 즐거운 수업이었고 다음시간을 또 기대해 봅니다~&nbsp;</p>          </td>
        </tr>',516,1741618800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36375,'dus3','김나예','nayea22@gmail.com','솔로몬방 정*현 아동이 남산초 유치원에 입학했습니다.','<p>3월 4일 정*현 아동이 필동어린이집을 수료하고 남산초 유치원에 입학했습니다.</p><p><br></p><p>애교가 많고 붙임성이 좋은 성격으로 입학식에서도 새로운 친구들과 선생님들을 만나도 밝은 모습이었습니다.</p><p>유치원이라는 또다른 생활에서 여러가지를 배울 앞으로의 생활이 기다려집니다.</p><p>씩씩하고 건강한 유치원 생활이 되길 소망합니다.</p>          </td>
        </tr>',553,1741359600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36355,'dus3','양현주','','3월 4일 남산초 신학기 시작했습니다.','<p>새 학년 새 학기가 시작 되었습니다.</p><p>1학년 동생들이 초등학교에 입학하게 되었고</p><p>5학년 언니들이 6학년에 진급하게 되었습니다.</p><p>새로운 친구들과 새로운 담임선생님도 만나고&nbsp;</p><p>모든 게 새로운 하루였습니다.</p><p>앞으로 새로 시작하는 1년을 응원하며!</p><p>긍정적인 마음으로 지도하도록 하겠습니다.&nbsp;</p>          </td>
        </tr>',535,1741014000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36358,'dus3','최준희','ch3596@hanmail.net','모세방 유*인, 임*하 아동 남산초 입학했습니다.','<table width="100%" border="0" cellpadding="0" cellspacing="0" style="color: rgb(132, 127, 116); line-height: 19.2px; font-family: verdana;"><tbody><tr><td height="50" colspan="4" style="line-height: 19.2px;"><table width="100%" border="0" cellpadding="10" cellspacing="0" style="line-height: 19.2px;"><tbody><tr><td align="left" style="line-height: 19.2px; padding-top: 5px;"><p>모세방 임*하, 유*인 아동이 언니 오빠들을 따라 남산초에 입학했습니다!</p><p><br></p><p>유치원으로 걸어갈 것 같은 아이들이 벌써 초등학생이 되었다는 것이 기특합니다.&nbsp;</p><p>12월부터 곧 초등학교에 들어간다며 내내 설레하던 아동들이 드디어 초등학교 문턱을 넘었습니다.</p><p>언니 오빠들을 따라 학교에서 선생님들의 가르침을 받고, 더 멋진 언니들로 성장하길 기대합니다^^</p></td></tr></tbody>',569,1741100400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36258,'dus3','김지은','','2월 14일 남산초 종업식 했습니다','<p>남산초 종업식 했습니다.</p><p>친구들, 선생님과 인사 나누고 마지막 수업도 잘 마치며 1년간 사용한 짐도 모두 챙겨왔습니다.</p><p>3월 3일 새학년 맞이 잘준비하도록 지도하겠습니다.</p>          </td>
        </tr>',561,1739545200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36255,'dus3','문소연','dawooriy3175@gmail.com','룻방 박*리, 연*빈 아동 졸업식을 했습니다.','<p>오늘 우리 룻방 *리와 *빈이가 초등학교 졸업식을 했습니다.</p><p>6년간의 학습을 무사히 끝내고 학사모를 쓴 우리 아이들을 보니</p><p>아이들이 성장했음을 새삼 느끼는 날입니다.</p><p>아이들이 중학교 가서도 열심히 재미있게 공부, 놀이 할 수 있도록</p><p>옆에서 지원하겠습니다 :)</p>          </td>
        </tr>',563,1739458800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36254,'dus3','김형식','','다윗 장*울 아동 졸업했습니다.','<p>다윗방 장*울 아동의 졸업식이 있었습니다.</p><p>늠름하게 단상 앞으로 나와 졸업장과&nbsp;</p><p>표창장(체육부분)을 받는 모습이 멋졌습니다.</p><p>졸업은 끝이 아니라 새로운 시작이라고 하지요.</p><p>아동이 배정받은 중학교에 진학해 성실하고 멋지게&nbsp;</p><p>학교생활 이어 갈 수 있도록 지원 아끼지 않겠습니다.</p>          </td>
        </tr>',556,1739458800,'', '', '', '', '', '');
