INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36250,'dus3','김보영','qwert7337@naver.com','모세방 유*인, 임*하 아동 졸업장 및 상장 받았습니다.','<p>모세방 임*하, 유*인 아동 모두 유치원 졸업식과 함께</p><p>아동들과 어울리는 멋진 상장 받았습니다.</p><p>임*하 아동은 평소 포기하지 않고 도전 및 노력하는 행동이 다른 어린이의 모범이 되어 \'도전용기 어린이상\' 을 받았습니다.</p><p>유*인 아동은 다양한 생각들을 그림으로 표현하는 능력이 뛰어나 \'반짝 예술가 어린이상\' 을 받았습니다.</p><p>두 아동들 모두 상장을 받고 무척 뿌듯해하였답니다.</p><p>모세방의 멋진 막내들 모두 졸업과 멋진 상 축하합니다~^^</p>          </td>
        </tr>',564,1739199600,'', '', '', '', '', '');
