INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36249,'dus3','김보영','qwert7337@naver.com','모세방 유*인, 임*하 아동 남산 유치원 졸업식 했습니다.','<p><span style="color: rgb(0, 0, 0); font-family: verdana;">모세방의 귀여운 두 막내</span><br style="color: rgb(132, 127, 116); font-family: verdana;"><span style="color: rgb(0, 0, 0); font-family: verdana;">유*인, 임*하 아동이 오늘 남산 유치원 졸업을 하였습니다.</span><br style="color: rgb(132, 127, 116); font-family: verdana;"><br style="color: rgb(132, 127, 116); font-family: verdana;"><span style="color: rgb(0, 0, 0); font-family: verdana;">이제 의젓한 초등학생으로서</span><br style="color: rgb(132, 127, 116); font-family: verdana;"><span style="color: rgb(0, 0, 0); font-family: verdana;">한 발짝 앞으로 내딛는 날로 두 아동들 모두 씩씩하게</span><br style="color: rgb(132, 127, 116); font-family: verdana;"><span style="color: rgb(0, 0, 0); font-family: verdana;">졸업식 잘 참여해주었습니다 ㅎㅎ</span><br style="color: rgb(132, 127, 116); font-family: verdana;"><span style="color: rgb(0, 0, 0); font-family: verdana;">담임 선생님과 친구들과 떨어지는 것은 아쉬워하였지만</span><br style="color: rgb(132, 127, 116); font-family: verdana;"><span style="color: rgb(0, 0, 0); font-family: verdana;">이제 언니가 된다는 설레임에</span><br style="color: rgb(132, 127, 116); font-family: verdana;"><span style="color: rgb(0, 0, 0); font-family: verdana;">웃으며 졸업식을 잘 마무리하고 왔습니다!</span><br style="color: rgb(132, 127, 116); font-family: verdana;"><span style="color: rgb(0, 0, 0); font-family: verdana;">예쁜 꽃다발과 선물도 받고 무척 좋아하였답니다~^^</span><br style="color: rgb(132, 127, 116); font-family: verdana;"><br style="color: rgb(132, 127, 116); font-family: verdana;"><span style="color: rgb(0, 0, 0); font-family: verdana;">두 아동의 졸업을 다시 한번 진심으로 축하합니다!</span></p>          </td>
        </tr>',585,1739199600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36238,'dus3','김지은','','2월 6일 환일중 종업식했습니다.','<p>2월 6일 환일중 종업식했습니다.</p><p>겨울방학 잘보내고 몇주간 학교생활을 한후 종업식을 했습니다.</p><p>친구들, 선생님들과 인사를 나누고 왔습니다.</p><p>3월 새학년 맞이하기 전까지 부족한 학습도 하며 새학년 준비 잘 하도록 지도하겠습니다.</p>          </td>
        </tr>',558,1739026800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36225,'dus3','김지은','','2월 3일 남산초 개학했습니다','<p>오늘 남산초 개학하여 아이들 등교했습니다.</p><p>겨울방학 잘 보내고 가서 수업 받고왔습니다.</p><p>오랜만에 친구들도 만나 이야기도 나누고 반가운 선생님도 뵈었습니다.</p><p>박*수, 장*울 아동 중입배정통지서받아 환일중으로 배정받았습니다.</p><p>내일 통지서 제출 잘 다녀오도록 하겠습니다.</p>          </td>
        </tr>',658,1738508400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36136,'dus3','김지은','','1월 20일 환일중 개학 및 스키캠프 갔습니다.','<p>1월 20일 환일중학교 개학을 했습니다.</p><p>개학과 동시에 스키캠프를 2박 3일 일정으로 다녀왔습니다.</p><p>하이원으로 가게 되서 용돈과 렌탈비, 갈아입을 의복과 필요한 물품을 챙겨 갔습니다.</p><p>오늘 2박 3일을 마치고 귀원했는데 아동 매우 즐거운 시간이었다고 합니다.</p><p>남은 학교생활도 잘 할 수 있도록 지도하겠습니다.</p>          </td>
        </tr>',571,1737471600,'', '', '', '', '', '');
