INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36030,'dus3','오정복','jungbokoh@hanmail.net','1월7일 남산초 원예프로그램 진행 하였습니다.','<p>원예프로그램 마지막 수업 입니다.</p><p>다양한 경험을 하게 해주시고 즐거운 시간을 선물해 주신 선생님~ 감사합니다.</p><p>개성이 담긴 액자를 만들고 맛있는 점심도 먹었습니다.</p><p>때로는 어렵기도 했지만 언제든지 하고 싶은 원예프로그램이었습니다.&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</p>          </td>
        </tr>',571,1736348400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36029,'dus3','오정복','jungbokoh@hanmail.net','12월30일 남산초 원예프로그램 진행하였습니다.','<p>남산초등학교 원예 프로그램 진행 하였습니다.</p><p>작은 돌과 장식으로 꾸민 어항 화분에 액체를 부었는데</p><p>물컹하지만 흐르지 않고 식물을 잘 지탱해 줘서 신기했습니다.</p><p>책상위를 장식할 멋진 식물 친구가 생겼습니다.</p>          </td>
        </tr>',559,1736348400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36022,'dus3','홍영지','youngzzji@gmail.com','다윗방 박*수 아동 졸업식 진행했습니다.','<p>다윗방 박*수 아동 충무초 겨울방학식 및 졸업식 진행했습니다.</p><p>입학을 한 게 엊그제 같은데 벌써 졸업을 하니&nbsp;</p><p>옆에서 지켜본 교사 입장에서도 뿌듯함과 함께 감동이 밀려옵니다.</p><p>아동도 그동안 정말 많은 성장을 이뤘습니다.&nbsp;</p><p>중학교에 가서도 아동이 나아갈 길을 응원하도록 하겠습니다 :)</p>          </td>
        </tr>',564,1736348400,'', '', '', '', '', '');
