INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36018,'dus3','이세랑','','바울방 이* 아동의 2학기 기말고사가 끝났습니다.','<p>바울방 이* 아동의 2학기 기말고사가 끝났습니다.</p><p>시험기간동안 수고했습니다~&nbsp;</p><p>노력한만큼 결과가 나올길 바랍니다^^&nbsp;</p><p><br></p>          </td>
        </tr>',582,1736262000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (36011,'dus3','이세랑','','바울방 이* 아동의 2학기 기말고사가 시작되었습니다','<p>덕수중에 재학중인 이* 아동의 2학기 기말고사 시작되었습니다~&nbsp;</p><p>1/6(월)~1/7(화) 2일간 시험을 보게됩니다.&nbsp;</p><p>마지막시험인만큼 끝까지 열심히 노력하길 바랍니다</p>          </td>
        </tr>',588,1736089200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35938,'dus3','양현주','','남산초등학교 아동들 겨울방학을 시작했습니다.','<p>남산초 아동들 12월 27일 부터 2월 2일까지 겨울방학을 시작했습니다.</p><p>방학동안 과제도 성실하게! 몸도, 마음도 튼튼하게 생활할 수 있도록 보육하겠습니다.</p>          </td>
        </tr>',588,1735225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35937,'dus3','오정복','jungbokoh@hanmail.net','12월27일 솔로몬방 초등학생들 겨울방학을 하였습니다.','<p>솔로몬방의 개성 넘치고 웃음이 많은 초등 아동들의 겨울방학이 시작 되었습니다.</p><p>음악과 미술에 재능이 있는 박*주 아동,&nbsp; 마술을 잘하는 고*태 아동,</p><p>빠르고 운동을 좋아하는 박*훈 아동, 춤과 노래 그리고 공부도 끊임없이 노력하는 박*랑 아동,&nbsp;</p><p>주변에 도움을 많이 주고 영어 공부에 푹빠진 김*빈 아동이 알차고 행복한 방학 생활을 하도록 돕겠습니다.&nbsp;</p><p>1년 동안 사랑과 정성으로 가르쳐주신 남산초등학교 선생님들~~ 감사합니다.</p>          </td>
        </tr>',570,1735225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35936,'dus3','문소연','dawooriy3175@gmail.com','12월 27일 룻방 초등학생 아동 겨울방학식 하였습니다.','<p>룻방 박*리 아동이 오늘 남산초등학교 겨울방학식을 했습니다.</p><p>*리는 초등학교의 마지막 겨울방학인데요~</p><p>겨울방학동안 중학교를 가기 위해 부족한 공부도 하고,</p><p>즐겁게 겨울방학을 어떻게 보낼지 고민하는 *리입니다~</p><p>추운 겨울 아이들 건강에 유의하며 보육하겠습니다 :)</p>          </td>
        </tr>',571,1735225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35935,'dus3','이세랑','','바울방 정*,박* 아동 골프과목 상장 받았습니다.','<p>바울방 정*,박* 두아동이 골프예절과 성실한 태도로 타의 모범이되어 상장 받았습니다.&nbsp;</p><p>평소 체육에 큰관심과 재능을 보였던 아동들입니다.칭찬의 박수를 보냅니다.&nbsp;</p><p>일년동안 열심히 수업에 참여한 아동들이 너무나도 대견합니다.내년에도 타의 모범이 되길 기대해 봅니다!&nbsp;</p><p><br></p>          </td>
        </tr>',615,1735225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35934,'dus3','이세랑','','12월 27일 바울방 초등학생 아동들 겨울방학식 하였습니다.','<p>바울방 최*,정*,소*,박*,박* 다섯명 아동들이 오늘 12월27일 남산초등학교 겨울방학식을 했습니다.</p><p>1년 동안의 학교생활에 대해 이야기를 나눠보았습니다!! 모두 즐거운 학교생활을 한 것같습니다^^</p><p>37일 기간동안 한학년이 올라가는 중요한 시기인만큼 즐겁고 유익한 방학을 보내고자 계획을 세워봅니다~!&nbsp;</p><p>추운 겨울날 건강에 유의하며 아동들이 행복한 방학을 보낼 수 있도록 지원하겠습니다^^&nbsp;</p><p><br></p><p><br></p><p><br></p>          </td>
        </tr>',554,1735225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35933,'dus3','이선주','dltjswn222@naver.com','12월 27일 모세방 초등학생, 유치원생 아동들 겨울방학식 하였습니다.','<p style="color: rgb(132, 127, 116); font-family: verdana;">즐거운 겨울방학을 맞이한 연0빈, 박0서, 유0나, 유0민, 유0인, 임0하입니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">추운 겨울 따뜻하게 보낼 수 있도록 옆에서 보육하겠습니다.</p>          </td>
        </tr>',589,1735225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35932,'dus3','이선주','dltjswn222@naver.com','모세방 연0빈 아동 골프과목 상장 받았습니다.','<p>모세방 연0빈 아동 골프 과목 한 학기 동안 열심히 참여하고, 타 아동들에게 모범을 보여 상장을 받아왔습니다.</p><p>한 학기 동안 열심히 골프 과목에 참여한 연0빈 아동 정말 고생 많았고 수고했습니다~^^</p><p>다가오는 2025년에도 성실하게 학교생활을 할 수 있도록 응원의 박수 보냅니다</p>          </td>
        </tr>',583,1735225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35844,'dus3','김희영','hui_99@naver.com','룻방 한*은 아동의 2학기 기말고사가 시작되었습니다.','<p>​<span style="color: rgb(132, 127, 116); margin: 0px; padding: 0px; font-family: 함초롬바탕;">의료보건 고등학교 재학 중인 룻방 한</span><span lang="EN-US" style="color: rgb(132, 127, 116); font-family: verdana; margin: 0px; padding: 0px; letter-spacing: 0pt;">*</span><span style="color: rgb(132, 127, 116); margin: 0px; padding: 0px; font-family: 함초롬바탕;">은 아동의&nbsp;</span><span lang="EN-US" style="color: rgb(132, 127, 116); font-family: verdana; margin: 0px; padding: 0px; letter-spacing: 0pt;">2</span><span style="color: rgb(132, 127, 116); margin: 0px; padding: 0px; font-family: 함초롬바탕;">학기 중간고사가 시작되었습니다</span><span lang="EN-US" style="color: rgb(132, 127, 116); font-family: verdana; margin: 0px; padding: 0px; letter-spacing: 0pt;">.</span>&nbsp;</p><p class="0" style="color: rgb(132, 127, 116);"><span lang="EN-US" style="margin: 0px; padding: 0px; letter-spacing: 0pt;"><font face="verdana">12/09(</font><font face="함초롬바탕">월</font></span><span lang="EN-US" style="font-family: verdana; margin: 0px; padding: 0px; letter-spacing: 0pt;">)~12/12(</span><span lang="EN-US" style="margin: 0px; padding: 0px; letter-spacing: 0pt;"><font face="함초롬바탕">목</font></span><span lang="EN-US" style="font-family: verdana; margin: 0px; padding: 0px; letter-spacing: 0pt;">) 4</span><span style="font-family: 함초롬바탕; margin: 0px; padding: 0px;">일간 시험을 보게 됩니다</span><span lang="EN-US" style="font-family: verdana; margin: 0px; padding: 0px; letter-spacing: 0pt;">.</span></p><p class="0" style="color: rgb(132, 127, 116);"><font face="함초롬바탕">시험기간 전부터 하교 후에도 열심히 공부를 하던 아동이었습니다.</font></p><p class="0" style="color: rgb(132, 127, 116);"><font face="함초롬바탕">아동의 좋은 결과가 있길 기도합니다.</font></p>          </td>
        </tr>',591,1733670000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35859,'dus3','문소연','dawooriy3175@gmail.com','룻방 한*은 아동의 2학기 기말고사가 끝났습니다.','<p>12/9(월)~12/12(목) 서울의료보건고등학교 1학년 한*은 아동의 기말고사 기간이였습니다.</p><p>밤 늦게까지 공부한 아동에게 좋은 결과가 있길 바랍니다~</p><p>수고했어요 :)</p>          </td>
        </tr>',608,1733929200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35784,'dus3','오정복','jungbokoh@hanmail.net','12월03일 남산초 원예프로그램 진행하였습니다.','<p>편백나무를 이용해 크리스마스 화분을 만들었습니다.</p><p>편백나무를 직접 다듬어 성취감이 더 컸다고 합니다.</p><p>같은 재료이지만 각자의 개성이 담긴 모습이 제각각입니다.</p><p>책상 위에 장식하니 더 예쁜 크리스마스 화분입니다.</p>          </td>
        </tr>',605,1733238000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35759,'dus3','오정복','jungbokoh@hanmail.net','11얼26일 남산초 원예프로그램 진행하였습니다.','<p>압화를 이용해 액자와 키링을 만들었습니다.</p><p>꽃잎이 다치지 않도록 조심조심 움직이는 손끝이 야무집니다.</p><p>아동들 각자 개성이 담긴 액자와 키링에서 가을과 봄이 느껴 집니다.</p>          </td>
        </tr>',596,1732719600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35760,'dus3','오정복','jungbokoh@hanmail.net','11월 20일 필동어린이집 가을 음악회 소식입니다.','<p>남산원의 막내 정*현 아동이 다니는 필동 어린이집에서 가을 음악회가 있었습니다.</p><p>개별 무대와 같은 반 친구들과 함께 하는 무대가 있었습니다.</p><p>긴장한 얼굴로 올라갔지만 자신감 있고 밝은 모습에 박수가 쏟아졌습니다.</p><p>발표회를 기대하던 *현이도 기분이 매우 좋았습니다.</p><p>사진도 많이 찍고 칭찬도 많이 받은 가을 음악회였습니다.~~</p>          </td>
        </tr>',602,1732719600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35723,'dus3','심주현','pikaccu85@hanmail.net','남산초등학교 간담회를 진행하였습니다.','<table width="100%" border="0" cellpadding="0" cellspacing="0" style="color: rgb(132, 127, 116); line-height: 19.2px; font-family: verdana;"><tbody><tr><td height="50" colspan="4" style="line-height: 19.2px;"><table width="100%" border="0" cellpadding="10" cellspacing="0" style="line-height: 19.2px;"><tbody><tr><td align="left" style="line-height: 19.2px; padding-top: 5px;"><p>오늘 남산초등학교 간담회를 진행 하였습니다.</p><p>이번 간담회를 통해 우리 아이들에 대한 이해를 넓히는데 중요한 시간이 되었다고 생각합니다.</p><p>앞으로도 남산초등학교와 잘 협력하여 아이들이 건강하게 잘 성장할 수 있도록 최선을 다해 지원 하겠습니다.</p><p>큰 관심과 사랑을 보여주신 남산초등학교 선생님들께 다시한번 깊은 감사를 드립니다.</p></td></tr></tbody>',646,1732028400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35722,'dus3','오정복','jungbokoh@hanmail.net','11얼19일 남산초 원예프로그램 진행하였습니다.','<p>공룔시대에 함께 자란 고사리에 대해 알아보고 화산 폭발 체험을 해 보았습니다.</p><p>화산 키트 실험을 하며 집중하고 즐거워 하였고</p><p>고사리를 관찰하며 이야기를 나누는 유익한 시간을 보냈습니다.</p>          </td>
        </tr>',619,1732028400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35686,'dus3','홍영지','youngzzji@gmail.com','남산초 원예프로그램 진행하였습니다.','<p>남산초 원예프로그램 진행하였습니다.</p><p>오늘은 빼빼로 만들기 해보는 시간을 가졌습니다.</p><p>아동들은 프로그램 시작 전부터 신나서 들뜬 모습이었습니다.</p><p>막대과자에 초콜릿을 듬뿍 묻히고 다양한 색의 가루를 뿌려</p><p>자신만의 빼빼로를 완성해 서로 나누어 먹었답니다!</p><p><br></p><p><br></p>          </td>
        </tr>',649,1731337200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35684,'dus3','김지은','','덕수중학교 2학기 중간고사 실시했습니다.','<p>덕수중학교 아동들 2학기 중간고사 시험이 있었습니다.</p><p>11월 4일-6일까지 3일간 진행했습니다.</p><p>중2인 아동은 3일차 되는 6일에는 시험이 없어 체험학습으로 서울특별시 융합과학교육원 남산분관에 다녀왔습니다.</p><p>남산산책도 하고, 체험활동 및 멘토링 활동을 하고 맛있는 점심도 먹고 귀원했습니다.</p><p>중간고사 시험도 잘 마무리 되었습니다. 고생했습니다!^^</p>          </td>
        </tr>',638,1731250800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35657,'dus3','홍영지','youngzzji@gmail.com','남산초 원예프로그램 진행하였습니다. (11월 05일)','<p style="color: rgb(132, 127, 116); font-family: verdana;">남산초 원예 프로그램 진행하였습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">독도 화분 만들기를 해보는 시간 가졌습니다!</p><p style="color: rgb(132, 127, 116); font-family: verdana;">먼저 독도에 관련한 영상을 시청하고 각자만의 특별한 독도 화분을 만들었습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">파랗고 하얀 모래로 바다를 꾸미고 동도와 서도를 표현한 돌 위에 난을 얹어 완성했습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">자신만의 독도 화분을 완성한 아동들은 뿌듯함에 웃음이 가득했답니다!</p>          </td>
        </tr>',652,1730991600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35656,'dus3','홍영지','youngzzji@gmail.com','남산초 원예프로그램 진행하였습니다. (10월 22일)','<p style="color: rgb(132, 127, 116); font-family: verdana;">남산초 원예 프로그램 진행하였습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">커피박화분 만들기와 다육이심기 활동하였습니다.</p><p style="color: rgb(132, 127, 116); font-family: verdana;">평소에 자주 접하지 않는 색다른 체험을 해보는 시간 보냈습니다 :)</p>          </td>
        </tr>',608,1730991600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35637,'dus3','김지은','','11월 1일 남산초등학교 개교기념일입니다','<p>오늘은 11월 1일 남산초등학교 개교기념일 입니다.</p><p>초등학생들은 등교하지 않아 오전에는 신나는 체육활동을 하고, 오후에는 각 방 외출활동과 원내 프로그램을 하며 시간을 보냈습니다.</p><p>11월 4일은 남산초등학교 자율휴업일로 방과후도 휴강하고 학교에 가지 않아 주말을 포함해 4일간 쉬게됩니다.</p><p>4일이라는 기간동안 즐거운 프로그램도 하고, 부족한 학습도 하며 의미있게 보낼 수 있도록 지도하겠습니다.^^</p>          </td>
        </tr>',651,1730473200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35633,'dus3','이세랑','rheese1228@naver.com','룻방 한* 아동 ITQ시험 합격했습니다.','<p>룻방 한* 아동 정보기술자격(ITQ) 한글파워포인트 A등급 받았습니다!</p><p>세등급 중 가장 높은 등급으로 합격하였습니다! 축하합니다.</p><p>여러 자격증 시험에 도전하고 있는 아동입니다.앞으로도 아동의 도전을 응원합니다~^^&nbsp;</p>          </td>
        </tr>',658,1730386800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35615,'dus3','이세랑','','룻방 김* 아동 동명생활경영고등학교 영유아보육과 수료증 받았습니다.','<p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">룻방 </span>김*<span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">&nbsp;아동이 영유아보육교육과 수료증을 받았습니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span></p><p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">유치원교사의 꿈을 이루고자 노력하는 모습이 대견한 아동입니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span></p><p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">아동의 노력의 결과에 아낌없이 칭찬하였습니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">. </span></p><p class="0"><span style="font-family:함초롬바탕;mso-fareast-font-family:함초롬바탕;">앞으로 더욱 성장할 아동을 응원합니다</span><span lang="EN-US" style="mso-fareast-font-family:함초롬바탕;mso-font-width:100%;letter-spacing:0pt;mso-text-raise:0pt;">!</span></p>          </td>
        </tr>',684,1730041200,'', '', '', '', '', '');
