INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35279,'dus3','문소연','dawooriy3175@gmail.com','08월 21일 모세방 초등 아이들 개학했습니다.','<p>오늘 우리 모세방 초등생 아이들이</p><p>개학을 했습니다.</p><p>여름방학동안 캐리비안베이, 롯데월드, 아이스쇼,</p><p>야구장 등 즐겁고 다양하게 즐겼는데요~</p><p>열심히 일기도 쓰고, 건강하게 아픈 곳 없이</p><p>무사히 개학을 할 수 있었습니다!</p><p>남은 학기도 무사히 잘 마칠 수 있도록</p><p>옆에서 지원하겠습니다 :)</p>          </td>
        </tr>',670,1724166000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35278,'dus3','심주현','pikaccu85@hanmail.net','8월 21일 남산초등학교 개학 하였습니다.','<p><span style="color: rgb(132, 127, 116); font-family: verdana;">오늘 남산초등학교 개학을 하였습니다.&nbsp;</span></p><div style="margin: 0px; padding: 0px; color: rgb(132, 127, 116); font-family: verdana;">여름방학동안 아이들은 집에서 시원하게 수영장 물놀이도 하고&nbsp;</div><div style="margin: 0px; padding: 0px; color: rgb(132, 127, 116); font-family: verdana;">여름캠프, 롯데월드, 캐리비안베이에 다녀오며 무더운 여름을 알차게 보냈습니다.</div><div style="margin: 0px; padding: 0px; color: rgb(132, 127, 116); font-family: verdana;">방학숙제도 열심히 했답니다.^^</div><div style="margin: 0px; padding: 0px; color: rgb(132, 127, 116); font-family: verdana;"><br></div><div style="margin: 0px; padding: 0px; color: rgb(132, 127, 116); font-family: verdana;">여름방학 끝나는 것을 아쉬워 하였지만&nbsp;</div><div style="margin: 0px; padding: 0px; color: rgb(132, 127, 116); font-family: verdana;">2학기를 즐거운 마음으로 시작할 수 있도록 많은 응원을 해주었습니다.&nbsp;</div><div style="margin: 0px; padding: 0px; color: rgb(132, 127, 116); font-family: verdana;">방학기간동안 보지못한 친구들과의 반가운 만남을 기대하며&nbsp;</div><div style="margin: 0px; padding: 0px; color: rgb(132, 127, 116); font-family: verdana;">2학기에도 건강하고 예의바른 아동들이 되도록 보육하겠습니다~!</div>          </td>
        </tr>',685,1724166000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35144,'dus3','정경희','kh347g@naver.com','남산초등학교 토탈공예프로그램 참여하였습니다. (07.30)','<p>남산초등학교 토탈공예프로그램 마지막날 목재를 조립하고 </p><p>철판용 스티커를 붙여 꾸미기를 해보았습니다.</p><p>담당선생님의 말씀처럼 첫수업에는 낯설고 어려워했는데&nbsp;</p><p>웃으면서 토탈공예프로그램을 잘 마무리했습니다.</p><p>담당선생님께 감동을 안겨드리고, 우리는 공예의 다양함을</p><p>배운 프로그램에 감사드립니다.&nbsp;&nbsp;</p>          </td>
        </tr>',702,1722265200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35104,'dus3','이선주','dltjswn222@naver.com','한나방 아동들 여름방학식 하였습니다.','<p>7/19 동명생활경영고등학교 김0민 / 의료보건고 한0은</p><p>7/23 남산초등학교 박0주, 박0빈, 장0아, 박0리 여름방학식 했습니다.</p><p>여름 방학 동안 신나고 행복하게 보낼 수 있도록 하겠습니다.</p>          </td>
        </tr>',694,1721833200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35103,'dus3','김아름','kjj375@naver.com','7월 24일 다윗방 충무초등학교 여름방학식 하였습니다.','<p>즐거운 여름방학을 맞이한 다윗방 박*수 아동입니다.</p><p><br></p><p>시원하고 즐거운 여름방학을 즐길 수 있도록 보육지원 하겠습니다.</p>          </td>
