INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35102,'dus3','김아름','kjj375@naver.com','7월 23일 다윗방 남산초등학교 아동들 여름방학식 하였습니다.','<p>오늘은 남산초등학교 방학식 입니다.</p><p>방학을 맞이한&nbsp; 정*호, 박*민, 박*주, 장*울 아동입니다.</p><p>시원하고 즐거운 여름방학이 될 수 있도록 보육지원 하겠습니다.</p>          </td>
