INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35097,'dus3','문소연','dawooriy3175@gmail.com','남산초등학교 토탈공예프로그램 참여하였습니다. (07.23)','<p>우리 아이들 오늘 토탈공예 수업에서는</p><p>지난주에 진행했던 신부 액자를 마무리하는</p><p>시간을 보냈습니다.</p><p>꽃 모양을 만들어 머리를 풍성하게 만드는데</p><p>반짝반짝 불빛도 붙여서 더 작품이 아름다워졌답니다 ~!</p>          </td>
        </tr>',682,1721660400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35092,'dus3','이주현','dlwngus0608@gmail.com','바울방 박*성, 박*윤 아동 골프과목 상장 받았습니다.','<p>바울방 박*성, 박*윤 아동은 골프과목 상장을 받아왔습니다 ^^</p><p>한학기동안 바른 골프예절과 성실한 태도로 수업에 적극적으로 참여하여&nbsp;</p><p>모범적인 모습을 보여줌에 골프과목 상장을 받았다고 합니다~!</p><p>항상 수업에 적극적이고 바른 모습을 보여준 아동들에게 많은 칭찬과 응원을 해주었습니다 ^^</p>          </td>
        </tr>',726,1721660400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35096,'dus3','문소연','dawooriy3175@gmail.com','7월 23일 모세방 초등생 아이들 여름방학식을 하였습니다.','<p>우리 모세방 초등 아이들</p><p>여름방학식을 했습니다.</p><p><br></p><p>올해 1학년이 되어 처음 방학을 즐겨보는 하*, 리* !</p><p>4학년의 처음이자 마지막 여름방학을 보내는 은*</p><p>초등학생의 마지막 여름방학을 보내는 수*</p><p><br></p><p>모두 즐거운 여름방학을 보낼 수 있도록</p><p>옆에서 지원하겠습니다 :D</p>          </td>
        </tr>',720,1721660400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35091,'dus3','이주현','dlwngus0608@gmail.com','7월 23일 바울방 초등학생 아동들 여름방학식 하였습니다.','<p>오늘은 바울방 박*성, 박*태, 박*윤, 소*지, 최*울 아동들 방학식을 하였습니다!<br></p><p>1학기를 어떻게 생활했는지 1학기 평가서를 보며 함께 되돌아보고~</p><p>방학을 어떻게 보낼지 방학계획표를 보며 나만의 과제도 정했습니다!&nbsp;</p><p>각자 책상 앞에 붙여주며 방학동안 잘 실천하고 생활할 수 있도록 응원해주었습니다 ^^&nbsp;</p><p>신나고 알찬 방학이 될 수 있도록 보육하겠습니다~!!</p>          </td>
        </tr>',696,1721660400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (35090,'dus3','심주현','pikaccu85@hanmail.net','7월 23일 솔로몬 초등학생 아동들 여름방학식 하였습니다.','<p><span style="color: rgb(132, 127, 116); font-family: verdana;">오늘은 초등학교 여름방학식이 있는 날입니다.&nbsp;</span></p><div style="margin: 0px; padding: 0px; color: rgb(132, 127, 116); font-family: verdana;">솔로몬방 *빈, *랑, *훈, *태, *진이가 방학을 하였습니다.&nbsp;<br><div style="margin: 0px; padding: 0px;">아이들이 나의 학교생활과 여름방학 안내문을 받아와&nbsp;</div><div style="margin: 0px; padding: 0px;">1학기를 돌아보며 함께 이야기 나누는 시간을 보냈습니다.&nbsp;</div><div style="margin: 0px; padding: 0px;">여름방학때 공통과제와 나만의 과제도 정해보았습니다.&nbsp;</div><div style="margin: 0px; padding: 0px;">아이들이 알찬 여름방학 생활을 할 수 있도록&nbsp; 지원하겠습니다. ^^</div></div>          </td>
        </tr>',843,1721660400,'', '', '', '', '', '');
