INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34971,'dus3','이세랑','rheese1228@naver.com','룻방 덕수중학교 정* 아동 기말고사 끝났습니다.','<p class="0" style="line-height: 130%"><span style="font-family: 함초롬바탕">룻방 덕수중학교 정</span><span lang="EN-US" style="letter-spacing: 0pt">*</span><span style="font-family: 함초롬바탕">아동의 </span><span lang="EN-US" style="letter-spacing: 0pt">1</span><span style="font-family: 함초롬바탕">학기 기말고사가 끝났습니다</span><span lang="EN-US" style="letter-spacing: 0pt">.</span></p>
