INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34803,'dus3','최준희','ch3596@hanmail.net','남산초등학교 학부모 공개수업 다녀왔습니다.','5월 29일 수요일에 남산초등학교 학부모 공개수업에 다녀왔습니다^^
<div><br />
<div>지 *, 김*빈, 이*나, 유*나 아동의 학교 생활을 보니 원에서와는 또 다른 모습을 볼 수 있었답니다!</div></div>
<div><br /></div>
<div>부끄럼이 많은 지 *이는 다른 학부모님이 계셔서 발표하는 것을 어려워 할 줄 알았지만, 씩씩하게 대답도 잘 했구요~</div>
<div>애교 많은 김*빈은 담임 선생님께서 발표하고 싶은 사람 손 들어보라고 하시자 손을 번쩍 들며 발표에 적극적이었습니다.</div>
<div>말하는 것을 좋아하는 이*나는 수업 시간에는 진지하게, 쉬는 시간에는 다시 평소의 모습으로 자신의 작품들을 보여주고 다른 친구들의 작품도 소개해주었어요.</div>
<div>평소 장난끼가 많은 유*나는 발표하는 시간이 되자 부끄러워서 손을 들지 못 하다가, 다른 친구들이 손을 드는 모습에 손을 번쩍 들고 씩씩하게 자신의 의견을 표현했답니다.</div>
<div><span style="font-size: 9pt"><br /></span></div>
<div><span style="font-size: 9pt">학교 생활도 성실히 하고, 수업에도 적극적으로 참여하는 우리 아이들의 모습에 기특하기도 하고,</span></div>
<div><span style="font-size: 9pt">어리게 보였던 우리 아이들이 많이 성장했다는 것이 느껴지는 하루였습니다!</span><span style="font-size: 9pt">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></div>          </td>
        </tr>',810,1716994800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34797,'dus3','홍미진','ghdalwls0410@naver.com','남산초등학교 학부모 공개수업 다녀왔습니다.','<div>남산초 윤*은, 정*호 학부모 공개수업에 다녀왔습니다.</div>
<div>공개수업이 시작되기전 교실안으로 들어가는</div>
<div>복도에는&nbsp; 아이들의 초상화그림과&nbsp;</div>
<div>아이들 마음을 읽을수 있는 글, 만들기 작품이 함께&nbsp; 전시되어있었습니다~^^</div>
<div>공개수업이 시작되고</div>
<div>아이들은 긴장하는 모습없이</div>
<div>선생님수업에 집중하며</div>
<div>씩씩하게 발표도 잘하고</div>
<div>활동지도 막힘없이 잘하는 모습이었습니다~^^!!</div>
<div><br /></div>          </td>
        </tr>',778,1716908400,'', '', '', '', '', '');
