INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34796,'dus3','오정복','jungbokoh@hanmail.net','남산초등학교 학부모 공개 수업 다녀왔습니다.','박*랑, 박*윤, 박*태, 박*훈, 박*서, 고*태 학부모 참관 수업 다녀 왔습니다.

<div>이야기를 듣고 해결 방법을 찾아 보고</div>
<div>친구들의 고민을 듣고 특별 처방 음식과 조언을 해 주기도 하였습니다.</div>
<div>이야기의 흐름에 따라 그림을 나열 해 보고 요약하는 시간도 재미있었습니다.</div>
<div>차분하게 그리고 적극적으로 참여하는 아이들의 모습이 집에서보다 더 의젓하고 반짝였습니다.</div>
<div><br /></div>          </td>
        </tr>',772,1716908400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34794,'dus3','이선주','dltjswn222@naver.com','남산초등학교 학부모 공개수업 다녀왔습니다.','5-1 박0빈, 박0진, 박0성

<div>5-2 박윤0, 박동0, 고0태, 장0아</div>
<div>6-1 장0울, 박0리의 학부모 공개수업 다녀왔습니다.</div>
<div><br /></div>
<div>5-1 아동들은 반에 에이스들인지 셋이서 앞다투어 발표를 하겠다고 적극적으로 손을 들며 발표했습니다.</div>
<div>5-2 박동0 아동은 다른 아동들이 발표에 참여하지 않으니 나서서 자신이 발표하겠다고 말하며 기특한 모습을 보였습니다.</div>
<div>6-1 아이들은 퀄리티 있는 피피티도 만들고 대본을 직접 써서 발표를 하는 등 그동안 얼마나 노력했는지 알 수 있는 시간이였습니다.&nbsp;<span style="font-size: 9pt">위에 아동들 모두 학교 수업에 적극적으로 참여하고 발표도 열심히 했습니다.&nbsp;</span></div>          </td>
        </tr>',801,1716908400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34795,'dus3','이주현','dlwngus0608@gmail.com','바울방 남산초 학부모 공개수업 다녀왔습니다.','<div>바울방 최*울, 소*지, 박*태 아동&nbsp;<span style="font-size: 9pt">학부모 공개수업 참관하였습니다.</span></div>
<div>우리 아동들이 학교에서 어떻게 지내는지, 수업시간에 잘 참여하고 있는지를 볼 수 있었는데요!</div>
<div>수업시간에 적극적이고, 발표도 멋지게 잘 하고, 친구들과도 잘 지내는 모습을 볼 수 있어서</div>
<div>대견하고 고마움을 느낄 수 있는 시간이였습니다 ^^</div>
<div>아동들이 지금처럼 잘 성장할 수 있도록 집에서도 보육하겠습니다~</div>          </td>
        </tr>',789,1716908400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34785,'dus3','정경희','kh347g@naver.com','남산초등학교 토탈공예프로그램 참여했습니다.(05.28)','매주 화요일 남산초등학교 토탈공예프로그램을 진행합니다.
<div>오늘은 저번주에 이어 과일가게 만들기에서 채색&amp; 소품만들기를&nbsp;</div>
<div>하였습니다.</div>
<div>꼼꼼하게 채색하고 잘 말려 다음주에는 과일가게 만들기를&nbsp;</div>
<div>마무리한다고 합니다.</div>
<div>잘 참여하도록 지원하겠습니다.&nbsp;</div>          </td>
        </tr>',781,1716822000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34749,'dus3','김지은','','남산초등학교 토탈공예프로그램 참여했습니다. (05.21)','<p class="0" style="line-height: 100%"><span style="letter-spacing: -0.8pt">매주 화요일 남산초등학교 토탈공예 프로그램을 진행하고 있습니다</span><span lang="EN-US" style="letter-spacing: -0.8pt">.</span></p>
<p class="0" style="line-height: 100%"><span style="letter-spacing: -0.8pt">오늘은 과일가게만들기활동을 했습니다</span><span lang="EN-US" style="letter-spacing: -0.8pt">.</span></p>
<p class="0" style="line-height: 100%"><span style="letter-spacing: -0.8pt">아이들이 토탈공예활동을 매우 좋아합니다</span><span lang="EN-US" style="letter-spacing: -0.8pt">.</span></p>
<p class="0" style="line-height: 100%"><span style="letter-spacing: -0.8pt">집중력을 발휘하여 꼼꼼하게 작업했습니다</span><span lang="EN-US" style="letter-spacing: -0.8pt">.</span></p>
<p class="0" style="line-height: 100%"><span style="letter-spacing: -0.8pt">매주 새로운 활동으로 아동들을 지도해주시는 선생님 감사합니다</span><span lang="EN-US" style="letter-spacing: -0.8pt">!</span></p>
<p class="0" style="line-height: 100%"><span style="letter-spacing: -0.8pt">꾸준히 잘 참여할 수 있도록 지도하겠습니다</span><span lang="EN-US" style="letter-spacing: -0.8pt">.</span></p>
<div id="hwpEditorBoardContent" class="hwp_editor_board_content" data-hjs&#111;&#110;ver="1.0" data-js&#111;&#110;len="8833"></div>          </td>
        </tr>',825,1716217200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34711,'dus3','김지은','','바울방 이*민, 배*욱 중간고사 잘 마쳤습니다.','덕수중학교 이*민, 환일중학교 배*욱 중간고사 잘 마쳤습니다.

<div>덕수중학교는 이틀, 환일중학교는 하루 시험을 봤습니다.</div>
<div>중1인 아동은 자유학기제로 점수에는 들어가지 않지만 기본 학습상태를 평가 받을 수 있는 시험이었습니다.</div>
