INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34355,'dus3','김지은','','3월 4일 남산초등학교 개학했습니다.','3월 4일 월요일 남산초등학교 개학을 했습니다.
<div>아동들 한학년씩 승급하여 새로운 학년과 반을 배정받아 등교를 했습니다.</div>
<div>새로운 담임선생님을 만나 인사하고, 친구들도 오랜만에 만나 반갑게 인사했습니다.</div>
<div>개학이라 아동들 가져온 가정통신문도 많고, 준비물도 많지만 빠짐없이 챙겨보내며 학교생활 잘 적응하며 지내도록 지도하겠습니다.</div>
<div>2024년 1년도 건강하고 행복한 학교생활이 되길 바랍니다~^^</div>          </td>
        </tr>',838,1709478000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34353,'dus3','오정복','jungbokoh@hanmail.net','3월4일 배*욱 아동 환일중 입학식이 있었습니다.','다윗방 배*욱아동 환일중학교에 입학하였습니다.
<div>단정하게 교복을 차려 입고 나서는 모습이 의젓합니다.</div>
<div>또하나의 출발을 하는 아동을 축하합니다.</div>
