INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33903,'dus3','이선주','dltjswn222@naver.com','모세방 남산초등학교 겨울방학식 있었습니다.','모세방 오늘 남산초 겨울방학식 있었습니다~

<div>다들 방학을 맞이하여 뭐하고 지낼지 이야기 하는 시간을 가졌는데요^^</div>
<div>겨울방학 계획도 세워보고 또, 방학에 롯데월드를 놀러가는 얘기도 하며</div>
<div>도란도란 이야기 꽃을 피우는 모세방 볼 수 있었습니다^^</div>
<div>신나고 행복한 겨울방학 보낼 수 있도록 옆에서 지도하겠습니다.</div>          </td>
        </tr>',881,1704985200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33901,'dus3','김지은','','바울방 윤*우 아동 남산초등학교 행복반 다녀왔습니다.','남산초등학교 1학년 신입생으로 입학하는 윤*우 아동&nbsp;
<div>남산초등학교 개별반 행복반에 다녀왔습니다.</div>
<div>입학하기 전 아동이 다닐 학교 원반과 개별반 교실, 급식실 가는법도 알아보는 연습을 했습니다.</div>
<div>입학전 조금이라도 적응하기 위해 개별반 선생님과도 이야기나누고, 개별반 형/누나들도 만나보았습니다.</div>
<div>아동이 좋아하는 풍선, 클레이, 트램펄린 등 놀잇감과 놀이기구가 많이 있어 무척이나 좋아했습니다.</div>
<div>그리고 행복반 선생님과 조금이나마 가까워 질 수 있는 시간도 가져보았습니다.</div>
<div>잠깐이지만 선생님과 한결 가까워진 느낌입니다.</div>
<div>아동 잘 적응해서 1학년생활 잘 할 수 있도록 지도하겠습니다.</div>
<div><br /></div>          </td>
        </tr>',910,1704985200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33900,'dus3','오정복','jungbokoh@hanmail.net','다윗방 남산초등학교 아동들 겨울방학 하였습니다.~','다윗방 초등 아동들 겨울 방학이 시작되었습니다.

<div>동*는 담임 선생님과 헤어지며 눈물을 흘렸다고 합니다</div>
<div>박*성 아동은 골프 수업에 적극 적으로 참여해 상장을 받았습니다.</div>
<div><span style="font-size: 9pt">정*, 지* 아동은 종업식 과자 파티를 하였다며 이야기 꽃을 피웁니다.</span></div>
<div>짐 정리도하고 어떤 숙제가 있는지 찾아보고 방학 동안 해 보고 싶은 것들도 이야기하였습니다.</div>
<div>지금처럼 많이 웃을 수 있도록,</div>
<div>건강하게 자랄 수 있도록,</div>
<div>실력을 높일 수 있도록 방학을 알차게 보내겠습니다.</div>
<div>1년 동안 사랑으로 가르쳐 주신 선생님들 감사합니다.</div>
<div><br /></div>          </td>
        </tr>',880,1704985200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33902,'dus3','오정복','jungbokoh@hanmail.net','남산초등학교 졸업식이 있었습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'2401131227173_1.jpg\');><img src=\'/admin/data/bbs/dus3/M2401131227173_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
							<col width=100%></col>
							<tr>
								<td><img src=\'\' border=\'0\' name=\'wiz_target_resize\' width=\'0\' height=\'0\'></td>
							</tr>',913,1704985200,'cats.jpg', '', '', 'cats.jpg', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33899,'dus3','김지은','','바울방 남산초등학교 종업식을 했습니다.','금일은 남산초등학교 종업식을 했습니다.

<div>1년동안 열심히 학교생활을 한 아동들&nbsp;</div>
<div>담임선생님과 한해동안 못다한 이야기나누고, 남아있는 짐을 챙겨 집으로 돌아왔습니다.</div>
<div>사랑과 정성으로 아동들을 아껴주시고 지도해주신 남산초등학교 선생님들께 진심으로 감사드립니다.</div>
<div>아동들과 학교생활에 대해 이야기를 나누며 아쉬움도 많고 즐거웠다는 좋은 이야기들이 많이 나왔습니다.</div>
<div>선생님들과의 작별도 많이 아쉬운가 봅니다.</div>
<div>올해도 작년보다 더욱 성장하는 아동들이 될 수 있도록 지도하겠습니다.</div>
<div>아동들 겨울방학 즐겁게 보내고, 새 학년에서도 건강하고 열심히 생활하길 바랍니다.~^^</div>          </td>
        </tr>',852,1704985200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33898,'dus3','심채희','chaehee.shim@gmail.com','한나방  남산초등학교 아동들에게도 겨울방학이 왔습니다.','<p class="0" style="line-height: 100%"><span lang="EN-US"> </span>겨울방학과 함께 시작된 남산원내 종일보육이 오늘부터 시작됩니다.</p>
<p class="0" style="line-height: 100%"><br /></p>
<p class="0" style="line-height: 100%"><span style="font-size: 9pt">남산초등학교는 봄방학과 겨울방학을 통합하여 겨울방학 기간을&nbsp;&nbsp;</span><span lang="EN-US" style="font-size: 9pt; letter-spacing: 0pt">3</span><span style="font-size: 9pt">월 3일까지로 정하고 있습니다</span><span lang="EN-US" style="font-size: 9pt; letter-spacing: 0pt">.&nbsp;</span></p>
<p class="0" style="line-height: 100%"><span lang="EN-US" style="letter-spacing: 0pt"><br /></span></p>
<p class="0" style="line-height: 100%"><span style="font-size: 9pt">겨울방학은 초등학생들에게 여러 가지 장점을 제공합니다</span><span lang="EN-US" style="font-size: 9pt; letter-spacing: 0pt">.&nbsp;</span></p>
<p class="0" style="line-height: 100%"><span lang="EN-US" style="font-size: 9pt; letter-spacing: 0pt"><br /></span></p>
<p class="0" style="line-height: 100%">첫째로<span lang="EN-US" style="letter-spacing: 0pt">, </span>휴식과 여가활동을 즐길 수 있는 시간입니다<span lang="EN-US" style="letter-spacing: 0pt">. </span><span lang="EN-US" style="letter-spacing: 0pt">&nbsp;</span>취미활동을 즐기며 스트레스를 해소할 수 있습니다<span lang="EN-US" style="letter-spacing: 0pt">.</span></p>
<p class="0" style="line-height: 100%"><span lang="EN-US" style="letter-spacing: 0pt"><br /></span></p>
<p class="0" style="line-height: 100%">둘째로<span lang="EN-US" style="letter-spacing: 0pt">, </span>겨울방학은 학습 기회를 제공합니다<span lang="EN-US" style="letter-spacing: 0pt">.&nbsp; 전학년도의 내용과&nbsp; 다음 학년도의 내용을 한번씩 점검 해 보는 좋은 기간이겠죠?</span></p>
<p class="0" style="line-height: 100%"><span lang="EN-US" style="letter-spacing: 0pt"><br /></span></p>
<p class="0" style="line-height: 100%"><span lang="EN-US" style="letter-spacing: 0pt">선생님과 아동들이 습관적으로 책도읽고, 학습도 하며 보내야 겠습니다. 물론, 건강한 체력을 기르는 학습을 포함해서요~</span></p>
<p class="0" style="line-height: 100%"><span lang="EN-US" style="letter-spacing: 0pt"><br /></span></p>
<p class="0" style="line-height: 100%">마지막으로<span lang="EN-US" style="letter-spacing: 0pt">, </span>겨울방학은 개인적인 성장을 위한 시간입니다<span lang="EN-US" style="letter-spacing: 0pt">. </span>관심 있는 분야나 특기를 개발하고 발전시킬 수 있습니다<span lang="EN-US" style="letter-spacing: 0pt">.&nbsp;</span></p>
<p class="0" style="line-height: 100%"><span lang="EN-US" style="letter-spacing: 0pt"><br /></span></p>
<p class="0" style="line-height: 100%"><span lang="EN-US" style="letter-spacing: 0pt">날씨는 춥고,매섭지만, 겨울방학동안의 남산원 한나방은&nbsp; 따뜻하고,정감있고,바르게 성장하는 기간이 되었으면 좋겠습니다.</span></p>
<p class="0" style="line-height: 100%"><span lang="EN-US" style="letter-spacing: 0pt"><br /></span></p>
<p class="0" style="line-height: 100%"><span lang="EN-US" style="letter-spacing: 0pt">남산원 선생님들~ 아자!아자! 화이팅입니다^^~</span></p>
<p class="0" style="background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial"><o:p></o:p></p>          </td>
        </tr>',825,1704985200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33897,'dus3','홍미진','ghdalwls0410@naver.com','룻방 남산초등학교 아동들이 방학식을 했습니다.','<p class="0"><span style="font-family: 함초롬바탕">룻방아이들이 기다리고 기다리던 겨울방학식을 하였습니다</span><span lang="EN-US" style="letter-spacing: 0pt">.^^*</span></p>
<p class="0"><span style="font-family: 함초롬바탕">겨울방학에는 맛있는 것도 많이 먹고 재미있는 놀이도 하고 그림도 많이 그리고 싶다고 말하는 기여운 아이들입니다</span><span lang="EN-US" style="letter-spacing: 0pt">.^^*</span></p>
<p class="0"><span style="font-family: 함초롬바탕">겨울방학동안 아이들과 함께 열심히 공부하고 재미있게 놀며 건강하게 자라날 수 있도록 보육하겠습니다</span><span lang="EN-US" style="letter-spacing: 0pt">~^^**</span></p>          </td>
        </tr>',829,1704985200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33891,'dus3','심주현','pikaccu85@hanmail.net','솔로몬 초등생 아동들 겨울방학 하였습니다.','<span style="color: #847f74; font-family: verdana">오늘은 학교 겨울방학식이 있는 날입니다.&nbsp;</span>
<div style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">솔로몬방 *빈, *랑,, *태, *진이가 방학을 하였습니다.&nbsp;<br />
<div style="margin: 0px; padding: 0px">아이들이 저마다 나의 학교생활과 겨울방학 안내문을 받아와&nbsp;</div>
<div style="margin: 0px; padding: 0px">1년을 돌아보며 함께 이야기 나누는 시간을 보냈습니다.&nbsp;</div>
<div style="margin: 0px; padding: 0px">아이들이 학년을 잘 마무리 하고 신학기를 잘 준비할 수 있도록&nbsp;</div>
<div style="margin: 0px; padding: 0px">최선을 다해 지원하겠습니다. ^^</div></div>          </td>
        </tr>',794,1704985200,'', '', '', '', '', '');
