INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33869,'dus3','이선주','dltjswn222@naver.com','1월 4일 모세방 소식입니다(초등학교 예비소집일)','<div>모세방 유O나, 유O민 초등학교 예비소집일 다녀왔습니다.</div>
<div>2024년도 갑진년을 맞이하여 벌써 8살이 된 아동들이 초등학교에 들어가게 되었는데요~</div>
<div>등하교하는 방법을 배우면서 신호등을 잘 지키는 방법에 대해서 배우고,</div>
<div>초등학교에 도착하고 나선 관리 선생님과 인사도 나누며 얼굴도 익히는 시간도 가졌습니다.</div>
<div>3월 4일 월요일 초등학교 입학식이 예정되어있습니다.</div>
<div>앞으로도 모세방 아동들 건강하게 지낼 수 있도록 지도하겠습니다.^^</div>          </td>
        </tr>',801,1704294000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33870,'dus3','이세랑','rheese1228@naver.com','1월 4일 룻방 소식입니다(초등학교 예비소집일)','<div align=\'LEFT\'><a href=javascript:viewImg(\'2401040714438_1.jpg\');><img src=\'/admin/data/bbs/dus3/M2401040714438_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
