INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33024,'dus3','김지은','','8월 23일 바울방 초등생 개학했습니다','바울방 초등생 아동들 8월 23일 수요일 초등학교 개학식이 있었습니다.

<div>각자 여름방학동안 작성한 일기장, 독후감, 관찰일기장 등 숙제를 모두 가방에 챙기고,&nbsp;</div>
<div>필기구 및 교재, 실내화까지 꼼꼼하게 챙기고 갔습니다.</div>
<div>방학동안 친구들이 키도 몸무게도 늘었고 컸다는 아동들에게 너희들도 매달 잘 크고 있다고 얘기해주었습니다.</div>
<div>방학숙제를 잘해서 칭찬을 받은 아동들도 많이 있었어요.</div>
<div>아동들 학교생활도 잘 할수 있도록 옆에서 지도하겠습니다.</div>          </td>
        </tr>',938,1693062000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33006,'dus3','진민지','grimreaper@naver.com','한나방 초등생 아동들 개학 했습니다.','<p class="0"><span style="font-family: 함초롬바탕">오늘 박</span><span lang="EN-US" style="letter-spacing: 0pt">*</span><span style="font-family: 함초롬바탕">주</span><span lang="EN-US" style="letter-spacing: 0pt">, </span><span style="font-family: 함초롬바탕">박</span><span lang="EN-US" style="letter-spacing: 0pt">*</span><span style="font-family: 함초롬바탕">빈</span><span lang="EN-US" style="letter-spacing: 0pt">, </span><span style="font-family: 함초롬바탕">연</span><span lang="EN-US" style="letter-spacing: 0pt">*</span><span style="font-family: 함초롬바탕">빈</span><span lang="EN-US" style="letter-spacing: 0pt">, </span><span style="font-family: 함초롬바탕">박</span><span lang="EN-US" style="letter-spacing: 0pt">*</span><span style="font-family: 함초롬바탕">리 아동은 여름방학 동안 열심히 한 과제를 들고&nbsp;</span></p>
<p class="0"><span style="font-family: 함초롬바탕">오랜만에 만날 친구들과 무슨 주제로 이야기를 할지 고민하며 들뜬 모습들이 역력했습니다</span><span lang="EN-US" style="letter-spacing: 0pt">.&nbsp;</span></p>
<p class="0"><span lang="EN-US" style="font-size: 9pt; letter-spacing: 0pt">2</span><span style="font-size: 9pt; font-family: 함초롬바탕">학기를 시작으로 아동들이 즐거운 학교생활을 할 수 있도록 지원하겠습니다</span><span lang="EN-US" style="font-size: 9pt; letter-spacing: 0pt">.&nbsp;</span></p>          </td>
        </tr>',876,1692716400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (33000,'dus3','차송희','thd4378@naver.com','룻방 고** 전교부회장 임명장 수여 받았습니다.','룻방 고** 아동이 전교부회장 임명장 수여 받았습니다.&nbsp;
<div>2학기에 전교부회장으로서 학교에서 귀하게 크게 쓰임을 받고 부회장으로서 활동함으로&nbsp;</div>
<div>많음 배움을 얻길 바라고 큰 뜻을갖고 성실히 학교생활 잘 할 수있도록 응원 해주시길 바랍니다!&nbsp;</div>          </td>
        </tr>',907,1692716400,'', '', '', '', '', '');
