INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (32864,'dus3','차송희','thd4378@naver.com','룻방 김*경,정* 덕수중학교 개학하였습니다.','여름방학이 끝나 개학한 저희 룻 큰 언니들입니다~!&nbsp;
<div>성실하고 열심히 학교생활하는 우리 정*, 현*이가 기특합니다^^*</div>
<div>개학 했으니 앞으로 힘차게 더 열심히 학교생활 하는 우리아이들을 응원합니다&nbsp;</div>
