INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (32715,'dus3','이세랑','rheese1228@naver.com','바울방 초등학생 아동들 방학 했습니다.','초등생들의 방학이 시작되었습니다~

<div>바울방 박*훈, 박*태, 박*윤, 소*지, 최*울 아동들의 여름방학이 시작되었습니다!</div>
<div>다 사용한 교과서를 가져와 배운것을 복습하는 시간도 갖고, 여름방학을 알차게 보내기 위해 계획을 세우고 있습니다!&nbsp;</div>
<div>무더운 여름 아동들이 즐거운 방학을 보낼 수 있도록 열심히 보육하겠습니다^^~</div>          </td>
        </tr>',850,1689865200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (32714,'dus3','김형식','','다윗방 초등학생 방학했습니다','<span style="color: #847f74; font-family: verdana">더위의 끝을 보여주는 오늘은 여름방학식이 있는 날입니다.&nbsp;</span>
<div style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana"><div style="margin: 0px; padding: 0px">아이들이 저마다 나의 학교생활과 여름방학 안내문을 받아왔습니다.&nbsp;</div>
<div style="margin: 0px; padding: 0px"><span style="font-size: 9pt">방학 때 공통과제와 나만의 과제 정해보는 시간을 가졌습니다.</span></div>
<div style="margin: 0px; padding: 0px">아동들이 안전하고 즐겁게 여름방학을 보낼 수 있도록 지원하겠습니다. ^^</div></div>          </td>
        </tr>',858,1689865200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (32713,'dus3','심주현','pikaccu85@hanmail.net','솔로몬 아이들 여름방학식 하였습니다.','오늘은 학교 여름방학식이 있는 날입니다.&nbsp;
<div>솔로몬방 *빈, *랑, *성, *태, *진이가 방학을 하였습니다.&nbsp;<br />
<div>아이들이 저마다 나의 학교생활과 여름방학 안내문을 받아와&nbsp;</div>
<div>1학기를 돌아보며 함께 이야기 나누는 시간을 보냈습니다.&nbsp;</div>
<div>여름방학때 공통과제와 나만의 과제도 정해보았습니다.&nbsp;</div>
<div>아이들이 알찬 여름방학 생활을 할 수 있도록 최선을 다해 지원하겠습니다. ^^</div></div>          </td>
        </tr>',868,1689865200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (32712,'dus3','오정복','jungbokoh@hanmail.net','모세방 초등학생 방학 했습니다.','남산 초등학교 방학이 시작했습니다.
<div>모세방 장*아, 박*서, 지* 아동은 1학기를 성실하게 보내고 마무리도 잘 하였습니다.</div>
<div>1학기 짐을 가져와 정리하고 방학 기간 동안 하고싶은 일들에 대해 이야기도 하였습니다.</div>
<div>재미있고 보람된 방학이 되도록 보육하겠습니다.</div>          </td>
        </tr>',871,1689865200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (32709,'dus3','문소연','dawooriy3175@gmail.com','룻방 윤*은, 고*라 아동의 방학이 시작되었습니다.','오늘 남산초등학교 1학년, 6학년에 재학 중인
<div>윤*은 아동과 고*라 아동의 여름방학식이 있었습니다.</div>
<div>방학을 처음 맞이하는 윤*은 아동과&nbsp;</div>
<div>초등학교의 마지막 여름방학을 보내는 고*라 아동이</div>
<div>방학기간동안 건강하고 행복한 추억을 쌓았으면 좋겠습니다.</div>          </td>
        </tr>',872,1689865200,'', '', '', '', '', '');
