INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (32083,'dus3','김지은','','바울방 정*현 충무어린이집 등원시작했습니다.','바울방 정*현 아동 바울방의 막내가 금주 월요일부터 어린이집 등원을 시작했습니다.
<div>첫주는 적응기간으로 첫날은 1시간정도 있었고, 그 이후부터는 11시까지 2시간을 있어보았습니다.</div>
<div>벌써부터 친구들, 선생님, 어린이집 다 좋다며 더 있고 싶어합니다.</div>
<div>잘 적응하면 다음주부터는 더 있다가 오자고 하며 약속했습니다.</div>
<div>처음 며칠은 울기도 했으나 금일부터는 울지 않고 예쁘게 인사하고 하원했습니다.</div>
<div>건강하게 적응하며 지낼 수 있도록 지도하겠습니다.</div>          </td>
        </tr>',983,1680620400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (32057,'dus3','심주현','pikaccu85@hanmail.net','남산초등학교 학부모 상담 다녀왔습니다.','<p>&lt; 2023.03.27~03.31&gt; 1주간 남산초등학교 학부모 상담 기간입니다. </p>
<p>우리 아이들이 학교 생활을 잘 하고 있는 것을 함께 이야기 나누며 </p>
<p>집에서와 학교에서의 모습들을 담임선생님과 함께 공유하는 시간을 가졌습니다. </p>
<p>큰 관심과 사랑으로 아이들을 대해 주시는 담임선생님들을 만나면서 </p>
<p>올 한해 학교 생활에 대한 걱정들이 한시름 놓였습니다. </p>
<p>아이들이 즐겁고 건강한 학교 생활을 할 수 있도록 열심히 지원하겠습니다. ^^</p>          </td>
        </tr>',965,1680188400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31991,'dus3','심주현','pikaccu85@hanmail.net','남산 초등학교 설명회 및 학급 설명회 참여하였습니다. (2023.03.15)','<p>남산초등학교 설명회 및 학급 설명회 참여하였습니다. </p>
<p>교장, 교감 선생님의 학교 운영 안내를 받으며 큰 열정과&nbsp; 관심으로&nbsp; 아이들을 위해 힘써 주시고 계시다는것을 </p>
<p>느낄 수 있었는데요 </p>
<p>학교 라운딩을 하면서 하나하나 소개해 주시는 모습에서 아이들을 위해 얼마나 신경을 많이 쓰고 </p>
<p>준비하셨는지 알 수 있는 시간이 되었습니다. &nbsp;</p>
<p>학급 설명회를 통해 새로운 담임선생님과도 인사를 나눌 수 있는 시간이 되어 좋았습니다. </p>
<p>아이들이 공부하는 책상에 앉아 교실을 바라보니 아이들의 학교생활을 조금이 나마 </p>
<p>알수 있음에 뭉클하기도 하였습니다. </p>
<p>아이들을 위한 좋은 교육환경에 힘써주시는 남산초등학교 김경미 교장선생님, 황신정 교감선생님 외 </p>
<p>남산초등학교 많은 선생님들께 진심으로 감사드립니다. ^^</p>          </td>
        </tr>',1040,1678892400,'', '', '', '', '', '');
