INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31734,'dus3','김지은','','남산초 개학했습니다','<font size="1">남산초 아동들 겨울방학 잘 보내고 개학했습니다.</font>
<div><font size="1">전날 방학숙제도 챙기고 필통도 챙기며 오랜만에 친구들과 선생님을 만날 설렘으로 준비 했어요.</font></div>
<div><font size="1">오늘 학교에 가서 숙제도 내고 친구들도 보니 너무 좋았다. 친구들이 많이 성장했다는 얘기도 했습니다.</font></div>
<div><font size="1">남은 학년 잘 마무리짓고 새 학년 맞도록 지도하겠습니다.</font></div>          </td>
        </tr>',953,1674745200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31733,'dus3','최준희','ch3596@hanmail.net','01월 26일 모세방  남산초 아동들 개학했습니다 !','즐거웠던 겨울 방학과 설 명절이 지난 후, 개학이 다가왔습니다 !
<div>보람차게 보냈던 방학을 마치며&nbsp;<span style="font-size: 9pt">방학이 끝나는 게 아쉽다고 이야기 했던 아동들이&nbsp;</span></div>
<div><span style="font-size: 9pt">오랜만에 친구들의 얼굴을 보고 와서&nbsp;</span><span style="font-size: 9pt">반가웠다고 이야기 하네요 ~</span></div>
<div>곧 다가올 종업식 전까지, 같은 반 친구들과 더 즐거운 추억 많이 쌓길 바라봅니다 ^^</div>          </td>
        </tr>',984,1674745200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31732,'dus3','이소영','','다윗방 남산초 아동들 개학했습니다 !(2022.01.26)','겨울방학이 끝나 개학한 저희 다윗방 형님들입니다.
<div>2023년이 되었고 이제 3월이 되면 정말로 학년 자체가 올라가기에, 아동들이 부쩍 더 커보입니다.</div>
<div>겨울방학동안 설날에는 곱게 한복 차려입고 아빠께 세배도 드리고, 세뱃돈도 받고. 시청역 스케이트장에서 스케이트도 타고, 국립중앙 박물관도 가는 등 방학동안에도 집에있지 않고 여러군데 다니면서 견문을 넓혔습니다.</div>
<div><br /></div>
<div>개학날에는 아침부터 눈이 내려 길이 미끄러웠지만 아동들은 굉장히 즐거워했습니다.</div>
<div>학교에서 친구들도 오랜만에 만나 이야기도 나누었다고 합니다.</div>
<div><br /></div>
<div>조금있으면 또 봄방학이지만, 개학한 이 기간동안엔 아동들 서로 잘 지내며 건강했으면 좋겠습니니다~!</div>          </td>
        </tr>',943,1674745200,'', '', '', '', '', '');
