INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31556,'dus3','김형식','','다윗방 남*초 아동들 겨울방학했습니다.','<div><span style="color: #847f74; font-family: verdana">한 해를 마무리하는 날 아동들이 다니는 학교에서도 겨울방학을 했습니다.</span></div>
<div style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">방학하며 겨울방학생활계획표를 받아왔습니다.</div>
<div style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana"><span style="font-size: 9pt">방학동안 아동들이 실천할 수 있는 자신과의 약속을 정해하고</span></div>
<div style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana"><span style="font-size: 9pt">스스로 실천에 옮길 수 있도록 지도할 예정입니다.</span></div>
<div style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">건강하고 보람찬 방학 보내도록 지도하겠습니다.</div>          </td>
        </tr>',1019,1672498800,'', '', '', '', '', '');
