INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31545,'dus3','김지은','','12월 30일 남산초 겨울방학식했습니다.','오늘은 남산초등학교 겨울방학식이 있는 날입니다.
<div>아동들 2학기 잘 마치고 귀가하여 털모자까지 하나씩 학교에서 선물로 받아왔습니다.</div>
<div>검정, 하늘 베이지 예쁜 색깔의 모자를 받아 기분좋게 귀가했습니다.</div>
<div>가방과 실내화, 실내화가방도 세탁하고 개학해서 깨끗한 걸로 가지고 가자고 하며 세탁해주었습니다.</div>
<div>겨울방학생활계획표도 하나씩 받아왔는데 아동들이 충분히 실천할 수 있는 내용입니다.</div>
<div>운동, 일기, 독서록 등의 숙제 잘 수행하고 건강하고 보람찬 방학 보낼 수 있도록 지도하겠습니다.</div>          </td>
        </tr>',943,1672326000,'', '', '', '', '', '');
