INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31075,'dus3','김형식','','다윗방 초등학생 학교상담 진행했습니다.','<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">아동들의 원만한 학교생활을 지원하기 위해</p>
<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">상,하반기에 한번씩 학교생활 상담을 진행하고 있습니다.</p>
<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">여러가지 일정 상 전화 상담 진행했습니다.</p>
<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">다윗방에는 초등학생이 모두 6명이 있는데</p>
<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">밝고 긍정적인 모습으로 생활하고 있다고 합니다.</p>
<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">아동들의 학교생활이 일상생활의 활력이 되도록</p>
<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">더 관심 가지며 지원 아끼지 않도록 하겠습니다. ^^</p>          </td>
        </tr>',920,1665414000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31056,'dus3','박계영','pky1216@naver.com','한나방 아동 2학기 학교상담 진행하였습니다.','2학기가 시작되고 아동들 한명씩 학교 상담을 진행하였고&nbsp;
<div>모두 상담을 잘 마쳤습니다.&nbsp;</div>
<div>1학기에 비해 학습 의욕도 늘고 적극적으로 참여하는 모습도 보인다며</div>
<div>모두 발전된 모습이라는 평에</div>
<div>조금씩 성장한 것 같아 기분이 좋습니다.&nbsp;</div>
<div>이번 학기도 잘 마무리 할 수 있도록&nbsp;</div>
<div>아동들 바르게 지원하겠습니다.</div>          </td>
        </tr>',912,1665068400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31055,'dus3','박계영','pky1216@naver.com','한나방 김*경 아동의 중간고사가 끝났습니다.','10/4~10/7까지 4일간의 중간고사가 끝이 났습니다.&nbsp;
<div>*경이는 올해 고3으로 이번이 고등학교 마지막 중간고사입니다.</div>
<div>아직 기말고사가 남아 있지만&nbsp;</div>
<div>마지막 중간고사를 후회없이 잘 치뤘기를 바래봅니다.&nbsp;</div>
<div>수고했어!</div>          </td>
        </tr>',944,1665068400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31054,'dus3','이소영','','솔로몬방 아동 2학기 학교상담 진행했습니다.','<p>솔로몬방 아동 전원 학교 상담을 진행했습니다.</p>
<p>아동들 모두 1학기때에 비해 조금 더 점잖아지거나 또는 더 활달해지거나 인기쟁이였습니다.</p>
<p>2학기를 맞이하여 아동들이 건강히 학교를 잘 다녔으면 좋겠습니다.</p>
<p>항상 저희 아동들을 사랑과 관심으로 대해주시는 남산초 모든 선생님들께 감사의 말씀 드립니다.</p>          </td>
        </tr>',901,1665068400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31039,'dus3','이주현','dlwngus0608@gmail.com','바울방 배*욱 아동 2학기 학교상담 진행했습니다.','바울방 배*욱 아동 담임선생님과의 학교상담 진행했습니다.
<div>아동은 원내에서와 같이 바른 모습과 활발한 모습을 학교에서도 보여주고 있다고 합니다.</div>
<div>눈웃음이 예쁜 아동으로 학교에서도 밝고 웃음 가득한 모습이 가득함을 칭찬해주셨습니다.</div>
<div>성적이 좋으며, 교우관계도 좋아 걱정할 점이 하나 없는 아동으로 칭찬만으로 학교 상담을 마무리했습니다.</div>
<div>아동이 행복한 학교 생활 할 수 있도록 도움 주시는 남산초 선생님들께 감사드립니다.</div>          </td>
        </tr>',930,1664722800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31018,'dus3','박계영','pky1216@naver.com','한나방 한*은 아동의 2학기 중간고사 끝났습니다.','<div><br /></div>2학기 중간고사가 끝이 났습니다.&nbsp;
<div>끝난 즐거움과 함께 결과가 걱정된다고 말합니다.</div>
<div>이틀 동안의 짧은 중간고사 였지만</div>
<div>
<div>그 동안 준비하며 노력했던 *은이의 결과가 잘 나오기를 기대해봅니다.</div></div>          </td>
        </tr>',909,1664463600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31013,'dus3','박현진','wls3379@naver.com','룻방 김*경 아동 중간고사 끝났습니다.','<p>룻방 김*경 아동 9/28-29 동안 중간고사 시험이었습니다.</p>
<p>채점하며 잘 본 것 같다고 하는 모습이 대견합니다.</p>
<p>앞으로도 열심히 준비해서 원하는 결과 나오길 바랍니다.</p>
<p><br /></p>
<p>&nbsp;</p>          </td>
        </tr>',897,1664463600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31010,'dus3','양현주','','바울방 박*태, 박*훈 아동 2학기 학교상담 진행했습니다.','박*훈 아동은 개학하고 학교생활에 잘 적응도 하고

<div>친구들 과도 잘 지내며 학습 능력도 보통이상이라고 칭찬해 주셨습니다.</div>
<div><br /></div>
<div>박*태 아동은 밝은 모습으로 글씨도 바르게 쓰고 참여하는 모습이</div>
