<div><br /></div>
<div>항상 저희 아이들 격려와 칭찬해주시는 남산초 선생님들의 노고에도 감사드립니다 ^^*</div>          </td>
        </tr>',962,1664377200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31020,'dus3','김지은','','9월 30일 바울방 최*울 체험학습다녀왔습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'2209300414119_1.jpg\');><img src=\'/admin/data/bbs/dus3/M2209300414119_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
