INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31009,'dus3','김지은','','남산초 박*태 아동 학교상담진행했습니다.','금주 월요일부터는 남산초등학교 담임선생님과 학부모가 상담하는 주간입니다.

<div>9월 27일 화요일에 바울방 박*태 아동 선생님과 교사가 상담하는 시간을 가졌습니다.</div>
<div>코로나로 방문하지 않고 전화상담으로 진행했습니다.</div>
<div>박*태 아동은 소극적인 모습이 있었는데 자기 감정 등의 표현도 잘하고 적극적인 모습을 보이고 있다며 칭찬해주셨습니다.</div>
<div>자습을 하면 선생님과 공부를 같이 하지 못해서 속상해한다며 학습의욕도 높고, 선생님께 의지하는 모습도 조금 있지만 열심히 생활하고 있다며 좋은 말씀 많이 해주셨습니다.</div>
<div>또래들과도 잘 어울리고 학교생활 충분히 잘 해내고 있어 감사한 마음이 듭니다.</div>
<div>남은 한 학기도 건강하게 학교생활 불편함 없이 잘 할 수 있도록 지도하겠습니다~</div>          </td>
        </tr>',1476,1664377200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31001,'dus3','박초아','cjdk1004@naver.com','한나방 덕수중 2학기 중간고사 기간입니다.','<p>한나방&nbsp;덕수중 한*은 아동 2학기 중간고사가 시작되었습니다~!</p>
<p>9월 28일부터 9월 29일까지 시험을 보게 됩니다.</p>
<p>잘 준비해서 좋은 성과 거두길 기원합니다~^^</p>          </td>
        </tr>',935,1664290800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31008,'dus3','김지은','','남산초 장*울, 김*빈 아동 학교상담했습니다','금주 월요일부터는 남산초등학교 담임선생님과 학부모가 상담하는 주간입니다.
<div>9월 26일 월요일에 바울방 장*울, 김*빈 아동 선생님과 교사가 상담하는 시간을 가졌습니다.</div>
<div>코로나로 방문하지 않고 전화상담으로 진행했습니다.</div>
<div>장*울 아동은 밥도 잘 먹고, 운동신경이 뛰어나 체육활동을 매우 잘하고 아동들과도 잘 어울린다며 칭찬해주셨습니다.</div>
<div>김*빈 아동은 1학년인데 1학기에 비해 학교생활 잘 적응하고 있고, 또래들과도 잘 어울리고 있으며 먼저 다가가는 면을 보이고 있고 학습수준이 높다고 칭찬해주셨습니다.</div>
<div>남은 한 학기도 잘 보낼 수 있도록 지도하겠습니다~</div>          </td>
        </tr>',954,1664377200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30940,'dus3','이소영','','솔로몬방 남산초 아동들 개학했습니다 !(2022.09.13)','남산초 개학을 했습니다.(2022.09.13)
<div>아동들은 방학동안 월미도 여름캠프, 교보문고, 다이소, 편의점, 남산산책 등 다녀오며 활동적이게 지냈습니다.</div>
<div>또한 방학숙제도 열심히 해서 제출토록 하였지요.</div>
<div><br /></div>
<div>2학기가 시작되는 날 깨끗하고 단정한 옷을 입도록 하고 등교했지요.</div>
<div>새학기 방과후를 아동들이 원하는것으로 선정하고 그렇게 결정되어 아동들 기대감도 좋습니다.</div>
<div><br /></div>
<div>2학기에도 건강하고 예의바른 아동들이 되도록 보육하겠습니다~!</div>          </td>
        </tr>',927,1663081200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30938,'dus3','양현주','','바울방 남산초 아동들 개학했습니다~','흥겨운 명절을 보내고 개학날이 되었습니다~

<div>들뜬 마음 이겠지만 차분하게 조심조심 다녀올 수 있도록 이야기 나누고</div>
<div>친구들과 여름방학동안 있었던 일들에 대해 이야기도 나누고 선생님과&nbsp;<span style="font-size: 9pt">반갑게 인사도 나누었다고 합니다.&nbsp;</span></div>
<div>방학이 끝나고 학교에 가게 되어 기쁘고 즐겁다고 이야기하는 아동들입니다.&nbsp;</div>
<div>박*훈, 박*태, 김*빈 아동은 오늘부터 방과 후 수업이 시작되었습니다.</div>
<div>음악 줄넘기 수업에 참여하여 신나는 음악에 맞춰 줄넘기를 하는 수업입니다.</div>
<div>처음이라 어려웠다고 이야기하지만 익숙하지 않아 그렇기에 열심히 잘 배워보자고 격려해주었습니다.&nbsp;</div>          </td>
        </tr>',918,1662994800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30754,'dus3','박초아','cjdk1004@naver.com','한나방 김*민, 손*영 아동 개학식 했습니다.','<p>동명생활경영고교 김*민, &nbsp;손*영 아동이&nbsp; 개학했습니다.</p>
<p>아동들에겐 짧은 여름방학이였겠지만 </p>
<p>좋은 추억과 경험을 느낀 방학이였길 바래봅니다^^</p>
<p>아동들이 다시 학교생활에 잘 적응할 수 있도록 지원하도록 하겠습니다~!</p>
<p><br /></p>          </td>
        </tr>',906,1661094000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30724,'dus3','박계영','pky1216@naver.com','한나방 한*은 아동 개학식 했습니다.','<p>방학을 마치고 *은이는 개학을 하였습니다. </p>
<p>다소 짧게 느껴진 여름방학이었지만 </p>
<p>충분한 휴식시간도 갖고 즐거운 활동과 공부도 하며 </p>
<p>알차게 보낸 여름방학이었습니다. </p>
<p>이제 다시 학교 생활에 적응하고</p>
<p>학업에 집중하도록 옆에서 도와주겠습니다. </p>          </td>
        </tr>',891,1660748400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30722,'dus3','서혜빈','','룻방 김*경 아동 개학식 했습니다.','<p>기나긴 방학이 끝나고 다시 일상으로 돌아가며 개학식을 맞이했습니다.</p>
<p>부지런하고 열심히 학교생활을 하는 현*이가 대견합니다~</p>
<p>앞으로도 학교생활에 있어 부족함 없이 지원하도록 하겠습니다.^^</p>
<p>화이팅!</p>          </td>
        </tr>',843,1660748400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30709,'dus3','박초아','cjdk1004@naver.com','한나방 김*경 아동 개학 했습니다.','<p>중경고 김*경 아동이 8/16(화)에 개학했습니다.</p>
<p>고등학교에서의 마지막 여름방학 알차게 보내고 </p>
<p>다시 등교를 시작하였습니다^^!</p>
<p>학교생활 잘 할 수 있도록 지원하겠습니다~!</p>          </td>
        </tr>',881,1660662000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30697,'dus3','이소영','','솔로몬방 아동들이 남산초 방과후 수업 참여하였습니다~','방학을 했어도 매주 월~금까지는 아동들 방과후수업에 참여한 것 그대로 참여합니다.
<div><span style="font-size: 9pt">월/목요일은 키즈쿠킹, 수/금요일은 컴퓨터 수업으로 아동들이 학기초에 원했던 방과 후 그대로 진행되고 있습니다.</span></div>
<div>키즈쿠킹 다녀온 아동들은 수업 후 자신이 만든 음식들을 함께하는 아동들에게 나누며 같이 먹기도 하구요 컴퓨터를 배운 아동은 집에</div>
<div>있는 컴퓨터를 활용하여 학교에서 배운것들을 응용하고 복습하고 있습니다.</div>
<div><br /></div>
<div>방학동안에도 집에만 있는 게 아니라 방과후 수업을 위해 학교를 가는데요, 기특하기도 하고 어느새 이렇게 자랐나 느껴지기도 합니다.</div>
<div>건강하게 잘 자라 개학날 한층 더 발전된 아동들이 되었으면 좋겠습니다.</div>          </td>
        </tr>',926,1660489200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30592,'dus3','김형식','','다윗방 초등학생 여름방학했습니다.','<p>초등학생&nbsp;6명의 아동이 여름방학을 했습니다. </p>
<p>학교 사정으로&nbsp;추석연휴까지&nbsp;기나긴 여름방학이 이어집니다.</p>
<p>개학은&nbsp;9월13일!!</p>
<p>방학식을 하고 온 오늘, 초등학생 모두&nbsp;들뜬 모습입니다^^</p>
<p>긴 방학기간 알차고 즐겁게 보내도록&nbsp;아낌없이 지원하겠습니다. </p>          </td>
        </tr>',963,1659106800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30584,'dus3','김혜숙','rhdnsdd2@naver.com','모세방 남산초 아동들 여름방학을 했습니다.','<p>남산초 박**. 지* 아동이 여름방학을 했습니다. </p>
<p>학교 사정으로 9월12일 추석연휴까지 집에서&nbsp;지내고 9월13일 개학을 하게 됩니다.</p>
<p>방학식을 하고 온 오늘, 신나고 들뜬 모습입니다^^</p>
<p>긴 방학기간 알차고 즐겁게 보내도록 마음을 다해 지원하겠습니다. </p>          </td>
        </tr>',912,1659020400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30585,'dus3','차송희','thd4378@naver.com','룻방 남산초등학교  아동들 여름방학 했습니다.','<p>남산초등학교 정*, 연*빈 아동 여름방학했습니다. </p>
<p>추석연휴까지 쉬고 9월13일 개학합니다. </p>
<p>방학을 해서 마냥 좋은지 신나고 들떠하는 모습입니다.^^</p>
<p>방학기간 동안&nbsp; 즐겁고 건강하게 학을 보낼 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',888,1659020400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30544,'dus3','박현진','wls3379@naver.com','한나방 *서가 상장을 받았습니다.','<p>한나방 *서가 학교에서 상장을 받아왔습니다.</p>
<p>*서 학급이 평소 바른 식습관을 가지고 \'잔반 줄이기\'를 모범적으로 실천하여 우수한 반으로 선정되었다고 합니다.</p>
<p>학교 생활도 모범적으로 열심히 하는 *서 칭찬합니다 ^^</p>
<p>&nbsp;</p>          </td>
        </tr>',920,1658415600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30527,'dus3','박계영','pky1216@naver.com','한나방 *영이와 *은이가 상장을 받았습니다.','<p>고등학교에 다니는 *영이는 교내 &lt;학교사랑 미술 공모전&gt;에서 </p>
<p>자유표현 부문에 입상하였습니다. </p>
<p><br /></p>
<p>중학교에 다니는 *은이는 교내 &lt;창업경진대회&gt;에서 우수한 발표로 동상을 수상하였습니다.</p>
<p><br /></p>
<p>아이들이 열심히 준비한 모습만으로도 뿌듯하였지만</p>
<p>상을 받아오니 더욱 기쁜 마음입니다.</p>
<p>아이들 모두 잘하였다고 응원과 칭찬 보내주세요:)</p>          </td>
        </tr>',910,1658242800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30526,'dus3','박계영','pky1216@naver.com','한나방 중,고등 아동들이 여름방학을 했습니다.','<p>중경고는 7/19(화)~8/16(화)</p>
<p>덕수중은 7/20(수)~8/18(목)</p>
<p>동명생경고는 7/20(수)~8/22(월)까지</p>
<p>여름방학 기간입니다.</p>
<p>방학을 맞이한 아동들은 신난 모습입니다.</p>
<p>방학동안 아이들이 한가지 목표를 가지고 알차게 보내도록 지원하겠습니다. </p>          </td>
