INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30451,'dus3','박계영','pky1216@naver.com','한나방 손*영, 김*민 아동의 기말고사 마지막날입니다.','오늘은 *민이와 *영이의 기말고사 마지막날입니다.&nbsp;
<div>그동안 잠도 줄여가며 공부한 아이들이 대견합니다.</div>
