INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30186,'dus3','차송희','thd4378@naver.com','룻방 남산초 공개수업 참여했습니다.','<p>오늘은 남산 초등학교 공개수업이 있는 날이였습니다. </p>
<p>우리아이들이 학교에서 어떻게 수업하고 어떻게 지내는지 많이 궁금했는데요 </p>
<p>염려하던 저의 마음과 달리 밝고 씩씩하게 선생님이 문제 내는것에 손을 번쩍 들어보이며 답하기도 하고 적극적인 수업태도로 속담문제를 내보기도 하고 맞추기도 하며&nbsp;&nbsp;아이들은 친구들과 같이 적극적으로 수업 참여하엿습니다. </p>
<p>아이들이 학교생활을 즐겁게 잘 할수있도록 지원하겠습니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',950,1653404400,'', '', '', '', '', '');
