INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30179,'dus3','김형식','','다윗방 남산초 공개수업 참여했습니다.','<p>오늘 남산초등학교에서&nbsp;학부모 공개수업이 있어 다녀왔습니다. </p>
<p>다윗방에는 2학년부터 4학년까지 6명의 아동이 있는데</p>
<p>분주하게 교실을 다니며 아동들의 학습하는 모습을 봤습니다.</p>
<p>수업을 진행하는 선생님의 말씀에 열심히 집중도 하고</p>
<p>자신감 넘치는 모습을 손을 번쩍 번쩍 들고 발표도 잘하는 모습이었습니다.</p>
<p>학교에서 오는 피드백에 늘 걱정이 앞서기만 했는데</p>
<p>아동들의 학교생활하는 모습을 보니 기우였고,&nbsp;많이&nbsp;컸음을 느꼈습니다. </p>
<p>앞으로도 아이들이 학교 생활을 즐겁게 &nbsp;잘&nbsp; 해 나아갈 수 있도록 </p>
<p>늘 아낌없이 지원하도록 하겠습니다. ^^</p>          </td>
        </tr>',980,1653404400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30178,'dus3','이주현','dlwngus0608@gmail.com','바울방 남산초등학교 학부모 공개수업에 참여하였습니다.','<p>오늘은 남산초에서 학부모참관수업이 있던 날입니다.</p>
<p><br /></p>
<p>김*빈 아동, 박*태 아동, 배*욱 아동, 박*수 아동의 공개수업에 참여하였습니다. 집이 아닌 학교에서는 어떻게 생활하고 있을지 궁금하였는데 우리 아동들이 바르게, 즐겁게, 행복한 학교생활을 하고 있음을 수업내내 느낄 수 있었답니다~!</p>
<p><br /></p>
<p>담임선생님의 말씀에 귀 기울이고, 대답도 잘하며 발표도 씩씩하게 큰 소리로 해내는 아동들이 대견하고 멋있게 느껴지는 하루였습니다. </p>
<p>아동들이 잘 생활할 수 있도록 도와주시는 남산초 모든 선생님들! 감사드립니다 ^^</p>          </td>
        </tr>',931,1653404400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30175,'dus3','심주현','pikaccu85@hanmail.net','모세방 남산초등학교 학부모 공개수업에 참여하였습니다.','<p>오늘 남산초등학교에서 진행한 학부모 참여수업에 다녀왔습니다. </p>
<p>1학년 *율, 3학년 *빈, *아 수업에 참관하였는데요 </p>
<p>학교에서 열심히 공부하는 나름 진지하고 집중력도 좋아 보였습니다. </p>
<p>발표도 씩씩하게 잘 하고 친구들과&nbsp;사이좋게 어울리는 모습을 보니 어찌나 든든하던지요~</p>
<p>눈을 마주치고는 더 자세를 바르게 고쳐 앉는 모습이 많이 긴장된듯 보였습니다. </p>
<p>학교에서 공부하는 모습에서 많이 성장하였음을 느낄 수 있었습니다. </p>
<p>앞으로도 아이들이 학교 생활을 즐겁게 &nbsp;잘&nbsp; 해 나아갈 수 있도록 지원하겠습니다. <br /></p>
<p><br /></p>          </td>
        </tr>',972,1653404400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30061,'dus3','김유진','coti501@naver.com','룻방 김*경 아동의 중간고사가 끝났습니다.','4월28일-29일 이틀간의 중간고사가 끝났습니다:)<br />열심히 공부하고 시험도 잘 치뤘다고 말해주는 아동의 모습이 기특합니다.<br />본인이 공부한 만큼의 성적을 받을 수 있기를 바랍니다.<br />          </td>
        </tr>',908,1651590000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30174,'dus3','이소영','','솔로몬방 남산초 학부모 공개수업에 참여하였습니다.','금일 남산초 학부모 공개수업에 참여하였습니다.  <br />아동들은 단번에 알아보고 눈인사도 하고 손인사도 하며 자신의 존재를 알렸지요. <br />집에서의 생활만 보다가 학교 생활을 보니 감회가 새로웠습니다. <br /><br />발표시간에 손을 번쩍번쩍 드는 아동이 있는가 하면 목소리를 차분하게 내며 수업에 참여하는 아동도 있었어요. <br />학교도 학년에 맞춰 교실이 꾸며져 있었는데 구경할것도 많고 아동들의 활동작품 등을 보게 되어 더 좋았습니다. <br /><br />뛰어노는 모습이 활기찼고 담임선생님들께 각 인사도 드렸습니다. <br />남산초 학교 선생님~! 항상 아동들을 위해 노력해주시는 점 감사합니다~!           </td>
        </tr>',912,1653404400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30060,'dus3','김지은','','5월 4일 남산초 어린이날 체육대회 했습니다','<p>오늘은 남산초등학교에서 어린이날 체육대회를 했습니다.</p>
<p>아침부터 편안한 복장을 하고, 시원한 물과 모자를 챙겨 그리고 선크림을 발라 아동들 모두 등교했습니다.</p>
<p>코로나 상황이 많이 완화되어 행사도 할 수 있게 되어 감사합니다.</p>
<p>아동들 다치지 말고 안전하게 활동하고 재미있게 행사 참여하도록 했습니다.</p>
<p>내일은 어린이날, 내일 모레는 남산초 자율휴업일입니다.</p>
<p>아동들 한주간 즐겁게 보낼 수 있도록 지도하겠습니다.</p>          </td>
        </tr>',977,1651590000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29991,'dus3','김혜은','','다윗방 정*호 어린이집 상담 했습니다.','<p>어린이집 상담 기간을 맞이하여 전화 상담이 아닌 대면 상담을 진행했습니다.</p>
<p>어린이집에서 발표도 잘하고 친구들과도 사이좋게 지낸다고 합니다.</p>
<p>앞으로도 잘 지낼 수 있도록 더 많이 격려해주었습니다.</p>          </td>
        </tr>',970,1650639600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30058,'dus3','박계영','pky1216@naver.com','한나방 손*영, 김*민 아동의 중간고사 마지막날입니다.','4/28(목)~ 5/3(화) 까지 *영이와 *민이의 중간고사 기간이었습니다.
<div>마지막날인 오늘은 시험이 끝나 즐거운 마음과&nbsp;</div>
<div>시험결과가 어떻게 될지로 인해 무거운 마음이&nbsp; 공존하는 아이들 입니다.&nbsp;</div>
<div>첫날부터 마지막날까지 잠을 줄이며 열심히 공부한 아이들이</div>
<div>만족 할 결과를 받기를 바라며 오늘은 편안히 휴식하도록 하였습니다.&nbsp;</div>
<div>기말고사를 잘 보겠다며 의욕적인 아이들을 교사들도 열심히 지원하겠습니다.</div>
<div><br /></div>          </td>
        </tr>',911,1651503600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29974,'dus3','김유진','coti501@naver.com','룻방 임*하, 유*인 필동어린이집 상담했습니다.','룻방 임*하, 유*인 필동어린이집 전화상담했습니다. <br />두 아동 모두 어린이집 선생님께서 친구들과 사이좋게 지내고 양보도 잘하며 스스로 해야하는 일도 바르게 하는 아동이라며 칭찬을 많이해주셨습니다. 놀이나 친구들과 같이 하는 영어, 체육 등의 활동도 적극적으로 참여한다고 덧붙여서 이야기해주셨습니다. <br />아이들 앞으로도 재미있게 어린이집 생활할 수 있도록 지원하겠습니다! <br />          </td>
        </tr>',1052,1650207600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29921,'dus3','김혜숙','rhdnsdd2@naver.com','모세방 유** 회현어린이집 현장학습 다녀왔습니다.','<p>금일 유** 아동이 회현어린이집에서 신당누리센터에 있는 \'하티붕붕\'으로 현장학습을 다녀왔습니다. </p>
<p>안전을 위해 회현어린이집 숲속반&nbsp;아동들만 입장하여 체험활동을 했다고 합니다. </p>
<p>**가 어린이집 생활을 잘 할 수 있도록 더욱&nbsp;열심히 지원하겠습니다. </p>          </td>
        </tr>',1115,1649862000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29971,'dus3','김지은','','4월 18일 바울방 필동어린이집 최*울 전화상담했습니다.','<p>필동어린이집 최*울 전화상담했습니다.</p>
<p>아동이 어린이집에서 잘 적응하고 있을지, 친구들과 잘 지내고 있을지 걱정했는데</p>
<p>큰 문제없이 잘 지내고 있다고 하셨습니다.</p>
<p>너무 사람을 좋아해서 옆에 붙어 있는 것을 좋아한다고 하시며 애정이 많은 아동이라고 하셨습니다.</p>
<p>아동 앞으로도 잘 적응하며 지낼 수 있도록 지도하겠습니다.</p>          </td>
        </tr>',962,1650207600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29922,'dus3','조한음','gksdma9277@naver.com','다윗방 정** 회현어린이집에서 현장학습 다녀왔습니다.','<p>정** 아동이 회현어린이집에서 중구육아종합지원센터 내 실내놀이터 \'하티 붕붕\'으로 현장학습을 다녀왔습니다</p>
<p>예약제 놀이터로 안전을 위해 미리 예약을 진행해,&nbsp;회현어린이집 숲속반만 입장하여 체험활동을 했다고 합니다. </p>
<p>정** 아동이&nbsp;어린이집 생활을 잘 할 수 있도록 더욱&nbsp;열심히 지원하겠습니다.</p>          </td>
        </tr>',962,1649862000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29871,'dus3','김지은','','바울방 박*수 아동 학교생활 상담 했습니다.','바울방 박*수 아동 담임선생님과 학교생활에 관한 상담을 진행했습니다.
<div>아동의 기본적인 생활에 관해 궁금하셨던 질문 몇가지 해주셔서 답변드리고,</div>
<div>담임선생님과 공유하며 아동을 이해하는 시간을 가졌습니다.</div>
<div>그리고 담임선생님께서 아동의 생활태도와 교우관계, 학교생활적응도 등에 관해 말씀해주셨습니다.</div>
<div>아동은 수업시간에 태도도 매우 좋고, 또래 친구들과도 잘 지내며 학교생활 성실히 하고 있다고 긍정적으로 말씀해주셨습니다.</div>
<div>앞으로도 생활에 어려움 없이 잘 지낼 수 있도록 지도하겠습니다.^^</div>          </td>
        </tr>',933,1649170800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29872,'dus3','차송희','thd4378@naver.com','룻방 정* 학교상담 진행했습니다.','<p><br /></p>
<p>새학기가 되어 학부모 전화상담 시작했습니다~!&nbsp;&nbsp;진단평가 국어, 수학 높은 점수 받았으며&nbsp;수학 단원평가도 높은점수 받았다고 말씀해주시며&nbsp; 학습태도, 이해도가 좋다고 칭찬해주셨습니다. 아동이 친구들을 잘 챙기는 것을&nbsp;유심히 봐주시며 신경써주시는 선생님들께 감사한 마음이 들고 아동 또한 새학기 새학년이 되어&nbsp;학습에 있어&nbsp;열심히 하고자 하는 모습과 공부에 대한 의지가 높고 친구들을 잘챙긴다는 아동의 착한 마음이 대견하고 기특한 마음이 듭니다.&nbsp;&nbsp;밝게 잘 성장할 수 있도록 학교생활 잘 적응할 수 있게&nbsp;지도 하겠습니다! &nbsp;&nbsp;</p>
<p><br /></p>          </td>
        </tr>',957,1649170800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29867,'dus3','서혜빈','','룻방 연*빈, 지* 아동 학교상담 진행했습니다.','<p>새학기가 시작되어 학부모 전화상담을 했습니다~^^</p>
<p>학교에서도 무엇이든 열심히 하며, 밝고 모범적으로 잘 생활하고 있다며</p>
<p>아낌없는 칭찬 해주셨습니다. 새로운 환경에서도 적응을 잘 하고, 성실한 모습으로</p>
<p>지내고 있어 대견스러운 마음이 큽니다. 늘 관심을 가지며 신경써주시는 선생님들께도</p>
<p></p>
<p>감사한 마음 입니다. 앞으로도 우리 아동들이 건강하고, 밝게 성장하며 </p>
<p>학교생활 할 수 있도록 신경써서 지원하도록 하겠습니다.^^</p>          </td>
        </tr>',923,1648998000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29841,'dus3','김채윤','','솔로몬 방 박*윤,이*민 초등학교 학부모상담을 했습니다.','<p class="0"><font face="돋움">금일 솔로몬 방 박<span lang="EN-US" style="letter-spacing: 0pt">*</span>윤 아동의 남산초 학부모 상담이 있었습니다<span lang="EN-US" style="letter-spacing: 0pt">.</span></font></p>
<p class="0"><font face="돋움">박<span lang="EN-US" style="letter-spacing: 0pt">*</span>윤은 친구들과 교우관계가 좋고 장난꾸러기 같은 모습도 있고 늘 활기차게 생활하고 있다고 합니다<span lang="EN-US" style="letter-spacing: 0pt">. </span>반 친구들과 다같이 대답하거나 합동해서 할 때 열정적인 모습이 보인다고 합니다<span lang="EN-US" style="letter-spacing: 0pt">. </span>개별 발표 할때는 쑥스러워 하지만 열심히 하는 모습을 보인다고 합니다<span lang="EN-US" style="letter-spacing: 0pt">.</span></font></p>
<p class="0"><span style="font-family: 돋움; font-size: 9pt">솔로몬방 이*민 아동은</span></p>
<p class="0"><span style="font-family: 돋움">이*민은 학교에서 조용하지만 자신의 할 일을 잘 해내고 친구들과 잘 지내려 노력하는 모습을 보인다고 합니다. 체육반장을 맡아 친구들과 어울려 활동할 수 있도록 힘쓰는 모습을 예쁘게 봐주셨습니다.&nbsp;</span></p>
<p class="0"><span style="font-family: 돋움"><br /></span></p>
<p class="0"><font face="돋움">아동을 위해 힘써주시는 담임선생님께 감사드리고 아동이 밝은 미소와 적극성을 가지고 학교에서 생활할 수 있도록 힘쓰겠습니다<span lang="EN-US" style="letter-spacing: 0pt">.</span></font></p>
<p class="0" style="background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial">  <font face="돋움">&nbsp;</font>  <o:p></o:p></p>          </td>
        </tr>',938,1648652400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29836,'dus3','이소영','','솔로몬방 박*민 아동 남산초 학부모상담 했습니다','금일 솔로몬 방 박*민 아동의 남산초 학부모 상담이 있었습니다.

<div>담임선생님께서 아동에 대해 똑똑하고 주변을 살필줄 알며 친구들과도 사이좋게 지내려 노력한다고 합니다.</div>
<div>부쩍 자라나는 아동이고 생각이 많은 우리 박*민 아동이 이번 학기동안 친구들과 사이좋게, 웃으며 행복하게 지냈으면 좋겠습니다.</div>
<div><br /></div>
<div>아동을 위해 힘써주시는 초등학교 담임 선생님께 감사드리며, 저희 교사 또한 아동의 깔깔거리는 미소가 더 풍부해지도록 애쓰겠습니다.</div>          </td>
        </tr>',949,1648566000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29838,'dus3','양현주','','바울방 박*훈, 배*욱 아동 1학기 학교상담 진행하였습니다~','<p>공룡과, 동물을 좋아하는 박*훈 아동은 공통 관심사가 있는 친구들과 </p>
<p>이야기를 나누는 것을 좋아하고 책도 많이 읽으며 낙천적이고 활동적으로 잘 생활하고 있다고 합니다 ^^</p>
<p><br /></p>
<p>배*욱 아동은 운동신경이 좋은만큼 체육시간에 가장 즐거워하며 규칙적으로 모범적이게 </p>
<p>잘 생활하며 친구들과도 잘 지내고 있다고 합니다. </p>          </td>
        </tr>',947,1648566000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29833,'dus3','김혜숙','rhdnsdd2@naver.com','모세방 정**, 박** 아동 남산초 학부모상담 했습니다','<p>이번 학기도 코로나로 인해 전화상담을 했습니다.</p>
<p>3학년이 되어 전보다 성숙하고 예민해진 아동들이</p>
<p>학교생활을 어떻게 하고 있는지 궁금한 점이 많았는데</p>
<p>상담을 통해 아이들을 더욱 이해하는 시간이 되었습니다.</p>
<p><br /></p>
<p>앞으로도 아동들이 학교생활을 잘 할 수 있도록</p>
<p>세심하게 지원하겠습니다&nbsp;</p>          </td>
        </tr>',941,1648479600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29828,'dus3','양현주','','바울방 박*태 아동 1학기 학교상담 진행하였습니다~','<p>집에서도 미소천사인 아동은&nbsp;학교에서도 밝게 웃고 적극적이라고 하셨습니다.</p>
<p>서투른 부분이 있어도 노력하고 끝까지 최선을 다하는 모습에 칭찬도 받고 있고, </p>
<p>활동적인 모습으로 잘 적응하고 있어 좋은 이야기를 많이 해주셨습니다 ^^</p>          </td>
        </tr>',929,1648393200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29826,'dus3','서혜빈','','룻방 김*경 아동 학교상담 진행했습니다.','<p>룻방 현*이의 새학기 첫 학교상담을 진행했습니다.</p>
<p>방역수칙 지키며 학교방문 대면상담으로 진행하였습니다. 룻방에서 처럼 </p>
<p>학교에서도 성실하고 바르게 생활하고 있다고 칭찬 많이 해주셨습니다.</p>
<p>현*에게도 긍정적으로 관심 가져주며 지도 해주시고 있는 선생님들께도 감사드립니다.</p>
<p>앞으로도 현경이가 곧고 바른 모습으로 학교생활 열심히 할 수 있도록</p>
<p>지원하겠습니다~^^<br /></p>
<p><br /></p>          </td>
        </tr>',887,1648393200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29823,'dus3','김지은','','바울방 소*지, 박*태, 김*빈 학교생활 상담 했습니다.','남산초등학교에 입학한 아동들 어린이집 생활과는 달라진 환경과 분위기로 인해&nbsp;
<div>잘 적응하고 있을 지 많은 걱정을 했는데 그 걱정은 괜한 걱정이었습니다.</div>
<div>아동들의 학교생활과 교우관계, 수업태도 등을 파악하고 선생님과 아동들에 관하여 공유하며</div>
<div>지도하고자 전화상담을 했습니다.</div>
<div>코로나로 인하여 대면하지 않고 전화상담을 하였는데 아동들 모두 친구들과도 잘 지내고 선생님 말씀도 잘듣고,</div>
<div>성실하게 수업참여하고 있다며 많은 칭찬해달라고 하셨습니다.</div>
<div>전화상이었지만 담임선생님들의 목소리와 아동들을 생각하는 마음이 느껴져서 좋은 시간이었습니다.</div>
<div>앞으로도 아동에 관해 중요사항 연락하기로 하며 통화 마무리하였습니다.</div>
<div>아동들 앞으로도 학교생활 잘 해나갈 수 있도록 지원하겠습니다.</div>
<div>&nbsp;</div>          </td>
        </tr>',935,1648393200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29822,'dus3','박계영','pky1216@naver.com','한나방 박*주 학교생활 상담했습니다.','<p>박*주 아동의 학교생활에 대해 상담을 하였습니다.</p>
<p>코로나로 인해 전화로 상담을 진행하였습니다.</p>
<p>학교에서 교유관계도 좋으며 적극적으로 참여하는 모습이 보기 좋다고 합니다.</p>
<p>앞으로도 아동의 활기찬 학교생활을 위해 세심히 신경쓰며 지도하겠습니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',958,1648393200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29821,'dus3','김형식','','다윗방 박*성, 고*태 학교생활 상담 했습니다.','<p>남산원에서는 신학기 아동들의 원만한 학교생활을 지원하기 위해</p>
<p>상,하반기에 한번씩 학교생활 상담을 진행하고 있습니다.</p>
<p>코로나19로 인해 방문 상담 하지 못하고 비대면으로 상담 진행했습니다.</p>
<p><br /></p>
<p>같은반인&nbsp;박*성, 고*태&nbsp;두 아동 모두</p>
<p>교우관계도 원만하고, 학급 분위기도 이끌어 갈 만큼</p>
<p>활기차고, 긍정적인 모습으로 생활하고 있다고 합니다.</p>
<p>좋은 피드백으로 인해 기분 좋은 상담시간이었습니다.</p>
<p><br /></p>
<p>아동들의 학교생활이 일상생활의 활력이 되도록</p>
<p>더 관심 가지며 지원하도록 하겠습니다. ^^</p>          </td>
        </tr>',936,1648393200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29753,'dus3','김희양','neworder@naver.com','김*경 학생이 바리스타 자격증을 취득하였습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'2203170235452_1.jpg\');><img src=\'/admin/data/bbs/dus3/M2203170235452_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
