INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29669,'dus3','김형식','','다윗방 아동들 개학했습니다.','<p>다윗방 아동들이 다니고 있는 남*초 / 성*공고가 개학했습니다.</p>
<p>유난히 겨울방학이 길게 느껴졌는데 아동들이 개학을 해 등교하니</p>
<p>뭔가 허전함이 밀려왔습니다.</p>
<p>하지만 이내 하교한 아동들로 인해 북적북적 해지는 것을 보니 개학이 실감납니다.</p>
<p>새롭게 시작된 새학기. 아동들이 학교생활에 충실하며 성실하게 다니도록 지원하겠습니다!</p>          </td>
        </tr>',936,1646146800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29675,'dus3','양현주','','바울방 아동들 새학기 맞이하여 남산초 등교하였습니다.','새 학기가 시작되어 아동들이 설레는 마음으로 학교에 다녀왔습니다. <br />작년에 같은 반이었던 친구와 새롭게 만나는 친구들에 대해 이야기를 나누고  <br />1학년 소*지 아동은 수업이 재미있었다고 이야기하기도 했습니다. <br />학교 의자에 앉아 오랜 시간 수업하는 것이 힘들었을 법도 한데 제법 대견스럽습니다^^ <br />아동들이 잘 적응할 수 있도록 매일 하교하고 돌아와 이야기를 나누고 있습니다.           </td>
        </tr>',950,1646233200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29667,'dus3','김유진','coti501@naver.com','룻방아이들 오늘 개학했습니다!','<p>룻방 언니들은 오늘 학교 개학을 하고 동생들은 어린이집에 처음으로 다니기 시작한날입니다^.^&nbsp;동생들은 처음 등원임에도 불구하고 씩씩하게 어린이집에 잘 다녀왔습니다. 언니들은 새로운 친구, 선생님, 환경에서의 앞으로를 많이 기대하고 있는 모습입니다. <br />아이들이 새로운 환경에서 잘 적응할 수 있도록 열심히 보육하겠습니다. <br /></p>          </td>
        </tr>',889,1646146800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29666,'dus3','심주현','pikaccu85@hanmail.net','솔로몬 초등학생 아이들 오늘 개학하였습니다. ^^','<p>오늘 솔로몬 아동들 학교 개학을 하여 등교하였습니다. </p>
<p>새학년, 새 친구, 새 담임선생님을 만나 매우 설레여 하였는데요~</p>
<p>벌써 부터 학교 생활이 많이 기대되는 모습입니다. </p>
<p>아이들이 안전하게 학교 생활을 즐겁게 시작할 수 있도록 지원하겠습니다. ^^</p>          </td>
        </tr>',934,1646146800,'', '', '', '', '', '');
