INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29121,'dus3','박계영','pky1216@naver.com','한나방 김*연, 김*민 아동이 졸업식을 하였습니다.','<p>오늘은 한나방 김*연, 김*민 두 아동이 졸업식을 하였습니다.<br />코로나로 인해 같이 참석하여 축하해주지 못해 아쉽지만</p>
<p>아이들끼리 즐거우면서 뭉클한 졸업식을 다녀온 것 같습니다.&nbsp;<br /></p>
<p>김*연 아동은 고등학교를 졸업하여 대학생활을 기다리고 있으며<br />김*민 아동은 중학교를 졸업하여 고등학교 생활을 기다리고 있습니다. <br /></p>
<p>두 아동 모두 졸업 축하합니다.<br /></p>          </td>
        </tr>',1029,1641481200,'', '', '', '', '', '');
