INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29119,'dus3','차송희','thd4378@naver.com','룻방 김*경아동 겨울방학식 했습니다.','오늘 룻방 덕수중학교 재학중인 김*경 아동의 겨울방학식이 있었습니다.
<div>내일부터 겨울방학기간인데 방학식 하기 전부터 방학하면 무엇을 하고 지낼지 들떠서 교사에게 말하는 모습을 보였습니다.&nbsp;</div>
<div><span style="font-size: 9pt">이번 겨울방학을 맞아 방학기간동안 무엇을 하며 시간을 의미있게 사용할지 계획을 짜보기도 하였는데 아이들이 건강하고 시간을 의미있게 보낼 수 있고 바르게 생활할 수 있도록 지도하겠습니다^^&nbsp;</span></div>          </td>
        </tr>',939,1641481200,'', '', '', '', '', '');
