INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29102,'dus3','김희양','neworder@naver.com','솔로몬방 아동들 겨울방학을 했습니다.','<p>솔로몬방 박*윤, 박*민, 박*진 아동이 겨울방학을 맞이했습니다.</p>
<p>겨울방학 생활표도 열심히 만들었고</p>
<p>방학동안 해야 할 것들에 대해서도 이야기 나누며</p>
<p>건강하고 즐거운 방학을 보내보기로 하였습니다.</p>
<p>즐거운 겨울방학 보내도록 하겠습니다.</p>          </td>
        </tr>',1002,1641308400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29105,'dus3','양현주','','바울방 남산초 아동들 방학했습니다.','금일 남산초등학교 방학식을 했습니다. <br /><br />이*민, 박*수, 박*성, 박*태, 박*훈 5명 아동 방학생활계획표를 작성하고 <br /><br />방학 동안 이루고 싶은 목표에 대해서도 각자 두 가지 씩 적어보았습니다. <br /><br />이룰 수 있는 작은 목표부터 차근차근 도전해 보고 알찬 방학을 보낼 수 있도록 <br /><br />방학 생활 계획에 대해서도 이야기 나눴습니다.           </td>
        </tr>',943,1641308400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29099,'dus3','김혜은','','다윗방 남산초 아동들 방학식 했습니다.','<p>아동들이 그토록 기다리고 바라던 방학식을 했습니다.</p>
<p>방학을 해서 너무 기쁘고 신이난다고 합니다.</p>
<p>숙제 없는것도 좋지만 재미있게 놀 생각에 더 서레인다고 합니다.</p>
<p>겨울동안 건강하게 생활하면서 즐거운 방학생활 잘 보내도록 하겠습니다.</p>          </td>
        </tr>',968,1641308400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29098,'dus3','박현진','wls3379@naver.com','한나방 고*라, 박*리, 박*주, 박*서 아동들 겨울 방학식 했습니다.','<p>오늘은 남산초의 겨울방학 날 입니다.</p>
<p>한나방의 고*라, 박*리, 박*주, 박*서 아동들이 방학을 했습니다.</p>
<p>코로나로 인해 마스크&nbsp;쓰고 수업듣는게 불편했을텐데 이번 년도도 모두 수고했습니다^^ </p>
<p>각자 세운 겨울방학 생활계획표 잘 지키고,&nbsp;즐거운 활동도 하고,</p>
<p>열심히 학습 하면서 보람찬 방학으로 잘 보낼 수 있도록 지도하겠습니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',992,1641308400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29096,'dus3','김안나','kl951023@naver.com','모세방 박*빈,  장*아 아동이 겨울방학을 했습니다.','아이들이 손꼽아 기다리던 방학이 시작되었습니다.
<div>새교과서를 미리 받아 틈틈히 읽고 있는 우리 아이들이 기특합니다.~</div>
<div>커다란 동그라미 계획표도 만들어 두었으니 내일부터는 알찬 가정학습을 위해 열심히 하겠습니다.</div>
<div><br /></div>          </td>
        </tr>',944,1641308400,'', '', '', '', '', '');
