INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29095,'dus3','김유진','coti501@naver.com','룻방 정*, 연*빈 아동 방학식 했습니다.','<p>오늘 룻방 정*, 연*빈 아동이 다니는 남산초의 겨울방학식이 있었습니다.<br />내일부터 2월28일까지 신나는 겨울방학 기간입니다!<br />이번 겨울방학을 맞아 아이들이 스스로 하고싶은 일, 해야할 일들을 계획표로 만들어두었는데<br />아이들이 잘 지키고&nbsp;건강하게 생활할 수 있도록 옆에서&nbsp;바르게 보육하겠습니다!^___^</p>
<p>&nbsp;</p>          </td>
        </tr>',899,1641308400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29044,'dus3','박현진','wls3379@naver.com','한나방 김*연, 박*민 아동 대학 합격했습니다.','<p>한나방 큰 언니들의 기쁜 소식입니다.</p>
<p>김*연 아동 서일대, 박*민 아동 유한대 합격 했습니다. </p>
<p><br /></p>
<p>20대 첫 시작인 대학교에서 보람있고&nbsp;즐거운 추억만 가득하고,</p>
<p>새로운 친구, 새로운 학교에서 다양한 경험들을 통해 더 행복하고 발전하길 바랍니다.</p>
<p>*연이, *민이 에게 많은 축하와 응원 부탁드립니다.</p>
<p><br /></p>
<p>너무너무 축하합니다 *^^*</p>
<p><br /></p>          </td>
        </tr>',1046,1640790000,'', '', '', '', '', '');
