INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28780,'dus3','김혜숙','rhdnsdd2@naver.com','한나방 김** 아동 동명생경고 합격했습니다.','<p>한나방 중3 김** 아동이 &nbsp;동명생경고에&nbsp;합격했습니다. </p>
<p>노력한 만큼 좋은 결과를 얻어 흐뭇합니다. </p>
<p>고등학교 생활도 지금처럼 열심히 하리라 기대해봅니다. </p>
