INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28740,'dus3','김안나','kl951023@naver.com','모세방 이*나 아동 충무어린이집 하반기 상담을 진행하였습니다.','<p>5세 *나는 호기심이 많고 새로운 물건을 좋아하며 어린이집에서 하는 모든 활동에 적극적으로 참여한다고 합니다.</p>
<p>몸을 움직이고 조절하는 신체활동도 잘하고 식사와 간식도 잘 먹어 건강합니다.</p>
<p>사회성 발달에 중요한 시기인 지금 다양한 친구들과 다양한 놀이활동을 하는 모습을 기대하고 있습니다.~</p>          </td>
        </tr>',1033,1637679600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28729,'dus3','박계영','pky1216@naver.com','한나방 보성여고 기말고사 기간입니다.','<p>한나방 보성여고 김*연 아동 11/22~11/30까지 기말고사 시험기간입니다.<br />얼마전 수능을 치른 고3 아동이라 큰 부담없이 시험에 임하고 있지만 </p>
<p>고등학교 마지막 시험인 만큼 유종의 미를 거둘수 있도록 잘 지도 하겠습니다.<br /></p>          </td>
        </tr>',1000,1637506800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28728,'dus3','박계영','pky1216@naver.com','한나방 김*경 아동 바리스타3급 자격증 취득','<p>한나방 김*경 아동이 사단법인 한국커피협회에서 시행하는 </p>
<p>바리스타 3급 자격증을 취득하였습니다.<br />한걸음 더 성장한 아동을 축하해주시고 응원해주세요^^ 감사합니다.</p>          </td>
        </tr>',1074,1637506800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28709,'dus3','양현주','','룻방 유*민아동 충무어린이집 하반기 학부모 상담 진행하였습니다.','<p>5살 유*민 아동의 어린이집 학부모 상담을 진행하였습니다.</p>
<p>어린이집에서 친구들과도 잘 지내고 모범이 되는 모습을 많이 보여준다고 전달받았습니다.</p>
<p>따듯하고 부드러운 말투를 사용하고 어휘력도 좋아 친구들에게 좋은 영향을 끼치고 있다고 합니다.</p>
<p>애교도 많고 친구들과도 사이좋게 지내는 모습 칭찬해 주며 내년에도 씩씩한 여섯 살이 되자고 아동하고 이야기 나누었습니다.</p>          </td>
        </tr>',1025,1637247600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28694,'dus3','김혜숙','rhdnsdd2@naver.com','한나방 아동들 수능시험입니다.','<p>한나방 김**, 박**아동 수능시험 참여합니다. </p>
<p>아이들 인생에서 제일 큰 시험을 치르는 거니 얼마나 떨릴까요?</p>
<p>차분하게 실력을 모두 발휘하길 기원합니다. </p>
<p><br /></p>
<p>며칠 전부터 아이들 도시락을 신경써주신 국장님, </p>
<p>새벽에 일어나 정성껏 도시락을 싸주신 선생님, &nbsp;감사합니다. </p>          </td>
        </tr>',956,1637161200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28596,'dus3','양현주','','룻방 필동어린이집 지* 아동 하반기 학부모 전화상담하였습니다~','<p>금일 필동어린이집 지* 아동 학부모 전화상담을 진행하였습니다.</p>
<p>집에서와같이 어린이집에서도 모범이 되어 친구들을 돕고 선생님도 많이 돕는다고 하였습니다.</p>
<p>학습 수준도 또래에 비해 높은 편이고 굉장히 똘똘하여 칭찬을 많이 해주셨습니다.</p>
<p>칭찬해 주신 부분 아동에게 이야기해주자 쑥스러워 하지만 매우 기분 좋아하였습니다.</p>
<p>지* 아동은 내년이면 초등학교에 입학하게 되어 조금씩 준비해 나가고 있습니다.</p>          </td>
        </tr>',987,1635951600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28699,'dus3','김지은','','룻방 지* 세계아동미술대회 최우수 수상했습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'2111190119383_1.jpg\');><img src=\'/admin/data/bbs/dus3/M2111190119383_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
