INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28587,'dus3','김지은','','11월 1일 남산초 개교기념일입니다','<p>오늘은 남산초등학교 개교기념일입니다.</p>
<p>초등학생 아동들은 학교에 가지 않고 오전에는 부족한 과목을 선택하여 학습하고, </p>
<p>병원에 가서 독감예방접종도 맞고 왔습니다.</p>
<p>울지 않고 씩씩하게 주사도 맞았답니다.</p>
<p>내일은 남산초 재량휴업일이라 학교에 가지 않는데 학습도 하고, 휴식취하여 즐겁게 하루 보낼 수 있도록 지도하겠습니다.^^</p>          </td>
        </tr>',1041,1635692400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28574,'dus3','양현주','','남산초 정* 아동 학교 전화상담진행하였습니다.','<p>정* 아동이 09월 새로 남산 초로 전학을 와서 첫 전화상담을 진행하였습니다. </p>
<p>아동이 잘 적응하고 있는지 여쭤보자</p>
<p>친구들과도 적응을 잘하고 발표도 잘하고 있다고 칭찬해 주셨습니다.</p>
<p>아동이 잘 적응할 수 있도록 지도하겠습니다 ^^*</p>          </td>
        </tr>',1002,1635606000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28572,'dus3','김지은','','남산초 연*빈 아동 학교전화상담했습니다','<p>남산초 연*빈 아동 학교 담임선생님과 전화상담진행했습니다.</p>
<p>전화상담 내내 아동의 학교생활에 대해 많은 칭찬을 해주셨습니다.</p>
<p>친구들과도 잘 지내고 수업태도도 좋고, 숙제나 모든 면에서 잘하고 열심히 한다고 해주셨습니다.</p>
<p>특히나 체육쪽은 앞에 나와서 할 정도로 아동이 잘 하는 과목이라고 말씀해주셨습니다.</p>
<p>아동이 앞으로도 학교생활에 어려움없이 잘 적응하며 지낼 수 있도록 지도하겠습니다.</p>          </td>
        </tr>',947,1635606000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28571,'dus3','김지은','','룻방 덕수중 김*경 아동 학교전화상담진행했습니다','<p>룻방 김*경 아동 학교담임선생님과 전화상담 진행했습니다.</p>
<p>아동이 1학기에 비해 조금씩 적극적인 모습을 보이고 있고, 또래들과도 잘 어울리는 모습과</p>
<p>다양한 프로그램을 진행하고 있는데 가장 잘 참여하고 결과물도 좋다고 말씀해주셨습니다.</p>
<p>열심히 하는 아동이라고 칭찬 많이 해달라고 하셨습니다.</p>
<p>앞으로도 남은 1학년 생활 잘 마무리할 수 있도록 지도하겠습니다.</p>          </td>
        </tr>',985,1635606000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28564,'dus3','김아름','kjj375@naver.com','10월29일 모세방 유*나 필동어린이집 전화상담 진행하였습니다.','<p>필동어린이집 다니는 리* 상담 진행 했습니다.</p>
<p>상담은 비대면&nbsp;전화상담으로 진행 되었습니다.</p>
<p>&nbsp;어린이집 등원 전&nbsp;늘 아동과 약속하고 가던 일은 많이 좋아졌다고 담임선생님께 이야기 들어 아동에게 칭찬을 해 주었습니다.</p>
<p>앞으로도 좋은 얘기만 들을 수 있도록 더욱 노력하겠습니다.</p>          </td>
        </tr>',1032,1635519600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28497,'dus3','김혜숙','rhdnsdd2@naver.com','한나방 중, 고등아동들 중간고사 잘 마쳤습니다.','<p>학교마다 일정을 조금씩 달리하여 9월 말부터 시작된 중간고사를 금일 박*민 아동을 끝으로 잘 마무리하였습니다. </p>
<p>새벽까지 잠을 이겨가며 열심히 노력한 아이들에게 박수를 보냅니다.</p>
<p>노력한만큼 좋은 성적이 나왔다고 기뻐하는 모습을 보면서 잘 성장하고 있음에 보람을 느낍니다.</p>
<p><br /></p>
<p>학교생활을 잘 할 수 있도록 더욱 열심히 지원하겠습니다. </p>          </td>
        </tr>',963,1634655600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28397,'dus3','김민지','','솔로몬방 박*윤,박*민,박*진 아동 상담하였습니다.','<p>학교에서 세 아동 모두 잘 지내고 있다고 하셨습니다.</p>
<p>우리 아이들 , 앞으로도 학교생활 잘 할수 있도록</p>
<p>적극 지원하겠습니다</p>          </td>
        </tr>',1046,1633186800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28380,'dus3','김혜은','','바울방 이*민, 박*수, 박*성, 박*훈 아동 학교 상담하였습니다.','<p>아동들이 학교 생활 잘 하고 즐겁게 생활 하고 있다고&nbsp;합니다.</p>
<p>아동들에게 칭찬 많이 해주면서 앞으로도 잘 지낼 수 있도록 이야기 하였습니다.</p>          </td>
        </tr>',1057,1632927600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28372,'dus3','이소영','','다윗방 고*태, 박*랑 아동 학교생활 상담했습니다','금일 오후 다윗방 아동의 학교 상담을 전화통화로 진행하였습니다.<br />두명 모두 1학기 때보다 현저히 학급태도와 학습실력이 향상하여 선생님이 칭찬 많이 하셨어요.<br />아동들이 점차 자라나며 긍정적으로 바뀌고 또 의젓해 지는게 느껴져 참 대견하고 좋습니다.<br />건강하며 바른 인성을 가지고 자라날 수 있도록 교사 또한 역량이 중요하다가 다시한번 느낍니다.          </td>
        </tr>',977,1632927600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28368,'dus3','김예지','','한나방 고*라, 박*리 아동 학교 상담을 진행하였습니다.','<p>  남산초등학교 2학기 학교상담을 진행하였습니다. 코로나19로 인하여 전화상담을 하게 되어 아쉬웠습니다.</p>
<p>*리, *라 담임선생님께서 아동들을 칭찬해주시는 목소리와 말투에서 저희 아동들 많이 아끼고 사랑해주심을</p>
<p>느낄 수 있었습니다.&nbsp;미흡한 부분도 있지만 바르게 잘 나아가고 있다고 하셔서 한시름 놓았습니다.</p>
<p>앞으로도&nbsp;아동들이 바르게 자랄 수 있도록 더 신경쓰며 노력하겠습니다. :)&nbsp;</p>          </td>
        </tr>',1006,1632841200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28366,'dus3','안유나','','모세방 장*아, 박*빈아동 학교전화상담 진행하였습니다.','<div>남산초등학교 장**, 박** 아동 하반기상담 진행하였습니다.</div>코로나19로 인해 대면상담이 아닌 비대면상담 진행하였습니다.
<div>아이들의 학교생활에 대해 자세히 알 수 있는 시간이 되었습니다.</div>
<div>선생님들이 두 아동 모두 칭찬을 많이 해주셔서 너무 뿌듯한 시간이었습니다.</div>
<div>1학기 때보다 많이 활발해진 장**아동, &nbsp;교우관계가 무척 좋은 박**아동,</div>
<div>두 아동들이 건강한 학교생활 할 수 있도록 많은 지원하도록 하겠습니다.</div>
<div><br /></div>          </td>
        </tr>',1001,1632841200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28354,'dus3','서혜빈','','바울방 박*태 아동 학교전화상담 진행하였습니다.','<p>박*태 아동 코로나로 인해 비대면 전화상담 진행하였습니다.</p>
<p>아동의 학교생활 및 교우관계에대해 상세하게 말씀해주시고, 더불어 진*가 1학기에 비해 더 성장하였다고 </p>
<p>칭찬도 많이 해주셨습니다~~^^&nbsp;앞으로도&nbsp;바른 모습으로 성장하며 학교생활에도 긍정적인 영향을 </p>
<p>미칠 수 있도록 아낌없는 사랑과 관심 주며 보육하도록 하겠습니다.</p>
<p>항상 애써주시는 선생님께도 다시한번 감사드립니다~!!<br /></p>          </td>
        </tr>',972,1632668400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28353,'dus3','김혜숙','rhdnsdd2@naver.com','한나방 박*주, 박*서 아동 학교상담을 하였습니다.','<p>남산초 2학기 학교상담을 진행하였습니다. </p>
<p>코로나19로 인해 1학기와 마찬가지로 전화상담을 하게되서 아쉬웠습니다. </p>
<p>*주, *서 모두 담임선생님께서 칭찬을 많이 해주셨습니다. </p>
<p>특히나 1학기보다 성장한 부분을 뿌듯해하시니 듣는 저도 흐뭇합니다. </p>
<p></p>
<p>아동들이 바르게 성장할 수 있도록 더욱 노력하겠습니다. </p>
<p></p>          </td>
        </tr>',995,1632668400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28352,'dus3','김형식','','다윗방 배*욱, 박*호 아동 학교생활 상담했습니다','<p>아동들의 원만한 학교생활을 지원하기 위해</p>
<p>상,하반기에 한번씩 학교생활 상담을 진행하고 있습니다.</p>
<p>코로나19만 아니면 학교에 방문해 선생님을 뵙고 상담을 진행할텐데</p>
<p>아쉽게도 전화로 상담을 진행했습니다.</p>
<p>배*욱, 박*호 두 아동 모두 긍정적인 모습으로 생활하고 있다고 합니다.</p>
<p>아동들의 학교생활이 일상생활의 활력이 되도록</p>
<p>더 관심 가지며 지원하도록 하겠습니다. ^^</p>          </td>
        </tr>',949,1632668400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28099,'dus3','김형식','','08월17일 남산초, 성동공고 개학했습니다.','<p>30여일의 여름방학을 마치고 21학년도 2학기 개학을 했습니다.</p>
<p>전날 등교 준비하며 아이들과 이야기를 나눴는데</p>
<p>빨리 학교 가고 싶다고 다들 아우성이더라구요...</p>
<p>2학기 학교생활도 아동들이 잘 적응하며 보내도록 지원하겠습니다!!</p>          </td>
        </tr>',996,1629385200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28084,'dus3','서혜빈','','남산초등학교 개학 하였습니다^^','<p>행복했던 여름방학을 지나 다시 일상으로 돌아가 개학을 맞이하였습니다~^^</p>
<p>오랜만에 선생님과, 친구들을 만나니 감회가 새롭고 즐거웠다고 이야기 하는 아동들에게</p>
<p>앞으로도 학교 생활 열심히 할 수 있도록&nbsp;격려해주었습니다.</p>
<p>아동들 학교 생활에 부족함 없도록 잘 보육하도록 하겠습니다~</p>
<p>남은 학기도 화이팅^^!!</p>          </td>
        </tr>',984,1629126000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27895,'dus3','김지은','','7월 16일 남산초 방학했습니다~^^','<p>남산초등학교 방학이 시작되었습니다~</p>
<p>8월 16일까지 31일간 방학을 하게되었습니다.</p>
<p>코로나19로 매일 마스크를 끼고 열심히 등교수업에 참여했는데 모처럼 여름방학을 맞았습니다.</p>
<p>4단계로 격상되며 언제까지 힘든 시간이 지속될지 모르겠지만 여름방학동안 학교숙제도 열심히하고,</p>
<p>다양한 프로그램에 참여하며 건강한 여름! 알찬 여름방학을 보낼 수 있도록 지도하겠습니다~^^</p>          </td>
        </tr>',1023,1626447600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27790,'dus3','김지은','','한나방 보성여고, 중경고 기말고사 시작됐습니다.','한나방 보성여자고등학교 김*연, 중경고등학교 김*경 기말고사 시험기간입니다.

<div>월요일부터 시험이 시작되서 김*연 아동은 점심먹고 학원에 가서 늦게까지 시험공부를 하고오고, 김*경 아동은 자습시간을 활용하여 교과서 위주로 공부하고 있습니다.</div>
<div>성적이 오르면 좋겠지만 노력하는 것이 더 중요하다고 알려주고&nbsp;<span style="font-size: 9pt">학습 충실히 할 수 있도록 지도하겠습니다.</span></div>
<div><span style="font-size: 9pt">더운 날씨속에 컨디션 관리 또한 신경쓰겠습니다~</span></div>
<div><div><br /></div></div>          </td>
        </tr>',1152,1624892400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27481,'dus3','김채윤','','다윗방 곽*민 아동이 학교에서 위촉장을 받아왔습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'2105191021297_1.jpg\');><img src=\'/admin/data/bbs/dus3/M2105191021297_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
							<col width=100%></col>
