								<td><img src=\'\' border=\'0\' name=\'wiz_target_resize\' width=\'0\' height=\'0\'></td>
							</tr>',1297,1620140400,'KakaoTalk_20210505_184107618.jpg', '', '', 'KakaoTalk_20210505_184107618.jpg', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27337,'dus3','김지은','','한나방 보성여고 중간고사 끝났습니다.','<p>한나방 보성여고 3학년인 김**아동 중간고사 끝났습니다.</p>
<p>4월 26일부터 시작한 시험이 끝나게 되어 지금은 학원다니고 방과후 수업과 온라인야자 참여하면서</p>
<p>수능을 대비하여 준비하고 있습니다.</p>
<p>앞으로도 열심히 준비해서 원하는 대학 진학할 수 있도록 돕겠습니다.</p>          </td>
        </tr>',1183,1620054000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27336,'dus3','김지은','','한나방 덕수중 중간고사 잘 치뤘습니다.','한나방 덕수중 3학년인 김**아동 중간고사 4월 29일-4월 30일까지 시험을 봤습니다.  <br />이틀간 시험을 봤는데 며칠동안 늦은 밤까지 공부하고, 학원수업다니면서 시험 열심히 준비했습니다. <br />결과는 아직 나오지 않았지만 그동안 수고 많았고, 노력한 만큼 좋은 결과 거둬서 원하는 고등학교 입학 할 수 있도록 <br />지도하겠습니다.           </td>
        </tr>',1069,1620054000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27329,'dus3','서혜빈','','바울방 김*빈 필동어린이집 정기상담 진행하였습니다.','<p>김*빈 아동 어린이집 전화상담 진행하였습니다.</p>
<p>늘 밝고 애교가 많은 우*이는 어린이집에서도 선한 영향력을&nbsp;선사한다고 합니다.&nbsp;</p>
<p>또래관계도&nbsp;좋으며, 선생님에게도 사랑을 듬뿍 주며 의젓하게 생활하고 있다고 합니다.</p>
<p>어린이집에서도 씩씩하게 적응하며&nbsp;아무탈 없이 잘 지내주어 참 다행입니다~^_^</p>
<p>우빈이에 대한 칭찬을 너무나 많이 해주셔서 상담 내내 흐뭇한 마음이였습니다~</p>
<p>항상 사랑으로 아껴주시는 어린이집 선생님께도 진심으로 감사드립니다~~</p>
<p><br /></p>          </td>
        </tr>',1062,1619967600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27292,'dus3','양현주','','룻방 지* 아동 필동어린이집 상반기 정기상담 했습니다~^^*','<p>룻방에 귀여운 막내 지* 아동 어린이집 정기 상담을 하였습니다.</p>
<p>의사 표현이 확실하며 논리적으로 이야기한다고 이야기하시며 </p>
<p>친구들과도 너무 잘 어울리며 야무지게 생활하고 있다고 전달받았습니다. </p>
<p>2학기에는 학교 갈 준비를 하며 앉아있는 연습과 기초 연산에 대해 활동할 예정이라고 합니다.</p>
<p>친구들을 도와주며 선생님께서도 너무 든든하다며 칭찬 일색이셨습니다. </p>
<p>칭찬에 약한 지* 아동이 어린이집에서도 솔선수범을 많이 하는 것 같습니다.</p>
<p>좋으신 선생님들을 만나 예쁨을 많이 받고 있는 지* 아동입니다 ^^</p>          </td>
        </tr>',1060,1619708400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27053,'dus3','김혜숙','rhdnsdd2@naver.com','4월1일 1학년 박**, 박** 남산초 학교상담 하였습니다.','<p>1학년 박**, 박** 남산초 학교상담을 했습니다.</p>
<p>아이들이 다행히 학교생활에 잘 적응하는 중이라고&nbsp;합니다. </p>
<p>학교와 긴밀히 연계하면서 부족함 없이 성심껏 지원하겠습니다.</p>          </td>
        </tr>',1093,1617202800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27052,'dus3','김채윤','','03월 31일 박*진, 박*주, 박*호 학교상담 했습니다.','<p>새학년이 된 이후 학교를 계속 등교 하면서 우리 아이들의 학교생활에 대해 궁금한 부분들을</p>
<p>선생님들과 같이 공유하고 이야기를 나눴습니다.</p>
<p>칭찬해 주시는 부분들에 대해서 듣고 공감했으며 부족한 부분들과 지도가 필요한 부분들을 자세히</p>
<p>얘기를 나누며 아동들이 학교생활을 좀 더 잘 할 수 있도록 지도하겠습니다. </p>          </td>
        </tr>',1040,1617116400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27050,'dus3','김혜은','','바울방 이*민, 박*민 아동 학교 상담 했습니다.','<p>이*민, 박*민 아동 학교 담임선생님과 1학기 정기 전화 상담 진행했습니다.</p>
<p>학교생활과 친구들과의 관계에 대한 얘기 나누며 아동들과 더 잘 지낼 수 있도록 상담하였습니다.</p>          </td>
        </tr>',1046,1617116400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27042,'dus3','김채윤','','03월 29일 다윗방 배*욱, 장*울 학교 상담했습니다.','<p>작년 한해 학교를 가지 못하다가&nbsp; 올해 들어서 학교를 가게 되니 </p>
<p>아이들의 얼굴에서 생기와 웃음, 즐거운 모습들이 더 자주 보입니다.</p>
<p>학교에서의 생활이 어떨지 궁금하기도 하고 걱정되는 부분들도 있었습니다.</p>
<p>배*욱 담임선생님께서는 아동의 인사성과 교우관계, 학습에 대해서 나무랄데 없이</p>
<p>잘 하고 있다는 칭찬 섞인 말들을 전해 들었고</p>
<p>장*울 담임선생님께서는 지금까지 아동의 행동과 말들에 \'나이스하다\'라는 칭찬의 말을</p>
<p>자주 했었고 아동도 만족하며 더 가르쳐주고 싶은 착한 아이라는 칭찬을 들었습니다.</p>
<p>아직 어린줄로만 알았던 아이들이&nbsp;너무 의젓하고 학습에서도 성실하게 생활을 잘 하고 있다는 얘기를&nbsp;들어서</p>
<p>기분 좋게 상담을 마쳤습니다. ^^</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1064,1617116400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27030,'dus3','양현주','','룻방 장*아 , 박*서 아동 1학기 학교 상담하였습니다.','<p>올해 1학년이 된 박*서 아동과 2학년이 된 장*아 아동의 학교상담을 진행하였습니다.</p>
<p>박*서 아동은 또래보다 야무지게 친구들을 챙기며 자신의 할 일을 잘 하고 있다고 하였습니다.</p>
<p>한글도 잘 읽고 학습 면에서 아주 잘하고 있다고 해주셨습니다. </p>
<p>장*아 아동은 학습 준비를 잘해오며 친구들과도 사교적이게 잘 어울린다고 하였습니다.</p>
<p>꼼꼼하고 야무진 성격에 칭찬을 많이 해주셨습니다.</p>
<p>두 아동 모두 친구들과 잘 어울리며 잘 적응하고 있어 다행이란 생각이 들었습니다.</p>
<p>칭찬도 많이 해주었답니다 ^^ 앞으로도 잘 적응할 수 있도록 지도하도록 하겠습니다!</p>          </td>
        </tr>',1092,1616943600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27040,'dus3','김민지','','룻방 박*주 , 박*빈 아동 학부모상담 진행하였습니다.','<p>오늘은 룻방의 *주와 *빈이의 상담을 진행했습니다~</p>
<p>작년에는 코로나로 인하여 등교를 많이 하지 못 한채, </p>
<p>올 해에 2학년이 되었습니다~</p>
<p>&nbsp;그래서 우리 아이들이 학교생활에&nbsp;적응을 잘 할수 있을까 걱정이 많았는데요~</p>
<p>다행히 우리 *주와 *빈이&nbsp;모두 학교생활을 잘 하고 있다고 합니다^^ </p>
<p>우리 룻방의 귀여운 *주와 *빈이의 학교생활을 응원해주세요~</p>
<p><br /></p>          </td>
        </tr>',1083,1617116400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27029,'dus3','이소영','','모세방 박*성, 박*태 아동 학교상담 진행했습니다.','초등학교 다니고 있는 저희 모세방 박*성, 박*태 아동 학교 상담을 오늘 오후에 진행하였습니다. <br />코로나로 인해 비대면 전화 상담을 진행하였는데요, 아동의 이야기 만으로 시간 가는 줄 몰랐습니다. <br />첫째인 박*성 아동은 자신의 반에서 학습적인 면에서 뛰어나다 칭찬 받고, 박*태 아동은 발음도 또랑또랑 말도 잘 한다고 칭찬 받았습니다. <br />아동들의 건강하고 예의바른 학교 생활을 위해 교사도 언제나 신경 쓰며 보육하겠습니다. <br /><br />*아동들을 위해 애써 주시는 초등학교 선생님 언제나 감사드립니다.           </td>
        </tr>',1077,1616943600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26982,'dus3','김지은','','한나방 김**, 한**아동 학교상담진행했습니다~','한나방 김**, 한** 아동은 덕수중학교에 다니고 있습니다.

<div>아동이 새학년이 되어 학교생활과 교우관계가 어떤지 담임선생님과 교사가 상담하는 시간을 가졌습니다.</div>
<div>코로나 19로 대면상담이 불가하여 전화상담을 진행하였는데,</div>
<div>한**아동은 배려심많고, 사교적인 성격으로 재미있게 학교생활하고 있다고 하셨고, 김**아동은 학습에 어려움을 보이지만 성실하게 학교생활하고 있다고 칭찬해주셨습니다.^^</div>
<div>아동이 학교생활에 잘 적응하고 있어서 안심이 되고 ,</div>
<div>앞으로도 열심히&nbsp; 생활할 수 있도록&nbsp; 지도하겠습니다.</div>          </td>
        </tr>',1079,1616598000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26984,'dus3','김지은','','한나방 김**아동 학교상담 진행했습니다~','<div>한나방 김**아동 덕수중 담임선생님과 전화상담 진행했습니다.</div>
<div>새학년이 되어서 학교생활 적응도와 교우관계, 학습태도, 진로/진학과 관련한 상담을 했습니다.</div>
<div>중3이 되어 고입을 바라보는 중요한 시기라</div>
<div>중3 1학기의 내신 비중이 커서 학습이 중요하다고 강조하셨고,</div>
<div>특성화고등학교로 진학에 대한 문의가&nbsp; 이루어졌습니다.</div>
<div>학습태도도 좋고 친구들과 두루 잘 지내고 있어 칭찬해주셨습니다.</div>
<div>앞으로도 학교생활 성실하게 할 수 있도록 지도하겠습니다.</div>          </td>
        </tr>',1047,1616598000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26938,'dus3','김혜은','','바울방 고*태, 박*훈 아동 학교상담 진행했습니다.','<p>고*태, 박*훈 아동 학교 담임선생님과 전화 상담 했습니다.</p>
<p>1학기 상담은 비대면으로 전화 상담 진행했습니다.</p>
<p>아동들이 학교 생활 적응 잘 하고 있고 교우관계도 적극적으로 잘 형성해나가고 있다고 하셨습니다.</p>
<p>앞으로도 적응 잘 할 수 있도록 잘 보육하겠습니다.</p>          </td>
        </tr>',1016,1616252400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26958,'dus3','김지은','','3월22일 한나방 박**아동 상장 받았습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'2103231129149_1.jpg\');><img src=\'/admin/data/bbs/dus3/M2103231129149_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
