INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26873,'dus3','김지은','','3월 16일 한나방 김*연 아동 장학금을 받게 되었습니다~','<p><br /></p>
<p>짝짝짝!!! 축하합니다~^^</p>
<p>한나방 고등생인 김*연 아동이 대상문화재단에서 장학금을 받게 되었습니다.</p>
<p>2020년 3월에 선발되었고, 2021년 3월부터 3, 6, 9, 12월까지 총 4달 각 30만원씩 120만원을 장학금으로 받게 됩니다.</p>
<p>대상문화재단은 국가발전에 기여할 우수한 인재를 육성하고, 학문발전에 기여하고 있는데</p>
<p>이러한 귀한 취지로 장학금을 받게 되었습니다.</p>
<p>받은 장학금 소중하게 잘 사용할 수 있도록 지도하겠습니다!!</p>          </td>
        </tr>',1059,1615820400,'', '', '', '', '', '');
