INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26576,'dus3','심주현','pikaccu85@hanmail.net','다윗방 남산초등학교 아이들 종업식을 하였습니다.','<p>오늘 남산초등학교 아이들 종업식을 하였습니다. </p>
<p>이번 개학기간에도 코로나19로 학교에 가지 못하고 온라인 수업을 하였는데요 </p>
<p>줌으로 친구들과 인사를 나누는 모습이 많이 애틋해 보였습니다. </p>
<p>영상으로 종업식 순서가 진행되었습니다. </p>
<p>국민의례 부터 원장님 말씀까지~&nbsp; </p>
<p>학교 소식도 영상으로 빠지지 않고 열심히 듣는 멋진 우리 아이들이 입니다. </p>
<p>이제 3월 2일 진급반으로 등교를 합니다. </p>
<p>2021년에는 친구들과 함께 공부를 할 수 있을 까요?</p>
<p>올해는 학교에서 새로운 담임선생님과 친구들이 함께 웃으며 수업하기를 기대해 봅니다. </p>          </td>
        </tr>',998,1613574000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26575,'dus3','양현주','','룻방 남산초 1,2학년 아동들 종업하였습니다!','<p>오늘은 1,2학년 아동들의 종업식 날입니다.</p>
<p>약 열흘간의 봄 방학 뒤에 새 학기가 시작됩니다.</p>
<p>새 교과서를 받고 이름을 적은 뒤에 교과서를 한 번씩 살펴보기도 했습니다. <br /></p>
<p>1학년 아동들은 줌 수업으로 종업식을 하며 비록 등교는 하지 못했지만 친구들과 인사를 나누며 몸은 멀어졌지만 </p>
<p>마음은 함께하자고 이야기를 하기도 하였습니다.<br />새로운 학년을 맞이하는 설레는 마음을 가지고 있는 아동들입니다. <br />약 열흘 정도의 짧은 방학이지만 1학년을 마무리하며 부족했던 부분에 대해 이야기도 나누어보고 더욱 성장하는 어린이가<br />되자고 하였습니다. 아동들 모두 씩씩하게&nbsp;<em>&nbsp;</em>대답하였습니다.<br />곧 1학년에 입학하게 되는 박*서 동생에게도 친절하게 학교생활에 대해 알려주기로 하였습니다. </p>          </td>
        </tr>',963,1613487600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26571,'dus3','김형식','','모세방 박*성. 이*민 종업식 참여했습니다.','<p>오늘 아이들이 다니고 있는 초등학교 종업식이 있었습니다.</p>
<p>코로나로 인해 학교에 잘 다니지 못해 그런지</p>
<p>아쉬움이 많이 남는다고 하네요~~</p>
<p>진급하는 학년에서 선생님 말씀 잘 듣고, 학교 생활하자고 이야기 해주었습니다.</p>
<p>3월이면 새학기 시작인데</p>
<p>남은 시간 잘 쉬고, 몸도 튼튼 마음도 튼튼하게 지내며 새학기 맞도록 지원하겠습니다 ^^</p>          </td>
        </tr>',977,1613487600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26569,'dus3','김예지','','한나방 김*경, 한*은 아동이 초등학교 졸업식을 하였습니다~^^*','<div align=\'LEFT\'><a href=javascript:viewImg(\'2102170841518_1.peg\');><img src=\'/admin/data/bbs/dus3/M2102170841518_1.peg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
							<col width=100%></col>
							<tr>
								<td><img src=\'\' border=\'0\' name=\'wiz_target_resize\' width=\'0\' height=\'0\'></td>
							</tr>',1014,1613487600,'09967572-868F-45CF-91DE-A677866585ED.jpeg', '', '', '09967572-868F-45CF-91DE-A677866585ED.jpeg', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26562,'dus3','김혜은','','바울방 3학년 배*욱, 1학년 고*태 아동 종업식 했습니다.','<p>오늘 남산 초등학교 종업식이 있었습니다.</p>
<p>바울방 배*욱 아동과 고*태 아동도 온라인 종업식에 참석했습니다.</p>
<p>교장선생님의 말씀도 듣고 애국가도 따라 부르며 종업식을 했습니다.</p>
<p>이제 4학년이 되는 배*욱 아동은 빨리 4학년이 되면 좋겠다며 기대감에 차있고 2학년이 되는 고*태 아동은 1학년 친구들과 진짜 헤어지는 것이냐며 교사에게 재차 확인합니다. 학교에서 만나면 반갑게 인사하자고 이야기 해주니 학교에서는 볼 수 있어서 다행이라고 합니다. 아동들이 아무탈 없이 학교생활 잘하고 마무리 할 수 있어서 다행입니다. </p>
<p>새로운 학년에서의 학교 생활도 우리 아동들이 잘 적응하고 잘 지낼 수 있도록 바라봅니다.</p>          </td>
        </tr>',986,1613487600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26556,'dus3','서혜빈','','바울방 4학년 배*욱 아동 등교하였습니다.','<p>배*욱 아동 개학하였습니다. 그동안 기다리고 기다렸던 개학 날을 맞이하니, 아동도 설레하며 기분이 한껏 들떠보이기도 하였습니다. 오랜만에 학교에 다녀온 기분을 물어보니, 선생님과 친구들을 만나니 매우 즐거웠다고 합니다. 올해는 코로나로 인하여 학교를 갔던날 보다 가지못한날이 더 많았던 나날이였지만 아쉬운 마음은 뒤로하고 좋은 추억으로 남기며 새로운 학기를 준비하려 합니다~^^ 새로운 반도 배정 받고, 또 설레는 마음으로 새학기를 기다려 봅니다. 새로운 학년, 만남, 출발을 응원합니다~!!! 화이팅!</p>          </td>
        </tr>',984,1613401200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26540,'dus3','양현주','','룻방 남산초 1학년 등교하였습니다.','<p>오늘은 남산초등학교에 다니는 룻방 1학년 3명의 아동들이 등교를 하였습니다.</p>
<p>일찍 일어나 머리도 예쁘게 단장하고 새 옷도 입고 들뜬 마음으로 학교로 향했습니다.</p>
<p>점심 식사를 마치고 하교하여 오늘 받아 온 생활통지표를 보여주며&nbsp;담임 선생님께서 </p>
<p>1학년 동안 열심히 해주어서 고맙다고 칭찬도 듬뿍해주셨다고 했습니다.</p>
<p>모두 모두 잘했다며 칭찬해 주며 2학년에 올라가서도 지금처럼 열심히 해보자고 이야기 나누었습니다.</p>
<p>1학년 아동들은 내일부터 온라인 수업이 시작되며 3월 2일부터 2학년 배정된 각 반으로 등교를 하게 됩니다~^^</p>          </td>
        </tr>',970,1613314800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26539,'dus3','김혜은','','바울방 1학년 고*태 아동 등교하였습니다.','<p>오늘 고*태 아동이 등교를 하였습니다.</p>
<p>온라인 수업으로만 얼굴을 보던 선생님과 친구들을&nbsp;직접 볼 생각에 들뜨고 신나는 모습으로&nbsp;등교를 하였습니다.</p>
<p>학교를 다녀와서&nbsp;있었던 일들을 이야기 하며 웃음꽃이 피었습니다. 헤어짐에 대해 아직 낯선지 선생님을 안본다고만 이야기하며</p>
<p>"무슨뜻이지?"라며 고개를 갸웃거립니다. 이제 2학년이 되고 새로운 선생님과 새로운 친구들을 만난다고 하니 "아하" 라고 받아들이는데 막상 학교를 가봐야 실감을 할 듯 합니다. </p>
<p>내일은 온라인 수업을 하고 그 다음날인 수요일에는 종업식을 합니다. 작년 한해 낯선 1학년을 잘 보내준 고*태 아동에게 잘했다고 </p>
<p>격려해주면서 앞으로는 더 멋진 2학년을 보낼 수 있도록 열심히 해보자고 이야기 하였습니다.</p>          </td>
        </tr>',980,1613314800,'', '', '', '', '', '');
