INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26427,'dus3','김지은','','2월 1일 중경고 개학했습니다.','<p>한나방 중경고 김*경 아동 개학했습니다.</p>
<p>자가학습이&nbsp;있어서&nbsp;아침부터 노트북을 세팅하고, 교과서 등을 준비해서 부지런히 수업준비를 했습니다.</p>
<p>영상을 시청하며 필수적인 과목 체크하며 학습 열심히 했습니다. </p>
<p>오랜만의 학습이지만 버벅거리거나 애로사항없이 잘 진행하여 학습마무리 했습니다.</p>
<p>2월 3일 수요일에는 새학년 교과서를 받으러 등교했고, 금주 금요일에는 방학식이 있습니다.</p>
<p>남은 학교생활 잘 수행할 수 있도록 지도하겠습니다.^^</p>
<p><br /></p>          </td>
        </tr>',1008,1612364400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26400,'dus3','김지은','','2월 2일 한나방 동명생경고 개학했습니다','<p>한나방&nbsp;겨울방학 잘 보내고 &nbsp;동명생경고 다니고 있는 아동이 개학했습니다.</p>
<p>오랜만의 온라인학습이지만 아침부터 시간맞춰 준비해서 순서에 따라 동영상강의 들으며 충실히 학습 이행했습니다.</p>
<p>내일은 교과서를 받으러 등교한다고 하는데 학교생활 잘 해나갈 수 있도록 지도하겠습니다^^</p>          </td>
        </tr>',1069,1612191600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26331,'dus3','심주현','pikaccu85@hanmail.net','다윗방 남산초등학교 아동 개학하였습니다.','<p>오늘 남산초등학교 아동들이 개학을 하였습니다. </p>
<p>코로나로 인해 온라인과 줌 수업으로 진행되었는데요 </p>
<p>오랜만에 담임선생님과 친구들 얼굴을 보는 아이들의 얼굴에 미소가 보였습니다. </p>
<p>직접 만나면 더 좋겠지만 그래도 아쉬운 마음을 달래며 수업에 참여하였습니다.^^</p>
<p>아이들이 얼마 남지 않은 학년 마무리를 잘 할 수 있도록 열심히 지원하겠습니다. ^O^/</p>          </td>
        </tr>',1107,1611586800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26327,'dus3','서혜빈','','바울방 남산초등학교 개학 하였습니다^ㅇ^','<p>4학년 배*욱, 1학년 고*준태 아동</p>
<p>드디어, 길고 길었던 방학을 지나 개학을 맞이하였습니다~ 코로나로 인하여 등교하지는 못했지만, 온라인 수업과 화상수업으로 대신하여 보고싶었던 선생님과 친구들을 화면으로나마 기쁘게 맞이해주던 우리 아이들의 모습 볼 수 있었습니다~~^^ 수업 참여도 열심히 하였구요. 열심히 새학기를 시작하자고 다짐 하며~&nbsp;하루 빨리 등교 하는 우리&nbsp;아이들의 모습도 궁금하네요!! </p>          </td>
        </tr>',1033,1611586800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26323,'dus3','양현주','','룻방 남산초 1,2학년 개학했습니다.','<p>오늘은 드디어 개학날!</p>
<p>비록 학교에 가지는 못하지만 온라인 줌수업을 통하여 선생님, 친구들과 함께했습니다.</p>
<p>줌수업을 즐겁게 참여하며 적극적인 모습을 보이기도 하였습니다.</p>
<p>방학 동안 열심히 했던 과제를 마무리하며 다시 학교에 갈 수 있는 날을 기다리고 있는 아동들입니다.</p>
<p><br /></p>          </td>
        </tr>',1133,1611586800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26320,'dus3','김지은','','한나방 남산초등학교 아동들 개학했습니다.^^','<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">남산초등학교에 다니고 있는 한나방 아동들 오늘 개학했습니다</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">코로나로 등교하지 않고 온라인수업으로 대체해서 학습을 진행했습니다</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">박</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">*</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">리 아동은 줌 수업에 참여해서 오랜만에 친구들과 선생님을 화상으로 만나봤습니다</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">반가운 얼굴들을 화상으로라도 볼 수 있어 감사했고</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">, </span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">반가운 시간이었습니다</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">다른 아동들은 줌수업은 없었지만 선생님께 오늘 학습한 내용을 인증샷으로 보내드리며 잘 지내고 있다고 안부인사를 하기도 했습니다</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">오랜만의 학습이었지만 모두 열심히 하는 모습이 기특합니다</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">2</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">월 </span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">17</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">일까지 온라인원격수업을 하게 된다고 하는데 추후 일정이 바뀔 수도 있지만 부족하지 않도록 학습 지도 열심히 하겠습니다</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-fareast-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-ascii-font-family: 굴림">. </span></p>          </td>
        </tr>',1031,1611586800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26317,'dus3','이소영','','모세방 이*민, 박*성 아동이 온라인 개학을 하였습니다.','<p>모세방에서 생활하는 초등생 이*민, 박*성 아동이 온라인&nbsp;개학을 하였습니다.</p>
<p>아동들 온라인 개학 옆에서 잘 할 수 있도록 보육하겠습니다.</p>
<p>코로나로 인해 학교에 가지 못해 온라인 개학을 하는 것이 새로운 개학방법이지만</p>
<p>어서빨리 종식되었으면 좋겠습니다.</p>          </td>
        </tr>',1009,1611586800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26196,'dus3','김지은','','덕수중 방학식 했습니다','<p>오늘 덕수중 방학식을 했습니다.</p>
<p>여전처럼 학교에 모여서 방학식하지 않고, 코로나로 인해 대면없이 가정에서 방학식을 했습니다.</p>
<p>코로나로 사람들과의 모임도 없이 제한된 생활을 하고 있지만</p>
<p>하루빨리 종식되어 안전하게 일상생활을 하며 학교도 다닐 수 있게 되길 바랍니다.</p>
<p>방학동안 부족한 공부도 하며 학업에도 최선을 다하고, 운동도 하며 건강한 방학 보낼수 있도록 지도하겠습니다.</p>          </td>
        </tr>',1077,1610463600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26188,'dus3','김지은','','한나방 보성여고 김** 아동 방학식했습니다.','<p>한나방 보성여고 김**아동 방학식을 했습니다. </p>
<p>코로나로 인해 학교에 등교하지 않고, 방학식을 했습니다.</p>
<p>3월 2일에 개학을 한다고 하는데 남은 방학기간동안 고3준비도 하며 부족한 과목 공부도 하고,</p>
<p>남은 1년 잘 준비할 수 있도록 지도하겠습니다~^^</p>          </td>
        </tr>',1069,1610377200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26168,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 정**아동 졸업식을 했습니다. (2021.01.08)','<p>성동공고 정**아동이 졸업식을 했습니다.</p>
<p>코로나로 인해 학생들만 등교해서 각반에서 조심스럽게 졸업장을 받았습니다.</p>
<p>함께하지 못해 아쉬운 마음은 저녁에 다같이 모여서 축하인사를 건네면서 대신했습니다. </p>
<p>졸업하기 전에 취업을 하고 안정적으로 회사생활을 하는 우리 **이~</p>
<p>흐뭇하고 기특합니다.</p>
<p>성인이 된 우리 **이가 나날이 발전하는 삶을 살수 있도록 </p>
<p>함께 기도부탁드립니다. </p>          </td>
        </tr>',1057,1610204400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26161,'dus3','김지은','','1월 8일 한나방 박**아동 방학식 했습니다~','<p>한나방 박지민 아동 방학식 했습니다. </p>
<p>등교해서 2학기 기말고사 성적표도 받고, </p>
<p>겨울방학생활 안내 가정통신문도 받아왔습니다.</p>
<p>오늘부터 봄방학 없이 3월 2일에 정상등교한다고 하는데</p>
<p>방학기간동안 부족한 학습도 하며 안전하게 보낼 수 있도록 지도하겠습니다.</p>          </td>
        </tr>',998,1610118000,'', '', '', '', '', '');
