INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (26072,'dus3','김지은','','한나방 남산초, 동명생경고, 중경고 방학식 했습니다.','<font size="2">12월 31일 한나방 아동들 방학식했습니다.
</font>
<div><br /></div>
<div>같은 반 친구들을 만나 인사하며 방학식을 했는데</div>
<div><br /></div>
<div>올해는 코로나가 심각해서 대면하지 않고 온라인으로 방학식을 했습니다.</div>
<div><br /></div>
<div>겨울 방학이 길진 않지만 아동들이&nbsp; 생활계획표 잘 작성해서</div>
<div><br /></div>
<div>부족한 학습도 하고, 건강을 위해 운동하고, 즐겁게 놀이하며</div>
<div><br /></div>
<div>방학 잘 보낼 수 있도록 지도하겠습니다.^^</div>          </td>
        </tr>',1149,1609426800,'', '', '', '', '', '');
