INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25995,'dus3','김지은','','한나방 기말고사 기간입니다~^^','한나방 아동들은 지난주부터 등교해서 기말고사 시험을 보고 있습니다.
<div><br /></div>
<div>중경고와 덕수중은 지난주로 시험이 끝났고,</div>
<div><br /></div>
<div>이번주에는 고1, 2학년 아동들이 시험을 보고있습니다.</div>
<div><br /></div>
<div>매일 늦은 시간까지 공부하며 시험을 준비하고 있는데</div>
<div><br /></div>
<div>중간고사때 생각보다 성적이 안나왔지만</div>
<div><br /></div>
<div>이번 기말고사에는 노력한만큼 조금이라도 올랐으면 좋겠습니다.</div>
<div><br /></div>
<div>온라인과 줌 수업으로 혼란스러운 한해를 보낸&nbsp; 아동들</div>
<div><br /></div>
<div>적응하며 노력하는 모습이 예쁩니다.</div>
<div><br /></div>
<div>남은 학교생활 잘 마무리할 수 있도록 지도하겠습니다~</div>
<div><br /></div>          </td>
        </tr>',1124,1608649200,'', '', '', '', '', '');
