INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25808,'dus3','이소영','applehyoji@naver.com','바울방 박*랑, 소*지 아동 어린이집 하반기 학부모 상담 진행하였습니다.','<p>충무 어린이집 등하원 하고 있는 바울방 아동 2명, 어린이집 가 있는 동안</p>
<p>비대면 전화상담으로 상담을 진행하였습니다.</p>
<p>교우관계도 좋고 스스로 다가가 함께 놀줄 알며 선생님 말씀도 잘 듣는다 칭찬 일색이셨습니다.</p>
<p>기특하여 하원시 칭찬 더 듬뿍 해주며 북돋아 주었습니다.</p>
<p>충무어린이집 선생님 코로나 시국 속 아동들을 위해 최선을 다해주시는 점&nbsp; 언제나 감사드립니다.</p>
<p><br /></p>          </td>
        </tr>',1107,1607180400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25807,'dus3','이소영','applehyoji@naver.com','바울방 박*민, 박*훈 아동 어린이집 하반기 학부모 상담 진행하였습니다.','<p>필동 어린이집 다니는 바울방 아동 2명이 어린이집 가 있는 동안,</p>
<p>어린이집 선생님과 상담을 진행하였습니다. </p>
<p>전화상담으로서 비대면 상담 하였습니다.</p>
<p>아동들 건강히 등하원 하고 있으며 화가 나도 조금 참고, 왜 화가 났는지도 말 해주려 노력하고. 교우관계도 좋다고 합니다.</p>
<p>노력해주는 아동들이 참 기특하고 고맙습니다.</p>
<p>필동 어린이집 선생님, 코로나 시국 속 아동들을 위해 최선을 다해주시는 점 감사합니다.<br /></p>          </td>
        </tr>',1116,1607180400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25713,'dus3','김민지','','룻방 지*아동 어린이집 하반기 학부모 상담 진행하였습니다.','<p>룻방의 막내 지*아동의 하반기 학부모 상담을 진행하였습니다.</p>
<p>어린이집에서 아주 씩씩하게 생활하고 있다는 소식입니다.</p>
<p>반에서 한글 읽기와 쓰기도 아주 잘 한대요~~~</p>
<p>&nbsp;한글을 잘 모르는 친구들을 가르치기도 한다는&nbsp;우리 막내가 너무 귀엽습니다.</p>
<p>한글 숫자쓰기 알파벳등등 학업에 아주 관심이 많고 열의도 넘친다는 우리 막내입니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1069,1606489200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25605,'dus3','심주현','pikaccu85@hanmail.net','남산초등학교 김경미 교장선생님께서 남산원에 방문하였습니다.','<p>오늘 9월1일 새로 부임하신&nbsp;남산초등학교&nbsp; 김경미 교장선생님이 방문하셨습니다. </p>
<p>우리 남산원 아이들에게 큰 관심과 사랑을 보여주셨는데요 </p>
<p>아이들이 학교에 등교를 하고 난 후 방문을 해 주셔서 기관 소개와 아이들이 생활하는 곳을 </p>
<p>안내해 드렸습니다. </p>
<p>아이들이 좋은 시설에서 잘 생활하는 것&nbsp; 같다며 아이들을 잘 길러주시는 </p>
<p>원장님 국장님께도 감사인사를 해주셨습니다. </p>
<p>아이들에게 많은 사랑과 관심을 주시는 김경미 교장선생님께도 감사인사를 전해 드렸습니다. </p>
<p>이번 방문을 통해 우리 아이들에 대한 이해를 넓히는데 중요한 시간이 되었다고 생각합니다. </p>
<p>앞으로도 남산초등학교와 잘 협력하여 우리 아이들이 푸른 꿈을 가지고 건강하게 </p>
<p>잘 성장할 수 있도록 최선을 다해 노력 하겠습니다. </p>
<p>큰 관심과 사랑을 보여주신 남산초등학교 교장선생님 이하 많은 선생님들께 다시한번 깊은 감사를 드립니다. </p>          </td>
        </tr>',1345,1605538800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25404,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 아동들 2학기 중간고사 기간입니다.','<p>다윗방 성동공고 아동들 2학기 중간고사(졸업고사) 기간입니다. </p>
<p>고3은 금일로 졸업고사를 마쳤고</p>
<p>고2는 수요일까지</p>
<p>고1은 목요일까지입니다.</p>
<p>아동들이 열심히 공부하도록 지도하겠습니다.</p>          </td>
        </tr>',1109,1603724400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25267,'dus3','이소영','applehyoji@naver.com','바울방 배*욱 아동 남산초 상담 진행했습니다.','<p>오늘은 바울방 첫째인 배*욱 아동의 남산초 상담이 있는 날입니다.</p>
<p>아동은 활기차며 다른 아동에게 그 나이대에 맞는 적당한 장난도 잘 치고</p>
<p>교우관계 또한 좋다고 합니다. 원내 바울방에서는 첫째이기에 아무래도 형으로서</p>
<p>동생들을 잘 돌봐주기도 하지만, 이렇게 학교에서도 잘 지낸다 하니, 역시 우리방 첫째 입니다.</p>
<p>예의바르고 건강히 보육하겠습니다~!</p>          </td>
        </tr>',1212,1602428400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25242,'dus3','김민지','','룻방 장*아 아동 학교상담을 진행하였습니다.','<p>장*아 아동 학교 상담을 진행하였습니다.</p>
<p>우리 *아 학교에서도 본인 일을 스스로 잘 하고</p>
<p>공부도 아주 잘 한다고 하셨습니다.</p>
<p>주2회 등교하는 상황이라 걱정이 많았는데요</p>
<p>학교에서 열심히 학교생활을 한다고 하니,마음이 놓입니다 ^^</p>          </td>
        </tr>',1145,1602255600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25232,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 초등 아동들 학교상담을 진행하였습니다.(2020.10.08)','<p>남산초 담임선생님들과 학교 상담을 했는데요,</p>
<p>*민이, *호, *울이, &nbsp;*수 4명 모두 </p>
<p>큰 문제없이&nbsp;학교생활을 잘 하고 있다는 얘기를&nbsp;들으니&nbsp;맘이 놓입니다. </p>
<p><br /></p>
<p>코로나로 학교를 많이 안나가서 아동들이 학습을 따라가는데 어려움이 있는 것은 어쩔 수 없는 부분이라</p>
<p>집에서 더욱 신경써서 지도하려고 합니다.</p>
<p><br /></p>
<p>친구들과 잘 지내는 우리 아이들~~</p>
<p>칭찬합니다!!!</p>          </td>
        </tr>',1115,1602169200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25224,'dus3','김예지','qlekrl501@naver.com','한나방 박*주 아동 학교 상담을 진행하였습니다.','<p>한나방 박*주 아동의 담임선생님과 학교상담을 진행했습니다.</p>
<p>코로나19로 인하여 대면 상담이 어려워 전화 상담을 하게 되었습니다.&nbsp;</p>
<p>수학 문제 푸는 것이 어렵다고 이야기 하면서 끝까지 해내려고 하고 국어 지문도 잘 읽는다고 하셨습니다.</p>
<p>체육시간이나 무용시간에 앞에 나서서 시범을 보이기도 하고 문제의 답이 틀려도 손 번쩍 들어 발표도 열심히 하여 적극적으로 수업에 참여한다고 하셨습니다.&nbsp;</p>
<p>학습적인 부분에서는 약간의 걱정을 하셨지만 그래도 수업 참여도도 높고 예쁘고 밝아서 고맙다고 이야기 하시며 아동에 대한 애정을 표현해주시기도 하셨습니다.&nbsp;</p>
<p>저희가 알 수 없는 학교 생활에 대해 상담 전화을 통해 알게 되었고, 아동이 너무 좋은 선생님을 만나서 안심되고 감사 했습니다.</p>
<p>학교에서 지도하기 어려운 부분은 집에서 열심히 지도하여 아동이 바르게 자랄 수 있도록 노력하겠습니다.&nbsp;</p>          </td>
        </tr>',1077,1602082800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25223,'dus3','김지은','jieuncs@naver.com','한나방 박*리, 김*경 아동 학교상담 진행했습니다.','<p>한나방 박*리, 김*경 아동의 담임선생님과 학교상담을 진행했습니다.</p>
<p>코로나로 방문하여 상담이 어려워 전화로 상담을 하게되었습니다.</p>
<p>아동의 학교에서의 모습과 가정에서의 모습이 별반 다르지 않다고 느꼈습니다.</p>
<p>코로나로 일주일에 2번 정도 등교를 하고 나머지는 온라인수업을 진행하고 있는데,</p>
<p>둘 다 부끄러움이 많아서 앞에 나서고 적극적인 모습을 보이지는 않지만 학교 숙제도 잘 해오고, 편식하지 않고 골고루 먹고,</p>
<p>큰 문제행동없이 잘 지내고 있다고 말씀해주셨습니다.</p>
<p>학습적인 부분에서는 교과서 위주로 복습하고, 기초를 다져서 다음 학년 생활에 잘 적응 할 수 있도록 지도해달라는 당부를</p>
<p>잊지 않으셨습니다.</p>
<p>담임선생님과의 상담을 통해 아동에 대해 더 잘 알게되었고, 아동이 좋은 선생님을 만나 너무 감사했습니다.</p>
<p>부족한 부분을 지도하며 아동이 잘 성장할 수 있도록 지도하겠습니다.</p>          </td>
        </tr>',1065,1602082800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25222,'dus3','이소영','applehyoji@naver.com','바울방 고*태 아동 남산초 상담 진행했습니다.','<p>바울방 고*태 어린이의 남산초 상담을 진행하였습니다.</p>
<p>선생님의 밝은 목소리가 아동이 학교생활을 열심히 하고 있다는 듯 들려와</p>
<p>좋았습니다.</p>
<p>청소도 1등 정리도1등! 우유곽 정리도1등! 1등이 세번이나 있네요 ^^*</p>
<p>원내에서도 하려고 하는 모습이 기특하고 열심히 하려는 모습이 있어서</p>
<p>담임선생님 칭찬이 참 기분이 좋았습니다.</p>
<p>통화 후 아동에게 칭찬도 많이 해주고 아동 자신도 뿌듯해 합니다.</p>          </td>
        </tr>',1012,1602082800,'', '', '', '', '', '');
