INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (24921,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 성동공고 개학했습니다.(2020.09.01)','<p>성동공고 아동 3명이 개학을&nbsp;해서 금일 온라인수업을 시작하였고 </p>
<p>3학년 정** 아동은 현장실습을 나갔습니다. </p>
