INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (24851,'dus3','김지은','jieuncs@naver.com','보성여고 개학했습니다.','<p>보성여고 김*연 아동 오늘부터 개학하여 등교했습니다. </p>
<p>귀원 후 체온 체크하고, 소독하며 개인 위생에 신경쓰고 있습니다.</p>
