INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (24829,'dus3','김지은','jieuncs@naver.com','한나방 초중고생 개학을 했습니다.','<p>남산초등학교 1, 2, 6학년 아동과&nbsp;덕수중 2학년 아동, 중경고 1학년 아동&nbsp;개학을 해서 오늘부터 온라인 수업을 했습니다.</p>
<p>오랜만의 수업이었지만 정해진 수업 내용 착실하게 듣고, 과제활동도 열심히 했습니다.</p>
<p>온라인수업과 등교하며 학교생활에 잘 적응할 수 있도록 지도하겠습니다~</p>          </td>
        </tr>',1072,1598022000,'', '', '', '', '', '');
