INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (24699,'dus3','김혜숙','rhdnsdd2@naver.com','8월6일 다윗방 고3 오** 아동이 여름방학식을 하였습니다.','어제 다윗방&nbsp;고3&nbsp;&nbsp;오** 아동이 드디어&nbsp;여름방학을 시작했습니다~ 

