INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (24210,'dus3','이소영','applehyoji@naver.com','바울방 아동들 어린이집 등원하였습니다!','<p>오늘은 미취학 아동들이 어린이집 등원하는 날 입니다 !</p>
<p><br /></p>
<p>저희 방은 총3명(박*민, 박*훈, 박*랑)의 아동이 등원을 하였습니다.</p>
<p><br /></p>
<p>코로나로 인해 등원이 계속 미루어지면서 아동들도 원내 수학 및 국어 등 학습을 받았지만</p>
<p><br /></p>
<p>역시 새 신과 새 옷을 입고 붕붕 차를 타고 어린이집에 가는게 더 즐거운가 봅니다.</p>
<p><br /></p>
<p>아동들 하원하여서는 어린이집에서 종이 핸드폰도 만들고 새로운 선생님과 친구들을 만났다며</p>
<p><br /></p>
<p>자랑하기 바쁩니다 ^^ </p>
<p><br /></p>
<p>어린이집에서 적응도 잘 하고 더 많은 세상을 보며 느끼고 자랐으면 좋겠습니다.</p>
<p><br /></p>
<p>건강하게 보육하겠습니다~!</p>          </td>
        </tr>',1096,1592146800,'', '', '', '', '', '');
