INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (24207,'dus3','양현주','4978824@naver.com','모세방 미취학 어린이집 등원하였습니다!','<p>오늘은 미취학 4명의 아동이 어린이집 등원을 하였습니다.</p>
<p>얼마나 기다리고 기다리던 어린이집 등원인지 아침부터 준비를 마치고 신나서 언제 출발하느냐고 계속해서 물어보았습니다.</p>
<p>4시에 하원을 하여 어린이집에서 어떻게 지냈는지 물으니 모두 신나고 재미있게 놀며 밥과 간식도 잘 먹었다고 했습니다.</p>
<p>앞으로 어린이집에 계속해서 갈 생각을 하니 신이났는지 어린이집에 가려면 일찍 자야 된다고 이야기 하자 바로 잠자리에</p>
<p>드는 모습도 보였습니다. 앞으로 아동들이 건강하게 어린이집에 등원할 수 있도록 옆에서 열심히 지도하겠습니다.</p>          </td>
        </tr>',1103,1592146800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (24143,'dus3','김예지','qlekrl501@naver.com','한나방 김*현경 아동이 오프라인 등교를 하였습니다','<br />
<div>언니들과 동생들이 등교하는 것을 보고 부러워 하던 *경이가 오늘 등교하였습니다</div>
<div><br /></div>
<div>설렌다며 새벽같이 일어나 단장하고 학교에 갔다오더니 오랜만에 친구들과 선생님을 만나서 좋았다고 이야기하고</div>
<div><br /></div>
<div>나중엔 다 같이 걸어서 등교했으면 좋겠다고 이야기 하기도 했습니다</div>
<div><br /></div>
<div>코로나19가 끝나 아이들이 다같이 웃으며 등교하는 그날까지 열심히 보육하겠습니다 :)</div>          </td>
        </tr>',1065,1591628400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (24090,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 아동 4명이 오프라인 등교를 하였습니다.(2020.06.03)','<p>다윗방 고1 우** 아동이 처음으로 고등학교를 다녀온 날입니다.</p>
<p>입학식도 못해보고 하복을 입어야하는 안타까운 상황이지만</p>
<p>우리 **이는 귀엽게 웃으며 학교에 다녀온 것을 만족해하고 있어 다행입니다^^</p>
<p>초등 3, 4학년 동생들도 학교에 다녀왔습니다.</p>
<p>더운 날 땀을 흘리면서 집에 도착한 아이들~ 수고했어~~!!</p>
<p><br /></p>
<p>학교에 또 가고 싶다는 아이들의 소망이 코로나19가 진정되는 것으로&nbsp;이루어지길 바랍니다. </p>
<p><br /></p>          </td>
        </tr>',1049,1591110000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (24032,'dus3','최호성','naomi1318@naver.com','다윗방 곽** 아동이 2학년 1학기 학급회장으로 임명되었습니다. (2020.05.28)','<p>다윗방&nbsp;곽** 아동이 성*고 2학년 1학기 학급회장으로 임명되었습니다.</p>
<p><br /></p>
<p>항상 자신감 넘치고, 리더십 있는 아동이라 학교에서도 모범이 되리라 믿습니다.<br /><br />많은 칭찬과 격려 부탁드립니다. </p>          </td>
        </tr>',1144,1590591600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (24022,'dus3','박하나','835251@hanmail.net','룻방1학년 아동들 첫 등교 하였습니다.','<p>룻방 1학년 시* 다* 윤* 아동 등교 하였습니다.</p>
<p>룻방 1학년 아동들 기다리던 학교에 자가진단을 하고 준비물 등을 가지고 등교 하였습니다.</p>
<p>학교에서 점심식사까지 마치고 돌아와 등교 첫날이라 공부는 안했고 재미있었다고 다들 한마디씩 하였습니다.</p>
<p>즐거운 학교생활이 되도록 룻방 1학년 아동들 화이팅 했습니다.</p>
<p><br /></p>
<p>&nbsp;&nbsp;</p>          </td>
        </tr>',1087,1590505200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23975,'dus3','이진선','jinsun9231@hanmail.net','룻방 지* 아동 필동어린이집에서 학습꾸러미 받았습니다.','<p>코로나 바이러스로 인해 어린이집 등원을 하지 못하고 있었는데요</p>
<p>어린이집에서 학습꾸러미 선물을 받았습니다~!</p>
<p>어린이집에서 줬다고 하니 매우 좋아하고 특별하게 생각하는 모습을 보였습니다^^</p>
<p>사탕막대기와 공, 단체티셔츠를 받았으며, 사탕은 룻방 아동들과 함께 나누어 먹는 착한 지*입니다~</p>
<p>선물을 받고나니 얼른 어린이집에 가고 싶다고 언제 가냐고 묻기도 합니다~</p>
<p>빨리 코로나 바이러스가 진정되길 바랍니다.</p>          </td>
        </tr>',1124,1589986800,'', '', '', '', '', '');
