INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23974,'dus3','안유나','dksdbsk98@naver.com','솔로몬B방 필동 어린이집 최*울아동 학습 꾸러미받았습니다.','<p><br /></p>
<p>&nbsp; 필동 어린이집에서 학습꾸러미와 어린이날 선물을 보내주셨습니다. </p>
<p><br /></p>
<p>코로나로 인해 등원이 미뤄져서 어린이집 가기만을 기다리는 아동에게 큰 선물이 되었습니다.</p>
<p><br /></p>
<p>곧 어린이집을 갈 수&nbsp;있다는 사실이 신이 났는지 선생님과 친구들을 빨리 만나고 싶다고 이야기해주었습니다. </p>
<p><br /></p>
<p>아동을 위해&nbsp;선물을&nbsp;보내주셔서 감사드립니다:)</p>
<p><br /></p>
<p>아동이 건강하고, 안전하게 등원할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1095,1589900400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23969,'dus3','양현주','4978824@naver.com','모세방 필동 어린이집 김*빈 학습 꾸러미 받았습니다.','<p>김*빈 어린이집 가방을 학습 꾸러미로 받았습니다.</p>
<p>어린이날 선물도 함께 챙겨주셔 감사히 받았습니다.</p>
<p>해당 아동도 어린이집 선생님과 만날 날을 손꼽아 기대하고 있습니다. </p>
<p>어린이집에 가는 날도 얼마 남지 않았는데 아동 건강상태 체크하며 안전하게 등원 할 수 있도록 지도하겠습니다^^</p>
<p><br /></p>          </td>
        </tr>',1160,1589900400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23966,'dus3','이소영','applehyoji@naver.com','바울방 필동 어린이집 박*민, 박*훈 아동 학습꾸러미 받았습니다.','<p>코로나로 인하여 어린이집을 못 가지만, 어린이집에서 아동들 학습꾸러미와 </p>
<p><br /></p>
<p>어린이집 가방, 그리고&nbsp;선물들을 가져왔습니다.</p>
<p><br /></p>
<p>선물에는 공, 사탕, 옷이 들어있어서 아동들 굉장히 기뻐하였어요.</p>
<p><br /></p>
<p>어린이집에 가서 선생님도 보고 친구들도 같이 보고 싶다고 하네요.</p>
<p><br /></p>
<p>건강하고 씩씩하게 등하원하며 안전하게 케어하겠습니다~~!</p>
<p><br /></p>
<p><br /></p>
<p>*아동들을 위해 여러 학습자료와 선물을 주신 필동 어린이집 선생님들께 감사드립니다.</p>          </td>
        </tr>',1149,1589900400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23824,'dus3','이소영','applehyoji@naver.com','바울방 충무 어린이집 박*랑 아동 학습꾸러미 받았습니다.','<p>충무 어린이집에서 학습 꾸러미를 받아 아동에게 설명한 뒤 주었더니 굉장히 좋아하였습니다.</p>
<p><br /></p>
<p>꾸러미 안에는 콩나물 기르기 키트와 천과 싸인펜 키드, 마스크 등이 들어있었어요.</p>
<p><br /></p>
<p>아동에게 하나씩 하나씩 사용방법과 놀이방법을 설명 해 준 뒤 함께 활동하였습니다.</p>
<p><br /></p>
<p>어린이집 담당 선생님의 정성어린 편지도 같이 들어있어서, 아동과 함께 읽어보았습니다.</p>
<p><br /></p>
<p>감사합니다.</p>
<p><br /></p>
<p>어서 코로나가 종식되어&nbsp;어린이집에서 더 많은 것을 보고 배우고 느꼈으면 좋겠습니다.</p>
<p><br /></p>          </td>
        </tr>',1144,1588518000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23826,'dus3','이진선','jinsun9231@hanmail.net','룻방 박*서 아동 어린이집에서 학습 꾸러미 받았습니다.','<p>코로나로 인해 어린이집에 가지 못해 어린이집 선생님께서 여러가지 학습 꾸러미를 보내주셨습니다^^!</p>
<p>마스크, 콩나물기르기, 장난감, 모자등이 들어있었습니다~</p>
<p>사랑이 가득 담긴 손편지도 함께 보내주셔 아동과 함께 읽어보았습니다.</p>
<p>박*서 아동은 편지를 읽고 매우 좋아하였으며, 얼른 어린이집에 가고 싶다고 이야기했습니다^^*</p>
<p>하루빨리 코로나 바이러스가 종식이 되어 아동들이 신나게 뛰어놀 수 있었으면 좋겠습니다.</p>          </td>
        </tr>',1150,1588518000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23667,'dus3','김예지','qlekrl501@naver.com','한나방 김*경,김*경,박*민,김*연,김*민,손*영 아동이 16일 온라인 개학을 하였습니다.','<p><br /></p>
<p><br /></p>
<p>지난 16일 한나방 고등학교 2학년 아동부터 초등학교 6학년 아동까지 온라인 개학을 하였습니다.</p>
<p>처음으로 해보는 온라인 학습이라 영상이 끊기고 서로 당황스러웠지만 그래도 곧 잘 수업에 집중하여 열심히 노력하였습니다.</p>
<p>아동들이 온라인 학습을 하는 것에 있어서 부족함이나 어려움 없도록 옆에서 열심히 지원하겠습니다. </p>          </td>
        </tr>',1106,1587481200,'', '', '', '', '', '');
