INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23640,'dus3','최호성','naomi1318@naver.com','다윗방 배**, 박** 아동이 온라인 개학을 하였습니다. (2020.04.20)','<p>4월 20일 다윗방에서 생활하는&nbsp;저학년 초등생 배**, 박** 아동이 온라인 개학을 하였습니다.</p>
<p><br /></p>
<p>이로써, 다윗방 모든 아동들이 온라인 수업을 진행하게 되었습니다.<br /><br />비록 온라인이지만 아동들이 학교처럼 열심히 공부할 수 있도록 면학분위기 유지하여 열심히 지도하겠습니다. </p>          </td>
        </tr>',1091,1587308400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23605,'dus3','김형식','jazzer80@naver.com','바울방 초등학생 교과서 및 학습꾸러미 받았습니다.','<p>04월20일(월) 초등학교 1-3학년 온라인 개학을 앞두고</p>
<p>금일 학교에 방문하여 교과서와 학습꾸러미 받아왔습니다.</p>
<p>아동들에게 교과서와 학습 꾸러미를 전달했더니&nbsp;실감이 나는지 반응이 남달랐습니다.</p>
<p>특별히 입학한 1학년 아동들의 학습꾸러미에는 </p>
<p>아동 개별로 6학년 선배들의 응원이 담긴 편지도 담겨져 있었습니다.</p>
<p>선생님들의 응원에 더불어 학교 선배들의 응원까지 더해지니 우리 아이들이 많은 힘이 날 것 같습니다.</p>
<p>아동들의 첫걸음 남은 시간 잘 준비해 학습 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1071,1586962800,'', '', '', '', '', '');
