INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23596,'dus3','박하나','835251@hanmail.net','룻방^^* 온라인 학교수업 자가학습 시뮬레이션에 참여하였습니다.','<p>2020년&nbsp;남산초 3학년 세*와 &nbsp;1학년이 되는 시*, 윤*, 다* 아동이 </p>
<p>4월 20일부터 시행하는 학교수업 온라인&nbsp;자가학습 시뮬레이션에 참여하였습니다.</p>
<p>사회적 거리두기로 인해 떨어져 앉아서, 학습하게 될 공간의&nbsp;자리를 확인하고,&nbsp; </p>
<p>앞으로 진행 될 수업에 대해 알 수 있는&nbsp;시간을 가졌습니다. </p>
<p>코로나19가 속히 진정되어 학교에 등교하는 날이 빨리 왔으면하는 바램입니다.</p>
<p><br /></p>          </td>
        </tr>',1075,1586876400,'', '', '', '', '', '');
