INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23179,'dus3','이진선','jinsun9231@hanmail.net','룻방 필동어린이집 아동들 상장 받았습니다.','<p>어린이집을 졸업하며 상장을 받아왔습니다.</p>
<p><br /></p>
<p>장*아 아동은 협동상과 독서상을 받았고,</p>
<p><br /></p>
<p>박*주 아동은 탐구상과 저축상을 받았습니다.</p>
<p><br /></p>
<p>박*빈 아동은 무려 3개를 받았는데요 독서상, 친절상, 저축상을 받았습니다.</p>
<p><br /></p>
<p>아동들에게 잘 했다고 칭찬과 박수를 쳐주었으며, 아동들 스스로 매우 뿌듯해 했습니다^^</p>          </td>
        </tr>',1195,1582124400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23178,'dus3','이진선','jinsun9231@hanmail.net','룻방 필동어린이집 졸업했습니다.','<p>룻방 8살 언니들이 어린이집 졸업을 했습니다^^</p>
<p><br /></p>
<p>장*아, 박*주, 박*빈 아동이 그동안의 추억을 간직한채 어린이집 졸업에 참여했습니다.</p>
<p><br /></p>
<p>어린이집을 떠나는 선생님도, 아동들도 모두 아쉬워하며 이별을 맞이 하였습니다.</p>
<p><br /></p>
<p>초등학교에 입학하여 잘 생활할 수 있도록 지도하겠습니다~</p>          </td>
        </tr>',1123,1582124400,'', '', '', '', '', '');
