INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23146,'dus3','이진선','jinsun9231@hanmail.net','룻방 박*음 아동 어린이집 상장 받았습니다.','<p>룻방 박*음 아동이 어린이집에서 \'미소상\'을 받았습니다.<br /><br /></p>
<p>항상 웃음을 잃지 않고 밝은 미소를 보여주어&nbsp;칭찬과 함께 상장을 받았습니다.</p>
<p><br /></p>
<p>밝은&nbsp;미소를 잃지 않도록 잘&nbsp;지내도록 하겠습니다^^&nbsp;</p>          </td>
        </tr>',1228,1581692400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23145,'dus3','이진선','jinsun9231@hanmail.net','룻방 을지어린이집 박*음 수료식하였습니다(20.02.14)','<p>룻방 박*음 아동이 을지어린이집 수료식을 하였습니다.</p>
<p><br /></p>
<p>지난 1년간 어린이집 생활을 잘 하였으며, 많은 것을 배울 수 있었습니다.</p>
<p><br /></p>
<p>*음이가 어린이집 선생님과 헤어지는것이 슬펐는지 펑펑 우는 모습을 보였습니다.</p>
<p><br /></p>
<p>&nbsp;새로운 어린이집에 가서 잘 적응할 수 있도록 지원하겠습니다^^</p>          </td>
        </tr>',1094,1581692400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23137,'dus3','김형식','jazzer80@naver.com','바울방 초등학교 아동들이 봄방학을 했습니다(2020.02.11)','<p>바울방에서 남산초에 다니는 박*수, 박*호 아동이 봄방학을 하고 신난 모습으로 귀원했습니다. </p>
<p>신종코로나바이러스로 인해 급하게 앞당겨진 방학에 선생님들은 분주함이 이만저만이 아니었지만</p>
<p>아동들은 무척이나 신나하는 모습이었습니다. </p>
<p>신학기 시작할 때까지 신종 코로나 바이러스에 잘 대처하며 즐거운 봄방학 보낼 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1084,1581606000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23136,'dus3','김형식','jazzer80@naver.com','을지어린이집 종업식이 있었습니다.','<p>금일 을지어린이집 졸업식과 더불어 종업식도 있었습니다.</p>
<p>바울방에서는 박*민, 박*윤, 박*훈&nbsp;아동이 을지어린이집을 다니고 있는데</p>
<p>지난 1년동안 많은 것을 경험하며 어린이집을 다녔습니다.</p>
<p>한해동안 아이들이 몰라보게 많이 자란 것 같습니다. </p>
<p>올한해도 어린이집에 다니며 많은 것을 배우고 경험하며 자랄 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1176,1581606000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23135,'dus3','김형식','jazzer80@naver.com','바울방 박*성 아동 필동어린이집 졸업식 있었습니다.','<p>바울방&nbsp;박*성 아동이&nbsp;필동 어린이집에서 졸업식을 하였습니다. </p>
<p>신종 코로나 바이러스 유행으로 원아들만 참석한 자리에서 졸업식이 진행되었습니다.</p>
<p>마치고 귀원하는 차안에서 아동이 많은 눈물을 흘렸다고 하네요.</p>
<p>그동안의 어린이집 생활에서 얼마나 많은 정을 쌓으며 생활했는지 알 수 있는 모습이었습니다.</p>
<p>박*성 아동이&nbsp;이제&nbsp;초등학교 입학을 앞두고 있는데&nbsp;잘 준비할 수 있도록 지원하겠습니다.&nbsp;&nbsp;</p>          </td>
        </tr>',1072,1581606000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23127,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 오*진 아동이 봄방학을 하였습니다.(2020.02.12)','<p>다윗방 한강고 오*진 아동이 봄방학을 하였습니다.(2020.02.12)</p>
<p>방학동안 휴식하면서 재충전을 하고</p>
<p>고3 새학년을 준비할 수 있도록</p>
<p>성심껏 지원하겠습니다. </p>          </td>
        </tr>',1042,1581433200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23124,'dus3','김예지','qlekrl501@naver.com','한나방 초등학생들이 봄방학을 했습니다.','<p><br /></p>
<p>신종 코로나 바이러스로 인하여 봄방학이 당겨져 오늘 봄방학을 하고 왔습니다.</p>
<p>그동안 사용한 물건들을 정리하며 언제 사용했는지 이야기하기도 하고 </p>
<p>학교생활기록표를 건내며 자신이 좋아한 과목에 대해 이야기 하는 모습도 보였습니다.</p>
<p>봄방학 동안&nbsp;새학기를 잘 준비할 수 있도록 열심히 지원하겠습니다. :)</p>          </td>
        </tr>',1019,1581346800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23123,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 초등 아동들 봄방학을 하였습니다.(2020.02.11)','<p>남산초 아동들이 봄방학을 하였습니다. </p>
<p>신종코로나바이러스로 인해 며칠 앞당겨져서 분주하게 종업식을 하게 되었는데요 </p>
<p>집에서 놀 수 있다고 신나서 떠들썩합니다. </p>
<p><br /></p>
<p>방학식 기념으로 공부하지 말고 행복운동장나가서 축구부터 하자고 했더니 </p>
<p>얼마나 빠르게 준비를 하는지요 ㅎㅎ</p>
<p>맨날 뛰어놀아도 노는 시간이 부족한가봅니다. </p>
<p><br /></p>
<p>우리 아이들이 행복한 시간을 보낼 수 있도록 </p>
<p>최선을 다해 보육하겠습니다. </p>
<p><br /></p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1047,1581346800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23121,'dus3','김예지','qlekrl501@naver.com','한나방 박*민 아동이 개학을 하였습니다.','<p>한나방 박*민 아동 개학을 하였습니다.</p>
<p>코로나바이러스로 개학이 하루 연기되어 오늘 다녀왔습니다.</p>
<p>학교에 다녀와서 개인 위생을 철저히 하는 모습을 보여주었습니다</p>
<p>앞으로도 개인위생을 잘 지키며&nbsp;생활 할 수 있도록 옆에서&nbsp;지원하겠습니다</p>          </td>
        </tr>',1045,1581346800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23105,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 환일중 3학년 우*운 아동이 졸업식을 하였습니다.(2020.02.06)','<p>다윗방 *운이가 금일 환일중을 졸업했습니다.</p>
<p>아직 어리게만 보았던 우리 *운이가 </p>
<p>학사모를&nbsp;쓰고 서 있으니&nbsp;멋지고 의젓합니다.</p>
<p>*운이 누나도 함께 와서 축하해주어 더욱 기쁜 날이 되었습니다. </p>
<p><br /></p>
<p>학부모는 졸업식을 함께&nbsp;하지 못하고 밖에서 기다리다가 끝난 후에 함께 사진을 찍었습니다. </p>
<p>우리 *운이가 고등학교에서도 즐거운 학교생활을 할 수 있도록</p>
<p>입학준비를 잘 지원하겠습니다. </p>
<p><br /></p>
<p>함께 기뻐해주시고 우리 *운이를 응원해주세요~~</p>
<p>&nbsp;</p>
<p><br /></p>          </td>
        </tr>',1008,1580914800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23104,'dus3','김지은','jieuncs@naver.com','한나방 김*연 아동 개학을 하였습니다.','<p>한나방 김*연 아동 개학을 하였습니다.</p>
