INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23070,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 초등 아동들이 개학을 하였습니다.(2020.01.29)','<p>다윗방 초등 아동들이 겨울방학을 끝내고 개학을 하였습니다. </p>
<p>설레어하며 방학숙제를 챙겨 학교에 다녀왔습니다.</p>
<p>오랫만에 만난 친구들과 방학동안 있었던 일을 자랑하고 왔다고 합니다.</p>
<p><br /></p>
<p>신종코로나바이러스로 걱정이 많은 요즘이지만</p>
<p>아이들은 오랫만에 친구들을 만나서 즐거웠던 모양입니다.</p>
