INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22831,'dus3','심주현','pikaccu85@hanmail.net','필동어린이집 아동들 세계아동미술대회에서 상을 받아왔습니다.','<p>룻방 필동어린이집 7세 아동들이 세계아동미술대회에서 상을 받았습니다. </p>
<p>박*주 우수상/&nbsp; 박*빈 장려상/  장*아 &nbsp;특상</p>
<p>아이들이 자신의 실력을 뽐내며 열심히 그렸는데요 모두 좋은 성과가 있어 뿌듯하였답니다. </p>
<p>많이 축하해 주세요~</p>          </td>
        </tr>',1147,1577199600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22832,'dus3','심주현','pikaccu85@hanmail.net','필동어린이집에서 산타잔치를 하였습니다.','<p>오늘 룻방 아동들이 필동어린이집에서 산타잔치에 참여하였습니다. </p>
<p>산타 할아버지가 직접 들려주시는 크리스마스 카드와 선물을 받으면서 너~무 기뻤했는데요</p>
<p>오늘은 어린이집에서도 집에서도 산타 할아버지를 많이 만난다며 좋아하는 아이들이랍니다. ^^</p>
<p>즐거운 성탄절을 보낼 수 있도록 지원하겠습니다. ^^ 메리크리스 마스!!</p>          </td>
        </tr>',1180,1577199600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22830,'dus3','심주현','pikaccu85@hanmail.net','필동어린이집에서 우당탕 아빠가 만든 놀이터 체험학습을 다녀왔습니다.','<p>오늘 룻방 지*, 박*주, 박*빈,장*아 바울 박*주 아동이 필동어린이집에서 우당탕 아빠가 만든 놀이터 체험학습을 </p>
<p>다녀왔습니다. 색칠하기, 미끄럼틀, 스폰지풀장, 나무블럭, 캠핑장 등 나무를 소재로한 자연 놀이터활동이였습니다. </p>
<p>다양한 놀이를 하며 즐거운 시간을 가졌는데요~</p>
<p>크리스마스 이브날에 가서 그런지 오늘은 다른 날 보다 더 즐거운 표정의 아이들이 무척이나 행복해 보였답니다. </p>
<p><br /></p>          </td>
        </tr>',1067,1577199600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22827,'dus3','김지은','jieuncs@naver.com','한나방 김*경, 연*빈 아동이 상장을 받았습니다.','<p>한나방 남산초 김*경, 연*빈 학생이 상장을 받아왔습니다.</p>
<p>수상내용은 독후활동으로 김*경 학생은 우수상을, 연*빈 학생은 최우수상을 수상하였습니다.</p>
<p>그동안 열심히 독서를 하고 독후감을 작성했는데 좋은 성적을 거두었습니다.</p>
<p>앞으로도 학교생활을 잘 할 수 있도록 지원하겠습니다.</p>
<p>축하해주세요~</p>
<p><br /></p>
<p></p>          </td>
        </tr>',1129,1577199600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22826,'dus3','김지은','jieuncs@naver.com','한나방 남산초(김*경, 박*리, 연*빈) 겨울방학을 했습니다.','<p>한나방 남산초에 다니고 있는 아동 3명(김*경, 박*리, 연*빈)이 오늘 겨울방학식을 했습니다~^^</p>
<p></p>
<p>학교에서 공부하던 책과 물품을 모두 챙겨 귀원하였습니다.</p>
<p>오늘부터 방학이 시작되고, 오늘 저녁 산타할아버지에게 선물을 받는다며 매우 신나했습니다.</p>
<p>아이들 추운겨울이지만 건강하게 잘 보낼 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1099,1577199600,'', '', '', '', '', '');
