INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22822,'dus3','김형식','jazzer80@naver.com','바울방 초등학생 03명 상장을 받았습니다.','<p>남산초 겨울방학을 맞아 방학식에서 각종 시상식이 있었습니다.</p>
<p>바울방 아동들 중 03명의 아동이 독후활동에 왕성한 활동을 보여</p>
<p>박*호, 이*민 아동은 장려상을 배*욱 아동은 최우수상을 받았습니다.</p>
<p>많이 축하해주세요~~~</p>
<p><br /></p>          </td>
        </tr>',1047,1577113200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22820,'dus3','김형식','jazzer80@naver.com','바울방 남산초 다니고 있는 아동들 겨울방학했습니다.','<p>바울방 남산초에 다니고 있는 아동 05명이 겨울방학을 맞았습니다.</p>
<p>(박*수, 박*호, 장*울, 배*욱, 이*민)</p>
<p>방학식을 마치고 귀원하는 발걸음이 어찌나 가볍던지....</p>
<p>건강하고 알차게 겨울방학을 보낼 수 있도록 지원하도록 하겠습니다.</p>          </td>
        </tr>',1087,1577113200,'', '', '', '', '', '');
