INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22783,'dus3','이소영','applehyoji@naver.com','솔로몬B방 김*빈 아동 을지어린이집 동극발표회 했습니다.(2019.12.19)','<p>솔로몬B방 김*빈 아동&nbsp;을지어린이집 성탄맞이&nbsp;동극발표회 했습니다.</p>
<p><br /></p>
<p>동극발표회에서 천사역을 맡은 아동이었는데요, 역할을 확실히 해서 어린이집 선생님께서</p>
<p><br /></p>
<p>칭찬 많이 해주셨다고 합니다.</p>
<p><br /></p>
<p>사람들 앞에서 발표를 할 때 긴장이 될 법도 한데 아동이 잘 해냈다는 이야기를 듣고</p>
<p><br /></p>
<p>대견해 칭찬 아끼지 않았습니다.</p>          </td>
        </tr>',1113,1576767600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22780,'dus3','이혜원','','바울방 박*진 아동이 성탄 행사에 참여하였습니다.','<p>바울방 박*진 아동이 성탄 행사에 참여하였습니다. </p>
<p>A팀과&nbsp;B팀이 나눠 산타행사와 크리스마스 비누만들기 활동을 번갈아 가서 하며 활동 하는 시간을 가졌는데</p>
<p>아이들이 산타 클로스 할아버지를 보고 매우 들뜬 모습이었습니다 ^^ </p>
<p>그 후 열심히 연습한 율동과 노래들을 발표하는 시간을 가졌는데 열심히 연습한만큼 멋지게 율동과 노래를 해내는 모습이 </p>
<p>아주 멋졌습니다 ^^ </p>
<p>남은 시간 어린이집 즐겁게 활동 할 수 있도록 지원하겠습니다. </p>
<p></p>
<p></p>          </td>
        </tr>',1032,1576767600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22779,'dus3','이혜원','','바울방 박*성 아동이 어린이집에서 동극 발표회를 하였습니다.','<p>바울방 박*성 아동이 어린이집에서 동극 발표회를 하였습니다.</p>
<p>열심히 연습한 만큼 멋지게 배역을 소화하는 모습이었습니다. </p>
<p>집에 와서 성탄별이 얼마나 중요한지 아냐며 친구들에게 설명을 해주는 모습도 있었습니다 ^^ </p>
<p>남은 시간 즐겁게 어린이집 생활 할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1000,1576767600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22774,'dus3','이진선','jinsun9231@hanmail.net','룻방 박*음 아동 을지어린이집 동극발표회 했습니다.','<p>룻방 박*음 아동 을지어린이집 성탄맞이&nbsp;동극발표회 했습니다.</p>
<p><br /></p>
<p>긴 대사도 열심히 외워 틀리지 않고 또박또박 말하며 디른 아동들과 함께 호흡을 맞추며 </p>
<p><br /></p>
<p>예수의 탄생에 대해 이야기를 꾸려나가는 모습이 정말 대견했습니다.</p>
<p><br /></p>
<p>그 외에도 *음이가 좋아하는 노래도 큰소리로 불러 좋아했습니다.</p>
<p><br /></p>
<p>떨지 않고 잘 발표했다고 박수치고 칭찬해주었습니다^^</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1064,1576681200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22773,'dus3','이진선','jinsun9231@hanmail.net','룻방 박*서 아동 충무어린이집 성탄행사에 참여했습니다.','<p>룻방 박*서 아동이 충무어린이집에서 성탄행사에 참여하여</p>
<p><br /></p>
<p>열심히 연습한 노래와 율동을 선보였으며, 떨지 않고 그 누구보다도 멋지게 노래를 불렀습니다.</p>
<p><br /></p>
<p>학부모님들의 힘찬 박수를 받고 좋아하는 모습이 아주 예뻤습니다.</p>
<p><br /></p>
<p>그외에도 남산원 선생님들이 방문하여 같이 비누만들기도 하고,&nbsp; 비행기 조립도 하며</p>
<p><br /></p>
<p>즐거운 시간을 보냈습니다^^</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1031,1576681200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22772,'dus3','이진선','jinsun9231@hanmail.net','룻방 박*서 아동 어린이집에서 디키디키 체험학습 다녀왔습니다.','<p>룻방 박*서 아동 어린이집에서 디키디키 체험학습 다녀왔습니다.</p>
<p><br /></p>
<p>활동적인 놀이를 좋아하는 우리 *서는 디키디키에 간다며 무척 좋아했습니다.</p>
<p><br /></p>
<p>디키디키에서 신나게 뛰어놀고 미끄럼틀도 타며 재밌는 시간을 보냈다고 합니다^^</p>          </td>
        </tr>',1039,1576681200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22771,'dus3','심주현','pikaccu85@hanmail.net','모세방 을지어린이집 박*윤, 박*민, 박*훈 아동 동극발표회에 참여하였습니다.','<p>오늘 을지어린이집 박*윤, 박*민, 박*훈 아동 동극발표회에 참여하였습니다. </p>
<p>크리스마스의 유래와 의미를 재미있는 동극으로 꾸며서 발표회를 하였는데요 </p>
<p>아이들이 직접 천사, 성탄별, 동방박사 가 되어 대사를 외우고 발표회를 하는 모습을 보니 </p>
<p>매우 대견하였습니다. </p>
<p>또한 예쁜 크리스마스 카드를 만들어 주기도 하였는데요 </p>
<p>다가오는 크리스마스가 아이들에게는 더욱 의미있는 날이 될것 같습니다. </p>
<p>오늘 아이들이 멋진 무대를 선보일 수 있도록 애써주신 을지어린이집 선생님들께 진심으로 감사드립니다. ^^*</p>          </td>
        </tr>',1061,1576681200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22770,'dus3','심주현','pikaccu85@hanmail.net','모세방 충무 어린이집  박*태, 박*랑, 소*지 아동 성탄절 행사에 참여하였습니다.','<p>오늘 충무 어린이집 박*태, 박*랑, 소*지 아동 성탄절 행사 및 부모참여수업에 참여하였습니다. </p>
<p>A팀과&nbsp;B팀이 나눠 산타행사와 크리스마스 비누만들기 활동을 번갈아 가서 하며 활동 하였는데요. </p>
<p>산타 할아버지가 아동에게 선물을 줄 때마다 아이들의 얼굴에 함박 웃음이 번져났고 </p>
<p>부모님과 함께하는 비누만들기에서는 아이들과 함께 만들고 싶은 모양에 대해 이야기 나누며 돈독한 시간을 보냈습니다. </p>
<p>오늘의 하이라이트 발표회에서는 그동안 열심히 연습한 깜찍하고 멋진 율동을 선보여 주었답니다. </p>
<p>작년보다 한층 더 성장한 아이들의 모습이 대견하기만 합니다.^^*</p>
<p>&nbsp;오늘 아이들이 반짝반짝 빛날 수 있도록 준비해주신 충무 어린이집 선생님들께&nbsp;대단히 감사드립니다. ^^</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1212,1576681200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22769,'dus3','심주현','pikaccu85@hanmail.net','모세방 충무 어린이집 박*태, 박*랑, 소*지 아동이  디키디키 놀이터 체험 다녀왔습니다.','<p class="0" style="background: #ffffff; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"></p>
<p class="0" style="background: #ffffff; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt"><br /></span></p>
<p class="0" style="background: #ffffff; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt"><br /></span></p><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">&nbsp;모세방 충무 어린이집 박*태, 박*랑, 소*지 아동이 오늘 디키디키 놀이터로 체험학습을 다녀왔습니다. </span>
<p></p>
<p class="0" style="background: #ffffff; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">아이들이 블럭을 가지고 놀기도 하고, 여러 미끄럼틀을 타며 신나게 놀고 왔다며 이야기를 들려주었습니다. </span></p>
<p class="0" style="background: #ffffff; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">아이들을 위해 힘써주시는 어린이집 선생님들께 감사드립니다. ^^*</span></p>
<p class="0" style="background: #ffffff; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><br /></p>          </td>
        </tr>',1033,1576681200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22763,'dus3','최호성','naomi1318@naver.com','다윗방 성동공고 3인의 아동이 현장체험을 다녀옵니다. (2019.12.19)','<p>다윗방&nbsp;성동공고 3인(김 *, 고*민, 김*현)&nbsp;의 아동들이&nbsp;각각 독립문역사공원과 올림픽공원으로 현장체험을 다녀옵니다.</p>
<p>졸업을 앞둔 아동이 일상을 벗어나 여유도 만끽하고, 다양한 활동을 통해 더 많은것들을 배워나가길 바랍니다.</p>          </td>
        </tr>',1019,1576681200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22762,'dus3','최호성','naomi1318@naver.com','다윗방 성동공고 건토과 2인의 아동이 과캠프에 참여하였습니다. (2019.12.19)','<p>다윗방 성동공고를 다니는 건축토목과 2인의 (정*균, 곽*민)아동이 직업체험 일환으로&nbsp;횡성으로 </p>
<p>1박 2일 과캠프에&nbsp;참여하였습니다.</p>
<p>아동들이&nbsp;즐거운 추억을 많이 만들고 오기를 기원합니다.</p>          </td>
        </tr>',997,1576681200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22744,'dus3','김지은','jieuncs@naver.com','한나방 손*영 아동이 상장을 받았습니다','<p>한나방 손*영 아동이 상장을 받았습니다.</p>
<p>아침 독서 활동 우수학생으로 선발되어 상장을 받았습니다.</p>
<p>학업을 더욱 충실하게 할수 있도록 지원하겠습니다.</p>          </td>
        </tr>',980,1576508400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22736,'dus3','김형식','jazzer80@naver.com','바울방 박*주 아동 어린이집에서 김장체험 했습니다.(2019.12.13)','<p>바울방 필동어린이집에 다니는 박*주 아동이 어린이집에서 김장체험을 했습니다.</p>
<p>김치를 만드는 과정을 경험하며 음식의 소중함을 깨달았으면 하는 마음이 듭니다^^*</p>
<p>만들어온 김치는 남산원 아동들과 모두 맛있게 나눠먹을 예정입니다.</p>          </td>
        </tr>',1053,1576335600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22731,'dus3','김지은','jieuncs@naver.com','한나방 손*영 아동 고등학교 교복구매하였습니다.','<p>2019년 12월 13일(금요일) </p>
<p>한나방 손*영 아동이 동명여자정보상업고등학교에 합격하여 교복을 구매하기 위해 스마트 교복에 다녀왔습니다~</p>
<p>자켓, 블라우스, 치마, 조끼, 가디건을 하나씩&nbsp;입어보며 특별한 기분을 느껴보았습니다.</p>
<p>고등학교에 가서도 새로운 환경에 잘 적응하고, 열심히 학교생활 할 수 있도록 지원하겠습니다!</p>          </td>
        </tr>',1041,1576249200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22724,'dus3','이진선','jinsun9231@hanmail.net','룻방 필동어린이집 김장체험 했습니다.','<p>룻방 필동어린이집에 다니는 박*주, 장*아, 지* 아동이 어린이집에서 김장체험을 했습니다.</p>
<p><br /></p>
<p>언니들반에서는 배추김치를, 동생반인 지*아동은 깍두기를 예쁘게 담아왔습니다.</p>
<p><br /></p>
<p>김치를 만드는 과정을 스스로 경험해 봄으로써 음식의 소중함을 깨달았으면 하는 마음이 듭니다^^*</p>
<p><br /></p>
<p>만들어온 김치는 남산원 아동들과 모두 맛있게 나눠먹을 예정입니다.</p>          </td>
        </tr>',1187,1576162800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22715,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태, 박*랑 아동 언어수업 다녀왔습니다^^(12.12)','<p>모세방 박*태, 박*랑 두 아동 언어 수업 다녀왔습니다. </p>
<p>책 속에 나오는 긴 문장도 읽어보고 과일 이름을 빠르게 말하기 등 </p>
<p>게임을 하면서 재밌게 언어를 더 많이 배우고 익힐 수 있는 수업 시간이었답니다. </p>
<p>장소:중구육아종합지원센터</p>          </td>
        </tr>',998,1576162800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22714,'dus3','유미정','3alwjd@hanmail.net','모세방 박*훈 외 2명의 아동이 어린이집에서 브이센터 견학 다녀왔습니다(12.12)','<p>모세방의 박*훈, 박*민, 박*윤 세 명의 아동이 </p>
<p>어린이집에서 브이센터 견학 다녀왔답니다. </p>
<p>로보트태권브이도 만나보고 과학도 배우는 재밌는 시간을 보내고 왔답니다. </p>
<p>무척 재밌었는지 집으로 돌아와 다른 친구들에게&nbsp;브이센터에서 보았던 것들에 대해 신나게 이야기도 해 주었답니다^^</p>          </td>
        </tr>',992,1576162800,'', '', '', '', '', '');
