INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22684,'dus3','김도연','311279_@hanmail.net','룻방 박*서 아동 충무어린이집 학부모 전화상담 하였습니다. (19.12.09)','<p>룻방 박*서 아동 어린이집 하반기 학부모 상담을 하였습니다.<br /></p>
<p>아동의&nbsp;어린이집 적응 및 생활에 대해 이야기를 나눴습니다.&nbsp;&nbsp;<br /></p>
<p>아동에게 부족한 부분은 채워주고&nbsp;아동이 올바른 방향으로 나갈</p>
<p>수 있도록 지도하겠습니다.&nbsp;</p>          </td>
