INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22680,'dus3','박성은','parktjddms@naver.com','한나방 손*영 아동이 합격통지서를 받아왔습니다. (2019.12.09)','<p>한나방 손*영&nbsp;아동이 고등학교에 합격하여 합격통지서를 받아왔습니다.</p>
<p><br /></p>
<p>오늘 입학신고를 하기 위해 학교를 방문하였는데 초,중학교 동창을 만나서 벌써 조금 친해졌다며 이야기하였습니다.</p>
