INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22676,'dus3','최호성','naomi1318@naver.com','다윗방 정*찬 아동이 DDP로 현장체험을 다녀왔습니다. (2019.12.09)','<p>다윗방&nbsp;미래고의 졸업반인&nbsp;정*찬 아동이&nbsp;DDP(동대문디자인플라자)로 현장체험을 다녀왔습니다.</p>
<p>DDP는 상업 문화활동 및 복합문화 공간을 목적으로 연말 연시를 앞두고 각종 행사와 전시, 컨퍼런스 등 </p>
<p>다양한 문화행사가 있었다고 합니다.</p>
<p>졸업을 앞둔 아동이 다양한 활동을 통해 더 많은것들을 배워나가길 바랍니다.</p>          </td>
        </tr>',1000,1575817200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22671,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 우*운 아동이 체험학습을 다녀왔습니다. (2019.12.06)','다윗방&nbsp;환일중 졸업반 우*운 아동이&nbsp;상암동 풋볼 펜타지움으로 체험학습을 다녀왔습니다.  

<p></p>
<p>졸업반이라서 교과수업이 끝나 다양한 경험을 위해 체험학습을 자주 나가는 것 같습니다.</p>
<p><br /></p>
<p>학교생활을 잘 마무리할 수 있도록 성심껏 지원하겠습니다.</p>          </td>
        </tr>',998,1575730800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22670,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 정*찬 아동이 영화관람을 다녀왔습니다. (2019.12.06)','<p>다윗방 정*찬 아동이 영화관람을 다녀왔습니다. (2019.12.06)</p>
<p>다윗방 미래고 졸업반 정*찬 아동이&nbsp;학교에서 단체 영화관람을 다녀왔습니다.&nbsp; </p>
<p><br /></p>
<p>고3 학교생활을 잘 마무리할 수 있도록 성심껏 지원하겠습니다.</p>          </td>
        </tr>',960,1575730800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22663,'dus3','김도연','311279_@hanmail.net','룻방 장*아, 박*주, 박*빈, 지* 아동이 어린이집에서 뮤지컬(비바프렌드)관람을 다녀왔습니다.(19.12.05)','<p>룻방 장*아, 박*주, 박*빈, 지* 아동이 지난 목요일(12/05) 어린이집에서 뮤지컬(비바프렌드)관람을 다녀왔습니다.</p>
<p>뮤지컬의 내용이 어떠했는지 물어보니 프리다라는 친구가 아빠가 선물로 준 마술연필로 여행을 떠나 윌리를 만나고,</p>
<p>프리다와 윌리가 함께 여행을 하며 납치된 친구들을 서로 힘을 합쳐 구출하는 내용이었다고 합니다.</p>
<p>뮤지컬도 재미있었지만 율동을 배우는 시간을 가져 프리다, 윌리와 함께 율동을 해보았던 것이 기억에 남는다고</p>
<p>합니다. 뮤지컬이 끝난 다음에는 작은 도서관에서 책을 읽을 수도 있었고, 책과 관련된 그림이나 글이 전시된 공간도</p>
<p>구경할 수&nbsp; 있어서 좋았다고 합니다. 오랜만에 관람한 뮤지컬로 즐거운 시간을 보낸 친구들인 것 같습니다.</p>          </td>
        </tr>',1046,1575644400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22647,'dus3','최호성','naomi1318@naver.com','다윗방 정*찬 아동이 용산전쟁기념관으로 현장체험을 다녀왔습니다. (2019.12.05)','<p>다윗방&nbsp;미래고의 졸업반인&nbsp;정*찬 아동이 용산전쟁기념관으로 현장체험을 다녀왔습니다.</p>
<p>선사시대부터 일제강점기까지의 역사도&nbsp;배우고,&nbsp;여러가지 전쟁무기도 구경하며&nbsp;성인과 청소년 등 대상에 맞는 교육 프로그램도</p>
<p>운영되어 흥미롭고 즐거웠다고 하네요. 졸업을 앞둔 아동이 다양한 활동을 통해 더 많은것들을 배워나가길 바랍니다.</p>          </td>
        </tr>',1011,1575471600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22646,'dus3','최호성','naomi1318@naver.com','다윗방 우*운 아동이 동대문 라뜰리에로 현장체험을 다녀왔습니다. (2019.12.05)','<p>다윗방 환일중 우*운 아동이 동대문 라뜰리에로 현장체험을 다녀왔습니다.</p>
<p>미술관에서 예술작품도 구경하고&nbsp;연극 관람까지 다채롭고 즐거운 경험이었다고 합니다. </p>          </td>
        </tr>',1013,1575471600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22644,'dus3','이진선','jinsun9231@hanmail.net','모세방 박*태, 박*랑 아동 언어수업 다녀왔습니다.','<p>모세방 박*태, 박*랑 아동 언어수업 다녀왔습니다.</p>
<p><br /></p>
<p>언어수업에 가는 것을 즐거워하는 우리 아동들, 오늘도 재밌게 언어수업을 했습니다.</p>
