INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22642,'dus3','이혜원','','바울방 박*주 아동이 서울숲 갤러리아 포레로 견학을 다녀왔습니다.','<p>바울방 박*주 아동이 서울숲 갤러리아 포레로 견학을 다녀왔습니다.</p>
<p>뮤지컬을 보고 와서 신이 난 모습이었습니다 ^^</p>
<p>오자마자 친구들과 형에게 뮤지컬에 대해&nbsp;자랑을 하는 모습이었습니다 ^^ </p>
<p>앞으로도 어린이집 생활 즐겁게 할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1013,1575471600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22639,'dus3','이진선','jinsun9231@hanmail.net','모세방 충무어린이집 하반기 정기상담 했습니다.(19.12.4)','<p>모세방 충무어린이집에 다니는 박*태, 박*랑, 소*지 아동 </p>
