INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22622,'dus3','최호성','naomi1318@naver.com','다윗방 정*찬 아동이 국립중앙박물관으로 체험학습을 다녀왔습니다. (2019.12.03)','다윗방 미래고 졸업반 정*찬 아동이&nbsp;국립중앙박물관으로 체험학습을 다녀왔습니다.

<p></p>
<p>우리나라 역사와 문화를&nbsp;보고 들을 수&nbsp;있었던 고3 졸업반을 앞두고 유익한 경험이었다고 합니다. </p>          </td>
        </tr>',951,1575298800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22621,'dus3','최호성','naomi1318@naver.com','다윗방 2명의 아동이 안보체험 활동을 다녀옵니다. (2019.12.03)','<p>다윗방의 성동공고 군특성 지원 중인&nbsp;김*현, 고*민 이하 2인의 아동들이 1박 2일로 동해지역&nbsp;해군1함대 안보현장 </p>
<p>체험학습에 참여하였습니다.</p>
<p>아동들이 더 많은 체험을 통해 올바른 안보의식과 평화에 대한 의미를 다시 한 번 되새기는 시간이기를 바랍니다.</p>
<p><br /></p>          </td>
        </tr>',976,1575298800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22602,'dus3','김도연','311279_@hanmail.net','룻방 장*아, 박*주, 박*빈, 지* 아동 필동어린이집 생일파티에 참여하였습니다.(19.11.29)','<p>룻방 장*아, 박*주, 박*빈, 지* 아동 필동어린이집 생일파티(11월~12월)에 참여하였습니다.</p>
<p>그 중에서 박*빈, 지* 아동이 생일파티의 주인공이기도 하여 친구들의 축하를 많이 받았습니다.</p>
<p>원에서 준비한 예쁜 드레스를 입고 등원하여 기념사진도 찍고 맛있는 것도 많이 먹으며 즐거운</p>
<p>하루를 보냈다며 자랑하느라 저녁시간에 정신이 없기도 하였습니다. </p>
<p>친구들의 예쁜 마음이 담긴 편지도 받아와서 함께 읽어보았습니다. </p>
<p>실제 생일에는 원내에서 생일파티를 다시 할 예정입니다. 생일 축하를 두 번씩 받는 우리 친구들이</p>
<p>밝고 건강하게 자랄 수 있도록 응원해주세요~</p>
<p><br /></p>          </td>
        </tr>',1177,1575039600,'', '', '', '', '', '');
