INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22601,'dus3','김도연','311279_@hanmail.net','룻방 박*음 아동이 을지어린이집에서 김장체험(깍두기 담그기)과 솔방울 줍기 활동에 참여하였습니다.(19.11.29)','<p>룻방 박*음 아동이 을지어린이집에서 김장체험으로 깍두기 담그기 활동과 어린이집 근처의 숲에서</p>
<p>솔방울을 줍는 활동을 해 보았다고 합니다. 솔방울을 줍기 위해서 모자와 장갑, 목도리까지 미리</p>
<p>준비를 단단히 하고 어린이집을 갔는데 덕분에 솔방울을 많이 주울 수 있었다고 자랑하였습니다.</p>
<p>김장체험으로 깍두기를 만들어 사실 집에 가져올 줄 알고 기대하였는데 아동이 빈 손으로 와서</p>
<p>만들기를 하지 못했다고 생각했는데 아동과 이야기를 나눠보니 만들었고 완성된 깍두기는 어린이집에서</p>
<p>먹는다고 합니다. 벌써 한번 먹었다고 하네요. 깍두기를 만드는 것이 어렵지는 않았냐고 물어보았는데</p>
<p>선생님들의 도움이 있어서 그런지 재미있었다고 합니다. 다음에는 만들어서 집에도 가져오길 살짝 </p>
<p>기대해봅니다. 어린이집에서의 여러 활동 덕분에 *음이는 겨울을 제대로 체험하고 배울 수 있는 것 </p>
<p>같습니다.&nbsp; 원에서도 아동이 여러 부분에서 경험하며 성장할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1372,1575039600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22598,'dus3','이소영','applehyoji@naver.com','솔로몬B방 아동이 어린이집에서 솔방울 줍기 체험 하였습니다^^(19.11.29)','<p>솔로몬B방에서 어린이집에 다니는 김*빈 아동이 솔방울 줍기 체험을 하였습니다.</p>
<p>장갑을 껴 손을 보호하고는 어린이집에서 솔방울 줍기 체험을 하였는데,</p>
<p>솔방울의 크기,모양,감촉등을 느끼며 바깥바람도 쐬었습니다~!</p>          </td>
        </tr>',1164,1575039600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22593,'dus3','최호성','naomi1318@naver.com','다윗방 우*운 아동이 진학할 고등학교에 최종합격하였습니다. (2019.11.29)','<p>다윗방 우*운 아동이 성동공고 컴퓨터응용기기과에 최종합격하였습니다.</p>
<p>본인이 원하는 학교와 학과에 합격하여 많이 기뻐하였고, 많은 선생님들이 축하와 응원을 해주었습니다.</p>
<p>아동이 고등학생이 되는 만큼 앞으로 공부도 더 열심히 하고 미래를 위해 고민하는 시간을 더 많이 가질 수 있기를 바라며, </p>
<p>즐겁고 보람찬 고교생활을 해나가도록 열심히 지도하겠습니다.</p>          </td>
        </tr>',1059,1574953200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22592,'dus3','한자혜','','한나방 손*영 아동 고등학교에 합격하였습니다.','<p>한나방 손*영 아동이 동명여자정보산업고등학교로 2020학년도 신입생 특별전형 합격을 하였다고 합니다. </p>
<p><br /></p>
<p>아동은 걱정을 많이 했으나 합격 통보를 받고 좋아하였습니다. </p>
<p><br /></p>
<p>아동이 고등학교 입학 준비를 잘 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1061,1574953200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22591,'dus3','한자혜','','한나방 김*경, 손*영 중학교에서 현장학습을 다녀왔습니다.','<p>한나방 김*경, 손*영 아동이 중학교에서&nbsp;현장학습으로 롯데월드에 다녀왔습니다. </p>
<p><br /></p>
<p>아이들은 놀이동산에서 놀이기구를 재미있게 타고 친구들과 좋은 추억을 남기고&nbsp;왔습니다. </p>
<p><br /></p>          </td>
        </tr>',1036,1574953200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22589,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태, 박*랑 아동 언어수업 다녀왔습니다(11.28)','<p>모세방 박*태, 박*랑 두 아동이 언어 수업 다녀왔습니다. </p>
<p>오늘도 즐거운 시간을 함께 하며 열심히 수업에 참여하였답니다. </p>
<p>장소:중구종합육아지원센터</p>          </td>
        </tr>',1022,1574953200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22588,'dus3','유미정','3alwjd@hanmail.net','모세방 아동 3명이 어린이집에서 김장 체험 하였습니다^^','<p>모세방의 박*훈, 박*민, 박*윤 세 아동이 다니는 어린이집에서 깍두기 담기로&nbsp;김장 체험을 하였답니다. </p>
<p></p>
<p>고사리 손으로 담근 깍두기로 점심 식사 시간에 맛있게 먹었답니다<br /></p>
<p><br /></p>          </td>
        </tr>',1066,1574866800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22576,'dus3','최호성','naomi1318@naver.com','다윗방 우*운 아동이 고등학교 원서접수를 진행하였습니다. (2019.11.27)','<p>다윗방 우*운 아동이 중학교 생활을 마무리하고, 고등학교 원서접수를 하였습니다.</p>
<p><br /></p>
<p>본인이 원하는 학교와 학과를 선택하여 원서접수를 한 뒤,&nbsp;금일은 난생처음 면접도 진행하였습니다.</p>
<p><br /></p>
<p>아동이 꼭 합격하여 원하는 학교에 진학하기를 바라며, 열심히 미래를 위해 힘쓰고 있는 아동을 위해 많은 응원 부탁드립니다.</p>          </td>
        </tr>',1062,1574780400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22566,'dus3','유미정','3alwjd@hanmail.net','모세방 아동 3명 어린이집에서 장애인식 개선 체험 인형극 관람하였습니다.(11.26)','<p>모세방의 박*훈, 박*민, 박*윤 세 아동이 어린이집에서 </p>
<p>장애인식 개선 체험 인형극 \'깜비와 떠나는 다름여행\' 공연을 관람하였습니다. </p>
<p>공연을 통해 모두가 하나되어 더불어 살아가는 우리들임을 새길 수 있는 시간을 가져보았답니다. </p>          </td>
        </tr>',1076,1574780400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22565,'dus3','김도연','311279_@hanmail.net','룻방 박*음 아동이 을지어린이집에서 장애인식개선공연 &quot;깜비와 함께 떠나는 다름여행&quot;을 관람하고 왔습니다.(19.11.26)','<p class="0" style="line-height: 120%; letter-spacing: 0pt; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">룻방 박</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">*</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">음 아동이 을지어린이집에서 장애인식개선공연 </span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">"</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">깜비와 함께 떠나는 다름여행</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">"</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">을 관람하고 왔습니다</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">.</span></p><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">어떠한 공연이었는지 물어보니 깜비와 몽이라는 친구를 통하여 앞이 보이지 않는 친구에 대해서 알아보는 </span></p>
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">시간이었다고 합니다. 그래서 직접 시각장애에 대한 체험도 해보고 그에 대한 퀴즈도 풀어보는 시간도 가져</span></p>
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">보았던 것 같습니다. 아동이 이야기 하기로는 열심히 공연을 관람하고 퀴즈도 맞혀 칭찬을 받았다고 합니다.</span></p>
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">보도블럭에 길다린 모양과 동그란 모양이 있는데 길다란 모양은 앞으로 가라는 뜻이고 동그란 모양은 멈추라는</span></p>
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">뜻이라는 것을 표현한다고 합니다. 이번에 공연을 관람하고 온 *음이 덕분에 저도 무심코 지나쳤던 보도블럭의</span></p>
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">하나의 의미를 조금을 알게 되었습니다. </span></p>
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">아동이 열심히 관람하고 퀴즈도 맞히고 온 점을 원내에서도 칭찬해주었습니다.&nbsp; 지금처럼 아동이 바르고 건강한</span></p>
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">마음으로 자랄 수 있도록 지속적으로 지원하겠습니다. </span></p>
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><br /></p></span>          </td>
        </tr>',1105,1574780400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22562,'dus3','김형식','jazzer80@naver.com','바울방 박*성 아동 어린이집에서 뮤지컬 관람하였습니다.','<p>을지어린이집에 다니는 박*성 아동이 장애인식 개선 교육 뮤지컬 "깜비와 함께 떠나는 다름 여행" 을 관람하고 왔습니다.</p>
<p>관람하면서 고양이 깜비가 낸 퀴즈(정답:시각장애인)도 아동이 맞추는 등 즐겁게 참여하면서 관람했다고 합니다.</p>
<p>아동에게 무슨 생각이 들었냐고 물으니 시각장애인, 청각장애인들이 슬퍼보였다고 합니다.</p>
<p>우리와 다름이 없고 몸이 조금 불편할 뿐임을 아동에게 이야기 해주며 </p>
<p>편견을 가지지 않고 있는 그대로를 인정해주는 모습이 필요함에 대해서도 이야기 나누었습니다.</p>
<p>아직 어리지만 이런 교육들을 통해 건전한 세계관을 함양할 수 있도록 지원 아끼지 않도록 하겠습니다.</p>          </td>
        </tr>',1085,1574694000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22563,'dus3','이소영','applehyoji@naver.com','솔로몬B방 김*빈 아동이 어린이집에서 뮤지컬 관람하였습니다.','<p>김*빈 아동이 을지어린이집에서, 장애인식 개선 교육 뮤지컬 "깜비와 함께 떠나는 다름 여행" 을 관람하고 왔습니다.</p>
<p><br /></p>
<p>아동은 장애역할을 하는 캐릭터에게 안쓰러운 눈빛을 보내기도 하고, 직접 나서서 도와주려고 하는 등</p>
<p><br /></p>
<p>적극적으로 관람했다고 합니다.</p>
<p><br /></p>
<p>아동이 아직 어리지만 생각하는 게 너무 상냥하고 다정하여 나중에 커서도 그 다정함과 상냥함이</p>
<p><br /></p>
<p>지속되었으면 좋겠습니다. 교사도 아동의 이런 장점을 잘 살려&nbsp;교육들을 통해 건전한 세계관을 함양할 수 있도록 </p>
<p><br /></p>
<p>노력하겠습니다.</p>
<p><br /></p>          </td>
        </tr>',1006,1574780400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22561,'dus3','김형식','jazzer80@naver.com','바울방 박*진 아동 어린이집 하반기 상담하였습니다','<p>오늘 바울방&nbsp;박*진 아동 어린이집 학부모 상담을 진행하였습니다. </p>
<p>또래 친구들과 사이좋은 관계를 유지하면서&nbsp;어린이집 생활을 매우 잘 하고 있다고 칭찬해주셨습니다.</p>
<p>7세로 이제 어린이집을 졸업하고 초등학교에 진학하는 나이인데&nbsp;즐겁게 어린이집 생활을&nbsp;마칠 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1056,1574694000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22554,'dus3','이진선','jinsun9231@hanmail.net','모세방 충무어린이집 아동들 아리수에 대해 배웠습니다.','<p>모세방 박*태, 박*랑, 소*지 아동들이 어린이집에서</p>
<p><br /></p>
<p>\'찾아가는 아리수 스토리텔러\'를 통해 아리수에 대해 배웠습니다.</p>
<p><br /></p>
<p>아동들에게 유익한 시간이 되었습니다~^^</p>          </td>
        </tr>',1052,1574607600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22555,'dus3','김도연','311279_@hanmail.net','룻방 박*서 아동 충무어린이집에서 &quot;찾아가는 아리수 스토리텔러&quot;수업에 참여하였습니다.(19.11.25)','<p>룻방 박*서 아동 충무어린이집에서 찾아가는 아리수 스토리텔러 수업을 통하여 </p>
<p>물의 여향, 물이 우리몸에서 하는 일, 깨끗하고 건강한 아리수에 대해서 알아 보았다고</p>
<p>합니다. 또한&nbsp;깨끗한 물을 지키기 위해서 우리가 할 수 있는 일에 대해서 이야기를 나누어</p>
<p>보았고 아리수가 어떻게 만들어져서 집까지 오는지에 대한 과정도 영상을 통하여 알아보아</p>
<p>조금은 신기했다고 합니다.&nbsp; </p>
<p>우리의 주변에 쉽게 접할 수 있지만&nbsp;그만큼은 잘 모르고 있었던 수돗물 아리수에 대해서</p>
<p>이번&nbsp;수업을 통해서 배우며 물의 소중함 또한 다시 깨닫는 시간이 되었다고 합니다.</p>
<p>아동이 어린이집&nbsp;생활도 열심히 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1027,1574694000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22551,'dus3','이혜원','','바울박 박*진 아동이 어린이집에서 아리수 교육을 받았습니다.','<p>바울방 박*진 아동이 오늘 어린이집에서 아리수 스토리텔링 교육을 받았습니다 ^^</p>
<p>안전한 서울의 아리수에 대해 이야기도 듣고 또 </p>
<p>다양한 실험도 해보면서 유익한 시간을 가졌습니다 ^^ </p>          </td>
        </tr>',1060,1574607600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22524,'dus3','김형식','jazzer80@naver.com','바울방 박*진 아동 충무어린이집 소방대피훈련 참여하였습니다.','<p>금일 바울방 박*진 아동이 충무어린이집에서 실시한&nbsp;소방대피훈련 참여하였습니다.</p>
<p>원내에서도 소방대피훈련을 며칠 전에 실시했는데 </p>
<p>어린이집에서 한다고 하니 조금 귀찮아 하며 등원해&nbsp;훈련에 참여한 것 같습니다.</p>
<p>하지만 안전 앞에 무감각 할 수 없으니 반복해 훈련에 참여하는 것 만큼 좋은 것은 없는 것 같습니다.</p>
<p>아이들에게도 늘 그런 점을 강조해&nbsp;훈련에 참여할 수 있도록 경각심을 심어줘야겠습니다.</p>          </td>
        </tr>',1227,1574348400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22536,'dus3','김도연','311279_@hanmail.net','룻방 박*서 아동이 충무어린이집 소방대피훈련에 참여하였습니다.(19.11.22)','<p>룻방 박*서 아동이 지난 11월 22일에 충무어린이집에서 소방대피훈련에 참여하였다고 합니다.</p>
<p>남산원에서 18일에 소방훈련을 한 차례 한 다음 어린이집에서 하다보니 조금 더 자신있게 할 수</p>
<p>있었다고 이야기하는 아동의 모습을 볼 수 있었습니다. 덕분에 어린이집 선생님의 질문에 대답을 </p>
<p>잘해서 칭찬도 받았다고 자랑하였습니다. 이번에는 원에서 실시한 소방훈련과 어린이집에서 한</p>
<p>소방훈련이 같은 주에 하게 되다 보니 잘 기억했지만 다음에도 잘 기억할 수 있을지는 모르는 일</p>
<p>이라고 아동에게 알려주었습니다. 평소에 반복적으로 훈련하고 연습해야만 정말 위급한 상황이 </p>
<p>생겼을 때 잘 대처할 수 있는 것이라고 말해주며, 아는 것이라도 더 열심히 들어야 한다고 </p>
<p>당부하였습니다. 원내에서도 지속적인 교육과 훈련을 통하여 아동들이 안전에 대해서 숙지 할 수 </p>
<p>있도록 지도하겠습니다.</p>          </td>
        </tr>',1114,1574521200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22516,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태, 박*랑 아동 언어 수업 다녀왔습니다^^','<p>모세방의 두 아동 *태와 *랑이 언어 수업에 참여하여&nbsp;</p>
<p>놀이 속에서 열심히 발음 연습도 하고 새로운 단어도 익히면서 즐겁고 신나게 수업에 참여하였답니다. </p>
<p>장소: 중구육아종합지원센터</p>          </td>
        </tr>',1004,1574262000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22507,'dus3','이혜원','','바울방 박*진 아동이 어린이집에서 키자니아 견학을 다녀왔습니다.','<p>바울방 박*진 아동이 어린이집에서 키자니아 견학을 다녀왔습니다. </p>
<p>다양한 직업들을 체험해보고 선물로 받은 초콜렛과 구운 계란도 보여주며 한참을 자랑하였습니다 ^^ </p>
<p>경찰관이 되어 봤던 시간이 제일 좋았다며 웃는 모습이었습니다 ^^ </p>
<p>앞으로도 즐겁게 어린이집 생활 할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1039,1574175600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22500,'dus3','김도연','311279_@hanmail.net','룻방 장*아, 박*주, 박*빈, 지* 아동이 필동어린이집에서 소방서 합동 소방대피훈련에 참여하였습니다.(19.11.19)','<p>룻방 장*아, 박*주, 박*빈, 지* 아동이 필동어린이집에서 소방서 합동 소방대피훈련에 참여하였습니다.</p>
<p>매달마다 이루어지는 소방대피 훈련을 참여하기는 하지만 대체로 어린이집에서 선생님과 친구들끼리만</p>
<p>함께 대피하는 연습만하다가 이번에는 소방관 아저씨가 직접 어린이집을 방문하셨다고 합니다.</p>
<p>소화기를 사용하는 방법을 알려주시고 대피하는 방법을 직접 보여주셔서 조금 더 빠르게 대피할 수 있었다고</p>
<p>합니다.&nbsp; 어린이집에 다니는 한 친구는 소방관이 꿈인데 직접 소방관 아저씨를 만났다고 너무 좋아했다고</p>
<p>전해 듣기도 하였습니다. </p>
<p>남산원에서도 전날 소방서와 함께 소방대피훈련과 심폐소생술을 배워보는 시간을 가졌습니다. 친구들이</p>
<p>이미 원에서 배웠기 때문에 어린이집에서는 선생님의 질문에 더 잘 대답할 수 있었다고 합니다. </p>
<p>앞으로도 아이들의 안전을 위해 지속적으로 교육하고 지도하겠습니다. </p>          </td>
        </tr>',1069,1574175600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22488,'dus3','박성은','parktjddms@naver.com','한나방 박*민 아동 학교에서 세례명을 받았습니다.','<p>주말과 평일에도 학교에 남아 세례식을 연습했습니다.</p>
<p><br /></p>
<p>오늘 세례식을 하고 세례명을 받고 귀원했습니다.</p>
<p><br /></p>
<p>자신이 받은 선물과 천주교 용품을 교사에게 보여주며 뿌듯해 하였습니다.</p>
<p><br /></p>
<p>남은 학교생활도 적극적으로 참여 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1065,1574002800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22470,'dus3','김도연','311279_@hanmail.net','룻방 장*아, 박*주, 박*빈, 지* 아동이 필동어린이집에서 &quot;우리 아빠가 최고야&quot;뮤지컬 관람을 하고 왔습니다.','<p>룻방 필동어린이집 친구 4인방 장*아, 박*주, 박*빈, 지* 아동이 용산 아이크몰로</p>
<p>안데르상 수상 작가 앤서니 브라운의 대표작 "우리 아빠가 최고야"를 관람하고 왔습니다.</p>
<p>먼저 뮤지컬을 본 다른 아동과&nbsp;뮤지컬 내용에 대해 서로 이야기를 나누느라 정신없는 </p>
<p>모습이었습니다. </p>
<p>앞으로도 장*아, 박*주, 박*빈, 지* 아동이 즐겁게 어린이집 생활 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1126,1573830000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22465,'dus3','최호성','naomi1318@naver.com','다윗방 우*운 아동이 군부대 체험학습을 다녀왔습니다. (2019.11.15)','<p>환일중에 다니고 있는 다윗방 우*운 아동이 군부대 체험학습을 다녀왔습니다.</p>
<p>가평의 맹호부대에 가서 실제 총도 만져보고, 장전도 해보았으며, 무전기 사용, 전차 탑승 등 신기한 경험을 많이&nbsp;해보았다고 하네요. 중학교 학창시절 마지막 현장체험학습이었던 만큼 좋은 추억으로 간직하기 바랍니다.</p>          </td>
        </tr>',1041,1573743600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22463,'dus3','이혜원','','바울방 박*주 아동 어린이집에서 뮤지컬을 관람하였습니다.','<p>바울방 박*주 아동이 어린이집에서 뮤지컬 관람하고 왔습니다.</p>
<p>뮤지컬"아빠가 최고야"를 관람하고 먼저 뮤지컬을 본 박*성 아동과 </p>
<p>한참 뮤지컬 내용에 대해 서로 이야기를 나누는 모습이었습니다. ^^</p>
<p>앞으로도 박*주 아동이 즐겁게 어린이집 생활 할 수 있도록 지원하겠습니다</p>          </td>
        </tr>',1000,1573743600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22453,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 고3 학생들이 수능시험을 보고 왔습니다.(2019.11.14)','<p>다윗방 김*현, 고*민 아동이&nbsp;수능시험을 보고 왔습니다.</p>
<p><br /></p>
<p>아침일찍 준비하고 나가서 어둑어둑한 시간까지 </p>
<p>힘든 시험을 보고 온 우리 아이들</p>
<p>수고 많았습니다. </p>
<p><br /></p>
<p>고생한만큼 편안하게 휴식하도록 지원하겠습니다. </p>          </td>
        </tr>',987,1573657200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22457,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태, 박*랑 아동 언어수업 다녀왔습니다^^','<p>오늘도 언어 수업을 간다며 무척 신나하며&nbsp;박*태, 박*랑 아동이 언어 수업 다녀왔습니다.&nbsp;</p>
<p>놀이르 하는 중에 수업을 하니 더 재밌고 신나 하는 모습이었답니다. </p>
