        </tr>',1049,1573657200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22449,'dus3','김형식','jazzer80@naver.com','바울방 박*성 아동 을지어린이집에서 뮤지컬 관람하고 왔습니다.','<p>바울방 박*성 아동이 을지어린이집에서 어린이대공원 나들이&nbsp;및 뮤지컬 관람하고 왔습니다.</p>
<p>뮤지컬"아빠가 최고야"를 관람하고 어린이대공원 놀이터에서 신나게&nbsp;뛰어놀았다고 하는데</p>
<p>정말 재미있었다고 합니다.</p>
<p>이야기를 하는 *성이의 얼굴에 그 모습이 그대로 담겨져 있었습니다.&nbsp;</p>
<p>즐겁게 어린이집 생활 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1019,1573657200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22444,'dus3','이진선','jinsun9231@hanmail.net','모세방 박*훈, 박*민, 박*윤 아동 어린이집에서 뮤지컬 보고 왔습니다','<p>모세방 박*훈, 박*민, 박*윤 아동 어린이집에서 뮤지컬 \'아빠가 최고야\' 보고 왔습니다~</p>
<p>뮤지컬의 내용을 교사와 다른 아동들에게 이야기해주는 시간을 가졌습니다.</p>
