INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22439,'dus3','김도연','311279_@hanmail.net','룻방 박*음 아동이 을지어린이집에서 뮤지컬&quot;아빠가 최고야&quot;를 관람하였습니다.','<p>룻방 박*음 아동이 을지어린이집에서 어린이대공원으로 견학 및 뮤지컬 관람을 다녀왔습니다.</p>
<p>어린이대공원에서 집에서 준비한 도시락을 먹고 뮤지컬을 관람하였다고 합니다.</p>
<p>뮤지컬"아빠가 최고야"를 관람하였고 대공원 놀이터에서 친구들과 함께 뛰어놀며 즐거운 시간을</p>
<p>보내다가 어린이집으로 가게 되었다고 합니다.</p>
<p>즐거운 견학을 하게 되어 기분이 좋았던 *음이의 모습을 볼 수 있었습니다.</p>
<p>앞으로도 즐거운 어린이집 생활을 할 수 있도록 지원하겠습니다.</p>
<p><br /></p>          </td>
        </tr>',999,1573570800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22434,'dus3','심주현','pikaccu85@hanmail.net','룻방 지* 아동 필동어린이집 상담을 하였습니다.','<p>오늘 룻방&nbsp;지* 아동 어린이집 학부모 상담을 진행하였습니다. </p>
<p>차분하게 어린이집 생활을 매우 잘 하고 있으며 또래 친구들과도 잘 어울린다며 칭찬을 많이 해 주셨습니다. </p>
<p>앞으로도 지금처럼 즐거운 어린이집 생활을 잘 이어갈 수 있도록 지원하겠습니다. ^^*</p>          </td>
        </tr>',987,1573484400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22413,'dus3','최호성','naomi1318@naver.com','다윗방 우*운 아동이 성동공고 진학설명회에 다녀왔습니다. (2019.11.09)','<p>다윗방 우*운 아동이 성동공고 진학설명회에 다녀왔습니다. </p>
<p>학교 구경도하고, 관심있는 학과에 대한 진학설명도 들으며 본인이 학과를 결정함에 있어</p>
<p>많은 도움이 되었습니다.</p>
<p>아동이 고등학교에 가서도 즐거운 학교생활이 될수 있도록 열심히 지원하겠습니다.</p>          </td>
        </tr>',1027,1573225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22409,'dus3','김도연','311279_@hanmail.net','룻방 장*아, 박*주, 박*빈, 지* 아동이 필동어린이집 마켓데이 활동에 참여하였습니다(19.11.08)','<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">룻방 장*아, 박*주, 박*빈, 지*&nbsp; 아동이 필동어린이집에서 진행된&nbsp;필동&nbsp;마켓데이에 참여했습니다.</p>
<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">귀원하자마자 아동들이 구입한 물건을 자랑 하느라 정신없는 모습을 보였습니다.</p>
<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">그리고 기특하게도 4명의 아이들이 자기들이 필요한 물건만 구입한 것이 아니라 아빠와 국장님을 드리겠다고 나름대로의 물건을 구입하였고 또 같이 생활하고 있는 동생들과 같이 놀 장난감이나 양말, 머리핀도 구입해오는 예쁘고 기특한 모습을 보여주었습니다.어제, 오늘 구입한 물건을 보고 가지고 노느라 정신없는 우리 룻방 친구들이었습니다.</p>
<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">이것저것 자랑하는 아동의 모습이 얼마나 재미있었는지를 보여주는 것 같습니다.</p>
<p style="margin: 0px; padding: 0px; color: #847f74; font-family: verdana">더 다양한 경험을 통해 심신이 건강하게 자랄 수 있도록 적극적으로 지원하겠습니다.</p>          </td>
        </tr>',1088,1573225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22408,'dus3','김형식','jazzer80@naver.com','바울방 박*주 아동 필동어린이집 마켓데이 참여했습니다.','<p>금일 바울방 박*주 아동이 필동어린이집에서 진행된&nbsp;필동&nbsp;마켓데이에 참여했습니다.</p>
<p>귀원하자마자 신나서 이것저것 자랑하는 아동의 모습이 얼마나 재미있었는지를 보여주는 것 같습니다.</p>
<p>작은 에코팩에 오이피클과 김치를 사왔는데 바울방 간식 먹을 때 이것도 같이 먹어요라고 말하는 </p>
<p>아동의 모습에서 함께 생활하는 같은 방 아동들을 생각하는 마음이 대견하게 느껴졌습니다.</p>
<p>더 다양한 경험을 통해 심신이 건강하게 자랄 수 있도록 적극적으로 지원하겠습니다.</p>          </td>
        </tr>',1076,1573225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22404,'dus3','이혜원','','바울방 초등학교 아동들이 사제동행 프로그램을 다녀왔습니다.','<p>바울방 초등학교 1학년 아동들이 담임선생님과 함께&nbsp;사제동행 프로그램을 다녀왔습니다.</p>
<p>담임 선생님과 용산에 있는 키즈카페도 다녀오고 저녁도 맛있게 먹고 왔다고 </p>
<p>신이 난 모습이었습니다 ^^ </p>
<p>앞으로도 학교 생활 잘 할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1021,1573138800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22405,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 우*운 아동이 환일중 현장체험을 다녀왔습니다.(2019.11.08)','<p>다윗방 우*운 아동이 환일중학교에서 현장체험을 다녀왔습니다.</p>
<p>고양시에 있는 스포츠몬스터를 가서</p>
<p>농구, 축구 등의 게임을 하면서 즐거운 시간을 보냈다고 합니다. </p>
<p><br /></p>
<p>우리 *운이가 더욱 즐겁게 학교생활을 할 수 있도록 </p>
<p>최선을 다해&nbsp;지원하겠습니다.</p>          </td>
        </tr>',1020,1573138800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22398,'dus3','한자혜','','한나방 남산초 일학년 아이들이 학교에서 키즈카페에 다녀왔습니다.','<p>한나방 박*리, 연*빈&nbsp;아동이 남산초 일학년 대상으로 하는 프로그램으로 키즈카페에 다녀왔습니다. </p>
<p><br /></p>
<p>용산 아이파크몰에 있는 챔피언 키즈카페로 놀러가서 신나게 놀다왔다고 합니다.</p>
<p><br /></p>
<p>아이들에게 시간을 내어주셔서 감사드립니다.</p>          </td>
        </tr>',1088,1573052400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22377,'dus3','이소영','applehyoji@naver.com','솔로몬B방 아동이 어린이집에서 중부시장 나들이 다녀왔습니다','<p>솔로몬B방 김*빈 아동이&nbsp;어린이집에서 중부시장 나들이를 다녀왔습니다.</p>
<p>어린이집 하원 할 때&nbsp;빨간 장바구니를 들고 굉장히 행복한 얼굴로 교사에게 자랑하면서</p>
<p>하원하였습니다.</p>
<p>장바구니 안에는 중부시장에서 산 귤, 오징어채, 김, 감말랭이, 과자 등 여러가지를 가지고 와,</p>
<p>동생들과 함께 나누어 먹었습니다 ^^*</p>
<p>또한, 자신의 모습이 그려진 그림(캐리커쳐)를 자랑하며 창문에다가 붙였는데 굉장히 좋아하였습니다.</p>          </td>
        </tr>',1075,1572966000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22375,'dus3','이진선','jinsun9231@hanmail.net','모세방 아동들 어린이집에서 중부시장 나들이 다녀왔습니다','<p>모세방 박*훈, 박*민, 박*윤 아동이 어린이집에서 중부시장 나들이를 다녀왔습니다.</p>
<p>하원 시 자신의 장바구니를 들고 교사에게 자랑하며 좋아하는 모습을 보였습니다~</p>
<p>장바구니 안에는 시장에서 살 수 있는 귤, 오징어채, 김, 감말랭이 등 여러가지 음식들이 있었고, </p>
<p>자신의 모습을 그려낸 캐리커쳐도 있어 방에 붙여주니 예쁘다며 좋아했습니다.</p>
<p>저녁을 먹은 후 모세방 아동들 모두가 중부시장에서 사온 음식을 맛있게 먹었습니다^^</p>          </td>
        </tr>',1006,1572879600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22374,'dus3','김형식','jazzer80@naver.com','바울방 미취학 아동 어린이집에서 중부시장 나들이 다녀왔습니다.','<p>을지, 필동 어린이집을 다니는 바울방 아동들(박*성, 박*주, 박*진)이 마켓데이 프로그램으로 중부시장에&nbsp;다녀왔습니다.</p>
<p>어린이집을 가기 전 부터&nbsp;신나하는 모습을 보이더니 하원할 때의 모습이 얼마나 들떠있던지요....</p>
<p>시장에서 자신들이 직접 구입한 물건을 아빠에게 보여드리며 자랑도 하고,</p>
<p>김은 식당에 전달해 아침 식사 할 때 같이 나눠 먹을 예정이고,</p>
<p>나머지 것들은(뻥튀기, 귤, 진미채, 곶감 등)을 간식을 먹을 때 친구, 형들과 나눠먹기도 하였습니다.</p>
<p>말하지 않아도 누구랑 같이 먹을래요, 누구랑 같이 먹을래요라고 말하며</p>
<p>자신의 것을 나누려고 하는 모습이 정말 흐뭇했습니다.</p>
<p>우리 아이들 정말 많이 컸죠?? </p>
<p>더 올바른 사람으로 커가도록 지도하며 지원하겠습니다.</p>
<p><br /></p>          </td>
        </tr>',1066,1572879600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22371,'dus3','박성은','parktjddms@naver.com','룻방 어린이집에서 중부시장 나들이 나녀왔습니다.','<p>을지, 필동 어린이집을 다니는 아동들이 마켓데이 프로그램으로 중부시장에 나들이를 다녀왔습니다.</p>
<p><br /></p>
<p>오늘 어린이집을 가기 전 부터 자신을 무엇을 살 거고 나눠주겠다며 신이나서 등원을 했습니다.</p>
<p><br /></p>
<p>지*, 박*음, 박*주 아동들은 과자와 김을 사왔습니다. 김은 나중에 식사시간에 나눠 먹기로 하였습니다.</p>
<p><br /></p>
<p>박*빈 아동은 귤과 과자를 사와서 동생들에게 나눠주며 같이 비타민 보충도 했습니다.</p>
<p><br /></p>
<p>장*아&nbsp;아동은 해바라기씨를 사왔습니다. 해바라기씨를 까주며 동생들과 친구들과 맛있게 나눠 먹었습니다.</p>
<p><br /></p>
<p>스스로 원하는 물건을 선택하고 살 수 있는 좋은 경험이 되는 활동이였던 것 같습니다.</p>
<p><br /></p>
<p>다음에는 무엇을 살지 이야기하면서 하루를 마무리 하였습니다~</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1005,1572879600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22361,'dus3','최호성','naomi1318@naver.com','다윗방 우*운 아동이 졸업고사를 치루었습니다. (2019.11.04)','<p>다윗방 우*운 아동이 졸업고사를 마지막으로 중학교의 마지막 시험을 후회없이 치루었습니다.</p>
<p>유종의 미를 거두었기를 바라며 아동이 고등학교에 진학해서도 열심히 공부할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1044,1572793200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22360,'dus3','문미숙','mo75on@naver.com','한나방 덕수중학교 기말시험 기간입니다.','<p>한나방 덕수중학교는 지금 기말시험 기간입니다. </p>
<p><br /></p>
<p>손*영, 김*경 아동들 시험에 대비하여 학습을 하고 있습니다. </p>          </td>
        </tr>',1176,1572793200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22335,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태, 박*랑 아동 언어수업 다녀왔습니다^^','<p>박*태, 박*랑 두 아동이 언어수업 다녀왔습니다. </p>
<p>놀이를 통해 어휘도 익히고 발음 공부도 하면서 재밌게 유익한 시간 보내고 왔습니다. </p>
<p>장 소 : 중구육아종합지원센터</p>          </td>
        </tr>',1039,1572447600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22330,'dus3','김도연','311279_@hanmail.net','룻방 박*빈 아동 모나미 환경사랑 어린이 미술대회에서 입선을 하였습니다.(19.10.25)','<p>룻방 박*빈 아동이 필동어린이집에서 참여한</p>
<p>모나미 환경사랑 어린이 미술대회에서 입선하였습니다.</p>
<p>열심히 그린 그림이 상을 받아서 무척이나 좋아하는 모습을 보였답니다.</p>
<p>아동의 재능이 더 빛날 수 있도록 적극적으로 지원하도록 하겠습니다.</p>          </td>
        </tr>',1080,1572447600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22329,'dus3','김도연','311279_@hanmail.net','룻방 장*아, 박*주, 박*빈, 지* 아동이 중구보건소에서 진행된 흡연피해 교육에 다녀왔습니다(19.10.21)','<p>룻방&nbsp;장*아, 박*주, 박*빈, 지*&nbsp;아동이 중구보건소에서 진행된 흡연피해 교육에 다녀왔습니다.</p>
<p>담배피지말고, 가까이도 가지말라고 배웠다고 합니다. </p>
<p>어렸을 때부터 반복적인 교육을 통해 흡연에 대한 바른 인식을 가질 수 있으면 좋겠습니다.</p>
<p>아동들이 다양한 체험활동 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1055,1572447600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22328,'dus3','김도연','311279_@hanmail.net','룻방 박*서 아동이 충무어린이집에서 어린이과학관으로 견학을 다녀왔습니다.(19.10.23)','<p>룻방 박*서 아동이 어린이과학관으로 현장학습 다녀왔습니다. </p>
<p>어린이집 등원 전부터 즐거워하였는데 재밌고 신나게 잘 다녀왔답니다</p>
<p>아동이 앞으로도 즐거운 어린이집 생활을 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1063,1572447600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22323,'dus3','한자혜','','한나방 남산처 현장학습을 다녀왔습니다. (19.10.17)','<p>한나방 아이들이 초등학교에서 현장학습을 다녀왔습니다. </p>
<p><br /></p>
<p>저학년인 박*리, 연*빈 아동은 이천와우목장에 다녀왔다고 합니다. </p>
<p><br /></p>
<p>먹이도 줘보고 젖소의 젖도 만져보며 젖도 짜보는 시간을 가졌다고 합니다. </p>
<p><br /></p>
<p>교사에게 손모습을 보여주며 열심히 설명하는 친구도 있고 </p>
<p><br /></p>
<p>무서워서 만져보지 못했다고 친구도 있었습니다. </p>
<p><br /></p>
<p>고학년인 김*경은 수원화성행성궁으로 놀러가서 여러가지 체험을 했다고 합니다.</p>
<p><br /></p>
<p>아이들이 많은 경험을 쌓는 시간이 되었길 바래봅니다.</p>          </td>
        </tr>',1061,1572447600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22322,'dus3','한자혜','','한나방 중등부 아이들이 현장학습을 다녀왔습니다.(19.10.15)','<p>한나방 중등부 아이들이 중학교에서 현장학습을 다녀왔습니다.</p>
<p><br /></p>
<p>일학년인 김*민 아동은 롯데월드에 다녀왔습니다.</p>
<p><br /></p>
<p>비록 무서움이 많이 놀이기구를 즐기지 못했지만 재미있었다고 합니다.</p>
<p><br /></p>
<p>삼학년인 손*영, 김*경 아동들은 국립중앙 박물관에 다녀왔습니다. </p>
<p><br /></p>
<p>마지막 현장학습으로 졸업사진을 예쁘게 찍고 왔다고 합니다. </p>          </td>
        </tr>',1055,1572447600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22312,'dus3','김형식','jazzer80@naver.com','바울방 박*주 아동 필동어린이집에서 중구보건소로 흡연피해 교육 다녀왔습니다(2019.10.21)','<p>바울방 박*주 아동이 중구보건소에서 진행된 흡연피해 교육에 다녀왔습니다.</p>
<p>담배피지말고, 가까이도 가지말라고 배웠다고 합니다. </p>
<p>어렸을 때부터 반복적인 교육을 통해 흡연에 대한 바른 인식을 가질 수 있으면 좋겠습니다.</p>
<p>아동들이 다양한 체험활동 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1063,1572361200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22313,'dus3','김형식','jazzer80@naver.com','바울방 박*주 아동 모나미 환경사랑 어린이 미술대회 입선했습니다.','<p>바울방 박*주 아동이 필동어린이집에서 참여한</p>
<p>모나미 환경사랑 어린이 미술대회에서 입선하였습니다.</p>
<p>지난 번 서울대공원에서 진행된 서아협 사생대회에서는 우수상을 받게 되었는데</p>
<p>근래 들어 그림쪽에서 두각을 나타내고 있는 아동의 모습이 멋지기만 합니다.</p>
<p>아동의 재능이 더 빛날 수 있도록 적극적으로 지원하도록 하겠습니다.</p>          </td>
        </tr>',1327,1572361200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22314,'dus3','김형식','jazzer80@naver.com','바울방 박*진 아동 충무어린이집에서 어린이박물관 다녀왔습니다.(2019.10.23)','<p>바울방 박하진 아동 충무어린이집에서 어린이 박물관 다녀왔습니다.</p>
<p>4D 영상관에서 다양한 효과를 몸으로 느끼면서 천문 영상을 본 것이 아동에게 크게 다가왔나 봅니다.</p>
<p>그 외에도 다양한 체험을 통한 활동들을 하면서 재미있게 놀고 왔다고 합니다.</p>
<p>다양한 체험으로 아동들이 많은 경험을 쌓을 수 있도록 지속적으로 지원하겠습니다.</p>          </td>
        </tr>',1056,1572361200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22295,'dus3','유미정','3alwjd@hanmail.net','모세방 박*훈, 박*윤 아동 어린이집 부모 수업 참여하였습니다^^(10.25)','<p>아동들이 다니고 있는 어린이집에서 부모님들을 초대하여 아동들이 생활하는 모습을 </p>
<p>함께 볼 수 있는 시간을 가졌습니다. </p>
<p>책보수업, 체육활동, 율동, 모래놀이 등 다양한 수업을 하면서</p>
<p>학부모님들이 지켜보는 가운데 쑥쓰러워하지 않고 두 아동은 열심히 수업에 참여하였답니다. &nbsp;</p>
<p>건강하고 밝은 모습으로 어린이집에서 생활을 잘하는 두 아동이 매우 대견합니다^^</p>          </td>
        </tr>',1084,1572274800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22296,'dus3','심주현','pikaccu85@hanmail.net','바울방 박*주 아동 필동어린이집 졸업앨범 촬영을 하였습니다.','<p>바울방 박*주 아동이 필동어린이집에서 졸업앨범 촬영을 하였습니다. </p>
<p>한옥마을에서 학사모도 쓰고, 조별로 컨셉을 정해 그룹 사진도 멋지게 잘 찍었습니다. </p>
