INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22292,'dus3','이혜원','','룻방 박*주, 박*빈, 장*아 아동이 졸업사진을 촬영하였습니다.','<p>룻방 박*주, 박*빈, 장*아 아동이 졸업사진을 촬영하였습니다.</p>
<p>가지고 간 예쁜 소품들로 졸업사진을 찍고 왔습니다.&nbsp;</p>
<p>졸업사진을 찍은 후 하원하는 길에 아동들이&nbsp;초등학교에 가는 준비라고 이야기 하는 모습이었습니다. </p>
<p>남은 어린이집 생활도 행복하게 할 수 있도록 지원하겠습니다 ^^ &nbsp;</p>          </td>
        </tr>',1109,1572274800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22291,'dus3','이혜원','','룻방 박*음 아동 어린이집 학부모 참여수업을 다녀왔습니다.','<p>박*음 아동 어린이집 학부모 참여 수업을 다녀왔습니다. </p>
<p>아동이 평소에 어떻게 생활하는지 알고 함께 수업도 참여하며 즐거운 시간을 보냈습니다.</p>
