INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22252,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태 외 2명 아동 어린이과학관으로 현장학습 다녀왔습니다^^(10.23)','<p>모세방 박*태, 박*랑, 소*지 세 아동이 어린이과학관으로 현장학습 다녀왔습니다. </p>
