INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22217,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태, 박*랑 아동 언어수업 다녀왔습니다(10.17)','<p>두 아동이 아주 재밌어하고 신나하는 언어수업 다녀왔습니다. </p>
<p>오늘은 두 아동이&nbsp;함께 수업을 받는 시간이 있어 더 재밌게 공부하고 왔답니다.&nbsp;</p>
