INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22216,'dus3','김혜숙','rhdnsdd2@naver.com','다윗방 초등학생들이 체험활동을 다녀왔습니다.(2019.10.17)','<p>다윗방 초등학생들이 체험활동을 다녀왔습니다.</p>
<p><br /></p>
<p>5학년 박*훈 아동은 수원 화성으로</p>
<p>3학년 박*호 아동은 이천 와우목장 체험을 하였습니다. </p>
<p>*호는 소가 송아지를 낳는 것도 봤다고 흥분해서 알려주네요^^</p>
<p><br /></p>
<p>아동들이 즐거운 학교생활을 하고 많은 추억을 만들 수 있도록&nbsp;열심히 지원하겠습니다.</p>          </td>
        </tr>',963,1571238000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22211,'dus3','이혜원','','룻방 박*주,박*빈, 장*아, 지* 아동이 고래실 마을로 견학을 다녀왔습니다.','<p>룻방 박*주,박*빈, 장*아, 지* 아동이 어린이집에서 견학을 다녀왔습니다. </p>
<p>고래실 체험마을에 가서 신이 나&nbsp;친구들과 즐겁게&nbsp;뛰어노는 모습이었습니다. &nbsp;</p>
<p>고구마도 캐보고 벼가 쌀이 되어 나오는 과정도 보고 </p>
<p>전통과자인 강정도 함께 만들어 보면서 유익하고 즐거운 시간을 보냈습니다. ^^</p>
<p>앞으로도 아동이 즐거운 어린이집 생활 할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',965,1571238000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22210,'dus3','김형식','jazzer80@naver.com','바울방 남산초에 다니는 05명의 아동들 와우목장으로 체험활동 다녀왔습니다.','<p>오늘 남산초에 다니는 바울방 05명의 아동들이&nbsp;경기도 이천에 있는 와우목장으로 체험활동&nbsp;다녀왔습니다.</p>
<p>치즈만들기, 젖짜기, 송아지 우유 및 건초주기, 아이스크림 만들기 등을 체험했는데</p>
<p>평소 하지 못해본 새로운 경험이어서 그런지 체험활동을 다녀와 전달하는 목소리가 무척 우렁찼습니다.</p>
<p>몇몇 아동은 소가 송아지를 낳는 것도 봤다고 하는데 완전 신기했다고 말하는 모습에서</p>
<p>오늘 체험학습이 얼마나 즐거운 시간이었는지 간접적으로 느낄 수 있었습니다.</p>
<p>아동들의 학교생활이 언제나 즐겁게 활기 넘치도록 지원하겠습니다.</p>          </td>
        </tr>',1003,1571238000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22209,'dus3','김형식','jazzer80@naver.com','바울방 박*주 아동 어린이집에서 질울 고래실마을로 소풍 다녀왔습니다.','<p>오늘 바울방 박*주 아동이&nbsp;필동 어린이집에서&nbsp;양평에 있는 질울 고래실마을로 소풍&nbsp;다녀왔습니다. <br /></p>
<p>수레기차도 타고, 제공되는 점심도 먹고, 고구마 캐기 등 다양한 체험을 했는데</p>
<p>함께 참여한 선생님의 이야기를 전해 들으니 *주가 아주 즐겁게 참여를 했다고 합니다.</p>
<p>앞으로도 *주가 즐거운 어린이집 생활을 할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1021,1571238000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22206,'dus3','김도연','311279_@hanmail.net','룻방 박*음 아동 을지어린이집에서 남산숲 견학을 다녀왔습니다.(19.10.16)','<p>룻방 박*음 아동이 을지어린이집에서 남산공원 한남유아숲체험원으로 견학을 다녀왔습니다.</p>
<p>숲체험원에 가서 잘 가꾸어진 정원을 구경하며 여러가지 가을 꽃들과 다양한 동물들을 </p>
<p>볼 수 있었다고 합니다. 또 박새, 청솔모, 밤나무, 남천, 모과나무 등을 관찰해보며, 점심으로</p>
<p>원에서 준비한 볶음밥과 계란국을 먹었다고 합니다. </p>
<p>체험장&nbsp;안에서도 줄타기, 그네, 원목 쌓기, 모래놀이를 하며 가을을 느낄 수 있는 시간이 되어</p>
<p>무척 즐거웠다고 합니다.&nbsp; 견학을 다녀오느라 고생하신 어린이집 선생님께 감사드리며, </p>
<p>원내에서도 다양한 지원과 경험을 할 수 있도록 도우며 아동이 건강하고 즐거원 어린이집 생활을</p>
<p>할 수 있도록 지속적으로 지원하겠습니다.</p>          </td>
        </tr>',1076,1571151600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22205,'dus3','심주현','pikaccu85@hanmail.net','바울방 박*성 아동 을지 어린이집에서 남산숲 체험장 다녀왔습니다.','<p>오늘 바울방 박*성 아동이 을지 어린이집에서 남산공원 한남유아숲체험원에 다녀왔습니다. <br />잘가꾸어진 정원에 다양한 가을 꽃들과 야생 동물들을 보고, 박새, 청솔모, 밤나무, 남천, <br />모과나무 등을 관찰해보며&nbsp; 어린이집에서 준비한 맛있는 간식도 먹었다고 합니다. <br />체험장 안에서도 줄타기, 그네, 원목 쌓기, 모래놀이를 하며 가을을 한껏 느낄 수 있는 시간이 되었다고 하네요 </p>
<p>*성이가 즐거운 어린이집 생활을 할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1008,1571151600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22204,'dus3','최호성','naomi1318@naver.com','다윗방 성동공고 2인의 아동들이 2박 3일로 수련회를 다녀왔습니다. (2019.10.16)','<p>다윗방 성동공고를 다니는 2인의(정*균, 곽*민)&nbsp;아동들이 2박 3일로 수련회를 다녀왔습니다.</p>
<p>각각 양평 미리내와 평창 청소년수련관에서 각종 레크레이션 프로그램과&nbsp;캠프파이어까지</p>
<p>너무 즐거웠다고 하네요.</p>
<p>수련회를 무사히 잘 마치고 귀가한 아동들이 다시 일상에서 즐겁게 생활할 수 있도록 열심히 지도하겠습니다.</p>          </td>
        </tr>',952,1571151600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22173,'dus3','한자혜','','한나방 초등부 아이들이 초등학교에서 운동회를 하였습니다.(19.10.11)','<p>한나방 아이들이 초등학교에서 한마음큰잔치 운동회를 하였습니다.&nbsp;&nbsp;</p>
<p>아이들이 달리기, 공 굴리기, 바구니 쌓기 등 다양한 게임들을 참여하였습니다. </p>
<p>참여하는 아이들도 응원하는 아이들도 열심히 하는 모습입니다. </p>
<p>아이들 모두 운동회가 재미있었다며 일화를 들려주었습니다.</p>
<p>아이들이 오늘과 같이 빛나는 학교 생활을 잘 이어갈 수 있도록 최선을 다해 지원하겠습니다. ^^**</p>          </td>
        </tr>',997,1570806000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22169,'dus3','심주현','pikaccu85@hanmail.net','바울방 아동들 남산초등학교 운동회에 참여하였습니다.','<p>오늘&nbsp;남산초등학교에서 &nbsp;한마음큰잔치 운동회를 하였습니다. </p>
<p>멋진 바울방 친구들이 달리기 계주 대표로 많이 선출되어 그 어느날 보다도 매우 빛나는 하루였습니다. </p>
<p>이밖에 공굴리기, 바구니 쌓기, 줄다리기 등 다양한 게임들이 진행되었는데요 </p>
<p>어찌나 열심히 응원하던지 아이들의 함성소리가 명동을 떠들석 하게 하였습니다. </p>
<p>하교하는 순간에도 아이들이 오늘 운동회가 너무 재미있었다며 하나같이 입을 모아 좋아하였답니다. </p>
<p>아이들이 오늘과 같이 빛나는 학교 생활을 잘 이어갈 수 있도록 최선을 다해 지원하겠습니다. ^^**</p>          </td>
        </tr>',994,1570719600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22166,'dus3','최호성','naomi1318@naver.com','남산초등학교 체육대회가 있었습니다. (2019.10.11)','<p>금일 한마음큰잔치 남산초등학교 체육대회가 있었습니다.</p>
<p>모든 아동들이 즐겁게 참여하였으며, 학부모와 함께 어울어져 진행되는 알찬 진행이 돋보였습니다.&nbsp;</p>
<p>많은 부분에서 활약한 아동들이었지만 특히 계주 부분에서 월등한 실력을 보여주어 너무나 자랑스러웠습니다.</p>
<p>앞으로도 건강하게 신체를 다지며 활력 넘치게 생활하도록 지원하겠습니다.</p>          </td>
        </tr>',1021,1570719600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22109,'dus3','최호성','naomi1318@naver.com','다윗방 환일중 우*운 아동이 서울랜드로 체험학습을 다녀옵니다. (2019.10.04)','<table width="100%" border="0" cellspacing="0" cellpadding="0">
<tbody>
<tr>
<td height="1" bgcolor="#d7d7d7" colspan="4"></td></tr>
<tr>
<td height="50" colspan="4">
<table width="100%" border="0" cellspacing="0" cellpadding="10">
<tbody>
<tr>
<td align="left" style="padding-top: 5px">
<p>다윗방 환일중 우*운 아동이 서울랜드로 체험학습을 다녀옵니다.</p>
<p>신나게 놀이기구도 타며, 친구들과 즐거운 추억 남기고 귀원하기 바랍니다.</p></td></tr></tbody>',1024,1570114800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22154,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태, 박*랑 아동 언어 수업 다녀왔습니다(10.10)','<p>모세방의 *태와 *랑 두 아동 언어수업 다녀왔습니다. </p>
<p>자기 차례를 기다리다 순서가 되면 아주 신나하면서 수업에 들어가 </p>
<p>재밌게 공부하는 시간을 가졌답니다. </p>
<p>장 소 : 중구육아종합지원센터</p>          </td>
        </tr>',1005,1570719600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22101,'dus3','김도연','311279_@hanmail.net','룻방 박*서 아동 충무어린이집 가을소풍(중산농원)을 다녀왔습니다.(19.10.02)','<p>룻방 박*서 아동이 충무어린이집 가을소풍으로 중산농원을 다녀왔습니다. </p>
<p>아침에 정확히 확정 여부를 알 수 있다고 하여 비가 온다는 소식에 소풍이 취소되는</p>
<p>것은 아닐까 걱정했는데 다행히 소풍을 잘 다녀왔습니다. 무엇을 해 보았는지 물어보니</p>
<p>호미로 고구마를 캐보았다고 하고 땅콩따기도 했다고 합니다. 또 마술쇼와 인형극도 </p>
<p>보았고 밭으로 오가며 트랙터도 신나게 타보았다고 합니다. 여러 가지를 경험할 수 </p>
<p>있어서 무척 재미있었다고 합니다. 얼마전에 다른 어린이집을 다니는 친구가 63빌딩과</p>
<p>유람선을 타고와서 자랑을 하여 *서도 빨리 소풍을 가고 싶어하였는데 이번에 소풍을 </p>
<p>다녀와서 덕분에 한결 나아졌습니다. </p>
<p>23일에 있는 현장학습도 무척 기대중이랍니다. 이렇게 시샘이 많기도 하지만 귀여운</p>
<p>아동들이 어린이집 생활과 원내 생활을 모두 즐겁고 건강하게 지낼 수 있도록 옆에서 </p>
<p>지원하겠습니다.</p>          </td>
        </tr>',1142,1569942000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22096,'dus3','유미정','3alwjd@hanmail.net','을지어린이집 하반기 부모상담 다녀왔습니다^^(10.01)','<p>모세방 박*훈, 박*민, 박*윤 아동이 다니는 을지어린이집 하반기 부모상담 다녀왔습니다. </p>
<p>우리 아이들이 어떤 공간에서 어떻게 생활하고 있는지도 살펴보고</p>
<p>어린이집 담임선생님과 아이들에 관한 이야기도 나누면서 </p>
<p>우리 아이들이 건강하고 바르게 자랄 수 있도록 뜻깊은 시간을 가졌답니다.^^</p>          </td>
        </tr>',1143,1569942000,'', '', '', '', '', '');
