INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22065,'dus3','김도연','311279_@hanmail.net','룻방 박*음 아동 을지어린이집 가을 소풍을 다녀왔습니다.(19.09.26)','룻방 박*음 아동이 을지어린이집 가을 소풍으로 63빌딩관람과 한강 유람선을 타고

<div>왔습니다. 먼저 유람선을 탑승하고 집에서 준비해간 도시락으로 점심식사를&nbsp; 한 후</div>
<div>63빌딩에서 수족관, 인어공주쇼, 전망대를 관람했다고 합니다. 가기 전부터 무척</div>
<div>들떠있던 *음이는 어린이집 가을 소풍을 다녀와서 경험한 것을 동생과 언니들에게</div>
<div>이야기 해주느라 정신없었답니다.&nbsp;</div>
<div><span style="font-size: 9pt">*음이가 얼마남지 않은 2학기 어린이집 생활도 열심히 하며&nbsp;</span><span style="font-size: 9pt">원내에서도 즐겁게 지낼 수</span></div>
<div>있도록 지원하겠습니다.^^</div>          </td>
        </tr>',1147,1569510000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22059,'dus3','한자혜','','한나방 남산초 아이들 학부모 상담을 하였습니다.','<p>한나방 남산초&nbsp;김*경, 박*리, 연*빈 아동&nbsp;학부모 상담을 하였습니다. </p>
<p><br /></p>
<p>아이들이 학교 생활을 원활하게 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1016,1569423600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22040,'dus3','최호성','naomi1318@naver.com','다윗방 성동공고 2인의 아동이 군특성 진해훈련에 참여하였습니다. (2019.09.23)','<p>다윗방 성동공고 3학년 고*민, 김*현 2인이 진해로 4박 5일간 교육사령부 훈련에 참여하였습니다. </p>
<p>아동들이 군 특성화 전공으로 그 꿈을 위해 힘든 훈련도 끝까지 버티고, 유익한 경험이 되리라 믿습니다.</p>
<p>많은것을 느끼고 건강하게&nbsp;다녀오기를 기원합니다.</p>          </td>
        </tr>',1067,1569164400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (22021,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태, 박*랑 아동 언어수업 다녀왔습니다.^^','<p>추석 명절이 있어 두주만에 언어수업을 다녀왔습니다. </p>
<p>그래서인지 더 신나하며 누구부터 시작하는지, 먼저 시작하겠다며 차 안에서부터 경쟁을 하였으나</p>
<p>오늘은 둘 다 같이 들어가서 수업을 하는 날이었답니다. </p>
<p>이쁜 목걸이 만들기도 하면서 재밌게 언어수업을 하였답니다. </p>
<p>장 소 : 중구육아종합지원센터</p>          </td>
        </tr>',1019,1568818800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21976,'dus3','김도연','311279_@hanmail.net','룻방 아동들이 어린이집에서 추석맞이 송편빚기 체험활동을 하였습니다.','<p>룻방 아동들이 화요일부터 수요일까지 2일에 걸쳐 각 어린이집마다 </p>
<p>송편빚기 체험활동을 하였습니다. 아이들이 직접 깨나 콩 등으로 속을 채워서 </p>
<p>만들어 온 송편으로 함께 나눠 먹었답니다. 아이들이 만들어서 그런지 콩이 들었어도</p>
<p>맛있다머 잘 먹는 모습을 모습을 보여주었습니다.&nbsp;</p>
<p>아이들이 즐거운 명절을 보낼 수 있도록 지원하겠습니다.</p>
<p><br /></p>          </td>
        </tr>',1150,1568214000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21959,'dus3','유미정','3alwjd@hanmail.net','모세방 박*훈, 박*민, 박*윤 아동이 어린이집에서 추석행사 하였습니다^^','<p>훈, 민, 윤 세 아동이 추석을 맞이하여 어린이집 추석 행사에 참여하였습니다. </p>
<p>등원 시 한복을 곱게 차려 입고 가서 </p>
<p>송편 빚기도 하고, 장구 등의 전통 악기 연주도 하고, 재밌는 민속 놀이도 하면서 </p>
<p>추석이 무엇인지 익히고 즐기는 시간을 가졌답니다. </p>
<p>고사리 손으로&nbsp;빚어 온 송편을 가져와서 어른들께도 드리고 친구들과도 나눠 먹으며 </p>
<p>자신들이 직접 빚었다는 것에 뿌듯해 하는 모습을 보이기도 하였답니다^^</p>          </td>
        </tr>',1114,1568041200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21951,'dus3','김도연','311279_@hanmail.net','룻방 아동들이 필동어린이집에서 추석맞이 민속놀이와 다도체험을 하였습니다(19.09.09)','룻방 장*아, 박*빈, 박*주, 지*&nbsp; 아동들이&nbsp;<span style="font-size: 9pt">필동어린이집에서 추석맞이하여 한복을</span>
<div>곱게 입고 등원하여 제기차기, 투호, 딱지치기,&nbsp;<span style="font-size: 9pt">공기놀이,씨름 등 여러가지 민속놀이를&nbsp;</span></div>
<div>배우고 직접 해보았다고 합니다. 다도체험&nbsp;<span style="font-size: 9pt">시간에는 선생님과 함께 잔을 들고 차를 마시는</span></div>
<div>방법도 배워보았습니다.&nbsp;</div>
<div>어린이집에서 명절에 대해서 배우며 곧 다가올&nbsp;<span style="font-size: 9pt">추석을 무척 기대하고 있는 룻방 친구들입니다</span></div>
<div>아이들이 건강하고 즐겁게 생활할 수 있도록&nbsp;<span style="font-size: 9pt">잘 지원하겠습니다.^^</span></div>          </td>
        </tr>',1179,1568041200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21950,'dus3','유미정','3alwjd@hanmail.net','모세방 박*민 아동 어린이집에서 생일파티 하였습니다.(09.05)','<p>어린이집에서 이 달에 생일을 맞은 모세방 박*민 아동의 생일 파티를 하였답니다. </p>
<p>이 달에는 생일 맞은 어린이집 친구들이 많아서 생일상도 풍성하고 더 즐거운 시간을 보냈다고 하네요. </p>
<p>박*민 아동이 더욱 건강하고 슬기롭게 자랄 수 있도록 함께 기도해주세요^^</p>          </td>
        </tr>',1278,1568041200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21949,'dus3','심주현','pikaccu85@hanmail.net','필동어린이집 박*주 아동  전통놀이체험에서 씨름왕 상을 받아왔습니다.','<p>금일 필동어린이집에서 진행한 전통놀이 체험에서 바울방 박*주 아동이 씨름왕상을 받아왔습니다. </p>
<p>작년에 이어 올해도 씨름왕상을 받아왔는데요 벌써 2관왕이 되었습니다. ^O^/ (짝짝짝!!)</p>
<p>부상으로 쌀 2kg도 받아왔습니다. ^^ 남산원 가족들이 함께 축하해 주는 시간을 가졌습니다. </p>
<p>*주가 씩씩하고 건강하게 잘 성장할 수 있도록 최선을 다해 지원하겠습니다. ^^</p>          </td>
        </tr>',1134,1568041200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21892,'dus3','최호성','naomi1318@naver.com','다윗방 김* 아동이 성동공고 3학년 2학기 부회장으로 임명되었습니다. (2019.08.31)','<p>다윗방&nbsp;김* 아동이 성동공고 3학년 2학기 부회장으로 임명되었습니다.</p>
<p><br /></p>
<p>항상 자신감 넘치고, 리더십 있는 아동이라 학교에서도 모범이 되리라 믿습니다.<br /><br />많은 칭찬과 격려 부탁드립니다. </p>          </td>
