INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21810,'dus3','김도연','311279_@hanmail.net','한나방 아동들이 개학하였습니다.','<p>한나방 김*연 아동이 다니는 보성여자고등학교는 8월 14일 수요일에 개학을 하였습니다.</p>
<p>벌써 어제 오랜만에 등교를 하여 정규수업을 다 듣고 왔습니다. 친구들을 다시 만나서 반갑기도</p>
<p>하지만 수업을 다 듣고 오려니 힘들었다고 이야기를 하는 *연이의 모습을 볼 수 있었습니다.</p>
<p>16일(내일)은 성심여자고등학교에 다니는 박*민 아동의 개학날입니다.</p>
<p>방학동안에 새롭게 안경을 맞춰서 나름 이미지 변신을 한 *민이의 모습을 친구들이</p>
<p>어떻게 바라볼지 궁금합니다. 주말이 지나면 19일에는 덕수중학교 친구들(김*민, 김*경, 손*영)과 </p>
<p>23일에는 남산초등학교 (박*리, 연*빈, 김*경) 친구들도 모두 학교에 가게 됩니다. </p>
<p>어느새 여름방학이 가고 2학기를 맞이하게 되는 우리 친구들입니다.</p>
<p>2학기에도 아동들이 올바르고 즐거운 학교생활을 할 수 있도록 지도하겠습니다.</p>          </td>
        </tr>',1066,1565794800,'', '', '', '', '', '');
