INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21571,'dus3','김형식','jazzer80@naver.com','다윗방 김*, 고*민, 김*현 아동 기능사 자격증 취득','<p>성동공고에 다니는 다윗방 김*, 고*민, 김*현 아동이 기능사 시험에 합격해</p>
<p>김*(생산자동화), 고*민, 김*현(전기기능사) 자격증을 취득했습니다.</p>
<p>현재&nbsp;2-3개의 자격증을 취득해 진로 결정에도 많은 도움을 받게 되었습니다.</p>
<p>함께 축하해주시고, 아동들의 앞길을 많이 응원해주세요!!</p>          </td>
        </tr>',1120,1562857200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21570,'dus3','김형식','jazzer80@naver.com','다윗방 우*운 아동 직업체험 다녀왔습니다.','<p>환일중학교에 다니는 다윗방 우*운 아동이&nbsp;직업체험으로 한국조리예술원에 다녀왔습니다.</p>
<p>에그타르트 만들기 체험을 했는데 어렵긴 했지만 그래도 즐거웠다고 하네요 ~!!</p>
<p>다양한 경험을 통해 자신에게 맞는 진로를 찾아갈 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1130,1562857200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21568,'dus3','이혜원','','룻방 박*빈,박*주,장*아,지* 아동이 어린이집에서 뮤지컬을 관람하였습니다.','<p>룻방 박*빈,박*주,장*아,지* 아동이 어린이집에서 뮤지컬을 관람하였습니다. </p>
<p>하원 후&nbsp; 뮤지컬을 보고 매우 신이 나서 동생과 친구들에게 인어공주 내용을 말해주는 모습이었습니다 ^^</p>
<p>앞으로도 아이들이 즐겁게 어린이집 생활할 수 있도록 지원하겠습니다. </p>
<p><br /></p>          </td>
        </tr>',1056,1562857200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21566,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태, 박*랑 아동 언어 수업 다녀왔습니다.(07.11)','<p>모세방의 두 아동 *태, *랑이 언어수업 다녀왔습니다. </p>
<p>재밌게 즐겁게 수업을 마친 후에 </p>
<p>오늘은 선생님께 스티커북과 부채, 과자를 선물 받고는 두 아동이 무척 좋아라 하였답니다. </p>
<p>돌아오는 차 안에서 과자를 먹고 싶지만 부스러기가 흐르니 집에 가서 먹겠다고 하는 </p>
<p>두 아이가 무척 대견해보였습니다.^^</p>
<p>장 소 : 중구육아종합지원센터</p>
<p><br /></p>          </td>
        </tr>',1078,1562857200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21564,'dus3','최호성','naomi1318@naver.com','다윗방 토목과 2인이 남산 한옥마을로 체험학습을 다녀왔습니다. (2019.07.11)','<p>다윗방 성동공고를 다니는 토목과 2인이(정*균, 곽*민)&nbsp;남산 한옥마을로  체험학습을 다녀왔습니다.</p>
<p>옜날 한옥들도 구경하고, 옛 선조들의&nbsp;전통문화를 체험해 볼 수 있어 정말 즐거웠다고 합니다.</p>
<p><br /></p>          </td>
        </tr>',1100,1562770800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21563,'dus3','최호성','naomi1318@naver.com','다윗방 우*운 아동이 미래인재 VR체험 견학을 다녀왔습니다. (2019.07.11)','<p>다윗방&nbsp;환일중학교를 다니는 우*운 아동이 미래인재 VR체험 견학을 다녀왔습니다.</p>
<p>VR을 통해 독특하고, 신기한 경험을 해보고,&nbsp;정말 즐거웠다고 하네요 ~!!</p>
<p></p>          </td>
        </tr>',1057,1562770800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21560,'dus3','이진선','jinsun9231@hanmail.net','모세방 박*진, 박*태, 박*랑, 소*지 아동 뮤지컬 관람하고 왔습니다.','<p>모세방 박*진, 박*태, 박*랑, 소*지 아동이 어린이집에서 뮤지컬 &lt;더 스토리 오브 언더더씨&gt;를 관람하고 왔습니다.</p>
<p>뮤지컬을 보고와서 뮤지컬내용을 다른 어린이집 아동들과 교사에게 설명해주는 시간을 가졌습니다.&nbsp;</p>
<p>뮤지컬이 재미있었는지 또 보러가고 싶다고 하였습니다.</p>          </td>
        </tr>',1065,1562770800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21557,'dus3','조미영','','룻방 박*서, 장*아,박*주,박*빈,지* 아동들이 견학 다녀 왔습니다.','<p>충무 어린이집을 다니는 박*서 아동은 뮤지컬 \'더스토리 오브더 언더더씨\' 공연을 보고 왔습니다.</p>
<p>토기와 자라, 문어등 바다속 동물들에 생생한 모습을 </p>
<p>이야기를 나누는 시간에 동생들과 언니들에게 전달하는 모습을 보입니다**</p>
<p>필동어린이집을 친구들도 \'화폐박물관을 다녀왔습니다. </p>
<p>옛날 돈에 모양을 이야기 하며 지금과는 다르다는 것과 </p>
<p>가짜 돈을 만들어 사용하면 벌을 받는 다는 것을 말해주는 아동들에 모습을 보며 </p>
<p>날마다 조금씩 조금씩 성장하는 아동들이 기특해 보였습니다~~**</p>          </td>
        </tr>',1003,1562684400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21556,'dus3','심주현','pikaccu85@hanmail.net','필동어린이집 박*주 아동 화폐박물관 견학 다녀왔습니다.','<p>오늘 박*주 아동이 필동어린이집에서 화폐박물관에 견학을 다녀왔습니다. (한국은행)</p>
<p>우리나라 화폐와 다른 나라 화폐를 알아보고 </p>
<p>위조지폐를 구별하는 방법에 대해서도 배워보는 등 화폐에 대해 배울 수 있는 시간이었는데요 </p>
<p>오늘 배운 내용을 잘 기억하고 집에 돌아와&nbsp; 설명해 주는 모습에서 얼마나 관심있게 들었는지 알수 있었습니다. </p>
<p>*주가 즐거운 어린이집 생활을 할 수 있도록 최선을 다해 지원하도록 하겠습니다. ^^</p>          </td>
        </tr>',1065,1562684400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21552,'dus3','최호성','naomi1318@naver.com','다윗방 토목과 2인이 서울숲으로 체험학습을 다녀왔습니다. (2019.07.10)','<p>다윗방 성동공고를 다니는 토목과 2인이(정*균, 곽*민)&nbsp;서울숲으로 체험학습을 다녀왔습니다.</p>
<p>향긋한 꽃내음과 아름다운 숲의 경치를 보고, 아동들은 자연의 소중함을 다시금 느꼈다고 하네요.</p>
<p>자연을 통해 마음까지 힐링하고 온 아동들의 얼굴은 미소로 가득차있었습니다. </p>          </td>
        </tr>',1054,1562684400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21550,'dus3','최호성','naomi1318@naver.com','다윗방 전기과 2인의 아동이 교내 캠프에 참여하였습니다. (2019.07.09)','<p>다윗방 성동공고를 다니는 전기과 2인의 (고*민, 김*현)아동이 전기과 교내 캠프에 참여하였습니다.</p>
<p>이번 캠프는 고3 마지막을&nbsp;맞이하여&nbsp;교내에서 진행하는 자체 캠프로 아동들끼리 고기도 구어먹고, 음식도 만들어보는</p>
<p>자립활동&nbsp;캠프라고 합니다. 아동들이 마지막 학창시절 즐거운 추억을 많이 만들고 오기를 기원합니다.</p>          </td>
        </tr>',988,1562684400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21527,'dus3','김도연','311279_@hanmail.net','한나방 김*경 아동 방과후 수업(꼼지락 도예수업)에서 양초 만들기를 하였습니다.(19.07.05)','<p>한나방 중학교 3학년 김*경 아동이 학교 방과후 수업(꼼지락 도예수업)에서</p>
<p>양초만드기를 하였습니다. 지난번에 만들었던 미니 도자기 쟁반을 가져왔습니다.</p>
<p>도자기에 그림을 그려서 가져온 것이 아동의 그림 실력도 볼 수 있고&nbsp;나름 실용적인</p>
<p>물품이라서 장식용으로도 사용할 수도 있고 여러모로 도움이 많이 될 예정이라 </p>
<p>기대가 됩니다.&nbsp; 이번에 만든 양초도 아직은 소식만 듣고 직접 만든 것은 보지</p>
<p>못했지만 나름대로 기대하고 있습니다. 아동이 열심히 만든 활동을 응원하며, </p>
<p>다음에는 또 어떠한 작품을 만들지 궁금합니다. 이제 도예교실은 2학기에나 </p>
<p>한다고 합니다. 아동이 앞으로도 학교 생활이나 방과후수업에도 열심히 참여할 수</p>
<p>있도록 지도하겠습니다.</p>          </td>
        </tr>',1094,1562252400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21526,'dus3','김도연','311279_@hanmail.net','한나방 덕수중학교, 보성여자고등학교 친구들 1학기 기말고사 끝났습니다.','<p>한나방 덕수중학교 3학년 김*경, 손*영 아동은 7/4일로 기말고사가 끝났고</p>
<p>7/5일은 보성여자고등학교 1학년 김*연 아동의 기말고사가 끝났습니다.</p>
<p>1학기 기말고사까지 끝나고 어느새 여름방학을 앞두고 있습니다.</p>
<p>아직 성적표도 나오지 않았도 방학까지 더 날짜가 남았지만 기말고사가 </p>
<p>끝났다는 이유만으로도 친구들의 얼굴이 환해졌답니다. </p>
<p>아이들이 1학기를 잘 마무리하여 즐거운 여름방학을 맞이할 수 있도록 </p>
<p>성실히 지도하겠습니다. </p>
<p>박*민 아동이 다니는 성심여자고등학교는 7/9 (화요일)에 기말고사가 </p>
<p>종료됩니다. 박*민 아동도 시험 마지막 날까지 잘 할 수 있도록 응원하겠습니다.^^</p>          </td>
        </tr>',1069,1562252400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21521,'dus3','유미정','3alwjd@hanmail.net','모세방 박*태, 박*랑 아동 언어수업 다녀왔습니다','<p>언어 수업 가는 날이라며 엄청 신나하는 두 아동들과 함께 언어 수업 다녀왔습니다. </p>
<p>놀이를 하면서 재미나게 배우고 훈련하는 시간을 가졌답니다. </p>
<p>장 소 : 중구육아종합지원센터</p>          </td>
        </tr>',1010,1562166000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21519,'dus3','신미지','mijishin@hanmail.net','박*태, 박*수 아동 언어치료 진행하였습니다.','<p>박*태, 박*수 아동 언어치료 진행하였습니다.</p>
<p>&nbsp;장소 : 중구육아종합지원센터</p>          </td>
        </tr>',1018,1562166000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21518,'dus3','신미지','mijishin@hanmail.net','박*훈 아동 놀이치료 진행하였습니다.','<p>박*훈 아동 금일 놀이치료 진행하였습니다.</p>
<p>&nbsp;장소 : 신당종합사회복지관</p>
<p><br /></p>          </td>
        </tr>',1063,1562166000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21515,'dus3','김도연','311279_@hanmail.net','한나방 중학생 김*민 아동이 학교활동의 일환으로 뮤지컬&quot;프리즌 &quot;을 관람하였습니다.(19.07.03)','한나방 중학교 1학년 김*민 아동이 자율학기제 시행으로 시험을 보지않아서
<div>언니들이 시험을 보는 이 때에&nbsp; 진로체험 관련 프로그램을 3일간 경험하고&nbsp;</div>
<div>있습니다.&nbsp;</div>
<div>7/2에는 학교에서 초빙한 강사 선생님의 진로에 대한 강연을 들어보는&nbsp;</div>
<div>진로콘서트,&nbsp; 7/3에는 연예인에 대한 관심이 많은 친구들의 호기심을</div>
<div>충족시킬 수 있도록 대학로에서 뮤지컬"프리즌"을 관람하였습니다.</div>
<div>뮤지컬이 재미었는지 집에 와서도 언니, 동생들에게 뮤지컬 내용을&nbsp;</div>
<div>이야기하기에 정신없는 모습을 보였습니다. 7/4에는 ☆ ☆대학교에서</div>
<div>IT학과 체험을 해본다고 기대가 많았습니다.&nbsp;</div>
<div>시험을 보지 않아 중 2,3 학년 언니들과 비교했을 때 기본적인 성적</div>
<div><span style="font-size: 9pt">관리도 어렵고 미래에 대해서도 마냥 먼 일이라고만 여길까봐 걱정했지만</span></div>
<div><span style="font-size: 9pt">짧은 시간이더라도 다양한 경험 및 체험으로 아동이 조금 더 폭 넓게 직업에&nbsp;</span></div>
<div><span style="font-size: 9pt">대해 바라보고 생각할 수 있는 기회가 생긴 것 같습니다.&nbsp;</span></div>
<div><span style="font-size: 9pt">앞으로 원내에서도 아동이 꿈에 대해 다양한 경험을 할 수 있도록 돕고&nbsp;</span></div>
<div><span style="font-size: 9pt">아동이 목표하는 바를 이룰 수 있도록 힘껏 지원하겠습니다.&nbsp;&nbsp;</span></div>          </td>
        </tr>',1068,1562166000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21503,'dus3','배소연','cometrue22@naver.com','한나방 중고생 기말고사 기간입니다.','<p>한나방 중고생 아동들이 기말고사 기간에 돌입했습니다.</p>
<p>한학기를 마무리하는 중요한 시험인 만큼 아동들이 열심히 </p>
<p>공부한&nbsp;내용으로 시험을 잘&nbsp;치르기를 바랍니다.</p>
<p>아동들이 열심히 공부할 수 있게 잘 지원하겠습니다.</p>
<p>기말고사 일정</p>
<p>덕수중 07월 2일~4일</p>
<p>보성여고 07월 01일~5일</p>
<p>성심여고 07월 03일~9일</p>
<p><br /></p>          </td>
        </tr>',1168,1561993200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21507,'dus3','유미정','3alwjd@hanmail.net','모세방 박*민, 박*윤 아동이 어린이집에서 도담도담어린이건강체험관 다녀녀왔습니다.(19.07.02)','<p>등원 전부터 오늘은 어린이집에서 파랑색 버스를 타고 어디를 간다며 빨리 가고 싶다고 매우 신나하던 </p>
<p>박*민, 박*윤 두&nbsp;아동이 도담도담어린이건강체험관으로 불소도포 하러 다녀왔습니다. </p>
<p>바른 칫솔 사용법도 배우고 불소도포도 하고 왔답니다. </p>
<p>아주 의젓한 모습으로 불소도포를 잘 하였다며 어린이집 선생님이 칭찬도 해 주셨답니다. </p>
<p>집으로 돌아와선 오늘 저녁은 양치를 하면 안되고 내일 아침에 일어나서 해야 한다며 </p>
<p>배운 것을 열심히 설명도 잘 하였답니다. </p>
<p><br /></p>          </td>
        </tr>',1053,1562079600,'', '', '', '', '', '');
