INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21483,'dus3','김형식','jazzer80@naver.com','다윗방 박승호 아동 남산초 체험활동 참여했습니다.','<p>다윗방 박*호 아동이 남산초등학교에서 송암 스페이스센터로 체험활동 다녀왔습니다. </p>
<p>천문대에서&nbsp;별자리를 보고 설명을 들은 것이&nbsp;기억에 남는지 </p>
<p>별자리에 대해 말하는 아동의 모습에 절로 웃음이 지어졌습니다.&nbsp;</p>
<p>박*호 아동이&nbsp;즐거운 학교생활을 할 수 있도록 지속적으로 지원하겠습니다. </p>          </td>
        </tr>',1028,1561647600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21480,'dus3','이혜원','','박*빈,박*주.장*아,지* 아동이 어린이집에서 견학을 다녀왔습니다.','<p>박*빈,박*주.장*아,지* 아동이 어린이집에서 견학을 다녀왔습니다. </p>
<p>크라운 해태 키즈뮤지엄에 가서 멋진 과자집을 만들어보았습니다 ^^</p>
<p>아이들이 신이나 과자로 집을 만든 이야기들을 다른 친구들에게도 말해주는 모습이었습니다 ~^^</p>
<p>앞으로도 즐겁게 어린이집 생활할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1027,1561647600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21468,'dus3','김혜숙','rhdnsdd2@naver.com','바울방 박*주 아동이 어린이집 동시 발표회에 참여하였습니다.','<p>박*주 아동이 어린이집 동시 발표회에 참여하였습니다.</p>
<p><br /></p>
<p>멋진 자작시를 낭독하고 </p>
<p>친구와 함께 동시를 번갈아 낭독하는 시간을 가졌습니다.</p>
<p><br /></p>
<p>이제는 어린이집 제일 큰 반 형님답게</p>
<p>떨지 않고 의젓한 모습이 대견하였습니다~~^^</p>
<p><br /></p>
<p>우리 아동들이 행복한 어린이집 생활을 할 수 있도록 </p>
<p>열심히 지원하겠습니다.</p>          </td>
        </tr>',1115,1561561200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21466,'dus3','한자혜','','룻방 아이들 어린이집에서 동시 발표회가 있었습니다.','<p>룻방 장*아, 박*주, 박*빈, 지* 아동들이 어린이집에서 동시 발표회가 있었습니다. </p>
<p><br /></p>
<p>처음 무대에 서는 아동은 부끄러워서 한마디 하는 것도 어려워 하였지만 울지 않고 잘 올라선 것에 대견해보였습니다. </p>
<p><br /></p>
<p>무대 경험이 있는 아동들은 씩씩하고 자신감 있게 자신의 동시를 잘 기억하고 발표하는 모습입니다. </p>
<p><br /></p>
<p>잘 하는 아동들은 친구과 호흡을 맞추면서 발표를 해보기도 하였습니다. </p>
<p><br /></p>
<p>한해 한해 잘 자라주는 우리 아이들을 보니 사랑스럽고 기특합니다.</p>          </td>
        </tr>',1073,1561561200,'', '', '', '', '', '');
