INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21461,'dus3','심주현','pikaccu85@hanmail.net','바울방 이*민 아동 남산초등학교에서 송암스페이스센터로 현장학습 다녀왔습니다.','<p>바울방 이*민 아동이 남산초등학교에서 송암 스페이스센터로 현장학습을 다녀왔습니다. </p>
<p>케이블카를 타고 천문대도 가보고 별자리를 알아보는 등 매우 유익한 시간을 가졌는데요 </p>
<p>오늘 활동이 재미있었는지 동생들에게 별자리에 대해 말해주는 모습이 기특하였습니다. </p>
<p>*민이가 즐거운 학교생활을 할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1064,1561474800,'', '', '', '', '', '');
