INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21440,'dus3','유미정','3alwjd@hanmail.net','어린이집에서 박*진 아동의 생일 파티를 하였습니다.','<p>오늘 생일 맞은 박*진 아동의 생일 파티를 어린이집 친구들과 함께 하였답니다. </p>
<p>친구들의 축하 속에 촛불을 불고 소원도 빌고 맛있는 케익도 나눠 먹었지요.&nbsp; </p>
<p>그리고 </p>
<p>친구들에게 생일 축하 카드도 많이 받았다며 신이 나서 자랑을 하네요. </p>
<p>건강하게 무럭무럭 잘 자라주길&nbsp;기원합니다^^&nbsp;</p>          </td>
        </tr>',1107,1561302000,'', '', '', '', '', '');
