INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21421,'dus3','김도연','311279_@hanmail.net','한나방 김*경 아동이 초등학교에서 실시하는 구강검진을 다녀왔습니다.(19.06.21)','<p>6월 21일 한나방&nbsp;5학년 김*경 아동이 초등학교에서 실시하는 </p>
<p>구강검진을 다녀왔습니다.</p>
<p>학교 주변에 있는 지정 치과로 구강검진을 다녀왔습니다.</p>
<p>아동이 평소 양치질을 잘하고 있는지, 치아에 충치는 없는지 등</p>
<p>구강청결상태에 대해 확인할 수 있는 시간이였습니다.</p>
<p>다행히 평소에 양치질을 잘하여 아동이 충치가 없이 건강한 상태라고 합니다.</p>
<p>더 자세한 사항은 추후 학교를 통해서 결과지를 받을 수 있다고 합니다.</p>
<p>앞으로도 아동을 포함한 한나방 친구들이&nbsp;건강한 치아를 가질 수&nbsp;있도록 </p>
<p>지원하겠습니다.</p>          </td>
        </tr>',974,1561129200,'', '', '', '', '', '');
