INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21375,'dus3','심주현','pikaccu85@hanmail.net','바울방 박*주 아동 필동어린이집에서 청와대로 현장학습 다녀왔습니다. (2019.06.14)','<p>바울방 박*주 아동이 필동 어린이집에서 청와대로 견학을 다녀왔습니다. </p>
<p>멋진 목걸이 명함을 보여주며 청와대에 대해 말해주는 *주 얼굴에서&nbsp;오늘의 즐거움을 알수 있었습니다.</p>
