        </tr>',1018,1560610800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21360,'dus3','이혜원','','룻방 장*아, 박*주, 박*빈 아동이 어린이집에서 청와대로 견학을 다녀왔습니다.','<p>룻방 장*아, 박*주, 박*빈 아동이 어린이집에서 청와대로 견학을 다녀왔습니다. </p>
<p>집에 오자마자 신이 나서 청와대에서 받은 기념품도 보여주고 </p>
<p>동생과 선생님에게도 청와대가 어떤 곳인지 열심히 설명을 해주는 모습이었습니다. </p>
