INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21357,'dus3','배소연','cometrue22@naver.com','한나방 박*리, 연*빈 초등학교에서 실시한 구강검진 다녀왔습니다.','<p>한나방 박*리, 연*빈 아동이 </p>
<p>초등학교에서 실시하는 구강검진을 다녀왔습니다.</p>
<p>학교 주변에 있는 지정 치과로 구강검진을 다녀왔는데요. </p>
<p>아동들이 평소 양치질을 잘하고 있는지, 치아에 충치는 없는지등</p>
<p>구강청결상태에 대해 확인할 수 있는 시간이였습니다.</p>
<p>아동들 모두 충치가 없이 건강한 상태였는데요, 평소 치아관리를 잘 할 수 있도록 지원하겠습니다.</p>
<p><br /></p>          </td>
        </tr>',1014,1560438000,'', '', '', '', '', '');
