INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21352,'dus3','유미정','3alwjd@hanmail.net','모세방 박*진 아동이 어린이집에서 숲체험 다녀왔습니다(05.29)','<p>박*진 아동이 어린이집에서 무학봉으로 숲체험 다녀왔습니다. </p>
<p>여러 가지 식물도 보고 산책도 하며&nbsp;즐거운 시간을 보내고 왔답니다. &nbsp;</p>          </td>
