INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21270,'dus3','최호성','naomi1318@naver.com','다윗방 환일중 우*운 아동이 합창대회에 참여하였습니다. (2019.05.31)','<p>5월 31일 다윗방 환일중학교 우*운아동이 환일중학교에서 합창대회를 참여하였습니다.</p>
<p>열심히 노래를 외우고 연습하는 모습에서 열정을 느낄수 있었고,</p>
<p>즐겁게 합창대회를 진행하고 돌아온 아동들의 얼굴속에서 밝은 미래를 볼 수 있었습니다.</p>
<p>아동들이 항상 밝은 모습 유지하도록 열심히 지도하겠습니다.</p>          </td>
        </tr>',1066,1559228400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21283,'dus3','김형식','jazzer80@naver.com','다윗방 환일중 우*운 아동 마술쇼 관람하였습니다','<p>다윗방 환일중 우*운 아동이 이은결 일루션(예술의전당 토월극장) 마술쇼 관람하고 왔습니다.</p>
<p>마술에 대한 환상이 없어서 관심이 없었는데,</p>
<p>막방 관람하고 신기하고 재미있어서 또 보고 싶은 마음이 들었다고 합니다.</p>
<p>다양한 경험을 하며 밝게 웃으며 학교생활할 수 있도록 지속적으로 지원하겠습니다.</p>          </td>
        </tr>',1031,1559487600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21269,'dus3','최호성','naomi1318@naver.com','다윗방 미래고 정*찬 아동이 체육대회에 참여하였습니다. (2019.05.31)','<p>2018년 05월 31일&nbsp;미래산업고 체육대회가 있어 다윗방&nbsp;아동 01명이(정*찬) 참여했습니다.</p>
<p>체육대회를 통해 좋은 날씨 속에서&nbsp;일상의 스트레스를 날려버렸을 것 같습니다.&nbsp;</p>
<p>앞으로도 건강하게 신체를 다지며 활력 넘치게 생활하도록 지원하겠습니다.</p>          </td>
        </tr>',975,1559228400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21256,'dus3','김형식','jazzer80@naver.com','다윗방 정*찬 아동 체험활동 다녀왔습니다.','<p>한강미디어고에 다니는 다윗방 정*찬 아동이 금일 북서울 꿈의숲으로 체험활동 다녀왔습니다.</p>
<p>날이 더워 시원한 그늘 밑에서 이야기도 나누고, 게임도 하면서</p>
<p>학급 담임선생님, 반 친구들과 즐거운 시간을 보냈다고 합니다.</p>
<p>&nbsp;교우들과 좋은 관계 맺으며&nbsp;학교생활 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',950,1558969200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21268,'dus3','신미지','mijishin@hanmail.net','박*랑, 박*태 아동 언어치료 다녀왔습니다(5. 30)','<p>5월 30일 박*랑, 박*태 아동 언어치료 다녀왔습니다&nbsp;</p>
<p>&nbsp;장 소 : 중구육아종합지원센터</p>          </td>
        </tr>',968,1559228400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21241,'dus3','김도연','311279_@hanmail.net','한나방 왕*젤 아동이 초등학교에서 생존수영 수업을 시작합니다.(19.05.27)','<p>한나방 왕*젤 아동이 초등학교에서 드디어 생존수영 수업을 시작합니다. </p>
<p>3학년때 한 번 배우고 4학년때는 조금 더 심화과정을 배우는 것으로 알고 있습니다.</p>
<p>4학년은 5월 27일부터 6월 5일까지 2주에 걸쳐 수업을 하게 되며 총 5번 동안 합니다.</p>
<p>주 3회, 월, 수, 금으로 운영하며 9:30~12:00 수영수업 후 학교로 이동하여 점심식사 후</p>
<p>오후 수업을 하고 귀원합니다. </p>
<p>자신의 안전을 위해서 꼭 배우고 알아두어야 할 생존 수영, 아동이 열심히 배우고 와서</p>
<p>어떠한 내용이었는지 그날 그날마다 짧게나마 이야기 해주기로 하였습니다. </p>
<p>아동의 건강하고 안전한 생활을 위해 원내에서도 여러 교육을 통해 지도하고 있습니다.</p>
<p>앞으로도 아동들의 안전을 위해서 더욱 노력하겠습니다.</p>          </td>
        </tr>',965,1558882800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21240,'dus3','김도연','311279_@hanmail.net','한나방 박*민 아동이 학교 내 프로그램으로 교리교육에 참여하였습니다.(19.05.23~05.24)','<p>한나방 박*민 아동이 성심여자고등학교에 다니고 있습니다. </p>
<p>성심여자고등학교가 가톨릭계 고등학교이다 보니 어느 정도의 프로그램 </p>
<p>운영이 있는 것 같습니다. 이번에 운영한 신자학생과 예비신자학생을 위한</p>
<p>교리교육 프로그램은 의무 프로그램은 아니었지만 *민이의 호기심에 의해</p>
<p>참여하게 되었습니다. 저녁부터 다음날 점심때까지 1박 2일로 이루어진 일정이며</p>
<p>가톨릭교리에 대해서 함께 배우고 미사를 드리는 시간이었다고 합니다.</p>
<p>고등학교 3년의 시간동안 다녀야 할 학교니, 종교적인 접근이 아니더라도&nbsp;</p>
<p>조금 더 알게되면 이해할 수 있다는 측면으로 생각하고 접근한다면 좋을 것이라고</p>
<p>생각합니다. 아동의 원활하고 건강한 학교 생활을 응원하며, 옆에서 아동이 어려움을</p>
<p>잘 헤쳐나갈 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',982,1558882800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21239,'dus3','김도연','311279_@hanmail.net','한나방 김*선 아동이 대학 축제를 참여하였습니다. (19.05.23)','<p>한나방 맡언니 김*선 아동이 말로만 들어보던 대학 축제에 처음으로 아동도 </p>
<p>참여하게 되었습니다. 강의가 끝나고 집에 왔다가 다시 학교에 다서 축제를 </p>
<p>관람하기도 하고 학과가 운영하는 부스를 도와주기도 하였다고 합니다.</p>
<p>덕분에 늦게 귀원하였답니다.ㅠ.ㅠ</p>
<p>대학에서 초청한 연예인을 보는 재미도 쏠쏠했다고 합니다. </p>
<p>아동의 이야기를 듣다보면 저의 대학시절은 어떠했는지 다시 떠올려보게 </p>
<p>되는 것 같습니다. 나름대로 재미있었는지 23일 목요일에 이어 24일 금요일에도</p>
<p>축제에 참석한다고 합니다. 성실했던 아동답게 대학생활에서도 여러가지를 </p>
<p>경험해보려는 것 같기도 합니다.&nbsp; 바른 *선이는 12시는 넘기지 않으니까요.</p>
<p>아동의 건전한 대학 생활을 응원합니다.^^</p>
<p><br /></p>          </td>
        </tr>',975,1558796400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21219,'dus3','한자혜','','룻방 박*주, 박*빈, 장*아, 지* 아동이 어린이집에서 미술체험을 하였습니다.','<p>룻방 박*주, 박*빈, 장*아, 지* 아동이 어린이집에서 라뜰리에 탐험대 미술체험을 하였습니다.</p>
<p><br /></p>
<p>아이들은 오늘 미술 체험가는 것을 미리 알고 계속 말하는 모습으로 기대하며 등원하였습니다. </p>
<p><br /></p>
<p>아이들이 미술 체험으로 색다르고 즐거운 시간을 보냈길 바랍니다. </p>          </td>
        </tr>',948,1558623600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21225,'dus3','김도연','311279_@hanmail.net','한나방 김*경 아동이 학교 동아리 활동으로 경찰박물관을 다녀왔습니다.(19.05.23)','<p>한나방 김*경 아동이 덕수중학교 동아리 활동으로 경찰박물관으로</p>
<p>견학을 다녀왔습니다. 박물관을 가서 경찰직업체험교실을 이용했다고</p>
<p>합니다. 수사경찰(사이버범죄 활동업무), 교통경찰(교통관리, 기능, </p>
<p>활동사항 등)에 대해서 강의도 듣고 직접 사격 등의 업무를 체험할 수</p>
<p>있는 기회를 갖게 되어 좋았다고 합니다. </p>
<p>아동이 직업체험을 하며 진로에 대해서 한 번 더 고민해보는 시간이 </p>
<p>되었다고 하니 더욱 감사하게 느껴집니다.</p>
<p>원에서도 아동이 여러가지 활동에 참여하며 자신을 길을 찾을 수 있도록</p>
<p>지원하겠습니다.</p>          </td>
        </tr>',1006,1558710000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21223,'dus3','심주현','pikaccu85@hanmail.net','바울방 박*주 아동 필동어린이집에서 라뜰리에 미술관 다녀왔습니다.','<p>바울방 박*주 아동이 필동어린이집에서 라뜰리에 미술관을 다녀왔습니다. </p>
<p>유명한 화가들의 작품을 마음껏 감상하고 고흐 뮤지컬로 관람하는 등 볼거리가 매우 많았다고 합니다. </p>
<p>*주가 즐거운 어린이집 생활을 할 수 있도록 최선을 다해 지원하도록 하겠습니다. (^^)(__)(^^)</p>
<p><br /></p>          </td>
        </tr>',1016,1558623600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21211,'dus3','김혜숙','rhdnsdd2@naver.com','바울방 박*주 아동이 어린이집에서 119아동안전체험을 다녀왔습니다.','<p>땅이 흔들리고 불이난 체험을 해보았다고 합니다.</p>
<p>구조대 미끄럼틀 연습과 사다리타기 연습도 해보았다면서 </p>
<p>"선생님 이건 정말 중요한거에요." 하고 가르쳐주네요^^</p>
<p>우리 *주이가 어린이집 생활 즐겁게 할 수 있도록 최선을 다해 지원하겠습니다. <br /></p>          </td>
