INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21212,'dus3','이혜원','','룻방 박*주,박*빈,장*아 아동이 어린이집에서 체험학습을 다녀왔습니다.','<p>룻방 박*주,박*빈,장*아 아동이 어린이집에서 체험학습을 다녀왔습니다. </p>
<p>119 아동안전 체험을 하고와서 교사와 동생들에게 지진 시 대피 요령에 대해 설명을 해주고 </p>
<p>또 화재 시 소화기 사용법, 탈출법 등에 대해 이야기 해주며 오늘 직접 비상 계단도 이용해 봤다고 하네요~</p>
<p>아동들이 안전하게 잘 지낼 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',979,1558537200,'', '', '', '', '', '');
