INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21209,'dus3','이혜원','','룻방 박*음 아동이 어린이집에서 체험학습을 다녀왔습니다.','<p>룻방 박*음 아동이 어린이집에서 체험학습을 다녀왔습니다. </p>
<p>아동이 견학으로 거인의 침대 연극을 보고 왔습니다. 매우 좋아하며 언니들에게 자기가 본 연극을 이야기 해주며</p>
