INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21185,'dus3','김형식','jazzer80@naver.com','다윗방 정*찬 아동 종이접기 교내 전시회(05월23일~30일)','종이접기 강사 및 사범 과정 자격증을 취득하고, 마스터 과정을 밟고 있는 다윗방 정*찬 아동이 <br /><br />다니고 있는 학교에서 선생님들의 전폭적인 지지로 종이접기 전시회를 진행한다고 합니다. <br /><br />문화와 노니는 도서관 전시회라는 타이틀 아래, <br /><br />개막식 : 2019년 05월 23일(목), 13:00 <br />전시일정 : 2019년 05월23일 ~ 30일 <br />체험활동 : 전시 기간 중 13:00 ~ 13:15 으로 이루어 진다고 합니다. <br /><br />아동에게  색다른 경험이 될 이번 전시회를 통해 한 단계 더 성장하는 기회가 되기를 응원합니다.          </td>
        </tr>',1001,1558278000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21151,'dus3','이소영','applehyoji@naver.com','솔로몬B방 소*지 아동이 어린이집에서 도담도감 건강체험관에 다녀왔습니다','<table width="100%" border="0" cellspacing="0" cellpadding="0">
