INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21155,'dus3','심주현','pikaccu85@hanmail.net','바울방  이*민 아동이 남산초등학교에서  수영 수업에 다녀왔습니다.','<p>오늘 바울방 이*민 아동이 남산초등학교에서 진행하는 수영 수업에 다녀왔습니다. </p>
<p>물을 워낙 좋아하는 *민이라서 그런지 잠수도 하고 수영도 배우며 재미있었다고 합니다. </p>
<p>벌써부터 다음주 수영수업을 기다리는 모습이 귀엽기만 하네요~ ^^</p>
<p>*민이가 즐거운 학교생활을 보낼 수 있도록 최선을 다해 지원하도록 하겠습니다. </p>          </td>
        </tr>',975,1558018800,'', '', '', '', '', '');
