INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21132,'dus3','최호성','naomi1318@naver.com','다윗방 성동공고 4인이 체육대회에 참여하였습니다. (2019.05.15)','<p>2019년 05월 15일&nbsp;다윗방 성동공고 4인(김*, 고*민, 곽*민, 정*균) 이 성동공고 체육대회에 참여하였습니다.</p>
<p>체육대회를 통해 좋은 날씨 속에서&nbsp;일상의 스트레스를 날려버렸을 것 같습니다.&nbsp;</p>
<p>앞으로도 건강하게 신체를 다지며 활력 넘치게 생활하도록 지원하겠습니다.</p>          </td>
        </tr>',914,1557846000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21057,'dus3','이혜원','','룻방 지*,박*빈,박*주,장*아 아동이 어린이날 행사에 참여했습니다.','<p>룻방 지*,박*빈,박*주,장*아 아동이 어린이날을 맞이하여 어린이집에서&nbsp;어린이날 행사를 하였습니다.</p>          </td>
        </tr>',966,1556895600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21090,'dus3','김도연','311279_@hanmail.net','한나방 중,고등학생 4명의 아동이 학교 수련회 및 소규모테마교육여행을 다녀옵니다.(19.05.08~19.05.10)','<p>한나방의 어여쁜 중,고등학생 친구들 4명이 수련회 및 소규모테마교육여행을 </p>
<p>다녀오게 되었습니다.&nbsp; 날이 따뜻해지자 다들 비슷한 시기에 움직이기로 약속이라도</p>
<p>한 듯 일정도 날짜가 맞아 5월 8일~5월 10일까지 2박 3일로 4명의 아동이 학년이나 학교가</p>
<p>조금 다르고 가는 지역은 아예 달라도 같은 날&nbsp; 움직이게 되었습니다. </p>
<p>덕분에 한나방은 조금 쓸쓸해지게 되었답니다.</p>
<p>중학교 1학년 *민이는 청소년수련마을로 수련회를 다녀오고 </p>
<p>중학교 3학년 *영, *경이는 강원도로 소규모테마교육여행을 </p>
<p>고등학교 1학년 *민이는 대전 청소년 수련원으로 수련회를 다녀옵니다. </p>
<p>아이들 모두가 즐겁고 안전한 여행, 친구들, 선생님과 떠올기면 행복했던 추억을 한아름</p>
<p>만들고 올 수 있기를 바랍니다.&nbsp;원에 있는 동생들은 언니들이 언제 오는지 벌써부터 </p>
<p>물어보고 있습니다. ^^ 아이들이 건강한 학교 생활과 여러 가지 경험을 하도록 앞으로도</p>
<p>끊임없이 지원하도록 하겠습니다.</p>          </td>
        </tr>',1043,1557327600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21054,'dus3','최호성','naomi1318@naver.com','다윗방 성동공고 곽*민, 정*균 아동이 안산 시화호 견학을 다녀왔습니다. (2019.05.03)','<p>다윗방 성동공고 곽*민, 정*균 아동이 건축토목과 안산 시화호 견학을 다녀왔습니다.</p>
<p>바다를 보며 기분전환도 하고, 발전소 내 조력발전 시스템도&nbsp;구경도 하는 등 이것저것&nbsp;흥미로운 경험이었다고 합니다. </p>
<p></p>          </td>
        </tr>',964,1556809200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21041,'dus3','한자혜','','룻방 박*서 아동 어린이집에서 어린이날 행사를 하였습니다.','<p>룻방 박*서 아동&nbsp;어린이날을 맞이하여 어린이집에서&nbsp;어린이날 행사를 하였습니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1063,1556722800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21034,'dus3','김도연','311279_@hanmail.net','한나방 김*민 아동 중학교에서 진로캠프로 신원도예센터와 송린한과를 다녀옵니다.(19.04.30~19.05.01)','<p>한나방 중학교 1학년 김*민 아동이 학교 진로캠프로 우리 전통의 멋과 아름다움에 대해 느끼고</p>
<p>심성을 수련하는 시간을 갖고자 신원도예센터와 송린한과를 다녀온다고 합니다. </p>
<p>오늘 (4월 30일) 아침에 학교에 모여서 출발하였고 첫날에는 물레, 도자기 체험, 세라믹 아트 체험</p>
<p>레크리에이션과 나의 진로에 대해서 친구들과 이야기를 나누는 시간을 갖는다고 합니다.</p>
<p>내일 (5월 1일)에는 안성맞춤 직매장으로 가서 구경을 해보고 한과만들기를 직접 체험 해보기로</p>
<p>하였다고 들었습니다. 중학교에 들어가서 처음 친구들과 하룻밤을 지내고 오는 활동이라</p>
<p>더 재미있게 느껴지지 않았을까 싶은 마음이 듭니다. 전통에 대해서도 배우고 친구들과도 조금 더 </p>
<p>가까워지는 시간이 되었기를 바랍니다. </p>
<p>아동이 건강하고 바른 학교와 원내생활을 할 수 있도록 앞으로도 지지하고 응원하겠습니다.</p>          </td>
        </tr>',1030,1556550000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21033,'dus3','김도연','311279_@hanmail.net','한나방 김*선 아동 대학교 학과 견학으로 부산을 다녀왔습니다.(19.04.29~04.30)','<p>한나방 김*선 아동이 대학 학과 견학의 일환으로 부산에 있는 공장을</p>
<p>29~30일까지 1박2일로 견학하고 왔습니다. 산업경영학과라 그런지 </p>
<p>공장을 견학하는 과정이 있습니다. 어떠했는지 아동에게 물어보니</p>
<p>생각했던 것보다는 재미있기는 했지만 계속 버스로 이동했던 점은 조금</p>
<p>힘들기도 했다고 하였습니다. 아무래도 공장들이 크고&nbsp;거리가 있다보니</p>
<p>걸어서 움직이기 보다는 차를 타고 다녔기 때문인가 봅니다.</p>
<p>아이들을 통해서 잘 모르는 부분도 새롭게 알게되고 </p>
<p>조금이지만 간접적으로 경험하게 되는 것 같습니다. </p>
<p>앞으로도 아이들이 더 성장하고 많은 것들을 보고 배울 수 있도록 아낌없이 </p>
<p>지원하도록 노력하겠습니다.</p>          </td>
        </tr>',973,1556550000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21031,'dus3','최호성','naomi1318@naver.com','다윗방 박*호 아동이 광희영어체험센터로 현장체험학습을 다녀왔습니다. (2019.04.30)','<p>다윗방 박*호 아동이 광희영어체험센터로 현장체험학습을 다녀왔습니다.</p>
