INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21030,'dus3','최호성','naomi1318@naver.com','다윗방 성동공고 2인이 진해로 교육사령부 훈련에 참여하였습니다. (2019.04.29)','<p>다윗방 성동공고 3학년 고*민, 김*현 2인이 진해로 4박 5일간 교육사령부 훈련에 참여하였습니다. </p>
<p>아동들이 군 특성화 전공으로 그 꿈을 위해 힘든 훈련도 끝까지 버티고, 유익한 경험이 되리라 믿습니다.</p>
<p>많은것을 느끼고 건강하게&nbsp;다녀오기를 기원합니다.</p>          </td>
        </tr>',985,1556550000,'', '', '', '', '', '');
