INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (21021,'dus3','배소연','cometrue22@naver.com','한나방 왕*젤 아동이 학교 학예행사에서 최우수상을 받았습니다.','<p>한나방 왕*젤 아동이 초등학교 교내 학교폭력예방 및 </p>
<p>생명존중, 친구사랑 학예행사에서 최우수상을 받았습니다.</p>
<p>아동이 교내 방송을 통해 상장을 수여받은 것을 무척이나 뿌듯해하며</p>
<p>여러차례 다른 친구들에게 자랑하는 모습을 보였습니다.</p>
<p>아동이 학교생활을 즐겁게 할 수 있도록 노력하겠습니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1017,1556463600,'', '', '', '', '', '');
