INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20995,'dus3','심주현','pikaccu85@hanmail.net','바울방 박*주 아동 필동어린이집에서 아침이슬 딸기마을로 현장학습 다녀왔습니다.','<p>바울방 박*주 아동이 오늘 필동어린이집에서 아침이슬 딸기마을로 현장학습을 다녀왔습니다. </p>
<p>딸기 따기 체험도 하고 딸기잼도 만들었다며 집에 가져와 보여주는 모습이 매우 귀여웠습니다. </p>
<p>얼마 되지는 않지만 다 함께 나눠 먹는 *주의 마음이 너무 예뻤답니다. </p>
<p>*주가 즐거운 어린이집 생활을 할 수 있도록 최선을 다해 지원하겠습니다. ^^</p>          </td>
        </tr>',1076,1556204400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20994,'dus3','이혜원','','룻방 장*아,박*빈,박*주,지* 아동이 어린이집에서 소풍을 다녀왔습니다.','<p>룻방 장*아,박*빈,박*주,지* 아동이 어린이집에서 딸기농장으로&nbsp;소풍을 다녀왔습니다. </p>
<p>소풍을 가기 전부터 굉장히&nbsp;설레하며 맛있는 도시락도 싸서 신이 나서 소풍을 다녀왔습니다. </p>
<p>아동들이 제일 좋아하는 과일인 딸기를 직접 따보고 자기가 딴 딸기를 먹어도 보며 즐거운 시간을 보냈다고 합니다~</p>
<p>앞으로도 즐겁게 어린이집 생활 할 수 있도록 지원하겠습니다. </p>
<p></p>          </td>
        </tr>',1020,1556204400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20993,'dus3','심주현','pikaccu85@hanmail.net','2019년 남산초등학교 담임교사 초청 간담회를 진행하였습니다.','<p>2019년 남산초등학교 담임교사 초청 간담회를 진행 하였습니다. </p>
<p>이번 간담회를 통해 우리 아이들에 대한 이해를 넓히는데 중요한 시간이 되었다고 생각합니다. </p>
<p>앞으로도 남산초등학교와 잘 협력하여 우리 아이들이 푸른 꿈을 가지고 건강하게 </p>
<p>잘 성장할 수 있도록 최선을 다해 노력 하겠습니다. </p>
<p>큰 관심과 사랑을 보여주신 남산초등학교 선생님들께 다시한번 깊은 감사를 드립니다. </p>          </td>
        </tr>',1043,1556204400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20989,'dus3','유미정','3alwjd@hanmail.net','모세방 박*진,박*태,박*랑 아동이 어린이집에서 봄소풍 다녀왔습니다(04.25)','<p>배다골 테마파크로 봄소풍 다녀왔습니다. </p>
<p>소풍을 간다며 아침부터 무척 설레이는 마음으로 출발하여</p>
<p>딸기향 맡으며 딸기청도 만들고 박물관 체험도 하면서 재밌게 소풍을 즐기고 </p>
<p>돌아오는 길에 직접 만든 딸기청을 가져와서 자랑을 하며 아주 신나하였답니다. </p>
<p>딸기청에 우유을 섞어서 맛있는 음료를 만들어 한잔씩~ 꿀꺽</p>
<p>서로 내가 만든 것이라며 으쓱해하며 자랑하느라 바쁜&nbsp;세 아이는 오늘도&nbsp;행복한 하루였답니다^^</p>          </td>
        </tr>',1011,1556204400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20986,'dus3','이혜원','','룻방 박*서 아동이 어린이집 봄소풍을 다녀왔습니다.','<p>룻방 박*서 아동이 어린이집에서 배다골 테마파크로 봄소풍을 다녀왔습니다.</p>
<p>물고기 밥도 주고 친구들과 함께 고슴도치와 토끼 등 다양한 동식물을 관찰하고 </p>
<p>아동이 제일 좋아하니 딸기로 맛있는 딸기청도 만들어 보았습니다~</p>
<p>아동이 앞으로도 즐겁게 생활 할 수 있도록 지원하겠습니다. &nbsp;</p>          </td>
        </tr>',1053,1556118000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20985,'dus3','송은숙','dart0202@hanmail.net','솔로몬B방 소*지가 어린이집에서 봄소풍 다녀왔습니다.~','<p>솔로몬B방 소*지가어린이집에서 배다골 테마파크로 봄소풍을 다녀왔습니다.</p>
<p>달콤한 딸기향을 맡으며 딸기청을 만들고 옛거리를 재현한 민속박물관 체험을 하였고</p>
<p>여러 꽃과 식물들이 있는 식물원을 체험하면서 신나는 하루를 보냈답니다.</p>
<p>테마파크에 도착하여 비가 오락가락 하였지만 실내에 있는 체험관에서 건강하게 활동하고 왔습니다.~~~</p>          </td>
        </tr>',1019,1556118000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20984,'dus3','유미정','3alwjd@hanmail.net','모세방 박*민,박*윤 아동이 어린이집에서 봄소풍을 다녀왔습니다(04.24)','<p><font size="2">민이와 윤이가 봄소풍으로 애니스토리를 다녀왔습니다. </font></p>
<p><font size="2">도시락 싸는 것을 옆에서 보며 들떤 모습으로 친구들에게 자랑을 하며 신나게 집을 나섰답니다. </font></p>
<p><font size="2">동물도 보고, 놀이도 하고, 맛있는 점심도 먹고 아주 재미있었다며 </font></p>
<p><font size="2">쫑알쫑알 종일 있었던 이야기를 해주며 신나하네요^^<font size="2">&nbsp;</font></font></p>          </td>
        </tr>',977,1556118000,'', '', '', '', '', '');
