INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20974,'dus3','최호성','naomi1318@naver.com','다윗방 오*진 아동이 수학여행을 다녀옵니다. (2019.04.24)','<p>다윗방에서 생활하는 한강미디어고 2학년&nbsp;오*진 아동이 2박 3일 간&nbsp;제주도로&nbsp;수학여행을 다녀옵니다. </p>
<p>&lt; 04.24 (수) ~ 04.26 (금) &gt;</p>
<p></p>
<p>즐거운 경험과 추억을 남기고 귀원하기를 기대합니다. </p>
<p></p>          </td>
        </tr>',956,1556031600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20969,'dus3','한자혜','','룻방 박*음 아동이 어린이집에서 중부시장 체험 활동에 다녀왔습니다.','<p>어린이집에서 중부시장으로 시장 체험 활동 다녀왔습니다. </p>
<p>여러 가지 물건을 직접 구매도 해 보고 </p>
<p>공연도 보고, 안전교육도 받고, 케리커쳐 그리기도 경험해 보았습니다.</p>
<p>아동은 사온 물건을 친구들과 함께 나눠 먹고 </p>
<p>이야기 하는 시간을 가져보았습니다.</p>
<p><br /></p>          </td>
        </tr>',977,1555945200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20971,'dus3','한자혜','','룻방 박*음 아동이 어린이집에서 봄소풍을 다녀왔습니다.','<p class="0" style="line-height: 120%; letter-spacing: 0pt; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">룻방 박</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">*</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">음 아동이 어린이집에서 반 친구들과</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">&nbsp;</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">처음으로</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">&nbsp;</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">소풍을 다녀왔습니다</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">. </span></p>
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">아동은 도시락과 간식을 챙기며 설레는 감정을 숨기지 못하고 </span></p>
<p class="0" style="line-height: 120%; letter-spacing: 0pt; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">들뜬 모습으로 등원하였습니다</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">.</span></p>
<p class="0" style="line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">누리과정을 통해 배웠던 동물들이 </span></p>
<p class="0" style="line-height: 120%; letter-spacing: 0pt; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt"><span style="font-family: 굴림; mso-fareast-font-family: 굴림">애니스토리</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">(</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">백로</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">,</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">앵무새</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">, </span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">물개</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">, </span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">기니피그</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">, </span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">너구리</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">, </span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">고양이 등</span><span lang="EN-US" style="letter-spacing: 0pt; font-family: 굴림; mso-ascii-font-family: 굴림; mso-font-width: 100%; mso-text-raise: 0pt; mso-fareast-font-family: 굴림">)</span><span style="font-family: 굴림; mso-fareast-font-family: 굴림">에 출연해서<br />&nbsp;<span style="font-family: 굴림; mso-fareast-font-family: 굴림">직접 눈으로 확인할 수 있는 생생학 체험학습이었다고 합니다.</span></span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">  &nbsp;  <o:p></o:p></p>          </td>
        </tr>',1011,1556031600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20966,'dus3','유미정','3alwjd@hanmail.net','모세방 박*진 아동이 충무어린이집에서 중부시장 체험활동 다녀왔습니다.','<p>어린이집에서 중부시장으로 장보기 등 시장 체험 활동 다녀왔습니다. </p>
<p>시장을 둘러보며 직접 물건을 사보기도 하는 등 재밌는 시간을 보내고 왔답니다. </p>
<p>집으로 돌아오며 딸기와 사과를 직접 사왔다며 아주 신나하였지요. </p>
<p>깨끗이 씻어서 다른 아동들과 함께 맛있게 먹었답니다. </p>          </td>
        </tr>',1019,1555945200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20967,'dus3','유미정','3alwjd@hanmail.net','모세방 박*민, 박*윤 아동이 을지어린이집에서 중부시장 체험 활동 다녀왔습니다.','<p>어린이집에서 중부시장으로 시장 체험 활동 다녀왔습니다. </p>
<p>건어물, 채소, 떡, 과일 등 여러 가지 물건을 직접 구매도 해 보고 </p>
<p>공연도 보고, 안전교육도 받고, 케리커쳐 그리기도 경험해 보았답니다. </p>
<p>여러 활동을 하며 재밌는 시간을 보내고 </p>
<p>구매한 물건을 집으로 가져와서 다른 친구들과 맛있게 나눠 먹으며 </p>
<p>시장에서 무엇을 하였는지 이야기 나누는 시간도 가졌답니다. </p>          </td>
        </tr>',1035,1555945200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20964,'dus3','심주현','pikaccu85@hanmail.net','바울방 박*주 아동 필동어린이집 학부모 상담 참여하였습니다.','<p>오늘 바울방 박*주 아동 어린이집 학부모 상담을 진행하였습니다. </p>
<p>집에서 처럼 어린이집에서도 밝고 씩씩한 모습을 많이 보여준다며 칭찬을 많이 해 주셨습니다. </p>
<p>앞으로도 지금처럼 즐거운 어린이집 생활을 잘 이어갈 수 있도록 지원하겠습니다. ^^*</p>
<p><br /></p>          </td>
        </tr>',1197,1555945200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20961,'dus3','한자혜','','룻방 장*아, 지율 아동 어린이집 학부모 상담을 하였습니다.','<p>아동들의 어린이집 생활을 알고 아동들이 더 건강하고 밝게 자랄 수 있도록 </p>
<p>어린이집 선생님과 지도 방법에 대해 논의 하였습니다. </p>
<p>아동들이 몸과 마음이 건강하게 잘 자랄 수 있도록 계속해서 지원하겠습니다. </p>          </td>
        </tr>',1004,1555945200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20963,'dus3','신미지','mijishin@hanmail.net','4월 22일 박*수 아동 언어치료 진행하였습니다.','<p>4월 22일 박*수 아동 언어치료 진행하였습니.</p>
<p>&nbsp;- 장소: 신당종합사회복지관</p>
<p>&nbsp;- 시간: 17:00~17:50</p>          </td>
        </tr>',981,1555945200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20959,'dus3','이혜원','','박*빈, 박*주 아동 어린이집 상반기 상담을 하였습니다.','<p>아동들의 어린이집 생활을 알고 아동들이 더 건강하고 밝게 자랄 수 있도록 </p>
<p>어린이집 선생님과 지도 방법에 대해 논의 하였습니다. </p>
<p>아동들이 몸과 마음이 건강하게 잘 자랄 수 있도록 계속해서 지원하겠습니다. </p>          </td>
        </tr>',996,1555945200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20956,'dus3','김도연','311279_@hanmail.net','한나방 박*리, 연*빈 아동이 초등학교 체험활동으로 두물머리 생태학교를 다녀왔습니다.(19.04.22)','<p>한나방 귀염둥이 막내 박*리, 연*빈 아동이 초등학교에 입학하여 처음으로 </p>
<p>체험활동을 다녀왔습니다. 가기 전부터 기대가 대단하여 달력을 보며 얼마 만큼 </p>
<p>남았는지를 자꾸 헤아리며 같은 말을 하고 또 하였습니다. 드디어 체험활동을 가는</p>
<p>당일, 개나리 같기도 하고 병아리 같은 학급 반티를 입고 두물머리 애벌레 상태학교를 </p>
<p>다녀왔습니다. *리는 조금 더 키우기 쉬운 허브 화분을 골라서 왔고, *빈이는 호기심 </p>
<p>대장이라 장수풍뎅이가 될 애벌레를 데리고 왔습니다. 먹이가 정확히 어떤 것인지도</p>
<p>모르면서, 또 애벌레가 든 유리병의 뚜껑을 열지 못해 계속 다른 사람에게 열어 달라고</p>
<p>하면서 받아왔습니다. ㅠ.ㅠ (왜, 이런 시련을...)그래도 저희집에 온 아이들이니 열심히</p>
<p>막내 친구들과 함께 열심히 키워보려고 합니다. 이제 먹이와 뚜껑 열기는 *빈이에 일임하려</p>
<p>합니다. 본인이 받아왔으니 책임을 져야지요. 아이들이 즐거웠다고 하니 기쁩니다만 뒷일이</p>
<p>걱정이라, 나중에 많이 자란 새 친구들의 소식도 알려드릴 수 있게 되었으면 좋겠습니다.</p>
<p>아이들이 건강한 학교 생활을 할 수 있도록 앞으로도&nbsp;응원하고 지원하도록 노력하겠습니다.</p>          </td>
        </tr>',1039,1555945200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20958,'dus3','심주현','pikaccu85@hanmail.net','바울방 남산초등학교 아동들 양평 두물머리 체험장 현장학습 다녀왔습니다.','<p>바울방&nbsp;장*울, 박*수,&nbsp;박*호 아동이&nbsp;초등학교에 입학하여 처음으로 현장학습을 다녀왔습니다. </p>
<p>양평 두물머리 체험장을 다녀왔는데요 </p>
<p>가서 토끼도 안아보고 새싹키우기 화분도 가져오는 등 오늘활동이 매우 재미있었다고 합니다. </p>
<p>그리고 학교에서 나눠 준 노란색 학급티셔츠도 매우 좋아하였답니다. ^^</p>
<p>아침에 싸준 도시락 통을 꺼내며 다 먹었다고 말해주는 아이들에게서 뿌듯함을 느꼈습니다. ^O^/</p>
<p>앞으로도 아이들이&nbsp;즐거운 학교 생활을 할 수 있도록 최선을 다해 지원하겠습니다. </p>          </td>
        </tr>',1083,1555945200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20954,'dus3','최호성','naomi1318@naver.com','다윗방 우*운 아동이 환일중학교 촛불예배에 참여하였습니다. (2019.04.22)','<p><br /></p>
<p>2019년 04월 22일 다윗방 우*운 아동이 환일중학교에서 부활절을 맞이하여 촛불예배에 참여하였습니다</p>
<p><br /></p>          </td>
        </tr>',1017,1555858800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20953,'dus3','최호성','naomi1318@naver.com','다윗방 배*욱 아동이 남산초 현장체험학습을 다녀왔습니다. (2019.04.22)','<p>다윗방 배*욱 아동이 남산초 1,2학년 대상으로 진행된&nbsp;현장체험학습을 다녀왔습니다.</p>
