INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20734,'dus3','김형식','jazzer80@naver.com','다윗방 배*욱, 박*호, 이*민 남산초 공개 수업 참여','<p>금일 남산초등학교에서 공개 수업이 있어 참여하고 왔습니다.</p>
<p>다윗방 배*욱, 박*호, 이*민 아동의 수업을 참관하고 왔는데요</p>
<p>평소 아동들이 학교에서 어떻게 생활하고 있는지에 대해 알 수 있었고,</p>
<p>공개수업을 마친 후 담임선생님과 짧게나마 대화도 나눌 수 있었습니다.</p>
<p>신학기의 시작은 그 어느 때보다 중요한데,</p>
<p>아동들이 잘 적응하고 좋은 교우 관계 맺으며 학교생활 할 수 있도록 지원하겠습니다.</p>
<p><br /></p>          </td>
        </tr>',963,1553007600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20739,'dus3','김혜숙','rhdnsdd2@naver.com','바울방 초등학생 학부모 공개수업에 참여하였습니다.','<p>바울방 박*훈, 박*호, 장*울, 박*수아동의 초등학교 공개수업에 참여하였습니다.</p>
<p>우리 아이들이 수업시간에 잘 참여하고 </p>
<p>친구들과도 즐겁게 생활하는 모습이 대견합니다^^</p>
<p><br /></p>
<p>더욱 즐거운 학교 생활을 할 수 있도록 성심껏 지원하겠습니다.</p>
<p>함께 해주신 선생님들께 감사드립니다.</p>
<p><br /></p>
<p></p>          </td>
        </tr>',1011,1553007600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20735,'dus3','배소연','cometrue22@naver.com','한나방 박*리, 연*빈, 왕*젤, 김*경 아동 초등학교 공개수업 참여','<p>한나방 박*리, 연*빈, 왕*젤, 김*경아동의 초등학교 공개수업에 참여하였습니다.</p>
<p>아동들이 수업에 집중하며 발표에 열심히 참여하는 모습이 참 대견스러웠습니다.</p>
<p>각자 아동들이 교실에서 어떻게 생활하며 지내는지 살펴볼 수 있는 기회였습니다.</p>
<p>아동들이 학교생활을 즐겁게 할 수 있도록 지원하겠습니다.</p>
<p>함께 참여해주신 선생님들께 감사드립니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1048,1553007600,'', '', '', '', '', '');
