INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20630,'dus3','최호성','naomi1318@naver.com','다윗방 고*민 아동이 성동공고 3학년 회장으로 임명되었습니다. (2019.03.07)','<p>다윗방&nbsp;고*민 아동이 성동공고 3학년 회장으로 임명되었습니다.</p>
<p>늘 재치있는 입담과 부드러운 말투로 학급 내에서도 인기가 좋았습니다.</p>
<p>이제 학급의 리더가 된 만큼 더 모범적인 모습을 보이도록 지도하겠습니다.<br /><br />많은 칭찬과 격려 부탁드립니다. </p>          </td>
        </tr>',973,1551884400,'', '', '', '', '', '');
