INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20614,'dus3','유미정','3alwjd@hanmail.net','솔로몬B방 소*지, 김*빈 아동이 어린이집 입학하였습니다.','<p>솔로몬B방 소*지, 김*빈 아동이&nbsp;오늘 어린이집에 입학하였습니다.&nbsp;</p>
<p>첫날이라 오전만&nbsp;참여하고 귀가하였답니다. </p>
<p>무엇을 했는지 물으니&nbsp;장난감 놀이도 하고 재미있었다며</p>
<p>처음 만난 친구들 이름을 알려주기도 하면서&nbsp;내일도 가겠다며 즐거워하는 모습을 보였습니다. </p>
<p>건강하고 씩씩하게 잘 자랄 수 있도록&nbsp;하겠습니다. &nbsp;</p>
<p><br /></p>          </td>
        </tr>',949,1551625200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20609,'dus3','김혜숙','rhdnsdd2@naver.com','바울방 박*호, 장*울, 박*수 아동이 남산초등학교에 입학하였습니다','오늘 오전 바울방 박*호, 장*울, 박*수 아동이 남산초등학교에 입학하였습니다~~~<br />긴장된 모습으로 교실 앞에서 머뭇거리는 모습이더니 <br />어느새 옆에 앉은 친구와 이야기도 나누고 웃기도 하네요^^<br />입학식을 마치고 중식당에서 점심도 맛나게 먹고 들어왔습니다.<br />내일부터 학교 급식도 먹고 방과 후 수업도 참여합니다.<br />우리 아이들이 씩씩하게 학교에 적응할 수 있도록 많이 응원해주세요~~<br />저희들도 즐거운 학교 생활을 위해 최선을 다해 지원하겠습니다.<br />이렇게 잘 크도록 사랑과 관심을 보내 주셔서 감사합니다^^          </td>
        </tr>',927,1551625200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20606,'dus3','이혜원','','룻 방 박*음, 지* 아동이 어린이집 입학을 하였습니다.','<p>룻 방 박*음, 지* 아동이 어린이집 입학을 하였습니다. <br /><br />설레는 얼굴로 가방과 준비물을 가지고 어린이집 입학을 하였습니다. </p>
<p>입학식이 끝나고는 즐거운 얼굴로 교사에게 어린이집에 다녀온 일, 선생님을 만난 일에 대해 재잘 재잘 이야기도 해주는 모습이었습니다. </p>
<p>앞으로도 밝은 모습으로 어린이집에 등원할 수 있도록 잘 지원하겠습니다. </p>          </td>
        </tr>',968,1551625200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20604,'dus3','최호성','naomi1318@naver.com','다윗방 곽*민 아동이 성동공고에 입학하였습니다. (2019.03.04)','다윗방 곽*민 아동이 성동공업고등학교에 입학하였습니다. <br /><br />아동이 새로운 환경에서 잘 적응하고 즐거운 고등학교 생활이 될수 있도록 지도하겠습니다.           </td>
        </tr>',983,1551625200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20586,'dus3','김도연','311279_@hanmail.net','한나방 아동들이 새 진급학교 오리엔테이션에 다녀왔습니다. (19.02.11~19.02.19)','<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">한나방 김</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">*</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">연 아동이 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">2</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">월 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">11</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일 보성여자고등학교로 오리엔테이션을 다녀왔습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">. </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">학교에 가서 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">(</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">수준별 수업을 위한</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">) </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">영어</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">, </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">수학 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">TEST, </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">교과서를 받아왔습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">박</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">*</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">민 아동은 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">2</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">월 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">15</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">, 2</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">월 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">18</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">2</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일간 성심여자고등학교로 신입생적응교육을 다녀왔습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">. 1</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일차에는 평화교육을 받았고 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">2</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일차에는 담임선생님에 대한 소개</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">, </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">학교규칙과 복장규정 안내</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">, </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">동아리 활동안내</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">, </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">학교생활 공안안내</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">, </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">교가 배우기 및 입학식 연습 등을 했다고 합니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">김</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">*</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">민 아동은 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">2</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">월 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">19</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일 덕수중학교로 오리엔테이션을 다녀왔습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">. </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">아동이 제일 마지막으로 다녀왔으며 인성</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">, </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">적성검사와 교과서 배부</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">, </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">교가와 입학식 예행연습을 하고 왔습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">  &nbsp;  <o:p></o:p></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">오리엔테이션을 통해서 학교 가는 길을 한 번 더 확인하고 학교 교가를 익히는 시간을 갖게 되었습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">한나방 아동들에게 아직은 새로운 것 투성인 학교겠지만 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">3</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">년을 보내며 점차 정도 들고 새로운 친구들도 많이 사귈 수 있게 되기를 기대해봅니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">. </span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">옆에서 잘 적응할 수 있도록 아동들을 응원하고 지원하겠습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.</span></p>          </td>
        </tr>',1011,1551366000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20585,'dus3','김도연','311279_@hanmail.net','한나방 큰 언니 김*선 아동이 대학교에 입학하였습니다. (19.02.21)','<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">한나방의 큰 언니이자 대들보인 김</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">*</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">선 아동이 대학교에서 입학식을 가졌습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">  &nbsp;  <o:p></o:p></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">학과 학생들이 많아 장소가 두 군데로 나눠져서 입학식이 이루어졌다고 합니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">  &nbsp;  <o:p></o:p></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">입학식 후에는 학점관리 하는 방법</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">, </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">수강신청 방법 등 대학 생활에 있어 기본적인</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">  &nbsp;  <o:p></o:p></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">정보를 나누는 시간을 가졌습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">. 2</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">월</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">25</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일부터 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">2</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">월 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">28</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일까지 교양수업을 수강신청</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">  &nbsp;  <o:p></o:p></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">하는 기간이라 하던데 잘 될 수 있을지 걱정이 되기도 합니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">. </span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">  &nbsp;  <o:p></o:p></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">새로운 시작을 하는 아동이 잘 적응할 수 있도록 옆에서 응원하고 지원하겠습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.</span></p>          </td>
        </tr>',993,1551366000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20584,'dus3','김도연','311279_@hanmail.net','한나방 김*선, 김*희 아동이 고등학교를 졸업하였습니다. (19.02.15)','<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">한나방 맏언니 라인의 김</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">*</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">선 아동</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">(19.01.04 </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">졸업</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">)</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">과 김</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">*</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">희 아동</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">(19.02.15 </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">졸업</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">)</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">이 각각&nbsp;<o:p></o:p></span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">고등학교를 졸업하였습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.&nbsp;&nbsp; <o:p></o:p></span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">김</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">*</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">선 아동은 대학교 입학을 기다리며 운전면허 자격증 취득을 위해 노력하고 있습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">. </span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">2</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">월 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">20</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일까지 장내기능시험을 합격하였고 현재는 도로주행 운전연습 일정을 기다리는 중입니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">. </span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">김</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">*</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">희 아동은 취득한 자격증으로 병원에 취업하여 독립 및 퇴소를 준비하고 있습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">두 아동들이 어엿한 사회인이 될 수 있도록 아직 가야할 길이 멀기는 하지만 각자의 자리에서</span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">열심히 하고 있는 만큼 앞으로의 모습이 더 기대됩니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">. </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">두 아동들의 앞날을 응원합니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.&nbsp;&nbsp; <o:p></o:p></span></p>          </td>
        </tr>',963,1551366000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20583,'dus3','김도연','311279_@hanmail.net','한나방 김*민 아동이 남산초등학교를 졸업하였습니다.(19.02.15)','<p>남산원의 초등학생 중 제일 큰 언니이자 누나인 한나방 김*민 아동이 </p>
<p>지난 2월 15일 남산초등학교를 졸업하였습니다. 아동의 뒤를 이를 제일 큰 </p>
<p>6학년 아동은 없고 5학년이 되는 친구들 2명만 있게 되어 조금 아쉽기도 </p>
<p>합니다. 의젓하고 동생들을 잘 챙겨준 아동 덕분에 많은 도움이 되었는데</p>
<p>말이죠. 동생들보다도 제가 더 아쉬울지도 모르겠습니다.</p>
<p>중학교에 가서도 잘 생활하리라고 생각합니다.&nbsp;새로운 학교에 가는 아동이</p>
<p>잘 적응할 수 있기를 함께 응원해주세요. 아동이 건강하고 바르게 자랄 수 </p>
<p>있도록 지원하겠습니다.</p>
<p><br /></p>          </td>
        </tr>',942,1551366000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20582,'dus3','김도연','311279_@hanmail.net','한나방 덕수중학교 김*연, 박*민 아동이 졸업하였습니다. (19.02.01)','<p>한나방 중학교 3학년 언니들인 김*연, 박*민 아동들이 지난 2월 1일 </p>
<p>덕수중학교에서 졸업을 하였습니다. 졸업식을 일찍 하여 다른 아이들에</p>
<p>비하여 봄방학을 일찍 시작하게 되었습니다. 방학동안에 고등학교에 갈</p>
<p>준비를 열심히 하며, 규칙적인 생활을 할 수 있도록 지원하겠습니다.</p>
<p>고등학교라는 새로운 세상에 도전하는 김*연, 박*민 아동을 함께 응원해주세요.</p>          </td>
        </tr>',1009,1551366000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20581,'dus3','김도연','311279_@hanmail.net','한나방 연*빈 아동이 을지어린이집을 졸업하였습니다. (19.02.15)','<p>한나방 연*빈 아동이 지난 2월 15일에 을지어린이집을 졸업하였습니다.</p>
<p>어린이집 과정을 마치고 초등학교 입학을 앞두고 있습니다.</p>
<p>새로운 친구들과 선생님을 만날 생각에 들뜨기도 하고 걱정을 한 가득하기도</p>
<p>합니다. 연*빈 아동이 어린이집에서 열심히 생활했던 것 처럼 초등학교에서도</p>
<p>잘 지낼 수 있도록 옆에서 응원하고 보살피겠습니다.</p>
<p>그동안 아동에게 지속적인 관심과 사랑으로&nbsp;애써주신 을지어린이집 선생님들과</p>
<p>남산원 원장님을 비롯한 모든 분들께 감사드립니다^^</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',992,1551366000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20571,'dus3','이혜원','','박*주, 장*아, 박*빈 아동이 어린이집에서 수료식을 하였습니다.','<p>박*주, 장*아, 박*빈 아동이 어린이집에서 수료식을 하였습니다. </p>
<p>아동들이 열심히 노력하여 받은 상장과 선물들도 많이 받아왔는데 아동들이 상을 자랑하며 매우 즐거워하는 모습이었습니다. </p>
<p>열심히 노력한 결과물에 대해 격려 해주고 칭찬을 많이 해주었습니다. </p>
<p>앞으로도 어린이집 생활 잘 할 수 있도록 지원하겠습니다 ^^</p>          </td>
        </tr>',1004,1551193200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20541,'dus3','김혜숙','rhdnsdd2@naver.com','박*리, 박*호 아동이 어린이집을 졸업하였습니다(2019.02.22)','<p>한나방 박*리, 바울방 박*호 아동이 어린이집을 졸업하였습니다.</p>
<p>헤어지는게 아쉬운지 눈물을 글썽이며 울음을 꾹 참는 모습이 사랑스럽습니다. </p>
<p>졸업식이 끝나고 햄버거세트도 먹고~~ 망고빙수도 맛보고~~</p>
<p>즐겁고 행복한 시간을 보냈습니다</p>
<p>초등학교에 들어갈 준비도 잘 지원하여 행복한 학교생활이 되도록 함께 하겠습니다^^</p>
<p><br /></p>          </td>
        </tr>',934,1550847600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20522,'dus3','김혜숙','rhdnsdd2@naver.com','바울방 박*수 아동이 어린이집을 졸업하였습니다~~','<p>박*수 아동이 어린이집 졸업을 하였습니다.</p>
<p>졸업가운을 입고 의젓하게 앉아있는 *수의 모습이 무척이나 대견스러웠습니다^^</p>
<p>"우와, 오늘 내가 주인공이다~~" 외치며 콩콩 뛰어다니더니</p>
<p>짜장면과 탕수육이 나오자 교사와 같이 축하해주러 간 형들에게 </p>
<p>먼저 먹으라고 권해주는 따뜻한 마음을 가진 우리 *수^^</p>
<p>초등학교에 들어갈 준비도 잘 지원하여 행복한 학교생활이 되도록 함께 하겠습니다^^</p>          </td>
        </tr>',982,1550588400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20535,'dus3','심주현','pikaccu85@hanmail.net','신한은행 후원자님께 새학기 학용품 후원을 받았습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'1902220656083_1.jpg\');><img src=\'/admin/data/bbs/dus3/M1902220656083_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
