INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20485,'dus3','심주현','pikaccu85@hanmail.net','바울방 장*울 아동 을지 어린이집 졸업하였습니다.','<p>오늘 바울방 장*울 아동 을지 어린이집 졸업을 하였습니다. </p>
<p>엊그제 어린이집을 간 것 같은데 어느새 늠름하게 자라 어린이집 졸업식을 하는 모습을 보니 </p>
<p>뭉클 하였습니다. 동생들에게&nbsp; 7세 대표로 답사를 하는 모습또한 너무 멋있었답니다. </p>
<p>졸업식 후 점심시간에는 부모님들이 직접 마련해 준 음식으로 뷔페 식사를 하였습니다. </p>
<p>원장님 및 선생님들과 함께 식사 하며 1년 동안의 생활을 함께 나눠보는 시간을 가졌다고 합니다. </p>
<p>*울이와 같이 식사를 하지 못해 아쉬웠으나 어린이집 선생님들, 동생, 같이 졸업하는 친구들과 함께 식사 하는 시간이 더욱 </p>
<p>뜻깊었을 거라 생각됩니다. (맛있는 식사는 다음에 하는 걸로 ^^)</p>
<p>*울아~ 어린이집 졸업을 축하해!!! (&gt;.&lt;)</p>
<p>*울이가 멋지고 씩씩한 초등학생이 될 수 있도록 최선을 다해 지원 하겠습니다. </p>          </td>
        </tr>',1046,1550156400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20536,'dus3','심주현','pikaccu85@hanmail.net','NHN wetoo 님 께서 새학기 학용품을 후원해 주셨습니다.','<div align=\'LEFT\'><a href=javascript:viewImg(\'1902220706215_1.jpg\');><img src=\'/admin/data/bbs/dus3/M1902220706215_1.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
