INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20438,'dus3','최호성','naomi1318@naver.com','다윗방 이*민 아동이 남산초 개별반에서 롯데월드를 다녀왔습니다. (2019.02.07)','<p>다윗방 이*민 아동이 남산초 개별반에서 롯데월드를&nbsp;다녀왔습니다. </p>
<p>맛있는것도 많이 먹고, 놀이기구도 타며 다양한 체험을 즐기고 왔습니다.</p>
<p>이*민 아동이 즐거운 학교생활을 할 수 있도록 열심히 지원하겠습니다. </p>          </td>
        </tr>',953,1549465200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20374,'dus3','김도연','311279_@hanmail.net','한나방 아동들이 다니는 남산초등학교, 덕수중학교가 개학을 하였습니다.(19.01.28)','<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">한나방 초등학생들이 다니는 남산초등학교</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">, </span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">중학생들이 다니는 덕수중학교가&nbsp;<o:p></o:p></span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">모두 같은 날인 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">1</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">월 </span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">28</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">일</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">(</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">월요일</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">)</span><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">에 개학을 하였습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.&nbsp;<o:p></o:p></span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">겨울방학 시작이 얼마되지 않은 것 같은데 어느새 개학날이 다가왔습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.&nbsp;<o:p></o:p></span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">아이들은 그것이 싫기도 하면서도 또 오랜만에 친구들과 선생님을 만날 수&nbsp;&nbsp;<o:p></o:p></span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">있다는 점에서 기대되기도 하는 모습을 보였습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.&nbsp;<o:p></o:p></span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">종업식과 졸업식때까지 다시 열심히 다니고 있겠지요</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.&nbsp;<o:p></o:p></span></p>
<p class="0" style="mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="font-family: 함초롬바탕; mso-fareast-font-family: 함초롬바탕">남은 학교 생활도 잘 할 수 있도록 옆에서 지원하겠습니다</span><span lang="EN-US" style="letter-spacing: 0pt; mso-fareast-font-family: 함초롬바탕; mso-font-width: 100%; mso-text-raise: 0pt">.</span></p>          </td>
        </tr>',993,1548687600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20340,'dus3','김도연','311279_@hanmail.net','한나방 연*빈 아동이 을지어린이집에서 디키디키 놀이터로 체험활동을 다녀왔습니다.(19.01.22)','<p>한나방 연*빈 아동이 1월 22일 (화) 을지어린이집에서 </p>
<p>동대문 DDP에 있는 디키디키 놀이터로 체험활동을 다녀왔습니다.</p>
<p>블럭을 가지고 놀기도 하고, 놀이터에서 엄마,아빠 역할놀이도 하고</p>
<p>놀이터에 있는 침대처럼&nbsp;생긴 공간에서 잠깐 쉬어보기도 해서 </p>
<p>무척 재미있었다고 합니다. 체험활동 덕분에 오늘의 점심식사가 더욱 </p>
<p>맛있었다고 말합니다. </p>
<p>아동이 좋아하는 활동을 마음껏하며&nbsp; 어린이집, 학교 및 원내생활을 열심히</p>
<p>할 수 있도록 옆에서 지원하겠습니다. 함께 응원해주세요.</p>
<p><br /></p>          </td>
        </tr>',1096,1548169200,'', '', '', '', '', '');
