INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20209,'dus3','유미정','3alwjd@hanmail.net','솔로몬B방 박*민, 박*윤 아동이 어린이집 작은음악회 공연에 참여했습니다^^','<p>박*민, 박*윤 아동이 그동안 어린이집에서 열심히 연습하며 준비했던</p>
<p>작은음악회 무대에 올랐답니다. </p>
<p>의상을 갈아입으며 악기 연주도 하고, 노래도 하고, 춤도 추면서 아주 신나게 공연을 하였답니다. </p>
<p>많은 사람들이 바라보는 무대에 서서 공연을 하는 것이 많이 떨릴법도 한데</p>
<p>우리 아이들의 목소리가 아주 우렁찹니다. </p>
<p>열심히 연습하고 무대에서도 신나게 즐길 줄 아는 두 아동에게 사랑의 박수를 보냅니다.^^</p>          </td>
        </tr>',976,1545922800,'', '', '', '', '', '');
