INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20206,'dus3','김혜숙','rhdnsdd2@naver.com','바울방 장*울, 박*성 아동이 어린이집 작은음악회를 했습니다','<p>우리 *울이, *성이가 오랜 시간 연습한 율동과 노래를&nbsp;</p>
<p>많은 사람들 앞에서 발표하는 시간을 가졌습니다.&nbsp;</p>
<p>멋진 옷을 차려입고 신나게 몸을 흔들며 </p>
<p>멋진 모습을 보여준 우리 아이들</p>
<p>너무 대견합니다~~</p>
<p>앞으로도 어린이집에서 즐겁게 활동할 수 있도록 </p>
<p>열심히 지원하겠습니다.</p>          </td>
        </tr>',995,1545836400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20205,'dus3','한자혜','','룻방 연*빈 아동이 어린이집 작은 음악회에 참석 하였습니다.','<p>룻방 연*빈 아동이 어린이집에서 하는 작은 음악회에&nbsp;참석을 하였습니다. </p>
<p><br /></p>
<p>인사말을 맡아 예쁜 드레스를 입고 무대에서서 씩씩하게 음악회의&nbsp;시작을 알렸습니다. </p>
<p><br /></p>
<p>또한 어린이집 친구들과 합을 이루며&nbsp;율동도&nbsp;멋지게 소화했습니다.</p>
<p><br /></p>
<p>아동은 웃어며 오늘 하루 바쁘게 시간이 갔다고 말하며 아동에게 보람찬&nbsp;시간 되었던 것 같습니다. </p>          </td>
        </tr>',1039,1545836400,'', '', '', '', '', '');
