INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20203,'dus3','최호성','naomi1318@naver.com','다윗방 환일중 곽*민 아동이 2박 3일로 스키캠프를 다녀옵니다. (2018.12.27)','<p>다윗방 환일중 3학년&nbsp;곽*민 아동이 2박 3일로 스키캠프를 다녀옵니다</p>
<p>아동들이 무사히 다녀와서 앞으로도 씩씩하게 지낼 수 있도록 지도하겠습니다. </p>          </td>
        </tr>',971,1545836400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20201,'dus3','김도연','311279_@hanmail.net','한나방 김*경 아동이 학교(방과후수업)에서 체험학습을 다녀왔습니다.(18.12.26)','<p>한나방 김*경 아동이 덕수중학교에서 마지막
방과후수업 수업으로 </p>
<p>세종요리학원을 방문하여
스파게티와 샌드위치를 만들어 보는 체험활동을 하였습니다. </p>
<p>오후에는 극장을 가서&nbsp; 영화&nbsp; \'그린츠\'를 관람하였다고 합니다.&nbsp;</p>
<p>직접 요리학원을 가서&nbsp; 음식을 만들다보니 도구가 많이 있어서 신기하기도 하고 </p>
<div>즐거웠다고 합니다.&nbsp;2학기 동안 열심히 방과후수업에 참여한 김*경 아동을</div>
<div>칭찬하며, 앞으로도 학교생활에 충실할 수 있도록 돕겠습니다.</div>
<div><br /></div>          </td>
        </tr>',964,1545836400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20198,'dus3','김형식','jazzer80@naver.com','다윗방 김*현, 고*민 아동 체험학습 참여','<p>다윗방 김*현, 고*민 아동이 학교 군 특성화 반&nbsp;활동과 관련하여&nbsp;가평 스타밸리로 체험학습을 갔습니다.</p>
<p>오리엔테이션 및 제식훈련, 제복 사이즈 측정 등의 일정 등이 있는데</p>
<p>1박2일의 짧은 일정이지만 안전하게 다녀오도록 만반의 준비를 마쳐서 보냈습니다.</p>
<p>군 특성화에 대한 자부심이 대단한 아동들인데 더 적극적인 활동과 참여를 통해</p>
<p>자신들의 진로를 확고하게 다져 나갈 수 있도록 지원을 아끼지 않겠습니다.</p>
<p><br /></p>          </td>
        </tr>',960,1545750000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20152,'dus3','한자혜','','룻방 아이들이 어린이집에서 가족그림편지쓰기대회에서 나눔가족상장을 받아왔습니다.','<p>룻방 박*리, 박*주, 박*빈, 장*아 아동이&nbsp;어린이집에서 </p>
<p><br /></p>
<p>굿네이버스가 주최하는 제7회 가족그림편지쓰기대회에서 나눔가족상장을 받아왔습니다.</p>
<p><br /></p>
<p>아이들이 나눔을 배우는 시간이 되었길 바랍니다.</p>          </td>
        </tr>',1010,1545318000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20149,'dus3','한자혜','','룻방 박*주, 박*빈, 장*아 아동이 어린이집에서 산타잔치에 참여하였습니다.','<p>룻방 박*주, 박*빈, 장*아 아동이 어린이집에서 주최하는 산타잔치에 참여하였습니다. </p>
<p><br /></p>
<p>아이들에게 즐거운 시간을 선물해 주신 선생님들께 너무나도 감사드립니다. </p>          </td>
        </tr>',928,1545318000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20146,'dus3','이혜원','','룻방 박*서 아동 어린이집 성탄절행사 및 학부모참여 수업을 하였습니다.','<p>룻방 박*서 아동이 어린이집에서 성탄절행사 및 학부모참여수업을 하였습니다.</p>
<p>산타할아버지를 만나서 선물도 받고,</p>
<p>생크림을 발라 케이크도 만들어 꾸며보고,</p>
<p>신나는 레크레이션도 함께 했습니다^^</p>
<p>집에 와서는 언니들에게 만든 케이크도 나누어 주고 맛있게 먹어보았습니다. <br /></p>
<p>앞으로도 어린이집에서 즐겁게 생활할 수 있도록 정성껏 지원하겠습니다.</p>          </td>
        </tr>',1058,1545318000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20144,'dus3','서보현','qkgkaks1@hanmail.net','솔로몬 B방 박*태, 박*랑 아동 어린이집 산타행사 있었습니다(2018.12.20)','<p>솔로몬 B방 박*태, 박*랑 아동 어린이집에서 산타행사 있었습니다</p>
<p>각 A,B C팀으로 나뉘어 행사진행이 되었고 우리 방 아가들은 A팀이었습니다</p>
<p>1부에는 산타할아버지로 부터 호명받아 선물을 받았으며</p>
<p>엄마와 함께 미니 크리스마스 케잌 만들기를 하였고</p>
<p>레크레이션 시간도 가졌습니다</p>
<p>마지막으로 가장 중요한 아가들의 발표회가 있었습니다.</p>
<p>무대 앞 다른 친구들과 함께 서서 &nbsp;짧지 않은 곡에 맞추어 노래를 부르고 율동을 하였고</p>
<p>멋지고 대견하게&nbsp;잘 마쳤습니다.</p>
<p><br /></p>          </td>
        </tr>',1071,1545318000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20142,'dus3','김혜숙','rhdnsdd2@naver.com','바울방 박*진, 박*수 아동 어린이집 성탄행사 및 부모참여수업','<p>바울방 박*진, 박*수 아동이 어린이집에서 성탄절행사 및 학부모참여수업을 하였습니다.</p>
<p>산타할아버지를 만나서 선물도 받고,</p>
<p>생크림을 발라 케이크도 만들어 꾸며보고,</p>
<p>신나는 레크레이션도 함께 했습니다^^</p>
<p><br /></p>
<p>2부에는 열심히 연습한 노래와 수화를 보여주더니&nbsp;오카리나연주까지!!</p>
<p>초롱초롱한 눈으로 틀리지 않으려고 집중하는 모습이 대견했습니다~~</p>
<p><br /></p>
<p>어린이집에서 즐겁게 생활할 수 있도록 정성껏 지원하겠습니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',998,1545231600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20132,'dus3','유미정','3alwjd@hanmail.net','솔로몬B방 박*민, 박*윤 아동이 어린이집에서 건강체험관을 다녀왔습니다.','<p>어린이집에서 도담도담어린이건강체험관에서 &lt;금연교육&gt;을 하고 왔답니다. </p>
<p>금연에 대한 공부도 하고 금연송도 배웠다고 합니다. </p>
<p>저녁을 먹은 후에 "배는 싫어요~"라며 노래를 부르며 율동을 하면서 </p>
<p>배운 것을 동생들에게 알려주는 기특한 모습을 보였습니다. </p>          </td>
        </tr>',942,1545058800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20129,'dus3','최호성','naomi1318@naver.com','다윗방 성동공고 2학년 김*현 아동이 봉사상을 받았습니다. (2018.12.17)','<p>성동공고에&nbsp;재학 중인 다윗방 김*현 아동이 학교에서&nbsp;봉사상 표창장 수여 받았습니다.</p>
<p>앞으로도 올바른 봉사정신을 갖으면서 생활하도록 지도하겠습니다. </p>          </td>
        </tr>',909,1544972400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20110,'dus3','김도연','311279_@hanmail.net','한나방 중학교 2학년 김*경, 손*영 아동이 기말고사를 마쳤습니다.','<p>한나방 덕수중학교 2학년 김*경, 손*영 아동이&nbsp;</p>
<p>2학년 생활의 마지막 기말고사를 무사히 마쳤습니다. </p>
