INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20096,'dus3','한자혜','','룻방 박*리 아동이 어린이집에서 마켓데이 수익금을 기부하였습니다.','<p>어린이집에서 열린 마켓데이 행사 수익금을 박*리 아동과 함께 </p>
<p><br />오늘 중구청 광장에서 열린 따뜻한 겨울나기  이웃돕기행사에 전달 하였다고 합니다.<br />&nbsp;<br />아이들과 선생님들의 예쁜 마음이&nbsp;불우한 이웃에게 전달되어 따뜻한 겨울을 보낼수 있길 바랍니다. </p>          </td>
        </tr>',914,1544540400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20097,'dus3','한자혜','','룻방 연*빈 아동이 어린이집에서 튼튼 스쿨 체험활동을 하였습니다.','<p>룻방 연*빈 아동이 어린이집에서 신중부시장으로 튼튼스쿨 체험활동을 하였습니다. &nbsp; </p>
<p><br /></p>
<p>식재료의 영양에 대해 배우고, 식재료를 구매하고, 식재료를 이용한 만들기를 하며 오감 체험을 하고 왔습니다.</p>
<p>&nbsp;</p>
<p>아동은 다양한 음식과 요리에 들어갈 재료를 사와 친구들에게 자랑하였습니다. </p>
<p><br /></p>
<p>음식에 대해 같이 이야기 나누며 먹을 수 있는 것은 같이 먹었습니다. </p>          </td>
        </tr>',967,1544540400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20095,'dus3','김도연','311279_@hanmail.net','한나방 중학교 3학년 김*연, 박*민 아동이 학교 체험활동을 다녀왔습니다.','<p>한나방 덕수중학교 3학년 김*연, 박*민 아동이 1, 2학년의 기말고사 기간 동안</p>
<p>학교 체험활동으로 여러 가지 문화체험을 하고 있습니다.</p>
<p>그 시작으로 12월 12일에는 광화문에 있는 대한민국역사박물관을 관람하고</p>
<p>왔습니다. 12월 13일에는 명동난타극장에서 난타공연 관람, 12월 14일에는 </p>
<p>혜화역에서 넌센스 공연관람을 할 예정입니다. </p>
<p>아이들이 친구들과 함께 교과 외 다양한 문화체험 활동을 통해 여러 가지를 </p>
<p>보고 느끼며 경험하고, 친구와의 즐거운 추억을 쌓는&nbsp;시간이 되기를 바랍니다.</p>
<p>앞으로도 아동들이 학교 생활을 즐겁게 할 수 있도록 돕고 원내 생활에서도 </p>
<p>바른 생활을 이어 갈 수 있도록 협력하겠습니다.</p>          </td>
        </tr>',940,1544540400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20094,'dus3','김도연','311279_@hanmail.net','한나방 중학교 2학년 김*경, 손*영 아동 기말고사 시험이 시작되었습니다.','<p>한나방 덕수중학교 2학년 김*경, 손*영 아동이</p>
<p>2018년 12월 12일(수) 부터 3일간 기말고사에 들어갑니다.</p>
<p>아동들에게 2학년 생활의 마지막 학교시험인 만큼 좋은 결과가 있길 바랍니다.</p>          </td>
        </tr>',940,1544540400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20090,'dus3','배소연','cometrue22@naver.com','한나방 김*연아동 장학증서 받았습니다.','<p>한나방 김*연아동이 중구인재육성장학재단에서 수여하는 장학금을 받습니다.</p>
<p>중학교를 졸업하고 고등학교에 진학하는 시기가 된 만큼</p>
<p>아동이 앞으로도 바른생활을 이어가고 학업증진에 힘쓸 수 있도록 </p>
<p>지원하겠습니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',904,1544454000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20068,'dus3','한자혜','','룻방 박*리, 박*주, 장*아, 박*빈 아동이 마켓데이 어린이집행사에 참여하였습니다.','<p>룻방 박*리, 박*주, 장*아, 박*빈 아동이 어린이집에서 마켓데이날 행사에 참여하였습니다.</p>
<p><br /></p>
<p>아이들이 직접 만든 것과 생활속에서 필요한 물건들, 먹거리를 준비하여 서로 팔고 사는 활동을 하였습니다. </p>
<p><br /></p>
<p>이날의 수익금은 불우이웃 돕기 성금으로 기부하여 아이들이 기분좋은 마음으로 여러 물품을 샀습니다. </p>
<p><br /></p>
<p>아이들이 산 물건을 교사에게&nbsp;보여주며 자랑을 하고,&nbsp;생일인 친구에게 산물건을 선물로 주기도 하였습니다. . &nbsp;</p>          </td>
        </tr>',1037,1544108400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20063,'dus3','최호성','naomi1318@naver.com','다윗방 환일고 오*진 아동이 서울역사박물관 견학을 다녀왔습니다. (2018.12.07)','<p></p>
<hr />다윗방 환일고 오*진 아동이 서울역사박물관 견학을 다녀왔습니다.
<p></p>
<p>고3 졸업반을 앞두고 유익한 경험이었다고 합니다. <br /></p>          </td>
        </tr>',976,1544108400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20064,'dus3','최호성','naomi1318@naver.com','다윗방 남산초 이*민 아동이 개별학습반 현장학습을 다녀왔습니다. (2018.12.07)','<p>다윗방 남산초 이*민 아동이 개별학습반 현장학습으로 국립중앙박물관에 다녀왔습니다.</p>
<p>여러가지 조각도 만들고, 유익한 볼거리도 구경하며 즐겁게 다녀왔다고 합니다.</p>          </td>
