INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20011,'dus3','김도연','311279_@hanmail.net','한나방 김*연, 박*민 아동 학교 체험활동으로 롯데월드를 다녀왔습니다.(18.11.30)','<p>한나방 덕수중 3학년 김*연, 박*민 아동이 학교 체험활동으로 </p>
<p>롯데월드를 다녀왔습니다. 고등학교 입학을 앞두고 그동안 마음을 </p>
<p>졸이며 생활했던 친구들이 오랜만에 친구들과 함께 재미있는 놀이기구도</p>
<p>타도 이것저것 구경하며 즐거운 시간을 보냈다고 합니다.</p>
<p>앞으로도&nbsp;친구들과 잘 어울리며 보람있는&nbsp;학교 생활을&nbsp;보낼 수 있도록&nbsp;</p>
<p>지원하겠습니다.&nbsp;&nbsp;&nbsp;</p>          </td>
        </tr>',929,1543503600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20010,'dus3','이혜원','','룻방 박*리, 박*빈, 박*주,장*아 아동이 동시 발표회에 참석하였습니다','<p>필동 어린이집에 다니는 룻방 박*리, 박*빈, 박*주,장*아 아동이</p>
<p>\'필동 아이들의 동시읊는 날\' 에 참여하였습니다.</p>
<p>예쁜 드레스를 입고 그동안 외운 동시를 많은 사람들 앞에서 발표하였습니다. </p>
<p>처음엔 긴장되고 떨린 모습이었지만 곧 멋지게 동시를 발표하는 모습이 너무 예뻤습니다. </p>
<p>아동들이 앞으로도 어린이집 생활 즐겁게 할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',983,1543503600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20009,'dus3','김혜숙','rhdnsdd2@naver.com','바울방 박*주, 박*호 아동이 동시발표회에 참여하였습니다.','<p>필동 어린이집에 다니는 박*주, 박*호 아동이</p>
<p>\'필동 아이들의 동시읊는 날\' 에 참여하였습니다.</p>
<p>멋지게 턱시도를 입고 또랑또랑 시를 읊는 모습이 무척 대견하였습니다.</p>
<p>어린이집에서 더욱 즐겁게 생활할 수 있도록 </p>
