INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19947,'dus3','배소연','cometrue22@naver.com','한나방 초등학생들 학교 학예회에 참여하였습니다.','<p>한나방 초등학생들(왕*젤, 김*경, 김*민)이 학교 학예회에 참여해</p>
<p>지난 1년간 수업시간에&nbsp;배우고 만든 작품을 전시하고</p>
<p>소금, 바이올린, 플릇, 오카리나&nbsp;등을 배워 그동안 갈고 닦은 실력을 뽐내는 시간을 가졌습니다.</p>
<p>열심히 하는 아동들의 모습에 힘찬 박수를 보냅니다.</p>
<p><br /></p>          </td>
        </tr>',971,1542726000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19945,'dus3','최호성','naomi1318@naver.com','다윗방 남산초 학예회에 다녀왔습니다. (2018.11.21)','<p>다윗방 이*민, 박*호 아동이&nbsp;다니고 있는&nbsp;남산초등학교 학예회에 다녀왔습니다.&nbsp; </p>
<p>우리 아이들이 열심히 준비한 공연들을 보면서 참 대견하다는 생각이 들었는데요~</p>
<p>열심히 연습한 모습들이 너무 멋져 보이는 시간이였습니다.&nbsp; </p>
<p>늘 천사같은 미소와 마음으로 밝고 건강하게 잘 자랄수 있도록 지원하겠습니다 ^^*</p>          </td>
        </tr>',967,1542726000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19946,'dus3','최호성','naomi1318@naver.com','다윗방 오*진 아동이 고등학교 마지막 학기말고사를 봅니다.','<p>다윗방 오*진 아동이 고등학교의 마지막 시험인 2학기 기말고사를&nbsp;보고 있습니다. </p>
<p>11/19~11/22까지 4일간 치뤄질 예정이며, 유종의 미를 거두기 위해서 열심히 하고 있습니다. </p>
<p>학창시절 마지막 시험인 만큼 최선을 다해 후회없는 시험을 치룰수 있도록 지도하겠습니다. </p>          </td>
        </tr>',960,1542726000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19899,'dus3','심주현','pikaccu85@hanmail.net','바울방 박*주 아동이 중구청에서 주최한 그림그리기 대회에서 동상을 받았습니다. (2018.11.14)','<p>바울방 박*주 아동이 서울특별시 중구청에서 주최한 <br /></p>
<p>\'2018 놀아요, 그려요, 써봐요 어린이 글짓기 그림그리기\' 대회에서 동상을 받았습니다.<br /></p>
<p>아동은 상 받은 것을 기뻐하며, 메달을 목에 걸고 매우 자랑스러워 하였습니다. <br /></p>
<p>*주가 그린 그림을 거실에 걸어 두어 다 함께 축하해 주는 시간을 가졌습니다. <br /></p>
<p>*주가 재능을 맘껏 펼칠 수 있도록 도와주신 필동어린이집 선생님들께 진심으로 감사드립니다. (^^)(__)(^^)</p>
<p><br /></p>          </td>
        </tr>',955,1542121200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19898,'dus3','한자혜','','룻방 장*아 아동이 어린이집에서 그림그리기 대회에서 은상을 받았습니다.','<p>룻방 장*아 아동이 서울 특별시 중구청에서 주최한 </p>
<p><br /></p>
<p>\'2018 놀아요, 그려요, 써봐요 어린이 글짓기 그림그리기\' 대회에서 은상을 받았습니다.</p>
<p><br /></p>
<p>아동은 상 받은 것을 기뻐하며, 메달을 종일 목에 달고 다녔습니다. </p>
<p><br /></p>
<p>참가한 많은 어린이집 아이들 중에서 입상을 한 것을 보니 뿌듯합니다.</p>
<p><br /></p>
<p>아이들이 꿈을 위해 한발&nbsp;더 나아갈 수 있도록&nbsp;많이 힘써주신 어린이집 선생님들 감사드립니다.</p>          </td>
        </tr>',984,1542034800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19872,'dus3','유미정','3alwjd@hanmail.net','솔로몬B방 박*민, 박*윤 아동이 중부시장 체험 학습 다녀왔습니다.','<p>어린이집에서 중부시장으로 체험학습 다녀왔습니다. 장보기 체험을 했다며 쥐포랑 김, 견과류도 가져오고</p>
