        </tr>',911,1540306800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19743,'dus3','김도연','311279_@hanmail.net','솔로몬B방 박*태, 박*랑 아동이 도담도담 체험관을 다녀왔습니다(18.09.06)','<p>솔로몬B방 박*태, 박*랑 아동이 9월 6일 어린이집에서 도담도담 건강체험관을 다녀왔습니다.</p>
<p>소아비만이 무엇인지 알아보고 너무 많이 먹거나 움직이지 않으면 어떻게 되는지 영상 등을&nbsp; </p>
<p>통해서 배워보는 시간이었다고 합니다. </p>
<p><br /></p>          </td>
        </tr>',920,1540306800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19744,'dus3','김도연','311279_@hanmail.net','솔로몬B방 박*민, 박*윤 아동이 타악기공연&quot;똑딱똑딱 악기 여행&quot;을 관람하였습니다. (18.09.20)','<p>솔로몬B방 박*민, 박*윤 아동이 9월 20일 어린이집 체험활동으로 "똑딱똑딱 악기여행"&nbsp;</p>
<p>타악기 공연 관람을 다녀왔습니다.&nbsp;여러 가지 악기를 구경할 수 있었고 잠깐이지만</p>
