INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19509,'dus3','배소연','cometrue22@naver.com','한나방 김*선아동 2018년 2학기 중간고사 시험기간입니다.','<p>한나방 김*선 아동이 오늘 9월 17일 부터 19일까지</p>
