INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19529,'dus3','배소연','cometrue22@naver.com','한나방 김*연, 박*민, 김*경, 손*영 아동 2학기 중간고사 기간입니다.','<p>한나방 김*연, 박*민, 김*경, 손*영 아동 중학교 2학기 중간고사 기간입니다.</p>
