INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19178,'dus3','배소연','cometrue22@naver.com','한나방 김*민 아동 청소년 광고기획 프로그램 장려상 수상','<p>한나방 김*민 아동(남산초 6학년)이 제5회 청소년 광고기획 &lt;내 꿈은 카피라이터&gt; 프로그램에서</p>
<p>장려상을 수상하였습니다.</p>
<p>같은 반 학급 친구들과 함께 그룹활동을 통해&nbsp;수여받은 상이라 </p>
