INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18988,'dus3','김형식','jazzer80@naver.com','다윗방 성동공고 아동 축구 대표로 경기 참여하였습니다.','<p>2018년 06월16일 성동공고에 다니는 다윗방 김XX 아동이 학교 대표로 대경상고와의 축구 경기에 참여했습니다.</p>
<p>경기를 마치고 귀원하며 8대2로 이겼다며 좋아하였습니다.</p>
<p>골도 넣고 싶었는데 수비수라 공격에 제대로 참여하지 못해 아쉬웠다고 말하면서도</p>
<p>수비수니까 수비에 집중해야죠라고 말하는 모습을 보여주었습니다.</p>
<p>학교내 여러가지 활동을 통해 조금씩 성숙해 가는 아동의 모습이 보기에 좋은 것 같습니다.</p>
<p>더 좋은 인성과 건강한 신체를 가지고 생활하도록 늘 지원하도록 하겠습니다.&nbsp;</p>          </td>
        </tr>',953,1529420400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (19047,'dus3','서보현','qkgkaks1@hanmail.net','한나방 박*민 아동 중구인재장학금을 받았습니다','<p>한나방 박*민 아동이 중구인재육성장학재단 장학생으로 선발되어 <br /><br />장학금을 수여받았습니다. <br /><br />이번 장학금수여가 아동의 미래에 좋은 계기가 되었으면 합니다.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </p>          </td>
        </tr>',954,1530025200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18987,'dus3','김형식','jazzer80@naver.com','다윗방 환일중 아동 거북이 마라톤 참여','<p>2018년 06월 16일 환일중 3학년 곽XX 아동이 거북이 마라톤에 참여했습니다.</p>
<p>7Km를 완주해 완주 메달을 받아왔습니다.</p>
<p>행사를 마치고 배 터지게 고기를 먹었다고 웃으며 좋아하는 모습이 무척이나 귀여웠습니다.</p>
<p>건강하게 생활할 수 있도록 지도하겠습니다.</p>          </td>
        </tr>',928,1529420400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18985,'dus3','김형식','jazzer80@naver.com','다윗방 성동공고 아동 학과 대표 사진 촬영 참여','<p>2018년 05월29일 성동공고에 다니는 고XX 아동이 학과 홍보를 위한 홍보 모델 촬영에 참여했습니다.</p>
<p>무더운 날씨에 동계 교복을 입고 땀 흘리며 촬영을 했다고 하는데 힘들었어도 기분은 좋았다고 합니다.</p>
<p>학과 홍보 브로셔가 나오면 보여준다고 하는데 기대해 봐야겠습니다.</p>          </td>
        </tr>',1083,1529420400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18986,'dus3','김형식','jazzer80@naver.com','다윗방 미래산업고 아동 체육대회 참여','<p>2018년 05월29일&nbsp;미래산업고 체육대회가 있어 다윗방&nbsp;아동 01명이 참여했습니다.</p>
<p>체육대회를 통해 좋은 날씨 속에서&nbsp;일상의 스트레스를 날려버렸을 것 같습니다.&nbsp;</p>
<p>앞으로도 건강하게 신체를 다지며 활력 넘치게 생활하도록 지원하겠습니다.</p>          </td>
        </tr>',1069,1529420400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18984,'dus3','김형식','jazzer80@naver.com','다윗방 성동공고 아동들 군특성화 반 안보체험','<p>2018년 05월23일 성동공고에 다니는 고2 학생 중 신청자에 한해 안보현장 체험이 있었습니다.</p>
<p>다윗방 아동 03명이 신청하여 안보현장 체험(파주 임진각 등)을 다녀왔는데,</p>
<p>올바른 안보의식과 평화에 대한 의미를 다시 한 번 되새기는 시간이었다고 합니다.</p>
<p>더 많은 체험을 통해 아동들의 세계관과 안보 의식이&nbsp;넓어질 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',990,1529420400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18983,'dus3','김형식','jazzer80@naver.com','다윗방 환일중 아동들 체육대회 참여','<p>2018년 05월16일&nbsp;환일중 체육대회가 있어 다윗방&nbsp;아동 02명이&nbsp; 참여했습니다.</p>
<p>안타깝게도 비가 내려 체육관에서 체육대회를 진행했는데</p>
<p>우천을 대비해 학교에서 이은결 마술사 등을 초대해 학생들에게 좋은 시간이 되었다고 합니다.</p>
<p>청소년 시기 구기종목에 관심이 많은데 비로 인한 아쉬움은 있었겠지만</p>
<p>또다른 재미가 있었을 것 같습니다.</p>
<p>더욱 더 학교생활이 풍성하도록 지원하겠습니다.</p>          </td>
        </tr>',903,1529420400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18982,'dus3','김형식','jazzer80@naver.com','다윗방 성동공고 아동들 체육대회 참여','<p>2018년 05월15일 성동공고 체육대회가 있어 다윗방&nbsp;아동 06명이&nbsp; 축구, 족구, 농구 등</p>
<p>여러가지 구기종목에 반대표로 참여하여 열심히 뛰었습니다.</p>
<p>좋은 날씨 속에서 열심히 뛴 아동들이 일상의 스트레스를 날려버렸을 것 같습니다.&nbsp;</p>
<p>앞으로도 건강하게 신체를 다지며 활력 넘치게 생활하도록 지원하겠습니다.</p>          </td>
        </tr>',965,1529420400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18981,'dus3','김형식','jazzer80@naver.com','다윗방 한양공고 아동 체육대회 참여','<p>2018년 05월10일~11일 한양공고 체육대회가 있어 다윗방 이XX 학생이 반대표 축구 선수로&nbsp;참여하는 등</p>
<p>체육대회에 참여하여 열심히 뛰고 탈없이 귀원하였습니다.</p>
<p>"건강한 신체에 건강한 정신이 깃든다"는 말이 있듯 아동들이 열심히 체육활동에 참여해</p>
<p>건강한 신체와 정신을 다질 수 있도록 아낌없이 지원하겠습니다.</p>          </td>
        </tr>',1032,1529420400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18689,'dus3','심주현','pikaccu85@hanmail.net','2018년 남산초등학교 교사 초청 간담회를 진행 하였습니다. (2018.04.25)','<p>2018년 남산초등학교 교사 초청 간담회를 진행 하였습니다. </p>
<p>이번 간담회를 통해 우리 아이들에 대한 이해를 넓히는데 중요한 시간이 되었다고 생각합니다. </p>
<p>앞으로도 남산초등학교와 잘 협력하여 우리 아이들이 푸른 꿈을 가지고 건강하게 </p>
<p>잘 성장할 수 있도록 최선을 다해 노력 하겠습니다. </p>
<p>남산초등학교 교장 선생님 이하 방문해 주신 모든 선생님들께 다시한번 깊은 감사를 드립니다. </p>          </td>
        </tr>',987,1524668400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18626,'dus3','최호성','naomi1318@naver.com','다윗방 한강미디어고 오*진아동이 수련회를 다녀옵니다. (2018.04.18)','<em><p>한강미디어고 1학년&nbsp;오 *진 아동이 2박 3일 횡성숲체원으로 수련회를 다녀옵니다.</p>
<p>즐거운 경험과 추억을 남기고 귀원하기를 기대합니다. </p></em>          </td>
        </tr>',938,1523977200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18593,'dus3','심주현','pikaccu85@hanmail.net','바울방 김*준 아동 학예행사(그리기 부분)에서 우수상을 받았습니다.','<p>바울방 김*준 아동이 남산초등학교에서 진행하는 학교폭력 학예행사(그리기부분)에서 우수상을 받았습니다. </p>
<p>아동이 재능을 잘 펼쳐 나아갈 수 있도록 최선을 다해 지원 하겠습니다. </p>          </td>
