INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18552,'dus3','최호성','naomi1318@naver.com','다윗방 성동공고 아동들이 자격증 시험에 도전합니다. (2018.04.07)','<p>다윗방에서 생활하고 있는 성동공고 아동들이&nbsp;자격증 시험에 지원하게 되었습니다.</p>
<p>4/7 승강기 필기시험 - 김*현, 고*민</p>
<p>4/8 실내건축 기능사 필기시험 - 이*결, 정*균</p>
<p>많은 응원 부탁드립니다. </p>          </td>
