INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18551,'dus3','최호성','naomi1318@naver.com','다윗방 환일중고등학교 아동들이 촛불예배를 다녀왔습니다. (2018.04.02)','2018.04.02&nbsp;환일중학교, 환일고등학교에서 부활절 맞이하여 촛불 예배가 진행되었습니다.          </td>
        </tr>',947,1523113200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18481,'dus3','심주현','pikaccu85@hanmail.net','바울방 배*욱, 이*민 아동 남산초등학교 학부모 상담 하였습니다.(2018.03.27)','<p>바울방 배*욱, 이*민 아동 남산초등학교 학부모 상담을 진행 하였습니다. </p>
<p>담임선생님과&nbsp;상담하여 아동 학교 생활에 대해 알아보고 아동의 생활에 대해 서도 함께 공유하는 </p>
<p>시간이 되었습니다. 앞으로도 아이들의 건강한 학교생활을 위해 최선을 다해 지원하도록 하겠습니다. </p>          </td>
        </tr>',1004,1522162800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18396,'dus3','한자혜','','룻방 박*서 아동이 어린이집 정상 등원을 시작 하였습니다.','<p>룻방 박*서 아동이 오늘 어린이집 적응 생활 끝으로 정상 등원을 시작하였습니다.</p>
<p><br /></p>
<p><br />아동은 언니 오빠들과 함께 오래 있고 싶다고 노래를 부르다가 오래 있는다고 하니 좋아하였습니다.</p>
<p><br /></p>
<p><br />막상 수업이 시작하고 생각보다 오래 있는다고 생각했는지 보육 교사가 보고 싶었다고 안기는 모습이었습니다.</p>
<p><br /></p>
<p><br />새로 어린이집에 들어간 아이들이 적응을 잘 할 수 있도록 지원하겠습니다.<br />&nbsp;</p>          </td>
        </tr>',1064,1520953200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18395,'dus3','한자혜','','룻방 박*서 아동이 어린이집 등원 하기 시작하였습니다.(18.03.02)','<p>룻방 박*서 아동이 어린이집을 처음으로 다니기 시작하였습니다.</p>
<p>매번 언니들을 배웅해주다가 같은 차에 타서 등원을 하니 기분이 좋아서 들떠있는 모습입니다. </p>
<p>아직 적응 기간이라 오래 있지 않고 일찍 갔다가 일찍 돌아왔습니다.</p>
<p>아동은 바로 적응을 하여 또 가고 싶다고 이야기 해주었습니다. </p>
<p>아동이 어린이집에 잘 다닐 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',997,1520953200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18229,'dus3','한자혜','','룻방 어린이집 입소 아동 상담하였습니다.','<p>룻방 박*서 아동 입소 시 새로운 어린이집에 잘 적응 할 수 있도록&nbsp;상담을 진행하였습니다.</p>
<p>박*서 아동이 새로운 어린이집에 대한 기대에 부응할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',997,1519225200,'', '', '', '', '', '');
