INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18226,'dus3','한자혜','','룻방 아이들 어린이집에서 수료식을 하였습니다.','<p>룻방 연*빈, 박*리, 박*빈, 박*주 아동이 필동어린이집에서 수료식을 하였습니다.</p>
<p>아이들은 한해 동안 어린이집 생활을 정리하고 새로 출발 하기 위한 마음을 정리해 봅니다.</p>
<p>수료증서 뿐만 아니라 독서상 저축상을 받았으며 </p>
<p>개별적으로 연*빈 아동은 창의상을, 박*리 아동은&nbsp;탐구상을, 박*주 아동은 우정상을, 박*빈 아동은 예술상을 받았습니다.</p>
<p>아이들이 어린이집에서 남은 시간을 잘 보낼 수 있도록 지원 하겠습니다.</p>          </td>
        </tr>',1027,1519225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18210,'dus3','심주현','pikaccu85@hanmail.net','바울방  박*성 아동 영락어린이집 졸업식을 하였습니다.','<p>바울방 박*성 아동이 영락 어린이집에서 졸업식을 하였습니다. </p>
<p>그동안 열심히 준비한 졸업식 노래와 꿈이야기를 발표하는 시간을 가졌습니다. </p>
<p>그리고 1년간의 추억이 담긴 사진을 영상으로 시청하기도 하였습니다. </p>
<p>1년간의 어린이집 생활을 보면서&nbsp;많이 성장한 *성이가 너무 대견하게 느껴졌답니다. <br /></p>
<p>함께 간 형들에게도 많은 축하를 받으며 졸업식에 참여하였습니다. </p>
<p>졸업식 후에는 맛있는 외식도 하며 즐거운 시간을 보냈습니다. </p>
<p>우리 아이들이 큰&nbsp;기쁨과 사랑으로 잘 성장할 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1082,1519052400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18211,'dus3','심주현','pikaccu85@hanmail.net','바울방 배*욱 아동이 필동어린이집 졸업식을 하였습니다.','<p>바울방&nbsp;배*욱 아동이&nbsp;필동 어린이집에서 졸업식을 하였습니다. </p>
<p>그동안 열심히 준비한 졸업식과 &nbsp;부모님에게 전하는 노래를 발표하는시간을 가졌습니다. </p>
<p>그리고 1년간의 추억이 담긴 사진을 영상으로 시청하기도 하였습니다. </p>
<p>1년간의 어린이집 생활을 보면서&nbsp;많이 성장한 *욱이가 너무 대견하게 느껴졌답니다. </p>
<p>졸업식 후에는 맛있는 외식도 하며 즐거운 시간을 보냈습니다. </p>
<p>*욱이가 어린이집 생활을 잘 마무리 하고 초등학교 입학을 잘 준비할 수 있도록 지원하겠습니다.&nbsp;&nbsp;</p>          </td>
        </tr>',1037,1519052400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18209,'dus3','한자혜','','룻방 장*아 아동이 어린이집에서 졸업식을 하였습니다.','룻방 장*아 아동이 어린이집에서 졸업식을 하였습니다. <br /><br />아동은 친구들과 함께 준비한 노래를 불러주고 영상도 보고 그리고 꿈이야기를 하며 졸업식을 장식했습니다. <br /><br />같이 축하해 주러 간 오빠들과 함께 축하 박수와 꽃다발을 건내줬습니다. <br /><br />아동은 좋아서 꽃자랑을 했습니다. <br /><br />축하 받은 아이들과 축하 해준 아이들 모두 점심에 외식을 하며 맛있게 먹었습니다. <br /><br />우리 아이들이 어린이집에서 남은 시간 마무리를 잘 할 수 있도록 지원하고 <br /><br />새로운 환경에 가서 입학을 하고 잘 적응 할 수 있도록 지원하겠습니다.           </td>
        </tr>',1038,1519052400,'', '', '', '', '', '');
