INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (17376,'dus3','한자혜','','룻방 남산초 김*경 아동 연극 활동과 독서실 뮤지컬 관람이 있었습니다.(17.09.27.수)','<p>룻방 남산초 김*경 아동 연극 활동으로 토끼와 자라 이야기로 연극을 선보였습니다. </p>
<p><br /></p>
<p>아동은 신나하면서 참여하였습니다. </p>
<p><br /></p>
<p>또한 연극이 끝나고 바로 동아리 활동으로 배운 바이올린 실력을 뽑내봅니다.</p>
<p><br /></p>
