INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (17074,'dus3','이소영','applehyoji@naver.com','한나방 김*선 아동 코엑스 무역아카데미 강의 참석.','<p>한나방 김*선 아동이 코엑스에서 하는 국제무역사2급 자격시험 대비반에 선정이 되어 8/7(월)부터 8/9(수)까지 강의를 듣습니다.</p>
<p>무역아카데미 제1강의실(삼성동 코엑스 4층) 에서 진행하며 국제무역사 2급 전과목 최종 정리 및 기출문제 해설을 교육받습니다.</p>
<p>교육 종료 시 수료증을 받습니다. </p>
<p>아동이 배우는것에 흥미를 잃지 않게 하며 공부를 더 열심히 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1177,1502118000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (17006,'dus3','이소영','applehyoji@naver.com','한나방 김*희 아동이 간호실습을 합니다.','<p>&nbsp;한나방 김*희 아동이 신금호 역 중*병원에서 간호 실습을 합니다.</p>
<p>2017.07.11(화)부터 2017.09.01(금)까지 실습이며, 월요일부터 금요일까지. </p>
<p>데이(9-17시) 이브닝(9-18시)로 매주 시간대가 다르게 실습 합니다.</p>
<p>병동과 수술방 등 여러 곳에서 실습 합니다.</p>
