INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16420,'dus3','황지현','','룻방 필동어린이집 딸기체험학습 참여','<p>룻방 필동어린이집 박*리, 연*빈, 박*빈, 박*주 아동들이 오늘 남양주에 있는 딸기농장에 다녀왔습니다.</p>
<p>가서 딸기도 직접 따보고 먹어보는 시간을&nbsp;가졌습니다.</p>
<p>오후에는&nbsp;아동들이 직접 따온 딸기와 수제잼을 먹어보는 시간을 가졌습니다.</p>
<p>아동들이&nbsp;더 적극적으로 어린이집 행사에 참여할 수 있게 지원하겠습니다.&nbsp;</p>          </td>
        </tr>',1146,1493305200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16419,'dus3','황지현','','룻방 김*민, 김*경 아동 남산초 어린이날기념 남산걷기대회 참여','<p>룻방 김*경, 김*민 아동이 남산초에서 외부활동으로 어린이날기념 남산걷기대회에 참여하였습니다.</p>
<p>아동이 학교행사에 잘 참여할 수 있도록 지원하겠습니다.</p>          </td>
