INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16351,'dus3','신영수','ysysking@naver.com','다윗방, 환일중학교 이*슬 아동 두산장학금 수령.','<p>다윗방에서 생활하고 있는 이*슬 아동이 두산가족 장학금을 수령하였습니다. </p>
<p>앞으로도 아동이 바르고 성실하게 생활할 수 있도록 지도하겠습니다. </p>          </td>
