INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16344,'dus3','최은희','chldmsdk2088@naver.com','바울방 김*준 박*호 이*민 남산초 양평두물머리애벌레생태 현장학습 갔다왔습니다~','<p><br /></p>
<p>오늘 비가 많이 와서 걱정을 했는데 다행이도 사고없이 양평 두물머리 애벌레 생태 농장</p>
<p>현장학습을 갔다 오후 3시30분쯤 귀가하였습니다 ~</p>
<p>체험장에서 키우라고 애벌레를 각각 나눠주었다고 하여 내일 날씨좋을때 남산원 화단에</p>
<p>풀어서 키울생각이라고 합니다 ^^</p>
<p>아이들에게 유익한 현장체험이 된것 같아 뿌듯합니다!</p>          </td>
        </tr>',1088,1492441200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16341,'dus3','한자혜','','룻방 김*경 아동이 남산초에서 현장학습을 다녀왔습니다.','<p>룻방 김*경 아동이 남산초에서 현장학습을 다녀왔습니다. <br /><br /></p>
<p>아동은 가기전 부터 빨리 가고 싶은 마음에 준비를 빨리 하는 모습으로&nbsp; 들뜬 마음 갖고&nbsp;출발하였습니다.</p>
<p>송암스페이스센터에 방문하여 별자리 및 우주의 관련하여 관찰하고 체험하는 시간을 가졌습니다.</p>
<p>아이가 체험한 것에 이야기를 나누며 좋은 추억으로 남을 수 있도록 잘 지도하겠습니다.</p>          </td>
        </tr>',1025,1492441200,'', '', '', '', '', '');
