INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16338,'dus3','신영수','ysysking@naver.com','다윗방 아동 3명 방과 후 학교 신청(성동공고)','<p>성동공고에서 재학 중인 아동 3명(고*민, 김 *, 김*현)이 5월 8일부터 6월 30일까지 진행하는 방과 후 학교를 신청하여 배드민턴과 농구 활동을 하게 되었습니다. </p>
<p>신체활동을 통하여 아동들이 더욱 건강하게 생활할 수 있도록 지도하겠습니다. </p>          </td>
        </tr>',1037,1492441200,'', '', '', '', '', '');
