INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16300,'dus3','김소영','suzume10@naver.com','한나방 아동들의 중간고사가 다음주부터 시작됩니다.','<p>덕수중 2학년 김*연, 박*민 아동은 4월24일(월)~26일(수)</p>
<p>대경상고 3학년 김*주 아동은 4월26일(수)~28일(금)</p>
<p>경기여상 2학년 김*희 아동은 4월24일(월)~27일(목)</p>
<p>송곡관광고 3학년 이*리 아동은 4월28일(금)~5월2일(화)</p>
<p>선일E비즈니스고 2학년 김*선 아동은 4월25일(화)~28일(금)</p>
<p>세그루패션디자인고 2학년 강*리 아동은 4월27일(목)~5월2일(화)</p>
<p>위와 같은 일정으로 중간고사를 시행합니다.</p>
<p>중간고사를 앞두고 시험준비를 잘 할 수 있도록 잘 지도하겠습니다.</p>          </td>
        </tr>',1039,1492268400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16334,'dus3','신영수','ysysking@naver.com','다윗방 아동들 다음주 중간고사 기간','<p>다윗방 아동들이 다음 주부터 중간고사가 시작됩니다.</p>
<p>평소에 부족한 과목 스스로 공부하도록 지도하고 있습니다. </p>
<p>좋은 결과 얻을 수 있도록&nbsp;지도하겠습니다.</p>          </td>
        </tr>',1033,1492354800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16289,'dus3','황지현','','룻방 김*경 외부학습 프로그램 참여','<p>룻방 김*경 아동이 학교 수업 후 피아노학원에 주 4일 참여하고 있습니다.</p>
<p>아동이 꾸준히 참여하고 흥미를 가지도록 지도하겠습니다.</p>          </td>
        </tr>',994,1492095600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16284,'dus3','황지현','','룻방 김*경 아동 학교생활','<p>룻방 김*경 아동이 학교에서 키움반과 방과 후 로봇교실에 참여하고 있습니다.</p>
<p>아동이 좀 더 흥미를 가지고 재미를 붙일 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1050,1492095600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16283,'dus3','최은희','chldmsdk2088@naver.com','바울방 박*진 , 박*수 현장학습 갔습니다~','<p><br /></p>
<p>충무 어린이집 박*진,박*수 아동</p>
<p>초록향기생태농장 현장학습 갔습니다. </p>
<p>많은것을 보고 아이들에게 좋은 경험을 심어준것 같아 기분이 좋습니다~</p>          </td>
        </tr>',1072,1492095600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16280,'dus3','한자혜','hjh8172@hanmail.net','룻방 김*민 학교생활','<p>룻방 김*민 아동이 학교에서 기본 수업 외에 중국어와 탁구 수업에 참여하고 있습니다.</p>
<p>아동의 학교생활이 더 즐겁게 될 수 있도록 지원하겠습니다. </p>          </td>
        </tr>',1015,1492095600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16266,'dus3','김소영','suzume10@naver.com','한나방 김*선 아동이 방과후학교에서 회계과목을 공부하고 있습니다.','<p>선일E비즈니즈고등학교 2학년에 재학중인&nbsp; 김*선 아동이 방과후학교에 회계과목을 공부하고 있습니다.</p>
<p>회계과목 수업을 통해서 회계 관련 자격증 공부하는데 큰 도움이 될 것입니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1022,1491922800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16271,'dus3','김소영','suzume10@naver.com','한나방 김*희 아동이 2박3일 일정으로 수학여행을 떠났습니다.(17.04.12~14)','<p>경기여상 2학년 김*희 아동이 2박3일 부산으로 수학여행을 떠났습니다.</p>
<p>친구들과 사진도 많이 찍고, 좋은 추억을 많이 쌓고 오길 바라며</p>
<p>2박 3일 동안 건강하게 잘 다녀오기를 바랍니다.</p>          </td>
        </tr>',1000,1491922800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16263,'dus3','신영수','ysysking@naver.com','다윗방 아동, 성동공고 고*민 청어람 방과 후 수업.','<p>다윗방에서 생활하고 있는&nbsp;성동공고 고*민 청어람 방과 후 수업 열심히 진행 중에 있습니다.</p>
<p>아동이 학교 생활에 잘 적응하여 좋은 결과 얻을 수 있도록 지도하겠습니다. </p>          </td>
        </tr>',998,1491922800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (15990,'dus3','현정은','486give@hanmail.net','고등학교에 입학하였습니다.','<p>다윗방의 정*찬, 김*현, 김*, 고*민 아동이</p>
<p>고등학교에 입학하였습니다. </p>
<p>교복을 깨끗하게 차려입은 모습이 어찌나 멋있던지요.</p>
<p>아동의 특성과 진로에 맞게 특성화고에 입학하였습니다.</p>
<p>아동들이 건강하게 성장하고 자립할 수 있도록 지원하겠습니다.</p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',1034,1488380400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (16262,'dus3','신영수','ysysking@naver.com','다윗방 아동 성수공고 이*울 전기기능사 자격증 도전','<p>다윗방에서 생활하고 있는 이*울 아동이 전기기능사 자격증 시험에 지원하게 되었습니다.</p>
<p>오늘부터 방과 후에 자격증 대비 수업을 하게 됩니다.</p>
<p>많은 응원 부탁드립니다. </p>          </td>
        </tr>',977,1491922800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (15987,'dus3','현정은','486give@hanmail.net','초등학교에 입학하였습니다.','<p>3월 2일 남산원 아동 3명이 남산 초등학교에 입학하였습니다.</p>
<p>박*호, 김*준, 이*민 아동의 입학을 축하합니다. </p>
<p>아동들이 원활하게 적응하여 건강한 교육을 받을 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1017,1488380400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (15989,'dus3','현정은','486give@hanmail.net','어린이 집에 입학하였습니다.','<p>바울방 - 박*수</p>
<p>룻방 - 박*빈, 박*주, 박*아 아동이</p>
<p>어린이집에 입학하였습니다.</p>
<p>아동들이 다른 친구들과 원활하게 어울리며 즐거운 생활을 하며 성장할 수 있도록 지원하겠습니다.</p>
<p>입학을 축하합니다.</p>          </td>
        </tr>',1000,1488380400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (15988,'dus3','현정은','486give@hanmail.net','중학교에 입학하였습니다.','<p>환일중학교 - 이*슬</p>
<p>덕수중학교 - 손*영, 김*희 </p>
<p>아동이 입학하였습니다. </p>
<p>교복을 의젓하게 차려입은 모습이 너무 잘어울린답니다.</p>
<p>아동이 중학교 생활에 잘 적응할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1090,1488380400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (15813,'dus3','한자혜','','룻방 아이들이 중학교 배정을 받았습니다.','<p>룻방&nbsp;김*경, 손*영&nbsp;아동이 덕수중학교에 입학하게 되었습니다.&nbsp; </p>
<p>아이들이 새로운 생활에 적응 할 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',1110,1486047600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (15812,'dus3','한자혜','','덕수중 아이들이 봄방학을 맞이하였습니다.','룻방 덕수중학교에 다니는 박*민 김*연 아동이 봄방학을 맞이하여  <br />신학기를 준비하는 시간을 갖게 되었습니다.           </td>
        </tr>',1055,1486047600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (15669,'dus3','현정은','486give@hanmail.net','방학 중 [방과후 학교]에 다녀요.','<p>현재 초, 중, 고등학생이 방학기간이예요.</p>
<p>초등학교에 다니는 아동들은 방학 중에도 자신이 원하는 분야의 수업을 받으러 방과후 학교를 다니고 있답니다.</p>
<p>룻방의 손*영 아동은 컴퓨터 자격증반, 김*민 아동과 김*경 아동은 로봇교실, 김*경 아동은 미각조리반을 </p>
<p>다니며 자신으 원하는 활동을 통해 재능과 꿈을 키워나가고 있습니다.</p>
<p>뜻깊은 방학이 되기를 응원해봅니다. </p>          </td>
        </tr>',1096,1483974000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (14560,'dus3','김선기','spsp99@naver.com','다윗방 수련회 및 수학여행 떠남(2016.06.15.)','환일중학교 1학년인, 곽*,2학년인 정*균, 이*결, 오 *진 아동이 강원도 정선으로 수련회를 떠났고(2016.0615~17)남산초 이*슬아동이 부여로(2016.0615~17)수학여행을 떠났습니다.          </td>
        </tr>',1242,1466002800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (14506,'dus3','김선기','spsp99@naver.com','덕수중학교 이*늘아동 졸업식(2016.02.05)','2016년 2월 5일(금) 덕수중학교 졸업식이 있었습니다. <br />다윗방 이*늘아동이 중학교 생활을 마무리 짓고 고등학교로 진학하게 되었습니다.&nbsp; <br /><br />          </td>
        </tr>',1230,1465225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (14559,'dus3','김선기','spsp99@naver.com','다윗방 중3 아동들이 제주도로 수학여행을 떠났습니다.(2016.06.14.)','환일중학교 3학년인, 김*수, 정*찬, 김*현, 김 * 아동이 제주도로 수학여행(2016.0614~17)을 떠났습니다.  제주도의 환상적인 아름다운 풍경속에서 좋은 시간을 보내고 건강하게 돌아오기를 바랍니다.          </td>
        </tr>',1160,1466002800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (14503,'dus3','김선기','spsp99@naver.com','환일중학교 3학년 아동들의 졸업식에 다녀왔습니다.(2016.02.04.)','모세방에서 생활하는 환일중학교 3학년 아동들이 졸업식을 하였습니다.  <br />올해 중학교를 졸업하는 오*진, 김*석 아동은 각자의 진로에 맞는 고등학교로 진학을 하게 되었습니다.  <br />특별히 이번 졸업식에서 오*진아동이 학교 공로상과 3년 개근상을 수상 하였습니다. <br />아쉬운 헤어짐보다 새로운 만남에 더 많은 기대를 하면서 앞으로 성실하게 고등학교 생활을 할 수 있도록 보육하겠습니다.          </td>
        </tr>',1214,1465225200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (14505,'dus3','김선기','spsp99@naver.com','다윗방 곽*민 아동의 졸업식이 있었습니다. (2016.02.19.)','<p>오늘 곽*민 아동의 남산초등학교 졸업식이 있었습니다. 새로 출발하는 앞길을 축복하며, 늘건강하고 밝은 곽*민이 되길 기원합니다. </p>          </td>
        </tr>',1165,1465225200,'', '', '', '', '', '');
