INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11958,'dus3','송명은','happysme@hanmail.net','대경정보산업고등학교 졸업식이 있었습니다.(2015.02.12)','<div>한나방 선* 아동이 대경정보산업 고등학교를 졸업하였습니다.</div>
<div>졸업을 축하합니다.</div>          </td>
        </tr>',1530,1423666800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11752,'dus3','송명은','happysme@hanmail.net','2014년도 2학기 중고생 기말고사에 대한 성적향상금을 전달하였습니다.(2015.01.02)','<div>중고생 아동들을 대상으로 기말고사의 성적이 향상된 아동들에게 성적향상금을 전달하였습니다.</div>
<div>강*리 : 38,000원</div>
<div>김*희 : 41,000원</div>
<div>김*선 : 123,000원</div>
<div>유*연 : 40,000원</div>
<div>김*철 : 41,000원</div>
<div>김*현 : 41,000원</div>
<div>김&nbsp;&nbsp;&nbsp;* : 48,000원</div>
<div>이*늘 : 38,000원</div>
<div>앞으로도 아동들이 열심히 노력한 결과의 기쁨을 느낄 수 있도록 보육하겠습니다.</div>          </td>
        </tr>',1528,1420124400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11056,'dus3','심주현','pikaccu85@hanmail.net','바울방 이*슬 아동이 학급 부회장으로 선출되었습니다.(2014.09.01)','<div>바울방 이*슬 아동이 학급부회장으로 선출되었습니다. 바울방에서도 늘 성실한 *슬이 인데요 ^^</div>
<div>2학기동안 학급을 잘 이끌어 나아갈 수 있도록&nbsp; 지원하겠습니다. </div>
<div><br />&nbsp;</div>
<div>&nbsp;</div>
<div>아동의 인권존중과 아동 개인정보 보호로 인하여 개인적인 아동들에 사진을 올리지 못함을 양해 부탁 드립니다.<br />홈페이지 관리 모세방 생활지도교사 김선기올림.</div>          </td>
        </tr>',1517,1409497200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11744,'dus3','송명은','happysme@hanmail.net','남산원 아동들이 겨울방학을 맞이하여 생활계획표를 만들었습니다.(2015.01.01)','겨울방학을 맞이하여 남산원 아동들은 초등부에서부터 고등부까지 유익한 겨울방학을 보내기 위해서 생활계획표를 만들었습니다.&nbsp;남산원 아동들이&nbsp;겨울방학을 좀 더 규칙적으로 생활하면서 부지런한 아동으로 생활할 수 있도록 열심히 보육하겠습니다.          </td>
        </tr>',1404,1420038000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (10879,'dus3','심주현','pikaccu85@hanmail.net','2014년 여름 방학 생활 계획표 시상식 사진입니다. (2014.07.29)','<div>오늘 아침 2014년 여름방학 생활 계획표 시상식을 하였습니다. </div>
<div>각 방에 최우수상. 우수상을 선정 하였는데요</div>
<div>그 어느때 보다도 아이들이 열심히 해서 작품을 선정하기가 매우 힘들 었던것 같습니다. </div>
<div>- 최우수상 :&nbsp; 임<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">현, 김</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">석, 김</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">희, 이</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">슬</span></div>
<div>- 우수상 : 안<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">현, 유</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">연, 김</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">지, 이</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">결, 정</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">균</span></div>
<div>수상한 아동들에게는 부상으로 문화상품권이 지급되었습니다. </div>
