INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (10020,'dus3','심주현','pikaccu85@hanmail.net','남산초등학교 선생님 초청 간담회날입니다.(2014.04.30)','<div>오늘은 남산초등학교 선생님 초청 간담회가 있었습니다. </div>
<div>교장선생님 이하 많은 선생님들께서 참석해 주셨는데요~^^</div>
<div>언제나 변함없는 사랑으로 우리 아이들에게 많은 관심과 지도를 해주시는 선생님들과의 만남이 참 귀한 시간이 되었던 것 같습니다.&nbsp; 남산초등학교 교장선생님께서 아이들을 위해 초코케잌과 쿠키선물을 준비해 주셨는데요 ^^</div>
<div>아이들과 함께 노래도 부르고 컷팅식도 하는 시간을 가졌습니다. 아이들의 인원수에 맞춰 초도 12개로 준비해 주셔서 더 의미있는 시간이 되었던 것 같습니다. 아이들 생활관 방문도 하시어 아이들의 가정생활도 함께 보며 즐거운 시간을 가졌습니다. </div>
<div>앞으로도 꾸준히 학교와 연계하여 아이들이 건강하고 즐거운 학교생활을 보낼 수 있도록 지원하겠습니다. </div>
<div>오늘 방문해 주신 남산초등학교 선생님들께 진심으로 감사드립니다. (^^)(__)(^^)</div>
<div>&nbsp;</div>
<div>&nbsp;</div>
<div>&nbsp;</div>
<div>아동의 인권존중과 아동 개인정보 보호로 인하여 개인적인 아동들에 사진을 올리지 못함을 양해 부탁 드립니다.<br />홈페이지 관리 모세방 생활지도교사 김선기올림.</div>          </td>
        </tr>',1662,1398783600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (10018,'dus3','박충일','a7124383@nate.com','다윗방 오*진 이*결 정*균아동 남산초간담회(2014.04.30)','<div>4월 30일 남산초등학교 간담회가 있었습니다. 남산초등학교 교장선생님이하 많은 선생님들께서 남산원에 방문해주셨습니다.</div>
<div>간담회를 마치고 각 생활관으로 이동하여 담임선생님과 담당생활지도교사의 상담시간이 있었습니다. 아동들의 생활에 대해 많이 궁금해하시고 아이들을 앞으로 더 잘 지도부탁드렸습니다. 아이들 생활상을 확인하시고 가셔서 안심이 되셨으리라 믿습니다. 학교생활 잘하도록 원에서도 적극 지원하겠습니다.</div>
