INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8945,'dus3','이소영','leesy5576@hanmail.net','룻2방 김*선이 후원자님께 선물을 받았습니다.','<p align="center">2014년 4월 5일 룻2방 김<span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">선이 후원자님께 운동화와 옷을 선물 받았습니다.</span></p>
