INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8958,'dus3','심주현','pikaccu85@hanmail.net','바울방 초등부 유니온스틸과 함께하는 사생대회에 참여하였습니다!(2014.04.04)','<div>오늘 바울방 초등부 아동과 막내 진욱이가 유니온스틸과 함께하는 봄맞이 사생대회에 참여하였습니다!!</div>
<div>요즘 한창 벚꽃이 이쁘게 피어 봄소식을 전하고 있는데요 ^^</div>
<div>날 좋은날 유니온 스틸 후원자님과 함께 다람쥐 놀이터에서 "우리집을 지키는 초록에너지" 라는 주제로 사생대회를 하였습니다. </div>
<div>우리집은 남산에 있어 매일 맑은 공기를 마시며 생활하고 있는데요 ^^</div>
<div>봄맞이 사생대회를 맞이하여 다시금 자연의 소중함에 대해 생각해 볼 수 있는 시간을 가지게 된 것 같습니다. 우리 아이들에게 기쁘고 즐거운 날을 선사해 주신 유니온 스틸 후원자분들께 진심으로 감사드립니다!! (^^)(__)(^^)</div>
<div>&nbsp;</div>
<div>&nbsp;</div>
<div>&nbsp;</div>
