INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8962,'dus3','이소영','leesy5576@hanmail.net','룻2방 손*영, 김*연이가 후원자님께 선물을 받았습니다.(2014. 04. 02)','<p align="center">2014년 4월 2일 룻2방 손*영, 김*연이가 후원자님께 달력과 노트를 선물받았습니다.</p>
