INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8967,'dus3','박충일','a7124383@nate.com','다윗방 아동들의 3월 모범상금시상이 있었습니다.(2014.04.01)','<div>3월 한달간 원내 바른생활을 지도하기 위한 선행포인트제 결과물인 모범상금시상식이 오늘 오전에 있었습니다.&nbsp; 다윗방 이*늘 32,400원, 김*현 28,000원, 김* 31,800원, 김*수 2,200원, 이*결 15,900원, 오*진 11,000원, 정*균 10,000원, 곽*환 12,800원등의 모범상금을 각각 받았습니다. 새로운 시작인 4월한달동안 열심히 생활하여 좋은 결과를 얻고 아동 스스로 바른 인성교육이 몸에베어 습관이 될 수 있도록 지도하겠습니다. 감사합니다.</div>
