INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8966,'dus3','박충일','a7124383@nate.com','다윗방 이*결아동이 최우수상장을 받았습니다. (2014.03.31)','<div>남산초등학교 6학년에 재학중인 다윗방 이*결 아동이 교내 인성교육실천주간 학예행사(표어부문)에서 우수한 재능을 보여 상장을 받았습니다. 원내 생활뿐 아니라 학교에서도 열심인 우리 한결이에게 많은 칭찬부탁드립니다. 감사합니다.</div>
