        </tr>',932,1396278000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8970,'dus3','이소영','leesy5576@hanmail.net','룻2방 주말오후 바깥놀이를 하였습니다.(2014. 03. 30)','<p align="center">2014년 3월 30일 룻2방 미취학, 초등학생 아동들이</p>
