INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8983,'dus3','박충일','a7124383@nate.com','다윗방아동들이 신장체중측정과 식단에 대한 기호도 조사를 하였습니다.(2014.03.27)','<div>다윗방 아동들이 금일 신장체중측정과 식단에 대한 기호도 조사를 하였습니다. 식사를 규칙적으로 잘하는 아동은 키가 많이 자랐고 편식하고 생활이 불규칙한 아동은 키가 그대로 였습니다. 따라서 식사 때마다 편식하지않도록 지도하며 취침시간 잘 지켜 충분한 수면을 취하도록 지도하고 있습니다. 또한 자신이 좋아하는 식단을 체크하여 식단표만들때 참조하도록 하였습니다.&nbsp; 잘 먹고 잘 자라며 운동과 공부도 열심히 하는 다윗방 아동들이 될 수 있도록 지도하겠습니다.</div>
