INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8989,'dus3','이소영','leesy5576@hanmail.net','룻2방 *영, *연이가 후원자님께 선물을 받았습니다.(2014. 03. 24)','<p align="center">2014년 3월 24일 룻2방 *영, *연이가</p>
