INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8990,'dus3','이소영','leesy5576@hanmail.net','룻2방 초등학생 아동이 특기적성수업에서 쿠키를만들어 귀가하였습니다.(2014. 03. 24)','<p align="center">2014년 3월 24일 룻2방 초등학생 저학년&nbsp;<span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">별,&nbsp;</span><span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진,&nbsp;</span><span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">민이가</span></p>
<p align="center">남산초등학교 특기적성 수업 클레이&amp;쿠키반에서 쿠키를 만들어 귀가하였습니다.</p>
