INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8993,'dus3','송명은','happysme@hanmail.net','룻2방 *연이가 2월의 칭찬왕이 되었습니다.(2014-03-22)','<p>룻2방에서 한달의 한번 점수가 높은 아동을 선정하는 칭찬왕에 2월달 칭찬왕으로 *연이가 선정되었습니다. 초등학교 5학년인 *연이는 중고생 언니들 못지않게 너무나 의젓한 모습으로 동생들을 챙겨주고 원내생활과 학교생활에서 모범적인 모습을 보여주는 사랑스러운 아동입니다.</p>
<p>그동안 추운 날씨에 바깥나들이를 하지 못해서 아쉬웠는지 2월달 칭찬왕이 된 *연이는 룻2방 선생님과 함께 맛있는 점심식사를 하고 자전거를 타면서 오랜만에 야외에서 즐겁고 신나는 시간을 보냈습니다.</p>
<p>앞으로 *연이가 지금보다 더 멋진 아동으로 성장할 수 있도록 열심히 보육하겠습니다.</p>
<p><br /></p>
<p>아동의 인권존중과 아동 개인정보 보호로 인하여 개인적인 아동들에 사진을 올리지 못함을 양해 부탁 드립니다.</p>          </td>
        </tr>',952,1395500400,'', '', '', '', '', '');
