INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8996,'dus3','이소영','leesy5576@hanmail.net','룻2방 초등학생 퀼트박물관 견학 및 바느질교육 2회기 사진입니다.(2014. 03. 22)','<p align="center">2013년 2월 22일 룻2방 초등학생 아동들이</p>
<p align="center">명동에 위치한 퀼트박물관에 가서 지난주에 이어 바느질교육을 받았습니다.</p>
<p align="center">지난 주에는 박물관 견학과&nbsp;휴지와 소지품을 보관할 수 있는 파우치를 만들었고</p>
