INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8998,'dus3','송명은','happysme@hanmail.net','룻2방 민지가 학급에서 임명장을 받았습니다.(2014-03-22)','계성여고 3학년에 재학중인 룻2방 민지가 학급에서 정보,경제,안전 도우미로 임명이 되어 임명장을 받았습니다.
<div>민지는 올해 고3으로 내년에 자립을 앞두고 열심히 준비하고 있습니다.민지가 올 한해 학교생활에 충실할수 있도록 열심히 보육하겠습니다.</div>
