INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9000,'dus3','송명은','happysme@hanmail.net','룻2방의 혜연이가 17번째 생일을 맞이하였습니다.(2014-03-21)','룻2방의 기분좋은 활력소인 혜연이가 17번째 생일을 맞이하였습니다. &nbsp;올해 고등학생이 된 혜연이는 학교생활과 원내생활에 성실하게 임하면서 열심히 생활하고 있습니다. 현재 의상과에 다니고 있는 혜연이가 멋진 의상 디자이너가 될 수있도록 열심히 지도하겠습니다.

