INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9001,'dus3','송명은','happysme@hanmail.net','룻2방 초등부가 교통안전교육을 받았습니다.(2014-03-21)','룻2방 초등부 아동들이 남산으로 교통안전교육을 다녀왔습니다.남산타워에 가는 버스를 타기 위해 한줄로 줄을 서고 버스비를 직접내보면서 안전하게 대중교통을 이용하는 방법에 대해서 알수있는 유익한 시간이었습니다.

<div>앞으로 아동들에게 필요한 다양한 교육을 지원하도록 하겠습니다.</div>
