INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9007,'dus3','송명은','happysme@hanmail.net','룻2방의 남산초 1학년 *별이와 *진이가 예쁜 클레이아트를 만들었습니다.(2014-03-17)','남산초등학교 1학년에 입학한 *별이와 *진이가 오늘 학교 특기적성 프로그램 으로 참여한 클레이아트부시간에 예쁜 토끼와 거북이를 만들었습니다.&nbsp;
