        </tr>',943,1394982000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9008,'dus3','이소영','leesy5576@hanmail.net','룻2방 중.고등학생아동 서울침례교회후원 봄나들이사진입니다.(2014.03.15)','2014년 3월 15일 룻2방 중, 고등학생 아동들이 서울침례교회후원으로 양평 두물머리로 봄나들이를 다녀왔습니다.
