INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9013,'dus3','송명은','happysme@hanmail.net','룻2방 아동들의 즐거운 주말오후시간입니다.(2014-03-16)','<font class="Apple-style-span" face="굴림">모처럼 따뜻한 날씨에 룻2방 아동들은 그동안 움크리고 있었던 몸과 마음을 활짝 피면서 즐겁고 재미있는 소꿉놀이를 하였습니다. 서로 역할을 정해서 맛있는 밥과 반찬을 만들면서 주말오후시간을 보냈습니다.</font>
<div><div style="font-family: 굴림">내일부터 시작되는 학교생활도 성실하게 임할수 있도록 열심히 보육하겠습니다.</div>
<div style="font-family: 굴림"><br /></div>
<div style="font-family: 굴림">아동의 인권존중과 아동 개인정보 보호로 인하여 개인적인 아동들에 사진을 올리지 못함을 양해 부탁 드립니다.</div></div>          </td>
        </tr>',918,1394895600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9014,'dus3','심주현','pikaccu85@hanmail.net','바울방 초등학생들이 퀼트박물관에 다녀왔습니다!!(2014.03.15)','<p align="left">오늘 바울방&nbsp;초등학생 아동들이 초전섬유퀼트박물관에 다녀왔습니다. </p>
<p align="left">이쁜 꽃모양의 휴지 주머니도 만들고 한국, 일본, 중국의전통 의상의 있는 전시실도 관람하였습니다. 보자기의 쓰임새와 우리나라 조상님의 예술성을 엿볼 수 있는 기회가 되었던 것 같습니다. 처음에는 아이들이 바느질을 어려워 하였으나 곧 잘 따라 하는 모습에 멋진 작품들이 나왔던 시간이였습니다. </p>
<p align="left">아이들에게 좋은 수업을 진행해 주신 관장님과 선생님들께 진신으로 감사드립니다^^*</p>          </td>
        </tr>',994,1394895600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9016,'dus3','이소영','leesy5576@hanmail.net','룻2방 초등학생 아동들이 초전섬유퀼트박물관에 다녀왔습니다.(2014. 03. 15)','<p align="center">2014년 3월 15일 룻2방 초등학생 아동들이</p>
<p align="center">초전섬유퀼트박물관에 방문하여 박물관을 견학하고 바느질 교육을 받았습니다.</p>
<p align="center">바느질하는 것을 어려워하였지만 관장님과 선생님들의 도움으로 파우치도 완성시키고</p>
<p align="center">수업 후 다같이 간식도 먹으며 즐거운 주말을 보냈습니다.</p>
<p align="center">2회기에는 복주머니도 만들고 아이들이 만든 작품으로 전시회도 할 예정입니다.</p>
<p align="center">남은 기간동안 프로그램 잘 지원할 수 있도록 하겠습니다.</p>          </td>
        </tr>',939,1394809200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9015,'dus3','이소영','leesy5576@hanmail.net','룻2방 초등학생 아동들이 소방안전교육을 받았습니다.(2014. 03. 15)','<p align="center">2014년 3월 15일 룻2방 초등학생 아동들이</p>
