INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9030,'dus3','박충일','a7124383@nate.com','다윗방 김*현,김*,김*수아동이 새 핸프폰을 받았습니다. (2014.03.08)','<div>다윗방 김*현, 김*, 김*수 아동이 새 핸드폰을 받았습니다. 아동들이 새 핸드폰을 받고 정말 기뻐하였습니다.&nbsp;</div>
