INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9029,'dus3','송명은','happysme@hanmail.net','룻2방의 *이가 요리학원에 다니게 되었습니다.(2014-03-09)','룻2방의 큰언니인 &nbsp;*이가 요리학원에 등록을 하였습니다. 올해 고3이 된*이의 장래희망인 요리사가 되기위한 첫발걸음을 내딛은 날이었습니다. 내일부터 한식조리사 자격증을 취득하기위해 열심히 학원수업에 임해서 필기와 실기시험에서 좋은 성적을 거둘수 있도록 열심히 지원하겠습니다.
