INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9034,'dus3','송명은','happysme@hanmail.net','룻2방 아동들은 장근석팬클럽분들과 즐거운 레크레이션 시간을 보냈습니다.(2014-03-08)','<p>작년에 이어서 올해도 남산원 아동들과 즐겁고 신나는 레크레이션 시간을 보내주신 장근석 팬클럽분들께 감사드립니다. 룻2방 아동들을 재미있는 레크레이션도하고 선물도 받으면서 즐거운 시간을 보냈습니다. 감사합니다.^^</p>
