INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9048,'dus3','송명은','happysme@hanmail.net','룻2방 *민이의 후원자님께서 맛있는 피자를 선물해주셨습니다.(2014-03-04)','<p>남산원 아동들을 위해 즐겁고 유익한 프로그램을 준비해주시고 후원해주시는 한국쓰리엠주식회사에 계시는 박민재 후원자님께서 룻2방 *민이를 기억해주셔서 오늘 남산원을 방문해주셔서 아동들을 위해 맛있는 피자를 후원해주셨습니다. 새학기가 되어서 분주한 시간을 보내던 아동들이 맛있는 피자를 먹고 힘내서 열심히 학교생활을 할수있도록 열심히 보육하겠습니다.</p>
