INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9065,'dus3','김선기','spsp99@naver.com','다윗방 오*진,김*현,김*석 운동화구입(2014.02.28.)','<div>다윗방 오*진,김*현,김*석아동이 운동화를 구입 하였습니다.운동화가 많이 달아서 새 운동화를 구입 하였습니다.운동화를 구입 하도록 지원해 주셔서 진심으로 감사 드립니다.아동들 모두 새 운동화를 구입해서 기뻐 하였습니다.</div>
