INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9066,'dus3','심주현','pikaccu85@hanmail.net','남산원 아동 새학기 학용품을 준비하였습니다!!(2014.02.27)','<div align="center">오늘 남산원 &nbsp;아동들이 새학기를 앞두고 학용품준비를&nbsp;하였습니다.</div>
