INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9067,'dus3','심주현','pikaccu85@hanmail.net','바울방이 김&장 법률사무소 후원 와플 점심식사를 하였습니다.(2014.02.27)','<p align="left">오늘 바울방 아동들이 김&amp;장 법률사무소 후원 점심식사를 하였습니다.</p>
