INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9068,'dus3','박충일','a7124383@nate.com','다윗방 아동들이 새학기 준비로 학용품을 받았습니다.(2014.02.27)','<div>이제 개학을 앞두고 새학기 준비로 다윗방 아동들이 학용품을 받았습니다. </div>
