        </tr>',731,1393426800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9069,'dus3','이소영','leesy5576@hanmail.net','룻2방 아동들이 김&장 법률사무소 후원 점심식사를하였습니다.(2014.02.27)','<p align="center">2014년 2월 27일 룻2방 아동들이 김&amp;장 법률사무소 후원 점심식사를 하였습니다.</p>
<p align="center">매년 남산원 바자회에서 간식으로 와플을 후원해주시고 계시는 후원자님들께서</p>
