        </tr>',683,1393426800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9071,'dus3','김선기','spsp99@naver.com','다윗방아동들 신장,체중 측정(2014.02.26.)','<div>다윗방 아동들이 신장과 체중을 측정 하였습니다.다윗방 아동들이 많이 키가 자라고 몸무게가 늘었습니다.아동들 모두 키가 자라고 몸무게가 늘어 기뻐 하였습니다.다윗방 아동들이 건강하게 잘 자랄 수 있도록 지원 하겠습니다.</div>
