INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9081,'dus3','정다올','ekdhf1989@naver.com','박윤지 후원자님께서 바울방 아동에게 신발을 후원해주셨습니다.(2014.02.24)','<p>바울방 아동 이승민,배진욱, 박승호 아동에게</p>
