INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9083,'dus3','심주현','pikaccu85@hanmail.net','바울방 귀요미 삼총사가 서울침례교회에 참석하였습니다!(2014.02.23)','<p>저번주에 의젓한 형님이 되어&nbsp;룻방에서 바울방에 새로온 배진욱, 박승호, 이승민 아동이</p>
<p>이번주 부터 서울 침례교회에 참석하게 되었습니다. </p>
<p>다른 친구들과 함께 색종이로 깃발도 만들고 율동과 찬양도 하는 등 즐거운 시간을 보냈습니다. </p>
<p>귀요미 삼총사 아이들이 종교활동을 즐겁게 참여할 수 있도록 지원하겠습니다. ^^</p>          </td>
        </tr>',766,1393167600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9085,'dus3','이소영','leesy5576@hanmail.net','룻2방 유*이의 생일파티사진입니다.(2014. 02. 22)','<p align="center">2014년 2월 22일 룻2방 맏언니 유*이의 열일곱번째의 생일을 맞아</p>
<p align="center">룻2방 아이들 모두 저녁식사를 하며 언니의 생일을 축하해주었습니다.</p>
