        </tr>',721,1393081200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9086,'dus3','남산원','jblee4@naver.com','다윗방 오*진,오*진아동이 후원자님께 선물을 받았습니다(2014.02.22)','<div>다윗방 형제인 오*진, 오*진아동이 박*성후원자님께 맛있는 식사와 함께 멋진 옷을 선물받았습니다. 오늘 하루동안 즐거운 시간 보내주시고 옷 선물까지 해주셔서 진심으로 감사드립니다^^*&nbsp;</div>
<div>&nbsp;</div>
<div>&nbsp;</div>
