INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9088,'dus3','박충일','a7124383@nate.com','다윗방 환일중신입생 3총사아동이 신입생OT에 참가하였습니다. (2014.02.21)','<div>남산초등학교를 졸업하고 환일중학교에 입학하는 다윗방 김*현, 김*, 김*수 아동이 새로 구입한 교복을입고 오늘 신입생 오리엔테이션(21일~22일 1박 2일 / 충남 태안 청포대)에 참가하기 위해 학교에 갔습니다. 금년에 입학하는 신입생들을 대상으로 보다나은 학교생활을 준비토록 하기 위하여 교육과정, 학업성적관리, 생활지도 및 중학교 생활에 필요한 전반적인 사항을 프로그램 짜여진&nbsp;신입생 오리엔테이션에 잘 참여하고 새로운 학교 생활에 적응 잘 하고 공부도 열심히 할 수 있도록 열심으로 지도하겠습니다. 감사합니다. </div>
