INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9087,'dus3','이소영','leesy5576@hanmail.net','룻2방 *별, *진이가 어린이집 졸업을 하였습니다.(2014. 02. 22)','<p align="center">2014년 2월 22일 룻2방 *별, *진이가 어린이집 졸업을 하였습니다.</p>
