INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9090,'dus3','심주현','pikaccu85@hanmail.net','바울방 손*민 아동 후원자님이 주신 선물사진입니다.(2014.02.20)','<p align="left">오늘 *민이 후원자님께서 바울방 아동들에게 간식을 사 주셨습니다.</p>
