INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9092,'dus3','이소영','leesy5576@hanmail.net','룻2방 초등학생아동 경제교육 사진입니다.(2014. 02. 18)','2014년 2월 18일 룻2방 초등학생&nbsp;<span style="text-align: -webkit-center">*</span>민,&nbsp;<span style="text-align: -webkit-center">*</span>연이가 경제교육을 받았습니다.

