INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9097,'dus3','김선기','spsp99@naver.com','바울방 이*결,오*진,정*균아동 다윗방으로 이동(2014.02.17.)','<p>바울방 남산초등학교 5학년에 재학중인 이*결,오*진,정*균아동이 다윗방 으로 방을 이동 하였습니다.바울방에서 오래 생활 하다가 다윗방으로 방을 옮겨 낮설기도 하는데 세아동 모두 다윗방에 올라와 다윗방 아동들과 같이 생활 하게 되 많이 기뻐하고 즐거워 하였습니다.</p>
<p>세아동들이 모두 다윗방 생활 잘 할 수 있도록 지원 하겠습니다.</p>          </td>
        </tr>',728,1392649200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9096,'dus3','김선기','spsp99@naver.com','다윗방 아동들 아침조회시간에 책을 읽습니다(2014.02.17.)','<p>다윗방 아동들이 자신들이 좋아하는 책을 가지고 내려가서 아침조회 시간에 책을 읽었습니다.다윗방에 올라&nbsp;온&nbsp;아동들도&nbsp;적응을 잘하며 아침 일찍 조회시간전에 내려가 책을 읽었습니다.</p>          </td>
        </tr>',713,1392649200,'', '', '', '', '', '');
