INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9101,'dus3','김성재','thunderdog9@naver.com','모세방 김*진 아동 졸업식(2014.02.14.)','<div>모세방 김*진 아동이 한강미디어고등학교 사진과 3년 과정을 무사히 마치고 2월 14일 졸업을 하였습니다. 원내에서도 모범적으로 생활하고&nbsp;동생들을 잘 챙기는 만큼 학교에서도 행실이 바르고 타의 모범이 되어 선행상도 받아 원장님과 국장님도 매우 기뻐하셨습니다. 졸업식 후에는 인근 식당에서 이른 저녁식사를 하며 즐거운 시간을 보냈습니다. 한*이는 유니클로에 취직하여 지난 가을부터 열심히 사회생활을 해오고 있습니다. 퇴소를 앞둔 한*이가 사회인으로서 자신의 몫을 충분히 해 나갈 수 있기를 기원합니다.</div>
<div>&nbsp;</div>
<div>&nbsp;</div>
<div>&nbsp;</div>
<div>&nbsp;</div>
<div>아동의 인권존중과 아동 개인정보 보호로 인하여 개인적인 아동들에 사진을 올리지 못함을 양해 부탁 드립니다.<br>홈페이지 관리 모세방 생활지도교사 김선기올림.</div>          </td>
        </tr>',740,1392562800,'', '', '', '', '', '');
