INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9106,'dus3','박충일','a7124383@nate.com','다윗방 김*수,김*,김*현아동이 코엑스아쿠아리움에 다녀왔습니다.(2014.2.15)','<div>롯데마트 후원행사로 다윗방 김*수 김*현 김*아동이 코엑스 아쿠아리움에 다녀왔습니다.</div>
