INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9107,'dus3','심주현','pikaccu85@hanmail.net','바울방이 코엑스 아쿠아리움에 다녀왔습니다(2014.02.15)','<p>오늘 바울방 아동들과 함게 롯데마트 후원프로그램으로 코엑스 아쿠아리움에 다녀왔습니다. </p>
