INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9120,'dus3','이소영','leesy5576@hanmail.net','룻2방 유*이가 졸업을하여 졸업선물을 받았습니다.(2014. 02. 08)','<p>2014년 2월 7일 룻2방 맏언니 유*이가 졸업을 하여 졸업앨범과 졸업선물을 받았습니다.</p>
<p>친구들과 용산공원에서 찍은 사진이 이쁘게 나와 귀가후에도 담당교사와 동생들과 사진을 보며 졸업을 축하하였습니다.</p>
<p>&nbsp;유*이가 중학교 생활을 잘 마무리하고 고등학교 생활을 잘 할 수 있도록 지원하겠습니다.</p>

<p><br></p>
<p><br></p>
<p>아동의 인권존중과 아동 개인정보 보호로 인하여 개인적인 아동들에 사진을 올리지 못함을 양해 부탁 드립니다.</p>          </td>
        </tr>',751,1391871600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9119,'dus3','김성재','thunderdog9@naver.com','환일중 김*철, 임*현 졸업(2014.02.07.)','<p>지난 금요일, 모세방 김*철 아동과 임*현 아동이 3년 개근으로 졸업을 하였습니다. 실업계 고등학교로 진로를 정한 두 아동은 각각 성동공고와 성수공고에 진학하여 입학을 앞두고 있습니다. 두 아동의 졸업을 진심으로 축하하며 고등학교에 진학해서도 성실하게 원내 및 학교생활에 임할 수 있도록 많은 응원 부탁드리겠습니다.</p>          </td>
        </tr>',743,1391958000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9121,'dus3','이소영','leesy5576@hanmail.net','룻2방 *선이가 칭찬왕이되어 외출을다녀왔습니다.(2014. 02. 09)','<p>룻2방에서는 한달마다 룻2방에서 가장 성실하고 바르게 생활한 아동을 칭찬왕으로 뽑아 담당교사와 외출을 하고있습니다.</p>
<p>2014년 2월 9일&nbsp;<span style="text-align: -webkit-center">*</span>선이가 룻2방의 1월의 칭찬왕이 되어 담당교사와 외출을 다녀왔습니다.</p>
<p>대학로에가서&nbsp;연극도보고 북카페에 가서 책을 읽고&nbsp; 저녁에는&nbsp;<span style="text-align: -webkit-center">*</span>선이가 좋아하는 피자도 먹으며 즐거운 시간을 보내고 귀가하였습니다.</p>
<p>남산원에서 가장 모범이 될 정도로 바르고 이쁘게 성장하고 있는&nbsp;<span style="text-align: -webkit-center">*</span>선이가 앞으로도 원내생활을 잘 할 수 있도록 지도하겠습니다.　　</p>
<p>&nbsp;</p>
<p><br /></p>
<p>아동의 인권존중과 아동 개인정보 보호로 인하여 개인적인 아동들에 사진을 올리지 못함을 양해 부탁 드립니다.</p>          </td>
        </tr>',753,1391871600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9123,'dus3','송명은','happysme@hanmail.net','룻2방 *희가 박재현선생님과 즐거운 주말오후시간을 보냈습니다.(2014.02.08)','일주일에 한번 남산원을 방문하셔서 룻2방&nbsp;<span style="text-align: -webkit-center">*</span>희의 영어학습지도를 해주시는 박재현선생님께서 눈이 내리고 쌀쌀한 날씨에도 불구하고&nbsp;<span style="text-align: -webkit-center">*</span>희와의 즐거운 데이트 약속을 지켜주셨습니다. 선생님으로 인해서 우리&nbsp;<span style="text-align: -webkit-center">*</span>희가 학습에 대한 흥미가 많이 생겨서 너무나 뿌듯하답니다. 오늘도 재미있는 영화관람과 맛있는 식사시간을 통해서&nbsp;<span style="text-align: -webkit-center">*</span>희와의 관계형성을 해주신 박재현선생님께 다시한번 감사드립니다.          </td>
        </tr>',741,1391785200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9122,'dus3','송명은','happysme@hanmail.net','룻2방이 소치 동계올림픽 개막식을 축하하였습니다.','<p>2014년 소치 동계올림픽 개막을 축하하는 의미로 룻2방 가족들은 저녁식사후에 즐거운 윷놀이를 하였습니다. 구정연휴때 재미있게 했던 윷놀이를 기억하며 팀을 나눠서 긴장되는 마음을 감추지 못하면서 재미있게 게임을 하는 아동들이 너무나 귀여웠습니다.</p>
<p>동계올림픽이 끝나는 날까지 아동들과 함께 열심히 우리나라 선수들을 응원하면서 애국심을 키울 수 있도록 열심히 보육하겠습니다.</p>          </td>
        </tr>',740,1391785200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9124,'dus3','송명은','happysme@hanmail.net','룻2방 아동들이 아동실종,유괴예방교육에 참석하였습니다.(2014.02.08)','<p>하얀눈이 예쁘게 내리는 토요일 오전시간에 룻2방 미취학,초등부 아동들은 "아동 ,실종유괴예방교육"에 참석하였습니다.&nbsp;</p>
<p>다음달이면 초등학교에 하게 되는&nbsp;<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">별,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진이에게는 꼭!필요했던 유익한&nbsp;교육시간이었습니다.</span></p>
<p>아동들이 안전한 생활을 할 수 있도록 열심히 보육하겠습니다.</p>          </td>
        </tr>',702,1391785200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9127,'dus3','박현정','kingi109@naver.com','한나방 설날세배드리기 프로그램(2014.01.31)','<p>&nbsp;* 한나방 아동들도 설날 세배드리기를 하였습니다.</p>
<p>&nbsp;&nbsp; 많이 성숙해지고 의젓해진 모습으로 부모님께 세배를 드렸는데요,</p>
<p>&nbsp;&nbsp; 선진이는 이번에 고3이 되서 진로에 대해 많은 고민을 하고 있는 중에 엄마께서 선진이</p>
<p>&nbsp;&nbsp; 를 응원해주셨고, 혜연이는 고등학교에 입학하기 때문에 좀 더 성실히 학교생활에 임할</p>
<p>&nbsp;&nbsp; 수 있기를 바라셨습니다. 늘 지금처럼만 행복하고 즐겁게 생활하길 응원합니다. </p>          </td>
        </tr>',727,1391698800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9125,'dus3','정다올','ekdhf1989@naver.com','바울방 아동들이 아동실종 유괴 예방교육을 하였습니다.(2014.02.08)','<p>바울방 아동들이 이소영 선생님이 주최하신</p>
<p>아동실종 유괴 예방교육 프로그램에 참여 하였습니다.</p>
<p>아동들이 그동안 잘 모르고 지나갔던 것에 대해서 </p>
<p>알수 있었고, 앞으로 일이 발생하면 대처할수 있도록</p>
<p>교육을 하여서 유익한 시간이 되었습니다.^^</p>          </td>
        </tr>',722,1391785200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9131,'dus3','심주현','pikaccu85@hanmail.net','바울방 오*진, 이*슬 아동이 상장을 받았습니다.(2014.02.05)','<p>바울방 오*진, 이*슬 아동이 2학기 동시외우기에 열심히 노력하여 동상과 금상을 받아왔습니다. 평소 열심히 생활하는 두 아이들이 학교에서 상을 받아와 매우 대견하고 뿌듯하였습니다. 앞으로도 학교생활을 열심히 할 수 있도록 지원하겠습니다. ^^</p>          </td>
        </tr>',697,1391612400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9133,'dus3','김선기','spsp99@naver.com','다윗방 김*수,김*,김*아동이 세배를 드렸습니다.(2014.02.03.)','<p>가정방문으로 인해 설명절에 세배를 하지 못한 다윗방 김*수,김*,김*아동이 오늘 저녁에 원장님과 국장님께 세배를 하였습니다.원장님과 국장님 께서는 기뻐 하셨고 아동들 모두 즐거워 하였습니다.</p>          </td>
        </tr>',735,1391353200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9134,'dus3','송명은','happysme@hanmail.net','룻2방 *영, *연이가 이윤지선생님께 새해선물을 받았습니다.(2014.02.03)','<p>일주일에 두번 남산원을 방문하셔서 룻2방 *영,*연이의 피아노수업을 지도해주시는 이윤지 선생님께서 오늘은 새해를 맞이해서 *영,*연이에게 예쁜 문구세트를 선물해주셨습니다.</p>
<p>항상 아이들을 생각해주시는 선생님의 그 따뜻한 마음에 깊은 감사드립니다.</p>
<p><br /></p>
<p><br /></p>
<p>아동의 인권존중과 아동 개인정보 보호로 인하여 개인적인 아동들에 사진을 올리지 못함을 양해 부탁 드립니다.</p>          </td>
        </tr>',714,1391353200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9132,'dus3','박충일','a7124383@nate.com','다윗방 김*현, 김*아동이 상장을 받았습니다.(2014.02.03)','<p>남산초등학교 6학년에 재학중인 김*현,김*아동이 2학기 동안 주어진 동시를 꾸준히 외워 아름다운 마음 가꾸기에 열심히 노력하여 금상과 동상 상장을 받았습니다. 예비 중학생으로 보습학원에도 열심히 다니고 있고 금일 중학교 배정도 받아 대견스럽고 뿌뜻하였습니다. 중학교생활도 잘 적응하고 공부도 열심히 할 수 있도록 열심으로 지도하겠습니다. 감사합니다. </p>          </td>
        </tr>',780,1391439600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9135,'dus3','송명은','happysme@hanmail.net','룻2방의 막내인 *현이가 충무어린이집에 등원하였습니다.(2014.02.03)','룻2방의 막내공주님인 *현이가 오늘부터 충무어린이집에 등원하게 되었습니다.&nbsp;
<div>올해 5살이 된 *현이는 충무어린이집에 첫 등원을 해서 달님반으로 배정이 되었답니다. 이번주 일주일은 적응기간이라서 조금 일찍 하원하게 되었는데 처음 만나는 선생님의 지도에도 잘 따르고 점심도 맛있게 잘 먹었다고 달님반 선생님께서 칭찬을 해주셨습니다.

<div>우리 *현이가 앞으로도 어린이집을 다니면서 여러가지 다양한 유익한 경험들을 하면서 올바르게 성장할 수 있도록 열심히 보육하겠습니다.</div>
<div>충무어린이집 달님반 김*현~ 화이팅!!^^</div></div>          </td>
        </tr>',708,1391353200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9136,'dus3','송명은','happysme@hanmail.net','룻2방 아동들이 1월 모범아동 상금을 받았습니다.(2014.02.02)','남산원의 원훈인 "바른인성을 교육받아 자립한다"에 맞는 아동으로 성장할 수 있도록 일상적인 생활에서의 태도에 대한 보육을 하는 과정에서 모범아동에게 상금을 지급하였습니다. 룻2방 아동들도 평소의 올바른 생활태도에 대해 더 열심히 지도해서 어디서나 모범적인 아동으로 성장할 수 있도록 보육하겠습니다.          </td>
        </tr>',721,1391266800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9137,'dus3','정다올','ekdhf1989@naver.com','바울방 아동들이 아동모범상금을 받았습니다.(2014.02.02)','<p>바울방 아동 오성진, 최남명, 오영재 아동이</p>
<p>아동 모범 상금 시상식에서</p>
<p>상금을 받았습니다.</p>
<p>앞으로도 아동들이 아침에 일찍 일어나는 </p>
<p>습관을 들이도록 하겠습니다.^^</p>          </td>
        </tr>',702,1391266800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9140,'dus3','송명은','happysme@hanmail.net','룻2방 아동들이 구정연휴 나들이 프로그램을 다녀왔습니다.(2014.02.01)','갑오년 새해를 맞이하여 구정연휴 세번째날에는 룻2방 가족 모두가 찜질방에 다녀왔습니다. 아침일찍 출발해서 찜질방에 도착해 몸과 마음을 깨끗히 씻고 모두 함께 맛있는 점심과 저녁까지 먹으면서 하루종일 신나고 즐거운 시간을 보냈습니다. &nbsp;룻2방의 막내인&nbsp;<span style="text-align: -webkit-center">*</span>현이도 언니들과의 첫 나들이 시간이 마냥 신나고 즐거웠는지 하루종일 언니들과 함께 뛰어다니면서 행복한 새해를 맞이하였습니다. 아동들이 지금처럼 건강하고 씩씩하게 성장할 수 있도록 열심히 보육하겠습니다.          </td>
        </tr>',680,1391180400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9138,'dus3','김선기','spsp99@naver.com','다윗방아동들상점시상에서상금을받았습니다.(2014.02.02.)','다윗방아동들이 상점시상에서 상금을 받았습니다.아동들 모두 기뻐하고 즐거워 하였습니다.다윗방 아동들이 더욱더 원내생활 잘 할수 있도록 지도 하겠습니다.          </td>
        </tr>',747,1391266800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9139,'dus3','김선기','spsp99@naver.com','다윗방설명절단합대회(2014.02.01.)','<p>다윗방아동들이 설명절을 맞이 하여 드래곤스파 찜질방에 다녀왔습니다.찜질방에 가서 목욕도 하고 맛있는 음식을 먹으며 많은 시간 휴식을 하였습니다.아동들에게 유익한 시간들 이었습니다.</p>          </td>
        </tr>',721,1391266800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9141,'dus3','정다올','ekdhf1989@naver.com','바울방아동들이설날연휴 나들이를 다녀왔습니다.(2014.02.01)','<p>바울방 아동들 오성진, 최남명, 오영재 아동과 함께</p>
<p>용산역에 가서 겨울왕국 더빙판을 관람 하고 팝콘도 먹고</p>
<p>아이파크에 있는 아이스링크 장에서 스케이트를 탔습니다.</p>
<p>스케이트를 탄후에 아이들과 함께 치즈 닭갈비를 </p>
<p>먹고 비가오는관계로 한옥마을은 구경을 못하고</p>
<p>집으로 돌아왔습니다.</p>
<p>아이들이 무척 즐거워 하였고, 지하철에서도 장난을 치지 않아서</p>
<p>대견스러웠습니다.^^</p>          </td>
        </tr>',724,1391180400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9143,'dus3','심주현','pikaccu85@hanmail.net','바울방 아동이 즐거운 설날을 보냈습니다!!(2014.01.31)','<p>오늘 아침 남산원 식구들이 다 함께 모여 차례지내기를 하였습니다. </p>
<p>막내 승민이 부터 퇴소아동까지 참여하여 최기석 설립원장님께 새해 인사를 드리는 뚯깊은 자리를 가졌습니다. </p>
<p>차례지내기를 마치고 남산원 아빠, 엄마께 나와 세배를 드리고 덕담을 받았는데요^^</p>
<p>아이들 얼굴에 절로 미소가 지어지는 시간이었습니다. </p>
<p>오후에는 바울방 친구들과 함께 시내에 나가서 멀티방에 가 보았는데요~</p>
<p>아이들과 함께 wii 게임도 하고 맛있는 고기도 먹는 시간을 가졌습니다. </p>
<p>청계천 산책을 하면서 새해 다짐도 해보는 귀한 시간이 되었습니다. </p>
<p>2014년에도 멋진 바울방이 되기 위해 노력하겠습니다. </p>
<p>감사합니다!! 새해 복 많이 받으세요!!</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',724,1391094000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9142,'dus3','박충일','a7124383@nate.com','다윗방아동들이 설명절날 세배하고 세뱃돈을 받았습니다. (2014.01.31)','<p>설 명절을 맞이하여 전날 절하는법을 배운 그 실력을 가지고 아빠엄마께 세배를 하고</p>
<p>세뱃돈을 받았습니다. 아빠엄마말씀대로 열심히 공부하고 건강하고 예의바르게 자랄게요~</p>
<p>새해복많이 받으시고 건강하세요~~^^* </p>          </td>
        </tr>',698,1391094000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9144,'dus3','이소영','leesy5576@hanmail.net','룻2방 아동들이 설날차례를지내고 세배를하였습니다.(2014. 01. 31)','2014년 1월 31일 룻2방&nbsp;<span style="text-align: -webkit-center">*</span>현,&nbsp;<span style="text-align: -webkit-center">*</span>민,&nbsp;<span style="text-align: -webkit-center">*</span>연,&nbsp;<span style="text-align: -webkit-center">*</span>선,&nbsp;<span style="text-align: -webkit-center">*</span>진이가 설날 아침 어른들께 새배를 하여 세뱃돈도 받고 어제 만들었던 명절음식으로 차례를 지내고 명절음식을 먹으며 남산원 가족들과 함께 시간을 보냈습니다. 남산 아빠, 엄마께서 덕담과 함께 준비해주신 세뱃돈을 받고 아이들 모두 신나고 재미있는 명절을 보냈습니다.

<div>올해에도 아이들이 건강하고 바르게 성장할 수 있도록 지원하겠습니다.</div>          </td>
        </tr>',732,1391094000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9146,'dus3','남산원','jblee4@naver.com','다윗방 아동들이 예절교육과 명절음식만들기 및 영화관람을 하였습니다.(2014.01.30)','<p>다윗방 아동들이 설 명절을 맞이하여 오전에 강당에서 한복입는법과 절하는 법등 예절교육을 받고 오후에는 명절음식만들기로 명태전과 동그랑땡전을 만들었습니다. 음식도 잘 만들고 마무리 뒷정리까지 깔끔하게 정리하는 모습에 대견스러웠습니다.^^*&nbsp; 그리고 저녁을 먹고 명동역CGV에서 영화관람도 하였습니다.&nbsp;연휴 첫날을 알차고 재미있게&nbsp;보냈습니다. </p>          </td>
        </tr>',757,1391007600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9147,'dus3','이소영','leesy5576@hanmail.net','룻2방 아동들이 명절음식만들기 프로그램에 참여하였습니다.(2014. 01. 30)','2014년 1월 30일 설날 명절을 맞이하여 룻2방 초등학생&nbsp;<span style="text-align: -webkit-center">*</span>민,&nbsp;<span style="text-align: -webkit-center">*</span>연이와 중학생&nbsp;<span style="text-align: -webkit-center">*</span>선,&nbsp;<span style="text-align: -webkit-center">*</span>진이가 명절음식을 만들었습니다.

<div>동그랑땡과 동태전등 명절음식을 만드는 법과 명절에 먹는 음식, 차례상 차리는 법 등 음식을 만들며 설날에 대한 여러가지 교육도 받았습니다.</div>
<div>막내&nbsp;<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">민이부터 큰언니&nbsp;</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진이까지 함께 하며 마무리까지 깔끔하게 마쳤습니다.</span></div>
<div>&nbsp;명절기간동안 아이들과 맛있는 음식을 먹으며 재미있게 보낼 수 있도록 지원하겠습니다.</div>
<div><br /></div>
<div><br /></div>
<div>아동의 인권존중과 아동 개인정보 보호로 인하여 개인적인 아동들에 사진을 올리지 못함을 양해 부탁 드립니다.</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',712,1391007600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9148,'dus3','이소영','leesy5576@hanmail.net','룻2방 아동들이 설날 한복입기예절교육을 받았습니다.(2014. 01. 30)','2014년 1월 30일 룻2방&nbsp;<span style="text-align: -webkit-center">*</span>현,&nbsp;<span style="text-align: -webkit-center">*</span>민,&nbsp;<span style="text-align: -webkit-center">*</span>연,&nbsp;<span style="text-align: -webkit-center">*</span>선,&nbsp;<span style="text-align: -webkit-center">*</span>진이가 설날을 맞이하여 원내에서 한복입기예절교육을 받았습니다.

<div>한복입는 방법과 절하는 방법등 명절 예의에 대해 교육 받고 배운내용을 토대로 한복을 입고 세배를 해보는 시간을 가졌습니다.</div>
<div>&nbsp;실생활에 꼭 필요한 교육으로서 아이들 모두 집중하여 교육을 마쳤습니다. 남은 연휴기간동안에도 아이들이 재미있게 명절을 보낼 수 있도록 지원하겠습니다.</div>
<div><br /></div>
<div>아동의 인권존중과 아동 개인정보 보호로 인하여 개인적인 아동들에 사진을 올리지 못함을 양해 부탁 드립니다.</div>          </td>
        </tr>',741,1391007600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9149,'dus3','정다올','ekdhf1989@naver.com','바울방 아동들이 설을 맞이하여 명절음식을 만들었습니다.(2014.01.30)','<p>바울방 아동들이 설맞이를 준비하면서</p>
<p>명절음식을 만들어 보았습니다.</p>
