INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9151,'dus3','김선기','spsp99@naver.com','다윗방 김*수,김*,김*현아동이 외환은행 나눔재단 프로그램에 참석하였습니다.(2014.01.28)','<p>다윗방 김*,김*현,김*수아동이&nbsp;남산원을 방문해주신 외환은행 나눔재단 후원자분들과 함께 구정을 맞이 하여&nbsp;맛있는 만두를 만들었습니다. 직접 만든 만두를 맛있게 먹으면서 아동들은 매우 기뻐 하였습니다.</p>          </td>
        </tr>',744,1390921200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9150,'dus3','정다올','ekdhf1989@naver.com','바울방 아동들이 설을맞이하여 예절교육을 하였습니다.(2014.01.30)','<p>바울방 아동들이 설을 맞이하여 </p>
<p>남산원에 있는 아동들이 </p>
<p>예절교육인 한복입기에 대해서</p>
<p>배우고 어떻게 입는지에 대해서 </p>
<p>알수 있는 시간이 되었습니다.^^</p>          </td>
        </tr>',714,1391007600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9152,'dus3','정다올','ekdhf1989@naver.com','바울방 아동들이 밀라보탕 아트엠 수업하는 사진입니다.(2014.01.28)','<p>오늘은 4번째 밀라보탕 아트엠을 하는 날이었습니다.</p>
<p>미취학 아동들이 저번시간에 찍은 자신의&nbsp;사진을</p>
<p>직접 가위로 오려서 오페라 하우스 에 붙이고</p>
<p>퍼즐을 오려서 재미있는 놀이를 하였습니다.</p>
<p>항상 저희 아동들에게 즐거운 시간을 만들어</p>
<p>주셔서 감사합니다.^^&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',706,1390834800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9155,'dus3','송명은','happysme@hanmail.net','룻2방 *별,*진이가 필동어린이집에서 행복더하기상을 받아왔습니다.(2014.01.27)','룻2방의 *별,*진이가 지난주에 있었던 중구관내 어린이집이 참석한 &nbsp;"사랑나눔 큰 잔치"발표회에서 발레공연을 선보인후에 "행복더하기상"을 받았습니다. 아동들이 좀 더 다양한 분야에서 많은 경험들을 할 수 있도록 열심히 보육하겠습니다.          </td>
        </tr>',696,1390748400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9154,'dus3','정다올','ekdhf1989@naver.com','바울방 아동들이 외환은행나눔재단 행사에 참여하였습니다.(2014.01.28)','<p>바울방 아동들이 멋있게 한복을 차려입고</p>
<p>외환은행 나눔재단 행사인 만두만들기</p>
<p>행사에 참여하여 만두를 만들고 덕담을 </p>
<p>듣는 시간을 가졌습니다.^^</p>          </td>
        </tr>',694,1390834800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9153,'dus3','송명은','happysme@hanmail.net','룻2방 아동들은 외환은행 나눔재단 프로그램에 참석하였습니다.(2014.01.28)','룻2방 아동들은 오늘 남산원을 방문해주신 외환은행 나눔재단 후원자분들과 함께 구정연휴를 위해 맛있는 만두를 만들었습니다. 직접 만든 만두를 맛있게 먹는 아동들의 모습을 흐뭇하게 바라봐주시는 후원자분들께 진심으로 감사드립니다. 올해 남산원 아동들의 학습지원금을 후원해주신 외환은행 나눔재단 후원자분들과 남산원 아동들과의 즐거운 식사시간이 되었습니다. 앞으로도 남산원을 향한 끊임없는 사랑과 관심 부탁드립니다. 새해 복 많이 받으세요~^^          </td>
        </tr>',706,1390834800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9157,'dus3','박충일','a7124383@nate.com','다윗방아동들이 오후시간 도서실에서 독서를 하였습니다.','<p>책을 좋아하는 다윗방 초등생아동들이 주일 도서실개방시간에 책을 읽었습니다. </p>
<p>양서를 많이 읽고 꿈과 희망이 커지고 그 꿈을 향해 노력할 수 있도록 지도하겠습니다. </p>          </td>
        </tr>',692,1390662000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9158,'dus3','박충일','a7124383@nate.com','다윗방 초등생 3총사가 필동감리교회 주일학교 졸업장을 받았습니다.(2014.01.26)','<p>다윗방 초등생 3총사&nbsp; 김도현, 김용, 김민수 아동이 필동감리교회 아동부를 졸업하여</p>
<p>졸업증을 받아왔습니다. 꽃 편지와함께 T머니를 부상으로 받았습니다. 매 주일마다 하나님의 </p>
<p>말씀을 듣고 지혜롭고 건강하게 잘 자라날 수 있도록 기도부탁드립니다. </p>          </td>
        </tr>',1046,1390662000,'', '', '', '', '', '');
