INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9159,'dus3','이소영','leesy5576@hanmail.net','룻2방 독서시간입니다.(2014. 01. 26)','2014년 1월 26일 주말 오후 도서실이 개방되어 룻2방 아동들이 도서실에가서 다 함께 책을 보았습니다.

<div>방학동안 도서실이 자주 개방되면서 막내&nbsp;<span style="text-align: -webkit-center">*</span>현이까지 집중력이 높아지는 것 같습니다.</div>
<div>아이들에게 책읽는 좋은 습관이 길러질 수 있도록 지속적으로 지원하겠습니다.</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',698,1390662000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9160,'dus3','이소영','leesy5576@hanmail.net','룻2방 *진이가 서울침례교회에서 생일선물을 받았습니다.(2014. 01. 26)','2014년 1월 26일 룻2방 *진이가 서울침례교회 아동부 주일예배를 보고 교회에서 생일파티를 열어주셔서 언니, 오빠, 친구들과 파티를 하고 선물을 받았습니다.

<div>초등학교에 입학하는 *진이에게 도움이 될 책과 *진이가 좋아하는 조각케익도 선물로 주셨습니다.</div>
<div>교회 유치부 졸업을 하고 아동부에 간 지 얼마 지나지 않았지만 교회에서 잘 적응하고 예배를 보는 모습이 기특합니다.</div>
<div>앞으로도 교회활동을 열심히 할 수 있도록 지원하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',701,1390662000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9161,'dus3','정다올','ekdhf1989@naver.com','바울방 아동들이 도서실에서 책읽는 사진입니다.(2014.01.26)','<p>바울방 미취학 아동들과 함께</p>
<p>도서실에 가서 책읽는 시간을 가졌습니다.</p>
<p>아동들이 과학도서에 많은 흥미를 느끼고</p>
<p>재미있게 보고 많이 읽어보도록 하였습니다.^^</p>          </td>
        </tr>',708,1390662000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9162,'dus3','송명은','happysme@hanmail.net','룻2방 *선이가 후원자님께 감사한 선물을 받았습니다.(2014.01.25)','룻2방&nbsp;<span style="text-align: -webkit-center">*</span>선이를 그동안 후원해주시고 계시는 호문애후원자님께서 비가 오는 굳은 날씨에도 남산원을 방문해주셨습니다. 호문애후원자님께서는&nbsp;<span style="text-align: -webkit-center">*</span>선이가 초등학교에 다닐때부터 변함없이&nbsp;<span style="text-align: -webkit-center">*</span>선이에게 많은 관심과 사랑을 보여주신답니다. 오늘은&nbsp;<span style="text-align: -webkit-center">*</span>선이와 함께 외출을해서 맛있는 점심식사를 함께 하시고&nbsp;<span style="text-align: -webkit-center">*</span>선이가 필요한 학생용 화장품을 선물해주셨습니다.

<div>올해 중학교 2학년이 되는&nbsp;<span style="text-align: -webkit-center">*</span>선이가 학교생활과 원내생활에 충실할 수 있는 아동으로 성장할 수 있도록 보육하겠습니다. 감사합니다.</div>          </td>
        </tr>',711,1390575600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9163,'dus3','이소영','leesy5576@hanmail.net','룻2방 초등학생 아동들이 소방안전교육을 받았습니다.(2014. 01. 24)','2014년 1월 24일 룻2방 초등학생&nbsp;<span style="text-align: -webkit-center">*</span>민,&nbsp;<span style="text-align: -webkit-center">*</span>영,&nbsp;<span style="text-align: -webkit-center">*</span>연이가 원내에서 소방안전교육을 받았습니다.

<div>원내에서 불이 났을 경우를 대비한 안전교육과 위험상황에 대한 사례동영상을 보며 불에 대한 위험을 알고 대처방법도 교육 받았습니다.</div>
<div>매년 정기적으로 소방안전교육을 진행하고 있어 아이들이 큰 사고없이 안전하게 생활하고 있는 것 같습니다. 추운날씨 지속적으로 아이들 안전하고 건강하게 성장할 수 있도록 지원하겠습니다.</div>          </td>
        </tr>',681,1390575600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9164,'dus3','정다올','ekdhf1989@naver.com','바울방 초등학교 아이들이 소방안전교육을 받았습니다.(2014.01.24)','<p>오늘 바울방 초등학교 아이들이 </p>
<p>강당에서 임태현 선생님이 교육하시는</p>
<p>소방안전교육을 배웠습니다.</p>
<p>화재가 났을때 어떻게 대처해야 하는지</p>
<p>알려주신 임태현 선생님께 감사드립니다.^^</p>          </td>
        </tr>',735,1390489200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9166,'dus3','이소영','leesy5576@hanmail.net','룻2방의 독서시간 사진입니다.(2014.01.22)','<p>2014년 1월 22일 룻2방 아동들이 원내 도서실을 이용하여 독서하는 시간을 가졌습니다.</p>
<p>겨울방학기간 도서실개방이 자주 이루어지고 있어 아이들이 자습을 하고 읽고 싶은 책을 마음껏 읽고 있습니다.</p>
<p>후원자님들의 도서후원으로 아이들이 다양하고 연령에 맞는 책을 읽을 수 있다는 것이 정말 감사하고 기쁩니다.</p>
<p>남산원에 관심가져주시고 도서후원을 해주시고 계시는 후원자님 감사드립니다.</p>
<p>　</p>
<p>　</p>
<p>　</p>          </td>
        </tr>',707,1390316400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9165,'dus3','송명은','happysme@hanmail.net','룻2방 *영이가 2013년도 12월 칭찬왕이 되어 외출을 다녀왔습니다.(2014.01.23)','2013년도 12월달의 칭찬왕이 된 *영이가 오늘 룻2방 선생님과 함께 즐거운 시간을 보내고 돌아왔습니다.

<div>*영이는 평소에 점심으로 평소에 좋아하는 맛있는 치킨을 먹고 벽화마을이라는 곳에 가서 벽에 그려진 신기한 그림들을 보면서 유익한 시간을 보내고 귀원하였습니다.</div>
<div>2014년도에도 *영이가 동생들에게 모범이 되고 언니들에게도 사랑받는 사랑스러운 아동으로 성장할 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',743,1390402800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9167,'dus3','정다올','ekdhf1989@naver.com','바울방 아이들이 라이언 봉사자님과 놀고 있는 사진입니다.(2014.01.22)','<p>바울방 아이들이 라이언 봉사자님이 오셔서</p>
<p>오랜만에 마당에서 경찰과 도둑이라는 </p>
<p>게임을 하면서 신나게 뛰어 노는 하루가 되었습니다.</p>
<p>아이들이 무척이나 재미있고 신나게 놀고 와서</p>
<p>더 놀고 싶어서 아쉬워 하였습니다.</p>
<p>저희 바울방 아이들과 좋은 시간 보내주셔서 감사합니다.^^</p>          </td>
        </tr>',715,1390316400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9169,'dus3','박충일','a7124383@nate.com','다윗방 김*석아동이 합기도 1단 승단심사합격하였습니다.','<p>다윗방 김*석아동이 태권도와 합기도학원에서 운동을 시작한지 6개월만에 </p>
<p>태권도 1단과 지난 달에 있었던 합기도 1단 승단심사에서 합격하였습니다. </p>
<p>열심히 땀흘려 운동한 결과의 열매가 나타남에 너무나 기쁘고 감사합니다. </p>
<p>앞으로도 꾸준히 열심으로 운동할 수 있도록 지도하겠습니다. 감사합니다. </p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',765,1390316400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9168,'dus3','정다올','ekdhf1989@naver.com','바울방 아동들이 도서실에서 책읽는 사진입니다.(2014.01.22)','<p>바울방 아이들이 선생님과 함께 도서실이 개방하자마자</p>
<p>도서실로 가서 자신이 읽고 싶었던 책을 차분히 앉아서</p>
<p>읽고 자신이 못다한 숙제를 하는 시간을 가졌습니다.</p>
<p>앞으로도 열심히 지도하겠습니다.^^</p>          </td>
        </tr>',669,1390316400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9170,'dus3','심주현','pikaccu85@hanmail.net','바울방 아동들이 환일고 어머니 구연동화 시간에 참여하였습니다!(2014.01.21)','<p>오늘 겨울방학을 맞이 하여 환일고 형들과 어머니께서 방문해 주셔서 아이들을 위해 구연동화를 해주셨습니다. </p>
<p>아이들 귀에 솔깃 솔깃한 이야깃 거리를&nbsp;많이 들었는데요 ^^</p>
<p>중간중간 퀴즈와 그림그리기 활동 등을 통하여 즐겁게 참여할 수 있도록 준비를 많이 해주셨답니다. ^^</p>
<p>추운날씨에도 우리 아이들에게 많은 관심과 사랑을 나눠 주신 환일고 형들과 어머니들께 진심으로&nbsp; 감사드립니다~(^^)(__)(^^)</p>          </td>
        </tr>',719,1390230000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9171,'dus3','송명은','happysme@hanmail.net','룻2방 *별,*진이가 중구 국공립 어린이집 발표회에 참석했습니다.','룻2방의 *별,*진이는 필동어린이집 7살 친구들이 참여한 "2014년 중구 국공립 어린이집 발표회"에 참여해서 예쁘고 멋진 발레공연을 선보였습니다.
<div>많은 사람들이 지켜보는 가운데 하는 공연이었는데도 떨지 않고 여유로운 표정으로 그동안 갈고닦은 실력을 선보이는 아이들이 너무나 사랑스러웠습니다.&nbsp;</div>
<div>올해 초등학생이 되는 *별이와 *진이가 어린이집에서 참여하는 마지막 프로그램이라서 그런지 공연이 끝나고 나서도 아쉬운 얼굴이었습니다.

<div>아동들에게 유익한 경험의 시간을 할 수 있도록 해주신 필동어린이집 선생님들께 감사드립니다.^^</div></div>          </td>
        </tr>',725,1390230000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9172,'dus3','송명은','happysme@hanmail.net','룻2방이 환일고 어머니회 구연동화시간에 참석하였습니다.(2014.01.21)','다음주 개학을 앞두고 마지막 겨울방학을 보내고 있는 룻2방 아동들에게 환일고 어머니회에서 방문하셔서 아동들을 위한 재미있는 구연동화를 해주셨습니다. 구연동화 시간 중간에 퀴즈를 맞추는 시간을 만들어서 아동들에게 적극적으로 참여할 수 있는 동기부여도 해주셨습니다. 앞으로도 남산원 아동들을 위해서 많은 관심부탁드립니다. 감사합니다.          </td>
        </tr>',705,1390230000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9173,'dus3','박충일','a7124383@nate.com','다윗방 오*진, 이*늘아동이 안경을 맞추었습니다. (2014.1.20)','<p>다윗방 오*진, 이*늘아동이 안경을 맞추었습니다. 지난 건강검진결과 시력이 좋지않아</p>
<p>안경을 맞추었습니다. 시력이 더 나빠지지 않도록 생활습관을 잘 지키고 안경도 오래 잘 관리해서 쓸 수 있도록 지도하겠습니다.&nbsp; 싸게 구매할 수 있도록 해주신 스마일안경점 사장님과 아빠께 감사합니다. </p>          </td>
        </tr>',811,1390230000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9175,'dus3','류덕례','yoodr1015@hanmail.net','모세방 김*진 생일파티(2014.01.19)','<p>&nbsp;&nbsp;&nbsp;&nbsp; * 모세방의 맏형 *진이의 스무번째 생일파티를 하였습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;졸업을 앞두고 직장과 병행하는 모습이 의젓하고 대견 합니다. </p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 얼마후 자립을 해야하는 *진이가 직장도 원대한 꿈도 모두 성취하길</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 바라며 사회에서 꼭 필요한 인재로 성장하길 기원합니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 생일을 진심으로 축하하며~&nbsp;건강도 챙기길 바란다.</p>
<p>&nbsp;</p>          </td>
        </tr>',756,1390057200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9174,'dus3','심주현','pikaccu85@hanmail.net','바울방 아동들의 독서시간입니다!(2014.01.19)','<p>오늘 주말을 맞아 도서실 개방을 하여 우리 바울방 아동들과 함께 도서실을 찾았습니다. </p>
<p>오늘 내일 바울방 적응훈련을 하는 진욱,승호,승민이도 함께 형들과 도서실에 갔는데요~</p>
<p>형들이 책도 골라주고 옆에서 읽어주는 모습이 유난히 아름다웠던 하루였습니다. </p>
<p>우리 아이들이 밝고 건강하게 잘 자랄수 있도록 지원하겠습니다!!</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',690,1390057200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9178,'dus3','송명은','happysme@hanmail.net','룻2방의 중학생들은 남산교회분들과 함께 강화도에 다녀왔습니다.(2014.01.18)','매주 주일마다 남산교회 예배를 드리는 룻2방의 중학생들은 오늘 남산교회분들과 함께 강화도에 다녀왔습니다.
<div>마니산과 전등사를 관람하고 맛있는 산채비빔밥과 꽃게탕을 먹으면서 즐거운 시간을 보내고 귀원하였습니다.</div>
<div>겨울방학동안 아동들에게 다양한 경험들을 할 수 있도록 후원해주신 남산교회 목사님,사모님을 비롯해서 많은 성도님들께 감사드립니다.</div>          </td>
        </tr>',735,1389970800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9177,'dus3','김선기','spsp99@naver.com','다윗방 이*울아동이 남산교회분들과 함께 강화도에 다녀왔습니다.(2014.01.18)','<p>다윗방 이*울아동이&nbsp;남산교회분들과 함께 강화도에 다녀왔습니다. </p>
<div>마니산과 전등사를 관람하고 맛있는 산채비빔밥과 꽃게탕을 먹으면서 즐거운 시간을 보냈습니다.겨울방학에 아동들에게 다양한 경험들을 할 수 있도록 후원해주신 남산교회 목사님,사모님과 남산교회 교인들께 진심으로&nbsp;감사를 드립니다.</div>          </td>
        </tr>',730,1390057200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9176,'dus3','이소영','leesy5576@hanmail.net','룻2방 미취학, 초등학생 아동 독서시간입니다.(2014. 01. 19)','2014년 1월 19일 남산원 도서실개방으로 점심식사 후 한시간동안 독서하는 시간을 가졌습니다.
<div>룻2방 미취학, 초등학생 아동들 모두 도서실에가서 자신이 읽고 싶은 책을 읽으며 시간을 보냈습니다.</div>
<div>방학기간 중 도서실을 개방해 날씨가 쌀쌀해 외부활동이 힘든 아동들에게 지원을 하고 있는데 남은 방학기간에도 유익한 시간일 될 수 있도록 하겠습니다.</div>
<div>　</div>          </td>
        </tr>',716,1390057200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9180,'dus3','심주현','pikaccu85@hanmail.net','롯데마트 후원자님과 함께하는 영화나들이!! (2014.01.18)','<p>오늘 롯데마트 후원자님과 함께&nbsp; "겨울왕국" 영화관람을 하였습니다.</p>
<p>어린&nbsp;<span style="text-align: -webkit-center">*</span>호,&nbsp;<span style="text-align: -webkit-center">*</span>현이 부터 큰형&nbsp;<span style="text-align: -webkit-center">*</span>철이 까지 함께 영화관람을 하였는데요~</p>
<p>오랜만에 극장에서 관람하는 영화라서 그런지 아이들이 매우 즐거워 하였습니다. </p>
<p>영화 관람 후 맛있는 점심식사 까지 후원자님과 함께하였는데요 ^^</p>
<p>추운날에도 저희 아이들에게 즐거운 주말을 선사해 주신 롯데마트 후원자님들께 진심으로 감사드립니다!!(^^)(__)(^^)</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',720,1389970800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9179,'dus3','송명은','happysme@hanmail.net','룻2방 *진이의 8번째 생일파티를 하였습니다.(2014.01.18)','룻2방의 백설공주인 *진이가 8번째 생일을 맞이하였습니다. 올해 초등학교에 입학하는 *진이는 룻2방의 막내 *현이부터 언니들의 진심어린 축하를 받으면서 즐거운 생일파티를 하였습니다. 요즘 초등학교 입학준비를 하느라 열심히 한글공부를 하고 있는 우리 *진이가 앞으로 많은 사람들에게 사랑받고 칭찬받는 아동으로 성장할 수 있도록 보육하겠습니다.

<div>사랑받기 위해 태어난 *진아~</div>
<div>지금까지 받아왔던 사랑보다 더많은 사랑을 받으면서 건강하게 생활할 수 있도록 기도할께~</div>
<div>생일 축하해~^^</div>          </td>
        </tr>',699,1389970800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9181,'dus3','정다올','ekdhf1989@naver.com','바울방 박*호 아동과 김다솜 학습선생님 나들이 사진입니다.(2014.01.17)','<p>바울방 박*호 아동이 자신의 학습 선생님인 김다솜선생님과</p>
<p>함께 나들이를 다녀왔습니다.</p>
<p>김다솜 선생님 손을 꼭 잡고 지하철을 타보고 좀 무서워 하긴 </p>
<p>했지만 재미있었다고 하였고, 과학관 탐방을 가서 자신의 </p>
<p>손을 본떠서 손 모양을 만들고 여러가지 달을 보고 </p>
<p>하늘에 떠있는 별을 보면서 많이 신기해 하였습니다.</p>
<p>저희 *호와 재미있고 유익한 시간을 보내주셔서</p>
<p>감사드립니다.*^^*</p>          </td>
        </tr>',756,1389884400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9182,'dus3','이소영','leesy5576@hanmail.net','룻2방 나*가 후원자님께 선물을 받았습니다.(2014.01.17)','2014년 1월 17일 룻2방 나*가 후원자님께 영양제를 선물받았습니다.
<div>또래아이들에 비해 작고 외소한 나*에게 필요한 영양제를 선물해주셔서 나리가 무척 좋아했습니다.</div>
