INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9183,'dus3','송명은','happysme@hanmail.net','룻2방이 축령산으로 새해맞이 등산프로그램을 다녀왔습니다.(2014.01.16)','새해를 맞이하여 룻2방 중학생 아동들은 축령산 휴양림으로 등산을 다녀왔습니다. 갑오년 새해에 각자가 세운 계획들을 다시한번 되새기면서 굳은 의지를 가지고 올 한해도 열심히 생활하기 위한 다짐을 하고 내려왔습니다. 여자 아동들이 등산을 하기에는 조금 힘든 코스들도 있었지만 특별한 사고없이 무사히 산행을 완주하였습니다. 어리게만 보았던 아이들이 중간에 포기하지 않고 끝까지 완주하는 모습이 대견스러운 하루였습니다. 오늘 축령산을 오르면서 각자가 했던 다짐들을 잊지 않으면서 올 한해도 힘내서 화이팅!!할 수 있도록 열심히 보육하겠습니다. ^^          </td>
        </tr>',736,1389884400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9184,'dus3','심주현','pikaccu85@hanmail.net','바울방 아동들이 축령산으로 등산을 다녀왔습니다.(2014.01.16)','<p>오늘 바울방 아동들이 남산원 중,고&nbsp; 형.누나들과 함께 축령산에 다녀왔습니다. </p>
<p>겨울방학을 맞아 심신을 단련하고자 남산원 식구들이 출동을 하였는데요^^</p>
<p>이른 아침부터 준비하여 모두 다함께 즐겁게 다녀왔습니다. </p>
<p>겨울산행이라 아이젠을 착용하여 아동모두 안전하게 다녀왔답니다^^</p>
<p>아이들 모두가 즐겁게 참여하여 더욱 뜻깊었던 하루가 되었던 것 같습니다. </p>
<p>아이들이 건강하게 생활할 수 있도록 보육하겠습니다!!</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',746,1389798000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9185,'dus3','박충일','a7124383@nate.com','다윗방아동들이 축령산휴양림으로 등산대회 다녀왔습니다.(2014.01.16)','<p>겨울방학동안 날씨관계로&nbsp;활동량이 적었는데 오늘 아빠와 선생님들과 모두 다함께 </p>
<p>축령산휴양림으로 등산을 다녀왔습니다. 겨울산이라 아이젠을 착용하고 안전하게 잘 다녀왔</p>
<p>습니다. 간식도 먹고 하산길&nbsp;눈미끄럼도 타고 저녁으로 외식을 하고 귀원하였습니다.</p>
<p>즐거운 추억이 하나 더 생겼습니다. 함께 해주신 이광선선생님께도 감사드립니다. </p>          </td>
        </tr>',792,1389798000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9186,'dus3','이소영','leesy5576@hanmail.net','룻2방 나*가 후원자님께 선물을 받았습니다.(2014. 01. 15)','2014년 1월 15일 룻2방 나*가 열다섯번째 생일을 맞아 박숙영 후원자님께 책을 선물 받았습니다.
<div>"어쩌다 중학생 같은 걸 하고 있을까"라는 중학교 2학년에 돌입한 스미레의 일상을 통해 이 시대 청소년의 상황과 속내를 가감 없이 보여 주는 성장기 소설로 나*에게 필요한 도서를 선물해주셨습니다.</div>
<div>학습이 종결된 이후에도 나*와 관계형성해주시며 관심갖고 지켜봐주시는 박숙영 선생님 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　&nbsp;</div>          </td>
        </tr>',750,1389711600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9187,'dus3','이소영','leesy5576@hanmail.net','룻2방 강*리아동 생일파티사진입니다.(2014. 01. 15)','2014년 1월 15일 룻2방 *리의 열다섯번째 생일을 맞아 저녁 생일파티를 하였습니다.

<div>평소 인간관계가 좋고 인기가 많아 언니, 동생들에게 많은 축하를 받으며 기분좋게 하루를 보냈습니다.</div>
