INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9204,'dus3','박충일','a7124383@nate.com','다윗방 중학생아동들이 중구보건소에서 건강검진을 받았습니다.(2014.1.8)','오전에 다윗방 아동들이 중구보건소에 가서&nbsp; 키 몸무게 검사, 시력검사, 소변검사, 흉부x-ray검사, 혈액검사를 하고 왔습니다. 우리 아동들이 건강히 잘 자랄 수 있도록 열심으로 보육하겠습니다.          </td>
        </tr>',997,1389106800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9206,'dus3','김성재','thunderdog9@naver.com','이광선 선생님과 함께 한 즐거운 하루(2014.01.08)','<p>남산원의 후원자이신&nbsp;이광선 선생님께서&nbsp;남산원을 방문해 주셨습니다.&nbsp;스포츠 매니아이신 선생님의 제안으로 진행된 프로그램을 통해 다윗방과 모세방 아동들은 운동장에서 농구와 축구로 땀을 한껏 낸 후 인근 찜질방에 가서 묵은 때도 벗기고 찜질도 하며&nbsp;정말 뜨거운 하루를 보냈습니다. 선생님은 앞으로도 주기적으로 방문하셔서 아동들이 겨울 방학동안 방 안에서만 머무르지 않도록&nbsp;함께 야외활동을 해주기로 하셨습니다. </p>          </td>
        </tr>',817,1389106800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9205,'dus3','박충일','a7124383@nate.com','다윗방 아동들이 이광선선생님과함께 운동(축구,농구)과 찜질방에 다녀왔습니다.(2014.01.08)','<p>이광선선생님께서 남산원에 오셔서 다윗방, 모세방 아동들과 함께 농구와 축구를 하시고</p>
<p>찜질방에 가셔서 아동들의 등도 밀어주시고 즐거운 하루를 선물해주셨습니다. </p>
<p>진심으로 감사드립니다. </p>          </td>
        </tr>',837,1389106800,'', '', '', '', '', '');
