INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9209,'dus3','이소영','leesy5576@hanmail.net','룻2방 아동들의 밀라보탕아트엠수업사진입니다.(2014. 01. 07)','2014년 1월 7일 룻2방 초등학생&nbsp;<span style="text-align: -webkit-center">*</span>별,&nbsp;<span style="text-align: -webkit-center">*</span>진,&nbsp;<span style="text-align: -webkit-center">*</span>민이가 밀라보탕아트엠 미술수업을 받았습니다.

