INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9213,'dus3','김선기','spsp99@naver.com','다윗방 아동들 겨울방학생활계획표 시상(2014.01.06.)','<p>다윗방 아동들이 겨울방학을 맞이하여 실시한 겨울방학 생활계획표 만들기에서 </p>
