INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9212,'dus3','이소영','leesy5576@hanmail.net','룻2방 아동들이 건강검진을 받았습니다.(2014. 01. 07)','2014년 1월 7일 룻2방 아이들이 중구보건소에 가서 건강검진을 받았습니다.

