INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9214,'dus3','심주현','pikaccu85@hanmail.net','바울방 박*호, 이*결 아동이 겨울방학 생활계획표 만들기 에서 수상하였습니다.(2014.01.06)','<p>바울방 아동들이 겨울방학을 맞이하여 실시한 겨울방학 생활계획표 만들기에서 </p>
<p>박*호 아동 최우수상, 이*결 아동 우수상을 수상하였습니다. </p>
<p>미취학 *호도 자신의 방학생활에 대해 계획해 보는 시간을 가졌는데요 ^^</p>
<p>열심히 작성하는 우리 아이들의 모습이 굉장히 멋져보였습니다. </p>
<p>방학생활표에 맞춰 보람찬 겨울방학을 보낼 수 있도록 지원하겠습니다!!</p>          </td>
        </tr>',794,1388934000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9215,'dus3','송명은','happysme@hanmail.net','룻2방 *희와 *리가 방학생활계획표 수상을 했습니다.(2014.01.06)','겨울방학을 맞이하여 방학동안의 일과에 대해서 열심히 만들었던&nbsp;<span style="text-align: -webkit-center">*</span>희와&nbsp;<span style="text-align: -webkit-center">*</span>리가 룻2방에서 방학생활계획표 수상을 하게 되었습니다.&nbsp;<span style="text-align: -webkit-center">*</span>희는 최우수상,&nbsp;<span style="text-align: -webkit-center">*</span>리는 우수상과 함께 용돈도 받았습니다. 아이들이 방학기간동안 직접 세운 계획들을 실천할 수 있도록 열심히 보육하겠습니다.^^          </td>
        </tr>',737,1388934000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9218,'dus3','박충일','a7124383@nate.com','다윗방 겨울생활계획표 1등 김*아동(2014.1.2)','겨울방학을 알차게 보내기 위하여 겨울방학생활계획표를 만들었습니다.&nbsp; 어릴적 미술을 배웠던 김*아동의 솜씨가 빛나는 순간이였습니다.&nbsp; 다윗방 아동들이 게임시간을 줄이고 알찬 겨울방학생활이 될 수 있도록 지도하겠습니다.          </td>
        </tr>',793,1388761200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9219,'dus3','박충일','a7124383@nate.com','다윗방 13년도 마지막 날~ 송년의 밤 행사와 축구하기 (2013.12.31)','<p>오랜만에 포근한 날씨에 다윗방아동들 전체가&nbsp; 마당에서 축구 경기를 하였습니다.</p>
<p>몇명 아동은 운동은 뒷전이고 늘 게임만 하였는데 다함께 축구를 하는 모습을 보니 </p>
<p>너무 좋아보였습니다.&nbsp; 저녁에는 13년도 마지막날에는 송년의 밤 행사로&nbsp; 다윗방아동들은</p>
<p>last christmas 를 합창하고 성대모사를 하였습니다. </p>          </td>
        </tr>',753,1388761200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9221,'dus3','이소영','leesy5576@hanmail.net','룻2방 아동들이 겨울방학생활계획표를 만들었습니다.(2014.01.01)','2014년 새해를 맞이해서 룻2방 아동들은 진지한 마음으로 올해 계획들을 생각해보았습니다.
<div>특별히 겨울방학을 알차게 보낼수 있을지 생각을 하면서 방학생활계획표를 만들었습니다.</div>
<div>각자가 운동을 하겠다고 하는 아동과 정해진 시간에 책을 읽고 싶다라는 아동도 있었습니다.</div>
<div>어떤 계획을 세우든지 아동들이 방학기간을 알차게 보낼 수 있도록 열심히 지원하겠습니다.</div>          </td>
        </tr>',794,1388502000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9220,'dus3','심주현','pikaccu85@hanmail.net','바울방 방학생활계획표 만들기 사진입니다.(2014.01.02)','<p>오늘 바울방 아동들과 함께 겨울방학 생활계획표를 작성해 보는 시간을 가졌습니다. </p>
<p>겨울방학을 했지만 우리 아이들은 겨울 솔바람학교로 매일 등교를 하는데요^^</p>
<p>일주일 후면 솔바람 학교도 방학을 하여 아동들이 매우 즐거워 하였답니다. </p>
<p>이번에 유치부 아동들도 있는 솜씨를 맘껏 발휘하여 생활계획표를 작성하였는데요!</p>
<p>어려운 글씨도 씩씩하게 쓰는 영호를 보면서 많이 뿌듯한 시간을 가졌던 것 같습니다. </p>
<p>우리 아이들이 자신의 방학생활을 잘 계획하여 알차게 보낼 수 있도록 지원하겠습니다!!</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',755,1388588400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9222,'dus3','이소영','leesy5576@hanmail.net','2014년 룻2방 아동들은 설날 상차림교육에 참석하였습니다.(2014.01.01)','2014년 갑오년을 시작하는 새해 첫날에 룻2방 아동들은 설날 상차림교육에 참석해서 유익한시간을 보냈습니다.

<div>룻2방의 막내인&nbsp;<span style="text-align: -webkit-center">*</span>현이부터 맏언니인 <span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진이까지 진지한 모습으로 교육에 임하였습니다.</span></div>
<div>2014년도 룻2방 아동들이 건강하고 씩씩하게 생활할 수 있도록 열심히 보육하겠습니다.</div>
<div>많은 관심과 사랑 부탁드립니다.^^</div>
<div>새해 복 많이 받으세요~^^</div>          </td>
        </tr>',737,1388502000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9223,'dus3','김성재','thunderdog9@naver.com','서울클럽 후원선물 받은 모세방 아동들(2013.12.31)','모세방 아동들이 송년의 밤을 맞이하여 장기자랑으로 숨겨왔던 끼도 뽐내고 서울클럽 후원자님들께서 보내주신 선물도 받으며 기분 좋은 2013년 마지막 날을 보냈습니다. 매년 남산원 아동들을 잊지 않고 챙겨주시는 서울클럽 후원자님들께 감사의 마음을 전하며 새해 복 많이 받으시길 기원합니다.          </td>
        </tr>',738,1388502000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9225,'dus3','이소영','leesy5576@hanmail.net','룻2방 아동들이 남산원 송년행사에 참여하였습니다.(2013. 12. 31)','<font face="굴림">2013년 12월 31일 남산원가족들과 함께 하는 송년행사에 룻2방도 참여하여 남산원 아빠의 덕담말씀도 듣고 장기자랑도 하며 다 함께 한 해를 마무리하였습니다.</font>
<div><font face="굴림">룻2방 맏언니 유진이부터 막내&nbsp;</font><span style="text-align: -webkit-center">*</span><font face="굴림">현이까지 그동안 장기자랑준비를 열심히 하며 송년행사 무대에서 준비했던 동요, 율동을 하는 모습이 정말 사랑스러웠습니다.</font></div>
<div><div style="font-family: 굴림">매년 12월 31일 송년의 밤 행사를 하며 아이들과의 시간을 되돌아보고 다함께 마무리하는 것에 대한 의미가 남다른 것 같습니다.</div>
<div style="font-family: 굴림">&nbsp;2014년에도 아이들이 건강하고 이쁘게 성장할 수 있도록 지원하겠습니다.</div></div>          </td>
        </tr>',753,1388502000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9224,'dus3','정다올','ekdhf1989@naver.com','바울방 새해맞이 예절교육 사진입니다.(2014.01.01)','<p>바울방 아동들이 모두 모여 새해 맞이 예정교육을</p>
<p>받았습니다.</p>
<p>차례상 을 차리는 법 부터 왜 동쪽 서쪽 으로 나뉘어서</p>
<p>놓는지를 국장님께서 직접 설명해 주시고 </p>
<p>차례지내는 법을 몸소 보여주시고 체험을 통해서</p>
<p>아동들이 쉽게 알수 있게 해주셨습니다.</p>
<p>아동들이 많은 것을 배울수 있는 계기를 마련해 주셔서</p>
<p>감사드립니다.^^</p>          </td>
        </tr>',738,1388502000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9227,'dus3','박충일','a7124383@nate.com','다윗방 아동들 남산원송년행사에서 서울클럽후원선물을 받았습니다.(2013.12.31)','<p>연말을 맞이하여 서울클럽에서 다윗방아동들에게 귀한 선물을 주셨습니다. 아동 한명 한명 귀한 선물을 해주셔서 진심으로 감사드립니다. 오늘은 특별히 남산원 송년의 밤으로 가족행사가 있었습니다. 각 방마다 장기를 뽑내며 즐겁운 추억을&nbsp; 쌓고 행복한 연말을 보냈습니다. 새해복 많이 받으세요 </p>          </td>
        </tr>',774,1388502000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9228,'dus3','심주현','pikaccu85@hanmail.net','바울방 서울클럽 선물 전달 사진입니다. (2013.12.31)','<p>오늘 송년행사와 함께 서울 클럽 선물 전달식이 있었습니다. </p>
<p>매년 우리 아이들을 위해 한명 한명 선물을  준비해 주시는 데요~</p>
<p>후원자님의 선물이 있어 우리 아이들이 더욱 즐거운&nbsp; 연말 행사가 되었던 것 같습니다. </p>
<p>언제나 우리 아이들에게 많은 관심과 사랑을 나눠 주시는 서울클럽 후원자 분들께 </p>
<p>진심으로 감사드리며 2014년에는 더욱 아동보육을 위해 힘쓰겠습니다!</p>
<p>새해 복 많이 받으세요!! 감사합니다 (^^)(__)(^^)</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',726,1388415600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9226,'dus3','이소영','leesy5576@hanmail.net','룻2방 아동들이 서울클럽후원자님께선물을받았습니다.(2013. 12. 31)','2013년 12월 31일 한 해가 지나는 마지막 날 룻2방 아동들이 서울클럽후원자님들께 선물을 받았습니다.
<div>아이들 연령에 맞춰 선물을 준비해주셔서 아이들이 송년행사를 하며 선물을 받으며 무척 좋아하였고 감사하는 마음을 가지고 한 해를 마무리 할 수 있게 되었습니다.</div>
<div>매년 마지막 날 아이들에게 선물을 후원해주시고 계시는 서울클럽후원자님 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',763,1388502000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9229,'dus3','심주현','pikaccu85@hanmail.net','바울방 송년행사 사진입니다. (2013.12.31)','<p>오늘은 2013년 마지막 날 입니다. </p>
<p>한해를 마무리 하는 날에는 온 가족이 모여 즐거운 파티를 하는데요 ^^</p>
<p>오늘도 역시 아이들이 준비한 장기자랑을 펼치며 다함께 웃는 시간을 가졌답니다!!</p>
<p>바울방에서는 유치부 영호와 영재의 "옥수수하모니카" 합창과 </p>
<p>초등학교 형들의 댄스 임창정의 "문을 여시오" 그리고....하이라이트 유치부가 </p>
<p>정준하의 "정주나요" 댄스를 펼쳤습니다!!</p>
<p>눈 뗄 시간도 없을 만큼 아이들이 너무 멋지게 잘 하였는데요!</p>
<p>그 결과 바울방에 1등을 하였습니다!! 짝!짝!짝!</p>
<p>2013년 우리 아이들을 많이 사랑해 주신 모든 분들께 진심으로 감사드리며 </p>
<p>2014년에도 우리 바울아동들이 멋지고 씩씩하게 성장할 수 있도록 지원하겠습니다.(^^)</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',782,1388415600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9230,'dus3','김성재','thunderdog9@naver.com','모세방 퇴소예비아동 의복구입(2013.12.28)','퇴소를 앞둔 모세방의 김한진, 조영주 아동이 사무실의 지원으로 정장을 구입했습니다. 정장이라는 의복이&nbsp;아직은 몸에 익숙하지 않겠지만&nbsp;성년이 되어서 적어도 한 벌은 꼭 필요하니 잘 보관해뒀다가 필요할 때 요긴하게 입을 수 있길 바라며&nbsp;세탁법 및 보관법도 함께 가르쳐주도록 하겠습니다.          </td>
        </tr>',734,1388415600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9231,'dus3','송명은','happysme@hanmail.net','룻2방 *영,*연이가 이윤지선생님께 따뜻한 선물을 받았습니다.(2013.12.30)','2013년을 하루 앞둔 추운날씨에도 남산원을 방문하셔서 룻2방 *영, *연이의 피아노지도를 해주시는 이윤지선생님께서 오늘은 아이들에게 따뜻한 목도리를 선물해주셨습니다.

<div>&nbsp;추운 날씨에 *영, *연이가 선물받은 목도리를 하고 건강하게 겨울을 보낼 수 있을 것 같습니다.

<div>이윤지선생님~감사합니다~^^</div></div>          </td>
        </tr>',753,1388329200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9234,'dus3','심주현','pikaccu85@hanmail.net','바울방아동들이 남산 가족과 함께 힐튼호텔에서 점심식사를 하였습니다!(2013.12.29)','<p>&nbsp;</p>
<p>오늘 바울방 아동들이 남산 가족들과 함께 힐튼호텔에서 송년파티를 하였습니다. </p>
<p>뷔페에서 점심식사를 하였는데요 ^-^*</p>
<p>모두가 다함께 모여 식사하는 자리인 만큼 그 어느때 보다도 맛있게 식사를 하였습니다!!</p>
<p>2013년을 돌아보며 우리 아이 하나하나 얼굴에 밝은 모습을 보면서 건강하게 잘 지내주어 매우 뿌듯하였습니다. </p>
<p>2014년에도 우리 바울이 들이 건강하고 멋있게 잘 성장할 수 있도록 열심히 보육하겠습니다!!</p>
<p>많이 많이 지켜봐 주세요!!&nbsp; ^-^*</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',727,1388242800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9232,'dus3','박충일','a7124383@nate.com','다윗방 아동들이 남산원가족식사모임에 다녀왔습니다.(2013.12.29)','다윗방 아동들이 남산원 가족식사모임에 다녀왔습니다. 남산원과 가까운 서울힐튼호텔에서 엄마아빠와 선생님들과 형누나동생들과 다함께 맛있는 뷔페를 먹으며 즐거운 추억을 만들고 왔습니다. 아빠께서 아동들에게 식사예절을 가르쳐주고 싶으셔서&nbsp; 이렇게 좋은 곳에서 식사하게 해주셨습니다. 아빠 감사해요 맛있게 잘먹었습니다^^*          </td>
        </tr>',757,1388242800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9233,'dus3','심주현','pikaccu85@hanmail.net','바울방 아동들이 침례교회에서 선물을 받아왔습니다.(2013.12.29)','<p>오늘 바울방 아동들이 침례교회에 다녀왔습니다. </p>
<p>주일 예배를 드리고 크리스마스 선물과 달란트 시장에서 선물을 받아왔는데요^^</p>
<p><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span>민이는 따뜻한 후드티를 영재와 영호는 귀여운 장갑을 선물로 받았습니다!!</p>
<p>우리 아이들에게 많은 관심과 사랑을 나눠 주시는 침례교회 선생님들께 진심으로 감사드립니다. (^^)(__)(^^)</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',749,1388242800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9237,'dus3','정다올','ekdhf1989@naver.com','바울방 아이들이 줄넘기 연습하는 사진입니다,(2013.12.28)','<p>바울방 이<span style="text-align: -webkit-center">*</span>결, 손<span style="text-align: -webkit-center">*</span>민, 이<span style="text-align: -webkit-center">*</span>슬 어린이가</p>
<p>겨울방학 숙제 중에 하나인 줄넘기 연습을</p>
<p>하려고 나와서 줄넘기 연습을 하였습니다.</p>
<p>아이들이 다치지 않도록 항상 곁에서</p>
<p>지켜보고 지원하겠습니다.^^</p>          </td>
        </tr>',716,1388156400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9235,'dus3','이소영','leesy5576@hanmail.net','룻2방이 송년행사 남산원가족점심외식을 하였습니다.(2013. 12. 29)','2013년 12월 29일 룻2방이 남산원 가족모두와 함께 힐튼호텔 뷔페에서 점심외식을 하였습니다.
<div>남산원 가족 모두 다 함께 외식하는 기회가 많지 않아 모두 맛있고 기분좋게 점심식사를 하였습니다.</div>
<div>2013년도 아이들이 큰 사고 없이 건강하고 바르게 성장한 모습을 보니 한해가 잘 마무리 된 것 같습니다. 2014년도에도 아이들이 건강하고 이쁘게 자랄 수 있도록 보육하겠습니다.</div>
