INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9239,'dus3','정다올','ekdhf1989@naver.com','청소년 나눔에서 바울방아동들과 함께 보드게임 활동하는 사진입니다.(2013.12.28)','<p>청소년 나눔에서 선생님들과 </p>
<p>학생들이 남산원에 방문하여서 </p>
