INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9240,'dus3','박충일','a7124383@nate.com','다윗방 3총사초등아동과 이*울아동이 대림산업후원행사에 다녀왔습니다.(2013.12.27)','대림산업후원으로 다윗방 초등생 3총사 아동과 이*울아동이 함께 영화를 보고 아웃백에서 식사를 하며 즐거운 시간을 보내고 왔습니다.&nbsp;

<div>대림산업임직원여러분께 진심으로 감사의 마음 전합니다. 감사합니다.</div>          </td>
