INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9238,'dus3','송명은','happysme@hanmail.net','룻2방 *영, *연, *선이는 애드리안 선생님에게 선물을 받았습니다.(2013.12.28)','매주 토요일마다 남산원을 방문하셔서 룻2방 *영, *연,&nbsp;<span style="text-align: -webkit-center">*</span>선이의 첼로수업을 해주시는 애드리안 선생님께서 아동들에게 크리스마스와 새해선물로 머그컵과 수첩을 선물해주셨습니다.&nbsp;

<div>언제나 아동들을 생각해주시고 사랑해주시는 변함없는 마음에 다시한번 감사드립니다.

<div>내년에도 우리 아이들 잘 부탁드립니다.^^</div></div>          </td>
        </tr>',740,1388156400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9243,'dus3','심주현','pikaccu85@hanmail.net','바울방 아이들이 대림산업 프로그램에 참여하였습니다.(2013.12.27)','<p>오늘 바울방 초등부 아동들과 모세방 안<span style="text-align: -webkit-center">*</span>현 아동이 대림산업 프로그램에 참여하였습니다. </p>
<p>대림산업 후원자님과 함께 성신여대CGV에서 "썬더와 마법저택"을 관람하였는데요 ^^</p>
<p>성신여대까지 후원자님과 함께 지하철을 타고 이동하였습니다. </p>
<p>아직 초등학생 아동들이 지하철을 이용하는 기회가 적어 새로운 경험을 할 수 있는 기회가 되었던 것 같습니다. </p>
<p>영화관람후 충무 아웃백에서 맛있는 저녁식사를 하였는데요 ^^</p>
<p>후원자님과 함께 즐겁게 담소를 나누며 즐거운 식사시간을 보냈답니다. </p>
<p>오늘 날씨가 추워 아이들이 감기에 걸릴까봐 많은 걱정을 해주셨는데요~</p>
<p>늘 아이들을 먼저 생각해 주시고&nbsp; 배려해 주시는 모습에 너무 감사함을 느낀 하루였습니다. </p>
<p>오늘 하루 우리 아이들에게 많은 사랑을 주신 대림산업 후원자 분들께 진심으로 감사드립니다. ^-^*</p>          </td>
        </tr>',745,1388070000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9241,'dus3','이소영','leesy5576@hanmail.net','룻2방 초등학생이 대림산업후원프로그램에 다녀왔습니다.(2013. 12. 27)','2013년 12월 27일 룻2방 초등학생&nbsp;<span style="text-align: -webkit-center">*</span>민,&nbsp;<span style="text-align: -webkit-center">*</span>영,&nbsp;<span style="text-align: -webkit-center">*</span>연이가 대림산업 후원프로그램으로 성신여대CGV에 가서 "썬더와 마법저택"이라는 애니메이션을 보고 아웃백에서 저녁식사를 하고 귀가하였습니다.

<div>오랜만에 지하철을 타고 후원자님, 언니 오빠들과 함께 새로운 경험을 하고 돌아와 신나 기분좋은 모습을 보니 저 역시 기분이 좋았습니다.</div>
<div>아이들의 문화체험을 위해 추운 날씨에도 후원, 봉사해주신 대림산업 후원자님 진심으로 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',742,1388070000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9242,'dus3','박충일','a7124383@nate.com','다윗방아동들이 현대자동차후원 선물을 받았습니다.(2013.12.26)','<p style="line-height: 120%" class="0"><font face="굴림">다윗방 아동들이 현대자동차 후원프로그램에 참여 하였습니다. 예쁜 옷을 선물로 받고 맛있는 피자와 치킨을 먹으면서 기쁜 저녁시간을 보냈습니다. 남산원 아동들에게 귀한 선물을 후원해 주신 현대자동차지역본부 후원자님들께 진심으로 감사를 드립니다.</font>&nbsp;</p>          </td>
        </tr>',733,1388070000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9244,'dus3','이소영','leesy5576@hanmail.net','룻2방 *현이가 후원자님께 선물을 받았습니다.(2013. 12. 27)','2013년 룻2방 *현이가 미군계약처 후원자님께 크리스마스선물을 받았습니다.

<div>*현이가 좋아하는 인형과 이쁜 원피스를 선물받아 너무 좋아하는 모습이였습니다.</div>
<div>추운날씨에도 직접방문하셔서 선물도 전달하고 짧은시간이지만&nbsp;<span style="text-align: -webkit-center">*</span>현이와 시간을 보내고 가셨습니다. 항상 관심가지고 이쁘게 봐주시는 후원자님께 진심으로 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',775,1388070000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9246,'dus3','정다올','ekdhf1989@naver.com','필동어린이집 아동들의 재롱잔치 사진입니다.(2013.12.24)','<p>필동어린이집 아동들 바울방의 박<span style="text-align: -webkit-center">*</span>호,전<span style="text-align: -webkit-center">*</span>호,오<span style="text-align: -webkit-center">*</span>재 아동과</p>
<p>룻2방 오<span style="text-align: -webkit-center">*</span>별, 손<span style="text-align: -webkit-center">*</span>진 아동이 필동 어린이집 재롱잔치에서</p>
<p>멋지고 아름다운 춤과 노래를 불렀습니다.</p>
<p>우리 아동들이 앞으로도 더욱더 열심히 잘 할수 있도록 지원하겠습니다.</p>          </td>
        </tr>',754,1387983600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9245,'dus3','송명은','happysme@hanmail.net','룻2방 현대자동차 후원프로그램에 참여하였습니다.(2013.12.26)','룻2방 아동들은 오늘 현대자동차 후원프로그램에 참여해서 예쁘고 따뜻한 옷을 선물로 받고 맛있는 피자와 치킨을 먹으면서 즐거운 저녁시간을 보냈습니다.
<div>언제나 잊지 않으시고 저희 남산원 아동들을 찾아주시는 현대자동차 중앙지역본부 후원자님들께 다시한번 감사드립니다. 추운 겨울날씨지만 후원해주신 따뜻한 의복으로 인해 마음까지 훈훈한 겨울을 보낼 수 있도록 보육하겠습니다.</div>          </td>
        </tr>',766,1388070000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9247,'dus3','심주현','pikaccu85@hanmail.net','바울방 아동들과 함께 크리스마스 파티를 하였습니다!!(2013.12.25)','<p>즐거운 크리스마스날!!</p>
<p>바울방 아동들과 함께 저녁에 크리스마스 파티를 하였습니다.^-^*</p>
<p>저녁 간식과 함께 아이들이 서로서로 모아 놓은 용돈을 모아 </p>
<p>우리만의 파티를 하였는데요~♡</p>
<p>저마다 열심히 준비하는 모습이 너무 기특하고 이뻐 보였습니다. </p>
<p>아이들이 밝고 건강하게 자랄 수 있도록 보육하겠습니다~</p>
<p>메리~크리스마스!!</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',751,1387983600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9248,'dus3','심주현','pikaccu85@hanmail.net','바울방 아동들이 남산교회에서 성탄선물을 받았습니다!!(2013.12.25)','<p>12월 25일 크리스마스 아침~</p>
<p>다함께 모여 강당에서 성탄 예배를 드렸습니다. </p>
<p>예배가 끝나고 남산교회에서 준비해 주신 크리스마스선물을 아이들 모두 </p>
<p>받아 보았는데요 ^^</p>
<p>멋진 장난감과 함께 아이들이 좋아하는 과자들이 가득 들어있었습니다^-^*</p>
<p>점심식사로 피자도 함께&nbsp;준비해 주셨는데요 ^^</p>
<p>아이들을 위해 큰 사랑을 나눠 주신 남산교회분들께 진심으로 감사드립니다!!</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',737,1387983600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9249,'dus3','심주현','pikaccu85@hanmail.net','바울방 아동들이 크리스마스 용돈을 받았습니다(2013.12.24)','<p align="left">12월 24일 크리스마스 이브날 아침~</p>
<p align="left">바울방 아동들이 남산 아빠께 크리스마스 용돈을 받았습니다.</p>
<p align="left">12월 동안 원내생활을 성실하게 하여&nbsp;바울방 아이들 모두 </p>
<p align="left">크리스마스 용돈을 받았는데요~</p>
<p align="left">막내 민호부터 큰형 한결이까지 모두 다 받게 되어 매우 행복한 하루였습니다. </p>
<p align="left">아이들이 용돈관리를 잘 하고 유용하게 사용 할 수 있도록 지도하겠습니다.</p>
