<p align="left">&nbsp;</p>
<p align="left">&nbsp;</p>          </td>
        </tr>',751,1387983600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9251,'dus3','이소영','leesy5576@hanmail.net','룻2방 미취학, 초등학생 아이들이 크리스마스선물을받았습니다.(2013. 12. 25)','<p align="center">2013년 12월 25일 룻2방 미취학, 초등학생 아이들이</p>
<p align="center">유니클로에서 후원해주신 히트텍을 선물받았습니다.</p>
<p align="center">등, 하교시 아이들이 추위를 많이 타 꼭 필요한 물품이였는데</p>
<p align="center">크리스마스를 맞이해 후원해 주셔서 아이들이 무척 좋아했습니다.</p>
<p align="center">지속적이고 꾸준한 봉사와 후원 감사드립니다.</p>
<p align="center">아이들이 겨울을 잘 보낼 수 있도록 지원하겠습니다.　</p>
<p align="center">　</p>          </td>
        </tr>',693,1387897200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9250,'dus3','박충일','a7124383@nate.com','다윗방아동들이 유니클로와 현대자동차후원으로 히트텍과 속옷양말세트 받았습니다.(2013.12.26)','유니클로에서 다윗방 아동들에게 히트텍을 선물해주셨습니다. 그리고 현대자동차후원금으로 각자 아동들의 팬티와 수면바지 그리고 양말까지 따뜻한 겨울을 날 수 있도록 겨울의복을 구입할 수 있었고&nbsp;같은 디자인이 아닌 자신들만의 개별화된 물품이여서&nbsp;다윗방아동들이 정말 기뻐하였고 기분좋아하였습니다. 정말 감사드립니다.          </td>
        </tr>',742,1387983600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9252,'dus3','박충일','a7124383@nate.com','다윗방 아동들이 아빠께 크리스마스용돈을 받았습니다.(2013.12.24)','<p>크리스마스를 맞이하여 다윗방아동들이 아빠께 용돈을 받았습니다. 앞으로 원내생활 잘하고 학교생활도 잘하며 바른인성교육을 잘 받은 예의바른 아이들로 자라날 수 있도록 열심으로 지도하겠습니다. 아빠!!~ 감사합니다. 메리크리스마스~ 건강하세요~ ^^* &nbsp;</p>          </td>
        </tr>',750,1387897200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9254,'dus3','송명은','happysme@hanmail.net','룻2방 *진이가 크리스마스 선물을 받았습니다.(2013.12.24)','덕수중학교 3학년에 재학중인 룻2방 *진이가 중학교 사회복지사 선생님께 졸업과 크리스마스선물을 받았습니다. 내년에 예일디자인고등학교에 입학하는 유*진이에게 USB와 버스카드를 선물해주셨습니다. *진이가 고등학교에 입학해서도 성실하게 학교생활을 할 수 있도록 열심히 보육하겠습니다. 감사합니다.^^          </td>
        </tr>',725,1387810800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9255,'dus3','김선기','spsp99@naver.com','다윗방 최*선 이*늘 아동 운동화 구입','다윗방 최*선,이*늘 아동이 운동화 구입을 지원 받았습니다.운동화를 구입해서 *선이와 *늘이가 많이 기뻐 하였습니다.

<div>운동화를 잘 관리하며 신을 수 있도록 지도 하겠습니다.감사 합니다.</div>          </td>
        </tr>',734,1387810800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9253,'dus3','송명은','happysme@hanmail.net','룻2방 *별,*진이가 필동어린이집에서 재롱잔치를 하였습니다.(2013.12.24)','필동어린이집 누리반에 등원하고 있는 룻2방의 *별,*진이가 재롱잔치에 참여하였습니다.&nbsp;
<div>그동안 갈고 닦은 여러가지 율동과 악기연주를 선보이는 아이들을 보면서 너무나 사랑스럽고 대견스러웠습니다.&nbsp;</div>
<div>특히 *별이는 혼자서 독창을 하는 영광스러운 순서도 있었습니다. 또 마지막에는 크리스마스 선물로 맛있는 과자세트도 받았습니다.

<div>내년에 초등학교에 입학하는 *별이와 *진이가 얼마남지 않은 어린이집 생활을 열심히 할 수 있도록 보육하겠습니다.</div>
<div>재롱잔치를 준비하시느라 고생 많으셨던 필동어린이집 선생님들 감사합니다.^^</div></div>          </td>
        </tr>',731,1387810800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9257,'dus3','박충일','a7124383@nate.com','다윗방아동들이 KDB생명후원으로 크리스마스 선물을 받았습니다.(2013.12.23)','<p style="line-height: 120%" class="0"><font face="굴림">다윗방 아동들이 KDB생명후원으로 크리스마스 선물을 받았습니다. 겨울의복비를 후원하여 주셔서 우리 아이들이 직접 옷매장가서 각자 마음에 드는 멋진옷들을 사고 오늘 선물포장과 함께 손글씨 연말카드와 함께 선물받았습니다. 아주 기쁘고 즐거운 행복한 날였습니다. KDB생명 임직원여러분께 진심으로 감사드립니다. 메리크리스마스 해피뉴이어~^^*</font></p>          </td>
        </tr>',731,1387810800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9258,'dus3','이소영','leesy5576@hanmail.net','룻2방이 KDB후원 송년행사에 참여하였습니다.(2013.12.23)','2013년 12월 23일 룻2방이 KDB후원 송년행사에 참여하여 크리스마스선물도 받고 한 해를 마무리 하면서 후원자님께 좋은 말씀도 들으며 시간을 보냈습니다.
<div>크리스마스 선물은 아이들이 따뜻한 겨울을 보낼 수 있도록 겨울옷을 선물해주셨습니다. 정성스러운 편지까지 준비하셔서 아이들이 선물포장을 뜯으며 무척 좋아하는 모습이였습니다.</div>
<div>정기적인 봉사와 함께 연말 아이들을 위해 후원해주신 KDB후원자님 진심으로 감사드립니다.</div>          </td>
        </tr>',736,1387724400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9256,'dus3','이소영','leesy5576@hanmail.net','룻2방 아이들이 크리스마스 용돈을 받았습니다.(2013. 12. 24)','<p align="center">2013년 12월 24일 룻2방이 남산 아빠께 크리스마스 용돈을 받았습니다.</p>
<p align="center">그동안 원내생활을 성실하게 하여 룻2방 아이들 모두 </p>
<p align="center">크리스마스 용돈을&nbsp;받아 기분좋게 하루를 시작하였습니다.</p>
<p align="center">룻2방에서는 *영,&nbsp;<span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">연이가 가장 성실하게 생활하여 칭찬왕이 되었고&nbsp;</span></p>
<p align="center">용돈을 가장 많이 받게되었습니다.</p>
<p align="center">아이들이 용돈관리를 잘 하고 유용하게 사용 할 수 있도록 지도하겠습니다.</p>
<p>　</p>
<p>&nbsp;</p>          </td>
        </tr>',733,1387810800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9260,'dus3','김성재','thunderdog9@naver.com','모세방 환경심사 1등 기념 회식(2013.12.22)','12월 원내 환경심사 1등을 기념하여 모세방 아동들과 종로에 있는 고기뷔페에서 회식을&nbsp;한 후&nbsp;겨울 의류를 구입하고 돌아왔습니다.&nbsp;너무나 오랜만에 1등을 하게 되어 모두들 감회가 새로운 듯 했습니다. 언제 또 1등을 하게 될런지는 모르겠지만 굳이 1등이 아니더라도 지속적으로 깔끔한 실내환경을 유지해줬으면 하는 바람을 가져봅니다. 당일 오전 환경정리에 도움 주신 자원봉사자 여러분들께도 감사드립니다.          </td>
        </tr>',754,1387724400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9261,'dus3','정다올','ekdhf1989@naver.com','바울방 이*결 아동이 신혜정 학습 선생님께 받은 선물입니다.(2013.12.22)','<p>바울방 이*결 아동이 학습 선생님을 만나서</p>
<p>학습선생님에게 선수가 직접 싸인한 야구공과 과자를 선물</p>
<p>받았습니다.</p>
<p>아동이 무척이나 기뻐하였습니다.</p>
<p>항상 *결이에게 신경 써주셔서 감사드립니다.^^</p>          </td>
        </tr>',761,1387724400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9259,'dus3','심주현','pikaccu85@hanmail.net','바울방 KDB 크리스마스 행사 사진입니다. (2013.12.23)','<p>오늘 KDB후원자님과 함께 크리스마스 파티를 하였습니다. </p>
<p>산타 할아버지께서 아이들에게&nbsp;하나하나&nbsp;선물도 나눠 주시고~</p>
<p>직접 작성하신 크리스마스 카드도 주셔서 너무 너무 행복했습니다!!</p>
<p>우리아이들에게 큰 관심과 사랑을 나눠 주신</p>
<p>KDB 후원자 분들께 진심으로 감사드립니다!!</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',759,1387724400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9263,'dus3','송명은','happysme@hanmail.net','룻2방 필동감리교회 아동들은 의미있는 선물을 받았습니다.(2013.12.22)','룻2방 필동감리교회에 다니고 있는&nbsp;<span style="text-align: -webkit-center">*</span>연이와 지민이는 오늘 교회에서 열린 물물교환 프로그램시간에 아동들이 사용하지 않는 물건을 준비해서 필요한 물건과 바꾸는 의미있는 시간을 가지게 되었습니다.&nbsp;<span style="text-align: -webkit-center">*</span>연이는 탁상시계와 필기도구를 지민이는 예쁜 머그컵을 교환해서 왔습니다. 아동들이 사용하지 않는 물건을 버리지 않고 필요한 친구와 나눠서 사용할 줄 아는 똘똘한 아동으로 성장할 수 있도록 앞으로 열심히 지도하겠습니다.          </td>
        </tr>',810,1387638000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9264,'dus3','송명은','happysme@hanmail.net','룻2방 침례교회 아동들은 신나는 크리스마스 선물을 받았습니다.(2013.12.22)','룻2방 침례교회에 유치부에 다니고 있는 아동들은 오늘 보기만해도 신나는 눈썰매와 맛있는 과자를 선물로 받았습니다.
<div>또 초등부 아동들은 직접 핸드크림과 양초를 만들어서 가져왔답니다. 항상 남산원 아동들에게 특별한 관심과 사랑을 보내주시는 침례교회 선생님들께 진심으로 감사드립니다. 내년에도 우리 남산원 아동들 잘 부탁드립니다.^^</div>          </td>
        </tr>',778,1387638000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9262,'dus3','정다올','ekdhf1989@naver.com','바울방 이*결 아동 후원자님께 받은 크리스마스 선물 사진입니다.(2013.12.22)','<p>바울방 이*결 아동이 후원자님께 받은 크리스마스 </p>
<p>선물입니다.</p>
