INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9265,'dus3','정다올','ekdhf1989@naver.com','바울방 이*슬 아동 후원자님께 받은 크리스마스 선물 사진입니다.(2013.12.22)','<p>바울방 이*슬 아동이 이환주 후원자님께서 *슬이를 위해&nbsp;</p>
<p>손난로 인형이라는 크리스마스 선물을 준비해 주셨습니다.</p>
