INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9267,'dus3','이소영','leesy5576@hanmail.net','룻2방 전기안전교육 사진입니다.(2013. 12. 21)','2013년 12월 21일 룻2방 아이들이 원내 강당에서 실생활에서 전기사용에 대한 주의점과 안전교육을 받았습니다.짧은 시간이였지만 집중하여 교육에 임하는 모습이였습니다.
<div>지속적으로 아이들에게 안전교육을 하며 안전한 생활을 할 수 있도록 보육하겠습니다.</div>
