INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9266,'dus3','정다올','ekdhf1989@naver.com','바울방 침례교회 크리스마스 선물 사진입니다.(2013.12.22)','<p>바울방 손<span style="text-align: -webkit-center">*</span>민, 최<span style="text-align: -webkit-center">*</span>명,박<span style="text-align: -webkit-center">*</span>호,오<span style="text-align: -webkit-center">*</span>재 아동이</p>
<p>침례교회에서 예배를 드리고 크리스마스 선물을</p>
<p>받았습니다.</p>
<p>아동부는 직접 만든 립밤과 핸드로션 초를 받았고,</p>
<p>유치부는 눈썰매를 받아서 아이들이 너무 좋아하는</p>
<p>모습입니다~^^</p>
<p>저희 남산원 아동들에게 항상 신경 많이 써주셔서 감사드립니다.^^</p>          </td>
        </tr>',751,1387638000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9270,'dus3','심주현','pikaccu85@hanmail.net','바울방 최*명, 박*호 아동 후원선물 사진입니다. (2013.12.21)','<p>오늘 최*명, 박*호 아동이 학습봉사자 김다솜 선생님께서 전달하신 선물을 받아 보았습니다. </p>
<p>조용하고 얌전히 활동을 잘하는 *호에게는 아이클레이와 반짝이 풀을. </p>
<p>착하고 활발한 *명이에게는 여러명이 함께 할수있는 악어 장난감을 선물로 받았습니다. </p>
<p>언제나 큰 관심으로 바울방 아동들을 많이 사랑해 주시는 김다솜 학습선생님께 진심으로 감사드립니다. </p>          </td>
        </tr>',746,1387638000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9269,'dus3','이소영','leesy5576@hanmail.net','룻2방 *영, *연이가 후원자님께 선물을 받았습니다.(2013. 12. 21)','2013년 12월 21일 룻2방 *영, *연이가 이윤지선생님께 크리스마스 선물을 받았습니다.

<div>매주 월요일, 수요일 *영이와 *연이의 피아노레슨을 해주시고 계시는 이윤지선생님께서 *영이 *연이와 외출하여 맛있는 저녁식사를 함께 하시고 아이들에게 꼭 필요한 겨울옷을 선물해주셨습니다.</div>
<div>평소 *영이 *연이뿐만 아니라 룻2방에도 많은 관심과 애정을 가지고 계셔서 룻2방에 초콜릿도 선물해주셨습니다.</div>
<div>아이들 모두 선생님께 감사한 마음을 갖고 초콜릿을 맛있게 나누어먹었습니다.</div>
<div>재능기부 뿐 만 아니라 남산원에 꾸준히 관심가져주시며 후원해주시고 계신 이윤지선생님께 진심으로 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',755,1387638000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9268,'dus3','심주현','pikaccu85@hanmail.net','용인이현초등학교 학용품 후원 사진입니다. (2013.12.21)','<p>용인이현초등학교에서 우리 아이들을 위해 학용품을 후원해 주셨습니다. </p>
<p>도서, 헤어핀, 샤프세트, 노트, 매직 등 많은 품목을 보내주셨는데요 ^^</p>
<p>후원자님의 깊은 사랑에 대단히 감사드리며 우리 아이들이 건강하게 잘 성장 할 수 있도록&nbsp; 보육하겠습니다. 감사합니다!!</p>          </td>
        </tr>',869,1387638000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9272,'dus3','심주현','pikaccu85@hanmail.net','바울방 롯데마트 후원선물 사진입니다. (2013.12.21)','<p>오늘 롯데마트 후원자 분들께서 아이들을 위해 통큰 블럭을 선물해 주셨습니다. </p>
<p>바울방은 블럭세트 중에서 영호가 좋아하는 바다이야기를 골랐는데요 ^^</p>
<p>역시나 블럭을 보자마자 유치부 아동들이 금방 모여&nbsp; 많으 관심을 보였답니다^^</p>
<p>아이들에게 좋은 선물은 전달해 주신 롯데마트 후원자 분들께 진심으로 감사드립니다^-^</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',729,1387551600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9271,'dus3','심주현','pikaccu85@hanmail.net','바울방 이*결 아동 생일파티 사진입니다.(2013.12.21)','<p>오늘은 바울방의 황태자 이*결아동의 12번째 생일날 입니다. </p>
<p>아침에 남산원 식구들과의 생일 노래와 함께 저녁에는 바울방 식구들과 시간을 가졌는데요 ^^ </p>
<p>생일날이라서 그런지 오늘 하루종일 *결이는 즐거워 보이는 모습입니다^-^*</p>
<p>앞으로 우리 *결이가 멋진 모습으로 잘 성장할 수 있도록 지원하겠습니다!!</p>
<p>모두들 많이 많이 축하해 주세요!!!</p>          </td>
        </tr>',724,1387551600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9273,'dus3','심주현','pikaccu85@hanmail.net','바울방 전기안전교육 사진입니다. (2013.12.21)','<p>오늘 오후 강당에서 아동들을 대상으로 전기안전교육을 받았습니다. </p>
<p>평소 아이들이 쉽게 접할수 있는 전기에 대해 안전하게 사용하는 법에 대해 배워보는 시간을 가졌는데요 ^^</p>
<p>평소 소홀히 지나갔던 부분도 다시금 확인할 수 있는 귀한 시간이 되었던 것 같습니다. </p>
<p>아이들이 전기를 안전하게 사용할 수 있도록 지도하겠습니다!! ^-^*</p>          </td>
        </tr>',724,1387551600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9275,'dus3','이소영','leesy5576@hanmail.net','룻2방 중학생아이들이 경제교육을 받았습니다.(2013. 12. 21)','2013년 12월 21일 룻2방 중학생&nbsp;<span style="text-align: -webkit-center">*</span>리,&nbsp;<span style="text-align: -webkit-center">*</span>선,&nbsp;<span style="text-align: -webkit-center">*</span>희,&nbsp;<span style="text-align: -webkit-center">*</span>진이가 &nbsp;경제교육을 받았습니다.

<div>서울시자원봉사센터에서 경제교육봉사를 담당해주시는 신한금융그룹 이종갑 선생님께서 방문하셔서 아이들이 자립에 필요한 경제교육을 해주셨습니다.

<div>실질적인 정보를 아이들의 수준에 맞춰 강의해주시고 재미있는 경제브루마블도 선물해주셔서 매우 유익한 시간이 되었습니다.</div></div>
<div>추운날씨에도 남산원 방문하셔서 아이들에게 도움을 주신 서울시자원봉사센터 후원자님 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',740,1387551600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9276,'dus3','이소영','leesy5576@hanmail.net','룻2방이 롯데마트후원프로그램에 참여하였습니다.(2013. 12. 21)','<font face="굴림">2013년 12월 21일 룻2방 미취학, 초등학생 아동들이 롯데마트 후원 마술프로그램에 참여하여 마술공연을 보고 아이들이 좋아하는 햄버거로 점심식사를 하였습니다.</font>
<div><font face="굴림">다양한 마술공연과 함께 아이들이 할 수 있는 마술도구도 선물해주시고 방법도 알려주셔 아이들이 무척 즐거워하였습니다.</font></div>
<div><font face="굴림">정기적인 봉사활동과 함께 후원프로그램도 진행해 주신 롯데마트 후원자님 감사드립니다.</font></div>
<div><font face="굴림">　</font></div>
<div><font face="굴림">　</font></div>
<div><font face="굴림">　</font></div>          </td>
        </tr>',764,1387551600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9274,'dus3','심주현','pikaccu85@hanmail.net','바울방 롯데마트 마술 프로그램 참가 사진입니다. (2013.12.21)','<p>오늘 바울방 전원 모두 롯데마트 마술 후원프로그램에 참여하였습니다. </p>
<p>마술사 형이 선보이는 화려한 마술도 보고 우리도 직접 체험해 보는 등 유익한 시간을 보냈는데요 ^^</p>
<p>아이들이 방에 와서 하루종일 마술 연습을 하며 선보이는 등 아주 멋진 하루를 보냈답니다.&nbsp; </p>
<p>점심식사로 롯데리아 햄버거를 준비해 주셔서 아동 모두 맛있게 잘 먹었습니다. </p>
<p>언제나 우리 아이들에게 큰 사랑을 나눠 주시는 롯데마트 후원자 분들께 진심으로 감사드립니다 ^^</p>          </td>
        </tr>',730,1387551600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9278,'dus3','심주현','pikaccu85@hanmail.net','바울방 이*슬 아동이 학교 담임선생님께 선물을 받았습니다^^(2013.12.20)','<p>오늘 *슬이는 학교 담임선생님과 함께 사제동행에 다녀왔습니다. </p>
<p>학교가 끝나고 담임선생님과 함께 영풍문고에 가서 아동이 읽고 싶은&nbsp;윔피키드&nbsp;책과 입체퍼즐을 직접 골라 선물로 받아 왔는데요^^</p>
<p>아동이 담임선생님과의 동행에 매우 즐거워 하였습니다. </p>
<p>늘 아낌없는 사랑으로 *슬이를 교육해주시는</p>
<p>남산초등학교 이윤희 선생님께 진심으로 감사드립니다 ^-^*</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',800,1387465200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9279,'dus3','박현정','kingi109@naver.com','미군계약처 한나방 선물 전달식(2013.12.19)','<p>* 미군계약처 후원자분들께서 한나방 아동들에게 선물을 전달해주셨습니다.</p>
