INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9282,'dus3','송명은','happysme@hanmail.net','룻2방이 미군계약처 후원자님께 소중한 선물을 받았습니다.(2013.12.19)','쌀쌀해진 날씨에도 불구하고 미군계약처 후원자님께서 남산원을 방문해주셔서 아동들을 위한 소중한 선물을 주셨습니다. 선물에는 아동들의 이름이 한명씩 적혀 있어서 그런지 아동들에게 더 감동스러운 선물이었던 것 같습니다. 룻2방 아동들도 후원자님께 받은 선물을 보면서 너무나 기뻐하고 즐거운 하루를 보냈습니다. 올 겨울 후원자님께서 보내주신 선물로 따뜻하게 보낼 수 있을 것 같습니다. 진심으로 감사드립니다.^^          </td>
        </tr>',742,1387378800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9281,'dus3','심주현','pikaccu85@hanmail.net','바울방이 미군계약처 후원자님께 크리스마스 선물을 받았습니다^^(2013.12.19)','<p>오늘 저녁 강당에 남산 식구들이 함께 보여 미군계약처 후원자님께 크리스마스 선물을 받았습니다 ^-^**</p>
<p>아동 한명한명에게 정성껏 준비 하신 선물을 직접 나눠 주셨는데요^^</p>
<p>우리 아이들을 생각하며 준비하신 모습을 생각하니 후원자님들의 따뜻한 사랑이 듬뿍 느껴졌습니다.&nbsp;</p>
<p>많이 추워진 날씨 속에서도 우리 아이들에게 사랑을 나눠 주시기 위해 방문하셔서 </p>
<p>선물을 전달 해 주신 미군계약처 후원자님께 진심으로 감사드립니다^-^*</p>          </td>
        </tr>',760,1387465200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9283,'dus3','이소영','leesy5576@hanmail.net','룻2방 *진이가 디딤씨앗공모전에서 수상을하였습니다.(2013. 12. 18)','2013년 12월 18일 룻2방 맏언니 *진이가 디딤씨앗공모전에서 한국사회복지협의회장상을 수상하여 국회의원회관에 가서 시상식을 하였습니다.
<div>받은 것을 다시 나누고 봉사하는 기쁨을 알아가는 모습을 그린 *진이의 나눔이 담긴 그림이 수상하게 되어 무척 기쁘고 대견하지만 무엇보다도 *진이가 나눔에 대해 생각하며 갖은 마음이 더욱 갚지고 이쁘게 느껴졌습니다.</div>
<div>이제 곧 중학교를 졸업하고 예일디자인고등학교에 입학하게 되어 여러가지 준비를 하고 있는 상황에서 *진이에게 상금과 함께 이쁜 가방도 부상으로 수여되어 기분좋게 식을 마치고 귀가하였습니다.</div>
<div>앞으로도 *진이가 밝고 성실하게 성장할 수 있도록 보육하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',770,1387292400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9284,'dus3','송명은','happysme@hanmail.net','룻2방 *희가 박재현선생님께 선물을 받았습니다.(2013.12.17)','박재현선생님께서 룻2방&nbsp;<span style="text-align: -webkit-center">*</span>희에게 겨울철에 꼭 필요한 핸드크림을 선물해주셨습니다. 너무나 추운 날씨에 선생님께서 선물해주신 핸드크림으로 마음까지 부드러운&nbsp;<span style="text-align: -webkit-center">*</span>희가 될 수 있도록 열심히 보육하겠습니다.

<div>감사합니다.^^</div>          </td>
        </tr>',719,1387206000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9285,'dus3','송명은','happysme@hanmail.net','룻2방 *별,*진이가 권주안선생님께 선물을 받았습니다.(2013.12.16)','룻2방의 *별,*진이는 한해동안 한글지도를 해주신 권주안선생님께 감사한 마음을 담아서 감사카드를 써서 전달했는데 오히려 권주안선생님께서는 *별,*진이에게 예쁜 문구용품을 선물해주셨습니다.
<div>&nbsp;내년에 초등학생이 되는 아이들에게 꼭!!필요한 선물을 주신 권주안선생님께 다시한번 감사드립니다.^^</div>          </td>
        </tr>',746,1387119600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9287,'dus3','남산원','jblee4@naver.com','다윗방 김*생일파티(2013.12.16)','<p>다윗방에 똑똑이 *이가 오늘 생일을 맞이 하였습니다.다윗방 아동들 모두 *이에 생일을 축하해 주고 축복해 주었습니다.*이야 생일 진심으로 축하하고 더 밝고 착하게 자라 주렴 선생님이 늘 기도할께 *이야 사랑한다 다윗방 김선기선생님이.</p>
<p></p>          </td>
        </tr>',843,1387119600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9288,'dus3','이소영','leesy5576@hanmail.net','룻2방 *영이가 유혜종선생님과외출을다녀왔습니다.(2013. 12. 15)','2013년 12월 15일 룻2방 *영이가 학습을 지도해주고 계신 유혜종 선생님과 외출을 다녀왔습니다.

<div>곧 크리스마스가 다가와 *영이에게 크리스마스선물과 함께 맛있는 점심식사를 사주셨습니다.&nbsp;</div>
<div>몇일 전 부터 선생님과의 데이트를 기대하고 있었는데 오랜만의 외출에 정말 좋아하며 감사하는 마음을 갖는 *영이의 모습을 볼 수 있었습니다.</div>
<div>항상 *영이와의 약속을 잘 지켜주시고 학습뿐만 아닌 여러 역할의 멘토역할도 해주시며 관심있게 지켜봐주시고 계시는 유혜종 선생님께 진심으로감사드립니다.</div>
<div>　</div>
<div>　　</div>
<div>　</div>          </td>
        </tr>',731,1387033200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9289,'dus3','심주현','pikaccu85@hanmail.net','오늘은 바울방 최*명 아동의 생일날 입니다.(2013.12.15)','<p>오늘은 바울방의 귀염둥이 최*명 아동의 8번째 생일입니다. </p>
<p>아침에 남산원 식구들과의 생일노래를 시작으로 </p>
<p>저녁에는 바울방 식구들과 함께&nbsp;생일파티 시간을 가졌는데요 ^^</p>
<p>생일날이라서 그런지 오늘 하루종일 *명이는 신나기만 합니다 ^-^*</p>
<p>앞으로 우리&nbsp;*명이가 멋진 모습으로&nbsp;잘 성장할 수 있도록 지원하겠습니다!!</p>
<p>모두들 많이 많이 축하해 주세요!!!</p>
          </td>
        </tr>',786,1387033200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9290,'dus3','송명은','happysme@hanmail.net','룻2방 중학생들은 KBS 방송국 견학을 하였습니다.(2013.12.14)','지난주 일요일을 마지막으로 중고생 직업멘토링 프로그램은 종결이 되었지만 남산원 아동들을 위해서 멘토선생님께서 KBS 방송국 견학을 관람할 수 있는 기회를 주셨습니다. 이에 룻2방 중학생 아동들은 쌀쌀한 날씨였지만 감사한 마음으로 방송국 견학을 하였습니다.

<div>방송국에 가서 가이드 선생님의 인솔에 따라서 그동안 알지 못했던 새로운 모습들을 알게 되는 유익한 시간이 되었습니다. 아동들에게 의미있는 시간을 보낼 수 있도록 해주신 직업멘토링 관계자분들께 진심으로 감사드립니다. 앞으로도 아동들에게 다양한 직업체험을 할 수 있는 기회를 제공할 수 있도록 열심히 지원하겠습니다.</div>          </td>
        </tr>',738,1386946800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9291,'dus3','송명은','happysme@hanmail.net','룻2방 *민이가 정수미선생님과 따뜻한 점심식사를 하였습니다.(2013.12.14)','그동안 남산원을 방문해주셔서 룻2방 *민이의 영어학습지도를 해주셨던 정수미선생님께서 개인적인 사정으로 *민이와의 수업을 종결하게 되었습니다.

<div>1년이 넘는 시간동안 *민이와의 학습지도를 해주신 정수미선생님과 지민이는 마지막 시간을 함께 보내기 위해서 추운 날씨였지만 따뜻한 점심식사를 하면서 아쉬움을 달랬습니다.&nbsp;</div>
<div>정수미 선생님~그동안 수고많으셨습니다. 앞으로도 남산원 자주 방문해주세요~감사합니다.^^</div>          </td>
        </tr>',774,1386946800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9292,'dus3','이소영','leesy5576@hanmail.net','룻2방 *민이가 이진경후원자님께선물을받았습니다.(2013. 12. 13)','2013년 12월 13일 룻2방 *민이가 이진경후원자님께 귀마개를 선물받았습니다.

<div>오후에 방문하셔서 하교한 아이들과 시간을 보내시고 추워지고 있는 날씨에 필요한 겨울용품을 전달해주고 가셨습니다.</div>
<div>항상 남산원을 관심있게 지켜봐주시며 후원해주고계시는 이진경후원자님 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',731,1386860400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9293,'dus3','박충일','a7124383@nate.com','다윗방 3총사 초등생아동 금융체험관에 다녀왔습다!!~^^','<p>다윗방 3총사 김도현,김용,김민수아동이 여의도에 있는 금융체험관에 다녀왔습니다. </p>
<p>세살 버릇 여든까지 간다는 속담처럼 학생이 물론 공부도 중요하지만 어릴적부터 재정(돈)에 관해 바른경제관념을 가지고 실제 생활속에서도 합리적으로 생활할 수 있도록 좋은 교육과 견학의 기회를 주셔서 진심으로 감사드립니다. </p>          </td>
        </tr>',738,1386774000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9295,'dus3','김성재','thunderdog9@naver.com','금융체험관 탐방 다녀왔습니다.(2013.12.12)','오늘은 서울시자원봉사센터의 후원으로 여의도에 위치한 금융투자교육원에 다녀왔습니다. 초등학교 고학년을 대상으로 진행된 이번 프로그램을 통해 아동들은 경제활동의 개념과 저축의 필요성, 그리고 작은 꿈부터 큰 꿈까지 자신의 희망을 생각해보고 그 꿈을 이루기 위해서는 금전적인 뒷받침이 필요하다는 사실을 교육과 애니메이션 시청을 통해 알아보았습니다. 무엇보다도 강사님의 재미있는 설명 덕분에 꿈을 이루기 위해서는 돈이 필요하다는 것 하나만은 분명히 배우고 돌아온 하루였습니다.          </td>
        </tr>',734,1386774000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9294,'dus3','송명은','happysme@hanmail.net','룻2방의 *연, *민이가 금융체험관에 다녀왔습니다.(2013.12.12)','하얀눈이 펑펑 내리는 추운 날씨였지만 룻2방의 *연이와 *민이는 금융체험관에 가서 의미있고 유익한 체험을 하였습니다.
<div>단순히 돈을 사용하는 방법에 대해서만 배운 것이 아니라 돈의 필요성에 대해서 먼저 교육을 받게 되니 아동들의 이해가 더 쉬웠습니다.&nbsp;</div>
<div>또 평소에도 용돈기입장을 사용하고 있는 *연이와 *민이는 오늘 예쁜 용돈기입장을 선물로 받았습니다.&nbsp;</div>
<div>어린 아동들이지만 지금부터 돈의 올바른 사용법에 대해서 열심히 지도해서 멋진 사회인으로 거듭날 수 있도록 보육하겠습니다.</div>          </td>
        </tr>',726,1386774000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9296,'dus3','정다올','ekdhf1989@naver.com','오늘 바울방 오*진,이*결,정*균 아동이 금융체험관 탐방을 다녀왔습니다.(2013.12.12)','<p>오늘 바울방 오*진,이*결,정*균 아동이 금융체험관 탐방을 다녀왔습니다.</p>
<p>아동들이 금융체험관 에 가서 금전에 관한것과 용돈기입장을 어떻게 </p>
<p>써야 하는지를 배우고 올수 있는 좋은계기가 되었습니다.</p>
<p>감사합니다.^^</p>          </td>
        </tr>',737,1386774000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9298,'dus3','박현정','kingi109@naver.com','한나 김*름 아동 젤네일 2급 자격증 취득(2013.12.11)','<p>&nbsp;* 한나방 *름 아동이 젤네일 2급 자격증 취득을 하였습니다.</p>
<p>&nbsp;&nbsp;&nbsp; 앞으로 더욱 더 성장할 아동에게 큰 관심과 기대 가져주시기 바랍니다.</p>
<p>&nbsp;&nbsp;&nbsp; 감사합니다. </p>          </td>
