INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9297,'dus3','이소영','leesy5576@hanmail.net','룻2방 *별이가 어린이집에서 생일파티를하고 귀가하였습니다.(2013. 12. 11)','2013년 12월 11일 룻2방 *별이가 필동어린이집에서 생일파티를 하고 귀가하였습니다.

<div>조금 늦은 생일파티지만 친구들과 선생님 다함께 축하해주며 함께하는 생일파티에서 많은 선물을 받아 귀가하여 *별이가 기분이 정말 좋았습니다.</div>
<div>항상 *별이를 사랑으로 관심있게 지켜봐주시는 필동어린이집 선생님 감사드립니다.</div>
<div>　</div>          </td>
        </tr>',759,1386687600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9299,'dus3','심주현','pikaccu85@hanmail.net','오늘은 바울방 오*진 아동의 생일날 입니다~(2013.12.11)','<p>오늘은 바울방의 멋쟁이 오*진 아동의 12번째 생일날 입니다. </p>
<p>아침 시간에는 남산원 식구들의 생일 노래와 </p>
<p>저녁에는 바울방 식구들의 생일파티 시간을 가졌는데요 ^^</p>
<p>오늘 *진이가 주인공인 만큼&nbsp; 하루종일 즐거운 하루였답니다 ^^</p>
<p>우리 *진이가 지금처럼 멋진 모습으로 잘 성장할 수 있도록 지원하겠습니다!!</p>
<p>모두들 많이 많이 축하해 주세요!!!</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',752,1386687600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9300,'dus3','심주현','pikaccu85@hanmail.net','바울방 이*슬, 이*결, 정*균 아동이 독서상을 받아왔습니다.(2013.12.11)','<p>바울방 이*슬, 이*결, 정*균 아동이 독서상을 받아왔습니다. </p>
<p>2학기 동안 책을 많이 읽어 다른사람의 모범이 되어 상장을 받았는데요 ^^</p>
<p>아이들의 독서 하는 습관들이 학교에서 모범이 되었다니 너무 대견하고 기특하게 보이는 하루였습니다. </p>
<p>우리아이들이 더욱 건강한 학교생활을 할 수 있도록 지원하겠습니다. ^^</p>          </td>
        </tr>',734,1386687600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9301,'dus3','이소영','leesy5576@hanmail.net','룻2방 *연이가 상장을받았습니다.(2013. 12. 11)','2013년 12월 11일 남산초등학교에 다니고 있는 룻2방 *연이가 독후감 상장을 받아왔습니다.

<div>평소 독서를 많이 하는 *연이가 한 학기동안 꾸준한 생각키우기의 결과를 받아와 기특하고 기쁩니다.</div>
<div>*연이가 책을 읽을 수 있도록 항상 후원해주시고 계시는 후원자님, MSC사고력 향상프로그램 선생님들 감사드립니다.</div>
