INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9302,'dus3','이소영','leesy5576@hanmail.net','룻2방 *현이가 후원자님께 선물을 받았습니다.(2013. 12. 11)','2013년 12월 11일 룻2방 *현이가 강수진 후원자님께 인형선물을 받았습니다.

<div>생활하는 공간이 바뀐것에 대한 우려와 달리 건강하고 이쁘게 잘 성장하고 있는 *현이를 기특해 하시며 일주일에 세번 *현이의 학습과 놀이활동도 도와주고 계십니다.</div>
<div>항상 *현이를 관심있게 지켜봐주시고 계신 강수진 봉사자님께 감사드립니다.</div>
