INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9305,'dus3','류덕례','yoodr1015@hanmail.net','모세방 *현이가 기말고사를 마치고 영화관람을 했습니다(2013.12.10)','<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; * 모세방 *현이가 기말고사를 마치고 다윗방 박충일 선생님의 인솔로</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 영화를 관람했습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 무엇이든 궁금하고 해고보고 싶은게 많은 *현이가 기말고사를</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 보면서 많은 생각을 했다고 하니 대견합니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; *현이는 중3을 대비하여 성적향상에 노력을 하기로 약속했습니다.</p>          </td>
        </tr>',809,1386601200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9304,'dus3','박충일','a7124383@nate.com','다윗방 최*선,오*진,이*늘아동 영화관람하고 왔습니다. (2013.12.10)','오늘은 환일중학교 기말고사 시험 마지막날로서 3일간 기말고사 시험준비로 스트레스가 쌓였을 아동들과 함께 영화를 보며 스트레스 해소와 정서적 지지를 얻을 수 있는 귀한 시간을 보냈습니다. 오늘 본 영화의 제목은 "어바웃 타임"으로 주인공이 시간여행을 할 수 있는 능력으로 자신의 인생을 좀 더 가치있고 매순간 소중하게 생각하며 감사하는 마음을 가지고 최선을 다해 살아가도록 하는 교훈과 감동을 주는 영화여서 유익한 교육자료도 되었습니다. 모세방 안*현아동도 함께하여 더욱 즐거운 추억을 만들었습니다. 감사합니다.          </td>
        </tr>',725,1386687600,'', '', '', '', '', '');
