INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9307,'dus3','정다올','ekdhf1989@naver.com','바울방의 초등학생들은 MSC 독서프로그램 선생님들께 따뜻한 선물을 받았습니다.(2013.12.09)','<p>그동안 저희 남산원 아동들을 위해서 MSC 독서프로그램을 지원해 주셔서 감사합니다.</p>
<p>선생님들에게 받은 저학년은 장갑, 고학년은 넥워머와 모자를 받고</p>
<p>너무 기뻐하였습니다.</p>
<p>그동안 정말 수고 많이 하셨구요~^^</p>
<p>아이들&nbsp; 책읽는 좋은 습관을 가지게 되어서 감사드립니다.^^</p>          </td>
        </tr>',780,1386601200,'', '', '', '', '', '');
