INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9308,'dus3','송명은','happysme@hanmail.net','룻2방의 초등학생들은 MSC 독서프로그램 선생님들께 따뜻한 선물을 받았습니다.(2013.12.09)','2011년부터 거의 3년동안의 시간동안 남산원을 방문하셔서 초등학생 아동들에게 책을 읽고 생각을 나누면서 아동들에게 정서적으로 긍정적인 영향력을 주셨던 선생님들께서 오늘 마지막 수업을 해주셨습니다. 선생님들께서는 마지막 수업을 기념하는 의미로 아동들에게 따뜻한 장갑과 편지를 선물해주셨습니다. 그동안 휴일을 반납하시고 남산원 아동들을 위해 애써주신 그 헌신에 깊은 감사를 드립니다. 남산원 아동들 잊지 마시고 가끔씩 아동들 만나러 와주세요~그동안 정말 수고많으셨습니다.          </td>
        </tr>',758,1386514800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9309,'dus3','송명은','happysme@hanmail.net','룻2방의 *민,*영이가 상장을 받았습니다.(2013.12.09)','룻2방의 *민이와 *영이가 남산초등학교에서 수여한 다독상을 받았습니다.&nbsp;
<div>평소에 책읽는 것을 좋아해서 하교후에 시간이 있을때마다 책을 읽기도 하고 학교 도서관에서 읽고 싶은 책을 빌려서 읽는 등 책을 가까이 하는 예쁘고 사랑스러운 *민이와 *영이랍니다.

<div>앞으로 우리 아동들이 책을 더 사랑하고 가까이 하는 아동으로 성장할 수 있도록 지도하겠습니다.</div></div>          </td>
        </tr>',757,1386514800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9310,'dus3','류덕례','yoodr1015@hanmail.net','모세방 *현이가 김동혁 학습선생님과의 즐거운 외출(2013.12.08)','<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; * 수현이의 학습선생님께서 *현이의 고등학교 합격기념을 축하해주는</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 시간을 가졌습니다. 매주 토요일 힘든과정의 학습을 지도하시는</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 선생님은 한번도 표현하지 않고 아동과의 관계를 갖고 계십니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;물론 고등학교에 입학해서도 부진한 학습을 지도하고 성장기 멘토를 </p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 잘해주실줄 믿습니다~ 감사합니다. 일년동안 수고하셨습니다.</p>          </td>
        </tr>',750,1386428400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9313,'dus3','박충일','a7124383@nate.com','다윗방 김*아동이 생일선물을 받았습니다.','<p>매주 일요일마다 *이의 학습지도를 해주시는 윤성신선생님으로부터 생일(12월16일)선물을 미리 받았습니다. 다윗방에서 가장 모범적으로 생활 잘하는 *이가 내년이면 중학생이 됩니다. 열심히 공부하고 훌륭한 인재로 자랄 수 있도록 지도하겠습니다. *이의 생일을 축하해주시고 많은분들의 관심과 기도부탁드리겠습니다.</p>          </td>
        </tr>',754,1386428400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9311,'dus3','송명은','happysme@hanmail.net','룻2방 *민이가 강석연선생님과의 즐거운 외출을 하였습니다.(2013.12.08)','매주 금요일마다 룻2방 *민이의 한글학습지도를 위해서 남산원을 방문해주시는 강석연선생님께서 휴일을 반납하시고 *민이와의 즐거운 시간을 보내주셨습니다.

<div>*민이와 강석연선생님께서는 패밀리레스토랑에 가서 여러가지 다양한 맛있는 음식을 함께 드시면서 *민이에게 소중한 추억의 시간을 선물해주셨습니다.&nbsp;</div>
<div>올해 초등학교 1학년에 입학해서 적응하기에 많은 어려움이 있었지만 강석연선생님의 학습지도로 *민이가 잘 적응할 수 있었습니다.</div>
<div>내년에도 우리 *민이 잘 부탁드립니다. 항상 감사합니다.^^</div>          </td>
        </tr>',812,1386428400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9312,'dus3','송명은','happysme@hanmail.net','룻2방 *현,*별,*진이가 침례교회에서 선물을 받았습니다.(2013.12.08)','룻2방 미취학 아동들은 오늘 침례교회 유치부예배때 있었던 성경말씀을 암송하는 시간에 열심히 참여해서 예쁜 수첩과 스티커,연필을 선물로 받았습니다.

<div>4살짜리 막내인 *현이도 선물을 받고는 너무나 기뻐하였습니다. 앞으로 아동들이 종교활동에도 적극적으로 참여할 수 있도록 열심히 보육하겠습니다.</div>
<div>침례교회 유치부 선생님~감사합니다.^^</div>          </td>
        </tr>',770,1386428400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9316,'dus3','박충일','a7124383@nate.com','다윗방 최*선, 김*현, 김*수아동 결혼식다녀왔습니다.','<p>다윗방 김*기선생님께서 결혼을 하셔서 다윗방아동을 대표해 최*선, 김*현, 김*수 아동이 충남 논산솔뫼웨딩홀에 다녀왔습니다<span style="font-size: 9pt; line-height: 1.5">.</span></p>
<p><span style="font-size: 9pt; line-height: 1.5">원장님과 박충일선생님과도 동행하였습니다.</span></p>
<p>맛있는 뷔페를 먹고 처음으로 결혼식에 참석해본 *현이와 *수는 신기해하며 선생님의 결혼을 진심으로 축하해드렸습니다.</p>
<p>결혼하신 후에 아버지의 마음으로 더 세심하게 다윗방아동들을 잘 보육하시리라 믿습니다. 선생님의 결혼을 진심으로 축하드립니다. </p>          </td>
        </tr>',790,1386342000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9315,'dus3','박충일','a7124383@nate.com','다윗방 김*, 오*진아동 명문법률생일파티에 다녀왔습니다.','<p>명문법률사무소 후원으로&nbsp;&nbsp;11월 12월에 생일을 맞은 남산원아동과 함께 </p>
<p>다윗방 김*, 오*진아동이 아웃백에 가서 맛있는 식사를 하고 왔습니다.</p>
<p>명문법률사무소 직원여러분께 진심으로 감사드립니다. </p>          </td>
        </tr>',796,1386342000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9314,'dus3','박충일','a7124383@nate.com','다윗방 이*늘, 이*울, 김*아동이 신세계푸드후원영화관람을 하고 왔습니다.','신세계푸드후원으로 다윗방 이*늘, 이*울, 김*아동이 영화를 보고 맛있는 피자를 먹고 왔습니다. 행복하고 즐거운 주말 좋은 추억을 만들어 주셔서 진심으로 감사드립니다.          </td>
        </tr>',730,1386342000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9317,'dus3','이소영','leesy5576@hanmail.net','룻2방 *민이가 11월 칭찬왕이 되어 외출을 다녀왔습니다.(2013. 12. 07)','<font face="굴림">룻2방에서는 한달간 학교생활, 원내생활을 성실하고 착실하게 할 때마다 칭찬을 하면서 상점을 주어 그 달 칭찬왕을 뽑고 룻2방 담당교사와 함께 데이트를 할 수 있는 시간을 가지고 있습니다.</font>
<div><font face="굴림">11월 룻2방 칭찬왕은 초등학생 맏언니 *민이가 되었습니다. 평소 엉뚱하긴 하지만 11월 생활을 하면서 동생들의 본보기가 될 수 있도록 성실하게 생활해준 *민이가 기특하고 자랑스럽습니다.</font></div>
<div><font face="굴림">*민이는 담당교사와 평소 읽고 싶었던 책을 읽고 그동안 함께 나누고 싶었던 이야기를 나누기 위해 외출을 하고 귀가하였습니다.</font></div>
<div><font face="굴림">맛있는 파스타도 먹고 즐거운 시간을 보내고 귀가하였습니다.</font></div>
<div><font face="굴림">앞으로도 *민이가 원내생활, 학교생활을 잘 하여 바르게 성장할 수 있도록 지원하겠습니다.</font></div>
<div>　</div>
<div>　</div>          </td>
        </tr>',731,1386342000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9319,'dus3','이소영','leesy5576@hanmail.net','룻2방 중학생이 신세계푸드후원 영화관람을 하고 귀가하였습니다.','2013년 12월 7일 룻2방&nbsp;<span style="text-align: -webkit-center">*</span>리,&nbsp;<span style="text-align: -webkit-center">*</span>희,&nbsp;<span style="text-align: -webkit-center">*</span>선,&nbsp;<span style="text-align: -webkit-center">*</span>진이가 신세계푸드후원 영화관람을 다녀왔습니다.

<div>얼마전 개봉한 "오싱"이라는 일본영화를 보았는데 실화를 바탕으로 한 영화이기도 하고 일본에서 베스트셀러로 영화를 보고 난 후 원작과 비교하고 느낀점을 공유하는 좋은 시간이 되었습니다.</div>
<div>영화를 보고 난 후 후원자님과 명동 미스터피자에 가서 점심식사도 함께 하였습니다.</div>
<div>아이들과 대화할 수 있는 공통점을 찾고 어색하지 않도록 진행해주셔서 아이들이 맛있고 편안한 점심식사를 하였습니다.</div>
<div>아이들에게 좋은 문화체험을 할 수 있도록 후원해주신 신세계푸드 후원자님 감사드립니다.</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',804,1386342000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9318,'dus3','이소영','leesy5576@hanmail.net','룻2방 *별, *민이가 명문법률사무소후원 생일파티에 다녀왔습니다.(2013. 12. 07)','2013년 12월 7일 룻2방 *별, *민이가 11월 명문법률사무소후원 생일파티에 다녀왔습니다.

<div>아이들이 좋아하는 아웃백에 가서 스테이크와 파스타를 먹으며 후원자님과 점심식사를 하고 귀가하였습니다.</div>
<div>오랫동안 아이들 생일파티 점심식사를 후원해주고 계신 명문법률사무소 후원자님 감사드립니다.</div>          </td>
        </tr>',768,1386342000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9322,'dus3','정다올','ekdhf1989@naver.com','바울방 박*호,오*재,전*호 아동이 어린이집에서 만든 김치 사진입니다.','<p>우리 바울방 박*호, 오*재,전*호 아동이</p>
<p>오늘 어린이집에서 김치를 만들어서 왔습니다.</p>
<p>우리 아동들에게 여러가지 체험을 하게 해주시는 필동 어린이집 </p>
<p>선생님들께 감사드립니다.^ㅡ^</p>          </td>
        </tr>',764,1386255600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9321,'dus3','송명은','happysme@hanmail.net','룻2방 *별,*진이가 즐거운 김장 담그기를 하였습니다.(2013.12.06)','룻2방의 사랑스러운 미취학 아동인 *별이와 *진이가 필동어린이집에서 김장 담그기 프로그램에 참여하였습니다.
<div>&nbsp;미리 준비한 쪽파를 넣은 맛있는 양념으로 버무린 배추김치를 한포기씩 가져오는 *별이와 *진이의 표정이 너무나 뿌듯한 얼굴이었습니다.&nbsp;</div>
<div>아이들이 직접 만든 김치라서 그런지 더 맛있어 보였습니다.&nbsp;</div>
<div>아이들에게 유익한 체험활동을 할 수 있도록 해주신 필동어린이집 선생님들께 감사드립니다.&nbsp;</div>
<div>맛있는 김치먹고 씩씩하게 성장할 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',739,1386255600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9323,'dus3','김성재','thunderdog9@naver.com','모세방 임*현 성수공고 합격(2013.12.06)','모세방&nbsp;임*현 아동이 성수공업고등학교 그린에너지과에 합격하여 오늘 합격증을 받아왔습니다. 진로와 관련해서 고민을 많이 했는데 다행히 멀지 않은 곳에 위치한 학교에 다니게 되었습니다. 고등학생이 되는 만큼 앞으로는 공부도 더 열심히 하고 미래를 위해 고민하는 시간을 더 많이 가질 수 있기를 바라며, 즐겁고 보람찬 고교생활을 해나가도록 응원하고 뒷바라지 하겠습니다.          </td>
        </tr>',812,1386255600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9325,'dus3','송명은','happysme@hanmail.net','룻2방 *민,*영이가 키자니아체험학습을 다녀왔습니다.','남산초등학교에 다니고 있는 룻2방의 *민,*영이는 교육복지특별지원사업으로 실시한 문화예술나들이 프로그램으로 "키자니아"체험학습을 다녀왔습니다.

<div>키자니아는 아동들이 직접 여러가지 직업들을 체험할 수 있도록 구성되어 있는 유익한 프로그램입니다.&nbsp;</div>
<div>이런 귀한 프로그램에 우리 *민이와 *영이가 참여할 수 있도록 해주신 남산초등학교 선생님들께 감사드립니다.&nbsp;</div>
<div>앞으로 우리 아동들이 미래에 대한 희망을 갖고 생활할 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',823,1386082800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9326,'dus3','이소영','leesy5576@hanmail.net','룻2방 *별, *진이가 현장학습을 다녀왔습니다.(2013. 12. 03)','2013년 12월 3일 룻2방 *별, *진이가 필동어린이집 현장학습을 다녀왔습니다.

<div>대한민국 역사 문화관(광화문)에 가서 견학도 하고 친구들과 맛있는 도시락도 먹으며 체험활동으로 태극기 모양 뺏지도 만들어 귀가하였습니다.</div>
<div>잠깐 추위가 주춤하는 사이 아이들이 외부활동을 할 수 있도록 지원해주신 필동어린이집 선생님 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',827,1385996400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9324,'dus3','김성재','thunderdog9@naver.com','모세방 김*철 성동공고 합격(2013.12.06)','진학을 위해 성동공업고등학교 전자기계과에 지원했던 모세방 김*철 아동이&nbsp;오늘 합격증을 받아왔습니다. 컴퓨터 전문가라는 진로를 이미 정해놓은 상황에서&nbsp;그에 맞게 적절한 학과를 선택하고 합격하게 되서 본인은 물론 원장님도 매우 기뻐하셨습니다. 워낙에 성실한 동*이인지라 고등학교 생활도 잘 해나갈 것이라고 믿으며 본인의 꿈을 이뤄나갈 수 있도록 지원하겠습니다.          </td>
        </tr>',760,1386255600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9328,'dus3','심주현','pikaccu85@hanmail.net','바울방 *호 어린이집 가는날!(2013.12.02)','오늘 바울방 막내 *호가 처음으로 어린이집에 등원하는날입니다! &nbsp;울지도않고 씩씩하게 나서는모습이 너무멋진*호!
<div>어린이집에 가서 많은친구들과 즐겁게 활동할수있도록 지원하겠습니다^^ &nbsp;</div>
<div><br></div>          </td>
        </tr>',783,1385910000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9327,'dus3','정다올','ekdhf1989@naver.com','바울방 손*민 , 이*슬 두발 정리 하고 왔습니다.','<p>우리 바울방 손*민 아동과 이*슬 아동이 머리가 길어서</p>
<p>깔끔하게 두발 정리를 하였는데요 </p>
<p>너무 이쁘지 않나요?^^</p>
<p>앞으로는 아이들 두발관리에 더 신경 쓰겠습니다.^ㅡ^</p>          </td>
        </tr>',788,1385910000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9329,'dus3','이소영','leesy5576@hanmail.net','룻2방 중학생 온누리교회멘토링 사진입니다.(2013. 11. 30)','2013년 11월 30일 룻2방 중학생&nbsp;<span style="text-align: -webkit-center">*</span>리, &nbsp;<span style="text-align: -webkit-center">*</span>선,&nbsp;<span style="text-align: -webkit-center">*</span>희,&nbsp;<span style="text-align: -webkit-center">*</span>진이가 온누리교회 멘토링에 참여하였습니다.

<div>멘토와 마인드맵을 그리고 자신의 꿈을 이야기하고 발표하는 시간을 가지며 시간을 보냈습니다.</div>
<div>꿈도 많고 하고 싶은 것도 많은 우리 아이들에게 좋은 말씀과 경험담을 이야기 해주시며 아이들에게 도움이 되고자 노력하시는 선생님들의 마음이 전해졌는지 남산원 아이들 모두 집중하고 프로그램에 임하는 모습이 너무 보기 좋고 뜻 깊은 시간이였던 것 같습니다.</div>
<div>지속적으로 남산원에 관심가져주시고 프로그램 진행해 주셔서 감사드립니다.</div>          </td>
        </tr>',795,1385910000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9330,'dus3','심주현','pikaccu85@hanmail.net','만복림 후원자님 학용품 후원사진 입니다. (2013.11.30)','<p>오늘 방문해 주신 만복림 후원자님께서 아이들이 학습에 필요한 </p>
<p>종합장, 스프링노트, 샤프심을 후원해 주셨습니다. </p>
<p>아이들이 학습하는데 많은 도움을 주셔서 감사합니다~ </p>
<p>앞으로도 남산원 아이들에게 많은 관심과 사랑 부탁드립니다 ^-^*</p>          </td>
        </tr>',769,1385823600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9331,'dus3','송명은','happysme@hanmail.net','룻2방은 만복림 후원프로그램에 참석하였습니다.(2013.11.30)','오늘 처음으로 남산원을 방문해주신 만복림에서 남산원 아동들을 위해 맛있는 점심으로 자장면과 탕수육을 후원해주셨습니다. 룻2방의 막내인&nbsp;<span style="text-align: -webkit-center">*</span>현이도 맛있는 자장면과 탕수육을 감사한 마음으로 먹었습니다. 또 식사후에는 너무나 멋진 마술사님께서 남산원 아동들을 위한 신기한 마술까지 보여주셨습니다. 11월의 마지막날에 만복림 후원자분들로 인해 아동들의 기억에 남을만한 즐거운 하루를 보냈습니다.

<div>앞으로도 우리 남산원 아동들을 위한 끊임없는 관심과 사랑을 부탁드립니다.^^</div>          </td>
        </tr>',781,1385737200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9332,'dus3','송명은','happysme@hanmail.net','룻2방의 중학생들은 온누리교회 멘토선생님들께 따뜻한 선물을 받았습니다.(2013.11.30)','11월 마지막날 온누리교회 멘토선생님들께서 남산원을 방문해주셔서 중고생 아동들에게 올한해 감사했던 일들과 아쉬웠던 일들을 다시한번 되돌아볼수 있는 의미있는 시간을 보낼 수 있도록 해주셨습니다.
<div>또 아동들 한명 한명에게 따뜻하고 예쁜 선물을 주셨습니다. 룻2방의 아동들도 멘토분들께 받은 목도리,장갑,털모자,니트를 받고 너무나 기뻐하였습니다.</div>
<div>앞으로도 우리 남산원 아동들의 멘토가 되어서 우리 아동들도 훗날 누군가에게 귀한 멘토의 역할을 할 수 있는 멋진 아동으로 성장할 수 있도록 많은 기도 부탁드립니다.^^</div>          </td>
        </tr>',798,1385737200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9334,'dus3','이소영','leesy5576@hanmail.net','룻2방 나*가 후원자님께 선물을 받았습니다.(2013. 11. 29)','2013년 11월 29일 룻2방 나*의 특기적성수업을 지도해주셨던 이윤선선생님께서 방문하셔서 오랜만에 만나는 나*에게 좋은말씀도 해주시고 나*의 간식도 선물해주셨습니다.
<div>추운날씨에 남산원 방문해주셔서 감사드립니다.</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',768,1385737200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9335,'dus3','심주현','pikaccu85@hanmail.net','바울방 환경심사 1위 저녁식사 사진입니다!(2013.11.29)','<p>바울방이 11월 환경심사 1위를 하여 맛있는 저녁식사 시간을 가졌습니다. </p>
<p>아이들이 좋아하는 피자와 치킨을 먹었는데요 ^^</p>
<p>역시나 아이들이 저녁시간 내내 너무 너무 좋아하였습니다. </p>
<p>신나하는 아이들과 12월 환경심사를 이야기 나누며 다음달도 열심히 하자 다짐하였답니다!</p>
<p>멋진 바울방을 기대해 주세요!! </p>          </td>
        </tr>',783,1385737200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9333,'dus3','정다올','ekdhf1989@naver.com','바울방 오*진,이*결아동 컴퓨터 자격증 합격했습니다.','<p>바울방 오*진 아동과 이*결 아동이 컴퓨터 자격증을 획득하는 기쁜소식이 전해져 왔습니다.</p>
<p>우리 아이들이 시험에 대비해서 열심히 하는 모습을 보았기 때문에 자격증 획득소식이 정말 기쁘고 우리아이들이 자랑스러웠습니다.^^</p>
<p>앞으로도 항상 열심히 하도록 지도하겠습니다.&gt;0&lt;</p>          </td>
        </tr>',780,1385737200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9336,'dus3','송명은','happysme@hanmail.net','룻2방의 *선이가 ITQ 파워포인트 자격증시험에 합격하였습니다.(2013.11.28)','지난 11월 9일 ITQ 파워포인트 자격증시험을 보았던 룻2방의&nbsp;<span style="text-align: -webkit-center">*</span>선이가 오늘 합격했다는 너무나 기쁜 소식을 듣게 되었습니다. 시험을 준비할 수 있는 기간이 짧아서 걱정을 많이 하면서 시험을 보았는데 자랑스럽게도 합격을 했다는 좋은 결과를 받게 되어서 너무나 기뻐했습니다.

<div>자격증 시험을 준비할 수 있도록 지도해주신 LG퍼포먼스 동아리 선생님들께 진심으로 감사드립니다.</div>          </td>
        </tr>',4724,1385564400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9337,'dus3','송명은','happysme@hanmail.net','룻2방 아동들에게 이진경후원회장님께서 달콤한 선물을 주셨습니다.(2013.11.28)','항상 남산원 아동들을 잊지 않으시고 사랑하는 마음으로 기도해주시며 후원해주시는 이진경 후원회장님께서 오늘은 룻2방 아동들에게 맛있고 달콤한 컵케익을 선물해주셨습니다. 여러가지 귀여운 모양의 컵케익은 너무나 예뻐서 먹기에도 아까울 정도였답니다.
<div>추운 겨울날 남산원 아동들을 위해 방문해주시고 또 달콤한 선물까지 주셔서 너무나 감사드립니다.</div>          </td>
        </tr>',750,1385564400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9338,'dus3','김선기','spsp99@naver.com','다윗방 이*울아동 이진경후원자님께 선물을 받았습니다.(2013.11.28)','<p>이진경후원자님께서 *울이에게 맛있는 크림 빵을 선물해 주셨습니다.</p>
<p>*울이는 기뻐하며 감사하며 다윗방 아동들과 같이 맛있게 먹었습니다.</p>          </td>
        </tr>',805,1385564400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9340,'dus3','이소영','leesy5576@hanmail.net','룻2방 *별이의 일곱번째 생일입니다.(2013. 11. 27)','2013년 11월 27일 룻2방 *별이의 일곱번째 생일, 아이들 모두 저녁에 모여 생일파티를 하며 *별이의 생일을 진심으로 축하해 주었습니다.

<div>남산원 아빠, 엄마, 언니 모두 *별이에게 선물을 주어 *별이가 무척 기뻐하고 즐거워하였습니다.</div>
<div>앞으로도 *별이가 건강하게 성장할 수 있도록 보육하겠습니다.</div>
<div><br />&nbsp;

<div>　</div></div>          </td>
        </tr>',801,1385478000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9341,'dus3','이소영','leesy5576@hanmail.net','룻2방, 초등학생(*민,*영,*연,*민)이 교육복지프로그램을 마쳤습니다.(2013. 11. 26)','룻2방 초등학생 *민, *영, *연, *민이가 남산초등학교 2학기 교육복지프로그램, "요리사의 꿈"을 종결하고 그동안의 수업내용이 담긴 책과 스티커를 받아 귀가하였습니다.

<div>케익, 쿠키, 무쌈말이등 아이들이 평소 좋아하는 음식을 직접만들어 보며 매주 목요일 요리체험을 하고 귀가하였는데 수업이 종결되어 아쉬워하였지만 마무리를 잘 하였습니다.</div>
<div>요리수업을 하며 다친 곳 없이 잘 이끌어주시고 지원해주신 남산초등학교 선생님들께 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',811,1385391600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9339,'dus3','이소영','leesy5576@hanmail.net','룻2방 *리가 후원자님께 겨울옷을 선물받았습니다.(2013. 11. 27)','2013년 11월 27일 룻2방 *리가 후원자님께 겨울옷을 선물 받았습니다.
<div>날씨가 많이 추워져 꼭 필요했던 패딩을 선물받아 *리가 무척 좋아하였습니다.</div>
<div>외모에 관심이 많아지는 시기에 *리에게 따뜻한 관심과 사랑을 주셔서 감사드립니다. 이번 겨울 건강하게 지낼 수 있도록 지원하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',792,1385478000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9343,'dus3','정다올','ekdhf1989@naver.com','바울방 *호와 *재는 침례교회 주일예배에 참석합니다.','<p>우리 바울방 *호 와 *재가 주일예배에 참석하여서</p>
<p>놀이를 하고 있는 모습이 너무 사랑스럽습니다.</p>
<p>앞으로도 건강하게만 자라주었으면 좋겠습니다.^^</p>          </td>
        </tr>',823,1385305200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9344,'dus3','송명은','happysme@hanmail.net','룻2방 *연이가 10월의 칭찬왕이 되었습니다.(2013.11.24)','룻2방에서는 평소 학교생활과 원내생활에서의 모습을 보고 칭찬을 해주면서 이런 칭찬받는 행동을 할때 마다 상점을 준답니다.&nbsp;
<div>그래서 매달 한번씩 그달에 제일 높은 상점을 받은 아동과 룻2방 선생님과의 즐거운 데이트시간을 보낸답니다.&nbsp;</div>
<div>10월의 칭찬왕은 초등부의 똑순이 *연이가 선정되었습니다.</div>
<div>*연이와 룻2방 선생님은 함께 맛있는 점심식사를 하고 재미있는 만화영화를 보면서 관계형성을 할 수 있는 귀한 시간을 보냈습니다.&nbsp;</div>
<div>앞으로 룻2방 모두가 칭찬받는 그날을 생각하며 열심히 보육하겠습니다.</div>          </td>
        </tr>',850,1385305200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9342,'dus3','송명은','happysme@hanmail.net','룻2방의 *영이와 *연이가 상장을 받았습니다.(2013.11.25)','룻2방의 *영이와 *연이는 남산초에서 실시되었던 "교내 독서발표대회"에서 *영이는 우수상을&nbsp;<span style="text-align: -webkit-center">*</span>연이는 최우수상을 받았습니다.&nbsp;

<div>작고 어린줄로만 알고 있던 우리 아이들이 상장을 받아온 것이 너무나 기특하고 사랑스러웠습니다.&nbsp;

<div>어릴때부터 독서하는 습관을 길러서 정서적으로 안정되고 성숙한 아동들로 성장할 수 있도록 지원하겠습니다.</div></div>          </td>
        </tr>',819,1385305200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9347,'dus3','이소영','leesy5576@hanmail.net','룻2방 *민이가 23회 아동복지종합예술제 그림부문에서 입선을하였습니다.(2013. 11. 23)','2013년 11월 23일 룻2방 *민이가 23회 아동복지 종합예술제 그림부문에서 입선을 하여 시상식에 다녀왔습니다.

<div>평소 그림과 글짓기에 관심을 가지고 재능을 보이는 *민이가 입상을 하게 되어 무척 뿌듯하고 기쁩니다.</div>
<div>장래희망이 PD인 *민이가 여러가지 경험을 하고 꿈을 펼쳐나갈 수 있도록 지원하도록 하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',837,1385132400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9345,'dus3','송명은','happysme@hanmail.net','룻2방 *별이와 *진이는 침례교회 주일예배에 참석합니다.(2013.11.24)','매주 일요일마다 룻2방의 *별이와 *진이는 침례교회 유치부예배에 참석한답니다.&nbsp;
<div>어릴때부터 하나님의 사랑안에 즐거운 마음으로 예배를 드리면서 생활하고 있습니다.&nbsp;</div>
<div>오늘은 예배를 드리기전에 재활용품을 가지고 각자가 만들고 싶은 모양을 만들어보는 시간을 갖기도 하였습니다.&nbsp;</div>
<div>그리고 특별히 27일(수)에 생일을 맞이한 *별이의 생일파티를 해주셔서 더욱더 기쁜 하루였습니다.

<div>앞으로도 우리 아동들이 열심히 종교생활을 할 수 있도록 열심히 보육하겠습니다.</div></div>          </td>
        </tr>',808,1385218800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9346,'dus3','이소영','leesy5576@hanmail.net','룻2방 *민이가 강석연선생님께 생일선물을 받았습니다.(2013. 11. 23)','2013년 11월 23일 룻2방 *민이의 학습을 지도해주고 계신 강석연선생님께서 11월 22일 *민이의 여덟번째 생일을 축하해주시며 생일선물로 *민이가 좋아하는 과자를 선물해주셨습니다.

<div>당일날 축하해 주지 못해 아쉬워하시며 *민이의 생일을 진심으로 축하해 주셨습니다.</div>
<div>*민이를 후원해주시는 여러 후원자님들의 관심과 사랑으로 *민이가 &nbsp;건강하고 밝게 자랄 수 있는 것 같습니다.</div>
<div>재능기부해주시고 계신 강석연선생님 진심으로 감사드립니다.</div>
<div>　</div>          </td>
        </tr>',835,1385132400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9349,'dus3','송명은','happysme@hanmail.net','룻2방 *민이의 8번째 생일파티를 했습니다.(2013.11.22)','룻2방의 귀염둥이 *민이가 8번째 생일을 맞이하였습니다.&nbsp;
<div>올해 초등학교에 입학해서 학교에서도 잘 적응하면서 생활하고 친구들과의 관계도 좋은 기특한 우리 *민이가 태어난 축복된 날입니다.&nbsp;</div>
<div>룻2방 모든 가족들이 *민이를 사랑하는 마음을 가득 담아서 생일파티를 하였습니다.&nbsp;</div>
<div>생일선물로 예쁘고 따뜻한 옷과 *민이가 좋아하는 여러가지 간식들을 받으면서 기뻐하는 *민이가 앞으로 건강하고 씩씩하게 성장할 수 있도록 보육하겠습니다.

<div>사랑받기위해 태어난 *민아~앞으로 더 많은 사랑과 축복을 받으면서 건강하고 예쁜게 자라길 기도할께~사랑해~^^</div></div>          </td>
        </tr>',779,1385046000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9348,'dus3','이소영','leesy5576@hanmail.net','룻2방 *민, *연이가 오수영후원자님과 점심외출을다녀왔습니다.(2013. 11.23)','<font face="굴림">2013년 11월 23일 룻2방&nbsp;*민,&nbsp;*연이가 오수영후원자님과 점심식사외출을 하고 귀가하였습니다.</font>
<div style="font-family: 굴림"><div style="font-family: 굴림" 굴림;"="">11월22일 *민이의 여덟번째 생일을 맞이하여 후원자님 가족과 함께 점심을 먹고 생일케이크와 아이들이 함께 먹을 수 있도록 빵을 선물해주셨습니다.</div>
<div style="font-family: 굴림" 굴림;"="">*민이, *연이를 오랫동안 뒤에서 지켜봐주시고 계신 오수영후원자님 감사드립니다.</div></div>          </td>
        </tr>',833,1385132400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9352,'dus3','심주현','pikaccu85@hanmail.net','바울방 막내 민*의 그림활동 사진입니다.(2013.11.21)','<p>오늘 민*는 형들이 어린이집과 학교에 가고 난 뒤에 </p>
<p>바울방에서 즐거운 미술 시간을 가졌습니다. </p>
<p>민*만큼 큰 그림 스케치북을 가지고 색칠 공부를 하였는데요 ^^</p>
<p>다양한 색깔을 가지고 번갈아 가면서 색칠 하는 모습이 너무 귀엽기만 합니다. &gt;.&lt;</p>
<p>늘 궁금한것도 많고 웃음도 많은 민*가 바울방에서 즐겁게 생활할 수 있도록 </p>
<p>지원하겠습니다. ^^</p>          </td>
        </tr>',799,1384959600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9350,'dus3','박현정','kingi109@naver.com','한나방 김*름 아동 네일아트 대회 동상 수상(2013.11.10)','<div align=\'LEFT\'><a href=javascript:viewImg(\'1385109296/drgdrgdr.jpg\');><img src=\'/admin/data/bbs/dus3/1385109296/drgdrgdr.jpg\' border=\'0\' name=\'wiz_target_resize\'></a></div>        	      		      		<table border=0 cellspacing=0 cellpadding=0 style=\'width:700px;height:0px;\' id=\'wiz_get_table_width\'>
