INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9351,'dus3','이소영','leesy5576@hanmail.net','룻2방 유*이가 징검다리체험학습을다녀왔습니다.(2013. 11. 21)','2013년 11월 21일 룻2방 유*이가 덕수중학교에서 징검다리 체험학습을 다녀왔습니다.
<div>기말고사가 끝나고 고등학교 원서를 쓰면서 정상수업을 대체하여 현장체험학습을 하고 있습니다.</div>
<div>첫 현장체험 학습은 진로체험으로 에이스침대 기업체 견학을 하고 귀가하였습니다. 견학 중 발표를 많이 하여 담요를 3개나 받아와서 학교에서 적극적이고활발한 유*이가 기특하였습니다.</div>
<div>졸업하기 전까지 자유시간이 많이 주어진 유*이에게 좋은 경험을 할 수 있도록 지원하겠습니다.</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',788,1384959600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9353,'dus3','송명은','happysme@hanmail.net','룻2방 *민,*영이가 침례교회 선생님과 즐거운 저녁식사를 하였습니다.(2013.11.20)','몇일전 첫눈이 내리고 영하로 떨어진 날씨에도 침례교회 초등부를 담당하고 계시는 김민아선생님께서 룻2방의 *민,*영이와 함께 즐거운 저녁식사시간을 보내시려고 방문해주셨습니다.
<div>&nbsp;김민아선생님과 룻2방 아동들은 맛있는 치킨과 햄버거를 먹으면서 따뜻한 저녁시간을 보냈습니다.</div>
<div>아이들에게 보여주시는 많은 관심과 사랑으로 우리 아이들 모두 건강하게 겨울을 보낼 수 있을 것 같습니다. 다시한번 감사드립니다.^^</div>          </td>
        </tr>',765,1384873200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9354,'dus3','정다올','ekdhf1989@naver.com','바울방 손*민,최*명 아동 침례교회 선생님과의 나들이(2013.11.20)','<p>바울방 손*민 아동과 최*명 아동이 침례교회 김미나 선생님과 함께</p>
<p>맛있는 저녁을 먹고 왔습니다.</p>
<p>항상 저희 아이들에게 관심과 사랑을 주셔서 감사합니다^^</p>          </td>
        </tr>',791,1384873200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9356,'dus3','이소영','leesy5576@hanmail.net','룻2방이 한국3M후원자님께선물을받았습니다.(2013. 11. 16)','2013년 11월 16일 한국3M 후원 프로그램이 끝난 후 후원자님께서 룻2방 아이들 전부에게 카드지갑을 선물해주셨습니다.
<div>교통카드를 쓰는 초등학생, 중학생 아이들에게 꼭 필요한 물품이여서 아이들이 무척 좋아하였습니다.</div>
<div>아이들의 기준에서 프로그램 재미있게 진행해주시고 후원해주셔서 감사드립니다.</div>
<div>　</div>          </td>
        </tr>',802,1384614000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9357,'dus3','이소영','leesy5576@hanmail.net','한국3M후원자님이  룻2방 *별,*민이의 생일파티를해주셨습니다.(2013. 11. 16)','<font face="굴림">2013년 11월 16일 한국3M 후원프로그램 진행 중 후원자님께서 11월&nbsp;*별,&nbsp;*민이의 생일을 아시고 깜짝 생일파티를 준비해주셨습니다.</font><br />
<div>*<font face="굴림">별,&nbsp;*민이를 닮은 귀여운 케익과 선물까지 준비해주셔서 많은 사람들과 함께 생일을 축하해주었습니다.</font></div>
<div><font face="굴림">프로그램을 진행하면서 세심한 부분까지 신경써주시고 후원해주신 한국3M 후원자님 감사드립니다.</font></div>          </td>
        </tr>',831,1384614000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9358,'dus3','박충일','a7124383@nate.com','다윗방 3총사 초등생 아동이  양평레일바이크에 다녀왔습니다.','<p>다윗방 초등생(6학년) 3총사&nbsp; 김용, 김도현, 김민수아동이 </p>
<p>3M 후원으로 양평에 있는 레일바이크를 체험하고 피자만들기와 자신들이 직접만든</p>
<p>피자를 맛있게 먹고 즐거운 하루를 보냈습니다. </p>          </td>
        </tr>',819,1384527600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9360,'dus3','심주현','pikaccu85@hanmail.net','바울방 한국3M 나들이 프로그램 사진입니다.(2013.11.16)','<p>오늘 바울방 아동들과 양평에 있는 피자치즈 만들기 체험과 레일바이크를 타고 왔습니다. </p>
<p>후원자님들과 함께 조를 이뤄 치즈와 피자 만들기를 하고 우리가 직접 만든 피자를 점심으로 맛있게 먹었습니다. </p>
<p>오후엔 양평 레일바이크에서 열심히 페달을 돌렸는데요 ^-^</p>
<p>아이들이 코스가 너무 짧다고 말을 할 정도로 추운줄도 모르고 신나고 즐겁게 활동을 하였습니다. </p>
<p>오늘 우리 아이들에게 즐거운 주말을 선사해 주신 한국 3M 후원자님께 진심으로 감사드립니다. (^^)(__)(^^)</p>
<p>&nbsp;</p>          </td>
        </tr>',818,1384527600,'', '', '', '', '', '');
