INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9362,'dus3','이소영','leesy5576@hanmail.net','룻2방 *리가 후원자님께 겨울옷을선물받았습니다.(2013. 11. 14)','<p align="center">2013년 11월 14일 룻2방 *리가 김미란 후원자님께 겨울옷을 선물받았습니다.</p>
