INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9363,'dus3','송명은','happysme@hanmail.net','룻2방 *진이가 후원자님께 따뜻한 선물을 받았습니다.(2013.11.13)','룻2방의 *진이가 후원자님으로부터 따뜻한 겨울잠바와 학생용 화장품을 선물받았습니다. 일찍 찾아온 추운 날씨지만 후원자님께 받은 겨울잠바를 입고 따뜻한 겨울을 보낼 수 있게 되었습니다. 또 한참 사춘기시절이라서 외모에 관심이 많은 *진이에게 학생들이 사용하는 기초화장품을 보내주셨습니다. 몸과 마음이 예쁜 아동으로 성장할 수 있도록 보육하겠습니다.          </td>
        </tr>',781,1384268400,'', '', '', '', '', '');
