INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9364,'dus3','송명은','happysme@hanmail.net','룻2방 *선이가 전통문화체험 프로그램에 참여하였습니다.(2013.11.12)','룻2방의 모범생&nbsp;<span style="text-align: -webkit-center">*</span>선이가 덕수중학교의 프로그램인 전통문화체험 프로그램에 참여하게 되었습니다. 담임선생님이 추천한 아동들만 참여할 수 있는 프로그램에 우리&nbsp;<span style="text-align: -webkit-center">*</span>선이도 당당하게 담임선생님의 추천을 받아서 경기도 안성에 있는 신원도예센터에 가서 액자도 만들고 도자기를 만들면서 문화체험을 하였습니다.

<div>앞으로도 지금처럼 학교생활에 충실할 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',780,1384268400,'', '', '', '', '', '');
