INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9368,'dus3','박현정','kingi109@naver.com','한나방 선* 아동 ucc콘테스트 최우수상 수상','<p align="center">* 한나방 선* 아동이 2013.10.22에 교내 ucc 콘테스트에서 최우수상(1위)를 받았습니다.</p>
<p align="center">학교생활도 열심히 하며, 노력하는 선*이가 대견스러워, 학교 담임선생님께서도 칭찬을</p>
<p align="center">많이 해주십니다. 선*이가 열심히 생활할 수 있도록 적극 지원하겠습니다. 감사합니다.</p>          </td>
        </tr>',785,1384095600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9367,'dus3','박충일','a7124383@nate.com','다윗방 멘토링직업체험프로그램','<p>2013년 11월 9일 주말을 맞이하여 중고생직업프로그램으로 </p>
<p>멘토링선생님과 함께 </p>
<p>다윗방 이하늘과 김웅아동이 국회의사당에 다녀왔고</p>
<p>다윗방 이한울은 룻2방 강나리아동과함께 하늘공원에&nbsp;다녀왔습니다.&nbsp;</p>          </td>
        </tr>',811,1384182000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9369,'dus3','송명은','happysme@hanmail.net','룻2방 *민,*영이가 후원자님께 선물을 받았습니다.(2013.11.10)','<p>11월달에 생일인 *민이는 침례교회 초등부예배때 생일파티를 하면서 초등부 선생님께 "지혜 쏙쏙 재미 팍팍"이라는 만화로 된 성경이야기 책을 선물로 받았습니다. 또 내일 빼빼로데이를 기념하면서 예쁜 빼빼로도 받았답니다.</p>
<p>또 *영이는 매주 일요일마다 *영이의 영어학습지도를 해주시는 유혜종선생님으로부터 너무나 귀여운 캐릭터가 그려진 필기도구세트를 선물로 받았습니다.</p>
<p>항상 우리 남산원 아동들에게 많은 관심과 사랑을 보여주시는 후원자분들께 다시한번 감사드립니다.</p>
<p>갑작스럽게 추워진 날씨에 아동들의 마음이 훈훈해지는 하루였습니다.</p>
<p>감사합니다.^^</p>          </td>
        </tr>',789,1384009200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9370,'dus3','이소영','leesy5576@hanmail.net','룻2방 미취학, 초등학생 신세계푸드후원프로그램사진입니다.(2013. 11. 09)','2013년 11월 9일 룻2방&nbsp;<span style="text-align: -webkit-center">*</span>현,&nbsp;<span style="text-align: -webkit-center">*</span>별,&nbsp;<span style="text-align: -webkit-center">*</span>진,&nbsp;<span style="text-align: -webkit-center">*</span>민이가 신세계푸드 후원프로그램 디보랜드키즈카페에 다녀왔습니다.

<div>야외에 나가서 놀기에 쌀쌀해지는 날씨때문에 아이들이 실내에서 생활하는 시간이 많은데 실내키즈카페에 갈 수 있도록 후원해주셔서 아이들이 매우 신나고 재미있게 놀 수 있었습니다.</div>
<div>점심식사도 아이들이 좋아하는 아웃백에 가서 스테이크를 후원해주셔서 맛있게 먹고 귀가하였습니다.</div>
<div>아이들에게 좋은 추억과 경험을 만들어주신 신세계푸드 후원자님 진심으로 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',785,1383922800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9371,'dus3','심주현','pikaccu85@hanmail.net','바울방 신세계푸드 후원~디보빌리지 다녀온날!!(2013.11.09)','<p align="center">오늘 미취학부터 초등학교 저학년까지 </p>
<p align="center">신세계푸드 후원자과 함께 디보빌리지에 다녀왔습니다!!</p>
<p align="center">실내 놀이동산에서 아이들이 매우 즐겁게 활동했는데요 ^^</p>
<p align="center">기차도 타고, 3D영화도 보고, 4D체험관도 가는 등 아이들이 너무 즐겁워 했답니다. </p>
<p align="center">넓은 공간에서 동화나라에 온듯 이리저리 구경하고 </p>
<p align="center">체험하고 활동하는냐고 정신이 없었는데요~</p>
<p align="center">신나게 놀고 맛있는 아웃백 점심식사 까지 아이들을 위해 </p>
