INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9372,'dus3','송명은','happysme@hanmail.net','룻2방은 필동어린이집 동요발표회에 참석하였습니다.(2013.11.08)','룻2방의 미취학 아동들이 등원하고 있는 필동어린이집 동요발표회에 참석하였습니다. 오늘은 언니들의 공연을 관람하기 위해 룻2방의 막둥이인&nbsp;<span style="text-align: -webkit-center">*</span>현이도 함께 다녀왔습니다. 그동안 원에서도 열심히 준비한 멋진 실력을 발휘하는&nbsp;<span style="text-align: -webkit-center">*</span>별이와&nbsp;<span style="text-align: -webkit-center">*</span>진이가 너무나 대견스러웠습니다.

<div>그런 모습을 집중하며 진지한 모습으로 바라보는&nbsp;<span style="text-align: -webkit-center">*</span>현이도 내년부터는 어린이집에 등원해서 언니들보다 더 멋진 공연을 하기로 약속하였습니다.</div>
<div>앞으로도 우리 룻2방의 아동들이 자신감 넘치는 아동으로 성장할 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',829,1383836400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9374,'dus3','정다올','ekdhf1989@naver.com','바울방 아이들 바깥놀이 사진입니다.','<p>바울방 아이들 바깥놀이 사진입니다.</p>
