INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9376,'dus3','심주현','pikaccu85@hanmail.net','바울방 최*명, 손*민 아동 침례교회 선생님과의 나들이!!(2013.11.06)','<p align="center">서울침례교회 초등부 김민아 선생님과 함께 </p>
