INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9375,'dus3','송명은','happysme@hanmail.net','룻2방이 환경심사 1등을 해서 맛있는 저녁식사를 하였습니다.(2013.11.06)','지난 10월달에 룻2방 아동들이 모두 힘을 합해서 열심히 청소한 결과 환경심사 2관왕이라는 영광스러운 일이 일어났습니다. 역시 열심히 노력하면 좋은 결과를 얻게 된다는 교훈을 아동들 모두가 경험한 유익한 시간이었습니다. 그에따른 부상으로 아동들이 먹고 싶어한 치킨과 떡볶이, 간식등 맛있는 저녁식사를 하였습니다. 룻2방 아동들 모두 이렇게 즐거운 시간을 가질 수 있도록 해주신 남산원 아빠께 감사하는 마음으로 남기지 않고 맛있게 먹었답니다.
<div>추운 날씨에 아동들 모두 건강하게 생활할 수 있도록 열심히 보육하겠습니다.^^</div>          </td>
        </tr>',800,1383663600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9377,'dus3','정다올','ekdhf1989@naver.com','바울방 바깥 야외활동 사진입니다.(2013.11.03)','<p>오늘&nbsp; 바울방&nbsp; 야외 활동 시간을 가졌습니다.</p>
<p>노랗게 물든 은행 나무 앞에서 가을에 정취를 흠뻑 느끼는 아이들의 모습이 매우 해맑은 모습이었습니다.</p>
<p>그네타기와 훌라후프를 가지고 놀며 즐거운 시간을 가졌는데요.^^</p>
