INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9405,'dus3','남산원','6336110@hanmail.net','바울방 정*균 아동 생일파티를 하였습니다(2013.10.09)','<p align="center">&nbsp;</p>
