INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9407,'dus3','심주현','pikaccu85@hanmail.net','바울방 이*슬 아동이 후원자님께 선물을 받았습니다^^(2013.10.04)','<p>바울방 이*슬 아동이 CJ 성정현 상무님께 야구배트를 선물 받았습니다. </p>
<p>우리 *슬이 장래 희망이 야구선수인데요 ^^ 그래서 인지 *슬이 얼굴에 미소가 한가득 </p>
<p>너무 행복해 보였습니다. 우리 *슬이에게 그 무엇보다 1등 선물이 되었습니다. </p>
<p>*슬이를 위해 너무나 뜻깊은 선물을 준비해 주신 CJ 성졍현 상무님께 진심으로 감사드립니다. </p>          </td>
        </tr>',850,1380812400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9408,'dus3','이소영','leesy5576@hanmail.net','룻2방 초등학생이 사생대회에 참석하여 선물을받았습니다.(2013. 10. 01)','룻2방 초등학생&nbsp;*민,&nbsp;*영,&nbsp;*연, *민이가 서울시 아동복지협회에서 주최한 사생대회에 참여하여 오전에 "내가 사랑하는 애완동물"이라는 주제로 그림을 그리고 파우치를 선물받아 귀원하였습니다.

<div>그림그리는 것을 좋아하는 저희아이들에게 좋은 경험을 할 수 있도록 지원해주신 서울시 아동복지협회 후원자님 감사드립니다.</div>          </td>
        </tr>',850,1380553200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9409,'dus3','박충일','a7124383@nate.com','다윗방 김*석, 오*진아동 핸드폰구입','<p>1) *석 아동은 추석명절 가정방문중에 열심히 집안일(고추따기 등)을 돕고 받은 용돈으로&nbsp; 이번에 중고핸드폰을 구입하게 되었습니다. 가지고 있던 핸드폰이 고장이 나서 불편하게 지냈는데 중고핸드폰이지만 이번기회에 좋은 핸드폰을 구입하게 되어 본인 스스로도 매우 만족해하며 무엇보다 자신감이 생긴다는 말에 저 또한 기뻤습니다.</p>
<p>2) 오*진 아동은 아버님이 쓰시던 핸드폰을 직접 내원하셔서 받았습니다. 아버님께 연락도 자주 드리고 동생도 잘 챙기라고 지도하겠습니다.&nbsp; </p>
<p>&nbsp;</p>
<p>사진에서 나타나듯 오늘은 감사하고 기쁜날입니다. 잊어버리지않고 소중하게 오래 잘 쓸수 있도록 지도하겠습니다. </p>          </td>
        </tr>',813,1380466800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9410,'dus3','송명은','happysme@hanmail.net','룻2방이 서울랜드로 주말나들이를 다녀왔습니다.(2013-09-28)','아동복지협회에서 주최한 사생대회가 열린 서울랜드에 가게된 룻2방은 오전에는 열심히 그림을 그렸고 맛있는 점심식사후에 오후시간에는 아동복지협회에서 후원해주신 놀이공원 티켓을 가지고 신나고 즐겁게 놀이기구를 타면서 주말오후 시간을 유익하게 보냈습니다.
<div>우리 아동들의 숨은 그림실력도 뽐내면서 재미있는 놀이기구도 탈 수 있도록 해주신 서울시 아동복지협회분들께 감사드립니다.</div>          </td>
        </tr>',792,1380380400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9411,'dus3','송명은','happysme@hanmail.net','룻2방이 사생대회에 참석하였습니다.(2013-09-28)','룻2방 아동들은 서울시아동복지협회에서 "우리들이 꿈구는 세상"이라는 주제로 개최한 사생대회에 참석하였습니다. 서울랜드에 직접가서 여러가지 주제를 가지고 자유롭게 그림을 그렸습니다. 룻2방 아동들은 "내가 사랑하는 애완동물"이라는 주제를 가지고 각자가 좋아하는 동물을 예쁘게 그리는 유익한 시간을 보냈습니다.          </td>
        </tr>',783,1380380400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9412,'dus3','남산원','jblee4@naver.com','다윗방 3총사 초등아동 서울랜드에 다녀왔습니다.(2013.09.28)','<p>남산원 초등학생 아동들이 </p>
<p><span><font face="굴림">서울아동복지협회 <span><font face="굴림">주관 </font></span><font face="굴림"><span>"우리들이 꿈꾸는 세상</span><span style="letter-spacing: 0pt; font-family: 굴림" lang="EN-US">" </span><span>사생대회를다녀왔습니다</span><span style="letter-spacing: 0pt; font-family: 굴림" lang="EN-US">!</span></font></font></span></p>
<p>&nbsp;</p>
<p>다윗방 김도현, 김용, 김민수 아동은 평소 다윗방에서는 막내이지만</p>
<p>오늘만큼은 6학년으로 제일 큰 형, 오빠 노릇을 하고 왔습니다.</p>
<p>&nbsp;</p>
<p>그림도 그리고 맛난 음식과 간식도 먹고 빅5 이용권으로 놀이기구도 타고</p>
<p>오늘 하루 재미있게 보냈습니다. </p>
<p><span><font face="굴림"><font face="굴림"><span></span></font>&nbsp;</font></span></p>          </td>
        </tr>',815,1380380400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9414,'dus3','심주현','pikaccu85@hanmail.net','초등부 아동들이 서울대공원으로 사생대회를 다녀왔습니다.','오늘 서울대공원으로 "우리들이 꿈꾸는 세상" 사생대회를다녀왔습니다!
<div>우리 아이들은 그림그리기를 하였는데요~ 저마다 자신의 독창성으로 작품을 완성시키는데 최선을 다하는 모습이 매우 기특해보였습니다~</div>
<div>오전에 그리기 활동을하고 오후에는 빅5 이용권을 가지고 놀이기구를 타며 즐거운 주말을 보냈습니다^^♥</div>
<div>아이들에게 즐거운 하루를 선사해주신 서울아동복지협회에 진심으로 감사드립니다!^-^♥</div>          </td>
        </tr>',787,1380294000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9413,'dus3','심주현','pikaccu85@hanmail.net','바울  서울대공원 다녀온날!(2013.09.28)','오늘 우리들이꿈꾸는세상 사생대회에 참여하고자 서울 대공원에 다녀왔습니다^^
<div>그림도 그리고 놀이기구도 타고 ^^</div>
<div>아이들에게 너무 유익했던 하루였습니다!</div>
<div>프로그램을 주관해주신 서울아동복지협회에 감사드리며</div>
<div>아이들이 건강한 아동기를 보낼수있도록 지원하겠습니다!</div>          </td>
        </tr>',776,1380294000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9415,'dus3','송명은','happysme@hanmail.net','대림산업 후원프로그램에 다녀왔습니다.(2013-09-27)','오늘은 아가방의 씩씩한 왕자님들과 룻2방의&nbsp;<span style="text-align: -webkit-center">*</span>현이와 바울방의&nbsp;<span style="text-align: -webkit-center">*</span>호가 대림산업 후원프로그램으로 청계천에 위치한 디보랜드에 다녀왔습니다.&nbsp;

<div>갑작스럽게 쌀쌀해진 날씨로 인해 우리 아가들은 바깥놀이보다는 실내놀이를 위주로 생활하고 있었던 요즘!!</div>
<div>디보랜드라는 실내놀이터를 가게 된 우리 아가들은 너무나 즐겁고 신나게 놀이터의 이곳저곳을 뛰어다니면서 즐거운 시간을 보냈습니다. 아가들을 배려해서 넓고 쾌적한 환경의 실내놀이터를 선택해주신 대림산업 후원자분들께 다시한번 감사드립니다.</div>          </td>
        </tr>',770,1380207600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9416,'dus3','이소영','leesy5576@hanmail.net','룻2방 *민, *영, *연, *민이가 쿠키를 만들었습니다.(2013. 09. 26)','2013년 9월 26일 룻2방 *민, *영, *연, *민이가 남산초등학교 교육복지특별지원사업 "요리사의 꿈"프로그램에서 쿠키를 만들어 하교하였습니다.

<div>아이들이 직접 만든 쿠키는 어른들과 룻2방 언니, 동생들과 나누어먹었습니다.</div>
<div>매주 목요일 진행되고 있는 요리프로그램을 아이들 모두 신나고 재미있게 참여한 후 감사하는 마음을 갖고 흥미를 느끼는 모습이 뿌듯하고 기특합니다.</div>
<div>아이들에게 좋은 경험을 할 수 있도록 지원해주시고 계시는 남산초등학교 선생님 진심으로 감사드립니다.</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',783,1380207600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9417,'dus3','박현정','kingi109@naver.com','한나방 정*영 생일파티(2013.09.25)','<p align="center">26일 생일인 *영이가 26일(목)~27일(금) 직장에서 1박2일 제주도로 워크샵을 가게되어</p>
<p align="center">하루 전날, 생일파티를 진행하였습니다.</p>
<p align="center">현재 자립을 준비중인 *영이를 격려하면서, *영이가 바빠 그동안 못 나눈 이야기들도</p>
<p align="center">많이 하였습니다~^^</p>
<p align="center">대견하고 예쁜 *영이 생일을 모두 축하해주세요~^^</p>          </td>
        </tr>',815,1380121200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9418,'dus3','송명은','happysme@hanmail.net','룻2방의 *민,*연,*민이가 예쁜 운동화를 받았습니다.(2013.09.25)','<p>갑작스럽게 쌀쌀해진 날씨에 룻2방 *민,*연,*민이는 따뜻한 선물을 받았답니다.</p>
<p>예쁜 운동화를 신고 열심히 학교생활에 임할 수 있도록 보육하겠습니다.</p>          </td>
        </tr>',791,1380034800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9420,'dus3','남산원','6336110@hanmail.net','바울방 미취학아동들이 환일고등학교 후원자님과 종이접기 프로그램에 참여하였습니다.','<p>&nbsp;</p>
<p>2013년 9월 21일&nbsp;오전 10시부터 11시까지 &nbsp;남명이와 영재, 영호 "환일고등학교" </p>
<p>&nbsp;</p>
<p>"청나동아리후원자"님과 종이접기 프로그램을 하였습니다.</p>
<p>&nbsp;</p>
<p>아이들과 봉사자 학생들과 컵받침대를 만들어보았습니다.</p>
<p>&nbsp;</p>
<p>종이접기도 어려울뿐더러 &nbsp;아동들이 꼼꼼하게 집중을 하며 적극적으로 &nbsp;열심히&nbsp; </p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>종이 접기를 만들어 칭찬을 많이 받았습니다.*^0^*♬</p>
<p>&nbsp;</p>
<p>추석연휴기간인 토요일에 "바울방 아동" 남명이와 영재, 영호 아동이 즐겁고&nbsp;보람있는&nbsp;시간을</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>보낼 수 있도록 후원해주신 &nbsp;"환일고등학교 후원자" &nbsp;분들께 진심으로 감사드립니다.</p>          </td>
        </tr>',837,1379775600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9419,'dus3','남산원','jblee4@naver.com','다윗방 김*석, 이*울, 오*진아동 직업멘토링','<p>다윗방 김*석, 이*울, 오*진아동이 </p>
<p>직업멘토링(직업군인) 조*현선생님께 시계선물을 받았습니다. 감사합니다. </p>
<p>이상 3명의 아동에게 좋은 멘토가 되어주셔서 진심으로 감사드립니다. </p>          </td>
        </tr>',796,1379775600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9421,'dus3','이소영','leesy5576@hanmail.net','룻2방 김*현, 오*별 환일고등학교후원 종이접기프로그램 활동사진입니다.(2013. 09. 21)','2013년 9월 21일 룻2방 *현이와 *별이가 환일고등학교 청나동아리후원자님과 종이접기 프로그램을 하였습니다.

<div>컵받침대를 만들어보았는데 어려운 종이접기방법임에도 꼼꼼하게 잘 만들어 칭찬을 많이 받았습니다.</div>
<div>추석연휴기간 *현이와 *별이가 재미있는 시간을 보낼 수 있도록 후원해주신 환일고등학교 후원자님 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',879,1379689200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9422,'dus3','심주현','pikaccu85@hanmail.net','바울방 추석맞이 나들이 다녀온날!!(2013.09.20)','<p>오늘은 바울방 추석맞이 나들이 날 입니다. ^-^*</p>
<p>어제 아빠께 선물받은 문화상품권으로 영화를 보고 왔는데요 ^^ 영화가 끝나고 남산한옥마을에 가서 제기만들기를 하고 탈 만들기 체험도 해보는 등 다양한 활동을 하였습니다. </p>
<p>사람이 부쩍부쩍 엄청 많았는데요!!</p>
<p>오랜만에 하는 나들이라 지친줄도 모르고 엄청 즐겁게 놀다 귀원하였답니다!!</p>
<p>남은 연휴에도 우리 아이들이 즐겁게 활동할수 있도록 지원하겠습니다!! </p>          </td>
        </tr>',814,1379602800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9423,'dus3','심주현','pikaccu85@hanmail.net','바울방이 추석을 맞아 문화상품권 선물을 받았습니다.^^(2013.09.19)','<p>추석을 맞이하여 남산원 아빠께서 아동들에게 문화상품권을 선물해주셨습니다. </p>
<p>늘 우리를 아껴주시고 사랑해 주시는&nbsp;아빠께 진심으로 감사드립니다 ^-^*</p>          </td>
        </tr>',771,1379602800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9424,'dus3','박충일','a7124383@nate.com','다윗방 추석맞이 단합대회(2013.09.19)','<p>다윗방아동들이 추석을 맞이하여 나들이 겸 단합대회를 가졌습니다.</p>
<p>오전에 차례지내기 예절교육 프로그램을 마치고 </p>
<p>롯데리아에서 버거세트로 점심식사를 하고&nbsp; 명동CGV에서 영화"스파이"를 본 뒤</p>
<p>청계천 =&gt; 영풍문고 =&gt; 경복궁 =&gt; 인사동거리를 구경하였습니다. </p>
<p>&nbsp;</p>
<p>영풍문고에 들려 이런저런 책도 구경하고 </p>
<p>경복궁에서는 수문장 교대식을하여 구경하였고 </p>
<p>인사동 쌈지길과 소리를 하시는분들의 창을 듣고 돌아왔습니다. </p>
<p>&nbsp;</p>
<p>오늘 낮 기온이 한 여름 날씨여서 먼 거리를 걷기에 덥고 힘들어했지만</p>
<p>영화도 재미있게 보고 여러곳을 한번에 돌아보며 지리도 익히고</p>
<p>무엇보다 선생님과 형들과 동생이 함께 하여서 너무나 좋은 추억하나가 생겼습니다.</p>
<p>&nbsp;</p>
<p>남은 추석연휴 잘 보내시고 즐거운 한가위 되세요^^*</p>          </td>
        </tr>',805,1379516400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9425,'dus3','송명은','happysme@hanmail.net','룻2방은 추석나들이 영화관람을 하였습니다.(2013.09.19)','추석연휴 두번째 날인 오늘 이른아침부터 아빠께 받은 문화상품권으로 그동안 보고싶었던 영화를 선택해서 관람하면서 오랫만의 룻2방 가족들과 함께 문화생활을 하였습니다. 또 영화관람 후에는 맛있는 식사를 하면서 꽃보다 예쁜 룻2방의 얼굴에서 더 환한 웃음꽃이 피었났답니다. 맛있는 식사를 할 수 있도록 지원해주신 아빠께 감사드립니다. 너무나 즐거운 추석연휴를 보내고 있는 룻2방이랍니다.^^          </td>
        </tr>',797,1379516400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9426,'dus3','송명은','happysme@hanmail.net','룻2방이 추석예절교육에 참석하였습니다.(2013.09.19)','매년 명절때마다 남산원 아동들이 반드시 알고 있어야 하는 예절에 대해서 알려주시는 예절교육을 이번 추석에도 어김없이 진행되었습니다.

<div>룻2방의 막둥이인&nbsp;<span style="text-align: -webkit-center">*</span>현이도 이번 예절교육에 처음 참석하였지만 조용하고 엄숙한 분위기속에서 언니,오빠들이 교육에 참석하는 모습을 유심히 보는 모습이 기특했습니다. 우리 남산원 아동들이 어른을 공경하고 예의바른 아동으로 성장할 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',986,1379516400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9427,'dus3','송명은','happysme@hanmail.net','룻2방은 추석을 맞이하여 문화상품권을 선물받았습니다.(2013.09.19)','추석을 맞이하여 남산원 아빠께서 아동들에게 문화상품권을 선물해주셨습니다. 꽃보다 예쁜 룻2방 아동들도 아침일찍부터 주시는 문화상품권을 감사한 마음으로 받았습니다. 감사합니다~^^          </td>
        </tr>',789,1379516400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9428,'dus3','남산원','jblee4@naver.com','다윗방 추석맞이 문화상품권&차례지내기(2013.09.19)','<p>추석을 맞이하여 아빠께 문화상품권을 받았습니다. 감사합니다^^</p>
<p>그리고 오전에 다같이 강당에 모여 차례상차리기와 절하는법 등 </p>
<p>추석 예절과 문화에 대해 배워</p>
<p>잔도 따라 올려보고 절도 해 보면서 실제 익히는 유익한 시간을 가졌습니다. </p>          </td>
        </tr>',807,1379516400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9429,'dus3','김성재','thunderdog9@naver.com','원장님께서 문화상품권을 선물로 주셨습니다.','추석을 맞이하여 원장님께서 모세방을 포함한 모든 방 아동들에게 문화상품권을 선물로 지급해주셨습니다. 명절 동안 영화도 보고 친구들과 만나 맛있는 음식도 사 먹으며 즐거운 시간 보내길 바랍니다. 선물을 주신 원장님께 감사하는 마음 갖는&nbsp;것도 잊지 말구요^~^          </td>
        </tr>',778,1379516400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9430,'dus3','김성재','thunderdog9@naver.com','모세방 아동들, 추석음식 만들기에 도전!!','명절을 맞아 모세방의 김<span style="text-align: -webkit-center">*</span>철, 안<span style="text-align: -webkit-center">*</span>현 아동을 포함한 남산원 아동들은 운동장 한켠에 마련된 천막 아래에서 선생님들의 지도에 따라 대표적인 명절 음식인 전을 부치며 즐거운 오후 한때를 보냈습니다. 요즘은 남자들도 명절때 집안일을 많이 도와야 하는데 이번 프로그램에 참가한 모세방 아동들에게 좋은 경험이 되었으리라 생각합니다. 남은 연휴도 아동들이 즐겁고 행복하게 보낼 수 있도록 힘쓰겠습니다.          </td>
        </tr>',771,1379516400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9432,'dus3','송명은','happysme@hanmail.net','룻2방 나*가 후원자분께 선물을 받았습니다.(2013-09-17)','추석을 맞이하여 룻2방 나*에게 후원자분께서 영양제를 선물해주셨습니다. 또래아이들에 비해서 조금 마른 나*에게 꼭!!필요한 귀한 선물이랍니다. 우리 나*가 영양제를 잘 먹고 건강한 중학교 생활을 할 수 있도록 보육하겠습니다. 감사합니다.          </td>
        </tr>',782,1379343600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9431,'dus3','송명은','happysme@hanmail.net','룻2방이 추석명절 음식만들기를 하였습니다.(2013-09-18)','우리나라의 고유명절인 추석을 맞이하여 룻2방 아동들은 추석명절에 먹는 음식을 만들면서 명절 첫째날을 보냈습니다. 남산원 가족들 모두가 함께 여러가지 전을 부쳐서인지 시간가는 줄 모르고 많은 양의 음식을 만들 수 있었답니다. 또 서로 이야기를 하면서 추석에 대해 조금은 이해할 수 있는 유익하고 즐거운 시간이 되었습니다.
<div>남은 추석연휴기간동안 아동들 모두가 신나고 풍성한 시간들이 될 수 있도록 지원하겠습니다.</div>          </td>
        </tr>',809,1379430000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9434,'dus3','송명은','happysme@hanmail.net','룻2방이 사랑하는 아빠의 생신을 축하드립니다.(2013.09.16)','<p>기쁜날~좋은날~우리에게 아빠를 보내주신날~~</p>
<p>사랑해요~축복해요~축하해요~</p>
<p>생신을 축하해요~♪♬</p>
<p>&nbsp;</p>
<p>사랑받기위해 태어나신 아빠의 생신을 룻2방 아동들 모두가~</p>
<p>사랑하고 축복하는 마음을 가득 담아서 축하드렸습니다.</p>
<p>아빠~</p>
<p>힘내세요~룻2방이 있자나요~</p>
<p>아빠~</p>
<p>앞으로 건강하시고 행복하시길 기도하겠습니다.</p>
<p>축하드립니다.^^</p>          </td>
        </tr>',784,1379257200,'', '', '', '', '', '');
