INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9438,'dus3','남산원','6336110@hanmail.net','오늘은 아빠의 생신입니다(2013.09.16) 바울방아동과 아빠와함께♥','<p>&nbsp;</p>
<p>&nbsp;</p>
<p>오늘은 아빠의 생신입니다. 바울방 아동과 아빠와 함께 찍은 인증샷입니다^_^*</p>
<p>&nbsp;</p>
<p>아이들과 함께 아빠의 편지를 &nbsp; 정성스레 만들었습니다~^_^*</p>
<p>&nbsp;</p>
<p>오늘하루 <font face="굴림">즐겁고 행복한 시간보내시길 바랍니다^_^* </font></p>
<p><font face="굴림"></font>&nbsp;</p>
<p><font face="굴림"></font>&nbsp;</p>
<p><font face="굴림">늘 항상 건강하세요.!! </font><font face="굴림">오늘 하루도 함박꽃 처럼 &nbsp;웃음이 넘치는 하루 보내세요~</font></p>
<p>&nbsp;</p>
<p>다시한번 아빠의 생신을 진심으로 축하축하 드립니다!!!^___^*</p>
<p>&nbsp;</p>
<p>- 바울방 올림- </p>          </td>
        </tr>',823,1379257200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9440,'dus3','송명은','happysme@hanmail.net','룻2방의 주일날 교회생활입니다.(2013.09.15)','<font face="굴림">매주일마다 룻2방의 미취학아동들과 초등부아동들은 침례교회에 가서 예배를 드린답니다.</font>
<div><div style="font-family: 굴림">얼마전 룻2방의 식구가 된 막둥이&nbsp;<span style="text-align: -webkit-center">*</span>현이도 오늘 침례교회 유치부에 새신자 등록을 하였답니다. 낯선 환경에서도 잘 적응하면서 언니들과 선생님들의 말씀에 귀를 기울이며 집중하는&nbsp;<span style="text-align: -webkit-center">*</span>현이가 너무나 귀엽고 사랑스러웠답니다. 오늘은 새신자선물로 멋진 선글라스도 받았습니다. 어린&nbsp;<span style="text-align: -webkit-center">*</span>현이지만 어릴때부터 하나님의 사랑을 가득 받으며 생활할 수 있도록 기도하며 보육하겠습니다.</div></div>          </td>
        </tr>',765,1379170800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9439,'dus3','남산원','jblee4@naver.com','다윗방 아빠생신날 기념사진','<p>오늘은 아빠의 생신날입니다. (오전 조회시간)</p>
<p>다른 여자아동방은 일찍 애교작전을 펼치는데 반해 남자아동들이라 그런지 </p>
<p>표현이 서툰건지 쑥스러운지는 몰라도 사진이 건조하게 나왔네요^^</p>
<p>그래도 속 마음은 진심으로 축하드리는 걸 믿습니다. </p>
<p>몇일 전부터 감사편지를 쓰면서 준비했거든요~^^</p>
<p>&nbsp;</p>
<p>아빠&nbsp;항상 감사합니다&nbsp;늘 건강하세요~~^^*&nbsp;&nbsp; - 다윗방 올림 </p>          </td>
        </tr>',809,1379257200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9441,'dus3','박충일','a7124383@nate.com','다윗방 주일 남산 아침산책.','<p>다윗방 아동전체가 주일 아침 일찍 남산 아침 산책을 다녀왔습니다.</p>
<p>서울 한 복판 명동에서 아침에 상쾌하고 신선한 공기를 마시며 </p>
<p>산책할 수 있다는 특권에 너무나 감사하고 기분좋은 주일 아침였습니다. ^^</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',793,1379170800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9443,'dus3','이소영','leesy5576@hanmail.net','룻2방 아침 남산 산책사진입니다.(2013. 09. 15)','2013년 9월 15일 아침 룻2방 맡언니&nbsp;<span style="text-align: -webkit-center">*</span>진이부터 막내&nbsp;<span style="text-align: -webkit-center">*</span>현이까지 전원 남산산책을 다녀왔습니다.

<div>한 주동안 내렸던 비가 그치고 성큼 다가온 가을 아침 아이들과 함께하는 산책이 오늘따라 더 상쾌하고 좋았습니다.</div>
<div>환절기 아이들이 아프지 않고 건강하게 생활할 수 있도록 지원하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>ㄱ</div>          </td>
        </tr>',787,1379170800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9442,'dus3','심주현','pikaccu85@hanmail.net','바울 남산 산책하는날!(2013.09.15)','오늘 아침 바울방 아동들이 남산 산책을 다녀왔습니다^^
<div>몇일간의 가을비가 끝나고 가는 산책이라 아침길이 무척 상쾌했는데요~</div>
<div>오늘은 유치부 아동들이 신나서 부지런히 간 모습이 가장 인상적이였답니다^^♥</div>
<div>아이들이 건강한 아동기를 보낼수있도록 지원하겠습니다!</div>          </td>
        </tr>',789,1379170800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9444,'dus3','남산원','jblee4@naver.com','다윗방 주말 미니축구 한게임','<p>저녁으로 이동떡볶이(김밥+순대+오뎅+포도)를 배부르게 맛있게 먹고 나오니</p>
<p>&nbsp;</p>
<p>*선이와 *석이가 공을 차며&nbsp; "선생님 축구해요~"&nbsp;"-어 그래&nbsp;축구할 애들 모아봐~"</p>
<p>&nbsp;</p>
<p>방에 들어가 4명을 데리고 나오니 축구하자던 녀석들이 안보이네요;;;</p>
<p>&nbsp;</p>
<p>그래서 저희끼리 골키퍼1:1&nbsp; 승부차기 놀이를 하다가 </p>
<p>편의점에 다녀온 *석이와 *선이까지 합하면 총 7명...</p>
<p>&nbsp;</p>
<p>짝이 안맞네;;&nbsp; 방에 들어가 *이보고 축구할래? "-아니요.." 게임이 더 좋은 *이..</p>
<p>모임방에 들어가 게임 삼매경인 *울이와 *늘이보고 축구할래? "-아니요.." </p>
<p>&nbsp;</p>
<p>어쩔 수 없이 4:3 명&nbsp; 편을 먹고 게임을 시작!!~</p>
<p>제일 중요한규칙 = 일렬로 정렬하여 인사하고 매너게임 안다치게 축구하자~~ ( 사진)</p>
<p>&nbsp;</p>
<p>게임 룰은 전후반 20분씩 시간을 정했으나 </p>
<p>치열한 2:2 접전이 이어지면서 날은 어두워지는데;;&nbsp; </p>
<p>이기고 싶었는지 운동장 라이트까지 켜달라 부탁하고 </p>
<p>쉬는 시간없이 40분을 경기하다 보니&nbsp; 지쳤는지&nbsp;&nbsp; 급 게임규칙 변경!!~</p>
<p>&nbsp;</p>
<p>골든볼!!!&nbsp; 먼저 골 넣는 팀이 승리!!&nbsp;&nbsp;&nbsp; 어느팀이든 빨리 끝내야 할 체력방전 시점^^</p>
<p>&nbsp;</p>
<p>선생님의 마지막 회심의 골로 A팀 승리!!~로 마무리^^</p>
<p>(오늘은 간식이 많은 관계로 내기는 없었습니다^^)</p>
<p>&nbsp;</p>
<p>경기 결과=&nbsp; A팀 승:선생님 최*선 김*현 김*수&nbsp;&nbsp;3&nbsp; vs&nbsp;&nbsp;2&nbsp;&nbsp;&nbsp; B팀 패: 김*석 오*진 김*</p>
<p>&nbsp;</p>
<p>B팀은 숫적 열세에도 불구하고 패쓰도 잘하고 정말 열심였고 &nbsp;</p>
<p>함께 다치지 않고 땀흘리며 운동한다는 단합의 의미와 승리에 대한 목적달성의식 고취와</p>
<p>대선이는 학교에서 2번째로 빠르단 사실도 알게 된 즐겁고 값진 축구시간였습니다. </p>
<p>&nbsp;</p>
<p>몸모 마음도 성품도 올바르게 무럭무럭 잘 자라날 수 있도록 기도부탁드립니다. </p>
<p>&nbsp;</p>
<p>사랑한다 다윗방!!~~~ 화이팅!!~ ^^/ </p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',1835,1379170800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9445,'dus3','이소영','leesy5576@hanmail.net','룻2방 김*선, 호문애선생님 외출사진입니다.(2013. 09. 14)','2013년 9월 14일 룻2방 *선이가 호문애후원자님과 외출을 다녀왔습니다.

<div>점심식사를 한 후 선생님과 쇼핑을 하며 주말을 알차게 보내고 귀가하였습니다. 선생님께서 *선이에게 2학기에 쓸 이쁜가방과 후드티를 선물해주셨습니다.</div>
<div>*선이에게 항상 좋은 가르침과 멘토로서 좋은 역할을 해주고 계셔서 진심으로 감사드립니다. 원에서도 *선이가 건강하고 바르게 자랄 수 있도록 보육하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',776,1379084400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9446,'dus3','이소영','leesy5576@hanmail.net','룻2방, 김*희 직업진로멘토링활동사진입니다.(2013. 09. 14)','2013년 9월 14일 룻2방&nbsp;<span style="text-align: -webkit-center">*</span>희가 직업진로멘토링활동을 하였습니다. 사진에 관심이 있던&nbsp;<span style="text-align: -webkit-center">*</span>희가 사진작가 이성우 선생님과 멘토링을 하고 이성우선생님 작품집을 선물받았습니다.

<div>사진작가 외에도 여러분야에 관심많고 꿈 많은&nbsp;<span style="text-align: -webkit-center">*</span>희가 이번직업진로멘토링을 기회로 좋은 경험을 쌓고 발전하였으면 좋겠습니다.</div>
<div><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span>희에게 좋은 가르침을 주시고 계시는 이성우 선생님 진심으로 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',777,1379084400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9447,'dus3','이소영','leesy5576@hanmail.net','룻2방 롯데마트 후원 송편만들기프로그램 활동사진입니다.(2013. 09. 14)','2013년 9월 14일 룻2방 미취학, 초등학생 아이들이 롯데마트 후원프로그램으로 송편을 만들었습니다.
<div>송편만드는법을 자세히 알려주셔서 아이들 모두 이쁘게 송편을 만들고 식혜와 함께 먹으며 프로그램을 마쳤습니다.</div>
<div>명절 전 남산원을 찾아 아이들과 함께 해주신 롯데마트후원자님 진심으로 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',750,1379084400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9449,'dus3','송명은','happysme@hanmail.net','룻2방의 *희와 *진이가 핸드폰을 받았습니다.(2013.09.13)','요즘 중고생들 사이에서 없어서는 안될 중요한 필수용품 중 하나인 핸드폰을 룻2방의&nbsp;<span style="text-align: -webkit-center">*</span>희와&nbsp;<span style="text-align: -webkit-center">*</span>진이가 받게 되었습니다. 여러가지 이유들로 인해 지금까지 받지 못했던&nbsp;<span style="text-align: -webkit-center">*</span>희와 전에 사용하던 핸드폰이 고장나는 바람에 이번에 새로 받게 된&nbsp;<span style="text-align: -webkit-center">*</span>진이는 그전에 사용하던 핸드폰과는 너무나 다른 최신형의 핸드폰을 받고 너무나 좋아하는 모습이었습니다. 아동들이 올바른 방법으로 핸드폰을 적절하게 잘 사용할 수 있도록 열심히 보육하겠습니다.          </td>
        </tr>',756,1378998000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9450,'dus3','송명은','happysme@hanmail.net','룻2방의 *별이와 *진이가 송편을 만들어왔습니다.(2013.09.13)','룻2방의 *별이와 *진이는 오늘 필동어린이집에서 다음주에 있는 추석명절을 맞이해서 송편만들기를 하였습니다.&nbsp;
<div>미리 준비한 앞치마와 머릿수건을 두르고 송편 속재료들을 직접 넣으면서 친구들과 사이좋게 만든 송편은 각자의 모습대로 너무나 예쁘고 맛있었습니다.

<div>아직은 어린 *별이와 *진이지만 최대명절인 추석명절을 잘 보낼 수 있도록 열심히 보육하겠습니다.</div></div>          </td>
        </tr>',802,1378998000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9451,'dus3','송명은','happysme@hanmail.net','아동복지협회에서 학습교재를 지원해주셨습니다.(2013.09.13)','지난번에 이어서 오늘도 아동복지협회에서 수능스타트라는 제목의 국,영,수 학습교재를 지원해주셨습니다.
<div>학습교재를 통해서 아동들이 학습에 더 집중할 수 있도록 보육하겠습니다. 감사합니다.</div>          </td>
        </tr>',728,1378998000,'', '', '', '', '', '');
