INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9452,'dus3','이소영','leesy5576@hanmail.net','룻2방, 초등학생(*민,*영,*연,*민)이 꼬마김밥을 만들었습니다.(2013. 09. 12)','2013년 9월 12일 룻2방 *민, *영, *연, *민이가 남산초등학교 교육복지특별지원사업 "요리사의 꿈" 프로그램에 참여하여 꼬마김밥을 만들어왔습니다.

<div>매주 목요일 프로그램을 할 때마다 맛있는 음식을 만들어 룻2방 가족들과 나누어 먹으며 뿌듯해하는 아이들을 보며 보람을 느낍니다.</div>
<div>남산원 아이들을 지원해주시는 남산초등학교 선생님 진심으로 감사드립니다.</div>
<div>앞으로도 아이들이 프로그램으로 인해 발전해나갈 수 있도록 지원하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',734,1378911600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9453,'dus3','송명은','happysme@hanmail.net','룻2방 *별이와 *진이가 필동어린이집 &quot;동시발표회&quot;에 참석하였습니다.','가을비가 내려서 갑작스럽게 쌀쌀해진 날씨에도 룻2방의 *별이와 *진이는 예쁜 공주님의 모습으로 필동어린이집 "동시발표회"에 참석하였습니다.

<div>그동안 어린이집에서 뿐만 아니라 집에서도 열심히 동시외우기 연습을 했던 우리 *별이와 *진이는 너무나 예쁘고 똘똘한 모습으로 동시를 외웠답니다. 함께 참석한 *현이와 *호도 언니와 형들의 모습을 물끄러미 쳐다보는 모습이 인상적이었습니다.&nbsp;</div>
<div>많은 학부모님들이 앞에 계셨는데도 전혀 떨지 않고 당당하게 실력을 발휘하는 우리 아이들이 너무나 자랑스러운 하루였습니다.&nbsp;</div>
<div>앞으로도 우리 아이들이 어디서나 자신감있게 생활할 수 있도록 보육하겠습니다.</div>          </td>
        </tr>',795,1378825200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9454,'dus3','남산원','6336110@hanmail.net','♥ 남산원 아동 친구들  필동어린이집 동시 발표회♥(2013.09.11)','<p>&nbsp;</p>
<p>오늘은 미취학 아동 친구들이 필동어린이집에서 동시 발표회가 있었습니다. </p>
<p>&nbsp;</p>
<p>동시발표회 시간은 오전 11:00~13:00까지 진행을 하였습니다. </p>
<p>&nbsp;</p>
<p>동시 발표회를 나간 아동 친구들은&nbsp;바울방에서는&nbsp;<span style="text-align: -webkit-center">*</span>재와&nbsp;<span style="text-align: -webkit-center">*</span>호, 룻2방에는&nbsp;<span style="text-align: -webkit-center">*</span>진,&nbsp;<span style="text-align: -webkit-center">*</span>별이가</p>
<p>&nbsp;</p>
<p>발표를 하였습니다.&nbsp; 아동들이 앞에 나가서 발표하는것이 떨리고 긴장을 해서 동시 발표는 </p>
<p>&nbsp;</p>
<p>원활하게 하지 못했지만 앞에 나가서 동시 발표회를 열심히 하려는 모습이 씩씩하고 </p>
<p>&nbsp;</p>
<p>대견스러웠습니다^^♥ 오늘 아동들이 턱시도와 치마를 입은 모습이 예쁜 공주같이 </p>
<p>&nbsp;</p>
<p>어여쁘며, 멋쟁이 였습니다! 아이들아, 오늘 하루동안 정말 많이 수고했어!!!!!</p>          </td>
        </tr>',767,1378825200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9455,'dus3','남산원','6336110@hanmail.net','바울방 미취학 꼬꼬마 아동 친구들 턱시도 입고 유치원 가기전에♥(2013.09.11)','<p>&nbsp;</p>
<p>&nbsp;</p>
<p>바울방 미취학 꼬꼬마 아동 친구들을 소개하겠습니다!</p>
<p>귀엽고 장난끼가 넘치는 영재와 영호입니다~^^</p>
<p>오늘 필동어린이집에서 동시 발표회가 있는데 아침에 턱시도를 멋지게 차려입고 </p>
<p>유치원 가기전에 턱시도를 입은 인증샷 모습입니다^ㅇ^* </p>
<p>바울방 미취학 아동들 귀엽고 멋있죠?!!!!! 턱시도가 잘 어울리는 영재와 영호♥</p>
<p>동시 발표회 화이팅!!!!!! </p>
<p>&nbsp;</p>          </td>
        </tr>',793,1378825200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9456,'dus3','이소영','leesy5576@hanmail.net','룻2방 김*연, 박*민 상장, 상금수여사진입니다.(2013. 09.11)','2013년 9월 11일 룻2방 *연이 *민이가 여름방학기간 영어공부와 숙제를 열심히 한 결과, 영어교과서 외우기 대회에서 최우수상을 받게 되어 아침조회 상장과 상금을 받았습니다.

<div>여름방학기간 내내 성실하게 숙제를 한 결과를 받게 되어 정말 기특하고 대견합니다.</div>
<div>2학기에도 *연이 *민이가 학교생활을 성실하게 잘 할 수 있도록 지원하고 보육하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',765,1378825200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9457,'dus3','심주현','pikaccu85@hanmail.net','바울방 송편만들기^^♥(2013.09.10)','<p>오늘 롯데카드 후원자님과 함께 송편만들기 시간을 가졌습니다. </p>
<p>아이들은 강아지, 돌고래, 눈사람 등 다양한 송편을 만들었는데요^^</p>
<p>자기것이 잘 만들었다며 다른조에 돌아다니며 구경시켜주는 모습이 너무</p>
<p>귀여웠습니다. </p>
<p>오늘 아이들이 만든 송편은 우리집 식구들의 간식으로 모두에게 돌아갔는데요 ^^</p>
<p>맛있다고 말해주는 누나들이 있어 오늘은 너무 행복했던 하루가 되었던 것 같습니다. </p>
<p>우리 아이들에게 좋은 프로그램을 선사해 주신 롯데카드 후원자 분들께 진심으로 감사드립니다!!(^^)(__)(^^)</p>          </td>
        </tr>',858,1378825200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9458,'dus3','이소영','leesy5576@hanmail.net','룻2방, 롯데카드후원 송편만들기프로그램 활동사진입니다.(2013. 09. 10)','2013년 9월 10일 룻2방 미취학, 초등학생 아이들이 롯데카드후원 송편만들기 프로그램에 참여하였습니다.
<div>얼마남지 않은 추석, 아이들이 미리 송편을 만들어보고 송편을 맛있게 먹으며 좋은 추억을 쌓았습니다.</div>
<div>아이들에게 송편과 일상생활에 필요한 교육을 해주신 롯데카드후원자님 진심으로 감사드립니다.</div>
