INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9460,'dus3','남산원','6336110@hanmail.net','&quot;바울방&quot; 주말 일요일 바깥나들이 아동들 모습(2013.09.08)','<p>&nbsp;</p>
<p>&nbsp;</p>
<p>안녕하세요! 아홉명의 남자아동이 함께 살고 있는 "바울방"입니다 </p>
<p>&nbsp;</p>
<p>바울방 아동들은 주말에 자유시간에 바깥놀이를 하였답니다~</p>
<p>&nbsp;</p>
<p>바울방 아동들을 소개하겠습니다. 멋지고 듬직한 초등학생 아동과 장난꾸러기 미취학 </p>
<p>&nbsp;</p>
<p>아동이 있습니다^-^~</p>          </td>
        </tr>',827,1378566000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9459,'dus3','남산원','jblee4@naver.com','다윗방 주말 농구 한게임','<p>다윗방에 처음&nbsp;온 날&nbsp; 미니축구 다음으로&nbsp;첫 주말 아이들과 함께&nbsp; 농구게임을 했습니다.</p>
<p>평일에는 학교를 마치고 학원에 다녀오면 늦은시간이라 오래 함께하지 못했는데</p>
<p>주말에 많은시간 원내생활하면서 농구게임도 하며 즐거운 주말을 보냈습니다.</p>
<p>&nbsp;</p>
<p>A팀:샘,오*진,김*현&nbsp;vs B팀:김*석,최*선,김*&nbsp;&nbsp; 심판:김*수 </p>
<p>&nbsp;</p>
<p>음료수과자내기 3전 2승제 B팀이 먼저 두 게임을 이겨서 </p>
<p>진 A팀인 *진이와 제가 과자와음료수를 사와서 시원하게 음료수를 마셨습니다. </p>
<p>&nbsp;</p>
<p>내기가 걸린만큼 치열한 승부였습니다.</p>
<p>&nbsp;</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A&nbsp; &nbsp;-&nbsp; B</p>
<p>1 경기 결과 :&nbsp; 10&nbsp; &nbsp;:&nbsp; 8</p>
<p>2 경기 결과 :&nbsp;&nbsp;&nbsp;7&nbsp;&nbsp; &nbsp;: 10&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;A팀이 7-0 으로 이기고 있는 상황에서 역전승 할 정도로</p>
<p>&nbsp;</p>
<p>열심히 땀흘린 결과로 시원한 음료수를 마시며 기분 상쾌해 하였습니다. </p>
<p>&nbsp;</p>
<p>다음 번 경기에서는 절대 봐주지 않도록 하겠습니다^^*</p>
<p>&nbsp;</p>
<p>다윗방 한울이,하늘이,웅이는 게임을 하며 주말을 보냈습니다. </p>
<p>다음에는 다 함께 운동하였으면 좋겠네요</p>
<p>&nbsp;</p>
<p>운동 중에 다치지 않고&nbsp; 다함께 웃으며 즐겁게 운동한 즐거운 주일였습니다.^^ </p>
<p>다음 주말에는 함께 남산등산도 가고싶네요~</p>
<p>&nbsp;</p>
<p>남산원을 사랑하는 모든 분들 환절기 감기조심하세요~ ^^/</p>          </td>
        </tr>',853,1378566000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9461,'dus3','심주현','pikaccu85@hanmail.net','바울방  농구게임!(2013.09.07)','오늘 &nbsp;바울방아동들과 미군 인사부 봉사자님들과 함께 농구게임을 하는 시간을 가졌습니다^^
<div>때마침 놀러온 성진친구와 함께 경기를 하였는데요~</div>
<div>햇빛이 들기는했으나 선선한 날씨여서 경기하기 더욱 좋은 하루가 되었던것 같습니다^^</div>
