INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9464,'dus3','송명은','happysme@hanmail.net','룻2방의 중학생들은 남산교회 사모님과의 외출을 다녀왔습니다.(2013.09.06)','평소에도 남산원 아동들에게 많은 관심과 후원으로 응원해주시는 남산교회 목사님과 사모님께서는 항상 남산원 아동들에게 넘치는 사랑을 표현해주십니다.
<div>오늘은 남산교회 사모님과 룻2방의 중학생들이 외출을 해서 맛있는 간식을 먹으면서 담소를 나누는 의미있는 시간을 보냈습니다. 한창 사춘기가 시작되서 예민해져 있는 중학생들에게 도움이 되는 많은 이야기들을 해주신 남산교회 사모님께 다시한번 감사의 인사를 드립니다. 앞으로도 우리 남산원 아동들의 미래를 위한 변함없는 기도 부탁드립니다. 감사합니다.</div>          </td>
        </tr>',792,1378393200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9466,'dus3','남산원','6336110@hanmail.net','바울방 미취학아동들 취침전 간식먹는모습(2013.09.05)','<p>&nbsp;</p>
