INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9465,'dus3','송명은','happysme@hanmail.net','아동복지협회에서 학습교재를 지원해주셨습니다.(2013.09.06)','사회복지공동모금회의 현물지원사업의 일환으로 진행되어진 ebs학습교재 지원사업에 따라서 남산원에도 아동들의 학습향상을 위해 아동복지협회를 통해서 37set의 ebs학습교재를 지원받았습니다. 학습교재를 바탕으로 남산원 아동들이 더욱 더 학습에 집중할 수 있도록 열심히 보육하겠습니다. 감사합니다.          </td>
