INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9469,'dus3','박현정','kingi109@naver.com','강*미, 김*진 아동 유니클로 입사(2013.09.05)','<p align="center">&nbsp;</p>
