INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9468,'dus3','송명은','happysme@hanmail.net','룻2방 덕수중학교 아동들은 교육복지 특별지원사업으로 가족문화체험프로그램에 참여하였습니다.','룻2방 덕수중학교에 다니고 있는 아동들은 오늘 교육복지특별지원사업으로 참가하게 된 가족문화체험프로그램으로 연극 "라이어"를 관람하였습니다. 학교 수업 후에 맛있는 간식을 먹고나서 대학로에 위치한 아티스탄홀에서 연극을 관람한 아동들은 집에 오자마자 유쾌하게 관람했던 연극이야기를 하면서 하루를 마무리하였습니다.
<div>아동들에게 새로운 문화체험을 할 수 있도록 지원해주신 덕수중학교 선생님들께 감사드립니다.</div>
