INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9476,'dus3','송명은','happysme@hanmail.net','룻2방으로 예쁜 막내공주님인 *현이가 새식구로 들어왔습니다.(2013.09.01)','그동안 남산원의 아가방에서 제일 맏언니로 생활하던 *현이가 룻2방의 막둥이로 새식구가 되었습니다.

<div>새롭게 룻2방이 된 *현이는 10명이나 되는 언니들의 사랑과 귀여움을 독차지 하며 벌써부터 언니들과 신나고 즐거운 첫날을 보냈습니다.&nbsp;</div>
<div>룻2방 언니들이 모두 마음을 담아서 *현이를 환영하는 파티를 해주었습니다.</div>
<div>*현이가 룻2방의 막내로써 많은 사랑과 관심으로 무럭무럭 건강하게 성장할 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',797,1377961200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9477,'dus3','송명은','happysme@hanmail.net','룻2방이 아동인권에 관한 그림그리기를 하였습니다.(2013.09.01)','세이브더칠드런에서 주최하는 \'소중한 아동인권\'작품 공모전에 룻2방의 아동들도 참가하였습니다.
<div>지난번 남산원을 방문하셔서 아동들에게 인권교육을 해주셨는데 교육을 들은 아동들은 각자가 생각하는 소중한 인권에 대한 생각을 그림으로 표현하는 귀한 시간을 보냈습니다. 아동들이 생각하고 꿈꾸는 아동들의 권리를 존중받을 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',777,1377961200,'', '', '', '', '', '');
