INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9482,'dus3','송명은','happysme@hanmail.net','룻2방에게 ACE손해보험 후원자분께서 예쁜 머리끈을 선물해주셨습니다.(2013.08.27)','더운날씨에도 남산원을 방문하셔서 노력봉사를 해주신 ACE손해보험 후원자분께서 룻2방 아동들에게 너무나 예쁜 머리끈과 머리삔을 선물해주셨습니다.
<div>미취학아동부터 초등학생까지 6명이나 되는 아동들의 머리를 매일 묶어주면서 부족한 머리끈으로 인해서 아쉬울때가 많았기 때문에 오늘 받은 특별한 선물에 룻2방 아이들 모두가 너무나 즐거워했답니다.</div>
<div>아침에 선물받은 머리끈으로 머리를 묶고 더욱 예쁜 모습으로 학교에 등교하였습니다.</div>
<div>남산원 아동들을 위해 세심한 선물까지 해주신 ACE손해보험 후원자분들께 진심으로 감사드립니다.</div>
<div>앞으로 겉모습 뿐만 아니라 마음속까지도 예쁜 아동으로 성장할 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',2095,1377615600,'', '', '', '', '', '');
