INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9488,'dus3','이소영','leesy5576@hanmail.net','룻2방 신세계푸드 채소모종심기 후원프로그램활동사진입니다.(2013. 8. 24)','<p>2013년 8월 24일 룻2방 미취학, 초등학생아이들이 신세계푸드 후원프로그램인 채소(배추, 무)모종심기 프로그램을 하였습니다.</p>
<p>늦더위 아이들이 배추와 무를 심어보면서 우리가 평소 먹고 있는 채소들이 자라나는 과정을 지켜보고 체험해보면서 건강한 먹거리에 감사함을 느낄 수 있는 시간이 되었던 것 같습니다.</p>
<p>아이들에게&nbsp;뜻깊은 시간을 보낼 수 있도록 지원해주신 신세계푸드 후원자님 감사드립니다.</p>
