INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9493,'dus3','송명은','happysme@hanmail.net','룻2방의 예쁜 요리사들이 맛있는 주먹밥을 만들었습니다.(2013.08.22)','룻2방의 남산초등학교 아동들은 오늘부터 매주 목요일마다 교육복지특별지원사업으로 시작되는 "요리사의 꿈"이라는 프로그램에 참석하게 되었습니다.
<div>오늘은 그 첫시간으로 맛있는 주먹밥을 직접 만들었답니다. 1학년인 재민이부터 4학년인 지민이까지 정성스럽게 만든 주먹밥을 예쁘게 포장까지 해왔답니다. 직접 만든 주먹밥을 남산원 아빠께 직접 드리고는 룻2방의 언니,동생들과 맛있게 나누어 먹었답니다. 앞으로도 우리 아동들에게 여러가지 다양한 경험들을 할 수 있도록 열심히 지원하겠습니다.</div>          </td>
        </tr>',806,1377097200,'', '', '', '', '', '');
