INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9499,'dus3','이소영','leesy5576@hanmail.net','룻2방 오*별, 손*진 필동어린이집 한옥마을산책사진입니다.(2013. 8.19)','2013년 8월 19일 룻2방 *별, *진이가 필동어린이집에서 가까운 한옥마을로 아침산책을 다녀왔습니다.

<div>여름방학을 마치고 어린이집에 다시 등원하여 월요일 아침을 기분좋게 시작하였습니다. 항상 어린이집 생활을 열심히 하고 적극적인 *별이 *진이가 기특하고 이쁩니다. 앞으로도 어린이집생활을 잘 할 수 있도록 원에서도 지원하도록 하겠습니다.</div>
<div>더운날씨에도 아이들 잘 보살펴주시고 항상 남산원에 관심가져주시고계시는 필동어린이집 선생님 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',865,1377010800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9498,'dus3','이소영','leesy5576@hanmail.net','룻2방 김*희 생일파티사진입니다.(2013. 8. 21)','2013년 8월 21일 룻2방 미소천사&nbsp;<span style="text-align: -webkit-center">*</span>희의 열다섯번째생일을 맞아 룻2방에서 생일파티를 하였습니다.

<div>인기 많은&nbsp;<span style="text-align: -webkit-center">*</span>희의 생일을 모두가 축하해주고&nbsp;<span style="text-align: -webkit-center">*</span>희의 영어학습을 담당하고 계시는 박재현선생님도 방문하셔서 다함께 진심으로 생일을 축하하며 즐거운 시간을 보냈습니다.</div>
<div><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span>희가 앞으로도 건강하고 밝게 성장할 수 있었으면 좋겠습니다.&nbsp;<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">희야, 생일축하해^. ^</span></div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',841,1377010800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9501,'dus3','송명은','happysme@hanmail.net','룻2방의 *진이가 학급회장이 되었습니다.(2013.08.20)','룻2방의 맏언니인 *진이가 덕수중학교 3학년2반 학급회장으로 임명이 되어서 당당하게 임명장을 받아왔습니다.
<div>평소에 밝고 주위사람들을 배려하는 *진이의 성격으로 인해 친구들에게 인기가 아주 많은 *진이랍니다.</div>
<div>학급 회장으로 임명장을 받아온 *진이는 2학기동안 3학년 2반을 위해서 열심히 솔선수범하겠다는 굳은 다짐을 하였습니다. 학교에서도 많은 사람들에게 칭찬받고 사랑받는 *진이가 될 수 있도록 열심히 보육하겠습니다. 김회장~화이팅!!^^</div>          </td>
        </tr>',828,1376924400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9502,'dus3','박현정','kingi109@naver.com','*연이가 부정맥 시술을 잘 마쳤습니다(2013.08.20)','<p align="center">&nbsp;</p>
<p align="center">*연이가 8월 16일 삼성서울병원에서 부정맥 시술을 하였습니다.</p>
<p align="center">한국심장재단에서 지원을 해주셔서 무사히 시술을 마칠 수 있었습니다.</p>
<p align="center">지원을 해주신 한국심장재단에 진심으로 감사드리며, </p>
<p align="center">*연이가 건강하게 잘 자랄 수 있도록 지원하겠습니다. 감사합니다!!</p>          </td>
        </tr>',834,1376924400,'', '', '', '', '', '');
