INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9503,'dus3','박현정','kingi109@naver.com','한나방 유*연 아동 운동화 구입(2013.08.20)','<p align="center">한나방 유*연 아동이 운동화 구입을 하였습니다.</p>
<p align="center">얼마전 *연이는 삼성서울병원에서 부정맥 시술을 하였습니다</p>
<p align="center">아파도 잘 견디며 생활하는 *연이를 보면 대견스럽기도 합니다.</p>
<p align="center">*연이를 응원해주세요~^^</p>          </td>
        </tr>',826,1376924400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9504,'dus3','심주현','pikaccu85@hanmail.net','바울방의 신나는 야외활동시간입니다^^(2013.08.20)','오늘 바울방에서는 무더운 햇빛을 피해 저녁식사후 즐거운 야외활동시간을 가졌습니다^^
<div>아이들은 다같이 숨바꼭질을 하였는데요~</div>
<div>어린 영재,영호도 함께 하겠다며 형들과 뛰어다니는 모습이 너무 귀여웠습니다~</div>
<div>무더운 날씨 속에서도 우리 &nbsp;아이들이 건강하게 생활할수있도록 지원하겠 습니다^^♥</div>          </td>
        </tr>',800,1376924400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9505,'dus3','박현정','kingi109@naver.com','한나방 선* 아동 운동화 구입(2013.08.19)','<p align="center">선*이와 함께 명동으로 외출하여 예쁜 운동화를 구입하였습니다!!</p>
<p align="center">운동화 잘 신겠습니다^^ 감사합니다.</p>          </td>
        </tr>',808,1376924400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9507,'dus3','송명은','happysme@hanmail.net','룻2방이 맛있는 이탈리아 레스토랑에서 저녁식사를 하였습니다.','무더운 여름방학이 끝나고 개학을 하면서 2학기가 시작되었습니다. 오랜만에 학교에 등교하는 아동들 모두 너무나 뜨거운 날씨에 모두가 지친 모습으로 하교를 하였답니다. 하지만 남산원 아동들을 사랑하는 마음으로 부암동에 위치한 "파란대문"이라는 이탈리아 레스토랑에서 저녁식사를 후원해주셨습니다.
<div>아름다운 마음만큼이나 너무나 예쁘신 사장님께서 아동들에게 부족한 음식은 없는지 꼼꼼히 챙겨주신 덕분에 맛있게 먹고 힘내서 2학기 학교생활도 열심히 할 수 있을 것 같습니다. 더운 날씨에 남산원 아동들을 위해서 애써주신 "파란대문"후원자분들께 진심으로 감사드립니다.</div>          </td>
        </tr>',815,1376838000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9506,'dus3','박진성','js2227@hanmail.net','파란대문 후원 맛있는 저녁식사(2013.08.19)','<p>파란대문은 부암동 서울미술관 앞에 있는 레스토랑입니다.</p>
<p>아담한 레스토랑에는 인상 좋으신 사장님과 주방장님을 비롯하여 여러 직원분들이 계시는데 음식 맛이 최고입니다.</p>
<p>이번에도 저희 아동들을 초대해주셔서 갖가지 맛있는 음식들을 대접해 주셨습니다.</p>
<p>개학을 한 아동들의 지친 마음을 달래주는 달콤함이 있어 아동들의 모습에 웃음이 가득하였습니다.</p>
<p>맛있는 저녁을 준비해주신 파란대문 직원분들께 진심을 감사드립니다^^</p>          </td>
        </tr>',809,1376924400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9508,'dus3','류덕례','yoodr1015@hanmail.net','모세방 선*영(2013.08.20) 생일파티를 하였습니다!!','<p align="left">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 모세방의 훈남 *영이가 19번째 맞이하여&nbsp;생일파티를 하였습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 늘 오늘처럼 웃는일만~기쁜일만 *영이의 미래가 밝도록&nbsp;</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 기원하였습니다. </p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;서로를 위하고 챙겨주는 모습이 새삼 마음이 따뜻한 시간이었습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 마음이 건강하고 자립을 준비하며&nbsp;성장할 수 있도록 남은 시간 잘&nbsp;</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;지도하겠습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;*영아~19번째 생일을 진심으로 축하한다!!&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>          </td>
        </tr>',871,1376838000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9509,'dus3','심주현','pikaccu85@hanmail.net','바울의 신나는 물놀이 시간!!(2013.08.17)','<p align="center">화창한 주말 오후 ~</p>
<p align="center">바울방 친구들과 함께 신나는 물놀이 시간을 가졌습니다 &gt;.&lt;</p>
<p align="center">다음주에 개학을 앞두고 여름방학으로는 거의 마지막 물놀이 시간이였는데요 ㅠㅠ</p>
<p align="center">날이 너무 더워 물에서 만큼은 시원한 시간을 보냈습니다. </p>
<p align="center">우리 아이들이 시원함으로 여름방학을 잘 마무리 할 수 있도록 </p>
<p align="center">건강한 생활을 할 수 있도록 지원하겠습니다!!</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',819,1376665200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9510,'dus3','송명은','happysme@hanmail.net','룻2방 필동어린이집 아동들의 작품전시회(2013.08.16)','룻2방의 미취학아동인&nbsp;<span style="text-align: -webkit-center">*</span>별이와&nbsp;<span style="text-align: -webkit-center">*</span>진이가 등원하고 있는 필동어린이집에서 작품전시회를 하였습니다.&nbsp;<span style="text-align: -webkit-center">*</span>별이와&nbsp;<span style="text-align: -webkit-center">*</span>진이가 직접만든 작품들을 전시한 후에 집으로 보내주셨답니다. 아동들이 직접 만든 작품을 보니 대견스럽기도 하고 작품을 통해서 그동안 아동들에게서 보지 못했던 새로운 면들도 발견하게 되는 의미있는 시간이었습니다. 언제나 남산원 아동들에게 더 세심한 관심을 갖고 보육해주시는 필동어린이집 선생님들께 진심으로 감사드립니다.^^          </td>
        </tr>',834,1376665200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9511,'dus3','송명은','happysme@hanmail.net','룻2방의 여름방학 마지막 물놀이시간입니다.(2013.08.17)','다음주 월요일이면 룻2방의 초등학생과 중학생들이 모두 개학을 한답니다. 개학을 앞두고 마지막 주말 오후시간을 물놀이를 하면서 시원하게 보냈습니다.&nbsp;
<div>유난히 더웠던 이번 여름에는 다행히도 남산원 수영장서의 물놀이 시간이 많은 힘이 되었답니다.</div>
<div>개학을 하더라도 학교생활에 충실할 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',832,1376665200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9513,'dus3','심주현','pikaccu85@hanmail.net','바울방 여름방학 나들이!!(2013.08.16)','<p align="center">&nbsp;</p>
<p align="center">오늘 바울방 초등부아동 여름방학 나들이를 다녀왔습니다. </p>
<p align="center">여름방학 마무리를 하면서 아이들과 신나게 보내고자</p>
<p align="center">종로 영풍문고와&nbsp; 노래방, 청계천 산책을 하였습니다. </p>
<p align="center">오랜만에 우리들끼리 밖으로 나와 즐거운 시간을 가졌는데요 ^^</p>
<p align="center">노래방에서&nbsp; 노래를 부르기 시작한 순간 우리 아이들의 </p>
<p align="center">끼를 맘껏 즐길 수 가 있었습니다. </p>
<p align="center">한 순간도 쉬지않고 일어나 춤추는 우리 아이들이 </p>
<p align="center">너무 귀엽게나&nbsp; 느껴지는 하루였습니다. </p>
<p align="center">멋지고 씩씩한 바울방 아이들이 </p>
<p align="center">건강한 아동기를 보낼 수 있도록&nbsp;&nbsp;지원하겠습니다!!</p>
<p>&nbsp;</p>          </td>
        </tr>',818,1376578800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9512,'dus3','류덕례','yoodr1015@hanmail.net','모세방 김*철, 임*현, 안*현  운동화 구입(2013.08.17)','<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; * 모세방&nbsp;환일중 동*, 수*, 정*이가&nbsp;개학을 앞두고 운동화구입을 지원받았습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;외모에 관심이 많은 중학생들에게 인솔교사와 함께 운동화를 직접가서 구입하고&nbsp;</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 특히, 남학생들이라서 새로 구입한&nbsp;운동화를 관리를 잘하도록 하였습니다. </p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;감사합니다.&nbsp;</p>          </td>
        </tr>',840,1376665200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9515,'dus3','이소영','leesy5576@hanmail.net','룻2방, 환일고등학교 망치동아리 천연모기약만들기 프로그램활동사진입니다.(2013. 8. 15)','2013년 8월 15일 환일고등학교 망치동아리에서 남산원 아이들을 위해 천연모기약만들기 프로그램을 후원해주셨습니다.
<div>프로그램 진행과 활동을 함께 하여 아이들의 수준에 맞게 잘 진행되었고 천연모기약이 냄새도 좋고 인체에 나쁘지 않아 아이들이 무척 좋아하였습니다.</div>
<div>아이들을 위해 프로그램 후 간식과 놀이시간도 함께 해주셨습니다.</div>
<div>항상 저희아이들에게 관심과 사랑으로 후원해주시고 계시는 망치동아리후원자님 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',858,1376492400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9514,'dus3','심주현','pikaccu85@hanmail.net','바울방 유치부 작품 전시회!!(2013.08.16)','<p align="center">&nbsp;</p>
<p align="center">기나긴 방학을 마치고 오늘 유치부가</p>
<p align="center">&nbsp;8월달에 처음으로 어린이 집 등원을 하였습니다. </p>
<p align="center">8월달에 남산캠프를 포함하여 다양한 프로그램이 많아 </p>
<p align="center">오늘 등원하게 되었는데요~</p>
<p align="center">7월달에 필동어린이집에서 있었던 아이들의 재활용품을</p>
<p align="center">&nbsp;활용한 작품들이 집으로 오게 되었습니다. </p>
<p align="center">아이들의 멋진 작품을 그냥 두기 너무 아까워 </p>
<p align="center">바울방에서 영호와 영재의 작품 전시회를&nbsp; 하였습니다. </p>
<p align="center">우리 귀염둥이 영호와 영재가 즐거운 어린이집 생활을 하면서 </p>
<p align="center">매일 즐겁게 활동할 수 있도록 지원하겠습니다!!</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',827,1376578800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9516,'dus3','이소영','leesy5576@hanmail.net','룻2방, 광복절교육 태극기만들기사진입니다.(2013. 8. 15)','2013년 8월 15일 68주년 광복절을 맞이하여 룻2방 아이들이 태극기를 그리며 광복절의 의미를 되새기고감사한 마음을 가졌습니다.
<div>매년 광복절 교육을 하고 있어 중학생아이들은 광복절에 대해 잘 알고 있지만 미취학, 초등학생 아이들은 잘 알지못해 교육적으로 알찬 시간이 된 것 같습니다.</div>
<div>아이들이 방학중 기본적인 교육과 건강한 방학생활을 할 수 있도록 지원하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　&nbsp;</div>          </td>
        </tr>',852,1376492400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9517,'dus3','심주현','pikaccu85@hanmail.net','환일고 망치 동아리와 함께 모기퇴치제 만들기!!(2013.08.15)','<p align="center">8월 15일 광복절^^</p>
<p align="center">환일고 망치동아리 형들과 함께 바울방 아동들이 </p>
<p align="center">천연 모기퇴치제 만들기를 하였습니다!!</p>
<p align="center">유난히 바울방을 이뻐해 주는 형들덕분에 우리 아이들도 </p>
<p align="center">망치 동아리 형들을 매우 잘 따르는 데요^^</p>
<p align="center">오늘도 역시 형들과 함께라 즐거운 시간을 보냈습니다. </p>
<p align="center">천연 모기퇴치제를 형들과 함께 2인 1조를 이뤄 만들고 </p>
<p align="center">형들이 준비해온 맛있는 간식도 먹는 시간을 가졌습니다. </p>
<p align="center">그리고 운동장에 나와 신나는 물놀이 한판 ㅋㅋ</p>
<p align="center">&nbsp;늘 아이들을 위해 멋진 프로그램을&nbsp; 준비해 주는</p>
<p align="center">환일고 망치 동아리 분들께 진심으로 감사드립니다 (^^)(__)(^^)</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',839,1376492400,'', '', '', '', '', '');
