INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9522,'dus3','심주현','pikaccu85@hanmail.net','바울 애니메이션센터 가는 날!!(2013.08.13)','<p align="center">&nbsp;</p>
<p align="center">오늘 애니메이션 센터 프로그램이 있어서 다녀온날 ^^</p>
