INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9523,'dus3','이소영','leesy5576@hanmail.net','룻2방 애니메이션센터 후원프로그램활동사진입니다(2013. 8. 13)','2013년 8월 13일 애니메이션센터에서 미취학, 초등학생, 중학생 아이들을 위한 후원프로그램이 있었습니다.
<div>클레이점토로 스톱모션애니메이션을 직접 촬영해보았고 4D체험활동도 해보았습니다.</div>
<div>남산원 아이들을 위해 캐리커쳐도 그려주셔서 아이들 모두 좋아하는 모습이였고 활동하는 내내 아이들 모두 재미있고 활동적으로 참여하는 모습이였습니다.</div>
<div>아이들에게 좋은 추억과 경험을 쌓게 해주셔서 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',857,1376319600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9525,'dus3','박현정','kingi109@naver.com','한나방 김*름 아동이 네일아트 2급 자격증 취득하였습니다(2013.08.09)','<p align="center">6월부터 종로 mbc아카데미 네일아트 수업을 배우기 시작한 *름이가 7월 필기시험을 통과하고, 8월 실기시험을 통과하여 최종 네일아트 2급 자격증을 취득하게되었습니다. 손재주가 많아, 다양한 그림과 만들기를 잘하는&nbsp;*름이는 몇개월 뒤면, 자립을 하기 때문에 *름이에게만 있는 특별한 재능을 키워가고 있습니다! 현재는 젤네일아트(스페셜과정)도 배울 예정에 있구요! 심화과정을 배우면서&nbsp;여러가지 자격증 취득을 하여 취업도 할 것입니다. *름이를 응원해주세요~!!^^</p>          </td>
        </tr>',806,1376233200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9524,'dus3','송명은','happysme@hanmail.net','룻2방 초등학생들이 아동인권교육에 참석하였습니다.(2013.08.12)','<font face="굴림">폭염이 계속 되는 무더운 여름이지만 우리 남산원 아동들은 "세이브더칠드런과 함께하는 아동인권교육"에 참석하였습니다. 인권교육이라고 하면 아동들에게 어렵고 지루하게만 생각할 수 있는 내용을 보다 쉽고 재밌게 이해할 수 있도록 3시간이 넘는 시간동안 땀흘리며 아동들을 지도해주신 강사님들께 진심으로 감사드립니다.</font>
<div><font face="굴림">오늘 교육시간중에 아동들은 권리지킴이라는 다짐서를 작성하는 의미있는 시간을 갖기도 하였습니다.<br /></font>
<div style="font-family: 굴림">앞으로 아동들의 인권을 보호하고 사랑으로 보육할 수 있도록 노력하겠습니다.&nbsp;</div></div>          </td>
        </tr>',848,1376233200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9526,'dus3','이소영','leesy5576@hanmail.net','룻2방, 강*리 김미란후원자님과의 외출사진입니다.(2013. 8. 11)','2013년 8월 11일 룻2방 *리를 후원해주시고 계시는 김미란 후원자님께서 수박을 사가지고 남산원에방문해주셨습니다.

<div>장마가 끝나고 더위가 한창인 날씨에 아이들을 위한 수박과 함께 나리와 외출을 다녀오셨습니다.</div>
<div>남산원에 대한 변함없는 관심과 사랑으로 아이들 모두 지켜봐 주시고 계서서 진심으로 감사드립니다.</div>
