INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9528,'dus3','남산원','jblee4@naver.com','다윗방 아동들이, 이춘영 사무국장님께 생신축하선물을 전달해 드렸습니다.','<table style="table-layout: fixed" cellspacing="0" cellpadding="0" width="100%" border="0"><colgroup><col width="100%" /></colgroup>
<tbody>
<tr>
<td class="list_han" valign="top">남산원의 어머니이신 이춘영 사무국장님의 생신을 맞이하여 조금 늦었지만 다윗방 아동들이 생신선물을 준비하여 편지와 함께 전달해 드리는 시간을 가졌습니다.&nbsp;생신 진심으로 축하드리고 항상 건강하시길 바랍니다.^~^</td></tr></tbody>',887,1376146800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9530,'dus3','송명은','happysme@hanmail.net','룻2방 아동들에게 이윤지선생님께서 의미있는 선물을 주셨습니다.(2013.08.07)','매주 월,수요일에 남산원을 방문하셔서 룻2방의&nbsp;*영이와&nbsp;*연이의 피아노수업을 해주시는 이윤지선생님께서 이번에는 룻2방 아동들에게 예쁜 수첩을 선물해주셨습니다. 어릴때부터 메모하는 습관을 익히면 훗날 성장했을 때 참 많은 도움이 될 것 같습니다. 언제나 남산원을 기억해주시고 관심주셔서 감사합니다. 무더운 날씨에 건강한 여름을 보내시길 기도하겠습니다.감사합니다.^^          </td>
        </tr>',839,1375974000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9531,'dus3','송명은','happysme@hanmail.net','룻2방의 즐거운 여름캠프 제3탄!!(2013.08.01~05)','<p>아쉽지만 내년을 기약하면서 4박5일동안의 여름캠프를 마무리했습니다.</p>
<p>남은 여름방학기간에도 남산원 아동들이 모두 건강하게 즐거운 여름방학을 보낼 수 있도록 보육하겠습니다.</p>          </td>
        </tr>',877,1375887600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9529,'dus3','송명은','happysme@hanmail.net','룻2방이 이혜경의원님의 후원으로 썸머클래식 공연을 관람하였습니다.(2013.08.10)','무더운 여름에 남산원의 아동들을 사랑하는 마음을 담아 이혜경의원님께서 세종문화회관에서 열린 "썸머클래식"이라는 공연을 관람할 수 있도록 후원해주셨습니다.
<div>남산원의 꽃보다 예쁜 룻2방도 이혜경의원님 덕분에 무더운 날씨에 아름다운 공연을 관람하면서 조금은 시원한 주말을 보낼 수 있었습니다. 감사합니다.</div>          </td>
        </tr>',826,1376060400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9533,'dus3','송명은','happysme@hanmail.net','룻2방의 즐거운 여름캠프 제1탄!!(2013.08.01~05)','<p>1년에 한번 남산원 아동들이 기다리고 기다리는 즐겨운 여름캠프가 드디어 시작되었습니다. 즐거운 여름캠프에&nbsp;꽃보다 예쁜 룻2방도 함께 참석해서 신나는 시간을&nbsp;보냈습니다.</p>
<p>이번 여름캠프에서는 오전에는&nbsp;직업진로교육을 하고 오후에는 자립관련&nbsp;프로그램을&nbsp;진행하면서 유익한 시간을 보냈습니다.</p>
<p>&nbsp;</p>          </td>
        </tr>',836,1375887600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9534,'dus3','이소영','leesy5576@hanmail.net','룻2방, 이춘영사무국장님생신축하선물전달사진입니다.(2013. 8. 8)','2013년 8월 8일 엄마생신을 맞이하여 아이들이 생신카드와 선물을 전달하였습니다.
<div>생신 전날 밤 아이들이 스스로 편지를 정성스럽게 만들고 써서 아침에 생신축하노래와 선물을 드리며 마음을 전달하였습니다.</div>
<div>이춘영사무국장님 생신 진심으로 축하드립니다. 건강하세요^^</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>&nbsp;&nbsp;</div>          </td>
        </tr>',909,1375887600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9532,'dus3','송명은','happysme@hanmail.net','룻2방의 즐거운 여름캠프 제2탄!!(2013.08.01~05)','<p>여름캠프가 즐거운 이유는 남산원 가족 모두가 함께 하기 때문인 것 같습니다.^^</p>          </td>
        </tr>',856,1375887600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9536,'dus3','김성재','thunderdog9@naver.com','다윗방 여름의복 구입했습니다.(2013.07.30)','다윗방 중학생 아동들이 여름의복을 구입했습니다. 정해진 금액 안에서 신중하게 자신이 원하는 옷을&nbsp;직접 골라 구매하는 과정 또한&nbsp;경제적인 교육의 일부라는 생각으로 의복구입을 진행하였습니다.&nbsp;구입한 옷에는 모두들 만족해하는 모습이었습니다. 예쁜 새&nbsp;옷, 아껴서 오래 입을 수 있도록 지도하겠습니다. 의복구입지원에 감사드립니다.          </td>
        </tr>',917,1375282800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9537,'dus3','류덕례','yoodr1015@hanmail.net','모세방 김*진 운동화 구입(2013.07.31)','<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; * 모세방 *진이가 여름방학을 맞이하여 운동화구입을 지원받았습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 패션과 운동화에 관심이 많아&nbsp;개성있는 운동화를</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 선택 하였습니다. </p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 고3이라서 진로 선택 및 장래를 설계하길 바랍니다.</p>          </td>
        </tr>',885,1375196400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9535,'dus3','심주현','pikaccu85@hanmail.net','바울방 여름방학 맞이 영화관람 하는날!!(2013.08.07)','<p align="center">&nbsp;</p>
<p align="center">즐거운 남산 여름캠프가 끝나고~</p>
<p align="center">오늘 여름방학을 맞이 하여 </p>
<p align="center">랄랄랄랄랄라~ 랄랄랄랄라~ ♪ 랄랄랄랄랄라~♩ 랄랄랄라라~♬</p>
<p align="center">대한극장에 스머프2를 관람하러 다녀왔습니다. ^^</p>
<p align="center">더빙으로 되어 있어 아이들이 편하게 영화관람을 할 수 있었는데요~</p>
<p align="center">여름방학 후 바쁜 프로그램일정으로 바울방 친구들과 여름방학이 되어 </p>
<p align="center">처음으로 나가는 나들이 였답니다~ ^^</p>
<p align="center">얼마 남지 않은 방학기간동안 우리 아이들이 즐겁게 생활할 수 있도록 </p>
<p align="center">지원하겠습니다!!</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',836,1375887600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9540,'dus3','송명은','happysme@hanmail.net','룻2방의  *연이가 생일을 맞이했습니다.(2013.07.29)','룻2방의 댄싱퀸 *연이가 11번째 생일을 맞이했습니다.

<div>선생님의 잔소리가 필요없을 정도로 똘똘한 우리 *연이는 무더운 여름에 태어난만큼 모든일에 뜨거운 열정을 갖고 열심히 생활하고 있답니다.</div>
<div>올해 4학년이 되어서 학교와 집에서 언제나 많은 사람들에게 칭찬받는 우리 *연이가 앞으로도 몸과 마음이 건강한 아동으로 성장할 수 있도록 지도하겠습니다.</div>
<div>사랑받기 위해 태어난&nbsp;<span style="text-align: -webkit-center">*</span>연아~11번째 생일을 진심으로 축하해~♥</div>          </td>
        </tr>',858,1375023600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9538,'dus3','류덕례','yoodr1015@hanmail.net','모세방 여름 의복구입(2013.07.31)했습니다.','<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; * 모세방 아동들이 원내행사로 여름의복 구입에 다녀왔습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;청소년기에 가장 관심이 많은 패션과 본인의 옷을 구입한다는</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 설레임으로&nbsp;멋진 모습으로 성장하길 바랍니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 의복구입을 지원해주셔서 감사합니다!!&nbsp;</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;</p>          </td>
        </tr>',926,1375196400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9539,'dus3','이소영','leesy5576@hanmail.net','룻2방, 방학생활계획표 시상식(2013. 7. 27)','2013년 7월 27일 룻2방 박<span style="text-align: -webkit-center">*</span>민, 김<span style="text-align: -webkit-center">*</span>희, 강<span style="text-align: -webkit-center">*</span>리 아동이 방학생활계획표를 만든 결과 아차상, 최우수상을 수상하여 상장과 문화상품권을 받았습니다.

<div>아이들이 방학을 의미있고 알차게 보내기 위해 작성한 방학생활계획표가 칭찬을 받고 좋은 결과가 나와 아이들에게 동기부여가 된 것 같습니다.</div>
<div>계획표에 맞게 성실하게 생활할 수 있도록 지원, 보육하도록 하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',885,1375196400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9542,'dus3','류덕례','yoodr1015@hanmail.net','모세방 조*주, 임*현 방학생활계획표 시상식(2013. 7. 28)','<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; * 원내프로그램으로 방학생활계획표를 성실하게 작성한</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; *주가 상을 탔습니다. *현이는 잘그렸지만 아쉬운 아차상을</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 받아서 상장과 상금을 받은 기쁜소식을 알립니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;계획대로 여름방학을 알차고 보람있는 생활을 보내길 바랍니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 성실한 모세방 *주와 *현의 밝은 미래를 기대합니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>          </td>
        </tr>',897,1374937200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9541,'dus3','남산원','jblee4@naver.com','다윗방 생활계획표 시상식(2013.07.28)','방학생활계획표를&nbsp;멋지게&nbsp;그린&nbsp;<span style="text-align: -webkit-center">*</span>석이가 다윗방 최우수상을,&nbsp;<span style="text-align: -webkit-center">*</span>수는 아차상을 받아&nbsp;상장과 함께 문화상품권을 지급받았습니다.&nbsp;

<div>이번 여름방학은 계획표대로 알차고 성실하게 지낼 수 있기를 바랍니다.</div>          </td>
        </tr>',941,1374937200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9543,'dus3','류덕례','yoodr1015@hanmail.net','모세방 성적향상소식(2013. 7. 25)','<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;* 모세방은 중학생부터 대학생까지 생활하는 아동입니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;중간고사보다 기말고사 성적이 많이 향상되어 원내 프로그램으로</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;1학기, 2학기 상장을 수여합니다.</p>
<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<span style="text-align: -webkit-center">*</span>주가 평균 17점정도 향상이 되었고&nbsp;<span style="text-align: -webkit-center">*</span>철,&nbsp;<span style="text-align: -webkit-center">*</span>진이도 향상되어</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;상장과 상금을 수여했습니다. 2학기 성적도 분발하도록 </p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 노력 바랍니다.</p>          </td>
        </tr>',898,1374937200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9544,'dus3','이소영','leesy5576@hanmail.net','룻2방 김*희, 강*리, 박*민 방학생활계획표 수상사진입니다.(2013. 7. 28)','남산원에서는 아동들의 여름방학을 맞이하여 여름방학계획표를 매년 스스로 계획하고 작성하여 실천하고 있습니다. &nbsp;&nbsp;

<div>2013년 7월 28일 룻2방 김*희, 강*리, 박*민아동이 방학생활계획표를 잘 계획하고 작성하여 상장과 문화상품권을 받았습니다.</div>
<div>아이들이 방학을 의미있게 보내기 위해 정성껏 작성한 후 좋은 결과를 얻어 정말 기특하고 이쁩니다.</div>
<div>아이들이 스스로 세운 계획인 만큼 실천하고 알찬 방학이 될 수 있도록 지원하겠습니다.</div>          </td>
        </tr>',1099,1374937200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9545,'dus3','송명은','happysme@hanmail.net','룻2방이 환일고와 함께 즐거운 종이접기를 하였습니다.(2013.07.27)','무더운 여름 토요일 오전부터 남산원 아동들과의 즐거운 시간을 위해 환일고 어머니분들과 오빠들이 함께 남산원을 방문해주셔서 초등학생 아동들과 예쁘고 멋진 종이접기를 하면서 액자도 만들고 예쁜 핸드백도 만들면서 즐거운 시간을 보냈습니다. 오늘 배운 종이접기 실력으로 앞으로 더 멋있는 작품들을 만들면서 신나는 여름방학을 보낼 수 있도록 지도하겠습니다. 감사합니다.^^          </td>
        </tr>',842,1374937200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9546,'dus3','김선기','spsp99@naver.com','다윗방 이*늘아동 생일(2013.07.27)','<p>다윗방에 멋쟁이 *늘이가 오늘 생일을 맞이 하였습니다.다윗방 아동들 모두 *늘이에 생일을 축하해 주고 축복해 주었습니다.*늘아 생일 진심으로 축하하고 더 밝고 착하게 자라 주렴 선생님이 늘 기도할께 *늘아 사랑한다 다윗방 김선기선생님이.</p>          </td>
        </tr>',911,1374850800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9548,'dus3','박현정','kingi109@naver.com','한나방 1학기 성적에 대한 상금지급!!(2013.07.25)','<p align="center">&nbsp;</p>
<p align="center">한나방 아동들 모두가 기말고사 성적이 올랐습니다~~~!!</p>
<p align="center">7점부터 33점까지~~~ 모두 열심히 해준 덕분에 아빠께서 상금을 주셨습니다!!</p>
<p align="center">선진이같은 경우에는 30점이나 올라 모두를 놀라게 하였습니다.</p>
<p align="center">이렇게 학교생활을 열심히 하는 아이들을 볼 때면 참 뿌듯합니다^^</p>
<p align="center">2학기때는 더 좋은 성적을 거두었으면 좋겠습니다~~~^^</p>          </td>
        </tr>',830,1374764400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9547,'dus3','이소영','leesy5576@hanmail.net','룻2방, 덕수중학교 성적향상금전달사진입니다.(2013. 7. 25)','<p>2013년 7월 25일 덕수중학교 재학중인</p>
<p>룻2방 김<span style="text-align: -webkit-center">*</span>희, 김<span style="text-align: -webkit-center">*</span>선, 강<span style="text-align: -webkit-center">*</span>리, 김<span style="text-align: -webkit-center">*</span>진 아동이 기말고사 성적이 향상되어</p>
<p>상장과 함께 성적향상금을 받았습니다.</p>
<p>룻2방 중학생 아이들 모두 성적이 향상되어 기특하고 대견합니다.</p>
<p>방학동안에도 예습, 복습을 잘 하여 2학기에도 성적이 향상될 수 있도록 보육하겠습니다.</p>
