<p>&nbsp;</p>          </td>
        </tr>',902,1374764400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9549,'dus3','박현정','kingi109@naver.com','한나방 옷 구입(2013.07.24)','<p align="center">한나방 아동(선진,강세미,유혜연)들이 명동에 직접 나가 여름 옷 구입을 하였습니다~!!!</p>
