INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9551,'dus3','박진성','js2227@hanmail.net','바울방 생활계획표 만들기(2013.07.25)','<p>바울방 아동들이 방학을 알차게 보내기 위해 생활계획표를 만들어 실천을 해보려고 합니다.</p>
<p>우리 바울방 아동들이 막내부터 가장 큰형까지 열심히 만들어 준비하였습니다.</p>
<p>즐거운 여름방학을 슬기롭게 보낼 수 있도록 응원해주세요~</p>
<p>뜻깊게 보내며 탐구하는 방학으로 보낼 수 있도록 지원을 하도록 하겠습니다.^^*</p>          </td>
        </tr>',836,1374678000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9552,'dus3','이소영','leesy5576@hanmail.net','룻2방, 방학생활계획표 작성 사진입니다.(2013. 7. 24)','2013년 7월 24일 룻2방 아이들이 방학을 하여 방학생활계획표를 만들었습니다.
<div>계획을 세우는 작은 습관들로 아이들이 방학을 알차고 의미있게 보냈으면 좋겠습니다.</div>
<div>방학동안 아이들이 생활계획표에 맞게 생활하고 건강하게 지낼 수 있도록 보육하겠습니다.</div>
