INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9557,'dus3','박진성','js2227@hanmail.net','여름방학 맞이 남산산책^^(2013.07.21)','<p>아침의 맑은 공기를 맡으며 아동들과 함께 남산산책을 다녀왔습니다.</p>
<p>남산초등학교의 여름방학으로 한가로운 일상을 시작한 아동들의 밝은 모습이 너무나 사랑스럽습니다.</p>
<p>우리 바울방이 지금처럼 건강한 모습으로 생활하길 간절히 기도해봅니다~^^*</p>          </td>
        </tr>',872,1374418800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9556,'dus3','이소영','leesy5576@hanmail.net','룻2방 파란대문후원 저녁식사 사진입니다.(2013. 07. 22)','2013년 7월 22일 룻2방 미취학, 초등학생아이들이 파란대문레스토랑 저녁식사를 후원받아 식사를 하였습니다.
<div>장마기간이 길어 외부활동을 많이 하지 못하고 있는 아이들이 오랜만에 밖으로 나가서 활동하고 좋아하는 피자, 파스타를 먹고 감사하는 마음을 가졌습니다.</div>
<div>우리 아이들에게 건강한 먹거리를 후원해주신 파란대문후원자님 감사드립니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',824,1374418800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9558,'dus3','송명은','happysme@hanmail.net','룻2방의 시원한 콘빙수 만들기 2탄!!(2013.07.21)','룻2방의 중학생 언니들도 시원한 콘빙수 만들기에 집중해서 열심히 만들고 열심히 먹기도 하였답니다.
<div>내일 여름방학을 하게 되는 우리 룻2방의 중학생 언니들이 알차고 유익한 여름방학을 보낼 수 있도록 열심히 보육하겠습니다.^^</div>          </td>
        </tr>',800,1374332400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9560,'dus3','송명은','happysme@hanmail.net','룻2방의 *연이와 *민이가 맛있고 예쁜 초코케익을 만들었습니다.(2013.07.21)','매주 일요일마다 필동감리교회 초등부예배에 참석하면서 열심히 종교생활을 하고 있는 룻2방의 *연이와 *민이는 오늘 예배를 마친후에 오후 프로그램으로 맛있는 초코케익을 만들었습니다. 감사한 마음을 가득 담아 케익위에 "Thank you"라는 글씨까지 정성껏 만든 케익을 룻2방 가족 모두가 맛있게 먹었답니다.

<div>항상 모든 일에 감사하며 생활하는 아동으로 성장할 수 있도로 지도하겠습니다.</div>          </td>
        </tr>',830,1374332400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9559,'dus3','송명은','happysme@hanmail.net','룻2방의 시원한 콘빙수 만들기 1탄!!(2013.07.21)','계속되는 장마에 후덥지근한 날씨가 계속되는 일요일 오후에 룻2방의 아동들은 모두 함께 시원한 콘빙수!!만들기를 하였습니다. 팥빙수 대신해서 옥수수콘을 준비하고 우유,미숫가루,콘푸러스트 등등 여러가지 재료들로 예쁘고 시원한 콘빙수를 만들었습니다.

<div>특히&nbsp;<span style="text-align: -webkit-center">*</span>별이와&nbsp;<span style="text-align: -webkit-center">*</span>연이가 만든 콘빙수는 남산원의 아빠,엄마께 직접 드리기도 하였답니다.</div>
<div>계소 되는 무더위에 우리 아동들이 건강하게 생활할 수 있도록 열심히 지도하겠습니다.</div>          </td>
        </tr>',832,1374332400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9561,'dus3','송명은','happysme@hanmail.net','룻2방의 *영이가 유혜종선생님과 즐거운 나들이를 하였습니다.(2013.07.21)','매주 일요일마다 룻2방의 *영이의 영어학습지도를 해주시는 유혜종선생님께서 *영이와 특별한 보내주셨습니다. &nbsp;

<div>무더운 여름을 시원하게 해줄 "어린이 드로잉쇼"라는 뮤지컬을 관람할 수 있도록 해주셨답니다.</div>
<div>*영이는 재미있는 뮤지컬도 보고 뮤지컬에 나오는 주인공과 사진도 찍었습니다. 또 맛있는 간식도 먹으면서 즐거운 하루를 보냈습니다.

<div>여름방학을 맞이하여&nbsp;*영이와 함께 보내주신 오늘을 우리 *영이가 마음 속 깊히 간직할 수 있을 것 같습니다. 다시한번 감사드립니다.^^</div></div>          </td>
        </tr>',853,1374332400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9563,'dus3','이소영','leesy5576@hanmail.net','룻2방 상장수여식 사진입니다.(2013. 7. 18)','<font face="굴림" style="font-family: 굴림">룻2방 아이들이 학교에서 도서 독후감상과 수영대회에서 수상을 하여 상을 받았습니다.</font>
<div><font face="굴림">아침에 상장수여식과 상금수여식을 갖으며 칭찬을 해주었습니다.</font>
<div style="font-family: 굴림"><font face="굴림">아이들의 노력의 결과가 뿌듯하고 기특합니다.</font></div>
<div style="font-family: 굴림"><font face="굴림">한 학기동안 룻2방 아이들이 학교생활을 잘 해주어 1학기를 마무리하고 방학을 맞이하는데 방학을 잘 보내고 건강하게 보낼수 있도록 보육하겠습니다.</font></div>
