<div style="font-family: 굴림"><div style="font-family: 굴림">&nbsp;&nbsp;</div></div></div>          </td>
        </tr>',852,1374073200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9562,'dus3','박진성','js2227@hanmail.net','바울방 컴퓨터 공부활동(2013.07.18)','<p>하교 후 모임방에서 토요일 특기적성 컴퓨터 활동을 하는 아동들의 컴퓨터 공부시간이 있었습니다.</p>
<p>평소와는 다르게 컴퓨터 활동을 하면서 집중모드입니다^^</p>
<p>우리 아동들이 관심 분야를 경험해보고 열심히 활동을 할 수 있도록 지원을 꾸준히 하도록 하겠습니다!!!</p>          </td>
        </tr>',846,1374073200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9564,'dus3','심주현','pikaccu85@hanmail.net','바울  상장 수여식 하는날^^(2013.07.18)','오늘 아침 바울방 이한결 정철균아동이 상장수여식을 하였습니다^^
<div>학교에서도 늘 모범을 보이는 한결 철균이가 받았는데요^^</div>
<div>1학기를 열심히 마무리하는모습이 너무 대견스럽습니다!</div>
<div>아이들이 즐거운학교생활을 보낼수있도록 지원하겠습니다!</div>
<div><br /></div>          </td>
        </tr>',792,1374073200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9565,'dus3','이소영','leesy5576@hanmail.net','룻2방 저녁식사후원 감사편지 전달사진입니다.(2013. 7. 15)','2013년 7월 11일&nbsp;*영이와&nbsp;*연이 피아노 지도를 해주시고 계시는 이윤지선생님께서 남산원을 위해 저녁식사로 햄버거를 후원해 주셨습니다.

<div>남산원에 대한 애정으로&nbsp;*영이&nbsp;*연이를 잘 지도해 주시고 항상 관심있게 지켜봐주시고 계십니다.</div>
<div>룻2방에서 이윤지선생님께 감사한마음을 조금이나마 보답하고자 정성스레 편지를 써서 이윤지선생님께 전달하였습니다.</div>
<div>앞으로도 저희 아이들 건강하고 이쁘게 잘 자랄 수 있도록 보육하겠습니다.</div>
<div>저녁식사 후원과 꾸준한 재능기부감사드립니다.^^</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',876,1373814000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9566,'dus3','송명은','happysme@hanmail.net','룻2방의 모범아동들이 탄생했습니다.(2013.07.14)','<font face="굴림">2013년 상반기를 돌아보며 그동안 남산원에서 아동들의 올바른 생활지도를 위해 실시한 상벌점제도 프로그램에서 가장 모범적인 아동으로 뽑힌 1등,2등,3등이 모두 룻2방에서 나왔습니다.</font>
<div><font face="굴림">1등-김</font><span style="text-align: -webkit-center">*</span><font face="굴림">선, 2등-강</font><span style="text-align: -webkit-center">*</span><font face="굴림">리,3등-김</font><span style="text-align: -webkit-center">*</span><font face="굴림">희입니다.</font></div>
<div><font face="굴림">세명의 아동들은 모두 룻2방에서 뿐만 아니라 원내에서도 어른들께 예의바르고 교우관계도 원만하게 잘 생활하고 있답니다. 이번에 모범상을 받은 세명의 아동에게는 남산원 아빠께서 아이들이 가장 좋아하는 문화상품권을 선물로 주셨답니다. 다음달에는 사랑스러운 초등학생도 모범아동으로 뽑힐 수 있도록 열심히 보육하겠습니다. 감사합니다.^^</font></div>          </td>
        </tr>',859,1373727600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9567,'dus3','송명은','happysme@hanmail.net','룻2방과 바울방이 주말나들이를 다녀왔습니다.(2013.07.13)','몇일째 계속되는 장마로 인해 바깥놀이가 힘든 아이들을 위해 신세계푸드에서 후원해주셔서 맛있는 점심식사도 하고 만화가 완성되기까지의 과정을 스케치한 전시회도 관람하면서 유익하고 즐거운 시간을 보냈습니다. 앞으로도 남산원 아동들을 향한 관심과 사랑을 부탁드립니다.
<div>감사합니다.^^</div>          </td>
        </tr>',856,1373727600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9568,'dus3','류덕례','yoodr1015@hanmail.net','박재민 선생님과 안*현, 김* 외출(2013.07.13)','<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;* 박재민 선생님과 안*현, 김*&nbsp;외출(2013.07.13)하였습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;평소 아동들과 사이가 돈독하신 박재민 선생님이 기말고사를</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;마친 아동들과 특별한 외출을 하였습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 맛있는 식사와 영화관람후 귀원한 아동들의 입가에 미소가</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;가득이었습니다. 한주도 빠지지 않고 수업해주신 박재민 선생님!!</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 성적도 쑥쑥 기대합니다. 감사합니다.</p>
<p>&nbsp;</p>          </td>
        </tr>',896,1373641200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9569,'dus3','송명은','happysme@hanmail.net','룻2방은 이윤지선생님께서 후원해주신 햄버거를 맛있게 먹었습니다.(2013.07.11)','룻2방을 대표하는 두명의 사랑스런 공주님~
<br />
<div><span style="font-size: 9pt; line-height: 1.5">*</span>영이와&nbsp;*연이의 피아노레슨을 지도해주시는 이윤지선생님께서 오늘은 특별히 남산원 아동들을 위해서 맛있는 햄버거를 후원해주셨습니다. 평소에도&nbsp;*영이와&nbsp;*연이를 위해 열정을 가지고 레슨을 해주시는 이윤지선생님입니다. 아이들의 피아노 실력 뿐만 아니라 아이들의 정서상태등을 신경써주시는 배려심 덕분에 아이들의 피아노 실력이 좋아지고 있답니다.</div>
<div>오늘도 후원해주신 맛있는 햄버거 덕분에&nbsp;*영이와&nbsp;*연이 뿐만 아니라 남산원 아동 모두가 즐겁고 신나는 저녁식사시간이 되었답니다. 다시한번 감사드립니다.^^</div>          </td>
        </tr>',894,1373468400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9570,'dus3','김성재','thunderdog9@naver.com','다윗방 구충제 복용했습니다.(2013. 7. 8)','<p>7월 8일은 원내아동들과 전직원이 구충제를 복용하는 날이었습니다. 다윗방 아동들도 구충제를 한 알씩 복용하고 잠자리에 들었습니다. 일년에 두 번 구충제 복용으로 좀 더 건강한 생활을 해 나갈 수 있도록 지원하겠습니다.</p>          </td>
        </tr>',830,1373382000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9571,'dus3','이소영','leesy5576@hanmail.net','룻2방, 강*리후원물품전달사진입니다.','2013년 7월 8일 룻2방 *리를 후원해주고 계시는 김미란 후원자님께서 *리의 여름옷과 신발, 간식을 보내주셨습니다.&nbsp;

<div>후원물품을 보고 *리가 정말 좋아하는 모습이였고옷과 신발을 입어보며 감사하는 마음을 가졌습니다.</div>
<div>간식은 룻2방 아이들 전체가 사이좋게 잘 나누어 먹었습니다.</div>
<div>꾸준히 *리에게 관심과 사랑주고 계시는 김미란후원자님 진심으로 감사드립니다.</div>
<div>*리가 후원자님의 사랑으로 건강하고 이쁘게 자라서 후원자님처럼 베풀줄 아는 훌륭한 사람이 될 수 있도록 보육하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',823,1373382000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9572,'dus3','박현정','kingi109@naver.com','한나방 아동 구충제 약 복용(2013.07.08)','<p align="center">&nbsp;</p>
<p align="center">한나방 아동이 구충제 약을 복용하였습니다.</p>          </td>
