INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9573,'dus3','송명은','happysme@hanmail.net','룻2방의 중학생들은 기말고사 준비를 열심히 하였습니다.(2013.07.07)','<p>덕수중학교를 다니고 있는 룻2방의 중학생들은 지난주부터 시작된 1학기 기말고사의 마지막 시험을 준비하느라 더운 여름인데도 불구하고&nbsp;머리에 땀이 나도록 열심히 공부를 하였습니다.</p>
<p>지난번 중간고사때보다 더 높은 점수를 받겠다는 의지를 가지고 시험공부에 집중하는 아이들이 너무나 기특하답니다. </p>
<p>내일이면 그동안 열심히 준비했던 시험이 끝나는 날이라서 기쁜마음도 더 큰 것 같습니다. 앞으로 우리 아이들의 학습실력이 조금씩 향상될 수 있도록 많은 관심과 사랑부탁드립니다.^^</p>
<p>강<span style="text-align: -webkit-center">*</span>리,김<span style="text-align: -webkit-center">*</span>희,김<span style="text-align: -webkit-center">*</span>선,김<span style="text-align: -webkit-center">*</span>진~~화이팅!!!</p>          </td>
        </tr>',870,1373122800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9574,'dus3','송명은','happysme@hanmail.net','룻2방 미취학아동들은 주일에 침례교회 유치부 예배를 드립니다.(2013.07.07)','<p>룻2방의&nbsp;<span style="text-align: -webkit-center">*</span>별이와&nbsp;<span style="text-align: -webkit-center">*</span>진이는 매주 주일마다 침례교회 유치부에서 예배를 드립니다.</p>
<p>처음에는 예배를 드릴때 기도를 하고 설교말씀을 듣는 시간이 지루하기만 했던&nbsp;<span style="text-align: -webkit-center">*</span>별이와&nbsp;<span style="text-align: -webkit-center">*</span>진이는 어느새 유치부의 제일 큰 언니,누나가 되어서 멋진 모습으로 동생들과 함께 예배를 드립니다. 또 오늘은 성경말씀 암송을 하는 날이어서 교회에 가기전부터 열심히 성경말씀 암송을 연습하였습니다. 앞으로도&nbsp;<span style="text-align: -webkit-center">*</span>별이와&nbsp;<span style="text-align: -webkit-center">*</span>진이뿐만 아니라 남산원의 모든 아동들이 하나님의 사랑가운데 건강하게 성장할 수 있도록 열심히 기도하며 보육하겠습니다.</p>          </td>
        </tr>',803,1373122800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9575,'dus3','심주현','pikaccu85@hanmail.net','바울방 서울침례교회 유치부 활동사진입니다^^(2013.07.07)','<p align="center">&nbsp;</p>
<p align="center">오늘은 교회가는날!!</p>
<p align="center">우리 유치부 아동들이 서울 침례교회에 가서 선생님과 함께 </p>
<p align="center">성경암송도 하며 즐거운 예배를 드리고 왔습니다 ^^</p>
<p align="center">아이들이 주일을 통해 종교활동을 열심히 할 수 있도록 </p>
<p align="center">지원하겠습니다 ^^</p>
<p align="center">&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',807,1373122800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9576,'dus3','박진성','js2227@hanmail.net','바울방  주말 남산 나들이(2013.07.07)','<p>바울방 아동들과 함께 남산 나들이를 갔습니다.</p>
<p>&nbsp;</p>
<p>열심히 뛰고 바람을 느끼며 즐겁고 상쾌한 시간을 보내고 왔어요~</p>
<p>&nbsp;</p>
