INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9580,'dus3','박현정','kingi109@naver.com','한나방 물놀이 사진(2013.06.30)','한나방 김아름, 유혜연 아동이 바울방, 다윗방 아동들과 함께 재미있는 물놀이를 하였습니다. 요즘 날씨가 너무 더워 걱정을 많이 하였는데 신나는 물놀이를 하면서 더위를 이겨내는 모습이 너무 예쁘네요~^^          </td>
