INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9582,'dus3','박진성','js2227@hanmail.net','바울방 수영장 안전하게 이용하기 프로그램(2013.06.30)','<p>교회 예배를 다녀와서 함께 남산원 수영장을 이용하였습니다.</p>
<p>다윗방 형들과 한나방 누나들, 그리고 룻2방의 아동들과 함께 신나는 물놀이를 하였습니다.</p>
<p>안전하게 미취학 아동들에게 튜브도 양보하고 즐겁게 활동을 하며 오후 시간을 보냈습니다.</p>
<p>수영장을 이용하며 안전하고 건강하게 놀이를 할 수 있도록 꾸준히 지원을 하도록 하겠습니다.^^</p>
<p>또한 시원한 여름을날 수 있도록 수영장 물놀이를 꾸준히 지원을 하도록 하겠습니다.</p>          </td>
        </tr>',815,1372518000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9581,'dus3','류덕례','yoodr1015@hanmail.net','모세방 임*현(2013.06.30) 생일파티','<p>&nbsp; * 모세방 *현(2013.06.30)이가 생일파티를 하였습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;중학년 3학년으로 16살 생일이 의미가 클것 같습니다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;진학을 앞두고 진로선택 그리고 매사에 머리가 영리하지만</p>
<p>&nbsp;&nbsp;&nbsp; 지금보다 노력을 하여서 성과를 거둘줄 믿습니다.</p>
<p>&nbsp;&nbsp;&nbsp; 형들과의 생활도 적응을 잘하고&nbsp;장점이 많은 *현이가</p>
<p>&nbsp;&nbsp;&nbsp; 훌륭하게 성장하도록 많은 성원부탁드립니다!!&nbsp;</p>          </td>
        </tr>',830,1372518000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9583,'dus3','이소영','leesy5576@hanmail.net','룻2방, 주말오후 물놀이 사진입니다.(2013. 6. 30)','<div style="font-family: 굴림">남산원에 아이들이 &nbsp;신나게 놀 수 있는 수영장이 설치되었습니다.</div><font face="굴림">내일부터 비가온다는 장마소식에 맑은 주말 룻2방 미취학, 초등학생 아이들이 오후에 물놀이를 하였습니다.</font>
