INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9584,'dus3','심주현','pikaccu85@hanmail.net','바울방의 즐거운 주말보내기!!(2013.06.29)','<p align="center">무더운 주말 오후 바울방은 남산원 수영장에서 수영 놀이를 하였습니다. ^^</p>
