INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9586,'dus3','송명은','happysme@hanmail.net','룻2방의 시원한 물놀이시간입니다.(2013.06.29)','가만히 있어도 땀이 흐를정도의 무더운 주말오후시간에 우리 룻2방의 예쁜 아동들은 시원한 물놀이를 하기 위해 수영장으로 나왔답니다. 수영을 하기 전에 가장 중요한 준비운동을 열심히 하는 귀여운 룻2방이랍니다.
<div>운동을 다 마친 후에 가볍게 물을 몸에 적시고 작은 수영장으로 풍덩~~^^</div>
