INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9590,'dus3','심주현','pikaccu85@hanmail.net','바울방 ktx 기차 조립모형 만들기!!(2013.06.26)','<p align="center">오늘 저녁에 아이들과 함께 지난번 순천만 정원박람회에 갔을때 </p>
<p align="center">선물받은 ktx 기차 조립 모형 만들기를 하였습니다. </p>
<p align="center">아이들이 집중력을 발휘해 손이 많이 가는 기차모형을 완성하였는데요 ^^</p>
<p align="center">저학년 아동들은 하기 어려워 고학년 형들이 많이 도와 주었답니다!!</p>
