INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9591,'dus3','심주현','pikaccu85@hanmail.net','바울방 남산원 수영장에서 노는날!!(2013.06.26)','<p align="center">바울방이 올해 처음으로 남산원에 </p>
