INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9589,'dus3','남산원','jblee4@naver.com','수영장에서 물놀이하는 다윗방 아동들(2013.06.27)','오늘도 어김없이 무더운 하루였습니다. 방과후 돌아와 남산원내에 설치된 수영장에서 물놀이를 하며&nbsp;더위를 식히는 다윗방 아동들의 모습을 사진에 담아봤습니다. 수영장설치에는 많은 자원봉사자분들이 도움을 주셨었죠. 안전사고가 발생하지 않도록 잘 지도하며 시원한 여름 보낼 수 있도록 하겠습니다.^~^          </td>
