INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9593,'dus3','이소영','leesy5576@hanmail.net','룻2방, 바울방, 다윗방 바느질수업 활동사진입니다.(2013. 6. 26)','2013년 6월 26일 룻2방, 바울방, 다윗방 초등학생 아이들이 바느질 수업을 하였습니다.&nbsp;
