INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9592,'dus3','심주현','pikaccu85@hanmail.net','바울방 쿠션 만들기!!(2013.06.26)','<p align="center">오늘 에버랜드 프로그램으로 쿠션만들기를 하였습니다. </p>
<p align="center">고사리 같은 손으로 바느질을 하여 완성한 쿠션인데요 ^^</p>
<p align="center">남자 아이들이기는 하지만 자기가 만든 쿠션이 좋은지 </p>
<p align="center">방에서도 하루종일 손에 들고 다니는 모습이랍니다 ^^</p>
