INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9597,'dus3','이소영','leesy5576@hanmail.net','2013. 6. 20 룻2방, 바울방, 다윗방 순천 국제정원박람회 현장학습 사진입니다.','2013년 6월 20일 룻2방, 바울방, 다윗방 초등학생 아이들이 한국철도공사후원 해피트레인 순천 국제정원박람회에 다녀왔습니다.
<div>무더운 날씨 아이들과 소풍가는 기분으로 KTX를 타고 아침일찍부터 출발하여 순천에 도착해 마음껏 뛰어놀고 정원박람회 관람 및 미로찾기, 미술관 관람, 박람회 작은 동물원에서 구경도 하며 재미있게 활동을 마치고 돌아왔습니다.</div>
<div>아이들에게 좋은 경험과 추억을 만들어 주신 한국철도공사후원자님 감사드립니다.</div>
