INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9599,'dus3','김선기','spsp99@naver.com','중부경찰서와함께하는안보현장탐방(2013.06.18)','<p>중부경찰서 후원으로 남산원 중학생 아동들이 사이버테러 방지교육과 제3땅굴을 직접 탐방하여 제3땅굴 견학을 다녀 왔습니다.아동들에게 안보의식 함양과 나라 사랑하는 마음을 심어 줄수 있는 귀한 시간 이었습니다.남산원 아동들을 위해 귀한 안보교육견학 프로그램을 준비해 주신 중부경찰서 서장님과 보안계 직원 여러분들께 진심으로 감사 드립니다.</p>          </td>
        </tr>',928,1371567600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9600,'dus3','김선기','spsp99@naver.com','다윗*석,*진 룻2*희,*진 미술전시회 관람(2013.06.14)','<p>남산교회 성도님의 후원으로 다윗방 *석이와 *진이 룻2방 *희와 *진이가&nbsp;강남구 대치동에 있는 미술관에 가서 미술전시회를 관람 하고 왔습니다.</p>
<p>귀한 자리에 초대해 주셔서 미술전시회를 관람 할수 있게 도와 주신 남산교회 성도님께 진심으로 감사를 드립니다.</p>          </td>
        </tr>',997,1371135600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9598,'dus3','심주현','pikaccu85@hanmail.net','바울 순천만 국제 정원 박람회 다녀온날!(2013.06.20)','오늘 &nbsp;코레일에서 주최하는 해피트레인&nbsp;
<div>순천만 국제정원 박람회에 다녀왔습니다!</div>
