INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9606,'dus3','심주현','pikaccu85@hanmail.net','*결이 북토큰카드 도서 구입!!(2013.06.09)','<p align="center">*결이가 학급에서 우수학생으로 받은 북토큰카드로 </p>
