INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9605,'dus3','박진성','js2227@hanmail.net','바울방 월요일 청소시간!!(2013.06.10)','초등하쿄3-6학년 형들이 msc수업을 하는 동안 &nbsp;선생님을 도와 열심히 청소하는 초등학교 1학년 최남명군과 초등학교 2학년 손<span style="text-align: -webkit-center">*</span>민군이예요~~!!!

<div>고사리손으로 선생님과 함께 바울방을 깨끗하게 청소하는 아이들의 손길이 참으로 예쁩니다!!!!</div>
