INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9607,'dus3','심주현','pikaccu85@hanmail.net','바울방의 신나는 물놀이 시간!!(2013.06.09)','<p align="center">오늘은 33도나 올라가는 무더운 날씨입니다.ㅠㅠ</p>
<p align="center">운동장에&nbsp;스프링쿨러를 이용해서 바울방의 물놀이를 시작 하였는데요 ^^</p>
<p align="center">스프링쿨러 하나만으로도 아이들은 시원한 물놀이를&nbsp; 즐길수 있었습니다!!</p>
<p align="center">우리 아이들은 역시 잘 즐기는 아이들이랍니다 ㅎㅎ</p>
<p align="center">오늘은 다른것 보다도 물 하나만으로 </p>
<p align="center">무더위를 싹~&nbsp; 날려버리는 하루였답니다 ^-^*</p>
<p align="center">앞으로도 아이들이 더욱 건강한 아동기를 보낼 수 있도록 지원하겠습니다!!</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',912,1370703600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9609,'dus3','송명은','happysme@hanmail.net','룻2방이 시원한 물놀이를 하였습니다.(2013.06.08)','무더운 여름이 일찍 다가와서인지 바깥놀이를 하기에도 너무나 더운 날씨로 인해서 룻2방의 아이들은 방에서만 시간을 보내고 있었습니다. 하지만 몇일전 운동장에 설치된 스프링쿨러를 이용해서 룻2방의 깜찍한 아이들은 물놀이를 하기 시작했답니다. 스프링쿨러 하나만으로는 부족했는지 플라스틱통으로 물총을 만들어 더욱 시원하고 즐거운 물놀이를 했습니다.
<div>시원한 물놀이를 마무리하고 더 시원한 아이스크림을 먹으면서 흐뭇해하는 우리 룻2방~~너무 사랑스러웠답니다. 앞으로도 우리 룻2방 아이들이 무더운 여름을 잘 이겨낼 수 있도록 여러가지 방법을 동원해서 열심히 보육하겠습니다.^^</div>          </td>
        </tr>',968,1370617200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9608,'dus3','심주현','pikaccu85@hanmail.net','남*이는 착한어린이!!(2013.06.09)','<p align="center">오늘 아침 남*이가 선생님을 돕겠다며 </p>
<p align="center">걸레를 들고 현관앞을 나와 청소를 합니다 ^-^*</p>
<p align="center">아직 남*이는 청소 구역이 없어 청소 시간에 </p>
<p align="center">미취학 어린이들과 함께 방에 앉아 책읽기 활동을 하고 있는데요!!</p>
<p align="center">오늘은 선생님을 돕겠다며 열심히 청소를 하는 </p>
<p align="center">모습입니다!! ^-^*</p>
<p align="center">늘 밝은 미소로 바울방에게 웃음을 주는 남명군!!</p>
<p align="center">&nbsp;참 잘했어요!!!! </p>
<p align="center">남*이!!&nbsp; 최고!!&nbsp; </p>
<p align="center">^O^/</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',928,1370703600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9610,'dus3','송명은','happysme@hanmail.net','룻2방이 환일고등학교의 오빠들과 함께 제습제를 만들었습니다.(2013.06.08)','룻2방의 초등학생과 환일고등학교 망치동아리 오빠들이 함께 제습제를 만들었습니다. 처음엔 직접 만들어야하는 제습제가 무엇인지도 잘 몰랐지만 친절하게 설명해주시는 환일고 어머니분들과 함께 제습제 만들기를 도와주는 오빠들 덕분에 제습제가 어떻게 사용되는지 알게 되었습니다. 올 여름에는 우리 아이들이 직접 만든 제습제 덕분에 뽀송뽀송한 여름을 보낼 수 있을 것 같습니다. 아이들에게 새로운 경험을 통해서 유익한 시간을 갖게 해주셔서 감사드립니다.          </td>
        </tr>',907,1370617200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9612,'dus3','심주현','pikaccu85@hanmail.net','바울방 바깥놀이 활동시간!!(2013.06.08)','<p align="center">오늘 환일고 망치 동아리 형들과 함께 </p>
<p align="center">운동장에서 축구경기를 하였습니다. </p>
<p align="center">형들과 함께 하는 경기는 매번 즐겁답니다. </p>
<p align="center">아이들이 형들과 하는 경기에서는 눈빛부터가 너무 초롱초롱 합니다 ^^</p>
<p align="center">날씨가 무더운데도 아이들의 지칠줄 모르는 체력은 역시 최고!!</p>
<p align="center">날씨가 더워도 아이들에겐 역시</p>
<p align="center">&nbsp;바깥놀이가 제일 즐거운 장소네요 ^-^*</p>
<p align="center">&nbsp;</p>
<p align="center">오늘도 바울방은&nbsp; 맑음 ^-^*</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',1838,1370617200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9613,'dus3','심주현','pikaccu85@hanmail.net','환일고 형들과 함께 제습제만들기!!(2013.06.08)','<p align="center">오늘 환일고 망치동아리 형, 오빠들과 함께 </p>
<p align="center">바울, 룻2 아동들이 제습제를 만들었습니다. </p>
<p align="center">물먹는 하마 플라스틱 통을 재활용하여 염화칼슘제를 넣고 </p>
<p align="center">이쁘게 자신만의 개성에 맞춰 통을 꾸미면 완성!!</p>
<p align="center">우리 옷장에 제습제가 꼭 필요한데요 ^^</p>
<p align="center">환일고 망치동아리 형들과 함께 만들어서 더욱 즐거운 시간이 되었던 것 같습니다 ^^</p>
<p align="center">욕심이 많은 우리 유치부 어린이들은 2~3통씩 만들었답니다 ㅋㅋㅋ</p>
<p align="center">오늘 좋은 만들기를 준비해 주신 </p>
<p align="center">환일고 망치동아리 봉사자분들께 진심으로 감사드립니다!!</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',915,1370617200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9611,'dus3','심주현','pikaccu85@hanmail.net','바울의 꿈 !!(2013.06.08)','<p>오늘은 바울방 친구들과 함께 </p>
<p>꿈에 대해 이야기 해 보는 시간을 가졌습니다. </p>
<p>미취학 부터 초등학교 5학년 까지 있는 바울방은&nbsp;</p>
<p>아이들이 꿈들로 가득한 공간인데요 ^-^*</p>
<p>오늘 그 꿈을 응원해 주고자&nbsp; 서로가 서로를 그려주고 </p>
<p>도와주고 꿈의 이야기를 주고 받는 시간을 가졌습니다. </p>
<p>&nbsp;</p>
<p>영호의 꿈은 화가 입니다. 우리 영호는 그림그리기를 참 좋아합니다. </p>
<p>성진이의 꿈은 연예인 입니다. 보이시한 목소리가 아주 매력적인 친구이지요. 학교에서도 인기가 아주 많은 친구랍니다 ^^</p>
<p>민혁, 호준, 남명이는 야구선수입니다. 야구프로를 볼 만큼 야구에 대해 아주 관심이 많은 친구들 이랍니다.&nbsp; </p>
<p>&nbsp;</p>
<p>이렇듯 오늘도 바울방은 아이들의 꿈으로 가득한 하루가 되었습니다. </p>
<p>오늘 우리 바울이는 &nbsp;큰 무대위, 전시장, 경기장 가운데에 우뚝 설 자신의 미래를 꿈꾸겠죠?</p>
<p>우리 아이들이 큰 꿈을 꾸며 성장할수 있도록 같이 응원해 주세요!! ^-^*</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',902,1370617200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9614,'dus3','박현정','kingi109@naver.com','한나방 선*, 강*미 아동이 아르바이트 참여(2013.06.08)','<p align="center">한나방 고2 선* 아동이 아르바이트를 시작하였습니다^^</p>
<p align="center">서빙 아르바이트를 시작한 아동은 전부터 아르바이트 활동을 해오다가, 최근에 댄스대회연습으로 참여하지 못하고, 8일(토) 아르바이트를 시작하게 되었습니다!</p>
<p align="center">학교생활도 열심히 하는 *이가 아르바이트 활동도 성실히 임해주길 바라며, </p>
<p align="center">선*이를 응원해주세요~!</p>
<p align="center">고3 강*미 아동도 아르바이트 활동을 시작할 예정인데요~</p>
<p align="center">세*도 아르바이트를 오랜만에 시작하게 되어, 많이 격려를 해주었습니다.</p>
<p align="center">15일(토) 부터 패스트푸드 가게에서 일할 세*에게 많은 응원부탁드립니다~!!</p>
<p align="center">&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',852,1370617200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9615,'dus3','박진성','js2227@hanmail.net','바울방의 즐거운 활동(2013.06.07)','남산초등학교 자율휴업일로 오랜만에 쉬면서 원내활동을 하였어요^^
<div>아동들이 좋아하는 wii게임도하고..</div>
<div>오후에 &nbsp;운동장에서 자전거를 타며 놀다가 스프링쿨러에서 나오는 물로 신나게 몸을 적셨어요~~~^^*</div>
<div>오랜만에 물장난도 &nbsp;하고..</div>
<div>즐거운 시간을 보냈습니다~~~~♥♥♥</div>          </td>
        </tr>',892,1370617200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9616,'dus3','박현정','kingi109@naver.com','한나방 선진아동이 수련회에 다녀왔습니다(2013.06.07)','<p>2013.06.03~2013.06.05 까지 2박3일간 수련회에 다녀왔습니다!</p>
<p>날이 더워, 조금 고생했다고 하지만, 친구들 선생님과의 소중한 추억을 쌓았다고 합니다^^</p>
<p>춤을 좋아하는 진이는 역시, 장기자랑에 참여하여 멋진 춤솜씨도 뽑냈다고 합니다!</p>
<p>진이는 댄스대회에 참여할 만큼이나 멋진 춤솜씨를 갖고 있는데요~^^</p>
<p>자신이 좋아하는 일을 할때가 가장 행복하다고 말하는 우리 진이에게 격려를 보내주세요~!!</p>          </td>
        </tr>',872,1370530800,'', '', '', '', '', '');
