INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9618,'dus3','심주현','pikaccu85@hanmail.net','남산초등학교 담임교사 초청의날!!(2013.06.05)','<p align="center">2013.06.05 남산초등학교 담임선생님 초청의날입니다!!</p>
<p align="center">남산 초등학교 선생님들께서는 </p>
<p align="center">변함없이 저희 남산원 아이들에게 많은 사랑과 관심으로 </p>
<p align="center">학교에서 잘 지도해 주시고 계시는데요 ^^</p>
<p align="center">오늘은 고마우신 선생님들을 저희집으로 초청하여 원장님 국장님과 함께 </p>
<p align="center">아이들에 관한 이야기를 나누며 아이들 환경을 둘러보고 </p>
<p align="center">어떻게 생활하는지 상담하는 시간을 가졌답니다~!!</p>
<p align="center">오늘 선생님들과 아이들과 함께 즐겁게 간식을 먹으며 이야기를 나눌수 있어 </p>
<p align="center">더욱 유익했던 것 같습니다. </p>
<p align="center">늘 저희 아이들에게 많은 관심과 사랑을 나눠 주시는 </p>
<p align="center">남산초등학교 선생님들께 진심으로 감사드립니다.(^^)(__)(^^)</p>
<p align="center">앞으로도 저희 아이들에게 큰 가르침 부탁드립니다 ^-^*</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',892,1370444400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9622,'dus3','심주현','pikaccu85@hanmail.net','바울방의 깜짝 선물!!(2013.06.02)','<p align="center">오늘 이지혜 봉사자님께서 귀여운 도너츠를 가지고 </p>
<p align="center">바울방을 방문해 주셨습니다. </p>
<p align="center">작년 바자회때 바울방 아동들을 지원해 주셨는데요 ^^</p>
<p align="center">아동들이 보고 싶어 맛있는 간식을 가지고 </p>
<p align="center">다시 방문해 주셨답니다 ^^</p>
<p align="center">아이들에게 큰 사랑을 나눠 주셔서 </p>
<p align="center">대단히 감사합니다 ^-^**</p>          </td>
        </tr>',916,1370098800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9620,'dus3','이소영','leesy5576@hanmail.net','2013. 6. 4 룻2방 손*진, 오*별 중구광장소식지 사진입니다.','<font face="굴림">룻2방 오*별, 손*진의 어린이집 남경수목원 체험학습사진이 6월 중구광장신문에 올라왔습니다.&nbsp;</font>
<div><font face="굴림">무더워진 날씨에도&nbsp;*별이&nbsp;*진이가 건강하게 자랄 수 있도록 외부활동 열심히 지원하도록 하겠습니다.</font></div>
<div><font face="굴림">　</font></div>
<div><font face="굴림">　</font></div>
<div><div style="font-family: 굴림">　</div></div>          </td>
