INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9621,'dus3','송명은','happysme@hanmail.net','덕수중학교로 학부모상담을 다녀왔습니다.(2013.06.03)','룻2방의 중학생들이 다니고 있는 덕수중학교로 학부모상담을 다녀왔습니다. 담임선생님들과의 상담시간을 미리 알고 있었던 아이들은 상담시간이 다가올수록 마음이 설레였다고 하였답니다. 룻2방에서 4명의 아동들을 지도해주시는 담임선생님들과의 상담시간은 아이들을 보육하고 있는 저에게도 개인적으로 너무나 유익한 시간이 되었고 우리 아이들의 단적인 면만 보시면서 판단하셨던 담임선생님들에게도 아이들을 조금 더 깊이 이해할 수 있는 의미있는 시간이 되었습니다. 한명 한명 상담을 하면서 담임선생님들께 여러가지 많은 이야기들을 듣게 되고 고민도 하고 뿌듯하기도 했던 시간이었습니다. 선생님들께서는 우리 아이들에게 남다른 애정을 가지고 계셨고 특히 올해 중3이 된 유진이의 진로에 대한 조언을 해주셔서 많이 걱정하던 저에게 도움이 되었습니다.<div>우리 아이들의 학습적인 부분에서만이 아니라 미래에 대한 많은 조언들도 해주시는 덕수중학교 선생님들께 다시한번 감사의 인사를 드립니다.^^</div>          </td>
        </tr>',926,1370185200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9625,'dus3','송명은','happysme@hanmail.net','룻2방의 초등학생을 소개합니다.(2013-05-31)','남산원을 대표하는 마스코트~^^

<div>꽃보다 예쁜 룻2방의 초등학생을 소개합니다.</div>
<div>학교에 등교하기 전에 너무나 좋은 날씨와 신선한 공기를 맡으며 룻2방의 초등학생들이 예쁜 포즈를 선보였습니다. 올해 신입생이 된&nbsp;*민이는 받아쓰기의 달인이라고 할 정도의 뛰어난 실력을 보여주고 있답니다.^^</div>
<div>모든일에 변함없이 언제나 성실하게 노력하는 귀여운&nbsp;*영이는 학교에서도 많은 친구들에게 인기가 많습니다.^^</div>
<div>귀여운 새침떼기인&nbsp;*연이는 공부면 공부, 춤이면 춤, 그림이면 그림~못하는 것이 없는 만능재주꾼이랍니다.^^</div>
<div>엉뚱하지만 알고보면 진지하고 속이 깊은 우리&nbsp;*민이는 성숙한 매력이 있답니다.^^</div>
<div>이렇게 각각의 다른 매력이 있는 아이들이지만 서로가 서로를 챙겨주고 배려하는 마음이 너무나 예쁜 사랑스러운 초등학생이랍니다. 앞으로 우리 아이들이 더 넓고 깊은 마음으로 주위사람들에게 인정받고 사랑받는 아동으로 성장할 수 있도록 보육하겠습니다.^^</div>          </td>
        </tr>',887,1370012400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9624,'dus3','김선기','spsp99@naver.com','다윗방 아동들 남산산책(2013.06.01)','<p>토요일 아침 아동들 조회를 마치고 다윗방 아동들과 다윗방 선생님과 원장님과 함께 남산을 산책 하였습니다.상쾌한 공기를 맞으며 기분 좋은 하루였습니다.^^</p>          </td>
        </tr>',909,1370012400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9623,'dus3','김선기','spsp99@naver.com','다윗방 이*울아동 생일파티(2013.06.01)','<p>다윗방에 멋쟁이 *울이가 오늘 생일을 맞이 하였습니다.다윗방 아동들 모두 *울이에 생일을 축하해 주고 축복해 주었습니다.</p>
<p>*울아 생일 진심으로 축하하고 더 밝고 착하게 자라 주렴 선생님이 늘 기도할께 *울아 사랑한다 다윗방 김선기선생님이.</p>          </td>
        </tr>',877,1370012400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9626,'dus3','심주현','pikaccu85@hanmail.net','바울방 남산 산책 입니다 ^^(2013.06.01)','<p align="center">화창한 토요일 아침 ^^</p>
