INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9628,'dus3','심주현','pikaccu85@hanmail.net','바울방 자습시간 입니다 ^^(2013.05.31)','<p align="center">평일 저녁 7시~8시까지 자습시간 입니다 ^^</p>
<p align="center">오늘 자습시간에 아이들이 열심히 하는 모습을 </p>
<p align="center">사진에 담아 보았는 데요 ^^</p>
<p align="center">자습시간에는 자율적으로 자신이 하고 싶은 공부를 할 수 있도록 </p>
<p align="center">지원하고 있습니다. </p>
