INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9627,'dus3','박진성','js2227@hanmail.net','바울방 미취학아이들의 주말(2013.06.01)','<p align="center">초등학교에 다니는 형들이 학교에 간 사이</p>
<p align="center">&nbsp;어린이집에 다니는 아이들이 너무나 신나는 운동장 놀이를 하였습니다~!!</p>
<p align="center">즐겁게 놀이터에서 미끄럼도 타고,</p>
