INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9629,'dus3','이소영','leesy5576@hanmail.net','룻2방, 5월 환경심사 1등 저녁식사 사진입니다.','5월 환경심사에서 1등을 하여 룻2방이 저녁식사를 하였습니다.
<div>평소 각자 맡은 구역을 성실하게 청소를 하여 깨끗한 환경을 만들고 있습니다. 6월달 환경심사에도 열심히 준비하여 쾌적한 생활을 할 수 있도록 지도하겠습니다.</div>
