INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9631,'dus3','심주현','pikaccu85@hanmail.net','바울방 63시티 다녀온날!!(2013.05.29)','<p align="center">오늘 바울방이 63시티에 다녀왔습니다 ^^</p>
<p align="center">사랑의 열매 지원으로 63시티 </p>
<p align="center">씨월드, 전망대 미술관, 왁스 뮤지엄을 관람하고 왔는데요 ^^</p>
<p align="center">영호는 물고기를 엄청 좋아하여 보는 내내 웃음이 멈추질 않았고</p>
<p align="center">고학년 아이들에게는 &nbsp;왁스 뮤지엄이 너무 즐거운</p>
