INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9630,'dus3','박현정','kingi109@naver.com','한나방 혜*이가 수술비 지원을 받게되었습니다(2013.05.30)','<p align="center">&nbsp;한나방 중3 혜*이가 부정맥으로 삼성서울병원에서 8월 15일 수술을 받을 예정이였습니다.</p>
<p align="center">&nbsp;혜*이의 수술비 마련이 가장 걱정이 되는 부분이였지만, 삼성서울병원 사회복지팀 선생님</p>
<p align="center">&nbsp;들께서 혜*이의 상황을 많이 걱정하시어, 한국심장재단에 지원요청을 하였고, 5월 28일 한</p>
<p align="center">&nbsp;국심장재단에서 혜*이에게 적극지원 해주시겠다는 연락을 해주셨습니다! 수술 후에는 혜*</p>
<p align="center">&nbsp;이가 더 건강해졌으면 좋겠습니다~! 모두 혜*이를 응원해주세요~^^</p>          </td>
        </tr>',959,1369839600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9633,'dus3','남산원','jblee4@naver.com','다윗방 김* 두산 장학금 수령','다윗방 김* 아동이 두산의 후원으로 장학금을 받고 에버랜드에도 다녀왔습니다. 선물까지 한아름 받아온 *이의 표정이 너무나 행복해보이네요.^~^          </td>
        </tr>',934,1369753200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9634,'dus3','심경숙','wdcyj1011@naver.com','환일중 김*석,오*진 아동 하복 구매','<p align="center">환일중 1학년에 재학중인 김*석,오*진 아동이 하복을 구매하였습니다.</p>
<p align="center">하복 구매가 즐겁고 신나는 일인지 미소를 머금는 두아동의</p>
<p align="center">미소가 보기 좋습니다.</p>          </td>
        </tr>',1059,1369666800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9632,'dus3','심주현','pikaccu85@hanmail.net','바울방 *민, *슬 두산 후원자님과의 에버랜드 나들이 다녀온날!(2013.05.29)','<p align="center">바울방&nbsp;&nbsp;*민이와 *슬이가 오늘 두산의 후원자님과 에버랜드에 &nbsp;다녀왔습니다. </p>
<p align="center">남산 초등학교에서 두산후원자님께 장학금도 받고 함께 에버랜드도 가게 되었는데요 ^^</p>
<p align="center">선물도 한아름 주셔서 아동들이 매우 즐거운 날이 되었답니다 ^-^*</p>
