INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9637,'dus3','심주현','pikaccu85@hanmail.net','바울방 남산 산책을 다녀왔습니다^^(2013.05.25)','<p align="center">지난 주말 토요일 아침 바울방이 남산 산책을 다녀왔습니다 ^^</p>
