INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9636,'dus3','박현정','kingi109@naver.com','한나방 진이가 상장을 받았습니다(2013.05.15)','<p align="center">&nbsp;2013.05.15 대경고에 다니는 고2 선진이가 학교에서 선행상을 받았습니다~!</p>
<p align="center">&nbsp;요즘, 학교생활을 하느라 많이 피곤했을텐데도! 원내생활에도 충실히 하려 노력하는 진이가</p>
<p align="center">&nbsp;대견스럽습니다. 학교생활에도 모범이 되는 진이를 보면서,&nbsp;다른 아동들도&nbsp;본받아 생활할 수 </p>
<p align="center">&nbsp;있었으면 좋겠습니다~!&nbsp;열심히&nbsp;학교생활 하는 진이를&nbsp;응원해주세요~!&nbsp;</p>          </td>
        </tr>',966,1369580400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9638,'dus3','이소영','leesy5576@hanmail.net','2013. 5. 26 룻2방, 바깥놀이 활동사진입니다.','<font face="굴림">2013년 5월 26일 주말 오후 룻2방 미취학, 초등학생 아이들이 운동장에서 자전거를 타며 자유시간을 보냈습니다.</font>
<div><font face="굴림">무더운 날씨에 멀리 나가지는 못하였지만 남산 운동장에서 자전거시합도 하고 이야기도 많이 나누며 자유시간을 보냈습니다.</font></div>
<div><font face="굴림">더운날씨에도 적절한 운동시간을 통해 아이들이 건강하고 밝게 성장할 수 있도록 보육하겠습니다.</font></div>
<div><font face="굴림">　</font></div>
<div><font face="굴림">　</font></div>
<div><div style="font-family: 굴림">　　</div>
<div style="font-family: 굴림">　</div>
<div style="font-family: 굴림">　</div></div>          </td>
        </tr>',926,1369494000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9639,'dus3','이소영','leesy5576@hanmail.net','2013. 5. 26 룻2방, 김*희, 김*진 남산교회 후원사진입니다.','2013년 5월 26일 남산교회에서&nbsp;<span style="text-align: -webkit-center">*</span>희,&nbsp;<span style="text-align: -webkit-center">*</span>진이에게 옷을 선물해주셨습니다.

<div>초여름 이쁘게 입을 수 있어&nbsp;<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">희와&nbsp;</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진이가 매우 마음에 들어하였습니다.</span></div>
<div>항상&nbsp;<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">희와&nbsp;</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진이를 사랑으로 지켜봐주셔서 감사드립니다.^^</span></div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',994,1369494000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9640,'dus3','심주현','pikaccu85@hanmail.net','하나은행 후원자님과 즐거운 외출!!(2013.05.25)','<p align="center">오늘 하나은행 후원자님과 남산타워에 케이블카를 타고 다녀왔습니다 ^^</p>
<p align="center">남산타워에서 아디다스에서 개최하는 클라이밍 대회를 하고 있었는데요 </p>
<p align="center">시민들도 체험할 수 있는 곳이 있어 우리 아동들도 모두 </p>
<p align="center">한번씩 클라이밍을 체험해 볼 수 있는 시간을 가졌습니다. </p>
<p align="center"><span style="font-size: 9pt; line-height: 1.5">*</span>민이는 너무 잘해서 커서 직업군인을 해도 되겠다는 칭찬까지 받았는데요 ^^*</p>
<p align="center">아이들이 승부욕이 있어 엄청 적극적으로 잘&nbsp;했답니다 ^^</p>
<p align="center">후원자님께서 아동들을 위해 비눗방울도 준비해 주셔서 </p>
<p align="center">비눗방울 놀이도 하는등 오늘 엄청 즐겁게 활동했습니다. </p>
<p align="center">점심으로는 &nbsp;맛있는 돈까스도 먹고 돌아왔습니다. </p>
<p align="center">아이들에게 밝은 미소로&nbsp; 함께해 주신 하나은행 후원자 분들께 진심으로 감사드립니다!!</p>
<p align="center">(^^)(__)(^^)</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',953,1369407600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9643,'dus3','송명은','happysme@hanmail.net','룻2방의 *희,*선이가 예쁜 수세미를 만들었습니다.(2013.05.24)','덕수중학교에 입학하고 즐거운 학교생활을 하고 있는 룻2방의&nbsp;<span style="text-align: -webkit-center">*</span>희,<span style="text-align: -webkit-center">*</span>선이는 한달에 한번 목요일마다 동아리활동을 하고 있습니다. 올해는 어떤 동아리에 참여할까 고민하다가 손뜨개반에 참여하게 되었습니다. 손뜨개반에서 배운 실력으로 예쁜 수세미를 만들어왔답니다. 항상 철없는 아이들로만 봤었는데 이렇게 예쁜 수세미를 만들어오는 모습을 보니 기특하였습니다. 동아리시간에 만든 것이 모자랐는지 남은 실을 가져와서는 여러가지 모양의 수세미를 만들느라 바쁜 하루를 보냈습니다. 앞으로도 우리 아이들이 가지고 있는 소질을 잘 발휘할 수 있는 환경을 만들어서 좀 더 자존감이 높은 아동으로 성장할 수 있도록 보육하겠습니다.^^          </td>
        </tr>',1008,1369321200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9641,'dus3','송명은','happysme@hanmail.net','룻2방이 남산산책을 다녀왔습니다.(2013.05.25)','학교에 가지 않는 토요일 아침에 룻2방 가족모두가 함께 남산으로 산책을 다녀왔습니다. 막내인&nbsp;<span style="text-align: -webkit-center">*</span>별이와&nbsp;<span style="text-align: -webkit-center">*</span>진이도 함께 다녀왔는데 힘들어하지도 않고 너무나 즐거운 마음으로 다녀왔습니다. 아침 이른시간이었는데도 남산에 산책을 나온 사람들이 많았습니다. 우리 아이들도 그 사람들처럼 언제나 부지런하고 성실한 아동으로 성장할 수 있도록 보육하겠습니다.          </td>
        </tr>',976,1369407600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9642,'dus3','송명은','happysme@hanmail.net','룻2방의 *리와 *진이가 덕수중학교 과학의 달 행사에서 입상을 하였습니다.(2013.05.25)','룻2방의 *리와 *진이가 덕수중학교에서 과학의 달을 기념하기 위해 열린 그리기 대회에서 입상을 하였습니다.*리는 환경포스터 그리기 대회에서 은상을 받았고, *진이는 발명만화 그리기 대회에서 은상을 받았습니다.
<div>아이들의 수상소식을 들으신 원장님께서는 너무나 기특해하시면서 아이들에게 상품으로 문화상품권을 주셨습니다. 아직은 어리지만 너무나 많은 가능성과 재주가 많은 우리 아이들이 지금 갖고 있는 귀한 달란트를 잘 키워나갈 수 있도록 열심히 보육하겠습니다.</div>          </td>
        </tr>',981,1369407600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9645,'dus3','이소영','leesy5576@hanmail.net','룻2방, 손*영, 김*연 남산초등학교 요리프로그램활동','2013년 2월 23일 서울특별시 중부교육지원청 지역기반형 사업 협력기관인 대한식문화연구원, 미각조리교육 프로그램에 참여하여 요리경연대회를 하였습니다.

<div>프로그램이 끝난 뒤 활동내용과 사진을 책으로 만들어 학교에서 나누어 주었습니다.&nbsp;</div>
<div>*영이와 *연이가 많은 프로그램에 참여하여 적성을 빨리 찾아 발전할 수 있도록 지원하겠습니다.</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>
<div>　</div>          </td>
        </tr>',1010,1369148400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9644,'dus3','심주현','pikaccu85@hanmail.net','바울방 방모임 시간입니다 ^^(2013.05.23)','<p align="center">오늘&nbsp; 바울방 방모임 시간에는 새로운 원내 생활 아동 벌점 규정에 대해</p>
<p align="center">이야기 나누기를 하였습니다. </p>
<p align="center">아직 미취학, 초등학생이라 원내생활 규정에 어긋나는 일들이 많이 해당되지는</p>
<p align="center">않지만 아동들이 생활규칙을 몸에 잘 익히고 배워 건강하게 성장하여 </p>
<p align="center">다윗방 모세방에 가서도 모범적인 생활을 할 수 있도록&nbsp; 지원하겠습니다. </p>
<p align="center">^-^*</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',958,1369234800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9646,'dus3','이소영','leesy5576@hanmail.net','룻2방, 김*선 생일선물사진입니다.','2013년 5월 19일 *선이를 오랫동안 지도해주시고 후원해주신 &nbsp;호문애선생님과 외출을 다녀왔습니다.
<div>&nbsp;뒤늦게 *선이의 생일을 축하해 주는 것을 미안해 하시며 티셔츠와 신발, 책들을 선물로 사주시며 진심으로 생일을 축하해주셨습니다.

<div>*선이에게 특별한 관심과 사랑주셔서 감사드립니다. 앞으로 *선이가 건강하고 밝게 성장할 수 있도록 보육하겠습니다.</div>
<div><br /></div></div>          </td>
        </tr>',983,1369148400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9649,'dus3','심주현','pikaccu85@hanmail.net','바울방이 *리의 첫 돌을 축하합니다!!(2013.05.21)','<p align="center">오늘은 룻방의 귀염둥이 *리의 첫돌 이 있는날입니다. </p>
<p align="center">저녁식사 후 남산원 가족들 모두 강당에 모여 </p>
<p align="center">*리의 첫 돌을 진심으로 축하해 주었습니다!!</p>
<p align="center">오늘 *리는 이쁜 공주님으로 나타났는데요 ^^</p>
<p align="center">늘 지금처럼 이쁜고 건강한 모습으로 성장하길 </p>
<p align="center">바울방 멋진 오빠들이 소원합니다!</p>
<p align="center">*리의 첫 돌을 진심으로 추카추카!! </p>
<p align="center">^-^/</p>          </td>
        </tr>',961,1369062000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9648,'dus3','이소영','leesy5576@hanmail.net','룻2방 손*영, 서울침례교회 생일선물 전달사진입니다.','2013년 5월 19일 서울침례교회에서 5월 생일인 *영이를 위해 생일파티를 해주셨습니다.&nbsp;

<div>초등부 다함께 맛있는 음식을 먹으며 *영이의 생일을 진심으로 축하해 주었습니다. 선생님께서는 책과 케익도 선물로 주셨습니다.&nbsp;</div>
<div>앞으로도 *영이가 건강하게 자랄 수 있도록 보육하겠습니다.&nbsp;</div>          </td>
        </tr>',1058,1369148400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9647,'dus3','이소영','leesy5576@hanmail.net','룻2방, 김유진 어린이날 선물사진입니다.','매주 일요일 유진이의 영어학습지도를 맡아주고 계신 김수현 선생님께서 5월 19일 머리끈을 선물해주셨습니다. 어린이날 선물을 못해주셨다며 앞으로 성적을 올릴 수 있도록 노력하자며 선물하셨습니다.
<div>항상 관심과 사랑으로 유진이를 지도해주셔서 감사드립니다.^^</div>
<div><br /></div>          </td>
        </tr>',1007,1369148400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9651,'dus3','박진성','js2227@hanmail.net','백민혁. 백호준 후원자님의 특별한  선물^^(2013.05.19)','<p>일요일 오전 차민영 후원자님의 감사한 방문이 있었습니다.</p>
<p>아동들과 함께 외출을 하여 롯데월드에도 다녀오시고 아동의 생일선물로 옷을 한벌씩 구입해주었습니다.</p>
<p>아동들이 만족해 하는 모습이 너무 좋아보였습니다.</p>
<p>후원자님 감사합니다^^</p>          </td>
        </tr>',961,1368975600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9650,'dus3','이소영','leesy5576@hanmail.net','룻2방, 덕수중학교 전일제봉사활동 다녀왔습니다.(2013. 5. 21)','<font face="굴림">2013년 5월 21일 덕수중학교 전일제봉사활동으로 현충원 유품전시관에 다녀왔습니다.</font>
<div><font face="굴림">일정중 영화관람이 취소되었지만 날씨가 좋아 봉사활동을 하는 보람도 느끼고 전시관 관람도 하고 돌아왔습니다.</font></div>
<div><font face="굴림">앞으로도 아이들이 학교생활을 잘 할 수 있도록 지원하겠습니다.&nbsp;</font></div>
<div><font face="굴림"><br /></font></div>
<div><font face="굴림">&nbsp;</font></div>          </td>
        </tr>',971,1369062000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9652,'dus3','박진성','js2227@hanmail.net','필동감리교회 아동부 야외예배(2013. 05. 19)','<p>필동감리교회 아동부 아동들이 임진각으로 야외예배를 갔습니다.</p>
<p>우리나라 분단의 아픔을 작게나마 느끼며 안타까워 하는 아동들의 모습에 역사를 바르게 알려주며 아동들이 나라사랑하는 마음을 기르고 돌아왔습니다.</p>
<p>야외예배도 드리고 음식을 나누며 하나가 되는 귀한 기도의 시간을 갖고 돌아왔습니다.</p>
<p>아동들이 하나하나 배우며 마음밭에 새길 수 있는 귀한 시간이 되었길 기도해봅니다.^^</p>          </td>
        </tr>',1239,1368889200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9655,'dus3','심주현','pikaccu85@hanmail.net','바울방 윤선희 실습선생님의 쿠키선물!!(2013.05.18)','<p align="center">얼마전 바울방에서 실습을 하셨던 윤선희 선생님께서 깜짝 방문을 하셨습니다 ^^</p>
<p align="center">바울방 아이들을 위해 맛있는 쿠키를 선물로 주셨는데요!!</p>
<p align="center">저녁에 거실에서 즐거운 간식시간을 가졌답니다 ^-^*</p>
<p align="center">바울방 아이들에게 늘 아낌없는 사랑을 나눠주시는 윤선희 실습선생님께 </p>
