        </tr>',2002,1368802800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9653,'dus3','이소영','leesy5576@hanmail.net','룻2방, 김*선아동 고모님 방문, 선물전달사진입니다.','2013년 5월 19일 김*선 아동 고모님이 방문하셨습니다.

<div>*선이의 생일을 맞이하여 아이들과 함께 나누어 먹을 간식도 사주시고 *선이의 생일을 축하해주고 가셨습니다.&nbsp;</div>
