INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9654,'dus3','남산원','jblee4@naver.com','5월 18일 아침 남산산책','5월 18일 아침, 원장님과 함께 모든 원생들이 남산산책을 다녀왔습니다.          </td>
