INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9657,'dus3','송명은','happysme@hanmail.net','룻2방의 *영,*연,*선이가 첼로연주회를 다녀왔습니다.(2013.05.18)','일주일에 한번 토요일마다 룻2방의 예쁜 *영,*연,*선이에게 첼로수업을 지도해주시는 애드리안선생님께서 오늘 직접 출연하시는 연주회에 우리 아이들을 초대해주셨답니다. 항상 아이들에게 첼로를 가르쳐주시던 모습만 보았던 애드리안선생님이 예쁜 드레스를 입고 아름다운 모습으로 첼로연주를 하시는 모습에 아이들 모두 넋을 잃고 관람하였답니다.

<div>항상 우리 남산원 아이들을 사랑해주시고 오늘은 이렇게 아름다운 연주회에 초대해주신 애드리안 선생님께 다시한번 감사드립니다.</div>
<div>아이들은 오늘 연주회를 마친 애드리안선생님께 감사편지와 카네이션을 전달하였습니다.</div>
<div>애드리안 선생님~감사합니다.^^</div>          </td>
        </tr>',928,1368802800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9658,'dus3','박현정','kingi109@naver.com','한나방 김*지 아동 수련회에 다녀왔습니다(2013.05.09)','<p align="center">&nbsp;</p>
<p align="center">&nbsp;한나방 김*지 아동이&nbsp;경기도 광주&nbsp;퇴촌으로 수련회를 다녀왔습니다.</p>
<p align="center">&nbsp;캠핑식으로 다녀온 수련회라, 많은 짐을 가지고 원을 출발하였습니다~!</p>
<p align="center">&nbsp;즐거운 마음으로 다녀온 민지는 또 다시 다녀오고 싶다고 이야기 하였고, 1박2일 수련회라,</p>
<p align="center">&nbsp;많이 아쉬웠다고 이야기 하였습니다. 내년이면, 고3이 되는 민지에겐</p>
<p align="center">&nbsp;마지막 여행이였지만, 좋은 추억이 되었습니다~! </p>          </td>
        </tr>',930,1368802800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9656,'dus3','박현정','kingi109@naver.com','한나방 아르바이트 아동을 소개합니다(2013.05.18)','<p align=center>&nbsp;한나방 민지와 세영이가 아르바이트 활동에 참여하고 있습니다.</p>
<p align=center>&nbsp;민지는 일주일에 1번 쉬고, 학교생활이 끝난 후에는 성실히 아르바이트 활동에 참여하고</p>
<p align=center>&nbsp;귀원합니다. 요즘 학교생활과 아르바이트 활동을 병행하느라, 피곤해보이는 아동을 많이</p>
<p align=center>&nbsp;격려해주고 있습니다! 열심히 참여하는 아동이 너무 대견하고 예쁩니다~^^</p>
<p align=center>&nbsp;고3 세영이도 학교생활이 끝나면 아르바이트 활동에 참여한 후에 귀원합니다. 세영이는 요</p>
<p align=center>&nbsp;즘 면접준비로 바쁜 하루를 보내고 있습니다. 6월달에는 영어회화 학원도 다니게 될 세영이</p>
<p align=center>&nbsp;를 옆에서 많이 격려하고 지원해주어야겠습니다~!^^ 많은 관심 부탁드리겠습니다~!!</p>          </td>
        </tr>',965,1368802800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9659,'dus3','심주현','pikaccu85@hanmail.net','바울방 아침 남산 산책 다녀온날!!(2013.05.18)','<p align="center">오늘 아침 남산원 가족 모두 남산 산책을 다녀왔습니다 ^^</p>
<p align="center">바울방 막내도 모두 다 함께 다녀왔는데요 ^^</p>
<p align="center">남산산책을 하며 꽃도 구경하고 맑은 공기도 마시며 </p>
<p align="center">즐겁게 다녀왔습니다. </p>
<p align="center">막내는 힘들어 하는 모습을 보여 모세방 형이 업어 주는 등 </p>
<p align="center">훈훈한 모습을 보여 더욱 즐거웠던 아침 산책이였습니다. </p>
<p align="center">아이들이 상쾌한 아침을 맞이하며 즐거운 아동기를 보낼수 있도록 </p>
<p align="center">지원하겠습니다 ^^♡</p>          </td>
        </tr>',940,1368802800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9660,'dus3','이소영','leesy5576@hanmail.net','룻2방, 한나방 아침남산산책사진입니다.(2013.5.18)','<p align="center">2013년 5월 18일 룻2방, 한나방 아침 원장님과&nbsp;남산 산책을 하며</p>
