<p align="center">함께 산책을 하며 이야기도 많이 할 수 있는 시간이 되었습니다.</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',914,1368802800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9661,'dus3','이소영','leesy5576@hanmail.net','룻2방, 바깥놀이활동 사진입니다.(2013. 5. 17)','<p align="center">2013년 5월 17일&nbsp;룻2방 바깥놀이 활동사진입니다.</p>
<p align="center">석가탄신일 연휴 등교하지 않아&nbsp;놀이터에서 자전거를 탔고</p>
