INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9663,'dus3','김성재','thunderdog9@naver.com','다윗방 이*늘 수련회 다녀왔습니다','<p align="left"><span style="font-size: 9pt; line-height: 1.5">다윗방 이*늘 아동이 5월 13일부터 2박 3일의 일정으로 양주에 있는 딱따구리수련원(</span><a href="http://www.ddkr.co.kr/" style="font-size: 9pt; line-height: 1.5" target="_blank">http://www.ddkr.co.kr/</a><span style="font-size: 9pt; line-height: 1.5">)으로 덕수중학교에서 주최하는 수련회를 다녀왔습니다.</span></p>
<p align="left">&nbsp;</p>
<p align="left">캠프파이어, 장기자랑, 서바이벌게임 등 재미있는 놀이도 했지만 정신력강화훈련은 매우 힘들었다고 합니다. 오랜만에 바깥 공기도 쐬며 급우들과의 우정도 더욱 돈독하게 다지는 시간이 되었기를 바라며 앞으로도 학교에서는 물론 원내에서도 바른 생활을 해나갈 수 있도록 지도하겠습니다.</p>          </td>
        </tr>',1064,1368716400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9662,'dus3','심주현','pikaccu85@hanmail.net','바울방의 즐거운 나들이!!(2013.05.17)','<p align="center">오늘 바울방과 다윗방 초등부 형들과 함께 나들이를 다녀왔습니다. </p>
<p align="center">공휴일을 맞아 명동에 나가 영화관람도 하고 맞있는 치킨과 햄버거도 먹고 </p>
<p align="center">그동안 모아놓은 문화상품권으로 영풍문고에 가서 사고싶은 </p>
<p align="center">책도 사는 시간을 가졌습니다 ^^ </p>
<p align="center">형들이 다윗방으로 가고 나서&nbsp; 오랜만에 함께한 나들이라&nbsp; </p>
<p align="center">더욱 즐거웠던 하루가 되었던 것 같습니다 ^^</p>
<p align="center">오늘 공휴일이라 명동거리에는 사람들이 무척 많았는데요 ^^;</p>
<p align="center">14명의 아이들이 서로 서로 손을 잡고&nbsp; 챙겨주며 걸어다니는 모습이 </p>
<p align="center">너무 기특하고 고마웠던 하루가 되었습니다^^</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',926,1368716400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9664,'dus3','박현정','kingi109@naver.com','한나방, 덕수중학교 수학여행(2013. 5.13~5. 15)다녀왔습니다.','<p align=center>&nbsp;</p>
<p align=center>한나방 혜연이가 5월 13일부터 15일까지 강원도 동해로 수학여행을 다녀왔습니다!!!!</p>
<p align=center>수학여행에 갈 기대를 잔뜩 안고! 원을 출발한 혜연이와 인사하면서,</p>
<p align=center>조심히 다녀올 것을 약속하고! 15일 무사히 귀원하였습니다.</p>
<p align=center>혜연이는 수학여행에서 있었던 일들을 이야기하면서, 즐거웠다며 또 가고 싶다고 이야기 하였습니다. 친구들과 친하게 지내며 학교생활도 적극적으로 해나가는 혜연이가</p>
<p align=center>너무도 대견스럽습니다. 날씨가 좋아 정말 즐거운 여행이였습니다~!!^^</p>          </td>
        </tr>',986,1368630000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9667,'dus3','이소영','leesy5576@hanmail.net','룻2방, 덕수중학교 수련회, 수학여행(2013. 5.13~5. 15)다녀왔습니다.','<p align="center">룻2방, 덕수중학교에 다니고 있는</p>
<p align="center">1학년 강<span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">리, 김</span><span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">희, 김</span><span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">선&nbsp;아동이 수련회를&nbsp;다녀왔고</span></p>
<p align="center">3학년 김유진 아동은&nbsp;수학여행을 다녀왔습니다.</p>
<p align="center">중학교에 입학하고 처음으로 다녀온 수련회에서 훈련이 힘들었지만</p>
<p align="center">친구들과 좋은 추억을 쌓고 올 수 있어서 좋았다고 말하였습니다.</p>
<p align="center">중학교 3학년인 유진이는 마지막 수학여행에서 기대치가 높았는지</p>
<p align="center">생각했던 것 보다 재미없었다며 아쉬워하였습니다.</p>
<p align="center">앞으로도 아이들이 학교생활을 더 잘할 수 있도록 지원하겠습니다.^^</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',1029,1368630000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9665,'dus3','송명은','happysme@hanmail.net','필동어린이집 누리반 선생님~감사합니다.(2013.05.15)','<p>남산원의 미취학 아동들이 오랫동안 다니고 있는 필동어린이집에서 이번에 봄소풍을 가게 되었습니다. 마침 봄소풍 가는 날이 스승의 날이라서 필동어린이집에서 제일 큰 언니,누나반인 누리반에서 생활하고 있는 룻2방의&nbsp;<span style="text-align: -webkit-center">*</span>별이와&nbsp;<span style="text-align: -webkit-center">*</span>진이를 사랑으로 지도해주시는 한은하선생님께 아이들이 직접 쓴 편지와 카네이션을 전달했습니다.</p>
<p>한은하선생님께서는 생각도 못한 특별한 선물에 너무나 기뻐하셨답니다.</p>
<p>남산원 미취학 아동들을 언제나 사랑으로 보살펴주시고 아이들의 마음을 이해해주시는 필동어린이집 원장님을 비롯해서 많은 선생님들께 진심으로 감사의 마음을 전달합니다.</p>
<p>필동어린이집 선생님~감사합니다.^^</p>          </td>
        </tr>',1104,1368630000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9666,'dus3','심경숙','wdcyj1011@naver.com','다윗방 이*늘 교복구입하였어요','<p align="center">2013년 02월 15일 신입소한 이<span style="text-align: -webkit-left">*</span>늘 아동이 교복을 구입하였습니다.</p>
