INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9669,'dus3','이소영','leesy5576@hanmail.net','룻2방 필동어린이집 남경수목원 봄소풍 사진입니다.','<p align="left">2013년 5월 15일&nbsp; 룻2방 오<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">별, 손</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진, 바</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">방 오</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">재, 박</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">호, 백</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">혁아동</span></p>
<p align="left">필동어린이집에서 경기도 장흥동 남경수목원으로 봄 소풍을 다녀왔습니다.</p>
<p align="left">난타체험, 방울토마토 화분 심기, 누에고치목걸이만들기, 바나나보트체험등을 하였고</p>
<p align="left">아이들 모두 무더운 날씨에도&nbsp;사고 없이&nbsp;재미있게 잘 다녀왔습니다.^^</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',1054,1368630000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9668,'dus3','이소영','leesy5576@hanmail.net','덕수중학교 1학년 강*리 하복구입하였습니다.','<p>룻2방, 덕수중학교 1학년 강*리 하복구입하였습니다.</p>
<p>중학교에 입학하여 무더운 날씨에 곧 입게 될 하복이 정말 잘 어울렸습니다.</p>
