INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9673,'dus3','심주현','pikaccu85@hanmail.net','*균이가 이민진 선생님께 받은 어린이날 선물!!(2013.05.14)','<p align="center">&nbsp;</p>
<p align="center">늘 *균이를 많이 생각해 주시고 아껴주시는 </p>
<p align="center">이민진 선생님께서 어린이날 선물로 닌자로 레고를 주셨습니다.</p>
<p align="center">지난 *균이 생일때도 닌자고레고를 선물해 주셨는데요 </p>
<p align="center">그 후로 *균이 보물 1호가 닌자로 레고가 될 만큼 아주 아끼는 물건이 되었습니다. </p>
<p align="center">이번에 받은 레고도 *균이가 매우 좋아합니다 ^^</p>
<p align="center">보물 2호가 생겼네요 ^^</p>
<p align="center">바울방 친구들과 함께 레고조립을 하는 모습이 </p>
<p align="center">마냥 귀엽기만 합니다 ^^</p>
<p align="center">이제는 레고조립도 순식간에 완성하네요 ^^</p>
<p align="center">늘 *균이를 위해 많은 사랑을 나눠 주시는 </p>
<p align="center">이민진 선생님께 진심으로 감사드립니다 ^^*</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',983,1368543600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9671,'dus3','심주현','pikaccu85@hanmail.net','어린이집 선생님 감사합니다!!(2013.05.15)','<p align="center">오늘 즐거운 봄소풍 이자 스승의 날입니다 ^^</p>
<p align="center">어린이집 선생님들께 작은 감사의 마음을 전달 하기 위하여 </p>
<p align="center">아이들이 직접 쓴 감사카드와 카네이션을 전달하였습니다 ^^</p>
<p align="center">늘 밝은 미소로 아이들을 잘 지도해 주시는데요 ^^</p>
<p align="center">지금처럼 우리아이들이 어린이집에서 밝고 건강하게 생활할 수 있도록 </p>
<p align="center">잘 부탁드립니다!! ^-^*</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',994,1368543600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9672,'dus3','심주현','pikaccu85@hanmail.net','어린이집 봄소풍 가는날!!(2013.05.15)','<p align="center">오늘 어린이집에서 일산에 있는 남경수목원으로 </p>
<p align="center">봄소풍을 다녀왔습니다 ^^*</p>
<p align="center">가족들과 함께 가는 이번 봄소풍에는 </p>
<p align="center">룻2방 이소영 선생님과 바울방 심주현 선생님이 </p>
<p align="center">참여하였습니다^-^*</p>
<p align="center">도심을 떠나 푸르른 나무와 강이 있는 남경수목원에는 </p>
<p align="center">아이들이 체험할 수 있는 곳도 많아 </p>
<p align="center">음악에 맞춰 난타와 토마토 모종심기</p>
<p align="center">바나나보트타기, 솜사탕먹기, 무당벌레목걸이 만들기, 자전거타기 등</p>
<p align="center">여러가지 체험을 해 보았습니다. </p>
<p align="center">우리 아이들이 이 많은 것들을 다 했다니 믿기지가 않네요 ㅎㅎ</p>
<p align="center">(영재는 오늘 세발자전거 타는 법을 배웠답니다 ^^)</p>
<p align="center">&nbsp;</p>
<p align="center">오늘은 가족과 함께여서 더 행복했던 봄소풍 이였습니다 ^-^*</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',1039,1368543600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9676,'dus3','송명은','happysme@hanmail.net','룻2방의 중학생들이 야구장나들이를 다녀왔습니다.(2013.05.12)','<p>룻2방의 예쁜 중학생 4명이 롯데마트 후원프로그램으로 야구장관람 나들이 프로그램에 참석하게되었습니다.</p>
<p>여자아동들이라 평소에 야구에 관심이 많진 않았는데 야구장에 다녀온 아이들 모두는 늦은 밤이었는데도 열정적인 응원을 해서 그런지 덥다고 하면서 너무나 즐거웠다는 이야기를 하였습니다. 야구의 규칙에 대해서 잘 모르지만 후원자분들과 함께 응원하고 우리 아이들이 응원한 팀이 이겼다는 것이 아이들에게는 큰 기쁨이었던 것 같습니다.</p>
<p>우리 아이들에게 새롭고 유익한 시간들을 통해서 새로운 경험을 할 수 있도록 후원해주신 롯데마트 후원자분들께 다시한번 감사드립니다.</p>
<p>&nbsp;</p>          </td>
        </tr>',963,1368370800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9675,'dus3','심주현','pikaccu85@hanmail.net','바울방 심주현 선생님 생일 파티!!(2013.05.13)','<p align="center">남산원에서 &nbsp;맞이 하는 첫번째 생일&nbsp; ^^</p>
<p align="center">출근하자마자 직원들 모두 생일 축하한다 &nbsp;</p>
<p align="center">말해주어 너무 감사해요!!</p>
<p align="center">오늘도 맡은 업무 충실히 하도록 하겠습니다 ^^*</p>
<p align="center">&nbsp;</p>
<p align="center">하교하는 바울방 아이들의 손에는 장미꽃 한 송이가^^</p>
<p align="center">장미꽃 한송이가 좋다고 하니 아이들이 용돈을 가지고</p>
<p align="center">&nbsp;장미꽃을 선물로 사가지고 왔지요.. </p>
<p align="center">정말 이루어 말할 수 없는 감동이었습니다. ㅠㅠ</p>
<p align="center">저녁에는 선생님들과 바울방 아이들이 전날 미리 준비한 </p>
<p align="center">깜짝 파티가 짜잔~ㅋㅋ.</p>
<p align="center">&nbsp;저 보다도 아이들의 표정이 더 밝아&nbsp; 기분 업!!</p>
<p align="center">오늘은 365일 중에 가장 행복한 날입니다 ^-^*</p>
<p align="center">&nbsp;</p>
<p align="center">모두들 정말로 감사하고 사랑합니다!!</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',1007,1368457200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9674,'dus3','김선기','spsp99@naver.com','다윗방 최*선아동 생일선물(2013.05.10)','다윗방 최*선아동 생일을 맞이해서 남산원 원장님께서 생일선물로 용돈을 주셨습니다.

<div>*선이가 매우 기뻐하고 감사 하였습니다.</div>
<div>남산원 원장님께 진심으로 감사드리고 *선이가 잘자랄 수 있도록 최선을 다해 보육 하겠습니다.</div>          </td>
        </tr>',975,1368457200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9678,'dus3','박진성','js2227@hanmail.net','바울방 오*재 아동의 5번째 생일(2013.05.12)','<p>우리 바울방에서 귀요미를 담당하고 있는 *재의 생일이었습니다~!</p>
<p>형들의 축하를 받으며 즐거운 시간을 보냈습니다.</p>
<p>선물도 많이 받고 축하도 많이 받으며 남산원에서 처음 맞는 생일을 기분좋게 보냈습니다~</p>
<p>우리 *재가 오늘처럼 행복하고 즐거운 생활을 하였으면 좋겠습니다.</p>
<p>*재야~ 생일축하해^^*</p>          </td>
        </tr>',953,1368370800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9677,'dus3','심경숙','wdcyj1011@naver.com','김*희,김*선 하복 구입했어요','<p align="center">덕수 중학교 1학년에 재학중인 김*선,김*희 아동이 하복을 구입하였습니다.</p>
<p align="center">점심시간에 구매하여서 식사도 걸렀다고 합니다.</p>
<p align="center">혹시 다음에 구매할 경우가 생기면 그때는 좀더 여유로운</p>
<p align="center">시간을 가지고 구매할 것을 약속하겠습니다.</p>          </td>
        </tr>',987,1368370800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9679,'dus3','김선기','spsp99@naver.com','다윗방김*수아동 운동화선물','다윗방 김*수아동이 *수 이모님으로 부터 멋진 운동화를 선물을 받았습니다.*

<div>수는 매우 기뻐하고 행복해 하였습니다.운동화를 보면서 *수는 이모님께 감사에 마음을 가지며 더 성실하게 생활하고 더&nbsp;열심히 공부 하기로 약속 하였습니다.</div>          </td>
        </tr>',986,1368284400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9680,'dus3','김선기','spsp99@naver.com','남산원원장님과 함께 남산산책','<p>주일 아침 아동들 조회를 마치고 다윗방 아동들과 원장님과 함께&nbsp;남산을 산책 하였습니다.상쾌한 공기를 맞으며 기분 좋은 하루였습니다.^^</p>          </td>
        </tr>',987,1368284400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9681,'dus3','송명은','happysme@hanmail.net','룻2방 작은 숙녀들의 활기찬 바깥놀이시간입니다.(2013.05.12)','<p>오전에는 말레이시아 대사관에서 주최하는 바자회에 참석하고 오후에는 날씨좋은 운동장을 누비면서 즐거운 주말 오후시간을 보냈습니다.</p>
<p>겉보기에는 작고 여린 아기들이지만 바깥놀이를 할때 만큼은 너무나 씩씩한 모습으로 변한답니다. 아침부터 외부활동으로 피곤했는지 미취학 아이들은 저녁식사후에 샤워를 하고 일찍 잠자리에 들었답니다. 앞으로 계속되는 좋은 날씨에 우리 아이들과 어떤 시간을 보내면서 지내야할지 계속 연구해봐야겠습니다.^^</p>          </td>
        </tr>',974,1368284400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9682,'dus3','송명은','happysme@hanmail.net','룻2방의 중학생들이 예쁜 옷을 구입했습니다.(2013.05.12)','<p>룻2방의 사랑스런 중학생들은 내일부터 수학여행과 수련회를 가게 될 예정입니다.</p>
<p>그동안 손꼽아 기다렸던 수학여행과 수련회를 위해서 남산원 원장님께서 예쁜 옷을 선물해주셨습니다. 여자아이들이라 그런지 외모에 관심도 많고 특히 패션에 너무나 민감한 아이들은 원장님께서 선물해주신 옷을 입어보면서 너무나 좋아했답니다.</p>
<p>내일부터 2박 3일동안 다녀올 여행에서 아이들이 아무 사고없이 많은 추억거리를 만들고 귀가할 수 있도록 열심히 지원하겠습니다.</p>
<p>사랑스런 우리 중학생들의 멋진 모습~~모델같지 않아요??~~^^</p>          </td>
        </tr>',1081,1368284400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9685,'dus3','이소영','leesy5576@hanmail.net','2013. 05. 11 삼성SDS 생태체험학습활동 사진입니다.','<p align="center">2013. 05. 11 삼성SDS 생태체험학습활동 사진입니다.</p>
<p align="center">룻2방, 바울방, 다윗방 미취학, 초등학생 아이들 17명이 참석하였습니다.</p>
<p align="center">이번 생태체험학습은 한강에 서식하는 식물을 알아보고</p>
<p align="center">환경보호방법을 알 수 있도록 체험해 보는 시간을 가졌습니다,</p>
<p align="center">아이들 모두 호기심을 가지고 즐겁게 참여하는 모습이였습니다.</p>
<p align="center">후원, 봉사해주신 삼성SDS임직원분들께 감사드립니다. 수고많으셨습니다.^^</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',979,1368284400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9683,'dus3','송명은','happysme@hanmail.net','룻2방이 말레이시아 대사관의 바자회에 다녀왔습니다.(2013.05.12)','<p>말레이시아 대사관의 초대를 받아서 우리 남산원 아동들이 함께 바자회에 다녀왔습니다.</p>
<p>그중에서도 룻2방의 미취학과 초등부 아동들이 함께 참석하게 되었답니다.</p>
<p>우리 남산원에서도 매년 바자회를 하지만 오늘 참석한 말레이시아 바자회를 보면서 이것저것 구경하고 말레이시아의 전통음식을 먹으면서 신기해하는 아이들이 귀엽기만 했습니다. 말레이시아의 음식은 조금 낯설기도 할텐데 어린 미취학 아동들도 너무나 맛있게 먹으면서 즐거운 시간을 보냈습니다. 오늘 저희에게 잊을 수 없는 소중한 추억거리를 만들어주신 후원자분들께 다시한번 감사드립니다.</p>          </td>
        </tr>',1009,1368284400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9684,'dus3','박진성','js2227@hanmail.net','바울방의 말레이시아대사관 바자회나들이(2013.05.12)','<p>말레이시아 대사관에서 남산원의 아동들을 초대해주셨습니다. </p>
<p>단연 남산원에서 멋쟁이를 담당하고 있는 멋진 바울방의 아동들도 참석을 하였습니다. 우리 아동들이 함께 하며 즐거운 시간을 보내고 돌아왔습니다. 우리 아동들이 우리 나라 뿐 아니라 다른 나라의 문화를 익혀보는 시간이 되었습니다. 준비해주신 맛난 음식도 먹고 돌아왔습니다~</p>
<p>우리 아동들의 식사를 준비해주신 손길들...특히 초대해주신 대사관의 관계자분들께 감사인사를 전합니다~!</p>          </td>
        </tr>',949,1368284400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9688,'dus3','이소영','leesy5576@hanmail.net','룻2방 오*별,손*진아동 필동어린이집 어린이날선물입니다.','<p align="left">룻2방 오*별, 손*진아동이 필동어린이집에서</p>
<p align="left">어린이날 선물로 티셔츠를 선물받았습니다.</p>
<p align="left">*별이 *진이는 같은 옷을 입고 사진을 찍는 것을 매우 좋아하였습니다.</p>
<p align="left">5월 15일 필동어린이집 체험학습에도 입고 갈 예정입니다.</p>
<p align="left">많은 관심가지고 지켜봐주시는 필동어린이집 선생님 감사드립니다.^^</p>
<p align="left">&nbsp;</p>
<p align="left">&nbsp;</p>
<p align="left">&nbsp;</p>
<p align="left">&nbsp;</p>
<p align="left">&nbsp;</p>          </td>
        </tr>',1119,1368111600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9687,'dus3','심주현','pikaccu85@hanmail.net','바울방의 즐거운 주말보내기!!(2013.05.11)','<p align="center">오늘 바울방은 삼성SDS 한강생태체험프로그램에 참여했습니다. </p>
<p align="center">양수리 한강생태체험박물관에 가서 한강에서 사는 물고기들도 보고 </p>
<p align="center">펌프체험을 하는 등 후원자님과 즐거운 시간을 보내고 왔습니다. </p>
<p align="center">오후에는 환일고 형들과 함께 운동장에서 축구경기를 하였습니다. </p>
<p align="center">형들이 따라 오기 힘들만큼 바울방 친구들의 체력은 </p>
<p align="center">정말 최고였지요 ㅋㅋㅋㅋ</p>
<p align="center">지칠줄을 모르는 바울방의 주말은 </p>
<p align="center">오늘도 이렇게 훌쩍 지났습니다 ^^</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',997,1368198000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9686,'dus3','남산원','jblee4@naver.com','다윗방 최*선 생일파티(2013.05.11)','<p>5월 10일 생일을 맞은 *선이의 생일파티를 하루 늦은 오늘 하게 되었습니다. 케익과 치킨으로 차려진 조촐한 생일상.&nbsp;</p>
<p>생일축하 노래를 부르며 *선이가 학교에서도 집에서도 밝고 건강하게 성장해 나가기를 기원했습니다.&nbsp;</p>
<p>*선아, 다시 한번 생일 축하한다.^~^</p>          </td>
        </tr>',1042,1368198000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9689,'dus3','박현정','kingi109@naver.com','한나방 어버이날을 맞이하여 엄마 아빠께 감사인사 드립니다(2013.05.08)','<p align="center">한나방 아동들이 어버이날을 맞이하여 엄마 아빠께 직접 손편지를 써서 </p>
<p align="center">마음을 전달하였습니다.</p>
<p align="center">&nbsp;엄마 아빠께 감사한 마음을 가지며 정성스럽게 카네이션도 접었답니다^^</p>
<p align="center">아르바이트와 바쁜 학교생활로 시간이 없음에도 불구하고 시간을 내어서 엄마 아빠께 정성스럽게 쓴 편지라 그런지 기특해보이기도 합니다~^^ </p>
<p align="center">엄마 아빠 항상 감사드리며 사랑합니다~!</p>          </td>
        </tr>',1046,1367938800,'', '', '', '', '', '');
