INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9693,'dus3','심주현','pikaccu85@hanmail.net','바울방 어버이날 감사 편지와 선물 전달식!! (2013.05.08)','<p align="center">오늘 어버이날을 맞아&nbsp; 아침에 바울방 어버이날 감사 편지와 </p>
<p align="center">선물 전달식이 있었습니다. 무더운 날씨를 맞이 하여 </p>
<p align="center">남산원 아빠의 하얀 피부를 보호해 드리고자 </p>
<p align="center">룻2방과 바울방이 함께 썬크림을 준비 하였습니다. </p>
<p align="center">늘 바른 인성을 위해 좋은 가르침을 주시는 아버지께, 어머니께</p>
<p align="center">진심으로 감사드리며 앞으로 더욱 공부 열심히 하는 바울방이 되겠습니다!!! </p>
<p align="center">남산원 아빠, 엄마 사랑해요!!</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',970,1367938800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9692,'dus3','송명은','happysme@hanmail.net','어버이날을 맞이해서 룻2방이 아빠,엄마께 사랑의 마음을 전달하였습니다.(2013.05.08)','<p>룻2방 아동들은 어버이날을 맞이해서 남산원의 아빠,엄마께 직접 만든 카네이션과 사랑의 마음들이 가득 담긴 편지와 선물을 전달하였습니다.</p>
<p>아이들 모두가 다른 모양의 카네이션을 만들었지만 아빠,엄마께 감사하는 마음은 같았습니다. 아이들의 마음을 전달받으신 아빠, 엄마께서는 너무나 흐뭇한 미소를 보이셨답니다. 항상 우리 아이들을 사랑하시는 마음으로 걱정해주시고 보살펴주시는 그 사랑을 절대 잊지 않고 앞으로 많은 사람들에게 그 사랑을 나눠주는 멋진 사람이 되어 보답할 수 있도록 저희도 곁에서 사랑으로 보육하겠습니다.</p>
<p>아빠~엄마~♥</p>
<p>사랑합니다~건강하세요~~^^</p>          </td>
        </tr>',1006,1367938800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9694,'dus3','김선기','spsp99@naver.com','어버이날다윗방원장님께카네이션달아드림','<p>5월 8일 어버이날을 맞이하여 다윗방아동들과 교사가 정성스럽게 손수 만들어서&nbsp;준비한 카네이션을 원장님께 달아 드렸습니다. 늘 사랑으로 아동들을 돌보아 주시는 원장님 늘 행복하시고 건강하게 오래오래 사세요.</p>
<p>&nbsp;</p>          </td>
        </tr>',955,1367938800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9696,'dus3','송명은','happysme@hanmail.net','정수미 선생님께서 룻2방에게 어린이날 선물을 주셨습니다.(2013.05.07)','<p>룻2방 지민이의 영어학습을 지도해주시는 정수미선생님께서 오늘은 학습시간이 아님에도 불구하고 시간을 내셔서 지민이를 비롯한 룻2방 모두에게 어린이날 선물로 맛있는 간식을 선물해주셨습니다. 심지어 낱개로 포장을 직접 하셔서 아이들에게 한개씩 선물해주셨답니다.</p>
<p>선생님의 그 정성어린 사랑의 마음들에 저희 모두 깊은 감사의 마음을 전달합니다.</p>
<p>앞으로도 우리 지민이 많이 사랑해주세요.감사합니다.^^</p>          </td>
        </tr>',1013,1367852400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9695,'dus3','송명은','happysme@hanmail.net','룻2방의 초등학교 신입생인 *민이는 받아쓰기가 즐거워요~(2013.05.07)','<p>지난번 학교에서 받아쓰기 시험을 봤는데 백점을 받아와서 너무나 대견스럽고 자랑스러워했던 *민이가 오늘까지 포함해서 모두 5번이나 백점을 받았답니다.</p>
<p>남산원 원장님께서는 너무나 기특한 *민이에게 격려하시는 마음으로 용돈을 주셨습니다.&nbsp;</p>
<p>용돈을 받은 *민이는 하루종일 즐거운 마음을 감추지 못했습니다. </p>
<p>처음 시작이 좋은 우리 *민이를 앞으로도 많이 응원하면서 보육하겠습니다.^^</p>
<p>1학년 1반 53번 김*민~!!화이팅!!!</p>          </td>
        </tr>',994,1367852400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9697,'dus3','송명은','happysme@hanmail.net','룻2방의 막둥이들이 어린이집에서 요리체험을 하고 왔습니다.(2013.05.06)','<p>꽃보다 예쁜 룻2방의 막둥이인&nbsp;<span style="text-align: -webkit-center">*</span>별이와&nbsp;<span style="text-align: -webkit-center">*</span>진이가 오늘 필동어린이집에서 중구 식생활교육정보센터에 가서 요리체험을 하고 왔습니다. 일일 요리사가 되어서 맛있는 당근컵케이크를 만들어 본 우리 막둥이들은 스스로 만든 음식이 너무나 신기했는지 집에 오자마자 선생님한테 조심스럽게 예쁜 컵케이크를 보여주었답니다.</p>
<p>직접 요리를 만들면서 자신감이 높아진 것 같아서 너무나 흐뭇했습니다.</p>
<p>앞으로 집에서도 이런 시간들을 많이 만들어서 우리 아동들의 자존감이 향상될 수 있도록 보육하겠습니다.</p>          </td>
        </tr>',1016,1367766000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9698,'dus3','송명은','happysme@hanmail.net','룻2방 중학생 *선이가 어린이날 예쁜 선물을 받았습니다.(2013.05.05)','<p>룻2방&nbsp;<span style="text-align: -webkit-center">*</span>선이의 영어학습을 지도해주시는 박기연 선생님께서 어린이날을 기념하는 선물로 예쁜 가방과 티셔츠를&nbsp;<span style="text-align: -webkit-center">*</span>선이에게 주셨습니다. </p>
<p>중학생이 되어서 어린이라고 하기에는 너무 커버린&nbsp;<span style="text-align: -webkit-center">*</span>선이지만 박기연 선생님이 보시기에는 한없이 어리고 사랑스러운 아이와 같은&nbsp;<span style="text-align: -webkit-center">*</span>선이였나봅니다.^^</p>
<p><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span>선이가 박기연선생님과 영어수업을 해서 그런지 이번 중간고사때 높은 점수를 받았답니다. 앞으로도 우리&nbsp;<span style="text-align: -webkit-center">*</span>선이의 영어학습향상에 많은 기대를 해봅니다.</p>
<p>다시한번 감사드립니다.^^</p>          </td>
        </tr>',987,1367766000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9699,'dus3','송명은','happysme@hanmail.net','룻2방도 남산운동회에 참여해서 즐거운 어린이날을 보냈습니다.(2013.05.04)','<p>푸르른 오월의 날씨를 더욱 빛나게 해준 남산원의 아동들이 어린이날을 기념하는 남산운동회를 하였답니다. 그중에서도 남산원의 꽃인 룻2방 아동들도 남산운동회에 참여해서 여러가지 게임들도 하고 맛있는 점심과 간식도 먹으면서 너무나 즐겁고 신나는 어린이날을 보냈답니다. 우리 남산원 아동들이 즐거운 마음으로 어린이날을 보낼 수 있도록 후원해주신 많은 분들께 진심으로 감사드립니다. </p>
<p>오월보다 더 푸르른 아동들로 성장할 수 있도록 열심히 보육하겠습니다.</p>          </td>
        </tr>',962,1367766000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9700,'dus3','심주현','pikaccu85@hanmail.net','체육대회 MVP 시상식!!(2013.05.05)','<p align="center">오늘 체육대회 MVP시상식을 가졌습니다^-^*</p>
<p align="center">청팀 MVP 조영주 , 백팀 MVP 선찬영아동이 시상을 하였습니다. </p>
<p align="center">(상품은 두구두구두구두구~ 문화상품권 !!!)</p>
<p align="center">둘다 각팀의 조장으로써 체육대회에서 열심히 참여해 주었는데요 </p>
<p align="center">영주는 육상을 찬영이는 농구를 했을 때 가장 빛나보였답니다 ^^</p>
<p align="center">아이들의 선의의 경쟁이 보기 좋은 하루였습니다. </p>
<p align="center">영주, 찬영 MVP 축하해!! ^-^♡</p>          </td>
        </tr>',1063,1367766000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9701,'dus3','김선기','spsp99@naver.com','5월 5일 체육대회 시상(2013.05.04)','5월 4일에 남산원 체육대회를 하였습니다.좋은 날씨 가운데에서 교사들과 아동들 모두 체육대회를 하면서&nbsp;기뻐하고 행복해 하였습니다.주일 아침 아동들 조회 시간에&nbsp;체육대회 시상을 하였습니다.아동들이&nbsp;아직 잠이&nbsp;덜 깨어서 사진 촬영을 하는데 눈을 감은 아동들이 몇명 있었습니다.&nbsp;남산원 원장님께서 남산원 아동들에게 체육대회 선물로 문화상품권을 주셨습니다.기쁘고 행복한 가운데 체육대회를 할수 있게 해 주시고 체육대회&nbsp;선물로 문화상품권을 주신 원장님께 진심으로 감사를 드립니다.          </td>
        </tr>',1003,1367679600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9702,'dus3','송명은','happysme@hanmail.net','룻2방의 *영이와 *선이의 생일파티를 했습니다.(2013.05.01)','<p align="left">꽃보다 예쁜 룻2방의 사랑스러운 *영이의&nbsp;10번째 생일과&nbsp;의젓하고 배려심많은 *선이가 15번째 생일을 맞이했습니다. *영이와 *선이는 신기하게도 생일이 같은날이랍니다. </p>
<p align="left">혼자가 아닌 둘이 함께라서 더 즐겁고 신나는 생일파티를 했습니다. 오늘은 특별히 *영이와 *선이의 첼로수업을 지도해주시는 애드리안 선생님께서 참석해주셔서 자리를 빛내주셨습니다. 많은 사람들에게 사랑받고 인정받는 *영이와 *선이가 지금보다 더 많은 사람들에게 사랑받고 인정받는 아동으로 성장할 수 있도록 기도하는 마음으로 보육하겠습니다. </p>
<p align="left">꽃보다 예쁜 *영,*선아~~생일축하하고 사랑해~~♥</p>          </td>
        </tr>',1001,1367334000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9703,'dus3','송명은','happysme@hanmail.net','룻2방의 귀여운 막내들과 함께 따뜻한 햇살을 받으며 외출을 다녀왔습니다.(2013.05.01)','<p>룻2방의 귀여운 막내인&nbsp;<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">별이와&nbsp;</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진이는 오늘 근로자의 날로 인해 어린이집을 가지 않게되었습니다. 오랜만의 자유시간을 얻은듯 기뻐하는 막내둥이들과 함께 명동으로 즐거운 외출을 다녀왔습니다. 선생님과 함께 은행에 가서 처음 보는 은행업무관련 기계들을 보면서 신기해하는 모습이 너무나 귀여웠습니다. 점심으로는&nbsp;</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">별이가 추천한 토아토스파게티를 함께 먹으면서 오랜만에 동갑내기 친구들과의 즐거운 데이트를 했답니다.^^</span></p>          </td>
        </tr>',959,1367334000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9704,'dus3','이소영','leesy5576@hanmail.net','2013. 5. 1 룻2방 손*영, 김*선 생일입니다.','<p align="center">2013. 5. 1 룻2방 손*영, 김*선 아동 생일입니다.</p>
<p align="center">아침식사시간에 남산원아이들 모두 *영이 *선이를 위해</p>
<p align="center">생일축하 노래를 불러주며&nbsp;축하해 주었습니다.</p>
<p align="center">*영이 *선이가 앞으로도 건강하고 이쁘게 자랄 수 있도록 보육하겠습니다.^^</p>
<p>&nbsp;</p>          </td>
        </tr>',981,1367334000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9705,'dus3','이소영','leesy5576@hanmail.net','2013. 04. 30 박*민 아동 선물전달.','<p align="center">*민이의 독서지도를 맡아주고 계신 선생님께서 야외수업을 마치고</p>
<p align="center">*민이와 저녁식사를 한 후 어린이날 선물로 인형과 양말을 선물해주셨습니다.</p>
<p align="center">*민이가 선생님과 함께한 시간이 매우 즐거웠는지 </p>
<p align="center">이야기를 많이 해주었고 기분이 매우 좋아보였습니다.</p>
<p align="center">오랜기간동안 지민이에게 관심과 사랑주셔서 감사드립니다.</p>
<p align="center">이번주 수고 많으셨습니다. ^^</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',997,1367247600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9706,'dus3','이소영','leesy5576@hanmail.net','2013. 04. 30 강*리 아동 신발선물 전달','<p align="center">강*리 아동이 후원자님께 어린이날 선물로 신발을 선물받았습니다.</p>
<p align="center">신발을 보고 색깔이 마음에 든다며 매우 좋아하였습니다.</p>
<p align="center">후원자님의 사랑과 관심속에서 나리가 건강하게 성장할 수 있도록 보육하겠습니다.</p>
<p align="center">후원자님들께 진심으로 감사드립니다.^^&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',1033,1367247600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9708,'dus3','이문섭','srlc1208@hanmail.net','모세방 4월 환경심사 1등기념 저녁식사(2013.04.29)','<p align="center">새해에는 좋은 일들만 생길것 같은 예감이 이루어진 것 같습니다.</p>
<p align="center">함께하면 무엇이든 못할 일이 없다는 것이 증명되기라도 한듯...^^</p>
<p align="center">온세상이 화려한 꽃들로 수놓은 4월 22일(월) 환경심사에서 </p>
<p align="center">드디어 모세방이 1등을 하였습니다.</p>
<p align="center">이번달부터 새가족이 된&nbsp;*철이,&nbsp;*현이,&nbsp;*현이가 </p>
<p align="center">형들보다 더 열심히 준비했다는 사실은 </p>
<p align="center">정말 놀라운 일이 아닐 수 없습니다.</p>
<p align="center">.</p>
<p align="center">.</p>
<p align="center">.</p>
<p align="center">노력한 댓가로 오늘 서울 뷔페에서 </p>
<p align="center">즐거운 저녁식사를 하였습니다...^^</p>
<p align="center">감사하고요</p>
<p align="center">내친김에 5월까지........</p>
<p align="center">(욕심이 과하면 화를 부를지도...참아야지!!!)</p>          </td>
        </tr>',967,1367161200,'', '', '', '', '', '');
