INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9710,'dus3','김선기','spsp99@naver.com','다윗방 김*현아동 생일선물','다윗방 김*현아동 생일을 맞이해서 남산원 원장님께서 생일선물로 용돈을 주셨습니다.*현이가 매우 기뻐하고 감사 하였습니다.남산원 원장님께 진심으로 감사드리고 *현이가 잘자랄 수 있도록 최선을 다해&nbsp;보육 하겠습니다.          </td>
        </tr>',975,1367161200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9711,'dus3','심주현','pikaccu85@hanmail.net','남산초등학교 5.6학년 수학여행!!(2013.04.26)','<p align="center">&nbsp;</p>
<p align="center">남산초등학교 5.6학년 아동들이 </p>
<p align="center">2013.04.24(수) ~ 2013.04.26(금) 2박3일 동안 </p>
<p align="center">공주.부여로 수학여행을 다녀왔습니다. </p>
<p align="center">백제문화를 체험하며 우리 문화에 대한 자랑스러움과</p>
<p align="center">소중함을 많이 느끼고 올 수 있는 귀한 시간이 되었는데요. </p>
