INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9718,'dus3','이소영','leesy5576@hanmail.net','서울침례교회 유치부 야외예배다녀왔습니다.','<p align="center">서울침례교회 유치부&nbsp;*진,&nbsp;<span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">별,&nbsp;</span><span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">혁,&nbsp;</span><span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">호,&nbsp;</span><span style="font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">재 한옥마을로 야외예배 다녀왔습니다.</span></p>
<p align="center">예배를 드리고 침례교회에서 준비해주신 도시락을 먹고</p>
<p align="center">저희가 준비한 간식을 유치부친구들과 침례교회선생님들과 나누어먹었습니다.</p>
<p align="center">점심식사 후 보물찾기를 하여 아이들 모두 상품을 받았고</p>
<p align="center">다친곳 없이 재미있게 다녀왔습니다.</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',980,1366470000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9719,'dus3','박진성','js2227@hanmail.net','바울방 훈남 백*준의 생일^^(2013.04.18)','남산원에서 처음 맞이한 생일을 보내며 교회선생님들의 축복과 같이 방을 사용하는 형, 동생들의 축하에 행복한 시간을 보냈습니다.

<div>*준이가 학교에서나 집에서나 늘 밝게 지내고 건강한 생각을 많이 하는 모습이 참 대견합니다.</div>
<div>*준이가 늘 사랑받는 아이로 성장하길 기도해봅니다.^^</div>
<div>*준아 생일 축하해~^^*</div>          </td>
        </tr>',961,1366210800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9720,'dus3','송명은','happysme@hanmail.net','온누리교회 멘토선생님께서 소중한 선물을 보내주셨습니다.(2013.04.18)','룻2방에 제일 큰언니인 유진이에게 온누리교회 멘토이신 고광미선생님께서 유진이에게 너무나 예쁜 성경책을 선물로 보내주셨습니다. 평소에 일본어에 관심이 많은 유진이에게 성경말씀을 일본어로 번역해서 공부하면 좋을 것 같다라는 말씀을 하시고는 바로 이렇게 소중한 성경책을 선물해주셨답니다. 유진이가 앞으로 성경책을 읽으면서 더 하나님을 바로 알고 하나님의 사랑을 많은 사람들에게 전달하는 귀한 아동으로 성장할 수 있도록 보육하겠습니다. 다시한번 감사드립니다.^^          </td>
        </tr>',992,1366210800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9721,'dus3','송명은','happysme@hanmail.net','남산초등학교 학부모상담을 다녀왔습니다.(2013.04.16)','<p>어제부터 시작된 남산초등학교 학부모상담을 다녀왔습니다.</p>
<p>오늘은 룻2방의&nbsp;*민이와&nbsp;*영이의 담임선생님과 상담을 하였습니다.</p>
<p>초등학교 1학년에 입학한 재민이가 학교에 잘 적응할 수 있을지 걱정을 많이 했었는데 생각보다 원만한 교우관계를 유지하면서 학교생활에 충실히 임하고 있다고 해주셨습니다.</p>
<p>또 올해 3학년이 된&nbsp;*영이는 담임선생님을 만나기 위해 교실을 들어서는 순간 선생님께서는 너무나 큰 소리로 "*영이 아주 잘 키우셨던데요~"라고 하시면서 반겨주셨습니다.</p>
<p>학부모의 입장으로 참석하게 된 상담시간에 내가 보육하는 아이의 칭찬을 듣게 되니 너무나 뿌듯하고 아이들이 기특했습니다.</p>
<p>남산원 아동들에게 더 특별한 관심과 사랑으로 언제나 신경써주시고 보듬어주시는 남산초등학교 선생님들께 진심으로 감사드립니다.</p>
<p>앞으로도 우리 아이들이 지금처럼 밝은 마음을 간직하면서 생활할 수 있도록 열심히 보육하겠습니다.</p>          </td>
        </tr>',959,1366038000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9722,'dus3','남산원','jblee4@naver.com','다윗방 김*수아동생일(2013.04.15.)','<p>다윗방에&nbsp;꽃미남 *수가 오늘 생일을 맞이 하였습니다.다윗방 아동들 모두&nbsp;*수에 생일을 축하해 주고 축복해 주었습니다.*수야 생일 진심으로 축하하고 더 밝고 착하게 자라 주렴 선생님이 늘 기도할께 *수야 사랑한다 다윗방 김선기선생님이.</p>          </td>
        </tr>',921,1366038000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9723,'dus3','송명은','happysme@hanmail.net','룻2방의 즐거운 주말오후시간입니다.(2013.04.14)','<p>따사로운 햇살이 룻2방 아동들의 마음을 설레게하는 너무나 좋은 날씨에 룻2방 아동들은 즐거운 바깥놀이활동을 하였답니다.</p>
<p>언니와 동생들이 함께 공차기도 하고 어린 동생들이 타는 자전거를 넘어지지 않도록 언니들이 옆에서 든든하게 잡아주는 모습은 너무나 기특했답니다.</p>
<p>또 바깥놀이활동에서 빠질 수 없는 소꿉놀이를 하면서 마무리를 하였답니다.</p>
<p>함께 놀이활동을 하면서도 서로를 생각하고 챙겨주는 모습이 너무나 사랑스러운 꽃보다 예쁜 룻2방이랍니다.^^</p>          </td>
        </tr>',936,1365865200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9724,'dus3','심주현','pikaccu85@hanmail.net','바울방 남산 나들이~(2013.04.14)','<p align="center">화창한 주말 ,,</p>
<p align="center">바울방 아이들과 남산 나들이를 다녀왔습니다 ^^</p>
<p align="center">아이들과 함께 남산타워까지 올라갔다 왔는데요~</p>
<p align="center">미취학 아동들도 힘들다는 말 없이 즐겁게 다녀왔습니다!!</p>
<p align="center">아직 벚꽃이 피지않아 개나리와 진달래만 보았지만</p>
<p align="center">벚꽃이 활짝 피면 아이들과 남산에 다시 나들이를 오자 </p>
<p align="center">이야기 나누었습니다 ^^</p>
<p align="center">귀요미 바울방 아이들이&nbsp;</p>
<p align="center">봄을 만끽하며 즐겁게 생활할 수 있도록 </p>
<p align="center">지원하겠습니다 ^-^*&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',999,1365865200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9726,'dus3','송명은','happysme@hanmail.net','룻2방 초등학교 1학년 *민이가 받아쓰기 백점을 받았습니다.(2013-04-10)','<p>올해 초등학교에 입학해서 주위의 모든것들이 신기하고 새롭기만한 룻2방의 *민이가 오늘 학교에서 처음 본 받아쓰기에서 백점을 받았습니다.</p>
<p>*민이의 받아쓰기 공책을 보는 순간 너무나 기뻐서 *민이를 아주 꽈~악 안아주고 칭찬해주었답니다.&nbsp;</p>
<p>같은 룻2방의 언니들도 동생인 *민이를 기특해하는 모습이 더 보기좋았답니다.&nbsp;</p>
<p>또래아이들에 비해서 체격이 작은 *민이라서 항상 어리게만 봐왔는데 받아쓰기에서 백점을 받은 모습을 보니 너무나 대견스러웠답니다.</p>
<p>물론 앞으로가 더 중요하겠지만 시작이 좋은만큼 우리 *민이가 앞으로도 학습에 더 흥미를 가지고 학교생활에 충실할 수 있도록 보육하겠습니다.</p>          </td>
        </tr>',1019,1365519600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9725,'dus3','남산원','jblee4@naver.com','다윗방 김*생일파티(2013.0410)','<p>다윗방에 재임스딘 *이가 오늘 생일을 맞이 하였습니다.다윗방 아동들 모두 웅이의 생일을 축하해 주고 축복해 주었습니다.중학교2학년이 되어서 저녁 늦게까지 열심히 공부하는 *이의 생일을 진심으로&nbsp;축복하고 축하합니다.*이야 생일 진심으로 축하하고 더 밝고 착하게 자라 주렴 선생님이 늘 기도할께 *이야 사랑한다 다윗방&nbsp;김선기선생님이.</p>          </td>
        </tr>',1043,1365606000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9727,'dus3','이문섭','srlc1208@hanmail.net','모세방 새가족이 생겼습니다...^^','<p align="center">다윗방에서 오랫동안 모범적인 생활을 해오던 </p>
<p align="center">김*철, 임*현, 안*현 아동이 </p>
<p align="center">4월 8일(월) 저녁부터 남산원의 제일 큰집 </p>
<p align="center">모세방으로&nbsp;이사를 하였습니다.</p>
<p align="center">모세방은 대학생과 고3 형들이 </p>
<p align="center">생활하고 있는데요 동생들이 불편하지 않도록</p>
<p align="center">서로 서로 협력하고 도와주는 아름다운 모습들을</p>
<p align="center">기대합니다.</p>
<p align="center">"건강하고 행복하고 보람있는" 모세방 생활을</p>
<p align="center">적극 지원하겠습니다...</p>
<p align="center">여러 선생님들의 격려와 응원 부탁합니다.</p>
<p align="center">감사합니다...^^</p>          </td>
        </tr>',1073,1365519600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9728,'dus3','송명은','happysme@hanmail.net','룻2방의 아동과 함께 다솜아동청소년연구소에 다녀왔습니다.(2013.04.08)','<p>지난번에 이어서 두번째로 룻2방의 아동의 발달검사를 위해 반포에 위치한 다솜아동청소년연구소에 다녀왔습니다. 선생님께서는 발달검사 중에서도 가장 신뢰도가 높은 검사지를 선택하셔서 지능검사와 정서검사를 해주셨습니다.</p>
<p>이런 검사의 결과들을 통해서 아동들을 보육하는데 많은 도움이 될 수 있도록 하겠습니다. 다시한번 감사드립니다.</p>          </td>
        </tr>',1051,1365346800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9729,'dus3','박진성','js2227@hanmail.net','다윗방에서의 새로운 시작을 응원합니다!(2013.04.07)','<p>&nbsp;바울방에서 맏형으로서 늘 모범을 보이던 오*진 아동과&nbsp; 6학년 김*, 김*현, 김*수 아동이 다윗방으로 이동을 하였습니다.</p>
<p>&nbsp;아쉬워하는 동생들을&nbsp;뒤로하고&nbsp;새로운 출발을 위해 나아가는 아동들의 모습을 보니 괜히 섭섭해지는 선생님의 마음은 아쉽기만 합니다.</p>
<p>&nbsp;우리 아동들이 건강하게 자신의 역활을 잘 하며 더욱 발전된 모습으로 성장해 나가기를 응원합니다!!!!</p>
<p>&nbsp;우리 아이들의 뒤에서 열심히 지지해주며 기도하겠습니다^^</p>          </td>
        </tr>',1050,1365260400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9730,'dus3','이소영','leesy5576@hanmail.net','룻2방 *연, *민 하교 후 자유시간','<p align="center">룻2방 *연이와 *민이 하교 후 놀이터에서 </p>
<p align="center">공놀이도 하고 모래놀이도 하며 즐겁게 자유시간을 보냈습니다.</p>
<p align="center">*연이는 *민이가 다치지 않게 잘챙겨주었고&nbsp;</p>
<p align="center">서로 재미있게 잘노는 모습이 사랑스러웠습니다.</p>
<p align="center">새학기가 시작되었고 *민이는 입학한지 얼마 되지 않았기때문에</p>
<p align="center">학교생활에 잘 적응할 수 있도록&nbsp;하교 후 자유시간을 활용해 지도하겠습니다.</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',964,1365087600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9731,'dus3','남산원','jblee4@naver.com','모세방 용인철 아동 커피전문점 아르바이트','<p align="center">모세방 용인철 아동의&nbsp;커피전문점 아르바이트 모습입니다.</p>
<p align="center">원래 쌍둥이형 인호가 주중에 하는 "스토리"라는 곳에서</p>
<p align="center">인철이도 하게 되었습니다.</p>
<p align="center">쌍둥이는 모습도 같지만 성격과 식성도&nbsp;똑같구요~ </p>
<p align="center">자립준비를 위해서 경제활동을 하는 모습이 대견합니다.</p>
<p align="center">늘 신앙생활을 열심히 하고 항상 웃고 남을 배려하는</p>
<p align="center">&nbsp;인철이를 위해 지지합니다.</p>
<p align="center">어느곳에서든 칭찬받고 겸손하게 생활할 줄 믿습니다.</p>
<p align="center">꿈을위해 도전하길 바랍니다.</p>          </td>
        </tr>',1129,1364914800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9732,'dus3','심주현','pikaccu85@hanmail.net','남명이의 학교생활!!(2013.04.02)','<p align="center">웃는 모습이 이쁜 남명이에요!!</p>
<p align="center">처음으로 체육복을 입고 학교에 등교했답니다!</p>
<p align="center">비록 날씨는 좋지 않지만 강당에서 술래잡기를 했다며 </p>
<p align="center">많이 좋아하더라구요 ^^</p>
<p align="center">우리 남명이가 학교에서 재미 있고 </p>
<p align="center">활기차게 활동할 수 있도록 잘 보살 피겠습니다!</p>
<p align="center">많이 지켜봐주세요 ^-^*</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',927,1364828400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9735,'dus3','심주현','pikaccu85@hanmail.net','다솜아동청소년연구소 발달검사 받는날~(2013.04.01)','<p align="center"> 
</p>
<p align="center">오늘은 우리 바울방 친구와 함께&nbsp; 
</p>
<div align="center">반포에 있는 다솜아동청소년 연구소에 다녀왔습니다~</div>
<div align="center">학습이&nbsp; 더딘 우리 아이를위해 학습봉사자선생님의&nbsp;</div>
<div align="center">소개로 이곳에 오게되었는데요~</div>
<div align="center">많은 분들의 관심과 사랑으로 &nbsp;</div>
<div align="center">이렇게 좋은 기회를 받은것같습니다!</div>
<div align="center">앞으로도 우리 아이들에게 &nbsp;</div>
<div align="center">더 좋은 환경과 &nbsp;교육을 위해 노력하겠습니다^^ &nbsp; </div>
<div align="center">감사합니다♥</div>
<p></p>
<div align="right" class="list_eng">&nbsp;</div>          </td>
        </tr>',1076,1364742000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9734,'dus3','송명은','happysme@hanmail.net','룻2방이 함께 남산원의 61번째 생일을 축하했습니다.(2013-04-01)','<p>우리 아동들이 아름다운 계절을 맞이할 수 있고 즐겁게 학교생활을 할 수 있고 언제나 우리 아동들을 사랑으로 보살펴주시는 아빠,엄마와 선생님들을 만날수 있게 된 남산원이 61번째 생일을 맞이했답니다. 우리 아동들이 태어난 날 만큼이나 너무나 귀하고 소중한 이날을 우리 남산원 아동들 모두 기쁨으로 감사하며 창립기념예배를 드렸답니다.</p>
<p>또 생일을 맞이해서 남산원 아빠께서 사주신 맛있는 간식을 먹으며 룻2방 아동들은&nbsp;감사한 마음을 담아&nbsp;남산원 생일파티를 하였답니다.</p>
<p>오늘 예배때 목사님께서 해주신 설교말씀처럼 우리 남산원 아동들 한사람 한사람이 너무나 귀하고 소중한 존재랍니다. 우리 아동들이 좀 더 자신감있고 당당하게 생활할 수 있도록 앞으로도 열심히 보육하겠습니다.</p>
<p>남산원!!!화이팅!!!</p>
<p>^^</p>
<p>&nbsp;</p>          </td>
        </tr>',1018,1364742000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9733,'dus3','남산원','jblee4@naver.com','남산원 61주년 창립기념일 예배(2013.04.01)','남산원 61주년 창립기념일 예배가 남산원 강당에서 남산교회 목사님을 모시고 진행 되었습니다.남산원 원장님과,교사들,아동들이 참여한 가운데 기쁨과 감사속에서 예배가 진행되어졌습니다.설교를 하신 남산교회목사님께서는 남산원 아동들에게 꿈과 희망의 메세지를 전해 주셨고 하나님에 귀한 자녀라는 것을 잊지 말고 자라 달라고 귀한 말씀을 전해 주셨습니다.남산원 61주년 생일을 축하하며 남산원이 더 발전되고 남산원 아동들이 날마다 기쁨과행복속에서 자라기를 기도합니다.          </td>
        </tr>',1087,1364828400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9736,'dus3','송명은','happysme@hanmail.net','룻2방 아동들은 따뜻한 햇살을 친구삼아 즐거운 주말시간을 보냈습니다.(2013-03-31)','<p>3월의 마지막날에 따뜻한 햇살을 선물받으며 오랜만의 바깥놀이를 하였답니다.</p>
<p>소꿉놀이, 그네타기, 배드민턴 등등~~즐거운 주말 오후시간을 보낸 룻2방 아동들은 오랜만의 바깥놀이가 피곤했는지 평소보다&nbsp;일찍 잠자리에 들었답니다. 피곤하지만 즐거운 시간을 생각하며 곤하게 잠든 아동들의 모습은 너무나 사랑스러웠습니다. ^^</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',912,1364655600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9737,'dus3','송명은','happysme@hanmail.net','부활절을 맞이해서 침례교회예배에 참석한 아동들은 맛있는 계란을 받았습니다.(2013-03-31)','<p>예수님의 부활을 기념하며 기쁘고 즐거운 마음으로 침례교회에 가서 예배를 드린 아동들은 맛있고 예쁜 계란을 받아왔답니다. 하루종일 계란을 먹으면서 부활절의 기쁨을 나누는 즐거운 하루를 보냈답니다. ^^</p>          </td>
        </tr>',937,1364655600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9738,'dus3','심주현','pikaccu85@hanmail.net','바울방 아동들의 행복한 주말나기!(2013.03.31)','<p align="center">&nbsp;</p>
<p align="center">날 좋은날~ 운동 장에서 신나게 ^-^*</p>
<p align="center">바울방 아동들이 주말동안 즐겁게 실외활동을 하였습니다. </p>
<p align="center">남자친구들이다 보니 바깥활동을 매우 즐거워 하였는데요^^</p>
<p align="center">우리 바울방 친구들이 무럭무럭 쑥쑥 잘 자랄 수 있도록</p>
<p align="center">잘 &nbsp;보살피도록 하겠습니다!! ♡</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',974,1364655600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9740,'dus3','남산원','jblee4@naver.com','남산교회 부활주일 영아 헌아식(남산원 룻방)','<p>부활주일에 남산원 영아들 헌아식이 남산교회 대예배때 진행 되었습니다.남산교회 목사님과사모님,성도님들과,남산원 원장님,교사들과,남산원 영아들이 예배를 드리는 가운데 헌아식이 진행 되었습니다.예배를 드리는 분들 모두 영아들을 축복 하는 마음으로 기도하며 헌아식을 하였습니다.밝고 천사 같은 남산원 영아들이&nbsp;건강히 잘자라&nbsp;하나님의 자녀로써 귀하게 쓰임받기를 기도해 봅니다.</p>          </td>
        </tr>',1218,1364655600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9739,'dus3','심주현','pikaccu85@hanmail.net','바울방 실습선생님과 즐거운 파티!!(2013.03.30)','<p align="center">오늘 바울방에서 실습을 해주신 </p>
