INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9741,'dus3','류덕례','yoodr1015@hanmail.net','모세방 이*남 아르바이트 (2013.03.30) 소개','<p align="center">모세방 이*남군의 아르바이트(2013.03.30)모습입니다.</p>
<p align="center">이*남 아동이 3월부터 대학진학 후 &nbsp;대만음식점</p>
<p align="center">"딘타이펑"명동점에서 아르바이트를 하고 있습니다.</p>
