        </tr>',950,1364310000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9749,'dus3','심주현','pikaccu85@hanmail.net','최*명 아동  옷 선물 전달!!(2013.03.25)','<p align="center">최*명 아동이 후원자님께 초등학교 입학 선물로 </p>
