INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9748,'dus3','심주현','pikaccu85@hanmail.net','바울방 이*슬 아동 생일파티!!(2013.03.26)','<p align="center">&nbsp;</p>
<p align="center">오늘은 바울방의 귀공자 *슬이의 생일 입니다!!</p>
