INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9750,'dus3','심주현','pikaccu85@hanmail.net','바울방 환경심사 1등!! (2013.03.25)','<p align="center">&nbsp;환경심사에서 바울방이 1등을 하였습니다!! ^-^* 짝짝짝!!</p>
<p align="center">어제 오늘&nbsp; 옷장과 서랍장을 중점으로 정리 하였는데요 </p>
