INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9751,'dus3','심주현','pikaccu85@hanmail.net','이경란 실습선생님 바울방 방문!!(2013.03.25)','<p align="center">오늘 바울방에서 실습을 하셨던 이경란 선생님이 방문해 주셨습니다. </p>
<p align="center">맛있는 쿠티와 빵 그리고 초콜렛을 가져 오셨는데요 ^-^*</p>
<p align="center">늘 아이들을 많이 생각해 주시고 사랑해 주시는 마음이 </p>
<p align="center">느껴지는 하루였습니다!!</p>
<p align="center">마침 오늘이 환경심사 날이라 바울방 아동들과 함께 </p>
<p align="center">바울방을 깨끗히 청소해 주셨습니다!</p>
<p align="center">늘 밝은 미소를 보여주시는 이경란 선생님!! 대단히 감사합니다! </p>
<p align="center">잘 먹겠습니다♡</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',994,1364223600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9752,'dus3','송명은','happysme@hanmail.net','룻2방 아동들 모두 열심히 환경심사를 준비했습니다.(2013.03.25)','<p>한달에 한번 실시되는 환경심사 준비를 하고 있는 룻2방입니다.</p>
<p>우리 룻2방은 평소에도 너무나 깨끗하고 정리정돈이 잘 되어 있는 방으로 남산원에서</p>
<p>유~~명하지만 그래도 특별한 날이니만큼 더 신경써서 룻2가족 모두가 열심히 쓸고 닦고 정리를 하였답니다.</p>
<p>비록 이번 환경심사에서 아쉽게 2등을 하였지만&nbsp;룻2방 선생님의 마음속엔 언제나 "꽃보다 예쁜 룻2방"이 1등이랍니다.</p>
<p>우리 예쁜 룻2방 아동들이 오늘 열심히 청소해서 깨끗해진 룻2방처럼 언제나 깨끗하고 환한 아동으로 성장할 수 있도록 보육하겠습니다.</p>
<p>사랑하는 룻2방~~오늘 정말 많이 수고했어요~~~^^</p>          </td>
        </tr>',932,1364137200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9753,'dus3','박현정','kingi109@naver.com','한나방 강*미 아동의 생일파티 사진입니다(2013.03.24)','<p align="center">남산원의 회장으로서 멋진 모습을 보여주고 있는 강*미 아동의 생일입니다~!</p>
