INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9757,'dus3','심주현','pikaccu85@hanmail.net','바울방 아이들의 신나는 주말나기!!(2013.03.23)','<p align="center">&nbsp;</p>
