INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9758,'dus3','이문섭','srlc1208@hanmail.net','모세방 용*철 생일파티','<p align="center">부천대학 호텔외식조리과 2학년에 재학중인 </p>
<p align="center">모세방 큰형 용*철의 스물한번째 생일을 맞이했습니다.</p>
<p align="center">쌍둥이 형 *호와 함께 파티를 하게 되어서 </p>
<p align="center">더욱 의미있고 기쁜 날입니다.</p>
<p align="center">많은 축하와 응원의 메세지를 보내주세요...</p>
<p align="center">대학생활 열심히 하고 원하는 직장에 취직도 잘 되기를 기도합니다.</p>
<p align="center">그리고 하나님의 용사가 되기를 기도합니다. </p>
<p align="center">*철아!!! *호야!!! 사랑한다...^^</p>          </td>
        </tr>',946,1363964400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9759,'dus3','송명은','happysme@hanmail.net','김인자 후원자님과 룻2방의 *선이가 따뜻한 데이트를 하였습니다.(2013-03-23)','<p>남산원에서 10년 넘게 봉사를 해주시고 계시는 김인자님께서 오늘은 평소에 후원하고 계시는 아동들중에 룻2방의&nbsp;<span style="text-align: -webkit-center">*</span>선이와 즐겁고 따뜻한 데이트을 하셨답니다.</p>
<p>오늘은&nbsp;<span style="text-align: -webkit-center">*</span>선이가 좋아하는 떡볶이를 먹으러 신당동에 다녀왔습니다.</p>
<p>날씨도 좋고 맛있는 음식도 좋았지만 그보다 더 마음좋은 김인자 후원자님과의 외출시간이&nbsp;<span style="text-align: -webkit-center">*</span>선이에게는 너무나 소중한 시간이 되었답니다.</p>
<p>&nbsp;</p>
<p>남산원 아동들도 훗날 김인자 후원자님처럼 많은 사람들에게 사랑을 베푸는 사람으로 성장할 수 있도록 열심히 보육하겠습니다.</p>          </td>
        </tr>',904,1363964400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9760,'dus3','송명은','happysme@hanmail.net','룻2방에서 김밥만들기의 달인이 탄생했습니다.(2013-03-23)','<p>오늘은 환일고 후원으로 김밥과 유부초밥을 만드는 프로그램을 하게 되었습니다.</p>
<p>룻2방에서는&nbsp;<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">희,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">선,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진이가 참여해서 맛있는 김밥과 유부초밥을 만들었답니다.</span></p>
<p>평소에는 지나칠정도로 활발한 세명의 말괄량이 삼총사였지만 김밥과 유부초밥을 만드는 시간만큼은 놀라울정도의 진지함와 집중력을 발휘하였답니다.</p>
<p>예상하지 못한 본인들의 솜씨에 더욱더 놀란 세명의 숙녀분들은 그야말로 룻2방의 김밥만들기의 "김장금"이 되었답니다. 그동안 아동들에게 볼 수 없었던 새로운 장점들을 볼 수 있는 기회를 만들어주신 환일고 어머니분들께 다시한번 감사드립니다.</p>
<p>오늘처럼 아동들이 숨겨진 재능을 발휘할 수 있는 시간들을&nbsp;경험할 수&nbsp;있도록 열심히 보육하겠습니다.</p>          </td>
        </tr>',944,1363964400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9761,'dus3','송명은','happysme@hanmail.net','룻2방의 *영이와 *연이가 줄넘기를 하면서 주말오후시간을 보내고 있습니다.(2013-03-23)','<p>따뜻한 햇볕이 내리쬐는 토요일 오후시간에 룻2방의 공주님께서 더욱더 건강한 신체발달성장을 위해서 열심히 줄넘기를 하고 있습니다.</p>
<p>우리 남산원은 넓은 운동장이 있어서 날씨가 좋은 날에는 밖에 나와서 이렇게 신나게 운동을 하면서 시간을 보낸답니다.</p>
<p>앞으로도 우리 아동들이 더욱더 건강하고 튼튼하게 성장할 수 있도록 열심히 보육하겠습니다.^^</p>          </td>
        </tr>',900,1363964400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9762,'dus3','송명은','happysme@hanmail.net','남산교회 목사님과 사모님께서 룻2방과 다윗방 아동들에게 맛있는 저녁식사를 선물해주셨습니다.(2013.03.22)','<p>항상 남산원 아동들을 위해 기도해주시는 남산교회 목사님과 사모님께서 룻2방의&nbsp;<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">희,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진이와 다윗방의&nbsp;</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">늘,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">석,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">울,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">현이에게 맛있는 저녁식사를 선물해주셨습니다.</span></p>
<p>매주 남산교회에서 예배를 드리는&nbsp;<span style="text-align: -webkit-center">*</span>희,<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">늘,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">울이를 비롯해서 요즘 한창 사춘기를 보내느라 예배에 소홀했던&nbsp;</span><span style="font-size: 9pt; line-height: 1.5; text-align: -webkit-center">*</span><span style="font-size: 9pt; line-height: 1.5">석,</span><span style="font-size: 9pt; line-height: 1.5; text-align: -webkit-center">*</span><span style="font-size: 9pt; line-height: 1.5">현이까지 챙겨주시는 그 마음에 깊은 감사를 드립니다.</span></p>
<p>오늘 아이들과 함께 맛있는 저녁식사를 하시면서 아이들에게 글이나 그림으로 자기소개를 해볼 수 있는 귀한 시간을 갖게 해주셔서 감사드립니다. 아이들이 단순히 먹는 것에 그치지 않고 나 자신을 생각하고 되돌아볼 수 있는 유익한 시간이 되었던 것 같습니다.</p>
<p>앞으로도 우리 남산원 아동들을 위해 많은 기도 부탁드립니다.</p>
<p>감사합니다.^^</p>          </td>
        </tr>',922,1363878000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9764,'dus3','박현정','kingi109@naver.com','한나방 유*연 아동 생일파티(2013.03.21)','<p>한나방에서 피부미인 *연이의 16번째 생일을 축하해주세요~!</p>
<p>학교에서도 인기가 많은지, 선물을 어마어마하게 받아왔습니다! 역시 원에서도 인기가 많은 *연이는 친구들의 축하를 받으며 즐거운 생일파티를 하였습니다~!</p>
<p>맛있는 걸 먹으면서 즐거워 하는 우리 한나방 친구들의 웃음을 보니 행복합니다~^^</p>
<p>*연아 생일 진심으로 축하해♡</p>          </td>
        </tr>',956,1363878000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9763,'dus3','심주현','pikaccu85@hanmail.net','바울방 *진이가 반장이 되었어요!!! (2013.03.22)','<p align="center">&nbsp;</p>
<p align="center">바울방 맏형 *진이가 3월 환일중학교에 입학하여 반장이 되었습니다!!</p>
<p align="center">&nbsp;1학년 각반 반장들이 남산초등학교 아이들로 많이 되었다며 </p>
<p align="center">남산초등학교에 대한 자부심도 매우 컸습니다!</p>
<p align="center">우리 *진이가 1학기 동안 </p>
<p align="center">환일중학교 1학년 3반을 잘 이끌어 나갈수 있도록</p>
<p align="center">많이 응원해 주세요!! ^-^*</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',945,1363878000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9765,'dus3','김선기','spsp99@naver.com','다윗방 이*늘,안*현,최*선 멋진 안경 구입(2013.03.21)','<p>다윗방 이*늘,안*현,최*선 아동이 안경을 구입 하였습니다.공부 하는데 칠판이 잘 안보여 힘들었는데 안경을 쓰게 되어서 밝고 선명하게 사물과 칠판을 볼수 있게 되었습니다.</p>
<p>아동들 모두 매우 기뻐하고 안경을 구입 할수 있게 도와 주신 남산원&nbsp;원장님께 감사 하였습니다.</p>
<p>아동들 모두 새로 구입한 안경을 쓰고 열심히 공부 하기로 약속 하였습니다.</p>
<p>안경을 구입 할수 있도록 도와 주신 남산원 원장님과 친절하게 저렴한&nbsp;가격으로 안경을 맞쳐주신 리갈안경원 사장님께&nbsp;진심으로 감사를 드립니다.</p>
<p>앞으로 아동들에게 더 많은&nbsp;사랑과 희망을 주며 열심히 보육 하겠습니다.</p>          </td>
        </tr>',1036,1363791600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9768,'dus3','박진성','js2227@hanmail.net','에버랜드와 함께하는 고무동력기 만들기(2013.03.20)','<p>남산원에 찾아오신 에버랜드 봉사자분들과 오늘은 고무 동력기를 만들었어요^^</p>
<p>초등학생 남자아동들의 눈이 반짝이는 시간이었습니다.</p>
<p>많은 도움을 받아서 완성하였지만 날려보고 원리를 알아가는 시간이 되었어요~</p>
<p>다 만들 후에는 보드게임과 동물퍼즐 맞추기도 하며 즐거운 시간을 보냈어요.</p>
<p>또 맛있는 저녁식사를 지원해주셔서 바울방 아동들은 배 불리 피자와 치킨을 먹으며 행복한 시간을 보냈답니니다.</p>
<p>즐겁고 신나는 하루를 선물해주신 에버랜드 봉사자분들께 진심으로 감사드립니다~!!^^*</p>          </td>
        </tr>',954,1363705200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9766,'dus3','박현정','kingi109@naver.com','바울방 고무동력기 놀이활동 체험(2013.03.21)','3월 20일 에버랜드 봉사자분들과 멋진 고무동력기를 제작하고 나서, 오늘 고무동력기를 실험을 해보았습니다. 바울방 아동들은&nbsp;제작과정에서 즐거웠던 이야기를 나누며, 멀리던지기 게임도 하였습니다. 바울방 아동들이 행복해하는 모습을 보니 흐뭇했습니다^^          </td>
        </tr>',950,1363791600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9767,'dus3','박진성','js2227@hanmail.net','바울방 아동들의 인기메뉴는 무얼까요??(2013.03.20)','<p>늘 우리에게 맛있는 음식을 주시는 영양급식팀에서 급/간식 기호도 조사를 하였습니다.</p>
<p>바울방아동들이 최근에 살도&nbsp;찌고 키도 쑥쑥 크고 있는데요~</p>
<p>이번에는 또 어떤 욕구 표현을 했을지.....</p>
<p>닭강정, 과일 종류가 아동들이 선호하는 음식이었어요~!!</p>
<p>맛있는 음식으로 늘 우리에게 사랑을 주시는 영양사님과 조리사님~정말 감사드려요!!!^^*</p>          </td>
        </tr>',943,1363705200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9769,'dus3','송명은','happysme@hanmail.net','룻2방 *리에게 김미란후원자님께서 소중한 선물을 보내주셨습니다.(2013-03-20)','<p>김미란 후원자님께서 룻2방의 *리에게 너무나 필요했던 선물을 보내주셨습니다.</p>
<p>어린이재단을 통해서 그동안 *리에게 사랑의 마음들을 표현해주셨던 김미란 후원자님께서는 올해에 중학교에 입학하게 된 *리를 위해서 수학,과학,사회 학습교재를 보내주셨습니다. 중학생이 되고 처음 접하는 환경속에서의 학습은 *리에게 너무나 큰 부담이었는데 후원자님께서 보내주신&nbsp;학습교재를 풀면서 큰 부담감이 조금씩 사라질 것이라고 생각됩니다. 또 학습교재를&nbsp;공부할 때 필요한 예쁜 필통과 그안에 깜찍한 필기도구까지 세심하게 챙겨주시는 그 관심에 힘입어 우리 *리가 더욱 자신감을 가지고 중학교생활을 할 수 있도록 보육하겠습니다. 감사합니다.^^</p>          </td>
        </tr>',989,1363705200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9771,'dus3','박진성','js2227@hanmail.net','한신영 후원자님의 선물(2013.03.18)','<p>2년전 영호와 영어 수업을 함께해주셨던 한신영 선생님이 방문 해주셨습니다.</p>
<p>큰 수술을 하고 회복하는 중이신데도 잊지 않고 영호의 생일이라며 찾아와주신 고마우신 선생님^^</p>
<p>영호에게 매달 후원금도 보내주시고 영호에게 도움이 필요할 때면 언제든지 지지해주시는 선생님의 마음에 너무 감사드립니다.</p>
<p>영호는 바울방에서 형들과 건강하게 생활하고 있고 키도 쑥쑥 자라고 있다는 말에 너무나 흐뭇해 하셨습니다. 선생님 감사드려요~~</p>
<p>빨리 건강해지셔서 선생님의 약속대로 따뜻한 5월에 만나요~~!!</p>
<p>&nbsp;</p>          </td>
        </tr>',973,1363705200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9770,'dus3','박진성','js2227@hanmail.net','바울방 아동들의 방모임 시간^^(2013.03.19)','<p>매일 바울방 아동들은 자신의 소리를 높이는 시간을 갖습니다.</p>
<p>남산원에서 생활하고 있는 아동들은 매일 밤 방모임을 통해&nbsp;자신의 소리를 높이지만 바울방은 조금 특별합니다!</p>
<p>초등학생과 미취학(어린이집)아동들이 함께 생활하는 바울방은,</p>
<p>미취학 아동들도 방모임 시작 전, 후 대표기도를 하고 방모임에서 자신의 준비물에 대해 이야기도 하며 자신의 의견을 발표력있게 표현을 합니다.</p>
<p>가끔 엉뚱한 소리를 해서 방모임 시간을 웃음바다로 만들기도 하구요~</p>
<p>초등학생 형들 사이사이에 앉아 형들과 더 까깝게 생활하고 있습니다.</p>
<p>이제는 방모임 시간에는 장난하지 않고 자신의 이야기를 하는 시간인걸 너무나 잘 아는 기특한 모습도 볼 수 있습니다.</p>
<p>바울방에서의 방모임은 우리 아동들이 여는 작은 자치회의입니다.</p>
<p>꾸준히 아동들이 자신을 표현하는데 어려움이 없으며 크게 성장할 수 있도록 지원을 하려고 노력하겠습니다!!</p>          </td>
        </tr>',945,1363705200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9773,'dus3','김선기','spsp99@naver.com','남산교회 예배(다윗방 이*늘,이*울)','다윗방 *늘이와 *울이가 남산교회 주일&nbsp;예배를 드렸습니다.예배에 집중하며 마칠때 까지 조용한 가운데 예배를 잘 드렸습니다.

<div>*늘이와 *울이가 신앙생활 하는데 어렵지 않도록 많은 도움을 주고 지도를 하겠습니다.</div>
<div>*늘이와 *울이가 신앙이 예쁘게 잘자랄 수 있도록 기도해 봅니다.</div>          </td>
        </tr>',972,1363446000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9772,'dus3','박진성','js2227@hanmail.net','바울방 바다의 왕자 박*호의 생일이예요(2013.03.17)','<p class="바탕글">바울방에서&nbsp;물고기를 사랑하는 귀요미&nbsp;*호가 여섯번째&nbsp;생일을 맞이 하였습니다 ^-^♡</p>
<p class="바탕글">늘&nbsp;조용히 그림을 그리고 만들기를 즐겨 하는&nbsp;*호는&nbsp;&nbsp;남산원에서 몇년 전만해도 막내였습니다. 하지만 동생들이 와서 멋진 형으로서 잘 자라고 있습니다!!</p>
<p class="바탕글">우리 *호가 언제나 행복하고 건강하고 밝게&nbsp;잘 성장할 수 있도록 지켜봐 주세요!! ^^</p>          </td>
        </tr>',1001,1363446000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9774,'dus3','김혜진','emo82@naver.com','룻2방 강*리,김*선 졸업선물 남산교회 후원 (2013.03.17)','<p align="center">남산교회에서 룻2방 *리와 *선이에게 졸업선물로 문화상품권을 후원해 주셨습니다.^^</p>
<p align="center">유익한&nbsp;책을 구입하여 아이들이 중학교에 입학해서 열심히 공부할&nbsp;수 있도록&nbsp;</p>
<p align="center">좋은 선물을 주신 남산교회 분들께 감사드립니다.</p>
<p align="center">항상 저희 아이들을 위해 신경써 주시고 관심가져주셔서 감사드립니다~! ^.^</p>          </td>
        </tr>',1000,1363446000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9775,'dus3','송명은','happysme@hanmail.net','룻2방 아동들이 모여서 즐거운 방모임을 하였습니다.(2013-03-16)','<p>남산원 아동들 모두가 저녁마다 방별로 모여서 방모임을 한답니다.</p>
<p>방모임은 아동들과 대화를 할 수 있는 시간이랍니다.</p>
<p>주로 아동들의 건의사항이나 하고싶은 이야기들을 자유롭게 하면서 서로 의사소통을 하고 있습니다. 또 아동들의 건강상태 확인이나 필요한 준비물 체크를 하면서 아동들의 부족한 부분들을 채워주기 위해서 담당 선생님이 아동들의 이야기에 귀를 기울이고 있습니다.</p>
<p>특별히 저희 룻2방에서는 매일 오늘 하루동안 지내면서 감사한 일을 한가지씩 이야기하는 시간이 있습니다.&nbsp;오늘은 대부분의 아이들이 날씨가 따뜻해서 오랜만에 오후에 바깥놀이를 할 수 있어서 감사하다는 이야기를 했습니다.&nbsp;어쩌면&nbsp;무심코 지나갈 수 있는 이런 작은 일에도 우리 룻2방 아동들이&nbsp;감사할 줄 아는 마음으로 생활할 수 있도록 보육하고 있습니다. </p>
<p>오늘도 감사한 마음을 가슴에 담고 하루를 마감하는 예쁜 룻2방이랍니다.^^</p>          </td>
        </tr>',1016,1363359600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9776,'dus3','이문섭','srlc1208@hanmail.net','모세방 용*철 대학생이 호텔외식조리과 MT를 다녀왔습니다...^^','<p>3월 14일(목) ~ 15일(금) 이틀간 부천대학 호텔외식조리과 2학년에 재학중인 용*철 대학생이 MT를 다녀왔습니다. 집에서나 학교에서나 적극적으로 열심히 생활하고 있는 *철이가 이번 MT에서도 중요한 역할(?)을 했다고 합니다.</p>
<p>아쉽게도 사진을 남기지 못했지만 친구들과 후배들에게 인기가 많았다고 합니다.</p>
<p>2학년 열심히 공부해서 원하는 곳에 취직할 수 있도록 많은 격려와 응원 부탁합니다.</p>
<p>감사합니다...^^</p>          </td>
        </tr>',979,1363359600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9777,'dus3','심주현','pikaccu85@hanmail.net','남산초 신입생 *명, *민이 체육복 구입!!(2013.03.16)','<p align="center">올해 &nbsp;남산초등학교 1학년에 입학한 *명이와 *민이가 </p>
<p align="center">체육복을 구입하였습니다.^^</p>
<p align="center">사복 입은 모습과 달리 체육복입은 모습이 </p>
<p align="center">너무 귀엽기만 합니다 ^-^*&nbsp;</p>
<p align="center">바울방과 룻2방의&nbsp;귀요미 *명이와 *민이가 </p>
<p align="center">즐거운 학교생활을 할 수 있도록 </p>
<p align="center">옆에서&nbsp;잘 지켜봐 주세요!!</p>
<p align="center">♡</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',1009,1363359600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9779,'dus3','송명은','happysme@hanmail.net','덕수중학교 학부모 공개수업에 다녀왔습니다.(2013-03-14)','<p>덕수중학교에서 실시한 학부모 공개수업에 참석하게 되었습니다.</p>
<p>룻2방의&nbsp;<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">리,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">선,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">희,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">진이가 공부하고 있는 덕수중학교에 가서 아이들의 반을 찾아다니며 수업을 하고 있는 모습을 보았습니다. 항상 방에서 생활하던 모습만 보다가 직접 수업을 하고 있는 아이들의 모습을 보니 기특하기도 하고 자랑스럽기도 하였습니다.아쉽게도 수업시간에는 사진촬영을 하지 못하게 하셔서 열심히 수업에 집중하고 있는 우리 아이들의 모습은 담아올 수 없었지만 학부모의 마음으로 참석하게 된 저의 마음에는 오랫동안 남아있을 것 같습니다. 이 마음을 잊지않고 책임감을 가지고 앞으로도 아이들을 열심히 보육하겠습니다.</span></p>          </td>
        </tr>',1064,1363186800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9780,'dus3','송명은','happysme@hanmail.net','룻2방의 *리가 학습선생님께 예쁜 선물을 받았습니다.(2013-03-13)','<p>룻2방의 *리에게&nbsp;수학을 지도해주시는 김희연선생님께서 *리에게 중학교 입학선물로 예쁜 보조가방을 선물해주셨습니다.</p>
<p>*리의 여성스러운 취향을 생각하셔서인지 예쁜 분홍색의 꽃모양으로 장식한 가방이 너무나 잘 어울리는 *리입니다. 신학기가 시작되어서 준비물이 많았는데 이제 선물받은 예쁜 가방에 넣고 학교에 등교하는 *리의 모습을 보게 될 수 있을 것 같습니다.</p>
<p>*리에게 이렇게 예쁜 가방을 선물해주신 그 사랑에 힘입어*리가 중학교 생활을 즐겁게 할 수 있도록 보육하겠습니다.</p>          </td>
        </tr>',1021,1363186800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9778,'dus3','김혜진','emo82@naver.com','룻2방 환경심사 결과 저녁외식~! (2013.03.15)','<p align="center">2월 28일 환경심사에서 1등을 한 룻2방 맛있는 저녁식사를 하고 왔습니다~!</p>
<p align="center">모두 다함께 분담하여 열심히 환경심사에 참여하여 좋은 결과를 맞이하여 </p>
<p align="center">기뻐하였습니다. 깨끗한 환경과 더불어 외식의 기회까지 주어지니 더욱 더 </p>
<p align="center">즐거워 하였습니다.^^</p>
<p align="center">아이들이 좋아하는 자장면과 탕수육까지 맛있는 저녁식사를 하고 함께 이뤄낸 결과에 </p>
<p align="center">뿌듯하기도 하였습니다. </p>
<p align="center">감사한 마음으로 즐거운 저녁식사시간을 보낸 룻2방 행복한 시간이었습니다~!</p>
<p align="center">^ㅡㅡㅡ^</p>          </td>
        </tr>',940,1363359600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9781,'dus3','박흥식','','[re] 귀여운 *민.*명이의 즐거운 하굣길!(2013.03.14)','수고 들많아요. 심선생. 잘하고 있어요.          </td>
