  </tr>',1041,1363186800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9782,'dus3','심주현','pikaccu85@hanmail.net','귀여운 *민.*명이의 즐거운 하굣길!(2013.03.14)','<p align="center"></p>
<p align="center">3월에 입학한 *민이와 *명이의 하굣길 입니다. </p>
<p align="center">아이들이 길이 익숙해져 집에 잘 찾아 올 수 있을 때 까지</p>
<p align="center">하교지도를 하고 있는데요 ^^</p>
<p align="center">오늘은 날이 너무 좋아서 아이스크림을 먹으며 </p>
<p align="center">하교하였습니다!!</p>
