<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',1035,1363186800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9783,'dus3','박흥식','','[re] 남산초등학교 1학년 최*명, 김*민 학교생활~!(2013.03.13)','수고들 많아요.스 팸은 김선기tr 삭제 하라고 하세요. 수고 .          </td>
