INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9786,'dus3','송명은','happysme@hanmail.net','온누리교회 멘토선생님께 귀한 선물을 받은 *리입니다.(2013-03-12)','<p>작년부터 시작된 온누리교회 멘토링프로그램에서 룻2방&nbsp;<span style="text-align: -webkit-center">*</span>리의 멘토가 되어주시는 안성민 선생님께서&nbsp;<span style="text-align: -webkit-center">*</span>리에게 귀한 선물을 주셨습니다. 장래희망이 패션디자이너인 나리에게</p>
<p>"Fashion Illustration Workbook"라는 시중에서 구하기 힘든 책을 선물해주셨습니다.</p>
<p>책에는&nbsp;<span style="text-align: -webkit-center">*</span>리가 직접 디자인을 할 수 있는 여러가지 자료들이 있어서 <span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">리에게 정말 많은 도움이 될 것 같습니다. 앞으로 나리가 본인의 꿈을 이루기 위해서 열심히 공부하고 생활할 수 있도록 지도하겠습니다.감사합니다.^^</span></p>          </td>
        </tr>',1129,1363014000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9785,'dus3','심주현','pikaccu85@hanmail.net','온누리 교회 멘토선생님께 선물받은 *진이^^(2013.03.10)','<p align="center">이번주에 온누리교회 선생님과의 멘토 수업을 하였습니다!!</p>
<p align="center">바울 *진이의 멘토가 되어 주시는 이경미 선생님께서 이번에 중학교에 올라간</p>
<p align="center">동진이를 위해 영어, 수학 문제집과 노트 그리고 성경이야기 책을 선물로 주셨습니다. </p>
<p align="center">*진이 꿈은 CEO인데요 </p>
<p align="center">멋진 CEO가 되기 위해서는 우선 공부를 잘 하는 것이겠지요^-^*</p>
<p align="center">*진이가 공부를 열심히 할 수 있도록 옆에서 많은 지원을 하도록 하겠습니다. </p>
<p align="center">*진이에게 좋은 멘토가 되어&nbsp;주신 이경미 선생님 감사합니다^^</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',1014,1363100400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9784,'dus3','김혜진','emo82@naver.com','남산초등학교 1학년 최*명, 김*민 학교생활~!(2013.03.13)','<p align="center">남산원의 귀염둥이 *민이와 *명이가 초등학교에 입학하여 잘 적응하고 있습니다.</p>
<p align="center">아직은 선생님과 함께 등하교를 하고 있지만 이제는 집에 돌아오는 길도 익혀서</p>
<p align="center">선생님에게 설명도 잘 해준답니다~^^</p>
<p align="center">새로운 환경에도 낯설어하지 않고 즐겁게 학교생활을 하고 있는 *민이와 *명이</p>
<p align="center">많이 많이 응원하고 격력해주세요~! </p>          </td>
        </tr>',982,1363100400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9789,'dus3','이문섭','srlc1208@hanmail.net','이*남 아동이 아르바이트를 시작합니다...^^','<p>그동안 오랫동안 아르바이트를 할려고 면접을 보았으나 잘 이루어지지 않았는데요</p>
<p>이번에 이호진 팀장님의 소개로 \'딘타이펑코리아\'라는 중식 레스토랑에서 3월11일(월) 오후 5시부터 아르바이트를 시작하게 되었습니다. 출근을 위해서 은행 급여 통장도 만들고 구두와 벨트도 구입했습니다. 유창한 중국어 실력으로 \'딘타이펑코리아\'에서 성실하게 인정받는 *남이가 되도록 다같이 응원의 메시지를 부탁합니다.</p>
<p>대학생활도 처음시작하고 아르바이트도 처음시작하는 경남이가 잘 적응할 수 있도록 적극 지원하겠습니다...^^</p>          </td>
        </tr>',1031,1362841200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9788,'dus3','김혜진','emo82@naver.com','룻2방의 호기심천국 박사 *민이의 11번째 생일입니다~(2013.03.10)','<p align="center" class="바탕글">룻2방의&nbsp;호기심 천국&nbsp;*민이의&nbsp;11번째 생일을 맞이했습니다.</p>
<p align="center" class="바탕글">기발한 아이디어와 뛰어난 기억력을 갖고 있는 *민이는 궁금한 것도 많아 알고 </p>
<p align="center" class="바탕글">있는 것도 많은 룻2방의 숨겨진 인재랍니다~! ^^</p>
<p align="center" class="바탕글">오늘 생일 파티에는 *민이의 학습선생님이신 정수미선생님께서 참석해주셔서 </p>
<p align="center" class="바탕글">*민이의 생일을 함께 축하해주셨습니다. </p>
<p align="center" class="바탕글">즐거운 자리를 함께 해주신 선생님께 감사드리구요~</p>
<p align="center" class="바탕글">*민이가 지금처럼 씩씩하고 건강하게 자랄 수 있도록 노력하겠습니다. ^^</p>          </td>
        </tr>',994,1362841200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9787,'dus3','김선기','spsp99@naver.com','남산교회 새친구로 등록(다윗방 이*울,이*늘아동)','남산교회에 새친구로 다윗방 이*울,이*늘아동이 등록을 했습니다.어제 처음 예배를 드렸는데 조용한 가운데 신령과 진정으로&nbsp;하나님께 예배를 잘 드렸습니다.어제 새친구로 등록을 했는데 *울이와 *늘이가 남산교회에 잘 정착 할수 있도록 지도 하겠습니다.          </td>
        </tr>',1047,1362927600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9790,'dus3','이문섭','srlc1208@hanmail.net','선*영 새 교복 바지를 맞췄습니다...^^','<p>그동안 2년동안 입었던 교복바지가 너무 많은 수선으로 더이상 입을 수가 없어서 이번에 새 교복 바지를 구입했습니다...^^</p>
<p>의리있고 멋있는 *영이의&nbsp;고3 생활을 응원합니다...^^&nbsp;</p>          </td>
        </tr>',1232,1362841200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9792,'dus3','김선기','spsp99@naver.com','태블릿 PC 너무 좋아요(다윗방)','<p></p>
<p style="line-height: 120%; margin-bottom: 1.6pt" class="바탕글"><span style="font-family: 굴림" lang="EN-US">KIRD회사의 후원으로 다윗방 아동들이 태블릿PC를 사용하고 있습니다.모두들 재미있게 유용하게 사용하고 있습니다.다윗방에서 태블릿PC사용으로 인해 다윗방 아동들이 공부하는데 큰 활력소가 되고 있고 큰 재미와 기쁨이 되고 있습니다.태블릿PC를 가지고 인터넷 검색,게임,영화를 보고 있습니다.태블릿PC가 다윗방에서 좋은 친구가 되고 있습니다.다윗방 아동들에게 큰 기쁨과 즐거움을 주신 KIRD회사 사장님께 진심으로 감사 드립니다.</span></p>          </td>
        </tr>',1044,1362668400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9791,'dus3','임태현','lth1342@naver.com','다윗방 태블릿PC 사용(2013.03.08)','<p style="line-height: 120%; margin-bottom: 1.6pt" class="바탕글" align="center">&nbsp;</p>
<p style="line-height: 120%; margin-bottom: 1.6pt" class="바탕글" align="center">KIRD회사의 소중한 후원 태블릿PC !</p>
<p style="line-height: 120%; margin-bottom: 1.6pt" class="바탕글" align="center">아동들이 학습은 물론 여가시간에&nbsp;다양한 기능을 이용하여&nbsp;태블릿PC를 생활에&nbsp;유용하게&nbsp;사용하고 있습니다.</p>
<p style="line-height: 120%; margin-bottom: 1.6pt" class="바탕글" align="center">남산원 아동들을 위해 소중한 태블릿PC를 후원해주신&nbsp;KIRD회사 사장님께 진심으로 감사 드립니다.</p>
<p style="line-height: 120%; margin-bottom: 1.6pt" class="바탕글">&nbsp;</p>
<p style="line-height: 120%; margin-bottom: 1.6pt" class="바탕글">&nbsp;</p>          </td>
        </tr>',1062,1362668400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9794,'dus3','심주현','pikaccu85@hanmail.net','3군단장 상을 받은 자랑스런 오*진!!(2013.03.05)','<p align="center">오*진아동이 &nbsp;남산초등학교 졸업을 하며 3군단장상을 받았습니다!!</p>
<p align="center">평소 바울방에서도 큰형으로써 늘 단정하고 학업을 열심히 해 주었었는데 </p>
<p align="center">이렇게 학교에서 대표로 상을 받으니 더욱 기쁨이 큽니다~</p>
<p align="center">중학교에 입학한 오*진아동이&nbsp;건강하게&nbsp;잘 자랄 수 있도록 지원하겠습니다. </p>
<p align="center">많이 응원해 주세요!!! ^-^*</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',1087,1362409200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9793,'dus3','임태현','lth1342@naver.com','다윗방 김*철 생일파티 (2013,03,03)','<p align="center">&nbsp;</p>
<p align="center">3월 3일 다윗방 김*철 아동의 생일이었습니다.</p>
<p align="center">다윗방에서 반장도 맡고 있고&nbsp;평소 책임감을 가지고 성실히 생활하는 아동입니다.</p>
<p align="center">학교 개학과 입학을 하루 앞둔 이날&nbsp;동*이의 생일을&nbsp;맞이하여 아동들이 모여 생일을 축하해 주고 맛있는 케익과 음식으로 즐거운 시간을 보냈습니다.</p>
<p align="center">동*이의 생일을 축하합니다!</p>          </td>
        </tr>',1069,1362582000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9795,'dus3','박진성','js2227@hanmail.net','바울방의 최*명, 오*진 입학식(2013.03.04)','<p>바우방에 즐거운 소식이 많은 2013년 3월입니다.</p>
<p>남산초등학교 1학년 2반에 입학한 최*명 아동과 환일중학교 1학년 3반에 입학한 오*진 아동!</p>
<p>적극적인 바울방의 이미지와 너무나 닮은 우리 두 아동들이 학교생활을 즐겁게 시작하길 바랍니다!!!</p>
<p>많은 응원바랍니다!!!^^*&nbsp;</p>          </td>
        </tr>',1099,1362409200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9796,'dus3','남산원','jblee4@naver.com','다윗방 이*늘 아동 덕수중학교 입학 (2013.03.4)','<p>다윗방&nbsp;막내&nbsp;이*늘아동이 덕수중학교에 입학을 하였습니다.봄방학기간동안 중학교 입학준비를 하고 처음 등교를 하였습니다.많은 기대를 가지고 입학한&nbsp;*늘이가 중학교 생활 잘 할수 있도록 지도 하겠습니다.</p>
<p></p>          </td>
        </tr>',1270,1362409200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9797,'dus3','송명은','happysme@hanmail.net','룻2방의 *리,*희,*선이가 덕수중학교에 입학했습니다.(2013.03.04)','<p>꽃보다 예쁜 룻2방의&nbsp;<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">리,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">희,</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">선이가 덕수중학교 1학년에 입학했습니다.</span></p>
<p>항상 밝고 명랑한 우리 아이들이 무지개처럼 예쁘고 다양한 색깔을 가지고 많은 사람들에게 인정받고 사랑받는 중학교생활을 할 수 있도록 많은 관심과 사랑 부탁드립니다.^^</p>
<p>강<span style="text-align: -webkit-center">*</span>리, 김<span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">희, 김</span><span style="text-align: -webkit-center; font-size: 9pt; line-height: 1.5">*</span><span style="font-size: 9pt; line-height: 1.5">선~~화이팅!!!^^</span></p>          </td>
        </tr>',1085,1362409200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9798,'dus3','김선기','spsp99@naver.com','다윗방 김*석 아동 환일중학교 입학 (2013.03.4)','<p>다윗방 김*석아동이 환일중학교에 입학을 하였습니다.봄방학기간동안 중학교 입학준비를 하고 처음 등교를 하였습니다.준*이가 초등학교때처럼 중학교 생활도 성실히&nbsp;잘 할수 있도록 지도 하겠습니다.</p>          </td>
        </tr>',1376,1362409200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9799,'dus3','이문섭','srlc1208@hanmail.net','모세방 이*남 아동이 백석예술대학에 입학했습니다.....^^','<p>오랜 시간동안 열심히 준비해온 *남이가 오늘 드디어 대학생이 되었습니다...</p>
<p>새로운 길을 걷기 시작했습니다...</p>
<p>즐겁고 보람있는 대학 생활이 되도록 오리엔테이션도 다녀오고 친구들도 여럿 사귀었다고 합니다...</p>
<p>졸업하는 순간까지 열심히 달려갈 수 있도록 많은 격려와 응원 부탁합니다.....^^</p>
<p>&nbsp;</p>
<p>&nbsp;</p>          </td>
        </tr>',1120,1362322800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9800,'dus3','송명은','happysme@hanmail.net','룻2방의 *민이가 남산초등학교 1학년에 입학하였습니다.(2013.03.04)','<p>마냥 어린 아이로만 봐왔던 우리 *민이가 드디어 초등학생이 되었답니다.</p>
<p>항상 동생들과 어린이집을 다니다가 *민이 또래 아이들을 만나게 된 *민이는 입학식 처음에는 조금 얼떨떨한 표정이었지만 입학식이 진행되면서 어느새 의젓한 초등학생으로써 입학식의 순서마다 박수를 치며 집중하는 모습이 귀여웠습니다.</p>
<p>오늘은 특별히 평소에 *민이를 후원해주시는 오수영님께서 바쁘신 가운데서도 참석해주셔서 자리를 빛내주셨습니다.</p>
<p>많은 사람들의 관심과 사랑을 받고 시작한 초등학교 생활을 열심히 할 수 있도록 앞으로도 우리 *민이에게 따뜻한 관심을 부탁드립니다.</p>
<p>남산초등학교 1학년 1반 3번 김*민~화이팅!!!</p>          </td>
        </tr>',1189,1362322800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9801,'dus3','박진성','js2227@hanmail.net','이진경 후원자님과의 외출-오*진, 이*울(2013.03.02)','<p>봄이 성큼 다가온 3월.</p>
<p>이진경 후원자님께서 바울방의 오*진 아동과 다윗방의 이*울 아동과&nbsp; 함께 즐거운시간을 보내주셨습니다.</p>
<p>아동들이 보고싶어하던 \'차이니즈 조디악\', \'베를린\'이라는 영화를 보고&nbsp;맛있는 저녁식사를 하였습니다.</p>
<p>오랜만에&nbsp;즐거운 시간을 보내며 행복해 하는&nbsp;사춘기 남자아동들의 행복한 모습입니다^^</p>
<p>최근에 말수도 적어지고 자신을 표현하는데 어색해 하는 아동들이지만 선생님과의 외출 에 행복해 하였습니다.</p>
<p>항상 아동들을 먼저 생각해주시고 이끌어 주시며&nbsp;또 아동들의 마음을 나누려고 애써주시는 이진경 후원회장님께 다시한번 감사드립니다.^^</p>          </td>
        </tr>',1163,1362150000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9802,'dus3','박진성','js2227@hanmail.net','3.1절 바울방 프로그램 참석(2013.03.01)','<p>94주년 3.1절 프로그램으로 시 낭독대회와 태극기 그리기 프로그램을 진행하였습니다.</p>
<p>아동들의 적극적인 참여로 시낭독대회에서는 2등을 하였고 태극기 그리기에서는 최남명아동이 우승을 하였습니다.</p>
<p>3.1절 프로그램을 통해 아동들이 나라사랑하는 마음과 우리 나라를 지키는 부분에 대해 다짐하는 귀한 시간을 보냈습니다.</p>
<p>우리 아동들이 건강하고 자랑스런 대한민국의 국민으로 살아갈 수 있도록 지원을 하겠습니다.</p>          </td>
        </tr>',1217,1362150000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9803,'dus3','박진성','js2227@hanmail.net','오*진 아동 임현경선생님께 졸업과 입학선물 받은 날(2013.03.01)','<p>*진이와 3년여동안 수학수업을 함께 하신 임현경 선생님께서 입학과 졸업을 축하하며 선물을 주셨습니다.</p>
<p>*진이의 든든한 후원자로서 아동과 함께하여 주시는 선생님의 마음이 느껴지는 귀한 선물 잘사합니다!!!^^*</p>          </td>
        </tr>',1466,1362150000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9804,'dus3','송명은','happysme@hanmail.net','3.1절기념 시 낭독대회에서 룻2방이 1등!!을 했습니다~(2013.03.01)','<p>올해로 94번째 3.1절을 맞이하는 오늘!!</p>
<p>남산원에서 열린 시 낭독대회에서 꽃보다 예쁜 룻2방이 1등을 했습니다.</p>
<p>룻2방 아이들 모두가 진지한 마음으로 열심히 준비한 결과인 것 같습니다.</p>
<p>또 미취학 아이들은 우리나라의 국기를 예쁘게 색칠해보는 시간을 보냈습니다. </p>
<p>오늘 이 마음을 잊지 않고 나라를 사랑하는 마음이 더욱 더 커지는 룻2방이 되어야겠습니다.^^</p>          </td>
        </tr>',1210,1362063600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9805,'dus3','류덕례','yoodr1015@hanmail.net','모세방 3.1절 프로그램(2013.03.01)','<p align="center">모세방 아동들이 3.1절 프로그램(2013.03.01)에 참여 하였습니다.</p>
<p align="center">남산의&nbsp;제일 큰형들이 3.1절의 의미를 알기 위하여 시낭송과</p>
<p align="center">3.1절 노래부르기를 쑥쓰럽지만 적극적으로 참여하는 모습을 칭찬합니다.</p>
<p align="center">용인철 아동은 3.1절 노래를 열심히 불러서&nbsp;남우 주연상으로 뽑혔으며</p>
<p align="center">모세방의 성적은 4등을 하였지만 참여한 아동들 모두 수고하셨습니다.!!</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',1223,1362063600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9806,'dus3','박진성','js2227@hanmail.net','3.1절 태극기 그리기 프로그램(2013.03.01)','<p>미취학 아동들과 함께 3.1절 태극기 그리기와 퀴즈대회를 하였습니다.</p>
<p>먼저 3.1절 관련 동영상을 보고, 손기정마라토너에 대한 동영상을 보았습니다.</p>
<p>그러고 나서 태극기를 색칠하고 퀴즈 대회를 진행하였습니다.</p>
<p>아동들의 구호도 나라사랑하는 마음을 담아 "만세", "우리나라", "대한민국", "독도는 우리땅", "최고" 등을 외치며 아동들과 3.1절의 의미를 아는 시간을 가졌습니다.</p>
<p>낮선 이야기에 귀 기울이며&nbsp; 나라사랑하는 마음을 키우는 귀한 시간이 되었습니다.</p>          </td>
        </tr>',1331,1362063600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9807,'dus3','심주현','pikaccu85@hanmail.net','바울방 멋쟁이 영*가 선물 받는 날!!(2013.02.28)','<p align="center">오늘 바울방 멋쟁이 영*가 박상은 후원자님으로 부터 </p>
<p align="center">브라우니 인형과 멋진 썬글라스. 귀여운 손목시계를 선물로 받았습니다. </p>
<p align="center">많은 관심과 사랑으로 영*를 지켜봐 주시는 </p>
<p align="center">후원자님께 진심으로 감사드립니다.^-^♡</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>
<p align="center">&nbsp;</p>          </td>
        </tr>',1312,1361977200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9808,'dus3','김선기','spsp99@naver.com','다윗방 김*석 중학교 입학 선물 남산교회 후원 (2013.02.25)','<p>남산교회에서 다윗방 준*이의 중학교 입학 선물을 후원해 주셨습니다~^^ 초등학교 졸업을 하고 중학교 입학을 앞두고 있는 준*이가 열심히 학교 생활을 할 수 있도록 바지와 예쁜 티를 선물해 주셨습니다.후원해 주신 남산교회에 진심으로 감사드립니다.</p>          </td>
        </tr>',1592,1361890800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9809,'dus3','박진성','js2227@hanmail.net','바울방 아동들과 서점 나들이(2013.02.27)','<p>윤성신선생님이 준비를 부탁한 학습교재를 구입하러 가며 바울방 아동들과 함께 서점을 다녀왔습니다.</p>
<p>아동들의 설레이는 발걸음에 기분이 좋았습니다. 날씨도 따뜻한 오후의 햇살을 받으며 영풍문고에 다녀왔습니다.</p>
<p>편하게 앉아 책도 자유롭게 읽고 평소 사고 싶어하던 것들을 신중하게 골라서 구입을 하고 돌아왔습니다.</p>
<p>잘 모아둔 문화상품권으로 구입한 책과 물건들을 들고 오며 뿌듯한 미소를 띈 아동들의 모습에 기분이 좋았습니다.</p>
<p>아동들과 꾸준히 함께하는 시간을 갖도록 하겠습니다.</p>          </td>
        </tr>',1377,1361890800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9810,'dus3','심주현','pikaccu85@hanmail.net','바울방 귀요미 민*이 생일이에요 ^-^♡ (2013.02.26)','<p class="바탕글">바울방 귀요미&nbsp;민*이가 여섯번째&nbsp;생일을 맞이 하였습니다 ^-^♡</p>
<p class="바탕글">늘 쾌할하고 즐거움을 표현하는&nbsp; 민*이는&nbsp;&nbsp;매우 긍정적인 아이랍니다!!</p>
<p class="바탕글">우리 민*이가 언제나 행복하고 건강하게 잘 성장할 수 있도록 지켜봐 주세요!! ^^</p>          </td>
        </tr>',1399,1361890800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9811,'dus3','이문섭','srlc1208@hanmail.net','이*남 아동 대학 신입생 오리엔테이션 참가','<p>모세방에서 생활하고 있는 이*남 아동이 백석예술대학 외국어학부 중국어과에 입학하여</p>
<p>오늘 아침 일찍 신입생 오리엔테이션에 참가했습니다...</p>
<p>이곳보다 조금 더 추울것 같은 강원도 평창 알펜시아리조트에서 1박2일간 참가하게 되었습니다...</p>
<p>진학할 대학에 대해서 더 상세히 알아볼 수 있는 좋은 기회가 주어진 것 같습니다...</p>
<p>친구들도 많이 사귈 수 있도록 응원합니다...</p>
<p>다음주 부터 대학생활을 시작하게 되었으니 많은 분들의 격려와 관심을 부탁합니다...</p>
<p>이*남!! 화이팅!!!</p>
<p>&nbsp;</p>          </td>
        </tr>',1535,1361804400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9812,'dus3','류덕례','yoodr1015@hanmail.net','다윗방 이*늘 덕수중학교 교복구입 (2013.02.26)','<p align="center">다윗방 이<span style="text-align: -webkit-left">*</span>늘 덕수중학교 교복구입 (2013.02.26)</p>
<p align="center">이<span style="text-align: -webkit-left">*</span>늘 아동이&nbsp;남산원의 생활에 명랑하고 활기차게 하고있습니다.</p>
<p align="center">적응도 잘하고 있으며&nbsp;새로운 출발을 위하여 덕수중학교 교복도 구입하였습니다.</p>
<p align="center">&nbsp;중학교에 입학하여 꿈도 크게 갖구요~ 새출발을 진심으로 축하합니다!!</p>          </td>
        </tr>',2359,1361804400,'', '', '', '', '', '');
